window.CB = {"cats":[{"id":"entry","name":{"en":"Entry & Entry Summary","es":"Entrada y resumen de entrada","ru":"Ввоз и итоговая декларация","tr":"Giriş ve Giriş Özeti","hi":"प्रवेश और एंट्री सारांश","ar":"الإدخال وملخص الإدخال"},"blurb":{"en":"Entry types, CBP Forms 3461/7501, deadlines, liquidation and recordkeeping.","es":"Tipos de entrada, formularios CBP 3461/7501, plazos, liquidación y registros.","ru":"Типы ввоза, формы CBP 3461/7501, сроки, ликвидация и хранение записей.","tr":"Giriş türleri, CBP Form 3461/7501, süreler, kesinleştirme ve kayıt tutma.","hi":"प्रवेश प्रकार, CBP फॉर्म 3461/7501, समय-सीमा, परिसमापन और रिकॉर्ड-कीपिंग।","ar":"أنواع الإدخال، ونماذج CBP 3461/7501، والمواعيد النهائية، والتصفية، وحفظ السجلات."}},{"id":"classification","name":{"en":"Classification (HTSUS)","es":"Clasificación (HTSUS)","ru":"Классификация (HTSUS)","tr":"Sınıflandırma (HTSUS)","hi":"वर्गीकरण (HTSUS)","ar":"التصنيف (HTSUS)"},"blurb":{"en":"The General Rules of Interpretation (GRI 1–6) and tariff structure.","es":"Las Reglas Generales de Interpretación (GRI 1–6) y la estructura arancelaria.","ru":"Основные правила интерпретации (GRI 1–6) и структура тарифа.","tr":"Genel Yorum Kuralları (GRI 1–6) ve tarife yapısı.","hi":"व्याख्या के सामान्य नियम (GRI 1–6) और टैरिफ संरचना।","ar":"القواعد العامة للتفسير (GRI 1–6) وبنية التعريفة."}},{"id":"valuation","name":{"en":"Customs Valuation","es":"Valoración aduanera","ru":"Таможенная оценка","tr":"Gümrük Kıymeti","hi":"सीमा शुल्क मूल्यांकन","ar":"التقييم الجمركي"},"blurb":{"en":"Transaction value, additions, assists, and the appraisement hierarchy.","es":"Valor de transacción, adiciones, assists y la jerarquía de valoración.","ru":"Стоимость сделки, добавления, assists и иерархия методов оценки.","tr":"İşlem değeri, eklemeler, asistler ve kıymet tespiti hiyerarşisi.","hi":"लेनदेन मूल्य, परिवर्धन, assists, और मूल्यांकन पदानुक्रम।","ar":"قيمة المعاملة، والإضافات، والمساعدات (assists)، وتسلسل التقييم."}},{"id":"duties","name":{"en":"Duties, Fees & Drawback","es":"Derechos, tasas y drawback","ru":"Пошлины, сборы и возврат","tr":"Vergiler, Ücretler ve Drawback","hi":"शुल्क, फीस और ड्रॉबैक","ar":"الرسوم والرسوم والاسترداد"},"blurb":{"en":"Duty calculation, MPF & HMF, ADD/CVD, quotas and drawback.","es":"Cálculo de derechos, MPF y HMF, ADD/CVD, cuotas y drawback.","ru":"Расчёт пошлин, MPF и HMF, ADD/CVD, квоты и возврат пошлин.","tr":"Vergi hesaplama, MPF ve HMF, ADD/CVD, kotalar ve drawback.","hi":"शुल्क गणना, MPF और HMF, ADD/CVD, कोटा और ड्रॉबैक।","ar":"حساب الرسوم، وMPF وHMF، وADD/CVD، والحصص، والاسترداد."}},{"id":"compliance","name":{"en":"Broker Compliance (19 CFR 111)","es":"Cumplimiento del agente (19 CFR 111)","ru":"Соответствие брокера (19 CFR 111)","tr":"Müşavir Uyumu (19 CFR 111)","hi":"ब्रोकर अनुपालन (19 CFR 111)","ar":"امتثال الوسيط (19 CFR 111)"},"blurb":{"en":"Licensing, powers of attorney, recordkeeping, supervision and penalties.","es":"Licencias, poderes notariales, registros, supervisión y sanciones.","ru":"Лицензирование, доверенности, хранение записей, надзор и штрафы.","tr":"Lisanslama, vekâletnameler, kayıt tutma, denetim ve cezalar.","hi":"लाइसेंसिंग, पावर ऑफ अटॉर्नी, रिकॉर्ड-कीपिंग, पर्यवेक्षण और दंड।","ar":"الترخيص، والتوكيلات، وحفظ السجلات، والإشراف، والعقوبات."}},{"id":"trade","name":{"en":"Trade Programs & Marking","es":"Programas comerciales y marcado","ru":"Торговые программы и маркировка","tr":"Ticaret Programları ve İşaretleme","hi":"व्यापार कार्यक्रम और अंकन","ar":"البرامج التجارية والوسم"},"blurb":{"en":"Marking, USMCA, FTZs, bonds, PGAs, IPR and prior disclosure.","es":"Marcado, USMCA, FTZ, fianzas, PGA, IPR y divulgación previa.","ru":"Маркировка, USMCA, FTZ, гарантии, PGA, IPR и предварительное раскрытие.","tr":"İşaretleme, USMCA, FTZ, teminatlar, PGA, IPR ve ön açıklama.","hi":"अंकन, USMCA, FTZ, बॉन्ड, PGA, IPR और पूर्व प्रकटीकरण।","ar":"الوسم، وUSMCA، وFTZ، وسندات الضمان، وPGA، وIPR، والإفصاح المسبق."}}],"q":[{"cat":"entry","a":0,"q":{"en":"An importer's broker files CBP Form 3461 and obtains conditional release of a shipment of consumer electronics. Absent any extension or special arrangement, within how long after the time of entry must the entry summary (CBP Form 7501) be filed and the estimated duties deposited?","es":"El agente aduanal (broker) de un importador presenta el CBP Form 3461 y obtiene la liberación condicional de un embarque de electrónicos de consumo. En ausencia de cualquier prórroga o arreglo especial, ¿dentro de cuánto tiempo después del momento de la entrada debe presentarse el resumen de entrada (CBP Form 7501) y depositarse los derechos estimados?","ru":"Брокер импортёра подаёт CBP Form 3461 и получает условный выпуск партии бытовой электроники. При отсутствии какого-либо продления или особой договорённости в течение какого срока после момента ввоза должна быть подана итоговая декларация (CBP Form 7501) и внесены расчётные пошлины?","tr":"Bir ithalatçının gümrük müşaviri CBP Form 3461'i sunar ve bir tüketici elektroniği sevkiyatının koşullu olarak serbest bırakılmasını sağlar. Herhangi bir uzatma veya özel düzenleme olmaksızın, giriş anından sonra giriş özeti (CBP Form 7501) en geç ne kadar süre içinde sunulmalı ve tahmini vergiler yatırılmalıdır?","hi":"एक आयातक का ब्रोकर CBP Form 3461 दाखिल करता है और उपभोक्ता इलेक्ट्रॉनिक्स के एक शिपमेंट की सशर्त रिलीज प्राप्त करता है। किसी भी विस्तार या विशेष व्यवस्था के अभाव में, प्रवेश के समय के बाद कितने समय के भीतर एंट्री सारांश (CBP Form 7501) दाखिल किया जाना चाहिए और अनुमानित शुल्क जमा किए जाने चाहिए?","ar":"يقوم وسيط المستورد بتقديم CBP Form 3461 ويحصل على الإفراج المشروط عن شحنة من الإلكترونيات الاستهلاكية. في غياب أي تمديد أو ترتيب خاص، خلال أي مدة بعد وقت الإدخال يجب تقديم ملخص الإدخال (CBP Form 7501) وإيداع الرسوم التقديرية؟"},"o":[{"en":"Within 10 working days after the time of entry","es":"Dentro de los 10 días hábiles posteriores al momento de la entrada","ru":"В течение 10 рабочих дней после момента ввоза","tr":"Giriş anından sonra 10 iş günü içinde","hi":"प्रवेश के समय के बाद 10 कार्य दिवसों के भीतर","ar":"خلال 10 أيام عمل بعد وقت الإدخال"},{"en":"Within 15 calendar days after the time of entry","es":"Dentro de los 15 días naturales posteriores al momento de la entrada","ru":"В течение 15 календарных дней после момента ввоза","tr":"Giriş anından sonra 15 takvim günü içinde","hi":"प्रवेश के समय के बाद 15 कैलेंडर दिनों के भीतर","ar":"خلال 15 يومًا تقويميًا بعد وقت الإدخال"},{"en":"Within 10 calendar days after the time of entry","es":"Dentro de los 10 días naturales posteriores al momento de la entrada","ru":"В течение 10 календарных дней после момента ввоза","tr":"Giriş anından sonra 10 takvim günü içinde","hi":"प्रवेश के समय के बाद 10 कैलेंडर दिनों के भीतर","ar":"خلال 10 أيام تقويمية بعد وقت الإدخال"},{"en":"Within 30 calendar days after the time of entry","es":"Dentro de los 30 días naturales posteriores al momento de la entrada","ru":"В течение 30 календарных дней после момента ввоза","tr":"Giriş anından sonra 30 takvim günü içinde","hi":"प्रवेश के समय के बाद 30 कैलेंडर दिनों के भीतर","ar":"خلال 30 يومًا تقويميًا بعد وقت الإدخال"}],"e":{"en":"The entry summary for consumption merchandise must be filed, and estimated duties deposited, within 10 working days after the time of entry. See 19 CFR 142.12(b) (cross-referenced by 19 CFR 142.16).","es":"El resumen de entrada de mercancía para consumo debe presentarse, y los derechos estimados depositarse, dentro de los 10 días hábiles posteriores al momento de la entrada. Véase 19 CFR 142.12(b) (con referencia cruzada en 19 CFR 142.16).","ru":"Итоговая декларация на товары для потребления должна быть подана, а расчётные пошлины внесены, в течение 10 рабочих дней после момента ввоза. См. 19 CFR 142.12(b) (с перекрёстной ссылкой на 19 CFR 142.16).","tr":"Tüketim malları için giriş özeti, giriş anından sonra 10 iş günü içinde sunulmalı ve tahmini vergiler yatırılmalıdır. Bkz. 19 CFR 142.12(b) (19 CFR 142.16 ile çapraz referans verilmiştir).","hi":"उपभोग माल के लिए एंट्री सारांश प्रवेश के समय के बाद 10 कार्य दिवसों के भीतर दाखिल किया जाना चाहिए, और अनुमानित शुल्क जमा किए जाने चाहिए। देखें 19 CFR 142.12(b) (19 CFR 142.16 द्वारा क्रॉस-संदर्भित)।","ar":"يجب تقديم ملخص الإدخال الخاص ببضائع الاستهلاك، وإيداع الرسوم التقديرية، خلال 10 أيام عمل بعد وقت الإدخال. انظر 19 CFR 142.12(b) (مع الإحالة المرجعية في 19 CFR 142.16)."}},{"cat":"entry","a":1,"q":{"en":"Imported merchandise for which entry is required arrives and is landed from the importing vessel. Within what period must entry be made before the merchandise is treated as unclaimed and sent to a general-order warehouse?","es":"Llega y se descarga del buque importador mercancía para la cual se requiere entrada. ¿Dentro de qué plazo debe efectuarse la entrada antes de que la mercancía sea tratada como no reclamada y enviada a un almacén de orden general (general-order warehouse)?","ru":"Импортируемые товары, по которым требуется таможенная декларация, прибывают и выгружаются с ввозящего судна. В течение какого срока должна быть оформлена таможенная декларация, прежде чем товары будут считаться невостребованными и отправлены на склад общего хранения (general-order warehouse)?","tr":"Giriş beyanı gerektiren ithal mallar gelir ve ithalat gemisinden boşaltılır. Mallar sahipsiz olarak değerlendirilip bir general-order (genel ambar) deposuna gönderilmeden önce, giriş beyanı en geç hangi süre içinde yapılmalıdır?","hi":"वह आयातित माल जिसके लिए प्रवेश आवश्यक है, आता है और आयात करने वाले जहाज से उतारा जाता है। माल को लावारिस माना जाए और जनरल-ऑर्डर वेयरहाउस भेजा जाए, उससे पहले किस अवधि के भीतर प्रवेश किया जाना चाहिए?","ar":"تصل البضائع المستوردة التي يُشترط لها بيان الإدخال ويتم تفريغها من السفينة المستوردة. خلال أي مدة يجب إجراء الإدخال قبل أن تُعامل البضائع على أنها غير مطالَب بها وتُرسَل إلى مستودع الأمر العام (general-order warehouse)؟"},"o":[{"en":"Within 5 working days after landing","es":"Dentro de los 5 días hábiles posteriores a la descarga","ru":"В течение 5 рабочих дней после выгрузки","tr":"Boşaltmadan sonra 5 iş günü içinde","hi":"उतारने के बाद 5 कार्य दिवसों के भीतर","ar":"خلال 5 أيام عمل بعد التفريغ"},{"en":"Within 15 calendar days after landing","es":"Dentro de los 15 días naturales posteriores a la descarga","ru":"В течение 15 календарных дней после выгрузки","tr":"Boşaltmadan sonra 15 takvim günü içinde","hi":"उतारने के बाद 15 कैलेंडर दिनों के भीतर","ar":"خلال 15 يومًا تقويميًا بعد التفريغ"},{"en":"Within 10 working days after landing","es":"Dentro de los 10 días hábiles posteriores a la descarga","ru":"В течение 10 рабочих дней после выгрузки","tr":"Boşaltmadan sonra 10 iş günü içinde","hi":"उतारने के बाद 10 कार्य दिवसों के भीतर","ar":"خلال 10 أيام عمل بعد التفريغ"},{"en":"Within 20 calendar days after landing","es":"Dentro de los 20 días naturales posteriores a la descarga","ru":"В течение 20 календарных дней после выгрузки","tr":"Boşaltmadan sonra 20 takvim günü içinde","hi":"उतारने के बाद 20 कैलेंडर दिनों के भीतर","ar":"خلال 20 يومًا تقويميًا بعد التفريغ"}],"e":{"en":"Merchandise for which entry is required must be entered within 15 calendar days after landing from a vessel, aircraft, or vehicle (or after arrival at the port of destination for in-bond merchandise). See 19 CFR 141.5 and 19 CFR 142.2(a).","es":"La mercancía para la cual se requiere entrada debe entrarse dentro de los 15 días naturales posteriores a la descarga de un buque, aeronave o vehículo (o posteriores a la llegada al puerto de destino para mercancía en tránsito aduanero, in-bond). Véase 19 CFR 141.5 y 19 CFR 142.2(a).","ru":"Товары, по которым требуется таможенная декларация, должны быть задекларированы в течение 15 календарных дней после выгрузки с судна, воздушного судна или транспортного средства (либо после прибытия в порт назначения для товаров, перемещаемых под таможенным контролем in-bond). См. 19 CFR 141.5 и 19 CFR 142.2(a).","tr":"Giriş beyanı gerektiren mallar, bir gemiden, uçaktan veya araçtan boşaltıldıktan sonra (veya in-bond mallar için varış limanına ulaştıktan sonra) 15 takvim günü içinde giriş beyanına tabi tutulmalıdır. Bkz. 19 CFR 141.5 ve 19 CFR 142.2(a).","hi":"जिस माल के लिए प्रवेश आवश्यक है, उसका प्रवेश जहाज, विमान या वाहन से उतारने के बाद 15 कैलेंडर दिनों के भीतर (या इन-बॉन्ड माल के लिए गंतव्य बंदरगाह पर आगमन के बाद) किया जाना चाहिए। देखें 19 CFR 141.5 और 19 CFR 142.2(a)।","ar":"يجب إدخال البضائع التي يُشترط لها بيان الإدخال خلال 15 يومًا تقويميًا بعد التفريغ من سفينة أو طائرة أو مركبة (أو بعد الوصول إلى ميناء الوجهة بالنسبة للبضائع المنقولة بموجب سند (in-bond)). انظر 19 CFR 141.5 و 19 CFR 142.2(a)."}},{"cat":"entry","a":2,"q":{"en":"Which document set most accurately reflects the function of CBP Form 3461 versus CBP Form 7501 in the entry process?","es":"¿Qué conjunto de documentos refleja con mayor precisión la función del CBP Form 3461 frente al CBP Form 7501 en el proceso de entrada?","ru":"Какой набор документов наиболее точно отражает функцию CBP Form 3461 по сравнению с CBP Form 7501 в процессе ввоза?","tr":"Hangi belge takımı, giriş sürecinde CBP Form 3461'in CBP Form 7501'e karşı işlevini en doğru şekilde yansıtır?","hi":"कौन सा दस्तावेज समूह प्रवेश प्रक्रिया में CBP Form 3461 बनाम CBP Form 7501 के कार्य को सबसे सटीक रूप से दर्शाता है?","ar":"أي مجموعة من المستندات تعكس بأكبر دقة وظيفة CBP Form 3461 مقابل CBP Form 7501 في عملية الإدخال؟"},"o":[{"en":"Form 3461 is the entry summary used to assess duties; Form 7501 is the entry used to obtain release","es":"El Form 3461 es el resumen de entrada usado para determinar derechos; el Form 7501 es la entrada usada para obtener la liberación","ru":"Form 3461 — это итоговая декларация, используемая для начисления пошлин; Form 7501 — это декларация для получения выпуска","tr":"Form 3461, vergileri tahakkuk ettirmek için kullanılan giriş özetidir; Form 7501, serbest bırakmayı sağlamak için kullanılan giriş beyanıdır","hi":"Form 3461 शुल्क निर्धारण के लिए उपयोग किया जाने वाला एंट्री सारांश है; Form 7501 रिलीज प्राप्त करने के लिए उपयोग की जाने वाली एंट्री है","ar":"Form 3461 هو ملخص الإدخال المستخدم لتقدير الرسوم؛ وForm 7501 هو بيان الإدخال المستخدم للحصول على الإفراج"},{"en":"Both forms are entry summaries, with Form 3461 used for formal and Form 7501 for informal entries","es":"Ambos formularios son resúmenes de entrada, usándose el Form 3461 para entradas formales y el Form 7501 para entradas informales","ru":"Обе формы являются итоговыми декларациями: Form 3461 используется для формального, а Form 7501 — для неформального ввоза","tr":"Her iki form da giriş özetidir; Form 3461 resmi (formal) girişler, Form 7501 ise gayri resmi (informal) girişler için kullanılır","hi":"दोनों फॉर्म एंट्री सारांश हैं, जिसमें Form 3461 औपचारिक के लिए और Form 7501 अनौपचारिक प्रवेशों के लिए उपयोग किया जाता है","ar":"كلا النموذجين عبارة عن ملخصات إدخال، حيث يُستخدم Form 3461 للإدخالات الرسمية وForm 7501 للإدخالات غير الرسمية"},{"en":"Form 3461 is the entry used to obtain release of merchandise; Form 7501 is the entry summary used to assess duties and collect statistics","es":"El Form 3461 es la entrada usada para obtener la liberación de la mercancía; el Form 7501 es el resumen de entrada usado para determinar derechos y recopilar estadísticas","ru":"Form 3461 — это декларация для получения выпуска товаров; Form 7501 — это итоговая декларация для начисления пошлин и сбора статистики","tr":"Form 3461, malların serbest bırakılmasını sağlamak için kullanılan giriş beyanıdır; Form 7501, vergileri tahakkuk ettirmek ve istatistik toplamak için kullanılan giriş özetidir","hi":"Form 3461 माल की रिलीज प्राप्त करने के लिए उपयोग की जाने वाली एंट्री है; Form 7501 शुल्क निर्धारण और आंकड़े एकत्र करने के लिए उपयोग किया जाने वाला एंट्री सारांश है","ar":"Form 3461 هو بيان الإدخال المستخدم للحصول على الإفراج عن البضائع؛ وForm 7501 هو ملخص الإدخال المستخدم لتقدير الرسوم وجمع الإحصاءات"},{"en":"Form 3461 is the carrier's certificate; Form 7501 is the immediate delivery application","es":"El Form 3461 es el certificado del transportista; el Form 7501 es la solicitud de entrega inmediata","ru":"Form 3461 — это сертификат перевозчика; Form 7501 — это заявление о немедленной доставке","tr":"Form 3461 taşıyıcının sertifikasıdır; Form 7501 acil teslim başvurusudur","hi":"Form 3461 वाहक का प्रमाणपत्र है; Form 7501 तत्काल वितरण आवेदन है","ar":"Form 3461 هو شهادة الناقل؛ وForm 7501 هو طلب التسليم الفوري"}],"e":{"en":"The 'entry' (CBP Form 3461 or its electronic equivalent) secures release of merchandise from CBP custody, while the 'entry summary' (CBP Form 7501) provides the data to assess duties and collect statistics. See 19 CFR 141.0a(a) and (b), 142.3, and 142.11.","es":"La 'entrada' (CBP Form 3461 o su equivalente electrónico) asegura la liberación de la mercancía de la custodia de CBP, mientras que el 'resumen de entrada' (CBP Form 7501) aporta los datos para determinar derechos y recopilar estadísticas. Véase 19 CFR 141.0a(a) y (b), 142.3 y 142.11.","ru":"«Декларация» (CBP Form 3461 или её электронный эквивалент) обеспечивает выпуск товаров из-под контроля CBP, тогда как «итоговая декларация» (CBP Form 7501) предоставляет данные для начисления пошлин и сбора статистики. См. 19 CFR 141.0a(a) и (b), 142.3 и 142.11.","tr":"'Giriş beyanı' (CBP Form 3461 veya elektronik eşdeğeri) malların CBP gözetiminden serbest bırakılmasını sağlar; 'giriş özeti' (CBP Form 7501) ise vergileri tahakkuk ettirmek ve istatistik toplamak için gereken verileri sağlar. Bkz. 19 CFR 141.0a(a) ve (b), 142.3 ve 142.11.","hi":"'एंट्री' (CBP Form 3461 या इसका इलेक्ट्रॉनिक समकक्ष) CBP अभिरक्षा से माल की रिलीज सुरक्षित करती है, जबकि 'एंट्री सारांश' (CBP Form 7501) शुल्क निर्धारण और आंकड़े एकत्र करने हेतु डेटा प्रदान करता है। देखें 19 CFR 141.0a(a) और (b), 142.3, और 142.11।","ar":"إن \"بيان الإدخال\" (CBP Form 3461 أو ما يعادله إلكترونيًا) يضمن الإفراج عن البضائع من عهدة CBP، بينما يوفّر \"ملخص الإدخال\" (CBP Form 7501) البيانات اللازمة لتقدير الرسوم وجمع الإحصاءات. انظر 19 CFR 141.0a(a) و(b) و142.3 و142.11."}},{"cat":"entry","a":1,"q":{"en":"Merchandise admitted under a temporary importation under bond (TIB) entry is not for sale and must ultimately be exported or destroyed. Counting the initial period plus all permissible extensions, what is the maximum total period the merchandise may remain in the United States?","es":"La mercancía admitida bajo una entrada de importación temporal con fianza (TIB) no es para venta y debe finalmente ser exportada o destruida. Contando el período inicial más todas las prórrogas permitidas, ¿cuál es el período total máximo que la mercancía puede permanecer en los Estados Unidos?","ru":"Товары, ввезённые по декларации временного ввоза под таможенную гарантию (TIB), не предназначены для продажи и в конечном итоге должны быть вывезены или уничтожены. С учётом первоначального срока плюс всех допустимых продлений, какой максимальный общий срок товары могут оставаться в Соединённых Штатах?","tr":"Bir temporary importation under bond (TIB - teminat altında geçici ithalat) girişi kapsamında kabul edilen mallar satışa konu değildir ve nihayetinde ihraç edilmeli veya imha edilmelidir. İlk süre artı izin verilen tüm uzatmalar sayıldığında, malların Amerika Birleşik Devletleri'nde kalabileceği azami toplam süre nedir?","hi":"बॉन्ड के तहत अस्थायी आयात (TIB) एंट्री के अंतर्गत प्रवेश दिया गया माल बिक्री के लिए नहीं है और अंततः निर्यात या नष्ट किया जाना चाहिए। प्रारंभिक अवधि और सभी अनुमेय विस्तारों को गिनते हुए, माल संयुक्त राज्य अमेरिका में अधिकतम कुल कितनी अवधि तक रह सकता है?","ar":"البضائع المدخلة بموجب بيان إدخال الاستيراد المؤقت بضمان (TIB) ليست معروضة للبيع ويجب في النهاية تصديرها أو إتلافها. باحتساب المدة الأولية بالإضافة إلى جميع التمديدات المسموح بها، ما هي أقصى مدة إجمالية يجوز أن تبقى فيها البضائع داخل الولايات المتحدة؟"},"o":[{"en":"Two years from the date of importation","es":"Dos años a partir de la fecha de importación","ru":"Два года с даты импортирования","tr":"İthalat tarihinden itibaren iki yıl","hi":"आयात की तारीख से दो वर्ष","ar":"سنتان من تاريخ الاستيراد"},{"en":"Three years from the date of importation","es":"Tres años a partir de la fecha de importación","ru":"Три года с даты импортирования","tr":"İthalat tarihinden itibaren üç yıl","hi":"आयात की तारीख से तीन वर्ष","ar":"ثلاث سنوات من تاريخ الاستيراد"},{"en":"One year from the date of importation, with no extension permitted","es":"Un año a partir de la fecha de importación, sin prórroga permitida","ru":"Один год с даты импортирования, без права продления","tr":"İthalat tarihinden itibaren bir yıl, herhangi bir uzatmaya izin verilmeksizin","hi":"आयात की तारीख से एक वर्ष, बिना किसी विस्तार की अनुमति के","ar":"سنة واحدة من تاريخ الاستيراد، دون السماح بأي تمديد"},{"en":"Five years from the date of importation","es":"Cinco años a partir de la fecha de importación","ru":"Пять лет с даты импортирования","tr":"İthalat tarihinden itibaren beş yıl","hi":"आयात की तारीख से पांच वर्ष","ar":"خمس سنوات من تاريخ الاستيراد"}],"e":{"en":"TIB merchandise is admitted for one year and the bond period may be extended for not more than two further one-year periods, for a maximum total of three years from the date of importation. See 19 CFR 10.31(g) and 10.37.","es":"La mercancía bajo TIB se admite por un año y el período de la fianza puede prorrogarse por no más de dos períodos adicionales de un año cada uno, para un total máximo de tres años a partir de la fecha de importación. Véase 19 CFR 10.31(g) y 10.37.","ru":"Товары по TIB допускаются на один год, и срок действия таможенной гарантии может быть продлён не более чем на два дополнительных одногодичных периода, что в сумме составляет максимум три года с даты импортирования. См. 19 CFR 10.31(g) и 10.37.","tr":"TIB malları bir yıl süreyle kabul edilir ve teminat süresi, her biri bir yıl olan ikiden fazla olmayan ilave dönem için uzatılabilir; bu da ithalat tarihinden itibaren azami toplam üç yıl eder. Bkz. 19 CFR 10.31(g) ve 10.37.","hi":"TIB माल को एक वर्ष के लिए प्रवेश दिया जाता है और बॉन्ड अवधि को अधिकतम दो और एक-वर्षीय अवधियों के लिए बढ़ाया जा सकता है, जिससे आयात की तारीख से अधिकतम कुल तीन वर्ष बनते हैं। देखें 19 CFR 10.31(g) और 10.37।","ar":"تُدخَل بضائع TIB لمدة سنة واحدة ويجوز تمديد مدة السند لما لا يزيد على فترتين إضافيتين مدة كل منهما سنة، بحد أقصى إجمالي قدره ثلاث سنوات من تاريخ الاستيراد. انظر 19 CFR 10.31(g) و10.37."}},{"cat":"entry","a":2,"q":{"en":"For a temporary importation under bond (TIB) entry of merchandise not entitled to the reduced-rate categories, what is the standard amount of the bond required?","es":"Para una entrada de importación temporal con fianza (TIB) de mercancía no acreedora a las categorías de tasa reducida, ¿cuál es el monto estándar de la fianza requerida?","ru":"Для декларации временного ввоза под таможенную гарантию (TIB) на товары, не относящиеся к категориям с пониженной ставкой, каков стандартный размер требуемой таможенной гарантии?","tr":"İndirimli oran kategorilerine hak kazanmayan malların temporary importation under bond (TIB - teminat altında geçici ithalat) girişi için gereken standart teminat tutarı nedir?","hi":"उस माल की बॉन्ड के तहत अस्थायी आयात (TIB) एंट्री के लिए जो घटी-दर श्रेणियों का हकदार नहीं है, आवश्यक बॉन्ड की मानक राशि क्या है?","ar":"بالنسبة لبيان إدخال الاستيراد المؤقت بضمان (TIB) لبضائع غير مؤهلة لفئات المعدل المخفّض، ما هو المقدار القياسي للسند المطلوب؟"},"o":[{"en":"An amount equal to the estimated duties and fees","es":"Un monto igual a los derechos y cargos estimados","ru":"Сумма, равная расчётным пошлинам и сборам","tr":"Tahmini vergi ve harçlara eşit bir tutar","hi":"अनुमानित शुल्कों और शुल्कों के बराबर राशि","ar":"مقدار يساوي الرسوم والمصاريف التقديرية"},{"en":"An amount equal to 110 percent of the estimated duties and fees","es":"Un monto igual al 110 por ciento de los derechos y cargos estimados","ru":"Сумма, равная 110 процентам расчётных пошлин и сборов","tr":"Tahmini vergi ve harçların yüzde 110'una eşit bir tutar","hi":"अनुमानित शुल्कों और शुल्कों के 110 प्रतिशत के बराबर राशि","ar":"مقدار يساوي 110 بالمئة من الرسوم والمصاريف التقديرية"},{"en":"An amount equal to double the duties and fees that would otherwise accrue","es":"Un monto igual al doble de los derechos y cargos que de otro modo se causarían","ru":"Сумма, равная удвоенному размеру пошлин и сборов, которые в противном случае подлежали бы уплате","tr":"Aksi halde tahakkuk edecek vergi ve harçların iki katına eşit bir tutar","hi":"उन शुल्कों और फीस के दोगुने के बराबर राशि जो अन्यथा उपार्जित होती","ar":"مقدار يساوي ضعف الرسوم والمصاريف التي كانت ستُستحَق لولا ذلك"},{"en":"An amount equal to the appraised value of the merchandise","es":"Un monto igual al valor de avalúo de la mercancía","ru":"Сумма, равная оценочной стоимости товаров","tr":"Malların takdir edilen (appraised) değerine eşit bir tutar","hi":"माल के मूल्यांकित मूल्य के बराबर राशि","ar":"مقدار يساوي القيمة المقدّرة للبضائع"}],"e":{"en":"A TIB bond is generally given in an amount equal to double the duties and fees that it is estimated would accrue had the merchandise been entered for consumption (certain categories such as samples and professional equipment require only 110 percent). See 19 CFR 10.31(f).","es":"Una fianza TIB generalmente se otorga por un monto igual al doble de los derechos y cargos que se estima se habrían causado si la mercancía hubiera sido entrada para consumo (ciertas categorías, como muestras y equipo profesional, requieren solo el 110 por ciento). Véase 19 CFR 10.31(f).","ru":"Таможенная гарантия по TIB, как правило, предоставляется в сумме, равной удвоенному размеру пошлин и сборов, которые, по оценке, подлежали бы уплате, если бы товары были задекларированы для потребления (для отдельных категорий, таких как образцы и профессиональное оборудование, требуется только 110 процентов). См. 19 CFR 10.31(f).","tr":"Bir TIB teminatı genel olarak, mallar tüketim için giriş beyanına tabi tutulsaydı tahakkuk edeceği tahmin edilen vergi ve harçların iki katına eşit bir tutarda verilir (numuneler ve profesyonel ekipman gibi belirli kategoriler yalnızca yüzde 110 gerektirir). Bkz. 19 CFR 10.31(f).","hi":"TIB बॉन्ड आम तौर पर उन शुल्कों और फीस के दोगुने के बराबर राशि में दिया जाता है, जिनके बारे में अनुमान है कि वे उपार्जित होतीं यदि माल को उपभोग के लिए प्रवेश दिया गया होता (कुछ श्रेणियों जैसे नमूने और पेशेवर उपकरण के लिए केवल 110 प्रतिशत आवश्यक है)। देखें 19 CFR 10.31(f)।","ar":"يُقدَّم سند TIB عمومًا بمقدار يساوي ضعف الرسوم والمصاريف التي يُقدَّر أنها كانت ستُستحَق لو أُدخِلت البضائع للاستهلاك (تتطلب فئات معينة مثل العينات والمعدات المهنية 110 بالمئة فقط). انظر 19 CFR 10.31(f)."}},{"cat":"entry","a":1,"q":{"en":"Merchandise is placed in a bonded warehouse under a warehouse entry. Under the current regulation, what is the maximum period the merchandise may remain in the bonded warehouse measured from the date of importation?","es":"Se coloca mercancía en un almacén afianzado (bonded warehouse) bajo una entrada de almacén. Conforme a la regulación vigente, ¿cuál es el período máximo que la mercancía puede permanecer en el almacén afianzado, medido a partir de la fecha de importación?","ru":"Товары помещены на таможенный склад (bonded warehouse) по складской декларации. Согласно действующему нормативному акту, каков максимальный срок, в течение которого товары могут оставаться на таможенном складе, отсчитываемый с даты импортирования?","tr":"Mallar bir antrepo girişi (warehouse entry) kapsamında teminatlı bir antrepoya konulur. Mevcut yönetmeliğe göre, ithalat tarihinden ölçülerek, malların teminatlı antrepoda kalabileceği azami süre nedir?","hi":"माल को वेयरहाउस एंट्री के तहत बॉन्डेड वेयरहाउस में रखा जाता है। वर्तमान विनियमन के तहत, आयात की तारीख से मापा जाए तो माल अधिकतम कितनी अवधि तक बॉन्डेड वेयरहाउस में रह सकता है?","ar":"تُوضَع البضائع في مستودع جمركي مضمون (bonded warehouse) بموجب بيان إدخال مستودعي. بموجب اللائحة الحالية، ما هي أقصى مدة يجوز أن تبقى فيها البضائع في المستودع الجمركي المضمون مقيسةً من تاريخ الاستيراد؟"},"o":[{"en":"3 years from the date of importation","es":"3 años a partir de la fecha de importación","ru":"3 года с даты импортирования","tr":"İthalat tarihinden itibaren 3 yıl","hi":"आयात की तारीख से 3 वर्ष","ar":"3 سنوات من تاريخ الاستيراد"},{"en":"5 years from the date of importation","es":"5 años a partir de la fecha de importación","ru":"5 лет с даты импортирования","tr":"İthalat tarihinden itibaren 5 yıl","hi":"आयात की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ الاستيراد"},{"en":"1 year from the date of importation","es":"1 año a partir de la fecha de importación","ru":"1 год с даты импортирования","tr":"İthalat tarihinden itibaren 1 yıl","hi":"आयात की तारीख से 1 वर्ष","ar":"سنة واحدة من تاريخ الاستيراد"},{"en":"5 years from the date of the warehouse entry","es":"5 años a partir de la fecha de la entrada de almacén","ru":"5 лет с даты складской декларации","tr":"Antrepo girişi tarihinden itibaren 5 yıl","hi":"वेयरहाउस एंट्री की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ بيان الإدخال المستودعي"}],"e":{"en":"Merchandise may remain in a bonded warehouse for a period of 5 years from the date of importation. See 19 CFR 144.5.","es":"La mercancía puede permanecer en un almacén afianzado por un período de 5 años a partir de la fecha de importación. Véase 19 CFR 144.5.","ru":"Товары могут оставаться на таможенном складе в течение 5 лет с даты импортирования. См. 19 CFR 144.5.","tr":"Mallar, ithalat tarihinden itibaren 5 yıl süreyle teminatlı bir antrepoda kalabilir. Bkz. 19 CFR 144.5.","hi":"माल आयात की तारीख से 5 वर्ष की अवधि तक बॉन्डेड वेयरहाउस में रह सकता है। देखें 19 CFR 144.5।","ar":"يجوز أن تبقى البضائع في المستودع الجمركي المضمون لمدة 5 سنوات من تاريخ الاستيراد. انظر 19 CFR 144.5."}},{"cat":"entry","a":1,"q":{"en":"A foreign shipment arrives at the port of Long Beach but is destined to be exported to Mexico without entering U.S. commerce. The goods will move in bond from Long Beach to the export port. Which type of entry and form applies?","es":"Un embarque extranjero llega al puerto de Long Beach pero está destinado a ser exportado a México sin ingresar al comercio de los EE. UU. Las mercancías se moverán en tránsito aduanero (in bond) desde Long Beach hasta el puerto de exportación. ¿Qué tipo de entrada y formulario aplica?","ru":"Иностранная партия прибывает в порт Лонг-Бич, но предназначена для вывоза в Мексику без поступления в торговый оборот США. Товары будут перемещаться под таможенным контролем (in bond) из Лонг-Бич в порт вывоза. Какой тип декларации и форма применяются?","tr":"Yabancı bir sevkiyat Long Beach limanına gelir, ancak ABD ticaretine girmeden Meksika'ya ihraç edilmek üzere yola çıkacaktır. Mallar Long Beach'ten ihracat limanına in-bond olarak taşınacaktır. Hangi tür giriş ve form geçerlidir?","hi":"एक विदेशी शिपमेंट लॉन्ग बीच के बंदरगाह पर पहुंचता है, लेकिन इसे अमेरिकी वाणिज्य में प्रवेश किए बिना मेक्सिको को निर्यात किया जाना है। माल लॉन्ग बीच से निर्यात बंदरगाह तक इन बॉन्ड स्थानांतरित होगा। किस प्रकार की एंट्री और फॉर्म लागू होता है?","ar":"تصل شحنة أجنبية إلى ميناء لونغ بيتش لكنها مخصصة للتصدير إلى المكسيك دون الدخول في التجارة الأمريكية. ستنتقل البضائع بموجب سند (in bond) من لونغ بيتش إلى ميناء التصدير. أي نوع من بيانات الإدخال والنماذج ينطبق؟"},"o":[{"en":"Immediate transportation (IT) entry on CBP Form 3461","es":"Entrada de transporte inmediato (IT) en el CBP Form 3461","ru":"Декларация немедленной транспортировки (IT) по CBP Form 3461","tr":"CBP Form 3461 üzerinde immediate transportation (IT - acil taşıma) girişi","hi":"CBP Form 3461 पर तत्काल परिवहन (IT) एंट्री","ar":"بيان إدخال النقل الفوري (IT) على CBP Form 3461"},{"en":"Transportation and exportation (T&E) entry on CBP Form 7512","es":"Entrada de transporte y exportación (T&E) en el CBP Form 7512","ru":"Декларация транспортировки и вывоза (T&E) по CBP Form 7512","tr":"CBP Form 7512 üzerinde transportation and exportation (T&E - taşıma ve ihracat) girişi","hi":"CBP Form 7512 पर परिवहन और निर्यात (T&E) एंट्री","ar":"بيان إدخال النقل والتصدير (T&E) على CBP Form 7512"},{"en":"Warehouse entry on CBP Form 7501","es":"Entrada de almacén en el CBP Form 7501","ru":"Складская декларация по CBP Form 7501","tr":"CBP Form 7501 üzerinde antrepo girişi (warehouse entry)","hi":"CBP Form 7501 पर वेयरहाउस एंट्री","ar":"بيان إدخال مستودعي على CBP Form 7501"},{"en":"Consumption entry on CBP Form 7501","es":"Entrada de consumo en el CBP Form 7501","ru":"Декларация для потребления по CBP Form 7501","tr":"CBP Form 7501 üzerinde tüketim girişi (consumption entry)","hi":"CBP Form 7501 पर उपभोग एंट्री","ar":"بيان إدخال للاستهلاك على CBP Form 7501"}],"e":{"en":"Merchandise moving in bond through the United States for exportation at another port is entered as a transportation and exportation (T&E) entry on CBP Form 7512. See 19 CFR 18.20 et seq.; 19 CFR 141.0a.","es":"La mercancía que se mueve en tránsito aduanero a través de los Estados Unidos para su exportación en otro puerto se entra como una entrada de transporte y exportación (T&E) en el CBP Form 7512. Véase 19 CFR 18.20 y siguientes; 19 CFR 141.0a.","ru":"Товары, перемещаемые под таможенным контролем через территорию Соединённых Штатов для вывоза в другом порту, декларируются как декларация транспортировки и вывоза (T&E) по CBP Form 7512. См. 19 CFR 18.20 и далее; 19 CFR 141.0a.","tr":"Amerika Birleşik Devletleri içinden başka bir limanda ihraç edilmek üzere in-bond olarak taşınan mallar, CBP Form 7512 üzerinde bir transportation and exportation (T&E - taşıma ve ihracat) girişi olarak giriş beyanına tabi tutulur. Bkz. 19 CFR 18.20 vd.; 19 CFR 141.0a.","hi":"दूसरे बंदरगाह पर निर्यात के लिए संयुक्त राज्य अमेरिका के माध्यम से इन बॉन्ड स्थानांतरित होने वाला माल CBP Form 7512 पर परिवहन और निर्यात (T&E) एंट्री के रूप में प्रवेश किया जाता है। देखें 19 CFR 18.20 et seq.; 19 CFR 141.0a।","ar":"البضائع المنقولة بموجب سند عبر الولايات المتحدة بغرض التصدير من ميناء آخر تُدخَل كبيان إدخال نقل وتصدير (T&E) على CBP Form 7512. انظر 19 CFR 18.20 وما يليها؛ 19 CFR 141.0a."}},{"cat":"entry","a":0,"q":{"en":"A shipment of merchandise has an aggregate value of $2,200 and is not subject to any special restriction requiring formal entry. Which statement best describes its eligibility for informal entry?","es":"Un embarque de mercancía tiene un valor agregado de $2,200 y no está sujeto a ninguna restricción especial que requiera entrada formal. ¿Qué afirmación describe mejor su elegibilidad para entrada informal?","ru":"Партия товаров имеет совокупную стоимость $2,200 и не подпадает под какие-либо особые ограничения, требующие формального ввоза. Какое утверждение лучше всего описывает её право на неформальный ввоз?","tr":"Bir mal sevkiyatının toplam değeri $2,200'dür ve resmi giriş gerektiren herhangi bir özel kısıtlamaya tabi değildir. Hangi ifade, gayri resmi giriş (informal entry) için uygunluğunu en iyi şekilde tanımlar?","hi":"एक माल शिपमेंट का कुल मूल्य $2,200 है और यह किसी भी विशेष प्रतिबंध के अधीन नहीं है जिसके लिए औपचारिक प्रवेश आवश्यक हो। कौन सा कथन अनौपचारिक प्रवेश के लिए इसकी पात्रता का सबसे अच्छा वर्णन करता है?","ar":"تبلغ القيمة الإجمالية لشحنة من البضائع $2,200 وهي غير خاضعة لأي قيد خاص يتطلب الإدخال الرسمي. أي عبارة تصف بأفضل شكل أهليتها للإدخال غير الرسمي؟"},"o":[{"en":"It is eligible for informal entry because the value does not exceed $2,500","es":"Es elegible para entrada informal porque el valor no excede $2,500","ru":"Она имеет право на неформальный ввоз, поскольку стоимость не превышает $2,500","tr":"Gayri resmi giriş için uygundur, çünkü değeri $2,500'ü aşmamaktadır","hi":"यह अनौपचारिक प्रवेश के लिए पात्र है क्योंकि मूल्य $2,500 से अधिक नहीं है","ar":"هي مؤهلة للإدخال غير الرسمي لأن القيمة لا تتجاوز $2,500"},{"en":"It is ineligible for informal entry because it exceeds $800","es":"No es elegible para entrada informal porque excede $800","ru":"Она не имеет права на неформальный ввоз, поскольку превышает $800","tr":"Gayri resmi giriş için uygun değildir, çünkü $800'ü aşmaktadır","hi":"यह अनौपचारिक प्रवेश के लिए अपात्र है क्योंकि यह $800 से अधिक है","ar":"هي غير مؤهلة للإدخال غير الرسمي لأنها تتجاوز $800"},{"en":"It is eligible for informal entry only if the value does not exceed $2,000","es":"Es elegible para entrada informal solo si el valor no excede $2,000","ru":"Она имеет право на неформальный ввоз, только если стоимость не превышает $2,000","tr":"Yalnızca değeri $2,000'i aşmaması halinde gayri resmi giriş için uygundur","hi":"यह अनौपचारिक प्रवेश के लिए केवल तभी पात्र है जब मूल्य $2,000 से अधिक न हो","ar":"هي مؤهلة للإدخال غير الرسمي فقط إذا كانت القيمة لا تتجاوز $2,000"},{"en":"It must be formally entered because all commercial shipments require formal entry","es":"Debe entrarse formalmente porque todos los embarques comerciales requieren entrada formal","ru":"Она должна быть задекларирована формально, поскольку все коммерческие партии требуют формального ввоза","tr":"Resmi olarak giriş beyanına tabi tutulmalıdır, çünkü tüm ticari sevkiyatlar resmi giriş gerektirir","hi":"इसे औपचारिक रूप से प्रवेश किया जाना चाहिए क्योंकि सभी वाणिज्यिक शिपमेंट के लिए औपचारिक प्रवेश आवश्यक है","ar":"يجب إدخالها رسميًا لأن جميع الشحنات التجارية تتطلب الإدخال الرسمي"}],"e":{"en":"Shipments of merchandise not exceeding $2,500 in value generally may be entered under informal entry (subject to stated exceptions, such as certain Chapter 99 articles). See 19 CFR 143.21(a).","es":"Los embarques de mercancía cuyo valor no exceda $2,500 generalmente pueden entrarse bajo entrada informal (sujeto a las excepciones establecidas, como ciertos artículos del Capítulo 99). Véase 19 CFR 143.21(a).","ru":"Партии товаров стоимостью не более $2,500, как правило, могут декларироваться в порядке неформального ввоза (с учётом указанных исключений, таких как отдельные товары главы 99). См. 19 CFR 143.21(a).","tr":"Değeri $2,500'ü aşmayan mal sevkiyatları genel olarak gayri resmi giriş (informal entry) kapsamında giriş beyanına tabi tutulabilir (belirli Bölüm 99 ürünleri gibi belirtilen istisnalara tabi). Bkz. 19 CFR 143.21(a).","hi":"$2,500 मूल्य से अधिक नहीं वाले माल के शिपमेंट को आम तौर पर अनौपचारिक प्रवेश के तहत प्रवेश किया जा सकता है (बताए गए अपवादों के अधीन, जैसे कुछ Chapter 99 वस्तुएं)। देखें 19 CFR 143.21(a)।","ar":"الشحنات من البضائع التي لا تتجاوز قيمتها $2,500 يجوز عمومًا إدخالها بموجب الإدخال غير الرسمي (مع مراعاة الاستثناءات المذكورة، مثل بعض المواد في الفصل 99). انظر 19 CFR 143.21(a)."}},{"cat":"entry","a":3,"q":{"en":"Goods imported by a common carrier are consigned 'to order.' Which of the following will satisfy the evidence of the right to make entry for the consignee?","es":"Mercancía importada por un transportista público (common carrier) está consignada 'a la orden' (to order). ¿Cuál de los siguientes satisface la prueba del derecho a efectuar la entrada para el consignatario?","ru":"Товары, ввезённые общественным перевозчиком (common carrier), отгружены «по приказу» (to order). Что из перечисленного будет служить доказательством права на оформление таможенной декларации для грузополучателя?","tr":"Ortak bir taşıyıcı (common carrier) tarafından ithal edilen mallar 'to order' (emre) konsinye edilmiştir. Aşağıdakilerden hangisi, alıcı (consignee) için giriş beyanı yapma hakkının kanıtını sağlar?","hi":"एक सामान्य वाहक द्वारा आयातित माल 'टू ऑर्डर' परेषित किया गया है। निम्नलिखित में से कौन सा परेषिती के लिए प्रवेश करने के अधिकार के साक्ष्य को संतुष्ट करेगा?","ar":"البضائع المستوردة بواسطة ناقل عام تكون مرسَلة \"لأمر\" (to order). أي مما يلي يفي بإثبات حق إجراء الإدخال لصالح المرسَل إليه؟"},"o":[{"en":"A commercial invoice signed by the foreign seller","es":"Una factura comercial firmada por el vendedor extranjero","ru":"Коммерческий счёт-фактура, подписанный иностранным продавцом","tr":"Yabancı satıcı tarafından imzalanmış bir ticari fatura","hi":"विदेशी विक्रेता द्वारा हस्ताक्षरित एक वाणिज्यिक चालान","ar":"فاتورة تجارية موقّعة من البائع الأجنبي"},{"en":"Mere physical possession of the merchandise at the time of arrival","es":"La mera posesión física de la mercancía al momento de la llegada","ru":"Простое физическое владение товарами на момент прибытия","tr":"Varış anında malların yalnızca fiziksel zilyetliği","hi":"आगमन के समय माल का मात्र भौतिक कब्जा","ar":"مجرد الحيازة المادية للبضائع وقت الوصول"},{"en":"A power of attorney filed with the entry summary","es":"Un poder (power of attorney) presentado junto con el resumen de entrada","ru":"Доверенность (POA), поданная вместе с итоговой декларацией","tr":"Giriş özeti ile birlikte sunulan bir vekâletname (power of attorney)","hi":"एंट्री सारांश के साथ दाखिल की गई एक POA","ar":"توكيل رسمي (POA) مقدَّم مع ملخص الإدخال"},{"en":"A properly endorsed bill of lading or a carrier's certificate naming the consignee","es":"Un conocimiento de embarque debidamente endosado o un certificado del transportista (carrier's certificate) que nombre al consignatario","ru":"Надлежащим образом индоссированный коносамент или сертификат перевозчика с указанием грузополучателя","tr":"Alıcıyı (consignee) adlandıran, usulüne uygun ciro edilmiş bir konşimento veya taşıyıcı sertifikası","hi":"परेषिती को स्वामी या परेषिती के रूप में नामित करते हुए एक उचित रूप से पृष्ठांकित लदान बिल या वाहक का प्रमाणपत्र","ar":"بوليصة شحن مظهَّرة على النحو الصحيح أو شهادة ناقل تسمّي المرسَل إليه"}],"e":{"en":"For merchandise carried by a common carrier, the right to make entry is evidenced by a properly endorsed bill of lading or air waybill, or a carrier's certificate, naming the consignee as owner or consignee. See 19 CFR 141.11(a).","es":"Para mercancía transportada por un transportista público, el derecho a efectuar la entrada se acredita mediante un conocimiento de embarque o guía aérea debidamente endosado, o un certificado del transportista, que nombre al consignatario como propietario o consignatario. Véase 19 CFR 141.11(a).","ru":"Для товаров, перевозимых общественным перевозчиком, право на оформление таможенной декларации подтверждается надлежащим образом индоссированным коносаментом или авианакладной, либо сертификатом перевозчика, с указанием грузополучателя в качестве владельца или получателя. См. 19 CFR 141.11(a).","tr":"Ortak bir taşıyıcı tarafından taşınan mallar için, giriş beyanı yapma hakkı, alıcıyı (consignee) malik veya alıcı olarak adlandıran, usulüne uygun ciro edilmiş bir konşimento veya hava konşimentosu ya da bir taşıyıcı sertifikası ile kanıtlanır. Bkz. 19 CFR 141.11(a).","hi":"सामान्य वाहक द्वारा ले जाए गए माल के लिए, प्रवेश करने का अधिकार उचित रूप से पृष्ठांकित लदान बिल या एयर वेबिल, या वाहक के प्रमाणपत्र द्वारा प्रमाणित होता है, जो परेषिती को स्वामी या परेषिती के रूप में नामित करता है। देखें 19 CFR 141.11(a)।","ar":"بالنسبة للبضائع المنقولة بواسطة ناقل عام، يُثبَت حق إجراء الإدخال ببوليصة شحن أو وثيقة شحن جوي مظهَّرة على النحو الصحيح، أو بشهادة ناقل، تسمّي المرسَل إليه بصفته المالك أو المرسَل إليه. انظر 19 CFR 141.11(a)."}},{"cat":"entry","a":0,"q":{"en":"An entry is filed and the merchandise is released, but CBP neither liquidates the entry nor suspends or extends liquidation. By operation of law, when is the entry deemed liquidated?","es":"Se presenta una entrada y la mercancía se libera, pero CBP ni liquida la entrada ni suspende o prorroga la liquidación. Por ministerio de ley, ¿cuándo se considera liquidada la entrada?","ru":"Таможенная декларация подана, и товары выпущены, но CBP не производит ликвидацию (окончательный расчёт пошлин) декларации и не приостанавливает и не продлевает ликвидацию. В силу закона, когда декларация считается ликвидированной?","tr":"Bir giriş beyanı sunulur ve mallar serbest bırakılır, ancak CBP girişi ne kesinleştirir (liquidate eder) ne de kesinleştirmeyi askıya alır ya da uzatır. Kanun gereği, giriş ne zaman kesinleşmiş (liquidated) sayılır?","hi":"एक एंट्री दाखिल की जाती है और माल रिलीज कर दिया जाता है, लेकिन CBP न तो एंट्री का परिसमापन करता है और न ही परिसमापन को निलंबित या विस्तारित करता है। कानून के संचालन से, एंट्री को कब परिसमापित माना जाता है?","ar":"يُقدَّم بيان إدخال ويُفرَج عن البضائع، لكن CBP لا تُجري التصفية للبيان ولا تعلّق أو تمدّد التصفية. بحكم القانون، متى يُعتبر البيان مصفّى؟"},"o":[{"en":"One year from the date of entry, at the rate and amount asserted by the importer","es":"Un año a partir de la fecha de entrada, a la tasa y monto declarados por el importador","ru":"Через один год с даты ввоза, по ставке и в размере, заявленным импортёром","tr":"Giriş tarihinden itibaren bir yıl sonra, ithalatçı tarafından beyan edilen oran ve tutar üzerinden","hi":"प्रवेश की तारीख से एक वर्ष, आयातक द्वारा प्रतिपादित दर और राशि पर","ar":"بعد سنة واحدة من تاريخ الإدخال، بالمعدل والمقدار اللذين أكّدهما المستورد"},{"en":"90 days from the date of release, at the rate asserted by CBP","es":"90 días a partir de la fecha de liberación, a la tasa declarada por CBP","ru":"Через 90 дней с даты выпуска, по ставке, заявленной CBP","tr":"Serbest bırakma tarihinden itibaren 90 gün sonra, CBP tarafından beyan edilen oran üzerinden","hi":"रिलीज की तारीख से 90 दिन, CBP द्वारा प्रतिपादित दर पर","ar":"بعد 90 يومًا من تاريخ الإفراج، بالمعدل الذي أكّدته CBP"},{"en":"Four years from the date of entry, at the rate asserted by the importer","es":"Cuatro años a partir de la fecha de entrada, a la tasa declarada por el importador","ru":"Через четыре года с даты ввоза, по ставке, заявленной импортёром","tr":"Giriş tarihinden itibaren dört yıl sonra, ithalatçı tarafından beyan edilen oran üzerinden","hi":"प्रवेश की तारीख से चार वर्ष, आयातक द्वारा प्रतिपादित दर पर","ar":"بعد أربع سنوات من تاريخ الإدخال، بالمعدل الذي أكّده المستورد"},{"en":"Six months from the date the entry summary is filed","es":"Seis meses a partir de la fecha en que se presenta el resumen de entrada","ru":"Через шесть месяцев с даты подачи итоговой декларации","tr":"Giriş özetinin sunulduğu tarihten itibaren altı ay sonra","hi":"एंट्री सारांश दाखिल होने की तारीख से छह माह","ar":"بعد ستة أشهر من تاريخ تقديم ملخص الإدخال"}],"e":{"en":"An entry not liquidated within one year from the date of entry is deemed liquidated by operation of law at the rate, value, quantity, and amount of duties asserted by the importer, unless liquidation is properly extended or suspended. See 19 CFR 159.11(a).","es":"Una entrada no liquidada dentro de un año a partir de la fecha de entrada se considera liquidada por ministerio de ley a la tasa, valor, cantidad y monto de derechos declarados por el importador, a menos que la liquidación sea debidamente prorrogada o suspendida. Véase 19 CFR 159.11(a).","ru":"Декларация, не ликвидированная в течение одного года с даты ввоза, считается ликвидированной в силу закона по ставке, стоимости, количеству и размеру пошлин, заявленным импортёром, если только ликвидация не была надлежащим образом продлена или приостановлена. См. 19 CFR 159.11(a).","tr":"Giriş tarihinden itibaren bir yıl içinde kesinleştirilmeyen bir giriş, kesinleştirme usulüne uygun olarak uzatılmadıkça veya askıya alınmadıkça, ithalatçı tarafından beyan edilen oran, değer, miktar ve vergi tutarı üzerinden kanun gereği kesinleşmiş (liquidated) sayılır. Bkz. 19 CFR 159.11(a).","hi":"प्रवेश की तारीख से एक वर्ष के भीतर परिसमापित नहीं की गई एंट्री को कानून के संचालन से आयातक द्वारा प्रतिपादित दर, मूल्य, मात्रा और शुल्क की राशि पर परिसमापित माना जाता है, जब तक कि परिसमापन को उचित रूप से विस्तारित या निलंबित न किया गया हो। देखें 19 CFR 159.11(a)।","ar":"البيان الذي لا تتم تصفيته خلال سنة واحدة من تاريخ الإدخال يُعتبر مصفّى بحكم القانون بالمعدل والقيمة والكمية ومقدار الرسوم التي أكّدها المستورد، ما لم تُمدَّد التصفية أو تُعلَّق على النحو الصحيح. انظر 19 CFR 159.11(a)."}},{"cat":"entry","a":1,"q":{"en":"CBP extends the liquidation period on an entry because needed appraisement information is unavailable. Including the original period and all permitted extensions, what is the outside time limit after which the entry will be deemed liquidated by operation of law (absent a statutory suspension or court order)?","es":"CBP prorroga el período de liquidación de una entrada porque la información de avalúo necesaria no está disponible. Incluyendo el período original y todas las prórrogas permitidas, ¿cuál es el límite máximo de tiempo después del cual la entrada se considerará liquidada por ministerio de ley (en ausencia de una suspensión legal u orden judicial)?","ru":"CBP продлевает срок ликвидации по декларации, поскольку отсутствует необходимая информация для оценки. С учётом первоначального срока и всех допустимых продлений, каков предельный срок, по истечении которого декларация будет считаться ликвидированной в силу закона (при отсутствии приостановления, предусмотренного законом, или судебного постановления)?","tr":"Gerekli takdir (appraisement) bilgileri mevcut olmadığından CBP, bir girişteki kesinleştirme (liquidation) süresini uzatır. Orijinal süre ve izin verilen tüm uzatmalar dahil olmak üzere, girişin (yasal bir askıya alma veya mahkeme kararı olmaksızın) kanun gereği kesinleşmiş sayılacağı azami süre sınırı nedir?","hi":"आवश्यक मूल्यांकन जानकारी अनुपलब्ध होने के कारण CBP एक एंट्री पर परिसमापन अवधि को विस्तारित करता है। मूल अवधि और सभी अनुमत विस्तारों सहित, वह बाहरी समय सीमा क्या है जिसके बाद एंट्री को कानून के संचालन से परिसमापित माना जाएगा (किसी वैधानिक निलंबन या अदालती आदेश के अभाव में)?","ar":"تُمدِّد CBP مدة التصفية لبيان إدخال لأن المعلومات اللازمة للتقدير غير متاحة. بما في ذلك المدة الأصلية وجميع التمديدات المسموح بها، ما هو الحد الزمني الأقصى الذي يُعتبر بعده البيان مصفّى بحكم القانون (في غياب تعليق قانوني أو أمر محكمة)؟"},"o":[{"en":"Three years from the date of entry","es":"Tres años a partir de la fecha de entrada","ru":"Три года с даты ввоза","tr":"Giriş tarihinden itibaren üç yıl","hi":"प्रवेश की तारीख से तीन वर्ष","ar":"ثلاث سنوات من تاريخ الإدخال"},{"en":"Four years from the date of entry","es":"Cuatro años a partir de la fecha de entrada","ru":"Четыре года с даты ввоза","tr":"Giriş tarihinden itibaren dört yıl","hi":"प्रवेश की तारीख से चार वर्ष","ar":"أربع سنوات من تاريخ الإدخال"},{"en":"Two years from the date of entry","es":"Dos años a partir de la fecha de entrada","ru":"Два года с даты ввоза","tr":"Giriş tarihinden itibaren iki yıl","hi":"प्रवेश की तारीख से दो वर्ष","ar":"سنتان من تاريخ الإدخال"},{"en":"Five years from the date of entry","es":"Cinco años a partir de la fecha de entrada","ru":"Пять лет с даты ввоза","tr":"Giriş tarihinden itibaren beş yıl","hi":"प्रवेश की तारीख से पांच वर्ष","ar":"خمس سنوات من تاريخ الإدخال"}],"e":{"en":"Liquidation may be extended for additional periods, but an entry not liquidated within four years from the date of entry is deemed liquidated by operation of law unless suspension is required by statute or court order. See 19 CFR 159.12(e) and (f).","es":"La liquidación puede prorrogarse por períodos adicionales, pero una entrada no liquidada dentro de cuatro años a partir de la fecha de entrada se considera liquidada por ministerio de ley, a menos que la suspensión sea requerida por ley u orden judicial. Véase 19 CFR 159.12(e) y (f).","ru":"Ликвидация может быть продлена на дополнительные периоды, но декларация, не ликвидированная в течение четырёх лет с даты ввоза, считается ликвидированной в силу закона, если только приостановление не требуется по закону или по судебному постановлению. См. 19 CFR 159.12(e) и (f).","tr":"Kesinleştirme ilave dönemler için uzatılabilir, ancak giriş tarihinden itibaren dört yıl içinde kesinleştirilmeyen bir giriş, kanun veya mahkeme kararı ile askıya alma gerekmedikçe kanun gereği kesinleşmiş sayılır. Bkz. 19 CFR 159.12(e) ve (f).","hi":"परिसमापन को अतिरिक्त अवधियों के लिए विस्तारित किया जा सकता है, लेकिन प्रवेश की तारीख से चार वर्ष के भीतर परिसमापित नहीं की गई एंट्री को कानून के संचालन से परिसमापित माना जाता है, जब तक कि क़ानून या अदालती आदेश द्वारा निलंबन आवश्यक न हो। देखें 19 CFR 159.12(e) और (f)।","ar":"يجوز تمديد التصفية لفترات إضافية، لكن البيان الذي لا تتم تصفيته خلال أربع سنوات من تاريخ الإدخال يُعتبر مصفّى بحكم القانون ما لم يكن التعليق مطلوبًا بموجب قانون أو أمر محكمة. انظر 19 CFR 159.12(e) و(f)."}},{"cat":"entry","a":1,"q":{"en":"Records pertaining to an importation that are subject to the recordkeeping requirements (the (a)(1)(A) list) must be retained by the importer for what period?","es":"Los registros relativos a una importación que están sujetos a los requisitos de conservación de registros (la lista (a)(1)(A)) deben ser conservados por el importador, ¿por cuánto tiempo?","ru":"Документы, относящиеся к импортированию, на которые распространяются требования о хранении документации (перечень (a)(1)(A)), должны храниться импортёром в течение какого срока?","tr":"Kayıt tutma gerekliliklerine (the (a)(1)(A) list) tabi olan, bir ithalata ilişkin kayıtlar, ithalatçı tarafından ne kadar süre saklanmalıdır?","hi":"रिकॉर्डकीपिंग आवश्यकताओं ((a)(1)(A) सूची) के अधीन किसी आयात से संबंधित रिकॉर्ड को आयातक द्वारा कितनी अवधि तक रखा जाना चाहिए?","ar":"السجلات المتعلقة بعملية استيراد والخاضعة لمتطلبات حفظ السجلات (قائمة (a)(1)(A)) يجب أن يحتفظ بها المستورد لأي مدة؟"},"o":[{"en":"3 years from the date of entry","es":"3 años a partir de la fecha de entrada","ru":"3 года с даты ввоза","tr":"Giriş tarihinden itibaren 3 yıl","hi":"प्रवेश की तारीख से 3 वर्ष","ar":"3 سنوات من تاريخ الإدخال"},{"en":"5 years from the date of entry","es":"5 años a partir de la fecha de entrada","ru":"5 лет с даты ввоза","tr":"Giriş tarihinden itibaren 5 yıl","hi":"प्रवेश की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ الإدخال"},{"en":"5 years from the date of liquidation","es":"5 años a partir de la fecha de liquidación","ru":"5 лет с даты ликвидации","tr":"Kesinleştirme (liquidation) tarihinden itibaren 5 yıl","hi":"परिसमापन की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ التصفية"},{"en":"7 years from the date of importation","es":"7 años a partir de la fecha de importación","ru":"7 лет с даты импортирования","tr":"İthalat tarihinden itibaren 7 yıl","hi":"आयात की तारीख से 7 वर्ष","ar":"7 سنوات من تاريخ الاستيراد"}],"e":{"en":"Records relating to an entry generally must be kept for 5 years from the date of entry (drawback records are measured differently). See 19 CFR 163.4(a).","es":"Los registros relativos a una entrada generalmente deben conservarse por 5 años a partir de la fecha de entrada (los registros de drawback se miden de forma diferente). Véase 19 CFR 163.4(a).","ru":"Документы, относящиеся к таможенной декларации, как правило, должны храниться в течение 5 лет с даты ввоза (для документов по возврату пошлин (drawback) срок исчисляется иначе). См. 19 CFR 163.4(a).","tr":"Bir girişe ilişkin kayıtlar genel olarak giriş tarihinden itibaren 5 yıl süreyle saklanmalıdır (drawback - gümrük vergisi iadesi kayıtları farklı şekilde ölçülür). Bkz. 19 CFR 163.4(a).","hi":"किसी एंट्री से संबंधित रिकॉर्ड आम तौर पर प्रवेश की तारीख से 5 वर्ष तक रखे जाने चाहिए (ड्रॉबैक (शुल्क वापसी) रिकॉर्ड को अलग ढंग से मापा जाता है)। देखें 19 CFR 163.4(a)।","ar":"يجب عمومًا حفظ السجلات المتعلقة ببيان الإدخال لمدة 5 سنوات من تاريخ الإدخال (تُقاس سجلات استرداد الرسوم (drawback) بشكل مختلف). انظر 19 CFR 163.4(a)."}},{"cat":"entry","a":0,"q":{"en":"When an entry summary is filed at the time of entry and serves as both the entry and the entry summary documentation, when does the 'time of entry' occur?","es":"Cuando un resumen de entrada se presenta al momento de la entrada y sirve como documentación tanto de la entrada como del resumen de entrada, ¿cuándo ocurre el 'momento de la entrada' (time of entry)?","ru":"Когда итоговая декларация подаётся в момент ввоза и служит одновременно и декларацией, и документацией итоговой декларации, когда наступает «момент ввоза»?","tr":"Bir giriş özeti giriş anında sunulduğunda ve hem giriş beyanı hem de giriş özeti belgesi olarak hizmet ettiğinde, 'giriş anı' ne zaman gerçekleşir?","hi":"जब एंट्री सारांश प्रवेश के समय दाखिल किया जाता है और एंट्री तथा एंट्री सारांश दस्तावेज़ीकरण दोनों के रूप में कार्य करता है, तो 'प्रवेश का समय' कब होता है?","ar":"عندما يُقدَّم ملخص الإدخال وقت الإدخال ويُستخدَم بوصفه مستند بيان الإدخال وملخص الإدخال معًا، متى يقع \"وقت الإدخال\"؟"},"o":[{"en":"When the entry summary is filed in proper form with estimated duties attached","es":"Cuando el resumen de entrada se presenta en debida forma con los derechos estimados adjuntos","ru":"Когда итоговая декларация подана в надлежащей форме с приложенными расчётными пошлинами","tr":"Giriş özeti, tahmini vergiler ekli olarak usulüne uygun biçimde sunulduğunda","hi":"जब एंट्री सारांश अनुमानित शुल्कों के साथ उचित रूप में दाखिल किया जाता है","ar":"عندما يُقدَّم ملخص الإدخال بالصيغة الصحيحة مع إرفاق الرسوم التقديرية"},{"en":"When the merchandise physically arrives within the limits of the port","es":"Cuando la mercancía llega físicamente dentro de los límites del puerto","ru":"Когда товары физически прибывают в пределы порта","tr":"Mallar fiziksel olarak liman sınırları içine vardığında","hi":"जब माल भौतिक रूप से बंदरगाह की सीमाओं के भीतर पहुंचता है","ar":"عندما تصل البضائع ماديًا إلى داخل حدود الميناء"},{"en":"When CBP authorizes release of the merchandise on Form 3461","es":"Cuando CBP autoriza la liberación de la mercancía en el Form 3461","ru":"Когда CBP разрешает выпуск товаров по Form 3461","tr":"CBP, Form 3461 üzerinde malların serbest bırakılmasına izin verdiğinde","hi":"जब CBP Form 3461 पर माल की रिलीज को अधिकृत करता है","ar":"عندما تأذن CBP بالإفراج عن البضائع على Form 3461"},{"en":"When the carrier files the manifest with CBP","es":"Cuando el transportista presenta el manifiesto ante CBP","ru":"Когда перевозчик подаёт манифест в CBP","tr":"Taşıyıcı manifestoyu CBP'ye sunduğunda","hi":"जब वाहक CBP के पास मेनिफेस्ट दाखिल करता है","ar":"عندما يقدّم الناقل البيان الجمركي (manifest) إلى CBP"}],"e":{"en":"When the entry summary serves as both entry and entry summary documentation under 19 CFR 142.3(b), the time of entry is when the entry summary is filed in proper form with estimated duties attached. See 19 CFR 141.68(b).","es":"Cuando el resumen de entrada sirve como documentación tanto de la entrada como del resumen de entrada conforme a 19 CFR 142.3(b), el momento de la entrada es cuando el resumen de entrada se presenta en debida forma con los derechos estimados adjuntos. Véase 19 CFR 141.68(b).","ru":"Когда итоговая декларация служит одновременно декларацией и документацией итоговой декларации согласно 19 CFR 142.3(b), моментом ввоза является момент подачи итоговой декларации в надлежащей форме с приложенными расчётными пошлинами. См. 19 CFR 141.68(b).","tr":"Giriş özeti, 19 CFR 142.3(b) kapsamında hem giriş beyanı hem de giriş özeti belgesi olarak hizmet ettiğinde, giriş anı, giriş özetinin tahmini vergiler ekli olarak usulüne uygun biçimde sunulduğu andır. Bkz. 19 CFR 141.68(b).","hi":"जब एंट्री सारांश 19 CFR 142.3(b) के तहत एंट्री और एंट्री सारांश दस्तावेज़ीकरण दोनों के रूप में कार्य करता है, तो प्रवेश का समय वह होता है जब एंट्री सारांश अनुमानित शुल्कों के साथ उचित रूप में दाखिल किया जाता है। देखें 19 CFR 141.68(b)।","ar":"عندما يُستخدَم ملخص الإدخال بوصفه مستند بيان الإدخال وملخص الإدخال معًا بموجب 19 CFR 142.3(b)، يكون وقت الإدخال هو وقت تقديم ملخص الإدخال بالصيغة الصحيحة مع إرفاق الرسوم التقديرية. انظر 19 CFR 141.68(b)."}},{"cat":"entry","a":3,"q":{"en":"Which of the following is NOT among the documentation generally required to be filed to obtain release of merchandise under an entry (CBP Form 3461)?","es":"¿Cuál de los siguientes NO está entre la documentación que generalmente se requiere presentar para obtener la liberación de mercancía bajo una entrada (CBP Form 3461)?","ru":"Что из перечисленного НЕ входит в число документов, которые, как правило, требуется подать для получения выпуска товаров по таможенной декларации (CBP Form 3461)?","tr":"Aşağıdakilerden hangisi, bir giriş (CBP Form 3461) kapsamında malların serbest bırakılmasını sağlamak için genel olarak sunulması gereken belgeler arasında YER ALMAZ?","hi":"निम्नलिखित में से कौन सा उस दस्तावेज़ीकरण में शामिल नहीं है जो आम तौर पर एंट्री (CBP Form 3461) के तहत माल की रिलीज प्राप्त करने के लिए दाखिल करना आवश्यक है?","ar":"أي مما يلي ليس من بين المستندات المطلوب عمومًا تقديمها للحصول على الإفراج عن البضائع بموجب بيان الإدخال (CBP Form 3461)؟"},"o":[{"en":"Evidence of the right to make entry","es":"Prueba del derecho a efectuar la entrada","ru":"Доказательство права на оформление таможенной декларации","tr":"Giriş beyanı yapma hakkının kanıtı","hi":"प्रवेश करने के अधिकार का साक्ष्य","ar":"إثبات حق إجراء الإدخال"},{"en":"A commercial invoice or an acceptable substitute","es":"Una factura comercial o un sustituto aceptable","ru":"Коммерческий счёт-фактура или приемлемая замена","tr":"Bir ticari fatura veya kabul edilebilir bir muadili","hi":"एक वाणिज्यिक चालान या एक स्वीकार्य विकल्प","ar":"فاتورة تجارية أو بديل مقبول عنها"},{"en":"Packing list, where appropriate","es":"Lista de empaque, cuando corresponda","ru":"Упаковочный лист, где это уместно","tr":"Uygun olduğu hallerde çeki listesi (packing list)","hi":"पैकिंग सूची, जहां उपयुक्त हो","ar":"قائمة التعبئة، حيثما كان ذلك مناسبًا"},{"en":"A final, paid record of the actual ocean freight charges","es":"Un registro final y pagado de los cargos reales de flete marítimo","ru":"Окончательная, оплаченная запись о фактических расходах на морской фрахт","tr":"Gerçek deniz navlun masraflarının nihai, ödenmiş kaydı","hi":"वास्तविक समुद्री माल भाड़ा शुल्कों का एक अंतिम, भुगतान किया गया रिकॉर्ड","ar":"سجل نهائي مدفوع لرسوم الشحن البحري الفعلية"}],"e":{"en":"Entry documentation required for release includes the entry form, evidence of the right to make entry, a commercial invoice (or acceptable substitute), a packing list where appropriate, and other required documents; a paid record of actual freight charges is not required for release. See 19 CFR 142.3(a).","es":"La documentación de entrada requerida para la liberación incluye el formulario de entrada, la prueba del derecho a efectuar la entrada, una factura comercial (o sustituto aceptable), una lista de empaque cuando corresponda y otros documentos requeridos; un registro pagado de los cargos reales de flete no se requiere para la liberación. Véase 19 CFR 142.3(a).","ru":"Документация для получения выпуска включает форму декларации, доказательство права на оформление таможенной декларации, коммерческий счёт-фактуру (или приемлемую замену), упаковочный лист, где это уместно, и другие необходимые документы; оплаченная запись о фактических расходах на фрахт для выпуска не требуется. См. 19 CFR 142.3(a).","tr":"Serbest bırakma için gereken giriş belgeleri arasında giriş formu, giriş beyanı yapma hakkının kanıtı, bir ticari fatura (veya kabul edilebilir muadili), uygun olduğu hallerde bir çeki listesi ve diğer gerekli belgeler bulunur; gerçek navlun masraflarının ödenmiş kaydı serbest bırakma için gerekli değildir. Bkz. 19 CFR 142.3(a).","hi":"रिलीज के लिए आवश्यक एंट्री दस्तावेज़ीकरण में एंट्री फॉर्म, प्रवेश करने के अधिकार का साक्ष्य, एक वाणिज्यिक चालान (या स्वीकार्य विकल्प), जहां उपयुक्त हो वहां पैकिंग सूची, और अन्य आवश्यक दस्तावेज़ शामिल हैं; वास्तविक माल भाड़ा शुल्कों का भुगतान किया गया रिकॉर्ड रिलीज के लिए आवश्यक नहीं है। देखें 19 CFR 142.3(a)।","ar":"تشمل مستندات الإدخال المطلوبة للإفراج نموذج الإدخال، وإثبات حق إجراء الإدخال، وفاتورة تجارية (أو بديل مقبول)، وقائمة تعبئة حيثما كان ذلك مناسبًا، وغيرها من المستندات المطلوبة؛ أما السجل المدفوع لرسوم الشحن الفعلية فليس مطلوبًا للإفراج. انظر 19 CFR 142.3(a)."}},{"cat":"entry","a":2,"q":{"en":"A broker transmits entry data to CBP through the Automated Broker Interface (ABI). Which statement best characterizes ABI and ACE in the entry process?","es":"Un agente aduanal transmite datos de entrada a CBP a través de la Automated Broker Interface (ABI). ¿Qué afirmación caracteriza mejor a ABI y ACE en el proceso de entrada?","ru":"Брокер передаёт данные таможенной декларации в CBP через автоматизированный брокерский интерфейс (ABI). Какое утверждение лучше всего характеризует ABI и ACE в процессе ввоза?","tr":"Bir gümrük müşaviri, giriş verilerini Automated Broker Interface (ABI) aracılığıyla CBP'ye iletir. Hangi ifade, giriş sürecinde ABI ve ACE'yi en iyi şekilde tanımlar?","hi":"एक ब्रोकर Automated Broker Interface (ABI) के माध्यम से CBP को एंट्री डेटा प्रेषित करता है। कौन सा कथन प्रवेश प्रक्रिया में ABI और ACE की सबसे अच्छी विशेषता बताता है?","ar":"يرسل وسيط بيانات الإدخال إلى CBP عبر واجهة الوسيط الآلية (ABI). أي عبارة تصف بأفضل شكل ABI وACE في عملية الإدخال؟"},"o":[{"en":"ABI is a paper-only backup used when ACE is unavailable","es":"ABI es un respaldo solo en papel que se usa cuando ACE no está disponible","ru":"ABI — это только бумажный резерв, используемый, когда ACE недоступен","tr":"ABI, yalnızca ACE kullanılamadığında kullanılan, kağıt tabanlı bir yedektir","hi":"ABI एक केवल-कागज वाला बैकअप है जिसका उपयोग तब किया जाता है जब ACE अनुपलब्ध हो","ar":"ABI هو نسخة احتياطية ورقية فقط تُستخدَم عندما يكون ACE غير متاح"},{"en":"ABI may be used only for informal entries, while ACE handles formal entries","es":"ABI puede usarse solo para entradas informales, mientras que ACE maneja las entradas formales","ru":"ABI может использоваться только для неформального ввоза, тогда как ACE обрабатывает формальный ввоз","tr":"ABI yalnızca gayri resmi girişler için kullanılabilir, ACE ise resmi girişleri ele alır","hi":"ABI का उपयोग केवल अनौपचारिक प्रवेशों के लिए किया जा सकता है, जबकि ACE औपचारिक प्रवेशों को संभालता है","ar":"يمكن استخدام ABI للإدخالات غير الرسمية فقط، بينما يتولى ACE الإدخالات الرسمية"},{"en":"ABI is the electronic system through which entry and entry summary data are transmitted to CBP, and ACE is CBP's system of record for processing that data","es":"ABI es el sistema electrónico a través del cual los datos de entrada y de resumen de entrada se transmiten a CBP, y ACE es el sistema de registro (system of record) de CBP para procesar esos datos","ru":"ABI — это электронная система, через которую данные декларации и итоговой декларации передаются в CBP, а ACE — это система учёта CBP для обработки этих данных","tr":"ABI, giriş ve giriş özeti verilerinin CBP'ye iletildiği elektronik sistemdir; ACE ise bu verilerin işlenmesi için CBP'nin kayıt sistemidir","hi":"ABI वह इलेक्ट्रॉनिक प्रणाली है जिसके माध्यम से एंट्री और एंट्री सारांश डेटा CBP को प्रेषित किया जाता है, और ACE उस डेटा के प्रसंस्करण के लिए CBP की रिकॉर्ड प्रणाली है","ar":"ABI هو النظام الإلكتروني الذي تُرسَل من خلاله بيانات الإدخال وملخص الإدخال إلى CBP، وACE هو نظام السجل لدى CBP لمعالجة تلك البيانات"},{"en":"ABI and ACE are interchangeable names for the carrier's manifest system","es":"ABI y ACE son nombres intercambiables del sistema de manifiestos del transportista","ru":"ABI и ACE — взаимозаменяемые названия системы манифестов перевозчика","tr":"ABI ve ACE, taşıyıcının manifesto sistemi için birbirinin yerine kullanılan adlardır","hi":"ABI और ACE वाहक की मेनिफेस्ट प्रणाली के लिए परस्पर बदले जा सकने वाले नाम हैं","ar":"ABI وACE اسمان مترادفان لنظام البيان الجمركي (manifest) الخاص بالناقل"}],"e":{"en":"The Automated Broker Interface (ABI) is the electronic interface filers use to transmit entry and entry summary data to CBP's Automated Commercial Environment (ACE), CBP's system of record. See 19 CFR 143.0 et seq. (Part 143, Subpart A) and 19 CFR 141.0a (electronic submission references).","es":"La Automated Broker Interface (ABI) es la interfaz electrónica que los declarantes usan para transmitir datos de entrada y de resumen de entrada al Automated Commercial Environment (ACE) de CBP, el sistema de registro de CBP. Véase 19 CFR 143.0 y siguientes (Parte 143, Subparte A) y 19 CFR 141.0a (referencias de presentación electrónica).","ru":"Автоматизированный брокерский интерфейс (ABI) — это электронный интерфейс, который податели используют для передачи данных декларации и итоговой декларации в автоматизированную коммерческую среду (ACE) CBP — систему учёта CBP. См. 19 CFR 143.0 и далее (часть 143, подраздел A) и 19 CFR 141.0a (ссылки на электронную подачу).","tr":"Automated Broker Interface (ABI), beyan sahiplerinin giriş ve giriş özeti verilerini CBP'nin kayıt sistemi olan Automated Commercial Environment (ACE) ortamına iletmek için kullandıkları elektronik arayüzdür. Bkz. 19 CFR 143.0 vd. (Part 143, Subpart A) ve 19 CFR 141.0a (elektronik sunum referansları).","hi":"Automated Broker Interface (ABI) वह इलेक्ट्रॉनिक इंटरफ़ेस है जिसका उपयोग फाइलर्स CBP के Automated Commercial Environment (ACE), जो CBP की रिकॉर्ड प्रणाली है, को एंट्री और एंट्री सारांश डेटा प्रेषित करने के लिए करते हैं। देखें 19 CFR 143.0 et seq. (Part 143, Subpart A) और 19 CFR 141.0a (इलेक्ट्रॉनिक प्रस्तुति संदर्भ)।","ar":"إن واجهة الوسيط الآلية (ABI) هي الواجهة الإلكترونية التي يستخدمها مقدّمو البيانات لإرسال بيانات الإدخال وملخص الإدخال إلى البيئة التجارية الآلية لدى CBP (ACE)، وهو نظام السجل لدى CBP. انظر 19 CFR 143.0 وما يليها (Part 143, Subpart A) و19 CFR 141.0a (مراجع التقديم الإلكتروني)."}},{"cat":"classification","a":0,"q":{"en":"When classifying goods under the HTSUS, in what order must the General Rules of Interpretation (GRI 1 through 6) generally be applied?","es":"Al clasificar mercancías bajo el HTSUS, ¿en qué orden deben aplicarse generalmente las Reglas Generales de Interpretación (GRI 1 a 6)?","ru":"При классификации товаров по HTSUS в каком порядке, как правило, должны применяться Основные правила интерпретации (GRI с 1 по 6)?","tr":"HTSUS kapsamında malları sınıflandırırken, Yorum Genel Kuralları (GRI 1 ila 6) genel olarak hangi sırada uygulanmalıdır?","hi":"HTSUS के तहत माल को वर्गीकृत करते समय, व्याख्या के सामान्य नियम (GRI 1 से 6) आम तौर पर किस क्रम में लागू किए जाने चाहिए?","ar":"عند تصنيف البضائع بموجب HTSUS، بأي ترتيب يجب عمومًا تطبيق القواعد العامة للتفسير (GRI 1 إلى 6)؟"},"o":[{"en":"In sequential order, so a later rule is reached only when the preceding rules do not resolve the classification","es":"En orden secuencial, de modo que se llega a una regla posterior solo cuando las reglas precedentes no resuelven la clasificación","ru":"В последовательном порядке, так что последующее правило применяется только тогда, когда предыдущие правила не разрешают классификацию","tr":"Sıralı düzende, böylece sonraki bir kurala ancak önceki kurallar sınıflandırmayı çözmediğinde başvurulur","hi":"अनुक्रमिक क्रम में, ताकि बाद के नियम तक तभी पहुंचा जाए जब पूर्ववर्ती नियम वर्गीकरण का समाधान न करें","ar":"بترتيب تسلسلي، بحيث لا يُلجأ إلى قاعدة لاحقة إلا عندما لا تحسم القواعد السابقة التصنيف"},{"en":"In any order, choosing whichever rule produces the lowest duty rate","es":"En cualquier orden, eligiendo la regla que produzca la tasa de derecho más baja","ru":"В любом порядке, выбирая то правило, которое даёт наименьшую ставку пошлины","tr":"Herhangi bir sırada, en düşük vergi oranını üreten kural seçilerek","hi":"किसी भी क्रम में, जो भी नियम सबसे कम शुल्क दर उत्पन्न करे उसे चुनते हुए","ar":"بأي ترتيب، باختيار القاعدة التي تنتج أدنى معدل رسوم"},{"en":"Beginning with GRI 3(b) because essential character is the most common basis for classification","es":"Comenzando con la GRI 3(b) porque el carácter esencial es la base más común de clasificación","ru":"Начиная с GRI 3(b), поскольку основной характер является наиболее распространённым основанием для классификации","tr":"En sık karşılaşılan sınıflandırma temeli esas nitelik olduğundan GRI 3(b) ile başlanarak","hi":"GRI 3(b) से शुरू करते हुए क्योंकि आवश्यक चरित्र वर्गीकरण का सबसे आम आधार है","ar":"بدءًا من GRI 3(b) لأن الطابع الأساسي هو الأساس الأكثر شيوعًا للتصنيف"},{"en":"GRI 6 first to fix the subheading, then GRI 1 through 5 to confirm the heading","es":"La GRI 6 primero para fijar la subpartida, luego la GRI 1 a 5 para confirmar la partida","ru":"Сначала GRI 6, чтобы определить субпозицию, затем GRI с 1 по 5, чтобы подтвердить позицию","tr":"Önce alt pozisyonu (subheading) belirlemek için GRI 6, ardından pozisyonu (heading) teyit etmek için GRI 1 ila 5","hi":"पहले GRI 6 शीर्षक उपशीर्षक तय करने के लिए, फिर GRI 1 से 5 शीर्षक की पुष्टि करने के लिए","ar":"GRI 6 أولًا لتحديد البند الفرعي، ثم GRI 1 إلى 5 لتأكيد البند"}],"e":{"en":"The GRIs are hierarchical and applied in sequence; one moves to the next rule only if the prior rule does not settle the matter. GRI 1 is applied first, and the others are reached only as needed. (GRI 1; structure of the General Rules of Interpretation.)","es":"Las GRI son jerárquicas y se aplican en secuencia; se pasa a la siguiente regla solo si la regla anterior no resuelve el asunto. La GRI 1 se aplica primero, y las demás se alcanzan solo según sea necesario. (GRI 1; estructura de las Reglas Generales de Interpretación.)","ru":"Правила GRI имеют иерархический характер и применяются последовательно; к следующему правилу переходят только в том случае, если предыдущее правило не разрешает вопрос. GRI 1 применяется первым, а остальные применяются только по мере необходимости. (GRI 1; структура Основных правил интерпретации.)","tr":"GRI'lar hiyerarşiktir ve sırayla uygulanır; bir sonraki kurala ancak önceki kural meseleyi çözmediğinde geçilir. Önce GRI 1 uygulanır ve diğerlerine yalnızca gerektiğinde başvurulur. (GRI 1; Yorum Genel Kuralları'nın yapısı.)","hi":"GRI पदानुक्रमिक हैं और क्रम में लागू किए जाते हैं; अगले नियम पर तभी जाया जाता है जब पूर्व नियम मामले को सुलझाता नहीं है। GRI 1 पहले लागू किया जाता है, और अन्य तक केवल आवश्यकता पड़ने पर ही पहुंचा जाता है। (GRI 1; व्याख्या के सामान्य नियमों की संरचना।)","ar":"إن قواعد GRI هرمية وتُطبَّق بالتسلسل؛ ولا يُنتقل إلى القاعدة التالية إلا إذا لم تحسم القاعدة السابقة المسألة. تُطبَّق GRI 1 أولًا، ولا يُلجأ إلى الأخرى إلا عند الحاجة. (GRI 1؛ بنية القواعد العامة للتفسير.)"}},{"cat":"classification","a":3,"q":{"en":"Under GRI 1, what controls classification at the four-digit heading level?","es":"Bajo la GRI 1, ¿qué rige la clasificación a nivel de partida de cuatro dígitos?","ru":"Согласно GRI 1, что определяет классификацию на уровне четырёхзначной позиции?","tr":"GRI 1 kapsamında, dört haneli pozisyon (heading) düzeyinde sınıflandırmayı ne belirler?","hi":"GRI 1 के तहत, चार-अंकीय शीर्षक स्तर पर वर्गीकरण को क्या नियंत्रित करता है?","ar":"بموجب GRI 1، ما الذي يتحكم في التصنيف عند مستوى البند المكوّن من أربعة أرقام؟"},"o":[{"en":"The commercial name the importer assigns to the merchandise on the commercial invoice","es":"El nombre comercial que el importador asigna a la mercancía en la factura comercial","ru":"Коммерческое название, которое импортёр присваивает товарам в коммерческом счёте-фактуре","tr":"İthalatçının ticari faturada mallara atadığı ticari isim","hi":"वह वाणिज्यिक नाम जो आयातक वाणिज्यिक चालान पर माल को निर्दिष्ट करता है","ar":"الاسم التجاري الذي يطلقه المستورد على البضائع في الفاتورة التجارية"},{"en":"The essential character of the article as determined by its most valuable component","es":"El carácter esencial del artículo determinado por su componente más valioso","ru":"Основной характер изделия, определяемый его наиболее ценным компонентом","tr":"Ürünün en değerli bileşeniyle belirlenen esas niteliği","hi":"सबसे मूल्यवान घटक द्वारा निर्धारित वस्तु का आवश्यक चरित्र","ar":"الطابع الأساسي للصنف كما يحدده مكوّنه الأعلى قيمةً"},{"en":"The principal use of goods of the same class or kind in the United States","es":"El uso principal de mercancías de la misma clase o tipo en los Estados Unidos","ru":"Основное использование товаров того же класса или вида в Соединённых Штатах","tr":"Aynı sınıf veya türdeki malların Amerika Birleşik Devletleri'ndeki başlıca kullanımı (principal use)","hi":"संयुक्त राज्य अमेरिका में समान वर्ग या प्रकार के माल का प्रमुख उपयोग","ar":"الاستخدام الرئيسي للبضائع من نفس الصنف أو النوع في الولايات المتحدة"},{"en":"The terms of the headings and any relative section or chapter notes","es":"Los términos de las partidas y cualquier nota relativa de sección o capítulo","ru":"Тексты позиций и любые относящиеся к ним примечания к разделам или главам","tr":"Pozisyonların (heading) ifadeleri ve ilgili herhangi bir bölüm veya fasıl notu","hi":"शीर्षकों की शर्तें और कोई भी संबंधित खंड या अध्याय टिप्पणियां","ar":"نصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة"}],"e":{"en":"GRI 1 states that classification is determined according to the terms of the headings and any relative section or chapter notes; titles of sections, chapters and subchapters are provided for ease of reference only and have no legal force. (GRI 1.)","es":"La GRI 1 establece que la clasificación se determina conforme a los términos de las partidas y cualquier nota relativa de sección o capítulo; los títulos de secciones, capítulos y subcapítulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal. (GRI 1.)","ru":"GRI 1 устанавливает, что классификация определяется в соответствии с текстами позиций и любыми относящимися к ним примечаниями к разделам или главам; названия разделов, глав и подглав приводятся только для удобства ссылок и не имеют юридической силы. (GRI 1.)","tr":"GRI 1, sınıflandırmanın pozisyonların (heading) ifadelerine ve ilgili herhangi bir bölüm veya fasıl notuna göre belirlendiğini belirtir; bölümlerin, fasılların ve alt fasılların başlıkları yalnızca kolay referans amacıyla verilmiştir ve hukuki bir bağlayıcılığı yoktur. (GRI 1.)","hi":"GRI 1 कहता है कि वर्गीकरण शीर्षकों की शर्तों और किसी भी संबंधित खंड या अध्याय टिप्पणियों के अनुसार निर्धारित होता है; खंडों, अध्यायों और उप-अध्यायों के शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है। (GRI 1.)","ar":"تنص GRI 1 على أن التصنيف يُحدَّد وفقًا لنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة؛ أما عناوين الأقسام والفصول والفصول الفرعية فهي مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية. (GRI 1.)"}},{"cat":"classification","a":2,"q":{"en":"A complete bicycle is imported disassembled in a single shipment, with all frame tubes, wheels, chain, and handlebars packed together but not yet bolted together. Which rule directs that this unassembled article be classified as if it were a complete, assembled bicycle?","es":"Una bicicleta completa se importa desarmada en un solo embarque, con todos los tubos del cuadro, ruedas, cadena y manubrios empacados juntos pero aún no atornillados entre sí. ¿Qué regla dispone que este artículo sin armar se clasifique como si fuera una bicicleta completa y armada?","ru":"Полный велосипед импортируется в разобранном виде одной партией: все трубы рамы, колёса, цепь и руль упакованы вместе, но ещё не скреплены болтами. Какое правило предписывает классифицировать это несобранное изделие так, как если бы это был полный, собранный велосипед?","tr":"Eksiksiz bir bisiklet, tüm kadro boruları, tekerlekleri, zinciri ve gidonu birlikte paketlenmiş ancak henüz cıvatalarla birleştirilmemiş halde, tek bir sevkiyatta sökülmüş olarak ithal edilir. Hangi kural, bu monte edilmemiş ürünün eksiksiz, monte edilmiş bir bisiklet gibi sınıflandırılmasını gerektirir?","hi":"एक पूर्ण साइकिल एक ही शिपमेंट में अलग-अलग करके आयात की जाती है, जिसमें सभी फ्रेम ट्यूब, पहिए, चेन और हैंडलबार एक साथ पैक किए गए हैं लेकिन अभी तक एक साथ बोल्ट नहीं किए गए हैं। कौन सा नियम निर्देशित करता है कि इस बिना जोड़ी गई वस्तु को एक पूर्ण, जुड़ी हुई साइकिल के रूप में वर्गीकृत किया जाए?","ar":"تُستورَد دراجة كاملة مفككة في شحنة واحدة، مع تعبئة جميع أنابيب الإطار والعجلات والسلسلة والمقود معًا لكن دون ربطها بعد. أي قاعدة تقضي بتصنيف هذا الصنف غير المجمَّع كما لو كان دراجة كاملة مجمَّعة؟"},"o":[{"en":"GRI 3(b), on the basis of the essential character of the assembled article","es":"GRI 3(b), con base en el carácter esencial del artículo armado","ru":"GRI 3(b), на основании основного характера собранного изделия","tr":"GRI 3(b), monte edilmiş ürünün esas niteliği temelinde","hi":"GRI 3(b), जुड़ी हुई वस्तु के आवश्यक चरित्र के आधार पर","ar":"GRI 3(b)، استنادًا إلى الطابع الأساسي للصنف المجمَّع"},{"en":"GRI 5(a), as goods presented with a fitted container","es":"GRI 5(a), como mercancías presentadas con un estuche ajustado","ru":"GRI 5(a), как товары, представленные с подогнанной тарой","tr":"GRI 5(a), kendine özel bir kap ile birlikte sunulan mallar olarak","hi":"GRI 5(a), एक फिट किए गए कंटेनर के साथ प्रस्तुत माल के रूप में","ar":"GRI 5(a)، باعتبارها بضائع مقدَّمة مع حاوية مُجهَّزة لها"},{"en":"GRI 2(a), which extends a heading to articles presented unassembled or disassembled","es":"GRI 2(a), que extiende una partida a artículos presentados sin armar o desarmados","ru":"GRI 2(a), которое распространяет позицию на изделия, представленные несобранными или разобранными","tr":"GRI 2(a), bir pozisyonu monte edilmemiş veya sökülmüş olarak sunulan ürünlere genişleten kural","hi":"GRI 2(a), जो किसी शीर्षक को बिना जोड़े या अलग करके प्रस्तुत की गई वस्तुओं तक विस्तारित करता है","ar":"GRI 2(a)، التي توسّع البند ليشمل الأصناف المقدَّمة غير مجمَّعة أو مفككة"},{"en":"GRI 4, as goods most akin to an assembled bicycle","es":"GRI 4, como mercancías más afines a una bicicleta armada","ru":"GRI 4, как товары, наиболее сходные с собранным велосипедом","tr":"GRI 4, monte edilmiş bir bisiklete en çok benzeyen mallar olarak","hi":"GRI 4, एक जुड़ी हुई साइकिल से सबसे समान माल के रूप में","ar":"GRI 4، باعتبارها بضائع أقرب ما تكون إلى دراجة مجمَّعة"}],"e":{"en":"GRI 2(a) provides that a reference to an article includes that article presented unassembled or disassembled (and incomplete or unfinished articles having the essential character of the complete article). The disassembled bicycle is classified as a complete bicycle. (GRI 2(a).)","es":"La GRI 2(a) dispone que una referencia a un artículo incluye ese artículo presentado sin armar o desarmado (y los artículos incompletos o sin terminar que tengan el carácter esencial del artículo completo). La bicicleta desarmada se clasifica como una bicicleta completa. (GRI 2(a).)","ru":"GRI 2(a) предусматривает, что ссылка на изделие включает это изделие, представленное несобранным или разобранным (а также некомплектные или незавершённые изделия, обладающие основным характером комплектного изделия). Разобранный велосипед классифицируется как полный велосипед. (GRI 2(a).)","tr":"GRI 2(a), bir ürüne yapılan atfın, o ürünü monte edilmemiş veya sökülmüş halde sunulan haliyle de kapsadığını öngörür (ve eksiksiz ürünün esas niteliğine sahip olan tamamlanmamış veya bitmemiş ürünleri de). Sökülmüş bisiklet, eksiksiz bir bisiklet olarak sınıflandırılır. (GRI 2(a).)","hi":"GRI 2(a) प्रावधान करता है कि किसी वस्तु का संदर्भ उस वस्तु को बिना जोड़े या अलग करके प्रस्तुत किए जाने को शामिल करता है (और अपूर्ण या अधूरी वस्तुएं जिनमें पूर्ण वस्तु का आवश्यक चरित्र हो)। अलग की गई साइकिल को एक पूर्ण साइकिल के रूप में वर्गीकृत किया जाता है। (GRI 2(a).)","ar":"تنص GRI 2(a) على أن الإشارة إلى صنف ما تشمل ذلك الصنف مقدَّمًا غير مجمَّع أو مفككًا (والأصناف غير الكاملة أو غير المنتهية التي لها الطابع الأساسي للصنف الكامل). فتُصنَّف الدراجة المفككة على أنها دراجة كاملة. (GRI 2(a).)"}},{"cat":"classification","a":0,"q":{"en":"GRI 2(a) extends a heading covering a complete article to an incomplete or unfinished article only when the incomplete or unfinished article has which attribute?","es":"La GRI 2(a) extiende una partida que comprende un artículo completo a un artículo incompleto o sin terminar solo cuando el artículo incompleto o sin terminar tiene ¿cuál atributo?","ru":"GRI 2(a) распространяет позицию, охватывающую комплектное изделие, на некомплектное или незавершённое изделие только тогда, когда некомплектное или незавершённое изделие обладает каким признаком?","tr":"GRI 2(a), eksiksiz bir ürünü kapsayan bir pozisyonu, tamamlanmamış veya bitmemiş bir ürüne yalnızca o ürün hangi özelliğe sahip olduğunda genişletir?","hi":"GRI 2(a) किसी पूर्ण वस्तु को कवर करने वाले शीर्षक को किसी अपूर्ण या अधूरी वस्तु तक केवल तभी विस्तारित करता है जब अपूर्ण या अधूरी वस्तु में कौन सी विशेषता हो?","ar":"توسّع GRI 2(a) البند الذي يشمل صنفًا كاملًا ليشمل صنفًا غير كامل أو غير منتهٍ فقط عندما يكون لهذا الصنف غير الكامل أو غير المنتهي أي صفة؟"},"o":[{"en":"The essential character of the complete or finished article as presented","es":"El carácter esencial del artículo completo o terminado tal como se presenta","ru":"Основным характером комплектного или завершённого изделия в представленном виде","tr":"Sunulduğu haliyle eksiksiz veya bitmiş ürünün esas niteliğine sahip olduğunda","hi":"प्रस्तुत किए जाने पर पूर्ण या तैयार वस्तु का आवश्यक चरित्र","ar":"الطابع الأساسي للصنف الكامل أو المنتهي كما هو مقدَّم"},{"en":"A value at least equal to half the value of the finished article","es":"Un valor al menos igual a la mitad del valor del artículo terminado","ru":"Стоимостью не менее половины стоимости завершённого изделия","tr":"Bitmiş ürünün değerinin en az yarısına eşit bir değere sahip olduğunda","hi":"तैयार वस्तु के मूल्य के कम से कम आधे के बराबर मूल्य","ar":"قيمة تساوي على الأقل نصف قيمة الصنف المنتهي"},{"en":"A principal use identical to that of the finished article in the United States","es":"Un uso principal idéntico al del artículo terminado en los Estados Unidos","ru":"Основным использованием, идентичным использованию завершённого изделия в Соединённых Штатах","tr":"Amerika Birleşik Devletleri'nde bitmiş ürünle aynı başlıca kullanıma (principal use) sahip olduğunda","hi":"संयुक्त राज्य अमेरिका में तैयार वस्तु के समान एक प्रमुख उपयोग","ar":"استخدام رئيسي مطابق لاستخدام الصنف المنتهي في الولايات المتحدة"},{"en":"The same six-digit subheading classification as the finished article","es":"La misma clasificación de subpartida de seis dígitos que el artículo terminado","ru":"Той же шестизначной классификацией субпозиции, что и завершённое изделие","tr":"Bitmiş ürünle aynı altı haneli alt pozisyon (subheading) sınıflandırmasına sahip olduğunda","hi":"तैयार वस्तु के समान छह-अंकीय उपशीर्षक वर्गीकरण","ar":"نفس تصنيف البند الفرعي المكوّن من ستة أرقام للصنف المنتهي"}],"e":{"en":"GRI 2(a) extends a heading to an incomplete or unfinished article provided that, as presented, it has the essential character of the complete or finished article (e.g., a blank that already has the approximate shape of the finished part). (GRI 2(a).)","es":"La GRI 2(a) extiende una partida a un artículo incompleto o sin terminar siempre que, tal como se presenta, tenga el carácter esencial del artículo completo o terminado (por ejemplo, un esbozo que ya tiene la forma aproximada de la pieza terminada). (GRI 2(a).)","ru":"GRI 2(a) распространяет позицию на некомплектное или незавершённое изделие при условии, что в представленном виде оно обладает основным характером комплектного или завершённого изделия (например, заготовка, уже имеющая приблизительную форму готовой детали). (GRI 2(a).)","tr":"GRI 2(a), bir pozisyonu tamamlanmamış veya bitmemiş bir ürüne, sunulduğu haliyle eksiksiz veya bitmiş ürünün esas niteliğine sahip olması koşuluyla genişletir (örneğin, halihazırda bitmiş parçanın yaklaşık şekline sahip bir taslak). (GRI 2(a).)","hi":"GRI 2(a) किसी शीर्षक को अपूर्ण या अधूरी वस्तु तक तब विस्तारित करता है, बशर्ते कि प्रस्तुत किए जाने पर उसमें पूर्ण या तैयार वस्तु का आवश्यक चरित्र हो (उदाहरण के लिए, एक ब्लैंक जिसमें पहले से ही तैयार भाग का अनुमानित आकार हो)। (GRI 2(a).)","ar":"توسّع GRI 2(a) البند ليشمل صنفًا غير كامل أو غير منتهٍ شريطة أن يكون له، كما هو مقدَّم، الطابع الأساسي للصنف الكامل أو المنتهي (مثل قالب أولي (blank) له بالفعل الشكل التقريبي للقطعة المنتهية). (GRI 2(a).)"}},{"cat":"classification","a":0,"q":{"en":"Goods that are, prima facie, classifiable under two or more headings are addressed by GRI 3. What is the FIRST test applied under GRI 3?","es":"Las mercancías que, prima facie, son clasificables en dos o más partidas se abordan en la GRI 3. ¿Cuál es la PRIMERA prueba que se aplica bajo la GRI 3?","ru":"Товары, которые prima facie могут быть классифицированы по двум или более позициям, рассматриваются согласно GRI 3. Какой тест применяется ПЕРВЫМ согласно GRI 3?","tr":"İlk bakışta (prima facie) iki veya daha fazla pozisyon (heading) altında sınıflandırılabilen mallar GRI 3 ile ele alınır. GRI 3 kapsamında uygulanan İLK test nedir?","hi":"वह माल जो प्रथम दृष्टया दो या अधिक शीर्षकों के तहत वर्गीकृत होने योग्य है, उसे GRI 3 द्वारा संबोधित किया जाता है। GRI 3 के तहत लागू किया जाने वाला पहला परीक्षण क्या है?","ar":"البضائع التي يمكن تصنيفها مبدئيًا (prima facie) تحت بندين أو أكثر تتناولها GRI 3. ما هو الاختبار الأول المطبَّق بموجب GRI 3؟"},"o":[{"en":"GRI 3(a): the heading providing the most specific description is preferred over headings providing a more general description","es":"GRI 3(a): se prefiere la partida que ofrezca la descripción más específica sobre las partidas que ofrezcan una descripción más general","ru":"GRI 3(a): позиция, дающая наиболее конкретное описание, имеет предпочтение перед позициями, дающими более общее описание","tr":"GRI 3(a): en spesifik tanımı sağlayan pozisyon, daha genel bir tanım sağlayan pozisyonlara tercih edilir","hi":"GRI 3(a): सबसे विशिष्ट विवरण प्रदान करने वाले शीर्षक को अधिक सामान्य विवरण प्रदान करने वाले शीर्षकों पर प्राथमिकता दी जाती है","ar":"GRI 3(a): يُفضَّل البند الذي يقدّم الوصف الأكثر تحديدًا على البنود التي تقدّم وصفًا أكثر عمومية"},{"en":"GRI 3(b): the component giving the goods their essential character determines the classification","es":"GRI 3(b): el componente que da a las mercancías su carácter esencial determina la clasificación","ru":"GRI 3(b): компонент, придающий товарам их основной характер, определяет классификацию","tr":"GRI 3(b): mallara esas niteliğini veren bileşen sınıflandırmayı belirler","hi":"GRI 3(b): माल को उसका आवश्यक चरित्र प्रदान करने वाला घटक वर्गीकरण निर्धारित करता है","ar":"GRI 3(b): المكوّن الذي يمنح البضائع طابعها الأساسي يحدد التصنيف"},{"en":"GRI 3(c): the heading occurring last in numerical order among those equally meriting consideration","es":"GRI 3(c): la partida que se ubique en último lugar en orden numérico entre las que igualmente merezcan consideración","ru":"GRI 3(c): позиция, последняя в порядке возрастания нумерации среди тех, что в равной степени заслуживают рассмотрения","tr":"GRI 3(c): eşit derecede dikkate alınmayı hak edenler arasında numara sırasında en sonda yer alan pozisyon","hi":"GRI 3(c): समान रूप से विचार के योग्य शीर्षकों में से संख्यात्मक क्रम में अंतिम स्थान पर आने वाला शीर्षक","ar":"GRI 3(c): البند الذي يأتي أخيرًا في الترتيب العددي بين البنود التي تستحق الاعتبار بالتساوي"},{"en":"GRI 4: the heading appropriate to the goods to which they are most akin","es":"GRI 4: la partida apropiada a las mercancías con las que tengan mayor afinidad","ru":"GRI 4: позиция, соответствующая товарам, наиболее сходным с ними","tr":"GRI 4: malların en çok benzediği mallara uygun pozisyon","hi":"GRI 4: उस माल के लिए उपयुक्त शीर्षक जिससे वे सबसे अधिक समान हैं","ar":"GRI 4: البند المناسب للبضائع التي تكون هي أقرب ما تكون إليها"}],"e":{"en":"GRI 3 is applied in the order (a), (b), (c). GRI 3(a) is tried first: the heading with the most specific description prevails over one with a more general description. Only if 3(a) does not resolve the issue does one proceed to 3(b), then 3(c). (GRI 3(a).)","es":"La GRI 3 se aplica en el orden (a), (b), (c). La GRI 3(a) se prueba primero: la partida con la descripción más específica prevalece sobre una con una descripción más general. Solo si la 3(a) no resuelve el asunto se procede a la 3(b), luego a la 3(c). (GRI 3(a).)","ru":"GRI 3 применяется в порядке (a), (b), (c). GRI 3(a) применяется первым: позиция с наиболее конкретным описанием имеет преимущество перед позицией с более общим описанием. Только если 3(a) не разрешает вопрос, переходят к 3(b), затем к 3(c). (GRI 3(a).)","tr":"GRI 3, (a), (b), (c) sırasıyla uygulanır. Önce GRI 3(a) denenir: en spesifik tanıma sahip pozisyon, daha genel bir tanıma sahip olana karşı üstün gelir. Yalnızca 3(a) meseleyi çözmediğinde 3(b)'ye, ardından 3(c)'ye geçilir. (GRI 3(a).)","hi":"GRI 3 को क्रम (a), (b), (c) में लागू किया जाता है। GRI 3(a) पहले आजमाया जाता है: सबसे विशिष्ट विवरण वाला शीर्षक अधिक सामान्य विवरण वाले शीर्षक पर प्रबल होता है। केवल यदि 3(a) मुद्दे को हल नहीं करता, तो 3(b), फिर 3(c) पर आगे बढ़ा जाता है। (GRI 3(a).)","ar":"تُطبَّق GRI 3 بالترتيب (a) و(b) و(c). تُجرَّب GRI 3(a) أولًا: البند ذو الوصف الأكثر تحديدًا يسود على البند ذي الوصف الأكثر عمومية. ولا يُنتقَل إلى 3(b) ثم 3(c) إلا إذا لم تحسم 3(a) المسألة. (GRI 3(a).)"}},{"cat":"classification","a":2,"q":{"en":"Under GRI 3(a), when two headings each refer to only PART of the materials in a mixture or composite good, or to only part of the items in a set put up for retail sale, how are those headings regarded?","es":"Bajo la GRI 3(a), cuando dos partidas se refieren cada una a solo PARTE de los materiales de una mezcla o de una mercancía compuesta, o a solo parte de los artículos de un surtido acondicionado para la venta al por menor, ¿cómo se consideran esas partidas?","ru":"Согласно GRI 3(a), когда каждая из двух позиций относится только к ЧАСТИ материалов в смеси или составном товаре, либо только к части предметов в наборе для розничной продажи, как рассматриваются эти позиции?","tr":"GRI 3(a) kapsamında, iki pozisyonun (heading) her biri bir karışım veya bileşik bir maldaki malzemelerin yalnızca BİR KISMINA ya da perakende satış için hazırlanmış bir setteki ürünlerin yalnızca bir kısmına atıfta bulunduğunda, bu pozisyonlar nasıl değerlendirilir?","hi":"GRI 3(a) के तहत, जब दो शीर्षक प्रत्येक किसी मिश्रण या मिश्रित माल में सामग्री के केवल एक भाग, या खुदरा बिक्री के लिए प्रस्तुत सेट में वस्तुओं के केवल एक भाग को संदर्भित करते हैं, तो उन शीर्षकों को कैसे माना जाता है?","ar":"بموجب GRI 3(a)، عندما يشير بندان كلٌّ منهما إلى جزء فقط من المواد في مزيج أو في بضائع مركّبة، أو إلى جزء فقط من الأصناف في مجموعة مُعدَّة للبيع بالتجزئة، كيف يُنظَر إلى هذين البندين؟"},"o":[{"en":"The heading with the lower numerical value is automatically treated as more specific","es":"La partida con el valor numérico más bajo se trata automáticamente como más específica","ru":"Позиция с меньшим числовым значением автоматически считается более конкретной","tr":"Daha düşük numara değerine sahip pozisyon otomatik olarak daha spesifik kabul edilir","hi":"कम संख्यात्मक मूल्य वाले शीर्षक को स्वचालित रूप से अधिक विशिष्ट माना जाता है","ar":"يُعامَل البند ذو القيمة العددية الأدنى تلقائيًا على أنه الأكثر تحديدًا"},{"en":"The heading describing the most valuable material is treated as the most specific","es":"La partida que describe el material más valioso se trata como la más específica","ru":"Позиция, описывающая наиболее ценный материал, считается наиболее конкретной","tr":"En değerli malzemeyi tanımlayan pozisyon en spesifik olarak kabul edilir","hi":"सबसे मूल्यवान सामग्री का वर्णन करने वाले शीर्षक को सबसे विशिष्ट माना जाता है","ar":"يُعامَل البند الذي يصف المادة الأعلى قيمةً على أنه الأكثر تحديدًا"},{"en":"They are regarded as equally specific, even if one gives a more complete or precise description","es":"Se consideran igualmente específicas, aunque una ofrezca una descripción más completa o precisa","ru":"Они считаются в равной степени конкретными, даже если одна даёт более полное или точное описание","tr":"Biri daha eksiksiz veya daha kesin bir tanım verse bile, eşit derecede spesifik kabul edilirler","hi":"उन्हें समान रूप से विशिष्ट माना जाता है, भले ही उनमें से एक अधिक पूर्ण या सटीक विवरण देता हो","ar":"يُعتبران متساويين في التحديد، حتى لو قدّم أحدهما وصفًا أكثر اكتمالًا أو دقة"},{"en":"Neither heading may be used, and classification falls directly to GRI 4","es":"Ninguna de las partidas puede usarse, y la clasificación recae directamente en la GRI 4","ru":"Ни одна из позиций не может использоваться, и классификация переходит непосредственно к GRI 4","tr":"Hiçbir pozisyon kullanılamaz ve sınıflandırma doğrudan GRI 4'e geçer","hi":"किसी भी शीर्षक का उपयोग नहीं किया जा सकता, और वर्गीकरण सीधे GRI 4 पर चला जाता है","ar":"لا يجوز استخدام أي من البندين، وينتقل التصنيف مباشرةً إلى GRI 4"}],"e":{"en":"GRI 3(a) provides that when two or more headings each refer to part only of the materials in mixed or composite goods, or to part only of the items in a retail set, those headings are to be regarded as equally specific, even if one gives a more complete description. The tie then moves the analysis to GRI 3(b). (GRI 3(a).)","es":"La GRI 3(a) dispone que cuando dos o más partidas se refieren cada una a solo parte de los materiales en mercancías mezcladas o compuestas, o a solo parte de los artículos de un surtido para venta al por menor, esas partidas deben considerarse igualmente específicas, aunque una ofrezca una descripción más completa. El empate entonces lleva el análisis a la GRI 3(b). (GRI 3(a).)","ru":"GRI 3(a) предусматривает, что когда каждая из двух или более позиций относится только к части материалов в смешанных или составных товарах либо только к части предметов в розничном наборе, эти позиции должны рассматриваться как в равной степени конкретные, даже если одна даёт более полное описание. Тогда анализ переходит к GRI 3(b). (GRI 3(a).)","tr":"GRI 3(a), iki veya daha fazla pozisyonun her birinin, karışık veya bileşik mallardaki malzemelerin yalnızca bir kısmına ya da perakende bir setteki ürünlerin yalnızca bir kısmına atıfta bulunduğu durumlarda, biri daha eksiksiz bir tanım verse bile bu pozisyonların eşit derecede spesifik kabul edilmesi gerektiğini öngörür. Eşitlik durumu, analizi GRI 3(b)'ye taşır. (GRI 3(a).)","hi":"GRI 3(a) प्रावधान करता है कि जब दो या अधिक शीर्षक प्रत्येक मिश्रित या मिश्रित माल में सामग्री के केवल एक भाग, या खुदरा सेट में वस्तुओं के केवल एक भाग को संदर्भित करते हैं, तो उन शीर्षकों को समान रूप से विशिष्ट माना जाना है, भले ही उनमें से एक अधिक पूर्ण विवरण देता हो। तब यह बराबरी विश्लेषण को GRI 3(b) पर ले जाती है। (GRI 3(a).)","ar":"تنص GRI 3(a) على أنه عندما يشير بندان أو أكثر كلٌّ منهما إلى جزء فقط من المواد في بضائع مخلوطة أو مركّبة، أو إلى جزء فقط من الأصناف في مجموعة تجزئة، فإن هذه البنود تُعتبر متساوية في التحديد، حتى لو قدّم أحدها وصفًا أكثر اكتمالًا. عندئذٍ يَنقل التعادل التحليل إلى GRI 3(b). (GRI 3(a).)"}},{"cat":"classification","a":0,"q":{"en":"A retail-packaged gift set contains a stainless-steel manicure scissor and a small leather pouch, sold together as a set put up for retail sale. The scissor and the pouch fall in different headings, and GRI 3(a) does not resolve the classification. Which rule is applied next, and on what basis?","es":"Un surtido de regalo en empaque para venta al por menor contiene unas tijeras de manicura de acero inoxidable y un pequeño estuche de cuero, vendidos juntos como un surtido acondicionado para la venta al por menor. Las tijeras y el estuche caen en partidas distintas, y la GRI 3(a) no resuelve la clasificación. ¿Qué regla se aplica a continuación, y sobre qué base?","ru":"Подарочный набор в розничной упаковке содержит маникюрные ножницы из нержавеющей стали и небольшой кожаный чехол, продаваемые вместе как набор для розничной продажи. Ножницы и чехол относятся к разным позициям, и GRI 3(a) не разрешает классификацию. Какое правило применяется следующим и на каком основании?","tr":"Perakende ambalajlı bir hediye seti, paslanmaz çelik bir manikür makası ve küçük bir deri kese içerir; bunlar perakende satış için hazırlanmış bir set olarak birlikte satılır. Makas ve kese farklı pozisyonlara (heading) düşer ve GRI 3(a) sınıflandırmayı çözmez. Bir sonraki uygulanan kural hangisidir ve hangi temele dayanır?","hi":"एक खुदरा-पैक उपहार सेट में एक स्टेनलेस-स्टील मैनीक्योर कैंची और एक छोटा चमड़े का थैला होता है, जिसे खुदरा बिक्री के लिए प्रस्तुत सेट के रूप में एक साथ बेचा जाता है। कैंची और थैला अलग-अलग शीर्षकों में आते हैं, और GRI 3(a) वर्गीकरण का समाधान नहीं करता। इसके बाद कौन सा नियम लागू किया जाता है, और किस आधार पर?","ar":"تحتوي مجموعة هدية معبأة للتجزئة على مقص عناية بالأظافر من الفولاذ المقاوم للصدأ وحقيبة جلدية صغيرة، تُباعان معًا بوصفهما مجموعة مُعدَّة للبيع بالتجزئة. يقع المقص والحقيبة في بندين مختلفين، ولا تحسم GRI 3(a) التصنيف. أي قاعدة تُطبَّق بعد ذلك، وعلى أي أساس؟"},"o":[{"en":"GRI 3(b), classifying the set by the component that imparts its essential character","es":"GRI 3(b), clasificando el surtido por el componente que le confiere su carácter esencial","ru":"GRI 3(b), классифицируя набор по компоненту, придающему ему основной характер","tr":"GRI 3(b), seti esas niteliğini veren bileşene göre sınıflandırarak","hi":"GRI 3(b), सेट को उस घटक द्वारा वर्गीकृत करते हुए जो इसका आवश्यक चरित्र प्रदान करता है","ar":"GRI 3(b)، بتصنيف المجموعة وفق المكوّن الذي يمنحها طابعها الأساسي"},{"en":"GRI 3(c), classifying the set under the heading last in numerical order","es":"GRI 3(c), clasificando el surtido bajo la partida que se ubique en último lugar en orden numérico","ru":"GRI 3(c), классифицируя набор по позиции, последней в порядке возрастания нумерации","tr":"GRI 3(c), seti numara sırasında en sonda yer alan pozisyon altında sınıflandırarak","hi":"GRI 3(c), सेट को संख्यात्मक क्रम में अंतिम शीर्षक के तहत वर्गीकृत करते हुए","ar":"GRI 3(c)، بتصنيف المجموعة تحت البند الأخير في الترتيب العددي"},{"en":"GRI 5(a), classifying the pouch and scissor together as a fitted case","es":"GRI 5(a), clasificando el estuche y las tijeras juntos como un estuche ajustado","ru":"GRI 5(a), классифицируя чехол и ножницы вместе как подогнанный футляр","tr":"GRI 5(a), keseyi ve makası kendine özel bir kutu olarak birlikte sınıflandırarak","hi":"GRI 5(a), थैले और कैंची को एक फिट किए गए केस के रूप में एक साथ वर्गीकृत करते हुए","ar":"GRI 5(a)، بتصنيف الحقيبة والمقص معًا كعلبة مُجهَّزة"},{"en":"GRI 2(b), classifying the set by the material of greatest bulk","es":"GRI 2(b), clasificando el surtido por el material de mayor volumen","ru":"GRI 2(b), классифицируя набор по материалу наибольшего объёма","tr":"GRI 2(b), seti en büyük hacme sahip malzemeye göre sınıflandırarak","hi":"GRI 2(b), सेट को सबसे अधिक मात्रा की सामग्री द्वारा वर्गीकृत करते हुए","ar":"GRI 2(b)، بتصنيف المجموعة وفق المادة الأكبر حجمًا"}],"e":{"en":"For mixtures, composite goods, and goods put up in sets for retail sale that cannot be classified under GRI 3(a), GRI 3(b) classifies them by the material or component that gives them their essential character. Only if essential character cannot be determined does one reach GRI 3(c). (GRI 3(b).)","es":"Para las mezclas, las mercancías compuestas y las mercancías acondicionadas en surtidos para la venta al por menor que no pueden clasificarse bajo la GRI 3(a), la GRI 3(b) las clasifica por el material o componente que les confiere su carácter esencial. Solo si el carácter esencial no puede determinarse se llega a la GRI 3(c). (GRI 3(b).)","ru":"Для смесей, составных товаров и товаров, представленных в наборах для розничной продажи, которые не могут быть классифицированы согласно GRI 3(a), GRI 3(b) классифицирует их по материалу или компоненту, придающему им основной характер. Только если основной характер не может быть определён, переходят к GRI 3(c). (GRI 3(b).)","tr":"GRI 3(a) kapsamında sınıflandırılamayan karışımlar, bileşik mallar ve perakende satış için setler halinde hazırlanmış mallar için GRI 3(b), bunları esas niteliğini veren malzeme veya bileşene göre sınıflandırır. Esas nitelik belirlenemediği takdirde GRI 3(c)'ye başvurulur. (GRI 3(b).)","hi":"मिश्रण, मिश्रित माल, और खुदरा बिक्री के लिए सेट में प्रस्तुत माल के लिए जिन्हें GRI 3(a) के तहत वर्गीकृत नहीं किया जा सकता, GRI 3(b) उन्हें उस सामग्री या घटक द्वारा वर्गीकृत करता है जो उन्हें उनका आवश्यक चरित्र प्रदान करता है। केवल यदि आवश्यक चरित्र निर्धारित नहीं किया जा सकता, तभी GRI 3(c) तक पहुंचा जाता है। (GRI 3(b).)","ar":"بالنسبة للمخاليط والبضائع المركّبة والبضائع المعدَّة في مجموعات للبيع بالتجزئة التي لا يمكن تصنيفها بموجب GRI 3(a)، تصنّفها GRI 3(b) وفق المادة أو المكوّن الذي يمنحها طابعها الأساسي. ولا يُلجأ إلى GRI 3(c) إلا إذا تعذّر تحديد الطابع الأساسي. (GRI 3(b).)"}},{"cat":"classification","a":3,"q":{"en":"Goods are classifiable under two headings that equally merit consideration, and the essential character cannot be determined under GRI 3(b). Heading 3924 and heading 7013 both apply equally. How does GRI 3(c) resolve this?","es":"Las mercancías son clasificables en dos partidas que igualmente merecen consideración, y el carácter esencial no puede determinarse bajo la GRI 3(b). La partida 3924 y la partida 7013 aplican por igual. ¿Cómo lo resuelve la GRI 3(c)?","ru":"Товары могут быть классифицированы по двум позициям, которые в равной степени заслуживают рассмотрения, и основной характер не может быть определён согласно GRI 3(b). Позиция 3924 и позиция 7013 применимы в равной степени. Как GRI 3(c) разрешает этот вопрос?","tr":"Mallar, eşit derecede dikkate alınmayı hak eden iki pozisyon (heading) altında sınıflandırılabilir ve esas nitelik GRI 3(b) kapsamında belirlenemez. 3924 pozisyonu ve 7013 pozisyonu eşit derecede uygulanır. GRI 3(c) bunu nasıl çözer?","hi":"माल दो शीर्षकों के तहत वर्गीकृत होने योग्य है जो समान रूप से विचार के योग्य हैं, और GRI 3(b) के तहत आवश्यक चरित्र निर्धारित नहीं किया जा सकता। शीर्षक 3924 और शीर्षक 7013 दोनों समान रूप से लागू होते हैं। GRI 3(c) इसका समाधान कैसे करता है?","ar":"يمكن تصنيف البضائع تحت بندين يستحقان الاعتبار بالتساوي، ولا يمكن تحديد الطابع الأساسي بموجب GRI 3(b). ينطبق البند 3924 والبند 7013 بالتساوي. كيف تحسم GRI 3(c) هذا الأمر؟"},"o":[{"en":"Classify under heading 3924, because it occurs first in numerical order","es":"Clasificar bajo la partida 3924, porque se ubica primero en orden numérico","ru":"Классифицировать по позиции 3924, поскольку она стоит первой в порядке возрастания нумерации","tr":"3924 pozisyonu altında sınıflandırılır, çünkü numara sırasında en başta yer alır","hi":"शीर्षक 3924 के तहत वर्गीकृत करें, क्योंकि यह संख्यात्मक क्रम में पहले आता है","ar":"التصنيف تحت البند 3924، لأنه يأتي أولًا في الترتيب العددي"},{"en":"Classify under whichever heading carries the higher rate of duty","es":"Clasificar bajo la partida que tenga la tasa de derecho más alta","ru":"Классифицировать по той позиции, которая имеет более высокую ставку пошлины","tr":"Daha yüksek vergi oranı taşıyan pozisyon altında sınıflandırılır","hi":"जो भी शीर्षक उच्च शुल्क दर वहन करता है उसके तहत वर्गीकृत करें","ar":"التصنيف تحت البند الذي يحمل معدل الرسوم الأعلى"},{"en":"Classify under heading 3924, because plastics generally precede glass in the schedule","es":"Clasificar bajo la partida 3924, porque los plásticos generalmente preceden al vidrio en la nomenclatura","ru":"Классифицировать по позиции 3924, поскольку пластмассы обычно предшествуют стеклу в номенклатуре","tr":"3924 pozisyonu altında sınıflandırılır, çünkü plastikler cetvelde genel olarak camdan önce gelir","hi":"शीर्षक 3924 के तहत वर्गीकृत करें, क्योंकि अनुसूची में प्लास्टिक आम तौर पर कांच से पहले आता है","ar":"التصنيف تحت البند 3924، لأن المواد البلاستيكية تسبق عمومًا الزجاج في الجدول"},{"en":"Classify under heading 7013, because it occurs last in numerical order","es":"Clasificar bajo la partida 7013, porque se ubica en último lugar en orden numérico","ru":"Классифицировать по позиции 7013, поскольку она стоит последней в порядке возрастания нумерации","tr":"7013 pozisyonu altında sınıflandırılır, çünkü numara sırasında en sonda yer alır","hi":"शीर्षक 7013 के तहत वर्गीकृत करें, क्योंकि यह संख्यात्मक क्रम में अंतिम आता है","ar":"التصنيف تحت البند 7013، لأنه يأتي أخيرًا في الترتيب العددي"}],"e":{"en":"GRI 3(c) provides that when goods cannot be classified by reference to 3(a) or 3(b), they are classified under the heading which occurs last in numerical order among those which equally merit consideration. Between 3924 and 7013, the last is 7013. (GRI 3(c).)","es":"La GRI 3(c) dispone que cuando las mercancías no pueden clasificarse por referencia a la 3(a) o la 3(b), se clasifican bajo la partida que se ubique en último lugar en orden numérico entre las que igualmente merezcan consideración. Entre 3924 y 7013, la última es 7013. (GRI 3(c).)","ru":"GRI 3(c) предусматривает, что когда товары не могут быть классифицированы со ссылкой на 3(a) или 3(b), они классифицируются по позиции, последней в порядке возрастания нумерации среди тех, что в равной степени заслуживают рассмотрения. Между 3924 и 7013 последней является 7013. (GRI 3(c).)","tr":"GRI 3(c), malların 3(a) veya 3(b)'ye başvurularak sınıflandırılamadığı durumlarda, eşit derecede dikkate alınmayı hak edenler arasında numara sırasında en sonda yer alan pozisyon altında sınıflandırılacağını öngörür. 3924 ile 7013 arasında en sonda yer alan 7013'tür. (GRI 3(c).)","hi":"GRI 3(c) प्रावधान करता है कि जब माल को 3(a) या 3(b) के संदर्भ से वर्गीकृत नहीं किया जा सकता, तो उन्हें उस शीर्षक के तहत वर्गीकृत किया जाता है जो समान रूप से विचार के योग्य शीर्षकों में संख्यात्मक क्रम में अंतिम आता है। 3924 और 7013 के बीच, अंतिम 7013 है। (GRI 3(c).)","ar":"تنص GRI 3(c) على أنه عندما لا يمكن تصنيف البضائع بالرجوع إلى 3(a) أو 3(b)، تُصنَّف تحت البند الذي يأتي أخيرًا في الترتيب العددي بين البنود التي تستحق الاعتبار بالتساوي. وبين 3924 و7013، الأخير هو 7013. (GRI 3(c).)"}},{"cat":"classification","a":2,"q":{"en":"A specially shaped and fitted hard case, of a kind normally sold with the article it contains and suitable for long-term use, is imported containing the camera it is designed to hold. Absent a section or chapter note to the contrary, how is the fitted case classified?","es":"Un estuche rígido especialmente moldeado y ajustado, del tipo que normalmente se vende con el artículo que contiene y apto para uso prolongado, se importa conteniendo la cámara para la que está diseñado. En ausencia de una nota de sección o capítulo en contrario, ¿cómo se clasifica el estuche ajustado?","ru":"Специально сформированный и подогнанный жёсткий футляр, такого рода, который обычно продаётся вместе с изделием, которое он содержит, и пригодный для длительного использования, импортируется содержащим фотоаппарат, для которого он предназначен. При отсутствии примечания к разделу или главе об обратном, как классифицируется подогнанный футляр?","tr":"İçindeki ürünle birlikte normalde satılan türden, uzun süreli kullanıma uygun, özel şekilli ve kendine özel sert bir kutu, taşımak üzere tasarlandığı kamerayı içerir halde ithal edilir. Aksine bir bölüm veya fasıl notu olmaması durumunda, bu kendine özel kutu nasıl sınıflandırılır?","hi":"एक विशेष रूप से आकार दिया गया और फिट किया गया सख्त केस, जो आम तौर पर उस वस्तु के साथ बेचा जाता है जिसे वह रखता है और दीर्घकालिक उपयोग के लिए उपयुक्त है, उस कैमरे को रखते हुए आयात किया जाता है जिसे रखने के लिए इसे डिज़ाइन किया गया है। इसके विपरीत किसी खंड या अध्याय टिप्पणी के अभाव में, फिट किए गए केस को कैसे वर्गीकृत किया जाता है?","ar":"تُستورَد علبة صلبة مُشكَّلة ومُجهَّزة خصيصًا، من نوع يُباع عادةً مع الصنف الذي تحتويه وصالحة للاستخدام طويل الأمد، وهي تحتوي على الكاميرا المصممة لاحتوائها. في غياب ملاحظة قسم أو فصل تقضي بخلاف ذلك، كيف تُصنَّف العلبة المُجهَّزة؟"},"o":[{"en":"Separately, under the heading for cases of its constituent material","es":"Por separado, bajo la partida para estuches de su material constitutivo","ru":"Отдельно, по позиции для футляров из составляющего его материала","tr":"Ayrı olarak, yapımında kullanılan malzemeden kutular için olan pozisyon altında","hi":"अलग से, इसकी घटक सामग्री के केसों के शीर्षक के तहत","ar":"بشكل منفصل، تحت البند الخاص بالعلب من مادتها المكوّنة"},{"en":"Under GRI 3(b), by determining the essential character of case and camera together","es":"Bajo la GRI 3(b), determinando el carácter esencial del estuche y la cámara en conjunto","ru":"Согласно GRI 3(b), путём определения основного характера футляра и фотоаппарата вместе","tr":"GRI 3(b) kapsamında, kutu ve kameranın esas niteliğini birlikte belirleyerek","hi":"GRI 3(b) के तहत, केस और कैमरे का एक साथ आवश्यक चरित्र निर्धारित करते हुए","ar":"بموجب GRI 3(b)، بتحديد الطابع الأساسي للعلبة والكاميرا معًا"},{"en":"With the camera, under GRI 5(a) covering fitted cases presented with their articles","es":"Junto con la cámara, bajo la GRI 5(a) que comprende los estuches ajustados presentados con sus artículos","ru":"Вместе с фотоаппаратом, согласно GRI 5(a), охватывающему подогнанные футляры, представленные с их изделиями","tr":"Kamerayla birlikte, kendine özel kutuları içindeki ürünleriyle birlikte kapsayan GRI 5(a) kapsamında","hi":"कैमरे के साथ, GRI 5(a) के तहत जो फिट किए गए केसों को उनकी वस्तुओं के साथ प्रस्तुत किए जाने को कवर करता है","ar":"مع الكاميرا، بموجب GRI 5(a) التي تشمل العلب المُجهَّزة المقدَّمة مع أصنافها"},{"en":"Under GRI 4, as goods most akin to a camera accessory","es":"Bajo la GRI 4, como mercancías más afines a un accesorio de cámara","ru":"Согласно GRI 4, как товары, наиболее сходные с принадлежностью к фотоаппарату","tr":"GRI 4 kapsamında, bir kamera aksesuarına en çok benzeyen mallar olarak","hi":"GRI 4 के तहत, कैमरा एक्सेसरी से सबसे समान माल के रूप में","ar":"بموجب GRI 4، باعتبارها بضائع أقرب ما تكون إلى ملحق كاميرا"}],"e":{"en":"GRI 5(a) provides that camera cases, instrument cases, and similar containers, specially shaped or fitted for a specific article, suitable for long-term use, and presented with the article, are classified with that article when of a kind normally sold therewith. (GRI 5(a).)","es":"La GRI 5(a) dispone que los estuches para cámaras, estuches para instrumentos y contenedores similares, especialmente moldeados o ajustados para un artículo específico, aptos para uso prolongado y presentados con el artículo, se clasifican junto con ese artículo cuando sean del tipo que normalmente se vende con él. (GRI 5(a).)","ru":"GRI 5(a) предусматривает, что футляры для фотоаппаратов, футляры для инструментов и аналогичные контейнеры, специально сформированные или подогнанные для конкретного изделия, пригодные для длительного использования и представленные вместе с изделием, классифицируются вместе с этим изделием, если они такого рода, который обычно продаётся вместе с ним. (GRI 5(a).)","tr":"GRI 5(a), belirli bir ürün için özel şekilli veya kendine özel olarak yapılmış, uzun süreli kullanıma uygun ve ürünle birlikte sunulan kamera kutuları, alet kutuları ve benzeri kapların, normalde o ürünle birlikte satılan türden olduğunda o ürünle birlikte sınıflandırılacağını öngörür. (GRI 5(a).)","hi":"GRI 5(a) प्रावधान करता है कि कैमरा केस, उपकरण केस, और समान कंटेनर, जो किसी विशिष्ट वस्तु के लिए विशेष रूप से आकार दिए गए या फिट किए गए हैं, दीर्घकालिक उपयोग के लिए उपयुक्त हैं, और वस्तु के साथ प्रस्तुत किए जाते हैं, उस वस्तु के साथ वर्गीकृत किए जाते हैं जब वे ऐसे प्रकार के हों जो आम तौर पर उसके साथ बेचे जाते हैं। (GRI 5(a).)","ar":"تنص GRI 5(a) على أن علب الكاميرات وعلب الأدوات والحاويات المماثلة، المُشكَّلة أو المُجهَّزة خصيصًا لصنف محدد، والصالحة للاستخدام طويل الأمد، والمقدَّمة مع الصنف، تُصنَّف مع ذلك الصنف عندما تكون من نوع يُباع عادةً معه. (GRI 5(a).)"}},{"cat":"classification","a":3,"q":{"en":"Subject to GRI 5(a), how does GRI 5(b) treat packing materials and packing containers presented with the goods they contain?","es":"Sujeto a la GRI 5(a), ¿cómo trata la GRI 5(b) los materiales de empaque y los envases de empaque presentados con las mercancías que contienen?","ru":"С учётом GRI 5(a), как GRI 5(b) рассматривает упаковочные материалы и упаковочные контейнеры, представленные вместе с товарами, которые они содержат?","tr":"GRI 5(a)'ya tabi olarak, GRI 5(b), içerdikleri mallarla birlikte sunulan ambalaj malzemelerini ve ambalaj kaplarını nasıl ele alır?","hi":"GRI 5(a) के अधीन, GRI 5(b) उनके द्वारा रखे गए माल के साथ प्रस्तुत पैकिंग सामग्री और पैकिंग कंटेनरों के साथ कैसा व्यवहार करता है?","ar":"مع مراعاة GRI 5(a)، كيف تعامل GRI 5(b) مواد التعبئة وحاويات التعبئة المقدَّمة مع البضائع التي تحتويها؟"},"o":[{"en":"They are always classified separately under the heading for their constituent material","es":"Siempre se clasifican por separado bajo la partida correspondiente a su material constitutivo","ru":"Они всегда классифицируются отдельно по позиции для составляющего их материала","tr":"Her zaman, yapımında kullanılan malzemeden olan pozisyon altında ayrı olarak sınıflandırılırlar","hi":"उन्हें हमेशा उनकी घटक सामग्री के शीर्षक के तहत अलग से वर्गीकृत किया जाता है","ar":"تُصنَّف دائمًا بشكل منفصل تحت البند الخاص بمادتها المكوّنة"},{"en":"They are classified under GRI 3(c) as occurring last in numerical order","es":"Se clasifican bajo la GRI 3(c) por ubicarse en último lugar en orden numérico","ru":"Они классифицируются согласно GRI 3(c) как последние в порядке возрастания нумерации","tr":"Numara sırasında en sonda yer aldığı için GRI 3(c) kapsamında sınıflandırılırlar","hi":"उन्हें GRI 3(c) के तहत संख्यात्मक क्रम में अंतिम आने के रूप में वर्गीकृत किया जाता है","ar":"تُصنَّف بموجب GRI 3(c) باعتبارها تأتي أخيرًا في الترتيب العددي"},{"en":"They are classified with the goods only if they impart the essential character of the shipment","es":"Se clasifican junto con las mercancías solo si confieren el carácter esencial del embarque","ru":"Они классифицируются вместе с товарами только в том случае, если придают основной характер партии","tr":"Yalnızca sevkiyatın esas niteliğini vermeleri halinde mallarla birlikte sınıflandırılırlar","hi":"उन्हें माल के साथ केवल तभी वर्गीकृत किया जाता है जब वे शिपमेंट का आवश्यक चरित्र प्रदान करते हैं","ar":"تُصنَّف مع البضائع فقط إذا منحت الشحنة طابعها الأساسي"},{"en":"They are classified with the goods if of a kind normally used for packing them, unless clearly suitable for repetitive use","es":"Se clasifican junto con las mercancías si son del tipo normalmente usado para empacarlas, salvo que sean claramente aptos para uso repetido","ru":"Они классифицируются вместе с товарами, если они такого рода, который обычно используется для упаковки таких товаров, кроме случаев, когда они явно пригодны для повторного использования","tr":"Bu tür malları ambalajlamak için normalde kullanılan türden iseler, açıkça tekrarlı kullanıma uygun olmadıkça mallarla birlikte sınıflandırılırlar","hi":"उन्हें माल के साथ वर्गीकृत किया जाता है यदि वे उन्हें पैक करने के लिए आम तौर पर उपयोग किए जाने वाले प्रकार के हों, जब तक कि वे स्पष्ट रूप से बार-बार उपयोग के लिए उपयुक्त न हों","ar":"تُصنَّف مع البضائع إذا كانت من نوع يُستخدَم عادةً لتعبئتها، ما لم تكن صالحة بوضوح للاستخدام المتكرر"}],"e":{"en":"GRI 5(b) provides that packing materials and containers presented with the goods are classified with the goods if they are of a kind normally used for packing such goods; this does not apply to packing clearly suitable for repetitive use. (GRI 5(b).)","es":"La GRI 5(b) dispone que los materiales de empaque y los envases presentados con las mercancías se clasifican junto con las mercancías si son del tipo normalmente usado para empacar tales mercancías; esto no aplica a los empaques claramente aptos para uso repetido. (GRI 5(b).)","ru":"GRI 5(b) предусматривает, что упаковочные материалы и контейнеры, представленные вместе с товарами, классифицируются вместе с товарами, если они такого рода, который обычно используется для упаковки таких товаров; это не применяется к упаковке, явно пригодной для повторного использования. (GRI 5(b).)","tr":"GRI 5(b), mallarla birlikte sunulan ambalaj malzemeleri ve kaplarının, bu tür malları ambalajlamak için normalde kullanılan türden olmaları halinde mallarla birlikte sınıflandırılacağını öngörür; bu durum, açıkça tekrarlı kullanıma uygun ambalajlar için geçerli değildir. (GRI 5(b).)","hi":"GRI 5(b) प्रावधान करता है कि माल के साथ प्रस्तुत पैकिंग सामग्री और कंटेनरों को माल के साथ वर्गीकृत किया जाता है यदि वे ऐसे माल को पैक करने के लिए आम तौर पर उपयोग किए जाने वाले प्रकार के हों; यह उस पैकिंग पर लागू नहीं होता जो स्पष्ट रूप से बार-बार उपयोग के लिए उपयुक्त हो। (GRI 5(b).)","ar":"تنص GRI 5(b) على أن مواد التعبئة والحاويات المقدَّمة مع البضائع تُصنَّف مع البضائع إذا كانت من نوع يُستخدَم عادةً لتعبئة هذه البضائع؛ ولا ينطبق ذلك على التعبئة الصالحة بوضوح للاستخدام المتكرر. (GRI 5(b).)"}},{"cat":"classification","a":0,"q":{"en":"Under GRI 6, comparison of subheadings within a heading to determine the correct six-digit (or further) classification may be made only between which subheadings?","es":"Bajo la GRI 6, la comparación de subpartidas dentro de una partida para determinar la clasificación correcta de seis dígitos (o más detallada) solo puede hacerse entre ¿cuáles subpartidas?","ru":"Согласно GRI 6, сравнение субпозиций в пределах одной позиции для определения правильной шестизначной (или более детальной) классификации может производиться только между какими субпозициями?","tr":"GRI 6 kapsamında, doğru altı haneli (veya daha ileri) sınıflandırmayı belirlemek için bir pozisyon (heading) içindeki alt pozisyonların (subheading) karşılaştırılması yalnızca hangi alt pozisyonlar arasında yapılabilir?","hi":"GRI 6 के तहत, सही छह-अंकीय (या उससे आगे) वर्गीकरण निर्धारित करने के लिए किसी शीर्षक के भीतर उपशीर्षकों की तुलना केवल किन उपशीर्षकों के बीच की जा सकती है?","ar":"بموجب GRI 6، لا تجوز مقارنة البنود الفرعية داخل بند ما لتحديد التصنيف الصحيح المكوّن من ستة أرقام (أو أكثر) إلا بين أي بنود فرعية؟"},"o":[{"en":"Subheadings at the same level (e.g., one-dash with one-dash, two-dash with two-dash)","es":"Subpartidas del mismo nivel (por ejemplo, una raya con una raya, dos rayas con dos rayas)","ru":"Субпозициями одного уровня (например, одно-дефисными с одно-дефисными, двух-дефисными с двух-дефисными)","tr":"Aynı düzeydeki alt pozisyonlar arasında (örneğin, tek tireli ile tek tireli, çift tireli ile çift tireli)","hi":"समान स्तर के उपशीर्षक (उदाहरण के लिए, एक-डैश के साथ एक-डैश, दो-डैश के साथ दो-डैश)","ar":"البنود الفرعية عند المستوى نفسه (مثل ذات الشرطة الواحدة مع ذات الشرطة الواحدة، وذات الشرطتين مع ذات الشرطتين)"},{"en":"Subheadings of any heading within the same chapter","es":"Subpartidas de cualquier partida dentro del mismo capítulo","ru":"Субпозициями любой позиции в пределах той же главы","tr":"Aynı fasıl içindeki herhangi bir pozisyonun alt pozisyonları arasında","hi":"समान अध्याय के भीतर किसी भी शीर्षक के उपशीर्षक","ar":"البنود الفرعية لأي بند ضمن الفصل نفسه"},{"en":"Subheadings carrying the same general rate of duty","es":"Subpartidas que tengan la misma tasa general de derecho","ru":"Субпозициями, имеющими одинаковую общую ставку пошлины","tr":"Aynı genel vergi oranını taşıyan alt pozisyonlar arasında","hi":"समान सामान्य शुल्क दर वहन करने वाले उपशीर्षक","ar":"البنود الفرعية التي تحمل معدل الرسوم العام نفسه"},{"en":"Subheadings that share the same statistical suffix","es":"Subpartidas que compartan el mismo sufijo estadístico","ru":"Субпозициями, имеющими одинаковый статистический суффикс","tr":"Aynı istatistiksel son eki paylaşan alt pozisyonlar arasında","hi":"समान सांख्यिकीय प्रत्यय साझा करने वाले उपशीर्षक","ar":"البنود الفرعية التي تشترك في اللاحقة الإحصائية نفسها"}],"e":{"en":"GRI 6 directs that classification at the subheading level is determined by the terms of the subheadings and any related subheading notes, and that only subheadings at the same level are comparable. The GRIs apply mutatis mutandis at the subheading level. (GRI 6.)","es":"La GRI 6 dispone que la clasificación a nivel de subpartida se determina por los términos de las subpartidas y cualquier nota de subpartida relacionada, y que solo las subpartidas del mismo nivel son comparables. Las GRI aplican mutatis mutandis a nivel de subpartida. (GRI 6.)","ru":"GRI 6 предписывает, что классификация на уровне субпозиций определяется текстами субпозиций и любыми относящимися к ним примечаниями к субпозициям, и что сравнимы только субпозиции одного уровня. Правила GRI применяются mutatis mutandis на уровне субпозиций. (GRI 6.)","tr":"GRI 6, alt pozisyon düzeyindeki sınıflandırmanın, alt pozisyonların ifadelerine ve ilgili herhangi bir alt pozisyon notuna göre belirlendiğini ve yalnızca aynı düzeydeki alt pozisyonların karşılaştırılabilir olduğunu öngörür. GRI'lar, alt pozisyon düzeyinde gerekli değişikliklerle (mutatis mutandis) uygulanır. (GRI 6.)","hi":"GRI 6 निर्देशित करता है कि उपशीर्षक स्तर पर वर्गीकरण उपशीर्षकों की शर्तों और किसी भी संबंधित उपशीर्षक टिप्पणियों द्वारा निर्धारित होता है, और केवल समान स्तर के उपशीर्षक तुलनीय हैं। GRI उपशीर्षक स्तर पर mutatis mutandis लागू होते हैं। (GRI 6.)","ar":"تقضي GRI 6 بأن التصنيف عند مستوى البند الفرعي يُحدَّد بنصوص البنود الفرعية وأي ملاحظات بنود فرعية ذات صلة، وأن البنود الفرعية عند المستوى نفسه فقط هي القابلة للمقارنة. وتُطبَّق قواعد GRI مع ما يلزم من تعديل (mutatis mutandis) عند مستوى البند الفرعي. (GRI 6.)"}},{"cat":"classification","a":1,"q":{"en":"Which statement best describes the legal force of section, chapter, and subchapter TITLES in the HTSUS, compared with section and chapter NOTES?","es":"¿Qué afirmación describe mejor la fuerza legal de los TÍTULOS de sección, capítulo y subcapítulo en el HTSUS, en comparación con las NOTAS de sección y capítulo?","ru":"Какое утверждение лучше всего описывает юридическую силу НАЗВАНИЙ разделов, глав и подглав в HTSUS по сравнению с ПРИМЕЧАНИЯМИ к разделам и главам?","tr":"HTSUS'taki bölüm, fasıl ve alt fasıl BAŞLIKLARININ hukuki bağlayıcılığını, bölüm ve fasıl NOTLARI ile karşılaştırıldığında, hangi ifade en iyi şekilde tanımlar?","hi":"कौन सा कथन HTSUS में खंड, अध्याय और उप-अध्याय शीर्षकों के कानूनी बल का खंड और अध्याय टिप्पणियों की तुलना में सबसे अच्छा वर्णन करता है?","ar":"أي عبارة تصف بأفضل شكل القوة القانونية لعناوين الأقسام والفصول والفصول الفرعية في HTSUS، مقارنةً بملاحظات الأقسام والفصول؟"},"o":[{"en":"Both titles and notes are provided for ease of reference only and have no legal force","es":"Tanto los títulos como las notas se proporcionan solo para facilitar la consulta y no tienen fuerza legal","ru":"И названия, и примечания приводятся только для удобства ссылок и не имеют юридической силы","tr":"Hem başlıklar hem de notlar yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur","hi":"शीर्षक और टिप्पणियां दोनों केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है","ar":"كل من العناوين والملاحظات مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية"},{"en":"Titles are provided for ease of reference only and have no legal force, whereas section and chapter notes are legally binding and control classification","es":"Los títulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal, mientras que las notas de sección y capítulo son legalmente vinculantes y rigen la clasificación","ru":"Названия приводятся только для удобства ссылок и не имеют юридической силы, тогда как примечания к разделам и главам юридически обязательны и определяют классификацию","tr":"Başlıklar yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur, oysa bölüm ve fasıl notları hukuken bağlayıcıdır ve sınıflandırmayı belirler","hi":"शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है, जबकि खंड और अध्याय टिप्पणियां कानूनी रूप से बाध्यकारी हैं और वर्गीकरण को नियंत्रित करती हैं","ar":"العناوين مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية، بينما ملاحظات الأقسام والفصول ملزِمة قانونًا وتتحكم في التصنيف"},{"en":"Titles control classification, while notes are merely explanatory and advisory","es":"Los títulos rigen la clasificación, mientras que las notas son meramente explicativas y orientativas","ru":"Названия определяют классификацию, а примечания носят лишь пояснительный и рекомендательный характер","tr":"Başlıklar sınıflandırmayı belirler, notlar ise yalnızca açıklayıcı ve tavsiye niteliğindedir","hi":"शीर्षक वर्गीकरण को नियंत्रित करते हैं, जबकि टिप्पणियां केवल व्याख्यात्मक और सलाहकारी हैं","ar":"العناوين تتحكم في التصنيف، بينما الملاحظات مجرد إيضاحية واستشارية"},{"en":"Both titles and notes are legally binding to the same degree under GRI 1","es":"Tanto los títulos como las notas son legalmente vinculantes en igual grado bajo la GRI 1","ru":"И названия, и примечания юридически обязательны в одинаковой степени согласно GRI 1","tr":"Hem başlıklar hem de notlar, GRI 1 kapsamında aynı ölçüde hukuken bağlayıcıdır","hi":"शीर्षक और टिप्पणियां दोनों GRI 1 के तहत समान रूप से कानूनी रूप से बाध्यकारी हैं","ar":"كل من العناوين والملاحظات ملزِمة قانونًا بالدرجة نفسها بموجب GRI 1"}],"e":{"en":"Under GRI 1, the titles of sections, chapters and subchapters are provided for ease of reference only and have no legal force; classification is determined by the terms of the headings and any relative section or chapter notes, which are legally binding. (GRI 1.)","es":"Bajo la GRI 1, los títulos de secciones, capítulos y subcapítulos se proporcionan solo para facilitar la consulta y no tienen fuerza legal; la clasificación se determina por los términos de las partidas y cualquier nota relativa de sección o capítulo, que son legalmente vinculantes. (GRI 1.)","ru":"Согласно GRI 1, названия разделов, глав и подглав приводятся только для удобства ссылок и не имеют юридической силы; классификация определяется текстами позиций и любыми относящимися к ним примечаниями к разделам или главам, которые юридически обязательны. (GRI 1.)","tr":"GRI 1 kapsamında, bölümlerin, fasılların ve alt fasılların başlıkları yalnızca kolay referans amacıyla verilmiştir ve hukuki bağlayıcılığı yoktur; sınıflandırma, hukuken bağlayıcı olan pozisyonların ifadelerine ve ilgili herhangi bir bölüm veya fasıl notuna göre belirlenir. (GRI 1.)","hi":"GRI 1 के तहत, खंडों, अध्यायों और उप-अध्यायों के शीर्षक केवल संदर्भ की सुविधा के लिए प्रदान किए जाते हैं और उनका कोई कानूनी बल नहीं है; वर्गीकरण शीर्षकों की शर्तों और किसी भी संबंधित खंड या अध्याय टिप्पणियों द्वारा निर्धारित होता है, जो कानूनी रूप से बाध्यकारी हैं। (GRI 1.)","ar":"بموجب GRI 1، عناوين الأقسام والفصول والفصول الفرعية مقدَّمة لسهولة الإحالة فقط وليست لها قوة قانونية؛ ويُحدَّد التصنيف بنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة، وهي ملزِمة قانونًا. (GRI 1.)"}},{"cat":"classification","a":2,"q":{"en":"In the ten-digit HTSUS number 6109.10.0040, which component identifies the internationally harmonized six-digit subheading, and which is the U.S. statistical suffix?","es":"En el número HTSUS de diez dígitos 6109.10.0040, ¿qué componente identifica la subpartida armonizada internacionalmente de seis dígitos, y cuál es el sufijo estadístico de los EE. UU.?","ru":"В десятизначном номере HTSUS 6109.10.0040 какой компонент обозначает международно гармонизированную шестизначную субпозицию, а какой является статистическим суффиксом США?","tr":"6109.10.0040 on haneli HTSUS numarasında, uluslararası uyumlaştırılmış altı haneli alt pozisyonu (subheading) hangi bileşen belirtir ve ABD istatistiksel son eki (statistical suffix) hangisidir?","hi":"दस-अंकीय HTSUS संख्या 6109.10.0040 में, कौन सा घटक अंतरराष्ट्रीय रूप से सामंजस्यपूर्ण छह-अंकीय उपशीर्षक की पहचान करता है, और कौन सा अमेरिकी सांख्यिकीय प्रत्यय है?","ar":"في الرقم العشاري المكوّن من عشرة أرقام في HTSUS وهو 6109.10.0040، أي مكوّن يحدّد البند الفرعي المنسَّق دوليًا المكوّن من ستة أرقام، وأي مكوّن هو اللاحقة الإحصائية الأمريكية؟"},"o":[{"en":"6109 is the subheading and 10.0040 is the statistical suffix","es":"6109 es la subpartida y 10.0040 es el sufijo estadístico","ru":"6109 — это субпозиция, а 10.0040 — статистический суффикс","tr":"6109 alt pozisyondur ve 10.0040 istatistiksel son ektir","hi":"6109 उपशीर्षक है और 10.0040 सांख्यिकीय प्रत्यय है","ar":"6109 هو البند الفرعي و10.0040 هو اللاحقة الإحصائية"},{"en":"6109.10.00 is the international subheading and 40 alone is the statistical suffix established by the WCO","es":"6109.10.00 es la subpartida internacional y solo 40 es el sufijo estadístico establecido por la WCO","ru":"6109.10.00 — это международная субпозиция, а только 40 — статистический суффикс, установленный WCO","tr":"6109.10.00 uluslararası alt pozisyondur ve tek başına 40, WCO tarafından belirlenen istatistiksel son ektir","hi":"6109.10.00 अंतरराष्ट्रीय उपशीर्षक है और अकेला 40 WCO द्वारा स्थापित सांख्यिकीय प्रत्यय है","ar":"6109.10.00 هو البند الفرعي الدولي و40 وحده هو اللاحقة الإحصائية المقرَّرة من قبل WCO"},{"en":"6109.10 is the international six-digit subheading and 0040 is the U.S. statistical suffix","es":"6109.10 es la subpartida internacional de seis dígitos y 0040 es el sufijo estadístico de los EE. UU.","ru":"6109.10 — это международная шестизначная субпозиция, а 0040 — статистический суффикс США","tr":"6109.10 uluslararası altı haneli alt pozisyondur ve 0040 ABD istatistiksel son ekidir","hi":"6109.10 अंतरराष्ट्रीय छह-अंकीय उपशीर्षक है और 0040 अमेरिकी सांख्यिकीय प्रत्यय है","ar":"6109.10 هو البند الفرعي الدولي المكوّن من ستة أرقام و0040 هو اللاحقة الإحصائية الأمريكية"},{"en":"610 is the heading and 9.10.0040 is the statistical suffix","es":"610 es la partida y 9.10.0040 es el sufijo estadístico","ru":"610 — это позиция, а 9.10.0040 — статистический суффикс","tr":"610 pozisyondur ve 9.10.0040 istatistiksel son ektir","hi":"610 शीर्षक है और 9.10.0040 सांख्यिकीय प्रत्यय है","ar":"610 هو البند و9.10.0040 هو اللاحقة الإحصائية"}],"e":{"en":"In HTSUS structure, the first four digits are the heading (6109), the first six digits form the internationally harmonized subheading (6109.10), the eighth digit completes the U.S. legal rate line, and the ninth and tenth digits (here 40, shown as 0040) are the U.S. statistical reporting suffix. (HTSUS structure; statistical suffixes.)","es":"En la estructura del HTSUS, los primeros cuatro dígitos son la partida (6109), los primeros seis dígitos forman la subpartida armonizada internacionalmente (6109.10), el octavo dígito completa la línea de tasa legal de los EE. UU., y los dígitos noveno y décimo (aquí 40, mostrados como 0040) son el sufijo estadístico de reporte de los EE. UU. (Estructura del HTSUS; sufijos estadísticos.)","ru":"В структуре HTSUS первые четыре цифры — это позиция (6109), первые шесть цифр образуют международно гармонизированную субпозицию (6109.10), восьмая цифра завершает законодательную строку ставки США, а девятая и десятая цифры (здесь 40, показанные как 0040) являются статистическим отчётным суффиксом США. (Структура HTSUS; статистические суффиксы.)","tr":"HTSUS yapısında, ilk dört hane pozisyonu (6109), ilk altı hane uluslararası uyumlaştırılmış alt pozisyonu (6109.10), sekizinci hane ABD yasal oran satırını tamamlar ve dokuzuncu ile onuncu haneler (burada 40, 0040 olarak gösterilir) ABD istatistiksel raporlama son ekidir. (HTSUS yapısı; istatistiksel son ekler.)","hi":"HTSUS संरचना में, पहले चार अंक शीर्षक (6109) हैं, पहले छह अंक अंतरराष्ट्रीय रूप से सामंजस्यपूर्ण उपशीर्षक (6109.10) बनाते हैं, आठवां अंक अमेरिकी कानूनी दर रेखा को पूरा करता है, और नौवां तथा दसवां अंक (यहां 40, 0040 के रूप में दिखाया गया) अमेरिकी सांख्यिकीय रिपोर्टिंग प्रत्यय हैं। (HTSUS संरचना; सांख्यिकीय प्रत्यय।)","ar":"في بنية HTSUS، الأرقام الأربعة الأولى هي البند (6109)، والأرقام الستة الأولى تشكّل البند الفرعي المنسَّق دوليًا (6109.10)، والرقم الثامن يُكمل سطر المعدل القانوني الأمريكي، والرقمان التاسع والعاشر (هنا 40، الموضّحان كـ 0040) هما اللاحقة الإحصائية الأمريكية للإبلاغ. (بنية HTSUS؛ اللواحق الإحصائية.)"}},{"cat":"classification","a":1,"q":{"en":"A heading is described as a 'principal use' provision (a use provision other than actual use). Under the Additional U.S. Rules of Interpretation, how is classification under such a provision controlled?","es":"Una partida se describe como una disposición de 'uso principal' (principal use), es decir, una disposición de uso distinta del uso real (actual use). Bajo las Additional U.S. Rules of Interpretation, ¿cómo se rige la clasificación bajo tal disposición?","ru":"Позиция описывается как положение об «основном использовании» (положение об использовании, отличное от фактического использования). Согласно Дополнительным правилам интерпретации США, как контролируется классификация по такому положению?","tr":"Bir pozisyon (heading), bir 'principal use' (başlıca kullanım) hükmü (gerçek kullanım dışında bir kullanım hükmü) olarak tanımlanır. Additional U.S. Rules of Interpretation (Ek ABD Yorum Kuralları) kapsamında, böyle bir hüküm altındaki sınıflandırma nasıl belirlenir?","hi":"एक शीर्षक को 'प्रमुख उपयोग' प्रावधान (वास्तविक उपयोग के अलावा एक उपयोग प्रावधान) के रूप में वर्णित किया गया है। व्याख्या के अतिरिक्त अमेरिकी नियमों के तहत, ऐसे प्रावधान के तहत वर्गीकरण को कैसे नियंत्रित किया जाता है?","ar":"يُوصَف بند ما بأنه حكم \"الاستخدام الرئيسي\" (principal use) (حكم استخدام غير الاستخدام الفعلي). بموجب القواعد الأمريكية الإضافية للتفسير، كيف يُتحكَّم في التصنيف بموجب هذا الحكم؟"},"o":[{"en":"By the actual use to which the specific imported article is later put, proven within three years","es":"Por el uso real al que se destina posteriormente el artículo importado específico, probado dentro de tres años","ru":"По фактическому использованию, которому впоследствии подвергается конкретное импортированное изделие, доказанному в течение трёх лет","tr":"Üç yıl içinde kanıtlanmak üzere, belirli ithal ürünün sonradan tabi tutulduğu gerçek kullanıma göre","hi":"उस वास्तविक उपयोग द्वारा जिसमें विशिष्ट आयातित वस्तु को बाद में लगाया जाता है, जो तीन वर्षों के भीतर सिद्ध हो","ar":"بالاستخدام الفعلي الذي يُوضَع فيه الصنف المستورد المحدد لاحقًا، بشرط إثباته خلال ثلاث سنوات"},{"en":"By the use in the United States, at or immediately prior to importation, of goods of the class or kind to which the imported goods belong; the controlling use is the principal use","es":"Por el uso en los Estados Unidos, en el momento de la importación o inmediatamente antes de ella, de las mercancías de la clase o tipo a la que pertenecen las mercancías importadas; el uso que rige es el uso principal","ru":"По использованию в Соединённых Штатах, в момент импортирования или непосредственно перед ним, товаров того класса или вида, к которому относятся импортируемые товары; контролирующим является основное использование","tr":"İthal malların ait olduğu sınıf veya türdeki malların, Amerika Birleşik Devletleri'nde, ithalat sırasında veya hemen öncesindeki kullanımına göre; belirleyici kullanım, başlıca kullanımdır","hi":"संयुक्त राज्य अमेरिका में, आयात के समय या उससे ठीक पहले, उस वर्ग या प्रकार के माल के उपयोग द्वारा जिससे आयातित माल संबंधित है; नियंत्रक उपयोग प्रमुख उपयोग है","ar":"بالاستخدام في الولايات المتحدة، في وقت الاستيراد أو قبله مباشرةً، للبضائع من الصنف أو النوع الذي تنتمي إليه البضائع المستوردة؛ والاستخدام المتحكِّم هو الاستخدام الرئيسي"},{"en":"By the use the importer subjectively intends for the article at the time of entry","es":"Por el uso que el importador subjetivamente pretende para el artículo al momento de la entrada","ru":"По использованию, которое импортёр субъективно предполагает для изделия в момент ввоза","tr":"İthalatçının giriş anında ürün için öznel olarak amaçladığı kullanıma göre","hi":"प्रवेश के समय वस्तु के लिए आयातक जो उपयोग व्यक्तिपरक रूप से इरादा रखता है उसके द्वारा","ar":"بالاستخدام الذي يقصده المستورد ذاتيًا للصنف وقت الإدخال"},{"en":"By the most specific description available under GRI 3(a)","es":"Por la descripción más específica disponible bajo la GRI 3(a)","ru":"По наиболее конкретному описанию, доступному согласно GRI 3(a)","tr":"GRI 3(a) kapsamında mevcut en spesifik tanıma göre","hi":"GRI 3(a) के तहत उपलब्ध सबसे विशिष्ट विवरण द्वारा","ar":"بالوصف الأكثر تحديدًا المتاح بموجب GRI 3(a)"}],"e":{"en":"Additional U.S. Rule of Interpretation 1(a): a tariff classification controlled by use (other than actual use) is determined by the use in the United States, at or immediately prior to importation, of goods of that class or kind; the controlling use is the principal use. (Additional U.S. Rule of Interpretation 1(a).)","es":"Additional U.S. Rule of Interpretation 1(a): una clasificación arancelaria regida por el uso (distinto del uso real) se determina por el uso en los Estados Unidos, en el momento de la importación o inmediatamente antes de ella, de las mercancías de esa clase o tipo; el uso que rige es el uso principal. (Additional U.S. Rule of Interpretation 1(a).)","ru":"Дополнительное правило интерпретации США 1(a): тарифная классификация, контролируемая использованием (отличным от фактического использования), определяется по использованию в Соединённых Штатах, в момент импортирования или непосредственно перед ним, товаров того класса или вида; контролирующим является основное использование. (Дополнительное правило интерпретации США 1(a).)","tr":"Additional U.S. Rule of Interpretation 1(a): kullanım (gerçek kullanım dışında) ile belirlenen bir tarife sınıflandırması, o sınıf veya türdeki malların Amerika Birleşik Devletleri'nde, ithalat sırasında veya hemen öncesindeki kullanımına göre belirlenir; belirleyici kullanım, başlıca kullanımdır. (Additional U.S. Rule of Interpretation 1(a).)","hi":"व्याख्या का अतिरिक्त अमेरिकी नियम 1(a): उपयोग द्वारा नियंत्रित एक टैरिफ वर्गीकरण (वास्तविक उपयोग के अलावा) संयुक्त राज्य अमेरिका में, आयात के समय या उससे ठीक पहले, उस वर्ग या प्रकार के माल के उपयोग द्वारा निर्धारित होता है; नियंत्रक उपयोग प्रमुख उपयोग है। (व्याख्या का अतिरिक्त अमेरिकी नियम 1(a)।)","ar":"القاعدة الأمريكية الإضافية للتفسير 1(a): التصنيف الجمركي المتحكَّم فيه بالاستخدام (غير الاستخدام الفعلي) يُحدَّد بالاستخدام في الولايات المتحدة، في وقت الاستيراد أو قبله مباشرةً، للبضائع من ذلك الصنف أو النوع؛ والاستخدام المتحكِّم هو الاستخدام الرئيسي. (القاعدة الأمريكية الإضافية للتفسير 1(a).)"}},{"cat":"classification","a":3,"q":{"en":"An imported article is solely and principally used as a part of a machine, but there is also a specific HTSUS provision that eo nomine (by name) describes that very article. Under the Additional U.S. Rules of Interpretation, how should it be classified?","es":"Un artículo importado se usa única y principalmente como parte de una máquina, pero existe también una disposición específica del HTSUS que eo nomine (por su nombre) describe ese mismo artículo. Bajo las Additional U.S. Rules of Interpretation, ¿cómo debe clasificarse?","ru":"Импортированное изделие используется исключительно и преимущественно как часть машины, но при этом существует конкретное положение HTSUS, которое eo nomine (по наименованию) описывает именно это изделие. Согласно Дополнительным правилам интерпретации США, как его следует классифицировать?","tr":"İthal edilen bir ürün, yalnızca ve esas olarak bir makinenin parçası olarak kullanılır, ancak aynı zamanda o ürünü adıyla (eo nomine) tanımlayan spesifik bir HTSUS hükmü de vardır. Additional U.S. Rules of Interpretation (Ek ABD Yorum Kuralları) kapsamında nasıl sınıflandırılmalıdır?","hi":"एक आयातित वस्तु का उपयोग पूरी तरह से और मुख्य रूप से किसी मशीन के एक भाग के रूप में किया जाता है, लेकिन एक विशिष्ट HTSUS प्रावधान भी है जो eo nomine (नाम से) उसी वस्तु का वर्णन करता है। व्याख्या के अतिरिक्त अमेरिकी नियमों के तहत, इसे कैसे वर्गीकृत किया जाना चाहिए?","ar":"يُستخدَم صنف مستورد حصريًا وبشكل رئيسي كجزء من آلة، لكن يوجد أيضًا حكم محدد في HTSUS يصف هذا الصنف بعينه بالاسم (eo nomine). بموجب القواعد الأمريكية الإضافية للتفسير، كيف ينبغي تصنيفه؟"},"o":[{"en":"Under the parts provision for the machine, because principal use as a part always controls","es":"Bajo la disposición de partes para la máquina, porque el uso principal como parte siempre rige","ru":"По положению о частях для машины, поскольку основное использование в качестве части всегда является контролирующим","tr":"Makineye ilişkin parçalar hükmü altında, çünkü parça olarak başlıca kullanım her zaman belirleyicidir","hi":"मशीन के लिए पुर्जे प्रावधान के तहत, क्योंकि एक भाग के रूप में प्रमुख उपयोग हमेशा नियंत्रित करता है","ar":"تحت حكم الأجزاء الخاص بالآلة، لأن الاستخدام الرئيسي كجزء يتحكم دائمًا"},{"en":"Under whichever provision occurs last in numerical order, per GRI 3(c)","es":"Bajo la disposición que se ubique en último lugar en orden numérico, conforme a la GRI 3(c)","ru":"По тому положению, которое стоит последним в порядке возрастания нумерации, согласно GRI 3(c)","tr":"GRI 3(c) uyarınca, numara sırasında en sonda yer alan hüküm altında","hi":"जो भी प्रावधान संख्यात्मक क्रम में अंतिम आता है उसके तहत, GRI 3(c) के अनुसार","ar":"تحت البند الذي يأتي أخيرًا في الترتيب العددي، وفق GRI 3(c)"},{"en":"Under GRI 4, as goods most akin to a part","es":"Bajo la GRI 4, como mercancías más afines a una parte","ru":"Согласно GRI 4, как товары, наиболее сходные с частью","tr":"GRI 4 kapsamında, bir parçaya en çok benzeyen mallar olarak","hi":"GRI 4 के तहत, एक भाग से सबसे समान माल के रूप में","ar":"تحت GRI 4، باعتباره بضائع أقرب ما تكون إلى جزء"},{"en":"Under the specific eo nomine provision, because a 'parts' provision does not prevail over a specific provision for the article","es":"Bajo la disposición específica eo nomine, porque una disposición de 'partes' no prevalece sobre una disposición específica para el artículo","ru":"По конкретному положению eo nomine, поскольку положение о «частях» не имеет преимущества перед конкретным положением для данного изделия","tr":"Spesifik eo nomine (adıyla) hüküm altında, çünkü bir 'parçalar' hükmü, ürüne ilişkin spesifik bir hükme karşı üstün gelmez","hi":"विशिष्ट eo nomine प्रावधान के तहत, क्योंकि एक 'पुर्जे' प्रावधान वस्तु के लिए एक विशिष्ट प्रावधान पर प्रबल नहीं होता","ar":"تحت الحكم المحدد بالاسم (eo nomine)، لأن حكم \"الأجزاء\" لا يسود على حكم محدد للصنف"}],"e":{"en":"Additional U.S. Rule of Interpretation 1(c): a provision for 'parts' or 'parts and accessories' does not prevail over a specific provision for the part or accessory. A specific (eo nomine) provision controls over a general parts provision. (Additional U.S. Rule of Interpretation 1(c).)","es":"Additional U.S. Rule of Interpretation 1(c): una disposición para 'partes' o 'partes y accesorios' no prevalece sobre una disposición específica para la parte o accesorio. Una disposición específica (eo nomine) rige sobre una disposición general de partes. (Additional U.S. Rule of Interpretation 1(c).)","ru":"Дополнительное правило интерпретации США 1(c): положение о «частях» или «частях и принадлежностях» не имеет преимущества перед конкретным положением для данной части или принадлежности. Конкретное (eo nomine) положение имеет преимущество перед общим положением о частях. (Дополнительное правило интерпретации США 1(c).)","tr":"Additional U.S. Rule of Interpretation 1(c): 'parçalar' veya 'parçalar ve aksesuarlar' için bir hüküm, o parça veya aksesuar için spesifik bir hükme karşı üstün gelmez. Spesifik (eo nomine) bir hüküm, genel bir parçalar hükmüne karşı belirleyicidir. (Additional U.S. Rule of Interpretation 1(c).)","hi":"व्याख्या का अतिरिक्त अमेरिकी नियम 1(c): 'पुर्जे' या 'पुर्जे और एक्सेसरीज' के लिए एक प्रावधान उस भाग या एक्सेसरी के लिए एक विशिष्ट प्रावधान पर प्रबल नहीं होता। एक विशिष्ट (eo nomine) प्रावधान एक सामान्य पुर्जे प्रावधान पर नियंत्रित करता है। (व्याख्या का अतिरिक्त अमेरिकी नियम 1(c)।)","ar":"القاعدة الأمريكية الإضافية للتفسير 1(c): حكم \"الأجزاء\" أو \"الأجزاء واللوازم\" لا يسود على حكم محدد للجزء أو اللازمة. فالحكم المحدد (eo nomine) يتحكم على حكم الأجزاء العام. (القاعدة الأمريكية الإضافية للتفسير 1(c).)"}},{"cat":"valuation","a":1,"q":{"en":"Under the customs appraisement statute and regulations, which basis of appraisement is the PREFERRED method that must be considered first when determining the value of imported merchandise?","es":"Bajo la ley y las regulaciones de avalúo aduanero, ¿qué base de avalúo es el método PREFERIDO que debe considerarse primero al determinar el valor de la mercancía importada?","ru":"Согласно статуту и нормативным актам о таможенной оценке, какая основа оценки является ПРЕДПОЧТИТЕЛЬНЫМ методом, который должен рассматриваться первым при определении стоимости импортируемых товаров?","tr":"Gümrük takdir (appraisement) kanunu ve yönetmelikleri kapsamında, ithal malların değerini belirlerken ilk olarak değerlendirilmesi gereken TERCİH EDİLEN takdir yöntemi hangisidir?","hi":"सीमा शुल्क मूल्यांकन क़ानून और विनियमों के तहत, मूल्यांकन का कौन सा आधार पसंदीदा विधि है जिस पर आयातित माल के मूल्य का निर्धारण करते समय पहले विचार किया जाना चाहिए?","ar":"بموجب قانون ولوائح التقدير الجمركي، أي أساس للتقدير هو الطريقة المُفضَّلة التي يجب النظر فيها أولًا عند تحديد قيمة البضائع المستوردة؟"},"o":[{"en":"Computed value","es":"Valor calculado (computed value)","ru":"Расчётная стоимость","tr":"Hesaplanmış değer (computed value)","hi":"परिकलित मूल्य","ar":"القيمة المحسوبة"},{"en":"Transaction value of the imported merchandise","es":"Valor de transacción de la mercancía importada","ru":"Стоимость сделки с импортируемыми товарами","tr":"İthal malların işlem değeri (transaction value)","hi":"आयातित माल का लेनदेन मूल्य","ar":"قيمة المعاملة للبضائع المستوردة"},{"en":"Deductive value","es":"Valor deductivo (deductive value)","ru":"Дедуктивная стоимость","tr":"İndirgenmiş değer (deductive value)","hi":"कटौती मूल्य","ar":"القيمة الاستنتاجية"},{"en":"Transaction value of similar merchandise","es":"Valor de transacción de mercancía similar","ru":"Стоимость сделки с аналогичными товарами","tr":"Benzer malların işlem değeri","hi":"समान माल का लेनदेन मूल्य","ar":"قيمة المعاملة لبضائع مشابهة"}],"e":{"en":"Transaction value of the imported merchandise is the primary basis of appraisement and must be used unless it cannot be determined or applied; the other methods are used only in the prescribed sequence when transaction value is unavailable. See 19 CFR 152.101(b) and 152.103.","es":"El valor de transacción de la mercancía importada es la base primaria de avalúo y debe usarse a menos que no pueda determinarse o aplicarse; los demás métodos se usan solo en la secuencia prescrita cuando el valor de transacción no está disponible. Véase 19 CFR 152.101(b) y 152.103.","ru":"Стоимость сделки с импортируемыми товарами является первичной основой оценки и должна использоваться, если только она не может быть определена или применена; другие методы используются только в предписанной последовательности, когда стоимость сделки недоступна. См. 19 CFR 152.101(b) и 152.103.","tr":"İthal malların işlem değeri (transaction value), birincil takdir yöntemidir ve belirlenemediği veya uygulanamadığı durumlar haricinde kullanılmalıdır; diğer yöntemler yalnızca işlem değeri mevcut olmadığında öngörülen sırayla kullanılır. Bkz. 19 CFR 152.101(b) ve 152.103.","hi":"आयातित माल का लेनदेन मूल्य मूल्यांकन का प्राथमिक आधार है और इसका उपयोग तब तक किया जाना चाहिए जब तक इसे निर्धारित या लागू नहीं किया जा सकता; अन्य विधियों का उपयोग केवल निर्धारित क्रम में तब किया जाता है जब लेनदेन मूल्य अनुपलब्ध हो। देखें 19 CFR 152.101(b) और 152.103।","ar":"قيمة المعاملة للبضائع المستوردة هي الأساس الأساسي للتقدير ويجب استخدامها ما لم يتعذّر تحديدها أو تطبيقها؛ ولا تُستخدَم الطرق الأخرى إلا بالتسلسل المقرَّر عندما تكون قيمة المعاملة غير متاحة. انظر 19 CFR 152.101(b) و152.103."}},{"cat":"valuation","a":0,"q":{"en":"Transaction value is the 'price actually paid or payable' for the merchandise when sold for exportation to the United States. Which statement BEST describes the 'price actually paid or payable'?","es":"El valor de transacción es el 'precio realmente pagado o por pagar' (price actually paid or payable) por la mercancía cuando se vende para exportación a los Estados Unidos. ¿Qué afirmación describe MEJOR el 'precio realmente pagado o por pagar'?","ru":"Стоимость сделки — это «цена, фактически уплаченная или подлежащая уплате» за товары при их продаже на экспорт в Соединённые Штаты. Какое утверждение НАИЛУЧШИМ образом описывает «цену, фактически уплаченную или подлежащую уплате»?","tr":"İşlem değeri (transaction value), mallar Amerika Birleşik Devletleri'ne ihracat için satıldığında mallar için 'fiilen ödenen veya ödenecek fiyat'tır. Hangi ifade, 'fiilen ödenen veya ödenecek fiyatı' EN İYİ şekilde tanımlar?","hi":"लेनदेन मूल्य माल के लिए 'वास्तव में भुगतान की गई या देय कीमत' है जब इसे संयुक्त राज्य अमेरिका को निर्यात के लिए बेचा जाता है। कौन सा कथन 'वास्तव में भुगतान की गई या देय कीमत' का सबसे अच्छा वर्णन करता है?","ar":"قيمة المعاملة هي \"السعر المدفوع فعليًا أو المستحَق الدفع\" عن البضائع عند بيعها للتصدير إلى الولايات المتحدة. أي عبارة تصف بأفضل شكل \"السعر المدفوع فعليًا أو المستحَق الدفع\"؟"},"o":[{"en":"The total payment made or to be made for the imported merchandise by the buyer to, or for the benefit of, the seller","es":"El pago total realizado o por realizar por la mercancía importada por el comprador al vendedor, o en beneficio de este","ru":"Общий платёж, произведённый или подлежащий произведению за импортированные товары покупателем продавцу или в пользу продавца","tr":"İthal mallar için alıcı tarafından satıcıya veya satıcı yararına yapılan ya da yapılacak toplam ödeme","hi":"खरीदार द्वारा विक्रेता को, या विक्रेता के लाभ के लिए, आयातित माल के लिए किया गया या किया जाने वाला कुल भुगतान","ar":"إجمالي المبلغ المدفوع أو المستحَق الدفع عن البضائع المستوردة من المشتري إلى البائع أو لمصلحته"},{"en":"Only the amount paid by wire transfer directly to the seller before the date of importation","es":"Solo el monto pagado por transferencia bancaria directamente al vendedor antes de la fecha de importación","ru":"Только сумма, уплаченная банковским переводом непосредственно продавцу до даты импортирования","tr":"Yalnızca, ithalat tarihinden önce doğrudan satıcıya havale yoluyla ödenen tutar","hi":"केवल वह राशि जो आयात की तारीख से पहले सीधे विक्रेता को वायर ट्रांसफर द्वारा भुगतान की गई","ar":"فقط المبلغ المدفوع بحوالة بنكية مباشرةً إلى البائع قبل تاريخ الاستيراد"},{"en":"The price shown on the commercial invoice, reduced by any quantity discount","es":"El precio que figura en la factura comercial, reducido por cualquier descuento por cantidad","ru":"Цена, указанная в коммерческом счёте-фактуре, уменьшенная на любую скидку за количество","tr":"Ticari faturada gösterilen fiyatın, herhangi bir miktar indirimi düşülerek azaltılmış hali","hi":"वाणिज्यिक चालान पर दिखाई गई कीमत, किसी भी मात्रा छूट से घटाई गई","ar":"السعر المبيَّن في الفاتورة التجارية، مخفّضًا بأي خصم كمية"},{"en":"The fair market value of the merchandise in the country of exportation on the date of export","es":"El valor justo de mercado de la mercancía en el país de exportación en la fecha de exportación","ru":"Справедливая рыночная стоимость товаров в стране вывоза на дату экспорта","tr":"Malların ihracat ülkesindeki, ihracat tarihindeki adil piyasa değeri","hi":"निर्यात की तारीख पर निर्यात देश में माल का उचित बाजार मूल्य","ar":"القيمة السوقية العادلة للبضائع في بلد التصدير في تاريخ التصدير"}],"e":{"en":"The price actually paid or payable is the total payment (whether or not made directly to the seller) made or to be made for the imported merchandise by the buyer to, or for the benefit of, the seller, exclusive of international freight and insurance. See 19 CFR 152.102(f) and 152.103(a)(1).","es":"El precio realmente pagado o por pagar es el pago total (ya sea hecho directamente al vendedor o no) realizado o por realizar por la mercancía importada por el comprador al vendedor, o en beneficio de este, excluyendo el flete y el seguro internacionales. Véase 19 CFR 152.102(f) y 152.103(a)(1).","ru":"Цена, фактически уплаченная или подлежащая уплате, — это общий платёж (независимо от того, произведён ли он непосредственно продавцу), произведённый или подлежащий произведению за импортированные товары покупателем продавцу или в пользу продавца, за исключением международного фрахта и страхования. См. 19 CFR 152.102(f) и 152.103(a)(1).","tr":"Fiilen ödenen veya ödenecek fiyat, ithal mallar için alıcı tarafından satıcıya veya satıcı yararına (doğrudan satıcıya yapılıp yapılmadığına bakılmaksızın) yapılan ya da yapılacak toplam ödemedir; uluslararası navlun ve sigorta hariçtir. Bkz. 19 CFR 152.102(f) ve 152.103(a)(1).","hi":"वास्तव में भुगतान की गई या देय कीमत वह कुल भुगतान है (चाहे सीधे विक्रेता को किया गया हो या नहीं) जो खरीदार द्वारा विक्रेता को, या विक्रेता के लाभ के लिए, आयातित माल के लिए किया गया या किया जाने वाला है, अंतरराष्ट्रीय माल भाड़े और बीमा को छोड़कर। देखें 19 CFR 152.102(f) और 152.103(a)(1)।","ar":"السعر المدفوع فعليًا أو المستحَق الدفع هو إجمالي المبلغ (سواء دُفِع مباشرةً إلى البائع أم لا) المدفوع أو المستحَق الدفع عن البضائع المستوردة من المشتري إلى البائع أو لمصلحته، باستثناء الشحن والتأمين الدوليين. انظر 19 CFR 152.102(f) و152.103(a)(1)."}},{"cat":"valuation","a":2,"q":{"en":"When determining transaction value, certain amounts are ADDED to the price actually paid or payable to the extent not already included. Which of the following is NOT one of the statutory additions?","es":"Al determinar el valor de transacción, ciertos montos se SUMAN al precio realmente pagado o por pagar en la medida en que no estén ya incluidos. ¿Cuál de los siguientes NO es una de las adiciones legales?","ru":"При определении стоимости сделки определённые суммы ДОБАВЛЯЮТСЯ к цене, фактически уплаченной или подлежащей уплате, в той мере, в какой они ещё не включены. Что из перечисленного НЕ является одним из предусмотренных законом добавлений?","tr":"İşlem değerini (transaction value) belirlerken, henüz dahil edilmemiş olması ölçüsünde fiilen ödenen veya ödenecek fiyata belirli tutarlar EKLENİR. Aşağıdakilerden hangisi yasal ilavelerden biri DEĞİLDİR?","hi":"लेनदेन मूल्य निर्धारित करते समय, कुछ राशियां वास्तव में भुगतान की गई या देय कीमत में जोड़ी जाती हैं, इस सीमा तक कि वे पहले से शामिल न हों। निम्नलिखित में से कौन सी वैधानिक वृद्धियों में से एक नहीं है?","ar":"عند تحديد قيمة المعاملة، تُضاف مبالغ معينة إلى السعر المدفوع فعليًا أو المستحَق الدفع بالقدر غير المُدرَج أصلًا. أي مما يلي ليس من الإضافات القانونية؟"},"o":[{"en":"Packing costs incurred by the buyer","es":"Los costos de empaque incurridos por el comprador","ru":"Расходы на упаковку, понесённые покупателем","tr":"Alıcı tarafından üstlenilen ambalaj masrafları","hi":"खरीदार द्वारा वहन की गई पैकिंग लागत","ar":"تكاليف التعبئة التي يتكبّدها المشتري"},{"en":"Any selling commission incurred by the buyer","es":"Cualquier comisión de venta incurrida por el comprador","ru":"Любая комиссия за продажу, понесённая покупателем","tr":"Alıcı tarafından üstlenilen herhangi bir satış komisyonu","hi":"खरीदार द्वारा वहन किया गया कोई भी विक्रय कमीशन","ar":"أي عمولة بيع يتكبّدها المشتري"},{"en":"The cost of international freight to transport the goods to the United States","es":"El costo del flete internacional para transportar las mercancías a los Estados Unidos","ru":"Стоимость международного фрахта для перевозки товаров в Соединённые Штаты","tr":"Malları Amerika Birleşik Devletleri'ne taşımak için uluslararası navlun masrafı","hi":"माल को संयुक्त राज्य अमेरिका तक पहुंचाने के लिए अंतरराष्ट्रीय माल भाड़े की लागत","ar":"تكلفة الشحن الدولي لنقل البضائع إلى الولايات المتحدة"},{"en":"Any royalty or license fee the buyer must pay as a condition of the sale for export","es":"Cualquier regalía o derecho de licencia que el comprador deba pagar como condición de la venta para exportación","ru":"Любой роялти или лицензионный платёж, который покупатель обязан уплатить как условие продажи на экспорт","tr":"Alıcının, ihracat için satışın bir koşulu olarak ödemek zorunda olduğu herhangi bir telif (royalty) veya lisans ücreti","hi":"कोई भी रॉयल्टी या लाइसेंस शुल्क जो खरीदार को निर्यात के लिए बिक्री की शर्त के रूप में भुगतान करना होगा","ar":"أي إتاوة أو رسم ترخيص يجب على المشتري دفعه كشرط للبيع للتصدير"}],"e":{"en":"The statutory additions are packing costs, selling commissions, the apportioned value of assists, royalties or license fees, and proceeds of subsequent resale accruing to the seller. International freight to the U.S. is excluded from the price actually paid or payable, not an addition. See 19 CFR 152.103(b)(1) and 152.103(i).","es":"Las adiciones legales son los costos de empaque, las comisiones de venta, el valor prorrateado de los assists (aportaciones), las regalías o derechos de licencia, y los productos de cualquier reventa posterior que reviertan al vendedor. El flete internacional a los EE. UU. se excluye del precio realmente pagado o por pagar, no es una adición. Véase 19 CFR 152.103(b)(1) y 152.103(i).","ru":"Предусмотренными законом добавлениями являются: расходы на упаковку, комиссии за продажу, распределённая стоимость assists, роялти или лицензионные платежи и поступления от последующей перепродажи, причитающиеся продавцу. Международный фрахт в США исключается из цены, фактически уплаченной или подлежащей уплате, и не является добавлением. См. 19 CFR 152.103(b)(1) и 152.103(i).","tr":"Yasal ilaveler şunlardır: ambalaj masrafları, satış komisyonları, asistlerin (assist) tahsis edilen değeri, telifler veya lisans ücretleri ve sonraki yeniden satıştan satıcıya tahakkuk eden gelirler. ABD'ye uluslararası navlun, fiilen ödenen veya ödenecek fiyattan hariç tutulur ve bir ilave değildir. Bkz. 19 CFR 152.103(b)(1) ve 152.103(i).","hi":"वैधानिक वृद्धियां हैं पैकिंग लागत, विक्रय कमीशन, सहायताओं (assists) का आबंटित मूल्य, रॉयल्टी या लाइसेंस शुल्क, और विक्रेता को उपार्जित होने वाली बाद की पुनर्विक्रय की आय। संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा वास्तव में भुगतान की गई या देय कीमत से बाहर रखा जाता है, यह एक वृद्धि नहीं है। देखें 19 CFR 152.103(b)(1) और 152.103(i)।","ar":"الإضافات القانونية هي تكاليف التعبئة، وعمولات البيع، والقيمة الموزَّعة للمساعدات (assists)، والإتاوات أو رسوم الترخيص، وعائدات إعادة البيع اللاحقة المستحَقة للبائع. أما الشحن الدولي إلى الولايات المتحدة فمستبعَد من السعر المدفوع فعليًا أو المستحَق الدفع، وليس إضافة. انظر 19 CFR 152.103(b)(1) و152.103(i)."}},{"cat":"valuation","a":3,"q":{"en":"Which of the following items, if separately identified, is EXCLUDED from transaction value (i.e., not part of the appraised value)?","es":"¿Cuál de los siguientes conceptos, si se identifica por separado, se EXCLUYE del valor de transacción (es decir, no forma parte del valor de avalúo)?","ru":"Что из перечисленного, если оно отдельно идентифицировано, ИСКЛЮЧАЕТСЯ из стоимости сделки (то есть не является частью оценочной стоимости)?","tr":"Aşağıdaki kalemlerden hangisi, ayrı olarak belirtilmesi halinde, işlem değerinden (transaction value) HARİÇ TUTULUR (yani takdir edilen değerin bir parçası değildir)?","hi":"निम्नलिखित में से कौन सी वस्तु, यदि अलग से पहचानी जाए, लेनदेन मूल्य से बाहर रखी जाती है (अर्थात, मूल्यांकित मूल्य का हिस्सा नहीं)?","ar":"أي من البنود التالية، إذا حُدِّد بشكل منفصل، يُستبعَد من قيمة المعاملة (أي ليس جزءًا من القيمة المقدّرة)؟"},"o":[{"en":"The apportioned value of a mold supplied free of charge by the buyer to the producer","es":"El valor prorrateado de un molde suministrado gratuitamente por el comprador al productor","ru":"Распределённая стоимость пресс-формы, предоставленной бесплатно покупателем производителю","tr":"Alıcı tarafından üreticiye ücretsiz olarak tedarik edilen bir kalıbın tahsis edilen değeri","hi":"उत्पादक को खरीदार द्वारा मुफ्त में आपूर्ति किए गए एक सांचे का आबंटित मूल्य","ar":"القيمة الموزَّعة لقالب يقدّمه المشتري مجانًا إلى المنتِج"},{"en":"A selling commission paid by the buyer to its agent abroad","es":"Una comisión de venta pagada por el comprador a su agente en el extranjero","ru":"Комиссия за продажу, уплаченная покупателем своему агенту за рубежом","tr":"Alıcı tarafından yurt dışındaki acentesine ödenen bir satış komisyonu","hi":"खरीदार द्वारा विदेश में अपने एजेंट को भुगतान किया गया एक विक्रय कमीशन","ar":"عمولة بيع يدفعها المشتري إلى وكيله في الخارج"},{"en":"The cost of cartons used to pack the goods for shipment to the United States","es":"El costo de las cajas usadas para empacar las mercancías para su embarque a los Estados Unidos","ru":"Стоимость коробок, используемых для упаковки товаров для отправки в Соединённые Штаты","tr":"Malları Amerika Birleşik Devletleri'ne sevk etmek üzere ambalajlamak için kullanılan kartonların maliyeti","hi":"संयुक्त राज्य अमेरिका को शिपमेंट के लिए माल पैक करने हेतु उपयोग किए गए कार्टन की लागत","ar":"تكلفة الكراتين المستخدمة لتعبئة البضائع لشحنها إلى الولايات المتحدة"},{"en":"U.S. customs duties and other Federal taxes payable on the imported merchandise","es":"Los derechos aduaneros de los EE. UU. y otros impuestos federales por pagar sobre la mercancía importada","ru":"Таможенные пошлины США и другие федеральные налоги, подлежащие уплате за импортированные товары","tr":"İthal mallar üzerinde ödenecek ABD gümrük vergileri ve diğer Federal vergiler","hi":"आयातित माल पर देय अमेरिकी सीमा शुल्क और अन्य संघीय कर","ar":"الرسوم الجمركية الأمريكية وغيرها من الضرائب الفيدرالية المستحَقة على البضائع المستوردة"}],"e":{"en":"Customs duties and other Federal taxes (and Federal excise taxes) on the imported merchandise are excluded from transaction value if identified separately. Assists, selling commissions, and packing costs are additions. See 19 CFR 152.103(i).","es":"Los derechos aduaneros y otros impuestos federales (e impuestos especiales federales) sobre la mercancía importada se excluyen del valor de transacción si se identifican por separado. Los assists (aportaciones), las comisiones de venta y los costos de empaque son adiciones. Véase 19 CFR 152.103(i).","ru":"Таможенные пошлины и другие федеральные налоги (а также федеральные акцизные сборы) на импортированные товары исключаются из стоимости сделки, если они идентифицированы отдельно. Assists, комиссии за продажу и расходы на упаковку являются добавлениями. См. 19 CFR 152.103(i).","tr":"İthal mallar üzerindeki gümrük vergileri ve diğer Federal vergiler (ve Federal tüketim vergileri), ayrı olarak belirtilmeleri halinde işlem değerinden hariç tutulur. Asistler (assist), satış komisyonları ve ambalaj masrafları ise ilavelerdir. Bkz. 19 CFR 152.103(i).","hi":"आयातित माल पर सीमा शुल्क और अन्य संघीय कर (और संघीय उत्पाद शुल्क) लेनदेन मूल्य से बाहर रखे जाते हैं यदि अलग से पहचाने जाएं। सहायताएं (assists), विक्रय कमीशन, और पैकिंग लागत वृद्धियां हैं। देखें 19 CFR 152.103(i)।","ar":"الرسوم الجمركية وغيرها من الضرائب الفيدرالية (وضرائب الإنتاج الفيدرالية) على البضائع المستوردة تُستبعَد من قيمة المعاملة إذا حُدِّدت بشكل منفصل. أما المساعدات (assists) وعمولات البيع وتكاليف التعبئة فهي إضافات. انظر 19 CFR 152.103(i)."}},{"cat":"valuation","a":2,"q":{"en":"An importer buys goods for a price actually paid or payable of $50,000. The buyer also paid a $4,000 selling commission to its buying-side commissionaire, paid $2,500 for ocean freight to the U.S., and supplied to the producer free of charge a special mold costing $9,000 that is being used to produce three equal shipments (this is the first of the three). What is the transaction value of this shipment?","es":"Un importador compra mercancías por un precio realmente pagado o por pagar de $50,000. El comprador también pagó una comisión de venta de $4,000 a su comisionista del lado de compra, pagó $2,500 por flete marítimo a los EE. UU., y suministró al productor gratuitamente un molde especial con un costo de $9,000 que se usa para producir tres embarques iguales (este es el primero de los tres). ¿Cuál es el valor de transacción de este embarque?","ru":"Импортёр покупает товары по цене, фактически уплаченной или подлежащей уплате, в размере $50,000. Покупатель также уплатил комиссию за продажу в размере $4,000 своему комиссионеру со стороны покупателя, уплатил $2,500 за морской фрахт в США и предоставил производителю бесплатно специальную пресс-форму стоимостью $9,000, которая используется для производства трёх равных партий (это первая из трёх). Какова стоимость сделки по этой партии?","tr":"Bir ithalatçı, fiilen ödenen veya ödenecek fiyatı $50,000 olan malları satın alır. Alıcı ayrıca, alım tarafındaki komisyoncusuna (commissionaire) $4,000 satış komisyonu ödemiş, ABD'ye deniz navlunu için $2,500 ödemiş ve üreticiye, üç eşit sevkiyatın üretilmesinde kullanılan, maliyeti $9,000 olan özel bir kalıbı ücretsiz olarak tedarik etmiştir (bu, üç sevkiyatın ilkidir). Bu sevkiyatın işlem değeri (transaction value) nedir?","hi":"एक आयातक माल को $50,000 की वास्तव में भुगतान की गई या देय कीमत पर खरीदता है। खरीदार ने अपने खरीद-पक्ष कमीशनेयर को $4,000 विक्रय कमीशन भी भुगतान किया, संयुक्त राज्य अमेरिका तक समुद्री माल भाड़े के लिए $2,500 भुगतान किया, और उत्पादक को मुफ्त में $9,000 लागत का एक विशेष सांचा आपूर्ति किया जो तीन समान शिपमेंट बनाने के लिए उपयोग किया जा रहा है (यह तीन में से पहला है)। इस शिपमेंट का लेनदेन मूल्य क्या है?","ar":"يشتري مستورد بضائع بسعر مدفوع فعليًا أو مستحَق الدفع قدره $50,000. كما دفع المشتري عمولة بيع قدرها $4,000 لوكيله بالعمولة من جانب الشراء، ودفع $2,500 للشحن البحري إلى الولايات المتحدة، وقدّم إلى المنتِج مجانًا قالبًا خاصًا تكلفته $9,000 يُستخدَم لإنتاج ثلاث شحنات متساوية (وهذه هي الأولى من الثلاث). ما هي قيمة المعاملة لهذه الشحنة؟"},"o":[{"en":"$54,000","es":"$54,000","ru":"$54,000","tr":"$54,000","hi":"$54,000","ar":"$54,000"},{"en":"$56,500","es":"$56,500","ru":"$56,500","tr":"$56,500","hi":"$56,500","ar":"$56,500"},{"en":"$57,000","es":"$57,000","ru":"$57,000","tr":"$57,000","hi":"$57,000","ar":"$57,000"},{"en":"$59,500","es":"$59,500","ru":"$59,500","tr":"$59,500","hi":"$59,500","ar":"$59,500"}],"e":{"en":"Transaction value = price ($50,000) + selling commission ($4,000) + apportioned assist ($9,000 / 3 = $3,000) = $57,000. Ocean freight to the U.S. is excluded. Note: a bona fide buying commission would not be added, but a selling commission is. See 19 CFR 152.103(b)(1).","es":"Valor de transacción = precio ($50,000) + comisión de venta ($4,000) + assist prorrateado ($9,000 / 3 = $3,000) = $57,000. El flete marítimo a los EE. UU. se excluye. Nota: una comisión de compra de buena fe no se sumaría, pero una comisión de venta sí. Véase 19 CFR 152.103(b)(1).","ru":"Стоимость сделки = цена ($50,000) + комиссия за продажу ($4,000) + распределённый assist ($9,000 / 3 = $3,000) = $57,000. Морской фрахт в США исключается. Примечание: добросовестная комиссия за покупку не добавлялась бы, но комиссия за продажу добавляется. См. 19 CFR 152.103(b)(1).","tr":"İşlem değeri = fiyat ($50,000) + satış komisyonu ($4,000) + tahsis edilen asist ($9,000 / 3 = $3,000) = $57,000. ABD'ye deniz navlunu hariç tutulur. Not: gerçek (bona fide) bir alım komisyonu eklenmezdi, ancak bir satış komisyonu eklenir. Bkz. 19 CFR 152.103(b)(1).","hi":"लेनदेन मूल्य = कीमत ($50,000) + विक्रय कमीशन ($4,000) + आबंटित सहायता ($9,000 / 3 = $3,000) = $57,000। संयुक्त राज्य अमेरिका तक समुद्री माल भाड़ा बाहर रखा जाता है। ध्यान दें: एक वास्तविक खरीद कमीशन नहीं जोड़ा जाता, लेकिन एक विक्रय कमीशन जोड़ा जाता है। देखें 19 CFR 152.103(b)(1)।","ar":"قيمة المعاملة = السعر ($50,000) + عمولة البيع ($4,000) + المساعدة الموزَّعة ($9,000 / 3 = $3,000) = $57,000. الشحن البحري إلى الولايات المتحدة مستبعَد. ملاحظة: عمولة الشراء الحقيقية لا تُضاف، لكن عمولة البيع تُضاف. انظر 19 CFR 152.103(b)(1)."}},{"cat":"valuation","a":0,"q":{"en":"Which of the following is the BEST definition of an 'assist' for customs valuation purposes?","es":"¿Cuál de las siguientes es la MEJOR definición de un 'assist' (aportación) para efectos de avalúo aduanero?","ru":"Что из перечисленного является НАИЛУЧШИМ определением «assist» (содействия) для целей таможенной оценки?","tr":"Gümrük değerlemesi amaçları açısından bir 'asist' (assist) için aşağıdakilerden hangisi EN İYİ tanımdır?","hi":"सीमा शुल्क मूल्यांकन प्रयोजनों के लिए 'सहायता' (assist) की सबसे अच्छी परिभाषा निम्नलिखित में से कौन सी है?","ar":"أي مما يلي هو أفضل تعريف لـ \"المساعدة\" (assist) لأغراض التقدير الجمركي؟"},"o":[{"en":"Items such as materials, tools, dies, or molds, or engineering done outside the U.S., supplied by the buyer free of charge or at reduced cost for use in producing the merchandise","es":"Conceptos tales como materiales, herramientas, troqueles o moldes, o trabajo de ingeniería realizado fuera de los EE. UU., suministrados por el comprador gratuitamente o a costo reducido para usarse en la producción de la mercancía","ru":"Такие предметы, как материалы, инструменты, штампы или пресс-формы, либо инженерные работы, выполненные за пределами США, предоставленные покупателем бесплатно или по сниженной стоимости для использования при производстве товаров","tr":"Malzemeler, takımlar, kalıplar gibi kalemler ya da ABD dışında yapılan mühendislik gibi, malların üretiminde kullanılmak üzere alıcı tarafından ücretsiz veya indirimli maliyetle tedarik edilen unsurlar","hi":"सामग्री, उपकरण, डाई, या सांचे जैसी वस्तुएं, या संयुक्त राज्य अमेरिका के बाहर किया गया इंजीनियरिंग कार्य, जो खरीदार द्वारा मुफ्त में या घटी हुई लागत पर माल के उत्पादन में उपयोग के लिए आपूर्ति की जाती हैं","ar":"بنود مثل المواد أو الأدوات أو القوالب الحدّية (dies) أو القوالب، أو الأعمال الهندسية المنجَزة خارج الولايات المتحدة، يقدّمها المشتري مجانًا أو بتكلفة مخفّضة للاستخدام في إنتاج البضائع"},{"en":"Any post-importation warranty service provided by the seller to the buyer at no charge","es":"Cualquier servicio de garantía posterior a la importación prestado por el vendedor al comprador sin cargo","ru":"Любое послеввозное гарантийное обслуживание, предоставляемое продавцом покупателю бесплатно","tr":"Satıcı tarafından alıcıya ücretsiz olarak sağlanan herhangi bir ithalat sonrası garanti hizmeti","hi":"विक्रेता द्वारा खरीदार को बिना किसी शुल्क के प्रदान की गई कोई भी आयात-पश्चात वारंटी सेवा","ar":"أي خدمة ضمان بعد الاستيراد يقدّمها البائع للمشتري دون مقابل"},{"en":"Financial assistance or credit extended by the seller to the buyer to facilitate the purchase","es":"Asistencia financiera o crédito otorgado por el vendedor al comprador para facilitar la compra","ru":"Финансовая помощь или кредит, предоставленные продавцом покупателю для облегчения покупки","tr":"Satın almayı kolaylaştırmak için satıcı tarafından alıcıya sağlanan mali yardım veya kredi","hi":"खरीद को सुगम बनाने के लिए विक्रेता द्वारा खरीदार को दी गई वित्तीय सहायता या ऋण","ar":"المساعدة المالية أو الائتمان الذي يقدّمه البائع للمشتري لتيسير الشراء"},{"en":"Any quantity discount granted by the seller because the buyer is a long-standing customer","es":"Cualquier descuento por cantidad otorgado por el vendedor porque el comprador es un cliente de larga data","ru":"Любая скидка за количество, предоставленная продавцом из-за того, что покупатель является давним клиентом","tr":"Alıcının uzun süredir devam eden bir müşteri olması nedeniyle satıcı tarafından verilen herhangi bir miktar indirimi","hi":"विक्रेता द्वारा दी गई कोई भी मात्रा छूट क्योंकि खरीदार एक दीर्घकालिक ग्राहक है","ar":"أي خصم كمية يمنحه البائع لأن المشتري عميل قديم"}],"e":{"en":"An assist is any of the following supplied directly or indirectly, and free of charge or at reduced cost, by the buyer for use in producing or selling the merchandise: (1) materials/components incorporated; (2) tools, dies, molds used in production; (3) merchandise consumed in production; and (4) engineering, development, artwork, design work, plans and sketches undertaken elsewhere than in the U.S. See 19 CFR 152.102(a)(1).","es":"Un assist (aportación) es cualquiera de los siguientes, suministrado directa o indirectamente, y gratuitamente o a costo reducido, por el comprador para usarse en la producción o venta de la mercancía: (1) materiales/componentes incorporados; (2) herramientas, troqueles, moldes usados en la producción; (3) mercancía consumida en la producción; y (4) ingeniería, desarrollo, trabajo artístico, diseño, planos y bocetos realizados fuera de los EE. UU. Véase 19 CFR 152.102(a)(1).","ru":"Assist — это любое из перечисленного, предоставленное прямо или косвенно, бесплатно или по сниженной стоимости, покупателем для использования при производстве или продаже товаров: (1) материалы/компоненты, включённые в товар; (2) инструменты, штампы, пресс-формы, используемые в производстве; (3) товары, потреблённые в производстве; и (4) инженерные работы, разработка, художественные работы, дизайн, планы и эскизы, выполненные за пределами США. См. 19 CFR 152.102(a)(1).","tr":"Bir asist (assist), malların üretiminde veya satışında kullanılmak üzere alıcı tarafından doğrudan veya dolaylı olarak ve ücretsiz ya da indirimli maliyetle tedarik edilen şunlardan herhangi biridir: (1) bünyeye dahil edilen malzemeler/bileşenler; (2) üretimde kullanılan takımlar, kalıplar; (3) üretimde tüketilen mallar; ve (4) ABD dışında bir yerde yürütülen mühendislik, geliştirme, sanat çalışması, tasarım çalışması, planlar ve eskizler. Bkz. 19 CFR 152.102(a)(1).","hi":"एक सहायता (assist) निम्नलिखित में से कोई भी है जो खरीदार द्वारा प्रत्यक्ष या अप्रत्यक्ष रूप से, और मुफ्त में या घटी हुई लागत पर, माल के उत्पादन या बिक्री में उपयोग के लिए आपूर्ति की जाती है: (1) शामिल की गई सामग्री/घटक; (2) उत्पादन में उपयोग किए गए उपकरण, डाई, सांचे; (3) उत्पादन में उपभोग किया गया माल; और (4) इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, योजनाएं और रेखाचित्र जो संयुक्त राज्य अमेरिका के अलावा कहीं और किए गए हों। देखें 19 CFR 152.102(a)(1)।","ar":"المساعدة (assist) هي أي مما يلي مقدَّمًا بشكل مباشر أو غير مباشر، ومجانًا أو بتكلفة مخفّضة، من قبل المشتري للاستخدام في إنتاج البضائع أو بيعها: (1) المواد/المكوّنات المُدمَجة؛ (2) الأدوات والقوالب الحدّية والقوالب المستخدمة في الإنتاج؛ (3) البضائع المستهلَكة في الإنتاج؛ و(4) الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسومات المنجَزة في مكان غير الولايات المتحدة. انظر 19 CFR 152.102(a)(1)."}},{"cat":"valuation","a":0,"q":{"en":"A U.S. buyer provides, free of charge, design work to the foreign producer of imported merchandise. Under what circumstance is this design work NOT treated as a dutiable assist?","es":"Un comprador estadounidense proporciona, gratuitamente, trabajo de diseño al productor extranjero de la mercancía importada. ¿En qué circunstancia este trabajo de diseño NO se trata como un assist (aportación) sujeto a derechos?","ru":"Покупатель из США предоставляет бесплатно дизайнерские работы иностранному производителю импортированных товаров. При каком обстоятельстве эти дизайнерские работы НЕ рассматриваются как облагаемый пошлиной assist?","tr":"Bir ABD alıcısı, ithal malların yabancı üreticisine ücretsiz olarak tasarım çalışması sağlar. Bu tasarım çalışması hangi durumda vergiye tabi bir asist (assist) olarak değerlendirilMEZ?","hi":"एक अमेरिकी खरीदार आयातित माल के विदेशी उत्पादक को मुफ्त में डिज़ाइन कार्य प्रदान करता है। किस परिस्थिति में इस डिज़ाइन कार्य को शुल्क-योग्य सहायता (assist) के रूप में नहीं माना जाता?","ar":"يقدّم مشترٍ أمريكي، مجانًا، أعمال تصميم للمنتِج الأجنبي للبضائع المستوردة. في أي ظرف لا تُعامَل أعمال التصميم هذه كمساعدة خاضعة للرسوم؟"},"o":[{"en":"When the design work is performed by a person domiciled in the United States and is undertaken in the United States","es":"Cuando el trabajo de diseño es realizado por una persona domiciliada en los Estados Unidos y se realiza en los Estados Unidos","ru":"Когда дизайнерские работы выполняются лицом, имеющим постоянное местожительство в Соединённых Штатах, и осуществляются в Соединённых Штатах","tr":"Tasarım çalışması, Amerika Birleşik Devletleri'nde ikamet eden bir kişi tarafından yapıldığında ve Amerika Birleşik Devletleri'nde yürütüldüğünde","hi":"जब डिज़ाइन कार्य संयुक्त राज्य अमेरिका में अधिवासित किसी व्यक्ति द्वारा किया जाता है और संयुक्त राज्य अमेरिका में किया जाता है","ar":"عندما تُنجَز أعمال التصميم على يد شخص مقيم في الولايات المتحدة وتُجرى داخل الولايات المتحدة"},{"en":"When the design work was paid for by the buyer rather than the seller","es":"Cuando el trabajo de diseño fue pagado por el comprador en lugar del vendedor","ru":"Когда дизайнерские работы оплачены покупателем, а не продавцом","tr":"Tasarım çalışmasının satıcı yerine alıcı tarafından ödenmiş olması durumunda","hi":"जब डिज़ाइन कार्य के लिए विक्रेता के बजाय खरीदार द्वारा भुगतान किया गया हो","ar":"عندما يكون المشتري قد دفع ثمن أعمال التصميم بدلًا من البائع"},{"en":"When the value of the design work is less than ten percent of the entered value","es":"Cuando el valor del trabajo de diseño es menor al diez por ciento del valor entrado","ru":"Когда стоимость дизайнерских работ составляет менее десяти процентов заявленной стоимости","tr":"Tasarım çalışmasının değeri, giriş değerinin yüzde onundan az olduğunda","hi":"जब डिज़ाइन कार्य का मूल्य प्रवेश मूल्य के दस प्रतिशत से कम हो","ar":"عندما تكون قيمة أعمال التصميم أقل من عشرة بالمئة من القيمة المُدخَلة"},{"en":"When the design work relates only to packaging rather than to the merchandise itself","es":"Cuando el trabajo de diseño se refiere solo al empaque en lugar de a la mercancía misma","ru":"Когда дизайнерские работы относятся только к упаковке, а не к самим товарам","tr":"Tasarım çalışması, malların kendisiyle değil yalnızca ambalajla ilgili olduğunda","hi":"जब डिज़ाइन कार्य केवल पैकेजिंग से संबंधित हो, न कि स्वयं माल से","ar":"عندما تتعلق أعمال التصميم بالتعبئة فقط وليس بالبضائع ذاتها"}],"e":{"en":"Engineering, development, artwork, design work, and plans and sketches are an assist only if undertaken elsewhere than in the United States. Such work performed by a person domiciled in the U.S. and undertaken in the U.S. is not an assist. See 19 CFR 152.102(a)(1)(iv) and 152.102(a)(2).","es":"La ingeniería, el desarrollo, el trabajo artístico, el diseño, y los planos y bocetos son un assist solo si se realizan fuera de los Estados Unidos. Tal trabajo realizado por una persona domiciliada en los EE. UU. y realizado en los EE. UU. no es un assist. Véase 19 CFR 152.102(a)(1)(iv) y 152.102(a)(2).","ru":"Инженерные работы, разработка, художественные работы, дизайн, планы и эскизы являются assist только в том случае, если они выполнены за пределами Соединённых Штатов. Такие работы, выполненные лицом, имеющим постоянное местожительство в США, и осуществлённые в США, не являются assist. См. 19 CFR 152.102(a)(1)(iv) и 152.102(a)(2).","tr":"Mühendislik, geliştirme, sanat çalışması, tasarım çalışması ile planlar ve eskizler, yalnızca Amerika Birleşik Devletleri dışında bir yerde yürütüldüklerinde bir asisttir (assist). Amerika Birleşik Devletleri'nde ikamet eden bir kişi tarafından yapılan ve Amerika Birleşik Devletleri'nde yürütülen bu tür bir çalışma bir asist değildir. Bkz. 19 CFR 152.102(a)(1)(iv) ve 152.102(a)(2).","hi":"इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, और योजनाएं तथा रेखाचित्र केवल तभी एक सहायता (assist) हैं यदि वे संयुक्त राज्य अमेरिका के अलावा कहीं और किए गए हों। संयुक्त राज्य अमेरिका में अधिवासित किसी व्यक्ति द्वारा संयुक्त राज्य अमेरिका में किया गया ऐसा कार्य एक सहायता नहीं है। देखें 19 CFR 152.102(a)(1)(iv) और 152.102(a)(2)।","ar":"الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسومات تكون مساعدة فقط إذا أُنجِزت في مكان غير الولايات المتحدة. أما هذه الأعمال المنجَزة على يد شخص مقيم في الولايات المتحدة والمُجراة داخلها فليست مساعدة. انظر 19 CFR 152.102(a)(1)(iv) و152.102(a)(2)."}},{"cat":"valuation","a":3,"q":{"en":"When the buyer and seller are related parties, the transaction value is acceptable for appraisement if which of the following is shown?","es":"Cuando el comprador y el vendedor son partes vinculadas (related parties), el valor de transacción es aceptable para avalúo si se demuestra ¿cuál de los siguientes?","ru":"Когда покупатель и продавец являются связанными сторонами, стоимость сделки приемлема для оценки, если показано что из следующего?","tr":"Alıcı ve satıcı ilişkili taraflar (related parties) olduğunda, işlem değeri (transaction value) takdir için aşağıdakilerden hangisi gösterildiğinde kabul edilebilir?","hi":"जब खरीदार और विक्रेता संबंधित पक्ष हों, तो मूल्यांकन के लिए लेनदेन मूल्य स्वीकार्य है यदि निम्नलिखित में से कौन सा दिखाया जाए?","ar":"عندما يكون المشتري والبائع طرفين مرتبطين، تكون قيمة المعاملة مقبولة للتقدير إذا تبيّن أي مما يلي؟"},"o":[{"en":"The merchandise is sold at a price that yields the seller a profit of at least ten percent","es":"La mercancía se vende a un precio que genera al vendedor una utilidad de al menos el diez por ciento","ru":"Товары продаются по цене, обеспечивающей продавцу прибыль не менее десяти процентов","tr":"Mallar, satıcıya en az yüzde on kâr sağlayan bir fiyattan satılır","hi":"माल एक ऐसी कीमत पर बेचा जाता है जो विक्रेता को कम से कम दस प्रतिशत का लाभ देती है","ar":"تُباع البضائع بسعر يحقق للبائع ربحًا لا يقل عن عشرة بالمئة"},{"en":"The related parties file a binding ruling request with CBP before each importation","es":"Las partes vinculadas presentan ante CBP una solicitud de resolución vinculante antes de cada importación","ru":"Связанные стороны подают в CBP запрос об обязывающем решении перед каждым импортированием","tr":"İlişkili taraflar, her ithalattan önce CBP'ye bağlayıcı bir görüş (ruling) talebinde bulunur","hi":"संबंधित पक्ष प्रत्येक आयात से पहले CBP के पास एक बाध्यकारी रूलिंग अनुरोध दाखिल करते हैं","ar":"يقدّم الطرفان المرتبطان طلب قرار مُلزِم إلى CBP قبل كل عملية استيراد"},{"en":"The buyer owns less than fifty percent of the seller's outstanding voting stock","es":"El comprador posee menos del cincuenta por ciento de las acciones con derecho a voto en circulación del vendedor","ru":"Покупатель владеет менее чем пятьюдесятью процентами голосующих акций продавца в обращении","tr":"Alıcı, satıcının ödenmiş oy hakkına sahip hisse senetlerinin yüzde ellisinden azına sahiptir","hi":"खरीदार के पास विक्रेता के बकाया मतदान स्टॉक के पचास प्रतिशत से कम का स्वामित्व है","ar":"يمتلك المشتري أقل من خمسين بالمئة من أسهم البائع القائمة ذات حق التصويت"},{"en":"An examination of the circumstances of the sale indicates the relationship did not influence the price, OR the transaction value closely approximates an acceptable test value","es":"Un examen de las circunstancias de la venta indica que la vinculación no influyó en el precio, O el valor de transacción se aproxima estrechamente a un valor de prueba aceptable","ru":"Изучение обстоятельств продажи показывает, что связь не повлияла на цену, ЛИБО стоимость сделки близко соответствует приемлемой проверочной стоимости (test value)","tr":"Satışın koşullarının incelenmesi ilişkinin fiyatı etkilemediğini gösterir VEYA işlem değeri, kabul edilebilir bir test değerine (test value) yakından yaklaşır","hi":"बिक्री की परिस्थितियों की जांच से संकेत मिलता है कि संबंध ने कीमत को प्रभावित नहीं किया, अथवा लेनदेन मूल्य किसी स्वीकार्य परीक्षण मूल्य के निकट है","ar":"يبيّن فحص ظروف البيع أن العلاقة لم تؤثر في السعر، أو أن قيمة المعاملة تقارب بشكل وثيق قيمة اختبار مقبولة"}],"e":{"en":"For related parties, transaction value is acceptable if examination of the circumstances of sale shows the relationship did not influence the price, or if the value closely approximates a 'test value' (e.g., transaction value of identical/similar merchandise to unrelated buyers, or deductive/computed value of such merchandise). See 19 CFR 152.103(j)(2) and 152.103(l).","es":"Para partes vinculadas, el valor de transacción es aceptable si el examen de las circunstancias de la venta muestra que la vinculación no influyó en el precio, o si el valor se aproxima estrechamente a un 'valor de prueba' (test value) (por ejemplo, el valor de transacción de mercancía idéntica/similar a compradores no vinculados, o el valor deductivo/calculado de tal mercancía). Véase 19 CFR 152.103(j)(2) y 152.103(l).","ru":"Для связанных сторон стоимость сделки приемлема, если изучение обстоятельств продажи показывает, что связь не повлияла на цену, либо если стоимость близко соответствует «проверочной стоимости» (test value) (например, стоимости сделки с идентичными/аналогичными товарами для несвязанных покупателей, либо дедуктивной или расчётной стоимости таких товаров). См. 19 CFR 152.103(j)(2) и 152.103(l).","tr":"İlişkili taraflar için işlem değeri, satış koşullarının incelenmesi ilişkinin fiyatı etkilemediğini gösteriyorsa veya değer bir 'test değerine' yakından yaklaşıyorsa (örneğin, ilişkisiz alıcılara satılan aynı/benzer malların işlem değeri ya da bu malların indirgenmiş/hesaplanmış değeri) kabul edilebilir. Bkz. 19 CFR 152.103(j)(2) ve 152.103(l).","hi":"संबंधित पक्षों के लिए, लेनदेन मूल्य स्वीकार्य है यदि बिक्री की परिस्थितियों की जांच से पता चले कि संबंध ने कीमत को प्रभावित नहीं किया, या यदि मूल्य किसी 'परीक्षण मूल्य' के निकट है (उदाहरण के लिए, असंबंधित खरीदारों को समान/समरूप माल का लेनदेन मूल्य, या ऐसे माल का कटौती/परिकलित मूल्य)। देखें 19 CFR 152.103(j)(2) और 152.103(l)।","ar":"بالنسبة للأطراف المرتبطة، تكون قيمة المعاملة مقبولة إذا بيّن فحص ظروف البيع أن العلاقة لم تؤثر في السعر، أو إذا كانت القيمة تقارب بشكل وثيق \"قيمة اختبار\" (مثل قيمة المعاملة لبضائع مطابقة/مشابهة لمشترين غير مرتبطين، أو القيمة الاستنتاجية/المحسوبة لهذه البضائع). انظر 19 CFR 152.103(j)(2) و152.103(l)."}},{"cat":"valuation","a":2,"q":{"en":"If the transaction value of the imported merchandise cannot be determined, what is the CORRECT order in which the remaining methods of appraisement are applied?","es":"Si el valor de transacción de la mercancía importada no puede determinarse, ¿cuál es el orden CORRECTO en que se aplican los métodos de avalúo restantes?","ru":"Если стоимость сделки с импортированными товарами не может быть определена, каков ПРАВИЛЬНЫЙ порядок применения остальных методов оценки?","tr":"İthal malların işlem değeri (transaction value) belirlenemezse, kalan takdir yöntemleri hangi DOĞRU sırayla uygulanır?","hi":"यदि आयातित माल का लेनदेन मूल्य निर्धारित नहीं किया जा सकता, तो शेष मूल्यांकन विधियों को लागू करने का सही क्रम क्या है?","ar":"إذا تعذّر تحديد قيمة المعاملة للبضائع المستوردة، ما هو الترتيب الصحيح الذي تُطبَّق به طرق التقدير المتبقية؟"},"o":[{"en":"Computed value, then deductive value, then transaction value of similar merchandise, then fallback","es":"Valor calculado, luego valor deductivo, luego valor de transacción de mercancía similar, luego valor de último recurso","ru":"Расчётная стоимость, затем дедуктивная стоимость, затем стоимость сделки с аналогичными товарами, затем резервный метод","tr":"Hesaplanmış değer, ardından indirgenmiş değer, ardından benzer malların işlem değeri, ardından fallback (geri dönüş)","hi":"परिकलित मूल्य, फिर कटौती मूल्य, फिर समान माल का लेनदेन मूल्य, फिर फॉलबैक","ar":"القيمة المحسوبة، ثم القيمة الاستنتاجية، ثم قيمة المعاملة لبضائع مشابهة، ثم الطريقة الاحتياطية"},{"en":"Deductive value, then computed value, then transaction value of identical merchandise, then of similar merchandise, then fallback","es":"Valor deductivo, luego valor calculado, luego valor de transacción de mercancía idéntica, luego de mercancía similar, luego valor de último recurso","ru":"Дедуктивная стоимость, затем расчётная стоимость, затем стоимость сделки с идентичными товарами, затем с аналогичными товарами, затем резервный метод","tr":"İndirgenmiş değer, ardından hesaplanmış değer, ardından özdeş malların işlem değeri, ardından benzer malların işlem değeri, ardından fallback","hi":"कटौती मूल्य, फिर परिकलित मूल्य, फिर एकसमान माल का लेनदेन मूल्य, फिर समान माल का, फिर फॉलबैक","ar":"القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم قيمة المعاملة لبضائع مطابقة، ثم لبضائع مشابهة، ثم الطريقة الاحتياطية"},{"en":"Transaction value of identical merchandise, then of similar merchandise, then deductive value, then computed value, then fallback (derived) value","es":"Valor de transacción de mercancía idéntica, luego de mercancía similar, luego valor deductivo, luego valor calculado, luego valor de último recurso (derivado)","ru":"Стоимость сделки с идентичными товарами, затем с аналогичными товарами, затем дедуктивная стоимость, затем расчётная стоимость, затем резервная (производная) стоимость","tr":"Özdeş malların işlem değeri, ardından benzer malların işlem değeri, ardından indirgenmiş değer, ardından hesaplanmış değer, ardından fallback (türetilmiş) değer","hi":"एकसमान माल का लेनदेन मूल्य, फिर समान माल का, फिर कटौती मूल्य, फिर परिकलित मूल्य, फिर फॉलबैक (व्युत्पन्न) मूल्य","ar":"قيمة المعاملة لبضائع مطابقة، ثم لبضائع مشابهة، ثم القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم القيمة الاحتياطية (المشتقة)"},{"en":"Fallback (derived) value, then deductive value, then computed value, then transaction value of identical merchandise","es":"Valor de último recurso (derivado), luego valor deductivo, luego valor calculado, luego valor de transacción de mercancía idéntica","ru":"Резервная (производная) стоимость, затем дедуктивная стоимость, затем расчётная стоимость, затем стоимость сделки с идентичными товарами","tr":"Fallback (türetilmiş) değer, ardından indirgenmiş değer, ardından hesaplanmış değer, ardından özdeş malların işlem değeri","hi":"फॉलबैक (व्युत्पन्न) मूल्य, फिर कटौती मूल्य, फिर परिकलित मूल्य, फिर एकसमान माल का लेनदेन मूल्य","ar":"القيمة الاحتياطية (المشتقة)، ثم القيمة الاستنتاجية، ثم القيمة المحسوبة، ثم قيمة المعاملة لبضائع مطابقة"}],"e":{"en":"The statutory hierarchy is: transaction value; transaction value of identical merchandise; transaction value of similar merchandise; deductive value; computed value; and finally the fallback (value derived from one of the prior methods adjusted as needed). See 19 CFR 152.101(b).","es":"La jerarquía legal es: valor de transacción; valor de transacción de mercancía idéntica; valor de transacción de mercancía similar; valor deductivo; valor calculado; y finalmente el valor de último recurso (valor derivado de uno de los métodos anteriores ajustado según sea necesario). Véase 19 CFR 152.101(b).","ru":"Установленная законом иерархия такова: стоимость сделки; стоимость сделки с идентичными товарами; стоимость сделки с аналогичными товарами; дедуктивная стоимость; расчётная стоимость; и, наконец, резервный метод (стоимость, производная от одного из предыдущих методов, скорректированная по мере необходимости). См. 19 CFR 152.101(b).","tr":"Yasal hiyerarşi şöyledir: işlem değeri; özdeş malların işlem değeri; benzer malların işlem değeri; indirgenmiş değer (deductive value); hesaplanmış değer (computed value); ve son olarak fallback (önceki yöntemlerden birinden türetilen ve gerektiği gibi düzeltilen değer). Bkz. 19 CFR 152.101(b).","hi":"वैधानिक पदानुक्रम है: लेनदेन मूल्य; एकसमान माल का लेनदेन मूल्य; समान माल का लेनदेन मूल्य; कटौती मूल्य; परिकलित मूल्य; और अंत में फॉलबैक (पूर्व विधियों में से एक से व्युत्पन्न मूल्य, आवश्यकतानुसार समायोजित)। देखें 19 CFR 152.101(b)।","ar":"التسلسل القانوني هو: قيمة المعاملة؛ ثم قيمة المعاملة لبضائع مطابقة؛ ثم قيمة المعاملة لبضائع مشابهة؛ ثم القيمة الاستنتاجية؛ ثم القيمة المحسوبة؛ وأخيرًا الطريقة الاحتياطية (قيمة مشتقة من إحدى الطرق السابقة مع تعديلها حسب الحاجة). انظر 19 CFR 152.101(b)."}},{"cat":"valuation","a":3,"q":{"en":"For appraisement under the transaction value of identical or similar merchandise, the merchandise compared must, among other requirements, have been:","es":"Para el avalúo bajo el valor de transacción de mercancía idéntica o similar, la mercancía comparada debe, entre otros requisitos, haber sido:","ru":"Для оценки по стоимости сделки с идентичными или аналогичными товарами сравниваемые товары должны, среди прочих требований, быть:","tr":"Özdeş veya benzer malların işlem değeri (transaction value) ile takdir için, karşılaştırılan malların, diğer gereklilikler arasında, şu özelliğe sahip olması gerekir:","hi":"एकसमान या समान माल के लेनदेन मूल्य के तहत मूल्यांकन के लिए, तुलना किया जाने वाला माल, अन्य आवश्यकताओं के साथ, ऐसा होना चाहिए जो:","ar":"للتقدير بموجب قيمة المعاملة لبضائع مطابقة أو مشابهة، يجب أن تكون البضائع المُقارَن بها، من بين متطلبات أخرى، قد:"},"o":[{"en":"Produced in any country, so long as it is the same class or kind of goods","es":"Producida en cualquier país, siempre que sea de la misma clase o tipo de mercancías","ru":"Произведены в любой стране, при условии что это товары того же класса или вида","tr":"Aynı sınıf veya türdeki mallar olması koşuluyla herhangi bir ülkede üretilmiş olması","hi":"किसी भी देश में उत्पादित हो, बशर्ते वह माल के समान वर्ग या प्रकार का हो","ar":"أُنتِجت في أي بلد، طالما أنها من الصنف أو النوع نفسه من البضائع"},{"en":"Sold to the same U.S. buyer as the merchandise being appraised","es":"Vendida al mismo comprador estadounidense que la mercancía que se está valuando","ru":"Проданы тому же покупателю в США, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ABD alıcısına satılmış olması","hi":"मूल्यांकित किए जा रहे माल के समान अमेरिकी खरीदार को बेचा गया हो","ar":"بِيعت لنفس المشتري الأمريكي الذي اشترى البضائع موضوع التقدير"},{"en":"Entered through the same U.S. port as the merchandise being appraised","es":"Entrada por el mismo puerto de los EE. UU. que la mercancía que se está valuando","ru":"Ввезены через тот же порт США, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ABD limanından giriş yapmış olması","hi":"मूल्यांकित किए जा रहे माल के समान अमेरिकी बंदरगाह के माध्यम से प्रवेश किया गया हो","ar":"أُدخِلت عبر نفس الميناء الأمريكي الذي أُدخِلت منه البضائع موضوع التقدير"},{"en":"Produced in the same country as, and by the same person as, the merchandise being appraised","es":"Producida en el mismo país que, y por la misma persona que, la mercancía que se está valuando","ru":"Произведены в той же стране и тем же лицом, что и оцениваемые товары","tr":"Takdir edilen mallarla aynı ülkede ve aynı kişi tarafından üretilmiş olması","hi":"मूल्यांकित किए जा रहे माल के समान देश में, और उसी व्यक्ति द्वारा उत्पादित हो","ar":"أُنتِجت في البلد نفسه، وعلى يد الشخص نفسه، الذي أنتَج البضائع موضوع التقدير"}],"e":{"en":"Identical merchandise means goods identical in all respects to, and produced in the same country and by the same person as, the merchandise being appraised; similar merchandise has the same country/producer requirement and must be like in characteristics and component material and commercially interchangeable (with limited provision for another producer in the same country if none exists from the same producer). See 19 CFR 152.102(d), 152.102(i), and 152.104.","es":"Mercancía idéntica significa mercancías idénticas en todos los aspectos a, y producidas en el mismo país y por la misma persona que, la mercancía que se está valuando; la mercancía similar tiene el mismo requisito de país/productor y debe ser semejante en características y material constitutivo, y comercialmente intercambiable (con una disposición limitada para otro productor en el mismo país si no existe del mismo productor). Véase 19 CFR 152.102(d), 152.102(i) y 152.104.","ru":"Идентичные товары означают товары, идентичные во всех отношениях оцениваемым товарам и произведённые в той же стране и тем же лицом; аналогичные товары имеют то же требование о стране/производителе и должны быть схожи по характеристикам и составляющему материалу и коммерчески взаимозаменяемы (с ограниченной возможностью использования другого производителя в той же стране, если товаров от того же производителя нет). См. 19 CFR 152.102(d), 152.102(i) и 152.104.","tr":"Özdeş mallar, takdir edilen mallarla her bakımdan özdeş olan ve onlarla aynı ülkede ve aynı kişi tarafından üretilen malları ifade eder; benzer mallar aynı ülke/üretici gerekliliğine sahiptir ve özellikler ile bileşen malzemesi bakımından benzer ve ticari olarak değiştirilebilir olmalıdır (aynı üreticiden hiç yoksa, aynı ülkedeki başka bir üreticiye yönelik sınırlı bir hükümle). Bkz. 19 CFR 152.102(d), 152.102(i) ve 152.104.","hi":"एकसमान माल का अर्थ है ऐसा माल जो सभी पहलुओं में मूल्यांकित किए जा रहे माल के समान हो, और उसी देश में तथा उसी व्यक्ति द्वारा उत्पादित हो; समान माल में वही देश/उत्पादक आवश्यकता होती है और इसे विशेषताओं तथा घटक सामग्री में जैसा होना चाहिए और वाणिज्यिक रूप से विनिमेय होना चाहिए (यदि उसी उत्पादक से कोई न हो तो उसी देश में किसी अन्य उत्पादक के लिए सीमित प्रावधान के साथ)। देखें 19 CFR 152.102(d), 152.102(i), और 152.104।","ar":"تعني البضائع المطابقة بضائع مطابقة من جميع النواحي، ومُنتَجة في البلد نفسه وعلى يد الشخص نفسه، للبضائع موضوع التقدير؛ أما البضائع المشابهة فلها متطلب البلد/المنتِج نفسه ويجب أن تكون متشابهة في الخصائص والمواد المكوّنة وقابلة للتبادل تجاريًا (مع حكم محدود لمنتِج آخر في البلد نفسه إذا لم يوجد منتِج من المنتِج نفسه). انظر 19 CFR 152.102(d) و152.102(i) و152.104."}},{"cat":"valuation","a":2,"q":{"en":"Computed value is being used to appraise imported merchandise. The producer's records show: cost or value of materials, fabrication, and processing of $30,000; an amount for profit and general expenses (consistent with sales of the same class or kind) of $6,000; an assist not otherwise included valued at $1,500; packing costs of $800; and international freight to the U.S. of $1,200. What is the computed value?","es":"Se está usando el valor calculado (computed value) para valuar mercancía importada. Los registros del productor muestran: costo o valor de los materiales, fabricación y procesamiento de $30,000; un monto por utilidad y gastos generales (consistente con las ventas de la misma clase o tipo) de $6,000; un assist no incluido de otra forma valuado en $1,500; costos de empaque de $800; y flete internacional a los EE. UU. de $1,200. ¿Cuál es el valor calculado?","ru":"Расчётная стоимость используется для оценки импортированных товаров. Записи производителя показывают: стоимость или цену материалов, изготовления и обработки в размере $30,000; сумму на прибыль и общие расходы (соответствующую продажам того же класса или вида) в размере $6,000; assist, не включённый иным образом, стоимостью $1,500; расходы на упаковку в размере $800; и международный фрахт в США в размере $1,200. Какова расчётная стоимость?","tr":"İthal malları takdir etmek için hesaplanmış değer (computed value) kullanılmaktadır. Üreticinin kayıtları şunları göstermektedir: malzemelerin, imalatın ve işlemenin maliyeti veya değeri $30,000; aynı sınıf veya türdeki mal satışlarıyla tutarlı bir kâr ve genel giderler tutarı $6,000; başka türlü dahil edilmemiş, değeri $1,500 olan bir asist (assist); ambalaj masrafları $800; ve ABD'ye uluslararası navlun $1,200. Hesaplanmış değer nedir?","hi":"आयातित माल का मूल्यांकन करने के लिए परिकलित मूल्य का उपयोग किया जा रहा है। उत्पादक के रिकॉर्ड दिखाते हैं: सामग्री, निर्माण, और प्रसंस्करण की लागत या मूल्य $30,000; लाभ और सामान्य खर्चों के लिए एक राशि (समान वर्ग या प्रकार की बिक्री के अनुरूप) $6,000; अन्यथा शामिल न की गई एक सहायता का मूल्य $1,500; पैकिंग लागत $800; और संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा $1,200। परिकलित मूल्य क्या है?","ar":"تُستخدَم القيمة المحسوبة لتقدير بضائع مستوردة. تُظهِر سجلات المنتِج ما يلي: تكلفة أو قيمة المواد والتصنيع والمعالجة قدرها $30,000؛ ومبلغ للربح والمصاريف العامة (متسق مع مبيعات الصنف أو النوع نفسه) قدره $6,000؛ ومساعدة غير مُدرَجة بطريقة أخرى قيمتها $1,500؛ وتكاليف تعبئة قدرها $800؛ وشحن دولي إلى الولايات المتحدة قدره $1,200. ما هي القيمة المحسوبة؟"},"o":[{"en":"$36,000","es":"$36,000","ru":"$36,000","tr":"$36,000","hi":"$36,000","ar":"$36,000"},{"en":"$37,500","es":"$37,500","ru":"$37,500","tr":"$37,500","hi":"$37,500","ar":"$37,500"},{"en":"$38,300","es":"$38,300","ru":"$38,300","tr":"$38,300","hi":"$38,300","ar":"$38,300"},{"en":"$39,500","es":"$39,500","ru":"$39,500","tr":"$39,500","hi":"$39,500","ar":"$39,500"}],"e":{"en":"Computed value = materials/fabrication/processing ($30,000) + profit and general expenses ($6,000) + assist not otherwise included ($1,500) + packing ($800) = $38,300. International freight to the U.S. is not a component of computed value. See 19 CFR 152.106(a) and (b).","es":"Valor calculado = materiales/fabricación/procesamiento ($30,000) + utilidad y gastos generales ($6,000) + assist no incluido de otra forma ($1,500) + empaque ($800) = $38,300. El flete internacional a los EE. UU. no es un componente del valor calculado. Véase 19 CFR 152.106(a) y (b).","ru":"Расчётная стоимость = материалы/изготовление/обработка ($30,000) + прибыль и общие расходы ($6,000) + assist, не включённый иным образом ($1,500) + упаковка ($800) = $38,300. Международный фрахт в США не является компонентом расчётной стоимости. См. 19 CFR 152.106(a) и (b).","tr":"Hesaplanmış değer = malzemeler/imalat/işleme ($30,000) + kâr ve genel giderler ($6,000) + başka türlü dahil edilmemiş asist ($1,500) + ambalaj ($800) = $38,300. ABD'ye uluslararası navlun, hesaplanmış değerin bir bileşeni değildir. Bkz. 19 CFR 152.106(a) ve (b).","hi":"परिकलित मूल्य = सामग्री/निर्माण/प्रसंस्करण ($30,000) + लाभ और सामान्य खर्च ($6,000) + अन्यथा शामिल न की गई सहायता ($1,500) + पैकिंग ($800) = $38,300। संयुक्त राज्य अमेरिका तक अंतरराष्ट्रीय माल भाड़ा परिकलित मूल्य का एक घटक नहीं है। देखें 19 CFR 152.106(a) और (b)।","ar":"القيمة المحسوبة = المواد/التصنيع/المعالجة ($30,000) + الربح والمصاريف العامة ($6,000) + المساعدة غير المُدرَجة بطريقة أخرى ($1,500) + التعبئة ($800) = $38,300. الشحن الدولي إلى الولايات المتحدة ليس مكوّنًا من مكوّنات القيمة المحسوبة. انظر 19 CFR 152.106(a) و(b)."}},{"cat":"valuation","a":0,"q":{"en":"Under the deductive value method, imported merchandise (not further processed) is appraised based on the price at which it is sold in the United States in the greatest aggregate quantity. Which of the following is a permitted DEDUCTION from that U.S. selling price?","es":"Bajo el método de valor deductivo, la mercancía importada (sin procesamiento adicional) se valúa con base en el precio al que se vende en los Estados Unidos en la mayor cantidad agregada (greatest aggregate quantity). ¿Cuál de los siguientes es una DEDUCCIÓN permitida de ese precio de venta en los EE. UU.?","ru":"При методе дедуктивной стоимости импортированные товары (не подвергнутые дальнейшей обработке) оцениваются на основе цены, по которой они продаются в Соединённых Штатах в наибольшем совокупном количестве. Что из перечисленного является допустимым ВЫЧЕТОМ из этой цены продажи в США?","tr":"İndirgenmiş değer (deductive value) yöntemi kapsamında, ithal mallar (daha fazla işlenmemiş), Amerika Birleşik Devletleri'nde en büyük toplam miktarda satıldığı fiyat temelinde takdir edilir. Aşağıdakilerden hangisi, bu ABD satış fiyatından izin verilen bir İNDİRİMDİR?","hi":"कटौती मूल्य विधि के तहत, आयातित माल (आगे संसाधित नहीं) का मूल्यांकन उस कीमत के आधार पर किया जाता है जिस पर इसे संयुक्त राज्य अमेरिका में सबसे बड़ी कुल मात्रा में बेचा जाता है। निम्नलिखित में से कौन सा उस अमेरिकी विक्रय कीमत से एक अनुमत कटौती है?","ar":"بموجب طريقة القيمة الاستنتاجية، تُقدَّر البضائع المستوردة (غير المعالَجة أكثر) استنادًا إلى السعر الذي تُباع به في الولايات المتحدة بأكبر كمية إجمالية. أي مما يلي هو خصم مسموح به من سعر البيع الأمريكي ذلك؟"},"o":[{"en":"The commissions usually paid, or the usual addition for profit and general expenses, in connection with U.S. sales of merchandise of the same class or kind","es":"Las comisiones usualmente pagadas, o la adición usual por utilidad y gastos generales, en relación con las ventas en los EE. UU. de mercancía de la misma clase o tipo","ru":"Комиссии, обычно уплачиваемые, или обычная надбавка на прибыль и общие расходы в связи с продажами в США товаров того же класса или вида","tr":"Aynı sınıf veya türdeki malların ABD satışlarıyla bağlantılı olarak genellikle ödenen komisyonlar veya kâr ve genel giderler için olağan ilave","hi":"समान वर्ग या प्रकार के माल की अमेरिकी बिक्री के संबंध में आम तौर पर भुगतान किए गए कमीशन, या लाभ और सामान्य खर्चों के लिए सामान्य वृद्धि","ar":"العمولات المدفوعة عادةً، أو الإضافة المعتادة للربح والمصاريف العامة، المتعلقة بالمبيعات الأمريكية لبضائع من الصنف أو النوع نفسه"},{"en":"The cost of the assists the buyer supplied to the foreign producer","es":"El costo de los assists que el comprador suministró al productor extranjero","ru":"Стоимость assists, которые покупатель предоставил иностранному производителю","tr":"Alıcının yabancı üreticiye tedarik ettiği asistlerin (assist) maliyeti","hi":"खरीदार द्वारा विदेशी उत्पादक को आपूर्ति की गई सहायताओं की लागत","ar":"تكلفة المساعدات التي قدّمها المشتري إلى المنتِج الأجنبي"},{"en":"Any royalty the buyer pays to a third party unrelated to the U.S. sale","es":"Cualquier regalía que el comprador pague a un tercero no relacionado con la venta en los EE. UU.","ru":"Любой роялти, который покупатель уплачивает третьей стороне, не связанной с продажей в США","tr":"Alıcının, ABD satışıyla ilişkisi olmayan üçüncü bir tarafa ödediği herhangi bir telif (royalty)","hi":"खरीदार द्वारा अमेरिकी बिक्री से असंबंधित किसी तीसरे पक्ष को भुगतान की गई कोई रॉयल्टी","ar":"أي إتاوة يدفعها المشتري لطرف ثالث غير مرتبط بالبيع الأمريكي"},{"en":"The seller's anticipated profit on future shipments of the merchandise","es":"La utilidad anticipada del vendedor sobre embarques futuros de la mercancía","ru":"Ожидаемая прибыль продавца от будущих поставок товаров","tr":"Satıcının malların gelecekteki sevkiyatlarından beklenen kârı","hi":"माल के भविष्य के शिपमेंट पर विक्रेता का प्रत्याशित लाभ","ar":"ربح البائع المتوقَّع على الشحنات المستقبلية من البضائع"}],"e":{"en":"From the U.S. unit price in the greatest aggregate quantity, deductive value subtracts: commissions usually paid (or the usual profit and general expenses) for that class or kind; transportation and insurance costs; U.S. customs duties and Federal taxes; and (if further processed) the value added by processing. See 19 CFR 152.105(c) and (d).","es":"Del precio unitario en los EE. UU. en la mayor cantidad agregada, el valor deductivo resta: las comisiones usualmente pagadas (o la utilidad y gastos generales usuales) para esa clase o tipo; los costos de transporte y seguro; los derechos aduaneros de los EE. UU. e impuestos federales; y (si hay procesamiento adicional) el valor agregado por el procesamiento. Véase 19 CFR 152.105(c) y (d).","ru":"Из удельной цены в США в наибольшем совокупном количестве дедуктивная стоимость вычитает: комиссии, обычно уплачиваемые (или обычную прибыль и общие расходы) для данного класса или вида; расходы на транспортировку и страхование; таможенные пошлины США и федеральные налоги; и (если товары подвергнуты дальнейшей обработке) стоимость, добавленную обработкой. См. 19 CFR 152.105(c) и (d).","tr":"En büyük toplam miktardaki ABD birim fiyatından, indirgenmiş değer şunları çıkarır: o sınıf veya tür için genellikle ödenen komisyonlar (veya olağan kâr ve genel giderler); taşıma ve sigorta masrafları; ABD gümrük vergileri ve Federal vergiler; ve (daha fazla işlenmişse) işlemeyle eklenen değer. Bkz. 19 CFR 152.105(c) ve (d).","hi":"सबसे बड़ी कुल मात्रा में अमेरिकी इकाई कीमत से, कटौती मूल्य घटाता है: उस वर्ग या प्रकार के लिए आम तौर पर भुगतान किए गए कमीशन (या सामान्य लाभ और सामान्य खर्च); परिवहन और बीमा लागत; अमेरिकी सीमा शुल्क और संघीय कर; और (यदि आगे संसाधित हो) प्रसंस्करण द्वारा जोड़ा गया मूल्य। देखें 19 CFR 152.105(c) और (d)।","ar":"من سعر الوحدة الأمريكي بأكبر كمية إجمالية، تطرح القيمة الاستنتاجية: العمولات المدفوعة عادةً (أو الربح والمصاريف العامة المعتادة) لذلك الصنف أو النوع؛ وتكاليف النقل والتأمين؛ والرسوم الجمركية الأمريكية والضرائب الفيدرالية؛ و(إذا عُولِجت أكثر) القيمة المضافة بالمعالجة. انظر 19 CFR 152.105(c) و(d)."}},{"cat":"valuation","a":2,"q":{"en":"For converting a price stated in foreign currency to U.S. dollars for appraisement, the certified quarterly rate of exchange is generally used. When must the certified daily rate be used instead?","es":"Para convertir un precio expresado en moneda extranjera a dólares estadounidenses para efectos de avalúo, generalmente se usa el tipo de cambio trimestral certificado. ¿Cuándo debe usarse en su lugar el tipo de cambio diario certificado?","ru":"Для пересчёта цены, выраженной в иностранной валюте, в доллары США для целей оценки, как правило, используется удостоверенный квартальный курс обмена. Когда вместо него должен использоваться удостоверенный дневной курс?","tr":"Takdir için yabancı para birimiyle belirtilen bir fiyatı ABD dolarına çevirirken, genellikle onaylı üç aylık (quarterly) döviz kuru kullanılır. Onaylı günlük kur (daily rate) bunun yerine ne zaman kullanılmalıdır?","hi":"मूल्यांकन के लिए विदेशी मुद्रा में बताई गई कीमत को अमेरिकी डॉलर में परिवर्तित करने के लिए, आम तौर पर प्रमाणित त्रैमासिक विनिमय दर का उपयोग किया जाता है। प्रमाणित दैनिक दर का उपयोग इसके बजाय कब किया जाना चाहिए?","ar":"لتحويل سعر مذكور بعملة أجنبية إلى دولارات أمريكية لغرض التقدير، يُستخدَم عمومًا سعر الصرف الفصلي المعتمَد. متى يجب استخدام السعر اليومي المعتمَد بدلًا منه؟"},"o":[{"en":"Whenever the importer requests the daily rate in writing on the entry summary","es":"Siempre que el importador solicite el tipo diario por escrito en el resumen de entrada","ru":"Всякий раз, когда импортёр запрашивает дневной курс в письменной форме в итоговой декларации","tr":"İthalatçı giriş özetinde yazılı olarak günlük kuru talep ettiğinde","hi":"जब भी आयातक एंट्री सारांश पर लिखित रूप में दैनिक दर का अनुरोध करता है","ar":"كلما طلب المستورد السعر اليومي كتابةً على ملخص الإدخال"},{"en":"Only when the merchandise is appraised under computed value rather than transaction value","es":"Solo cuando la mercancía se valúa bajo el valor calculado en lugar del valor de transacción","ru":"Только когда товары оцениваются по расчётной стоимости, а не по стоимости сделки","tr":"Yalnızca mallar işlem değeri yerine hesaplanmış değer kapsamında takdir edildiğinde","hi":"केवल जब माल का मूल्यांकन लेनदेन मूल्य के बजाय परिकलित मूल्य के तहत किया जाता है","ar":"فقط عندما تُقدَّر البضائع بموجب القيمة المحسوبة بدلًا من قيمة المعاملة"},{"en":"When the certified daily rate for the date of exportation varies by 5 percent or more from the certified quarterly rate","es":"Cuando el tipo de cambio diario certificado para la fecha de exportación varía en un 5 por ciento o más respecto del tipo de cambio trimestral certificado","ru":"Когда удостоверенный дневной курс на дату вывоза отличается на 5 процентов или более от удостоверенного квартального курса","tr":"İhracat tarihine ilişkin onaylı günlük kur, onaylı üç aylık kurdan yüzde 5 veya daha fazla farklılık gösterdiğinde","hi":"जब निर्यात की तारीख के लिए प्रमाणित दैनिक दर प्रमाणित त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है","ar":"عندما يختلف السعر اليومي المعتمَد لتاريخ التصدير بنسبة 5 بالمئة أو أكثر عن السعر الفصلي المعتمَد"},{"en":"When the date of exportation falls on the last business day of the calendar quarter","es":"Cuando la fecha de exportación cae en el último día hábil del trimestre calendario","ru":"Когда дата вывоза приходится на последний рабочий день календарного квартала","tr":"İhracat tarihi takvim çeyreğinin son iş gününe denk geldiğinde","hi":"जब निर्यात की तारीख कैलेंडर तिमाही के अंतिम कार्य दिवस पर पड़ती है","ar":"عندما يقع تاريخ التصدير في آخر يوم عمل من الربع التقويمي"}],"e":{"en":"The certified quarterly rate is used for the quarter, but if the certified daily rate for the date of exportation varies by 5 percent or more from the quarterly rate, the certified daily rate must be used. The conversion date is the date of exportation. See 19 CFR 159.34(b) and 159.32.","es":"El tipo de cambio trimestral certificado se usa para el trimestre, pero si el tipo de cambio diario certificado para la fecha de exportación varía en un 5 por ciento o más respecto del tipo trimestral, debe usarse el tipo de cambio diario certificado. La fecha de conversión es la fecha de exportación. Véase 19 CFR 159.34(b) y 159.32.","ru":"Удостоверенный квартальный курс используется в течение квартала, но если удостоверенный дневной курс на дату вывоза отличается на 5 процентов или более от квартального курса, должен использоваться удостоверенный дневной курс. Датой пересчёта является дата вывоза. См. 19 CFR 159.34(b) и 159.32.","tr":"Onaylı üç aylık kur, ilgili çeyrek için kullanılır, ancak ihracat tarihine ilişkin onaylı günlük kur, üç aylık kurdan yüzde 5 veya daha fazla farklılık gösteriyorsa onaylı günlük kur kullanılmalıdır. Dönüştürme tarihi, ihracat tarihidir. Bkz. 19 CFR 159.34(b) ve 159.32.","hi":"प्रमाणित त्रैमासिक दर का उपयोग उस तिमाही के लिए किया जाता है, लेकिन यदि निर्यात की तारीख के लिए प्रमाणित दैनिक दर त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है, तो प्रमाणित दैनिक दर का उपयोग किया जाना चाहिए। रूपांतरण तिथि निर्यात की तारीख है। देखें 19 CFR 159.34(b) और 159.32।","ar":"يُستخدَم السعر الفصلي المعتمَد للربع، لكن إذا اختلف السعر اليومي المعتمَد لتاريخ التصدير بنسبة 5 بالمئة أو أكثر عن السعر الفصلي، فيجب استخدام السعر اليومي المعتمَد. وتاريخ التحويل هو تاريخ التصدير. انظر 19 CFR 159.34(b) و159.32."}},{"cat":"valuation","a":3,"q":{"en":"A buyer supplies a special tool to its foreign producer free of charge. The tool cost the buyer $24,000 and is expected to be used to produce 8,000 units total. The current entry covers 2,000 of those units. If the entire tool value is apportioned over the total expected production, what assist value should be added to this entry's transaction value?","es":"Un comprador suministra una herramienta especial a su productor extranjero gratuitamente. La herramienta le costó al comprador $24,000 y se espera que se use para producir 8,000 unidades en total. La entrada actual cubre 2,000 de esas unidades. Si el valor total de la herramienta se prorratea sobre la producción total esperada, ¿qué valor de assist debe sumarse al valor de transacción de esta entrada?","ru":"Покупатель предоставляет специальный инструмент своему иностранному производителю бесплатно. Инструмент обошёлся покупателю в $24,000 и, как ожидается, будет использоваться для производства в общей сложности 8,000 единиц. Текущая декларация охватывает 2,000 из этих единиц. Если вся стоимость инструмента распределяется на весь ожидаемый объём производства, какая стоимость assist должна быть добавлена к стоимости сделки по этой декларации?","tr":"Bir alıcı, yabancı üreticisine özel bir takımı ücretsiz olarak tedarik eder. Takım alıcıya $24,000'a mal olmuştur ve toplamda 8,000 birim üretmek için kullanılması beklenmektedir. Mevcut giriş, bu birimlerin 2,000'ini kapsamaktadır. Takımın tüm değeri toplam beklenen üretime tahsis edilirse, bu girişin işlem değerine hangi asist (assist) değeri eklenmelidir?","hi":"एक खरीदार अपने विदेशी उत्पादक को मुफ्त में एक विशेष उपकरण आपूर्ति करता है। उपकरण की खरीदार को $24,000 लागत आई और इसका उपयोग कुल 8,000 इकाइयों के उत्पादन के लिए होने की उम्मीद है। वर्तमान एंट्री उन इकाइयों में से 2,000 को कवर करती है। यदि संपूर्ण उपकरण मूल्य को कुल अपेक्षित उत्पादन पर आबंटित किया जाए, तो इस एंट्री के लेनदेन मूल्य में कौन सा सहायता मूल्य जोड़ा जाना चाहिए?","ar":"يقدّم مشترٍ أداة خاصة إلى منتِجه الأجنبي مجانًا. كلّفت الأداة المشتري $24,000 ومن المتوقَّع استخدامها لإنتاج 8,000 وحدة إجمالًا. يغطّي الإدخال الحالي 2,000 من تلك الوحدات. إذا وُزِّعت قيمة الأداة كاملةً على إجمالي الإنتاج المتوقَّع، ما هي قيمة المساعدة التي ينبغي إضافتها إلى قيمة المعاملة لهذا الإدخال؟"},"o":[{"en":"$3,000","es":"$3,000","ru":"$3,000","tr":"$3,000","hi":"$3,000","ar":"$3,000"},{"en":"$12,000","es":"$12,000","ru":"$12,000","tr":"$12,000","hi":"$12,000","ar":"$12,000"},{"en":"$24,000","es":"$24,000","ru":"$24,000","tr":"$24,000","hi":"$24,000","ar":"$24,000"},{"en":"$6,000","es":"$6,000","ru":"$6,000","tr":"$6,000","hi":"$6,000","ar":"$6,000"}],"e":{"en":"The value of an assist is apportioned to the imported merchandise in a reasonable manner. Per unit = $24,000 / 8,000 = $3 per unit; for 2,000 units = $6,000. See 19 CFR 152.103(b)(1)(iii) and 152.103(e) (apportionment of assist value).","es":"El valor de un assist se prorratea a la mercancía importada de manera razonable. Por unidad = $24,000 / 8,000 = $3 por unidad; para 2,000 unidades = $6,000. Véase 19 CFR 152.103(b)(1)(iii) y 152.103(e) (prorrateo del valor del assist).","ru":"Стоимость assist распределяется на импортированные товары разумным образом. На единицу = $24,000 / 8,000 = $3 за единицу; для 2,000 единиц = $6,000. См. 19 CFR 152.103(b)(1)(iii) и 152.103(e) (распределение стоимости assist).","tr":"Bir asistin (assist) değeri, ithal mallara makul bir şekilde tahsis edilir. Birim başına = $24,000 / 8,000 = birim başına $3; 2,000 birim için = $6,000. Bkz. 19 CFR 152.103(b)(1)(iii) ve 152.103(e) (asist değerinin tahsisi).","hi":"एक सहायता (assist) का मूल्य आयातित माल को उचित तरीके से आबंटित किया जाता है। प्रति इकाई = $24,000 / 8,000 = $3 प्रति इकाई; 2,000 इकाइयों के लिए = $6,000। देखें 19 CFR 152.103(b)(1)(iii) और 152.103(e) (सहायता मूल्य का आबंटन)।","ar":"تُوزَّع قيمة المساعدة على البضائع المستوردة بطريقة معقولة. لكل وحدة = $24,000 / 8,000 = $3 للوحدة؛ ولـ 2,000 وحدة = $6,000. انظر 19 CFR 152.103(b)(1)(iii) و152.103(e) (توزيع قيمة المساعدة)."}},{"cat":"valuation","a":0,"q":{"en":"A royalty or license fee paid by the buyer is added to the price actually paid or payable in determining transaction value ONLY when:","es":"Una regalía o derecho de licencia pagado por el comprador se suma al precio realmente pagado o por pagar al determinar el valor de transacción SOLO cuando:","ru":"Роялти или лицензионный платёж, уплачиваемый покупателем, добавляется к цене, фактически уплаченной или подлежащей уплате, при определении стоимости сделки ТОЛЬКО когда:","tr":"Alıcı tarafından ödenen bir telif (royalty) veya lisans ücreti, işlem değeri (transaction value) belirlenirken fiilen ödenen veya ödenecek fiyata YALNIZCA hangi durumda eklenir?","hi":"खरीदार द्वारा भुगतान की गई एक रॉयल्टी या लाइसेंस शुल्क लेनदेन मूल्य निर्धारित करने में वास्तव में भुगतान की गई या देय कीमत में केवल तभी जोड़ी जाती है जब:","ar":"تُضاف الإتاوة أو رسم الترخيص الذي يدفعه المشتري إلى السعر المدفوع فعليًا أو المستحَق الدفع عند تحديد قيمة المعاملة فقط عندما:"},"o":[{"en":"The buyer is required to pay it, directly or indirectly, as a condition of the sale of the imported merchandise for exportation to the United States","es":"El comprador está obligado a pagarlo, directa o indirectamente, como condición de la venta de la mercancía importada para exportación a los Estados Unidos","ru":"Покупатель обязан уплатить его, прямо или косвенно, как условие продажи импортированных товаров на экспорт в Соединённые Штаты","tr":"Alıcının, malların Amerika Birleşik Devletleri'ne ihracat için satışının bir koşulu olarak bunu doğrudan veya dolaylı olarak ödemesi gerektiğinde","hi":"खरीदार को इसका भुगतान, प्रत्यक्ष या अप्रत्यक्ष रूप से, संयुक्त राज्य अमेरिका को निर्यात के लिए आयातित माल की बिक्री की शर्त के रूप में करना आवश्यक हो","ar":"يكون المشتري ملزَمًا بدفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضائع المستوردة للتصدير إلى الولايات المتحدة"},{"en":"The royalty is paid to any third party, regardless of its relationship to the sale","es":"La regalía se paga a cualquier tercero, independientemente de su relación con la venta","ru":"Роялти уплачивается любой третьей стороне, независимо от её связи с продажей","tr":"Telifin, satışla ilişkisine bakılmaksızın herhangi bir üçüncü tarafa ödenmesi durumunda","hi":"रॉयल्टी किसी भी तीसरे पक्ष को भुगतान की जाती है, बिक्री से उसके संबंध की परवाह किए बिना","ar":"تُدفَع الإتاوة لأي طرف ثالث، بصرف النظر عن علاقته بالبيع"},{"en":"The royalty represents a charge for the right to reproduce the merchandise in the United States","es":"La regalía representa un cargo por el derecho a reproducir la mercancía en los Estados Unidos","ru":"Роялти представляет собой плату за право воспроизводить товары в Соединённых Штатах","tr":"Telifin, malları Amerika Birleşik Devletleri'nde çoğaltma hakkı için bir bedel temsil etmesi durumunda","hi":"रॉयल्टी संयुक्त राज्य अमेरिका में माल को पुनरुत्पादित करने के अधिकार के लिए एक शुल्क का प्रतिनिधित्व करती है","ar":"تمثّل الإتاوة رسمًا مقابل حق إعادة إنتاج البضائع في الولايات المتحدة"},{"en":"The royalty is paid in U.S. dollars rather than in foreign currency","es":"La regalía se paga en dólares estadounidenses en lugar de en moneda extranjera","ru":"Роялти уплачивается в долларах США, а не в иностранной валюте","tr":"Telifin yabancı para birimi yerine ABD doları olarak ödenmesi durumunda","hi":"रॉयल्टी विदेशी मुद्रा के बजाय अमेरिकी डॉलर में भुगतान की जाती है","ar":"تُدفَع الإتاوة بالدولار الأمريكي بدلًا من العملة الأجنبية"}],"e":{"en":"A royalty or license fee is added only when the buyer is required to pay it, directly or indirectly, as a condition of the sale of the imported merchandise for exportation to the U.S. Charges for the right to reproduce the merchandise in the U.S. are specifically not added. See 19 CFR 152.103(b)(1)(iv) and 152.103(c).","es":"Una regalía o derecho de licencia se suma solo cuando el comprador está obligado a pagarlo, directa o indirectamente, como condición de la venta de la mercancía importada para exportación a los EE. UU. Los cargos por el derecho a reproducir la mercancía en los EE. UU. específicamente no se suman. Véase 19 CFR 152.103(b)(1)(iv) y 152.103(c).","ru":"Роялти или лицензионный платёж добавляется только тогда, когда покупатель обязан уплатить его, прямо или косвенно, как условие продажи импортированных товаров на экспорт в США. Платежи за право воспроизводить товары в США специально не добавляются. См. 19 CFR 152.103(b)(1)(iv) и 152.103(c).","tr":"Bir telif (royalty) veya lisans ücreti yalnızca, alıcının malların Amerika Birleşik Devletleri'ne ihracat için satışının bir koşulu olarak bunu doğrudan veya dolaylı olarak ödemesi gerektiğinde eklenir. Malları Amerika Birleşik Devletleri'nde çoğaltma hakkı için olan bedeller özellikle eklenmez. Bkz. 19 CFR 152.103(b)(1)(iv) ve 152.103(c).","hi":"एक रॉयल्टी या लाइसेंस शुल्क केवल तभी जोड़ा जाता है जब खरीदार को इसका भुगतान, प्रत्यक्ष या अप्रत्यक्ष रूप से, संयुक्त राज्य अमेरिका को निर्यात के लिए आयातित माल की बिक्री की शर्त के रूप में करना आवश्यक हो। संयुक्त राज्य अमेरिका में माल को पुनरुत्पादित करने के अधिकार के लिए शुल्क विशेष रूप से नहीं जोड़े जाते। देखें 19 CFR 152.103(b)(1)(iv) और 152.103(c)।","ar":"تُضاف الإتاوة أو رسم الترخيص فقط عندما يكون المشتري ملزَمًا بدفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضائع المستوردة للتصدير إلى الولايات المتحدة. أما الرسوم مقابل حق إعادة إنتاج البضائع في الولايات المتحدة فلا تُضاف تحديدًا. انظر 19 CFR 152.103(b)(1)(iv) و152.103(c)."}},{"cat":"duties","a":0,"q":{"en":"An importer enters a shipment of goods that are a product of a country with which the United States has normal trade relations and no special trade-program eligibility. Which column of the Harmonized Tariff Schedule of the United States supplies the applicable duty rate?","es":"Un importador declara un embarque de mercancías que son producto de un país con el cual Estados Unidos mantiene relaciones comerciales normales y sin elegibilidad para ningún programa comercial especial. ¿Qué columna del Harmonized Tariff Schedule of the United States (HTSUS) suministra la tasa de derechos aplicable?","ru":"Импортер оформляет ввоз партии товаров, произведенных в стране, с которой Соединенные Штаты имеют нормальные торговые отношения и которая не имеет права на участие в каких-либо специальных торговых программах. Какая колонка Гармонизированного тарифного расписания США (HTSUS) задает применимую ставку пошлины?","tr":"Bir ithalatçı, Amerika Birleşik Devletleri'nin normal ticari ilişkilere sahip olduğu ve herhangi bir özel ticaret programı uygunluğu bulunmayan bir ülkenin ürünü olan bir sevkiyatı beyan ediyor. Uygulanacak vergi oranı, Harmonized Tariff Schedule of the United States (HTSUS) tarifesinin hangi sütunundan alınır?","hi":"एक आयातकर्ता ऐसे माल की एंट्री करता है जो किसी ऐसे देश का उत्पाद है जिसके साथ संयुक्त राज्य अमेरिका के सामान्य व्यापार संबंध (normal trade relations) हैं और जिसकी किसी विशेष व्यापार-कार्यक्रम के लिए कोई पात्रता नहीं है। Harmonized Tariff Schedule of the United States का कौन-सा कॉलम लागू शुल्क दर प्रदान करता है?","ar":"يُدخل مستورد شحنة من البضائع التي تُعدّ منتجاً لبلد تربطه بالولايات المتحدة علاقات تجارية طبيعية ولا يتمتع بأهلية للاستفادة من أي برنامج تجاري خاص. أي عمود من جدول التعريفة المنسّق للولايات المتحدة (HTSUS) يحدّد معدل الرسوم المطبّق؟"},"o":[{"en":"Column 1, General subcolumn","es":"Columna 1, subcolumna General","ru":"Колонка 1, подколонка General (Общая)","tr":"Column 1, General alt sütunu","hi":"Column 1, General उपकॉलम","ar":"Column 1, العمود الفرعي General"},{"en":"Column 1, Special subcolumn","es":"Columna 1, subcolumna Special","ru":"Колонка 1, подколонка Special (Специальная)","tr":"Column 1, Special alt sütunu","hi":"Column 1, Special उपकॉलम","ar":"Column 1, العمود الفرعي Special"},{"en":"Column 2","es":"Columna 2","ru":"Колонка 2","tr":"Column 2","hi":"Column 2","ar":"Column 2"},{"en":"Whichever of Column 1 General or Column 2 is lower","es":"La que sea menor entre la Columna 1 General o la Columna 2","ru":"Та из Колонки 1 General или Колонки 2, которая ниже","tr":"Column 1 General veya Column 2'den hangisi daha düşükse o","hi":"Column 1 General या Column 2 में से जो भी कम हो","ar":"أيٌّ من Column 1 General أو Column 2 يكون أقل"}],"e":{"en":"The Column 1 General (normal trade relations / most-favored-nation) rate applies to products of countries with NTR status that do not qualify for a Special program. The Column 1 Special subcolumn applies only when a specific preference program (e.g., USMCA, GSP) is claimed and met, and Column 2 applies to products of a short list of countries denied NTR (e.g., Cuba, North Korea). See HTSUS General Notes 3(a) and (b).","es":"La tasa de la Columna 1 General (relaciones comerciales normales / nación más favorecida) se aplica a los productos de países con estatus NTR que no califican para un programa Special. La subcolumna Special de la Columna 1 se aplica únicamente cuando se reclama y se cumple un programa de preferencia específico (por ejemplo, USMCA, GSP), y la Columna 2 se aplica a los productos de una breve lista de países a los que se les niega el estatus NTR (por ejemplo, Cuba, Corea del Norte). Véanse las General Notes 3(a) y (b) del HTSUS.","ru":"Ставка Колонки 1 General (нормальные торговые отношения / режим наибольшего благоприятствования) применяется к товарам стран со статусом NTR, которые не имеют права на участие в Специальной программе. Подколонка Колонки 1 Special применяется только тогда, когда заявляется и подтверждается конкретная преференциальная программа (например, USMCA, GSP), а Колонка 2 применяется к товарам короткого перечня стран, лишенных статуса NTR (например, Куба, Северная Корея). См. HTSUS General Notes 3(a) и (b).","tr":"Column 1 General (normal ticari ilişkiler / en çok kayrılan ülke) oranı, NTR statüsüne sahip olan ancak bir Special programa hak kazanmayan ülkelerin ürünlerine uygulanır. Column 1 Special alt sütunu yalnızca belirli bir tercih programı (örneğin USMCA, GSP) talep edildiğinde ve şartları karşılandığında geçerlidir; Column 2 ise NTR'den mahrum bırakılmış kısa bir ülke listesinin (örneğin Küba, Kuzey Kore) ürünlerine uygulanır. Bakınız HTSUS General Notes 3(a) ve (b).","hi":"Column 1 General (normal trade relations / most-favored-nation) दर उन देशों के उत्पादों पर लागू होती है जिनकी NTR स्थिति है और जो किसी Special कार्यक्रम के लिए पात्र नहीं हैं। Column 1 Special उपकॉलम केवल तभी लागू होता है जब कोई विशिष्ट वरीयता कार्यक्रम (जैसे USMCA, GSP) का दावा किया जाए और वह पूरा हो, और Column 2 उन कुछ चुनिंदा देशों के उत्पादों पर लागू होता है जिन्हें NTR से वंचित किया गया है (जैसे Cuba, North Korea)। देखें HTSUS General Notes 3(a) और (b)।","ar":"ينطبق معدل Column 1 General (العلاقات التجارية الطبيعية / الدولة الأولى بالرعاية) على منتجات البلدان التي تتمتع بوضع NTR والتي لا تستوفي شروط برنامج Special. ولا ينطبق العمود الفرعي Column 1 Special إلا عند المطالبة باستيفاء شروط برنامج تفضيلي محدد (مثل USMCA أو GSP). أما Column 2 فينطبق على منتجات قائمة قصيرة من البلدان المحرومة من وضع NTR (مثل كوبا وكوريا الشمالية). انظر HTSUS General Notes 3(a) و(b)."}},{"cat":"duties","a":3,"q":{"en":"Goods are classified under a tariff provision carrying a Column 1 General rate of \"6.5%.\" The merchandise has an appraised (entered) value of forty thousand dollars. What is the estimated ad valorem duty?","es":"Las mercancías se clasifican bajo una disposición arancelaria que tiene una tasa de la Columna 1 General de \"6.5%\". La mercancía tiene un valor avaluado (declarado) de cuarenta mil dólares. ¿Cuál es el derecho ad valorem estimado?","ru":"Товары классифицируются по тарифной позиции со ставкой Колонки 1 General \"6.5%\". Оцененная (заявленная) стоимость товара составляет сорок тысяч долларов. Какова расчетная адвалорная пошлина?","tr":"Mallar, Column 1 General oranı \"%6.5\" olan bir tarife hükmü altında sınıflandırılmıştır. Malların kıymeti (beyan edilen değeri) kırk bin dolardır. Tahmini ad valorem gümrük vergisi nedir?","hi":"माल को एक ऐसे टैरिफ प्रावधान के अंतर्गत वर्गीकृत किया गया है जिसकी Column 1 General दर \"6.5%\" है। माल का मूल्यांकित (एंटर किया गया) मूल्य चालीस हजार डॉलर है। अनुमानित ad valorem शुल्क क्या है?","ar":"تُصنَّف بضائع بموجب بند تعريفي يحمل معدل Column 1 General قدره \"6.5%\". تبلغ القيمة المقدَّرة (المُدخَلة) للبضاعة أربعين ألف دولار. ما هو الرسم القيمي التقديري؟"},"o":[{"en":"Two thousand four hundred dollars","es":"Dos mil cuatrocientos dólares","ru":"Две тысячи четыреста долларов","tr":"İki bin dört yüz dolar","hi":"दो हजार चार सौ डॉलर","ar":"ألفان وأربعمئة دولار"},{"en":"Two thousand five hundred ninety dollars","es":"Dos mil quinientos noventa dólares","ru":"Две тысячи пятьсот девяносто долларов","tr":"İki bin beş yüz doksan dolar","hi":"दो हजार पाँच सौ नब्बे डॉलर","ar":"ألفان وخمسمئة وتسعون دولاراً"},{"en":"Two thousand seven hundred sixty dollars","es":"Dos mil setecientos sesenta dólares","ru":"Две тысячи семьсот шестьдесят долларов","tr":"İki bin yedi yüz altmış dolar","hi":"दो हजार सात सौ साठ डॉलर","ar":"ألفان وسبعمئة وستون دولاراً"},{"en":"Two thousand six hundred dollars","es":"Dos mil seiscientos dólares","ru":"Две тысячи шестьсот долларов","tr":"İki bin altı yüz dolar","hi":"दो हजार छह सौ डॉलर","ar":"ألفان وستمئة دولار"}],"e":{"en":"An ad valorem duty is a percentage of the entered value. $40,000 x 0.065 = $2,600. Ad valorem rates are applied to the customs (transaction) value under 19 U.S.C. 1401a; the rate column is set by HTSUS General Note 3.","es":"Un derecho ad valorem es un porcentaje del valor declarado. $40,000 x 0.065 = $2,600. Las tasas ad valorem se aplican al valor aduanero (valor de transacción) conforme a 19 U.S.C. 1401a; la columna de tasa se establece según la General Note 3 del HTSUS.","ru":"Адвалорная пошлина представляет собой процент от заявленной стоимости. $40,000 x 0.065 = $2,600. Адвалорные ставки применяются к таможенной стоимости (стоимости сделки) согласно 19 U.S.C. 1401a; колонка ставок определяется HTSUS General Note 3.","tr":"Ad valorem gümrük vergisi, beyan edilen değerin bir yüzdesidir. $40,000 x 0.065 = $2,600. Ad valorem oranları, 19 U.S.C. 1401a uyarınca gümrük (işlem) değerine uygulanır; oran sütunu ise HTSUS General Note 3 tarafından belirlenir.","hi":"ad valorem शुल्क एंटर किए गए मूल्य का एक प्रतिशत होता है। $40,000 x 0.065 = $2,600। ad valorem दरें 19 U.S.C. 1401a के तहत कस्टम (लेनदेन) मूल्य पर लागू की जाती हैं; दर कॉलम HTSUS General Note 3 द्वारा निर्धारित होता है।","ar":"الرسم القيمي هو نسبة مئوية من القيمة المُدخَلة. ‎$40,000 x 0.065 = $2,600‎. تُطبَّق المعدلات القيمية على القيمة الجمركية (قيمة المعاملة) بموجب 19 U.S.C. 1401a؛ ويُحدَّد عمود المعدل بموجب HTSUS General Note 3."}},{"cat":"duties","a":2,"q":{"en":"A tariff provision reads \"4.8 cents per liter.\" An importer enters two thousand liters of the product, which has an entered value of nine thousand dollars. What is the duty owed, and what type of rate is this?","es":"Una disposición arancelaria indica \"4.8 cents per liter\". Un importador declara dos mil litros del producto, que tiene un valor declarado de nueve mil dólares. ¿Cuál es el derecho adeudado y qué tipo de tasa es esta?","ru":"Тарифная позиция гласит \"4.8 cents per liter\" (4,8 цента за литр). Импортер оформляет ввоз двух тысяч литров продукта, заявленная стоимость которого составляет девять тысяч долларов. Какова сумма причитающейся пошлины и какой это тип ставки?","tr":"Bir tarife hükmü \"litre başına 4.8 sent\" şeklindedir. Bir ithalatçı, beyan edilen değeri dokuz bin dolar olan üründen iki bin litre beyan ediyor. Ödenecek gümrük vergisi ne kadardır ve bu hangi tür bir orandır?","hi":"एक टैरिफ प्रावधान में लिखा है \"4.8 cents per liter\"। एक आयातकर्ता उत्पाद के दो हजार लीटर की एंट्री करता है, जिसका एंटर किया गया मूल्य नौ हजार डॉलर है। देय शुल्क क्या है, और यह किस प्रकार की दर है?","ar":"ينصّ بند تعريفي على \"4.8 cents per liter\". يُدخل مستورد ألفي لتر من المنتج، وتبلغ قيمته المُدخَلة تسعة آلاف دولار. ما هو الرسم المستحق، وما نوع هذا المعدل؟"},"o":[{"en":"Four hundred thirty-two dollars; an ad valorem duty","es":"Cuatrocientos treinta y dos dólares; un derecho ad valorem","ru":"Четыреста тридцать два доллара; адвалорная пошлина","tr":"Dört yüz otuz iki dolar; ad valorem gümrük vergisi","hi":"चार सौ बत्तीस डॉलर; एक ad valorem शुल्क","ar":"أربعمئة واثنان وثلاثون دولاراً؛ رسم قيمي"},{"en":"Ninety-six dollars; a compound duty","es":"Noventa y seis dólares; un derecho compuesto","ru":"Девяносто шесть долларов; комбинированная (compound) пошлина","tr":"Doksan altı dolar; bileşik (compound) gümrük vergisi","hi":"छियानवे डॉलर; एक संयुक्त (compound) शुल्क","ar":"ستة وتسعون دولاراً؛ رسم مركّب"},{"en":"Ninety-six dollars; a specific duty","es":"Noventa y seis dólares; un derecho específico","ru":"Девяносто шесть долларов; специфическая пошлина","tr":"Doksan altı dolar; spesifik (specific) gümrük vergisi","hi":"छियानवे डॉलर; एक विशिष्ट (specific) शुल्क","ar":"ستة وتسعون دولاراً؛ رسم نوعي"},{"en":"Four hundred thirty-two dollars; a specific duty","es":"Cuatrocientos treinta y dos dólares; un derecho específico","ru":"Четыреста тридцать два доллара; специфическая пошлина","tr":"Dört yüz otuz iki dolar; spesifik (specific) gümrük vergisi","hi":"चार सौ बत्तीस डॉलर; एक विशिष्ट (specific) शुल्क","ar":"أربعمئة واثنان وثلاثون دولاراً؛ رسم نوعي"}],"e":{"en":"A specific duty is assessed on a unit of quantity (here, per liter) regardless of value. 2,000 liters x $0.048 = $96.00. Value is irrelevant to a pure specific rate. See HTSUS General Statistical Note 4 and the rates of duty in the HTSUS.","es":"Un derecho específico se calcula sobre una unidad de cantidad (aquí, por litro) independientemente del valor. 2,000 litros x $0.048 = $96.00. El valor es irrelevante para una tasa específica pura. Véanse la General Statistical Note 4 del HTSUS y las tasas de derechos del HTSUS.","ru":"Специфическая пошлина начисляется на единицу количества (здесь — за литр) независимо от стоимости. 2,000 литров x $0.048 = $96.00. Стоимость не имеет значения для чисто специфической ставки. См. HTSUS General Statistical Note 4 и ставки пошлин в HTSUS.","tr":"Spesifik gümrük vergisi, değerden bağımsız olarak bir miktar birimi (burada litre başına) üzerinden tahakkuk ettirilir. 2,000 litre x $0.048 = $96.00. Saf bir spesifik oran için değer önemsizdir. Bakınız HTSUS General Statistical Note 4 ve HTSUS'taki vergi oranları.","hi":"विशिष्ट (specific) शुल्क मात्रा की इकाई पर (यहाँ, प्रति लीटर) मूल्य की परवाह किए बिना लगाया जाता है। 2,000 लीटर x $0.048 = $96.00। शुद्ध विशिष्ट दर के लिए मूल्य अप्रासंगिक है। देखें HTSUS General Statistical Note 4 और HTSUS में शुल्क की दरें।","ar":"يُفرض الرسم النوعي على وحدة من الكمية (هنا، لكل لتر) بصرف النظر عن القيمة. ‎2,000 liters x $0.048 = $96.00‎. القيمة غير ذات صلة بالمعدل النوعي الخالص. انظر HTSUS General Statistical Note 4 ومعدلات الرسوم في HTSUS."}},{"cat":"duties","a":1,"q":{"en":"A provision carries a compound rate of \"12% + 30 cents per kilogram.\" An importer enters a shipment with an entered value of ten thousand dollars and a net weight of five hundred kilograms. What is the total estimated duty?","es":"Una disposición lleva una tasa compuesta de \"12% + 30 cents per kilogram\". Un importador declara un embarque con un valor declarado de diez mil dólares y un peso neto de quinientos kilogramos. ¿Cuál es el derecho total estimado?","ru":"Позиция имеет комбинированную (compound) ставку \"12% + 30 cents per kilogram\" (12% + 30 центов за килограмм). Импортер оформляет ввоз партии с заявленной стоимостью десять тысяч долларов и чистым весом пятьсот килограммов. Какова общая расчетная пошлина?","tr":"Bir hüküm, \"%12 + kilogram başına 30 sent\" şeklinde bir bileşik (compound) oran taşımaktadır. Bir ithalatçı, beyan edilen değeri on bin dolar ve net ağırlığı beş yüz kilogram olan bir sevkiyat beyan ediyor. Toplam tahmini gümrük vergisi nedir?","hi":"एक प्रावधान में \"12% + 30 cents per kilogram\" की संयुक्त (compound) दर है। एक आयातकर्ता ऐसे माल की एंट्री करता है जिसका एंटर किया गया मूल्य दस हजार डॉलर और शुद्ध वजन पाँच सौ किलोग्राम है। कुल अनुमानित शुल्क क्या है?","ar":"يحمل بند معدلاً مركّباً قدره \"12% + 30 cents per kilogram\". يُدخل مستورد شحنة قيمتها المُدخَلة عشرة آلاف دولار ووزنها الصافي خمسمئة كيلوغرام. ما هو إجمالي الرسم التقديري؟"},"o":[{"en":"One thousand two hundred dollars","es":"Mil doscientos dólares","ru":"Одна тысяча двести долларов","tr":"Bin iki yüz dolar","hi":"एक हजार दो सौ डॉलर","ar":"ألف ومئتا دولار"},{"en":"One thousand three hundred fifty dollars","es":"Mil trescientos cincuenta dólares","ru":"Одна тысяча триста пятьдесят долларов","tr":"Bin üç yüz elli dolar","hi":"एक हजार तीन सौ पचास डॉलर","ar":"ألف وثلاثمئة وخمسون دولاراً"},{"en":"One thousand five hundred dollars","es":"Mil quinientos dólares","ru":"Одна тысяча пятьсот долларов","tr":"Bin beş yüz dolar","hi":"एक हजार पाँच सौ डॉलर","ar":"ألف وخمسمئة دولار"},{"en":"One thousand three hundred twenty dollars","es":"Mil trescientos veinte dólares","ru":"Одна тысяча триста двадцать долларов","tr":"Bin üç yüz yirmi dolar","hi":"एक हजार तीन सौ बीस डॉलर","ar":"ألف وثلاثمئة وعشرون دولاراً"}],"e":{"en":"A compound duty combines an ad valorem and a specific component. Ad valorem: $10,000 x 0.12 = $1,200. Specific: 500 kg x $0.30 = $150. Total = $1,350. Both components are added together. See the HTSUS rates of duty columns.","es":"Un derecho compuesto combina un componente ad valorem y uno específico. Ad valorem: $10,000 x 0.12 = $1,200. Específico: 500 kg x $0.30 = $150. Total = $1,350. Ambos componentes se suman. Véanse las columnas de tasas de derechos del HTSUS.","ru":"Комбинированная (compound) пошлина сочетает адвалорную и специфическую составляющие. Адвалорная: $10,000 x 0.12 = $1,200. Специфическая: 500 kg x $0.30 = $150. Итого = $1,350. Обе составляющие складываются. См. колонки ставок пошлин HTSUS.","tr":"Bileşik (compound) gümrük vergisi, bir ad valorem ve bir spesifik bileşeni birleştirir. Ad valorem: $10,000 x 0.12 = $1,200. Spesifik: 500 kg x $0.30 = $150. Toplam = $1,350. Her iki bileşen birbirine eklenir. Bakınız HTSUS vergi oranları sütunları.","hi":"संयुक्त (compound) शुल्क एक ad valorem और एक विशिष्ट घटक को जोड़ता है। ad valorem: $10,000 x 0.12 = $1,200। विशिष्ट: 500 kg x $0.30 = $150। कुल = $1,350। दोनों घटकों को एक साथ जोड़ा जाता है। देखें HTSUS शुल्क-दर कॉलम।","ar":"يجمع الرسم المركّب بين مكوّن قيمي ومكوّن نوعي. القيمي: ‎$10,000 x 0.12 = $1,200‎. النوعي: ‎500 kg x $0.30 = $150‎. الإجمالي = ‎$1,350‎. يُجمع المكوّنان معاً. انظر أعمدة معدلات الرسوم في HTSUS."}},{"cat":"duties","a":3,"q":{"en":"A formally entered shipment has an entered value of one hundred thousand dollars. Using the current ad valorem merchandise processing fee (MPF) rate, what MPF is owed?","es":"Un embarque declarado formalmente tiene un valor declarado de cien mil dólares. Usando la tasa ad valorem actual del merchandise processing fee (MPF), ¿qué MPF se adeuda?","ru":"Официально оформленная партия имеет заявленную стоимость сто тысяч долларов. С использованием текущей адвалорной ставки сбора за обработку товаров (MPF), какой MPF причитается?","tr":"Resmi olarak beyan edilen bir sevkiyatın beyan edilen değeri yüz bin dolardır. Güncel ad valorem merchandise processing fee (MPF) oranı kullanıldığında, ödenecek MPF ne kadardır?","hi":"औपचारिक रूप से एंटर किए गए माल का एंटर किया गया मूल्य एक लाख डॉलर है। वर्तमान ad valorem merchandise processing fee (MPF) दर का उपयोग करते हुए, कितना MPF देय है?","ar":"شحنة مُدخلة رسمياً قيمتها المُدخَلة مئة ألف دولار. باستخدام المعدل القيمي الحالي لرسم معالجة البضائع (MPF)، ما هو MPF المستحق؟"},"o":[{"en":"Three hundred thirty-three dollars and ninety cents","es":"Trescientos treinta y tres dólares con noventa centavos","ru":"Триста тридцать три доллара и девяносто центов","tr":"Üç yüz otuz üç dolar doksan sent","hi":"तीन सौ तैंतीस डॉलर और नब्बे सेंट","ar":"ثلاثمئة وثلاثة وثلاثون دولاراً وتسعون سنتاً"},{"en":"Six hundred fifty-one dollars and fifty cents","es":"Seiscientos cincuenta y un dólares con cincuenta centavos","ru":"Шестьсот пятьдесят один доллар и пятьдесят центов","tr":"Altı yüz elli bir dolar elli sent","hi":"छह सौ इक्यावन डॉलर और पचास सेंट","ar":"ستمئة وواحد وخمسون دولاراً وخمسون سنتاً"},{"en":"One hundred twenty-five dollars","es":"Ciento veinticinco dólares","ru":"Сто двадцать пять долларов","tr":"Yüz yirmi beş dolar","hi":"एक सौ पच्चीस डॉलर","ar":"مئة وخمسة وعشرون دولاراً"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"}],"e":{"en":"The MPF for formal entries is 0.3464% of the entered value, subject to a minimum and maximum. $100,000 x 0.003464 = $346.40, which falls between the FY2026 minimum of $33.58 and maximum of $651.50, so the calculated amount applies. See 19 CFR 24.23(b)(1).","es":"El MPF para las entradas formales es 0.3464% del valor declarado, sujeto a un mínimo y un máximo. $100,000 x 0.003464 = $346.40, que se encuentra entre el mínimo del FY2026 de $33.58 y el máximo de $651.50, por lo que se aplica el monto calculado. Véase 19 CFR 24.23(b)(1).","ru":"MPF для официальных оформлений (formal entries) составляет 0.3464% от заявленной стоимости, с учетом минимума и максимума. $100,000 x 0.003464 = $346.40, что находится между минимумом FY2026 в $33.58 и максимумом $651.50, поэтому применяется рассчитанная сумма. См. 19 CFR 24.23(b)(1).","tr":"Resmi beyanlar için MPF, beyan edilen değerin %0.3464'üdür ve bir asgari ile azami tutara tabidir. $100,000 x 0.003464 = $346.40; bu tutar FY2026 asgari değeri olan $33.58 ile azami değeri olan $651.50 arasında kaldığından, hesaplanan tutar uygulanır. Bakınız 19 CFR 24.23(b)(1).","hi":"औपचारिक एंट्री के लिए MPF एंटर किए गए मूल्य का 0.3464% है, जो एक न्यूनतम और अधिकतम के अधीन है। $100,000 x 0.003464 = $346.40, जो FY2026 के न्यूनतम $33.58 और अधिकतम $651.50 के बीच आता है, इसलिए गणना की गई राशि लागू होती है। देखें 19 CFR 24.23(b)(1)।","ar":"يبلغ MPF للإدخالات الرسمية 0.3464% من القيمة المُدخَلة، رهناً بحد أدنى وحد أقصى. ‎$100,000 x 0.003464 = $346.40‎، وهو يقع بين الحد الأدنى للسنة المالية FY2026 البالغ ‎$33.58‎ والحد الأقصى البالغ ‎$651.50‎، فينطبق المبلغ المحسوب. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":0,"q":{"en":"A formal entry has an entered value of five thousand dollars. Applying the current MPF rate and its minimum, what MPF is due (FY2026 amounts)?","es":"Una entrada formal tiene un valor declarado de cinco mil dólares. Aplicando la tasa actual del MPF y su mínimo, ¿qué MPF se adeuda (montos del FY2026)?","ru":"Официальное оформление имеет заявленную стоимость пять тысяч долларов. С применением текущей ставки MPF и ее минимума, какой MPF причитается (суммы FY2026)?","tr":"Resmi bir beyanın beyan edilen değeri beş bin dolardır. Güncel MPF oranı ve asgari tutarı uygulandığında, ödenecek MPF ne kadardır (FY2026 tutarları)?","hi":"एक औपचारिक एंट्री का एंटर किया गया मूल्य पाँच हजार डॉलर है। वर्तमान MPF दर और उसके न्यूनतम को लागू करते हुए, कितना MPF देय है (FY2026 राशियाँ)?","ar":"إدخال رسمي قيمته المُدخَلة خمسة آلاف دولار. بتطبيق المعدل الحالي لـ MPF وحدّه الأدنى، ما هو MPF المستحق (مبالغ FY2026)؟"},"o":[{"en":"Thirty-three dollars and fifty-eight cents","es":"Treinta y tres dólares con cincuenta y ocho centavos","ru":"Тридцать три доллара и пятьдесят восемь центов","tr":"Otuz üç dolar elli sekiz sent","hi":"तैंतीस डॉलर और अट्ठावन सेंट","ar":"ثلاثة وثلاثون دولاراً وثمانية وخمسون سنتاً"},{"en":"Seventeen dollars and thirty-two cents","es":"Diecisiete dólares con treinta y dos centavos","ru":"Семнадцать долларов и тридцать два цента","tr":"On yedi dolar otuz iki sent","hi":"सत्रह डॉलर और बत्तीस सेंट","ar":"سبعة عشر دولاراً واثنان وثلاثون سنتاً"},{"en":"Thirty-two dollars and seventy-one cents","es":"Treinta y dos dólares con setenta y un centavos","ru":"Тридцать два доллара и семьдесят один цент","tr":"Otuz iki dolar yetmiş bir sent","hi":"बत्तीस डॉलर और इकहत्तर सेंट","ar":"اثنان وثلاثون دولاراً وواحد وسبعون سنتاً"},{"en":"Twenty-five dollars","es":"Veinticinco dólares","ru":"Двадцать пять долларов","tr":"Yirmi beş dolar","hi":"पच्चीस डॉलर","ar":"خمسة وعشرون دولاراً"}],"e":{"en":"0.3464% of $5,000 = $17.32, which is below the formal-entry MPF minimum. The minimum (effective October 1, 2025, for FY2026) is $33.58, so the floor amount applies. See 19 CFR 24.23(b)(1).","es":"0.3464% de $5,000 = $17.32, que está por debajo del mínimo del MPF para entradas formales. El mínimo (vigente a partir del October 1, 2025, para el FY2026) es $33.58, por lo que se aplica el monto piso. Véase 19 CFR 24.23(b)(1).","ru":"0.3464% от $5,000 = $17.32, что ниже минимума MPF для официального оформления. Минимум (действует с October 1, 2025, для FY2026) составляет $33.58, поэтому применяется нижняя пороговая сумма. См. 19 CFR 24.23(b)(1).","tr":"$5,000'in %0.3464'ü = $17.32; bu tutar resmi beyan MPF asgari değerinin altındadır. Asgari tutar (FY2026 için 1 Ekim 2025'ten itibaren geçerli) $33.58 olduğundan, taban tutarı uygulanır. Bakınız 19 CFR 24.23(b)(1).","hi":"$5,000 का 0.3464% = $17.32, जो औपचारिक-एंट्री MPF न्यूनतम से कम है। न्यूनतम (FY2026 के लिए October 1, 2025 से प्रभावी) $33.58 है, इसलिए न्यूनतम राशि लागू होती है। देखें 19 CFR 24.23(b)(1)।","ar":"‎0.3464% من ‎$5,000 = $17.32‎، وهو أدنى من الحد الأدنى لـ MPF للإدخال الرسمي. الحد الأدنى (النافذ اعتباراً من October 1, 2025 للسنة المالية FY2026) هو ‎$33.58‎، فينطبق مبلغ الحد الأدنى. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":2,"q":{"en":"A formal entry has an entered value of three hundred thousand dollars. Applying the current MPF rate and its cap, what MPF is due (FY2026 amounts)?","es":"Una entrada formal tiene un valor declarado de trescientos mil dólares. Aplicando la tasa actual del MPF y su tope, ¿qué MPF se adeuda (montos del FY2026)?","ru":"Официальное оформление имеет заявленную стоимость триста тысяч долларов. С применением текущей ставки MPF и ее предельного потолка, какой MPF причитается (суммы FY2026)?","tr":"Resmi bir beyanın beyan edilen değeri üç yüz bin dolardır. Güncel MPF oranı ve üst sınırı uygulandığında, ödenecek MPF ne kadardır (FY2026 tutarları)?","hi":"एक औपचारिक एंट्री का एंटर किया गया मूल्य तीन लाख डॉलर है। वर्तमान MPF दर और उसकी अधिकतम सीमा को लागू करते हुए, कितना MPF देय है (FY2026 राशियाँ)?","ar":"إدخال رسمي قيمته المُدخَلة ثلاثمئة ألف دولار. بتطبيق المعدل الحالي لـ MPF وحدّه الأقصى، ما هو MPF المستحق (مبالغ FY2026)؟"},"o":[{"en":"One thousand thirty-nine dollars and twenty cents","es":"Mil treinta y nueve dólares con veinte centavos","ru":"Одна тысяча тридцать девять долларов и двадцать центов","tr":"Bin otuz dokuz dolar yirmi sent","hi":"एक हजार उनतालीस डॉलर और बीस सेंट","ar":"ألف وتسعة وثلاثون دولاراً وعشرون سنتاً"},{"en":"Six hundred thirty-four dollars and sixty-two cents","es":"Seiscientos treinta y cuatro dólares con sesenta y dos centavos","ru":"Шестьсот тридцать четыре доллара и шестьдесят два цента","tr":"Altı yüz otuz dört dolar altmış iki sent","hi":"छह सौ चौंतीस डॉलर और बासठ सेंट","ar":"ستمئة وأربعة وثلاثون دولاراً واثنان وستون سنتاً"},{"en":"Six hundred fifty-one dollars and fifty cents","es":"Seiscientos cincuenta y un dólares con cincuenta centavos","ru":"Шестьсот пятьдесят один доллар и пятьдесят центов","tr":"Altı yüz elli bir dolar elli sent","hi":"छह सौ इक्यावन डॉलर और पचास सेंट","ar":"ستمئة وواحد وخمسون دولاراً وخمسون سنتاً"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"}],"e":{"en":"0.3464% of $300,000 = $1,039.20, which exceeds the formal-entry MPF maximum. The FY2026 maximum (effective October 1, 2025) is $651.50, so the cap applies. The prior-year cap of $634.62 is a distractor. See 19 CFR 24.23(b)(1).","es":"0.3464% de $300,000 = $1,039.20, que excede el máximo del MPF para entradas formales. El máximo del FY2026 (vigente a partir del October 1, 2025) es $651.50, por lo que se aplica el tope. El tope del año anterior de $634.62 es un distractor. Véase 19 CFR 24.23(b)(1).","ru":"0.3464% от $300,000 = $1,039.20, что превышает максимум MPF для официального оформления. Максимум FY2026 (действует с October 1, 2025) составляет $651.50, поэтому применяется потолок. Прошлогодний потолок $634.62 является отвлекающим вариантом. См. 19 CFR 24.23(b)(1).","tr":"$300,000'in %0.3464'ü = $1,039.20; bu tutar resmi beyan MPF azami değerini aşmaktadır. FY2026 azami tutarı (1 Ekim 2025'ten itibaren geçerli) $651.50 olduğundan, üst sınır uygulanır. Önceki yılın üst sınırı olan $634.62 bir şaşırtmacadır. Bakınız 19 CFR 24.23(b)(1).","hi":"$300,000 का 0.3464% = $1,039.20, जो औपचारिक-एंट्री MPF अधिकतम से अधिक है। FY2026 अधिकतम (October 1, 2025 से प्रभावी) $651.50 है, इसलिए अधिकतम सीमा लागू होती है। पिछले वर्ष की $634.62 सीमा एक भ्रामक विकल्प है। देखें 19 CFR 24.23(b)(1)।","ar":"‎0.3464% من ‎$300,000 = $1,039.20‎، وهو يتجاوز الحد الأقصى لـ MPF للإدخال الرسمي. الحد الأقصى للسنة المالية FY2026 (النافذ اعتباراً من October 1, 2025) هو ‎$651.50‎، فينطبق الحد الأقصى. أما الحد الأقصى للسنة السابقة البالغ ‎$634.62‎ فهو خيار مُضلِّل. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":1,"q":{"en":"A shipment of commercial cargo arrives by ocean vessel at a U.S. port subject to the harbor maintenance fee. The cargo's value is eighty thousand dollars. What is the harbor maintenance fee (HMF)?","es":"Un embarque de carga comercial llega por buque oceánico a un puerto de Estados Unidos sujeto al harbor maintenance fee. El valor de la carga es ochenta mil dólares. ¿Cuál es el harbor maintenance fee (HMF)?","ru":"Партия коммерческого груза прибывает морским судном в порт США, подпадающий под сбор за содержание гавани (HMF). Стоимость груза составляет восемьдесят тысяч долларов. Каков сбор за содержание гавани (HMF)?","tr":"Ticari bir yük sevkiyatı, harbor maintenance fee'ye tabi bir ABD limanına deniz yoluyla (gemiyle) ulaşıyor. Yükün değeri seksen bin dolardır. Harbor maintenance fee (HMF) ne kadardır?","hi":"वाणिज्यिक माल का एक शिपमेंट समुद्री जहाज से एक U.S. बंदरगाह पर पहुँचता है जो harbor maintenance fee के अधीन है। माल का मूल्य अस्सी हजार डॉलर है। harbor maintenance fee (HMF) क्या है?","ar":"تصل شحنة من البضائع التجارية بواسطة سفينة بحرية إلى ميناء أمريكي خاضع لرسم صيانة الموانئ. تبلغ قيمة البضاعة ثمانين ألف دولار. ما هو رسم صيانة الموانئ (HMF)؟"},"o":[{"en":"Two hundred seventy-seven dollars and twelve cents","es":"Doscientos setenta y siete dólares con doce centavos","ru":"Двести семьдесят семь долларов и двенадцать центов","tr":"İki yüz yetmiş yedi dolar on iki sent","hi":"दो सौ सतहत्तर डॉलर और बारह सेंट","ar":"مئتان وسبعة وسبعون دولاراً واثنا عشر سنتاً"},{"en":"One hundred dollars","es":"Cien dólares","ru":"Сто долларов","tr":"Yüz dolar","hi":"एक सौ डॉलर","ar":"مئة دولار"},{"en":"Three hundred forty-six dollars and forty cents","es":"Trescientos cuarenta y seis dólares con cuarenta centavos","ru":"Триста сорок шесть долларов и сорок центов","tr":"Üç yüz kırk altı dolar kırk sent","hi":"तीन सौ छियालीस डॉलर और चालीस सेंट","ar":"ثلاثمئة وستة وأربعون دولاراً وأربعون سنتاً"},{"en":"Ten dollars","es":"Diez dólares","ru":"Десять долларов","tr":"On dolar","hi":"दस डॉलर","ar":"عشرة دولارات"}],"e":{"en":"The HMF is 0.125% of the value of the commercial cargo and, unlike the MPF, has no minimum or maximum. $80,000 x 0.00125 = $100.00. The HMF applies to cargo arriving by vessel, not by air. See 19 CFR 24.24(b).","es":"El HMF es 0.125% del valor de la carga comercial y, a diferencia del MPF, no tiene mínimo ni máximo. $80,000 x 0.00125 = $100.00. El HMF se aplica a la carga que llega por buque, no por aire. Véase 19 CFR 24.24(b).","ru":"HMF составляет 0.125% от стоимости коммерческого груза и, в отличие от MPF, не имеет ни минимума, ни максимума. $80,000 x 0.00125 = $100.00. HMF применяется к грузам, прибывающим судном, а не по воздуху. См. 19 CFR 24.24(b).","tr":"HMF, ticari yükün değerinin %0.125'idir ve MPF'nin aksine asgari veya azami tutarı yoktur. $80,000 x 0.00125 = $100.00. HMF, hava yoluyla değil, gemiyle ulaşan yüke uygulanır. Bakınız 19 CFR 24.24(b).","hi":"HMF वाणिज्यिक माल के मूल्य का 0.125% है और, MPF के विपरीत, इसका कोई न्यूनतम या अधिकतम नहीं है। $80,000 x 0.00125 = $100.00। HMF जहाज से पहुँचने वाले माल पर लागू होता है, हवाई माल पर नहीं। देखें 19 CFR 24.24(b)।","ar":"يبلغ HMF 0.125% من قيمة البضائع التجارية، وخلافاً لـ MPF لا يخضع لحد أدنى أو أقصى. ‎$80,000 x 0.00125 = $100.00‎. ينطبق HMF على البضائع الواصلة بالسفن، لا بالجو. انظر 19 CFR 24.24(b)."}},{"cat":"duties","a":0,"q":{"en":"Which statement correctly distinguishes the merchandise processing fee from the harbor maintenance fee?","es":"¿Qué afirmación distingue correctamente el merchandise processing fee del harbor maintenance fee?","ru":"Какое утверждение правильно отличает сбор за обработку товаров (MPF) от сбора за содержание гавани (HMF)?","tr":"Aşağıdaki ifadelerden hangisi, merchandise processing fee'yi harbor maintenance fee'den doğru şekilde ayırt etmektedir?","hi":"कौन-सा कथन merchandise processing fee को harbor maintenance fee से सही ढंग से अलग करता है?","ar":"أي عبارة تميّز بشكل صحيح رسم معالجة البضائع عن رسم صيانة الموانئ؟"},"o":[{"en":"The MPF for formal entries has a minimum and maximum, while the HMF (0.125%) has neither","es":"El MPF para entradas formales tiene un mínimo y un máximo, mientras que el HMF (0.125%) no tiene ninguno de los dos","ru":"MPF для официальных оформлений имеет минимум и максимум, тогда как HMF (0.125%) не имеет ни того, ни другого","tr":"Resmi beyanlar için MPF'nin bir asgari ve azami tutarı vardır; HMF (%0.125) ise ne asgari ne de azami tutara sahiptir","hi":"औपचारिक एंट्री के लिए MPF का एक न्यूनतम और अधिकतम होता है, जबकि HMF (0.125%) का कोई भी नहीं होता","ar":"يخضع MPF للإدخالات الرسمية لحد أدنى وحد أقصى، بينما لا يخضع HMF (0.125%) لأيٍّ منهما"},{"en":"Both fees have a statutory minimum and maximum per entry","es":"Ambas tarifas tienen un mínimo y un máximo legal por entrada","ru":"Оба сбора имеют установленный законом минимум и максимум на одно оформление","tr":"Her iki ücretin de beyan başına yasal bir asgari ve azami tutarı vardır","hi":"दोनों शुल्कों का प्रति एंट्री एक वैधानिक न्यूनतम और अधिकतम होता है","ar":"يخضع كلا الرسمين لحد أدنى وحد أقصى قانوني لكل إدخال"},{"en":"The HMF applies to both vessel and air shipments; the MPF applies only to vessel shipments","es":"El HMF se aplica tanto a embarques por buque como por aire; el MPF se aplica solo a embarques por buque","ru":"HMF применяется как к морским, так и к авиационным отправлениям; MPF применяется только к морским отправлениям","tr":"HMF hem gemi hem hava sevkiyatlarına uygulanır; MPF yalnızca gemi sevkiyatlarına uygulanır","hi":"HMF जहाज और हवाई दोनों शिपमेंट पर लागू होता है; MPF केवल जहाज शिपमेंट पर लागू होता है","ar":"ينطبق HMF على الشحنات البحرية والجوية معاً؛ بينما ينطبق MPF على الشحنات البحرية فقط"},{"en":"The MPF is 0.125% and the HMF is 0.3464% of value","es":"El MPF es 0.125% y el HMF es 0.3464% del valor","ru":"MPF составляет 0.125%, а HMF — 0.3464% от стоимости","tr":"MPF değerin %0.125'i, HMF ise %0.3464'üdür","hi":"MPF मूल्य का 0.125% है और HMF 0.3464% है","ar":"يبلغ MPF نسبة 0.125% بينما يبلغ HMF نسبة 0.3464% من القيمة"}],"e":{"en":"The formal-entry MPF is 0.3464% with a per-entry minimum and maximum, whereas the HMF is a flat 0.125% of cargo value with no floor or ceiling. The HMF applies to waterborne cargo, not air. See 19 CFR 24.23(b)(1) and 19 CFR 24.24.","es":"El MPF para entradas formales es 0.3464% con un mínimo y un máximo por entrada, mientras que el HMF es un 0.125% fijo del valor de la carga sin piso ni techo. El HMF se aplica a la carga transportada por agua, no por aire. Véanse 19 CFR 24.23(b)(1) y 19 CFR 24.24.","ru":"MPF для официального оформления составляет 0.3464% с минимумом и максимумом на одно оформление, тогда как HMF — это фиксированные 0.125% от стоимости груза без нижнего или верхнего предела. HMF применяется к грузам, перевозимым по воде, а не по воздуху. См. 19 CFR 24.23(b)(1) и 19 CFR 24.24.","tr":"Resmi beyan MPF'si, beyan başına bir asgari ve azami tutara sahip %0.3464 oranındadır; HMF ise yük değerinin sabit %0.125'i olup taban veya tavanı yoktur. HMF, hava yoluyla değil su yoluyla taşınan yüke uygulanır. Bakınız 19 CFR 24.23(b)(1) ve 19 CFR 24.24.","hi":"औपचारिक-एंट्री MPF 0.3464% है जिसका प्रति एंट्री एक न्यूनतम और अधिकतम होता है, जबकि HMF माल मूल्य का एक समान 0.125% है जिसका कोई न्यूनतम या अधिकतम नहीं है। HMF जलमार्ग से आने वाले माल पर लागू होता है, हवाई पर नहीं। देखें 19 CFR 24.23(b)(1) और 19 CFR 24.24।","ar":"يبلغ MPF للإدخال الرسمي 0.3464% مع حد أدنى وحد أقصى لكل إدخال، بينما HMF رسم ثابت قدره 0.125% من قيمة البضاعة دون حد أدنى أو أقصى. وينطبق HMF على البضائع المنقولة بحراً، لا جواً. انظر 19 CFR 24.23(b)(1) و19 CFR 24.24."}},{"cat":"duties","a":3,"q":{"en":"Antidumping duties (ADD) are imposed to remedy which condition, and on what basis are the cash-deposit rates generally established?","es":"Los derechos antidumping (ADD) se imponen para remediar qué condición, ¿y sobre qué base se establecen generalmente las tasas de depósito en efectivo?","ru":"Антидемпинговые пошлины (ADD) вводятся для устранения какого условия, и на какой основе обычно устанавливаются ставки денежного депозита?","tr":"Antidumping vergileri (ADD) hangi durumu gidermek için uygulanır ve nakit teminat oranları genellikle hangi esasa göre belirlenir?","hi":"Antidumping शुल्क (ADD) किस स्थिति को ठीक करने के लिए लगाए जाते हैं, और cash-deposit दरें आम तौर पर किस आधार पर निर्धारित की जाती हैं?","ar":"تُفرض رسوم مكافحة الإغراق (ADD) لمعالجة أي حالة، وعلى أي أساس تُحدَّد عموماً معدلات الإيداع النقدي؟"},"o":[{"en":"Foreign government subsidies; based on the net countervailable subsidy","es":"Subsidios de un gobierno extranjero; con base en el subsidio neto compensable","ru":"Субсидии иностранного правительства; на основе чистой компенсируемой субсидии","tr":"Yabancı hükümet sübvansiyonları; net telafi edilebilir sübvansiyon esasına göre","hi":"विदेशी सरकार की सब्सिडी; शुद्ध countervailable सब्सिडी के आधार पर","ar":"إعانات الحكومة الأجنبية؛ استناداً إلى صافي الإعانة القابلة للتعويض"},{"en":"National-security threats; based on a flat 25% surcharge","es":"Amenazas a la seguridad nacional; con base en un recargo fijo del 25%","ru":"Угрозы национальной безопасности; на основе фиксированной надбавки в 25%","tr":"Ulusal güvenlik tehditleri; sabit %25 ek vergi esasına göre","hi":"राष्ट्रीय-सुरक्षा खतरे; एक समान 25% अधिभार के आधार पर","ar":"التهديدات للأمن القومي؛ استناداً إلى رسم إضافي ثابت قدره 25%"},{"en":"Import surges; based on a tariff-rate quota over-quota rate","es":"Aumentos repentinos de importaciones; con base en la tasa por encima del cupo de un contingente arancelario","ru":"Резкий рост импорта; на основе сверхквотной ставки тарифной квоты","tr":"İthalat dalgalanmaları; tarife kotası kota üstü oranı esasına göre","hi":"आयात में उछाल; tariff-rate quota की over-quota दर के आधार पर","ar":"موجات الواردات المفاجئة؛ استناداً إلى معدل تجاوز الحصة في حصة معدل التعريفة"},{"en":"Sales at less than fair value (below normal value); based on the dumping margin","es":"Ventas por debajo del valor justo (por debajo del valor normal); con base en el margen de dumping","ru":"Продажи по цене ниже справедливой стоимости (ниже нормальной стоимости); на основе демпинговой маржи","tr":"Adil değerin altında satışlar (normal değerin altında); dumping marjı esasına göre","hi":"उचित मूल्य से कम पर बिक्री (सामान्य मूल्य से नीचे); dumping मार्जिन के आधार पर","ar":"البيع بأقل من القيمة العادلة (دون القيمة الطبيعية)؛ استناداً إلى هامش الإغراق"}],"e":{"en":"Antidumping duties offset sales of foreign merchandise in the U.S. at less than fair value (below normal value), and the duty is set by the dumping margin. Countervailing duties, by contrast, offset foreign subsidies. The cases are administered by Commerce (margins) and the ITC (injury), with CBP collecting deposits. See 19 U.S.C. 1673 and 19 CFR part 351.","es":"Los derechos antidumping compensan las ventas de mercancía extranjera en Estados Unidos por debajo del valor justo (por debajo del valor normal), y el derecho se establece según el margen de dumping. Los derechos compensatorios, en cambio, compensan los subsidios extranjeros. Los casos son administrados por el Department of Commerce (márgenes) y la ITC (daño), con CBP cobrando los depósitos. Véanse 19 U.S.C. 1673 y 19 CFR part 351.","ru":"Антидемпинговые пошлины компенсируют продажи иностранных товаров в США по цене ниже справедливой стоимости (ниже нормальной стоимости), и пошлина устанавливается по демпинговой марже. Компенсационные пошлины (CVD), напротив, компенсируют иностранные субсидии. Дела ведут Министерство торговли (маржа) и ITC (ущерб), а CBP взимает депозиты. См. 19 U.S.C. 1673 и 19 CFR part 351.","tr":"Antidumping vergileri, yabancı malların ABD'de adil değerin altında (normal değerin altında) satışını telafi eder ve vergi, dumping marjı tarafından belirlenir. Buna karşılık, countervailing (telafi edici) vergiler yabancı sübvansiyonları telafi eder. Davalar Commerce (marjlar) ve ITC (zarar) tarafından yürütülür; teminatları ise CBP tahsil eder. Bakınız 19 U.S.C. 1673 ve 19 CFR part 351.","hi":"Antidumping शुल्क U.S. में विदेशी माल की उचित मूल्य से कम (सामान्य मूल्य से नीचे) बिक्री की भरपाई करते हैं, और शुल्क dumping मार्जिन द्वारा निर्धारित होता है। इसके विपरीत, countervailing शुल्क विदेशी सब्सिडी की भरपाई करते हैं। इन मामलों का प्रशासन Commerce (मार्जिन) और ITC (क्षति) द्वारा किया जाता है, जबकि CBP जमा राशि एकत्र करता है। देखें 19 U.S.C. 1673 और 19 CFR part 351।","ar":"تعوّض رسوم مكافحة الإغراق بيع البضائع الأجنبية في الولايات المتحدة بأقل من القيمة العادلة (دون القيمة الطبيعية)، ويُحدَّد الرسم بهامش الإغراق. أما رسوم التعويض، فتعوّض الإعانات الأجنبية. وتدير القضايا وزارة التجارة (الهوامش) ولجنة التجارة الدولية ITC (الضرر)، مع قيام CBP بتحصيل الإيداعات. انظر 19 U.S.C. 1673 و19 CFR part 351."}},{"cat":"duties","a":1,"q":{"en":"Merchandise is subject to an antidumping duty order. At the time of entry, the broker must deposit estimated antidumping duties. Which statement about these duties is correct?","es":"La mercancía está sujeta a una orden de derechos antidumping. Al momento de la entrada, el agente debe depositar los derechos antidumping estimados. ¿Qué afirmación sobre estos derechos es correcta?","ru":"Товары подпадают под приказ об антидемпинговой пошлине. На момент оформления брокер должен внести депозит расчетных антидемпинговых пошлин. Какое утверждение об этих пошлинах верно?","tr":"Mallar bir antidumping vergi emrine tabidir. Beyan anında, gümrük müşaviri (broker) tahmini antidumping vergilerini teminat olarak yatırmalıdır. Bu vergilerle ilgili hangi ifade doğrudur?","hi":"माल एक antidumping शुल्क आदेश के अधीन है। एंट्री के समय, ब्रोकर को अनुमानित antidumping शुल्क जमा करना होता है। इन शुल्कों के बारे में कौन-सा कथन सही है?","ar":"تخضع بضاعة لأمر فرض رسوم مكافحة إغراق. عند الإدخال، يجب على الوسيط إيداع رسوم مكافحة الإغراق التقديرية. أي عبارة عن هذه الرسوم صحيحة؟"},"o":[{"en":"ADD cash deposits are credited against, and reduce, the regular Column 1 duty owed","es":"Los depósitos en efectivo de ADD se acreditan contra, y reducen, el derecho regular de la Columna 1 adeudado","ru":"Денежные депозиты ADD засчитываются в счет обычной пошлины Колонки 1 и уменьшают ее","tr":"ADD nakit teminatları, ödenmesi gereken normal Column 1 vergisinden mahsup edilir ve onu azaltır","hi":"ADD cash deposits को नियमित Column 1 देय शुल्क के बदले में क्रेडिट किया जाता है, और उसे कम करते हैं","ar":"تُقيَّد الإيداعات النقدية لـ ADD لصالح رسم Column 1 العادي المستحق وتخفّضه"},{"en":"ADD is collected in addition to any applicable regular customs duties, MPF, and HMF","es":"El ADD se cobra adicionalmente a cualquier derecho aduanero regular aplicable, el MPF y el HMF","ru":"ADD взимается в дополнение к любым применимым обычным таможенным пошлинам, MPF и HMF","tr":"ADD, uygulanabilir normal gümrük vergilerine, MPF ve HMF'ye ek olarak tahsil edilir","hi":"ADD किसी भी लागू नियमित कस्टम शुल्क, MPF, और HMF के अतिरिक्त एकत्र किया जाता है","ar":"تُحصَّل ADD إضافةً إلى أي رسوم جمركية عادية مطبّقة، و MPF، و HMF"},{"en":"ADD is exempt from collection until the entry is liquidated","es":"El ADD está exento de cobro hasta que se liquide la entrada","ru":"ADD освобождается от взимания до ликвидации оформления","tr":"ADD, beyan kesinleştirilene (likidasyon) kadar tahsilattan muaftır","hi":"एंट्री के परिसमापन तक ADD संग्रह से छूट प्राप्त है","ar":"تُعفى ADD من التحصيل إلى حين تصفية الإدخال"},{"en":"ADD replaces the MPF on entries subject to an order","es":"El ADD reemplaza el MPF en las entradas sujetas a una orden","ru":"ADD заменяет MPF при оформлениях, подпадающих под приказ","tr":"ADD, bir emre tabi beyanlarda MPF'nin yerini alır","hi":"आदेश के अधीन एंट्री पर ADD, MPF का स्थान ले लेता है","ar":"تحلّ ADD محل MPF في الإدخالات الخاضعة لأمر"}],"e":{"en":"Antidumping (and countervailing) duties are assessed in addition to normal customs duties and applicable fees such as the MPF and HMF; they do not offset or replace them. Estimated ADD/CVD is deposited at entry and finalized at liquidation after any administrative review. See 19 U.S.C. 1673 and 19 CFR part 351.","es":"Los derechos antidumping (y compensatorios) se calculan adicionalmente a los derechos aduaneros normales y a tarifas aplicables como el MPF y el HMF; no los compensan ni los reemplazan. El ADD/CVD estimado se deposita en la entrada y se finaliza en la liquidación tras cualquier revisión administrativa. Véanse 19 U.S.C. 1673 y 19 CFR part 351.","ru":"Антидемпинговые (и компенсационные) пошлины начисляются в дополнение к обычным таможенным пошлинам и применимым сборам, таким как MPF и HMF; они не компенсируют и не заменяют их. Расчетные ADD/CVD депонируются при оформлении и окончательно определяются при ликвидации после любой административной проверки. См. 19 U.S.C. 1673 и 19 CFR part 351.","tr":"Antidumping (ve countervailing) vergileri, normal gümrük vergilerine ve MPF ile HMF gibi geçerli ücretlere ek olarak tahakkuk ettirilir; bunları mahsup etmez veya yerlerini almaz. Tahmini ADD/CVD beyanda teminat olarak yatırılır ve herhangi bir idari incelemenin ardından kesinleştirme (likidasyon) sırasında nihai hale getirilir. Bakınız 19 U.S.C. 1673 ve 19 CFR part 351.","hi":"Antidumping (और countervailing) शुल्क सामान्य कस्टम शुल्क और MPF तथा HMF जैसे लागू शुल्कों के अतिरिक्त लगाए जाते हैं; वे उनकी भरपाई नहीं करते या उनका स्थान नहीं लेते। अनुमानित ADD/CVD एंट्री के समय जमा किया जाता है और किसी भी प्रशासनिक समीक्षा के बाद परिसमापन पर अंतिम रूप दिया जाता है। देखें 19 U.S.C. 1673 और 19 CFR part 351।","ar":"تُفرض رسوم مكافحة الإغراق (والتعويض) إضافةً إلى الرسوم الجمركية العادية والرسوم المطبّقة مثل MPF و HMF؛ ولا تعوّضها أو تحلّ محلها. وتُودَع ADD/CVD التقديرية عند الإدخال وتُحسم نهائياً عند التصفية بعد أي مراجعة إدارية. انظر 19 U.S.C. 1673 و19 CFR part 351."}},{"cat":"duties","a":2,"q":{"en":"An importer wishes to enter merchandise subject to a quota. Under an ABSOLUTE quota, what happens to merchandise presented for entry after the quota quantity for the period has been reached?","es":"Un importador desea declarar mercancía sujeta a un contingente. Bajo un contingente ABSOLUTO, ¿qué sucede con la mercancía presentada para entrada después de que se haya alcanzado la cantidad del contingente para el período?","ru":"Импортер желает оформить ввоз товаров, подпадающих под квоту. При АБСОЛЮТНОЙ квоте что происходит с товарами, представленными к оформлению после того, как количество квоты за период было достигнуто?","tr":"Bir ithalatçı, bir kotaya tabi malları beyan etmek istiyor. MUTLAK (absolute) bir kota kapsamında, dönem için belirlenen kota miktarına ulaşıldıktan sonra beyan için sunulan mallara ne olur?","hi":"एक आयातकर्ता quota के अधीन माल की एंट्री करना चाहता है। एक ABSOLUTE quota के तहत, अवधि के लिए quota मात्रा पूरी हो जाने के बाद एंट्री के लिए प्रस्तुत माल का क्या होता है?","ar":"يرغب مستورد في إدخال بضاعة خاضعة لحصة. في ظل حصة مطلقة (ABSOLUTE)، ماذا يحدث للبضاعة المقدَّمة للإدخال بعد بلوغ كمية الحصة المخصّصة للفترة؟"},"o":[{"en":"It may enter at a higher over-quota duty rate","es":"Puede entrar a una tasa de derechos más alta por encima del cupo","ru":"Они могут быть ввезены по более высокой сверхквотной ставке пошлины","tr":"Daha yüksek bir kota üstü vergi oranıyla girebilir","hi":"यह अधिक over-quota शुल्क दर पर एंटर हो सकता है","ar":"يجوز إدخالها بمعدل رسوم أعلى لتجاوز الحصة"},{"en":"It enters duty-free until the next period opens","es":"Entra libre de derechos hasta que se abra el siguiente período","ru":"Они ввозятся беспошлинно до открытия следующего периода","tr":"Bir sonraki dönem açılana kadar vergisiz olarak girebilir","hi":"अगली अवधि शुरू होने तक यह शुल्क-मुक्त एंटर होता है","ar":"تُدخَل معفاةً من الرسوم إلى أن تُفتح الفترة التالية"},{"en":"No further quantity may be entered for consumption during that period; it may be warehoused, exported, or destroyed","es":"No puede entrarse ninguna cantidad adicional para consumo durante ese período; puede almacenarse, exportarse o destruirse","ru":"В течение этого периода никакое дополнительное количество не может быть оформлено для потребления; товары могут быть помещены на склад, экспортированы или уничтожены","tr":"O dönem boyunca tüketim için başka miktar girilemez; mallar antrepoya konabilir, ihraç edilebilir veya imha edilebilir","hi":"उस अवधि के दौरान उपभोग के लिए कोई और मात्रा एंटर नहीं की जा सकती; इसे warehouse में रखा जा सकता है, निर्यात किया जा सकता है, या नष्ट किया जा सकता है","ar":"لا يجوز إدخال أي كمية إضافية للاستهلاك خلال تلك الفترة؛ ويجوز إيداعها في مستودع أو تصديرها أو إتلافها"},{"en":"It enters at the Column 2 rate","es":"Entra a la tasa de la Columna 2","ru":"Они ввозятся по ставке Колонки 2","tr":"Column 2 oranıyla girebilir","hi":"यह Column 2 दर पर एंटर होता है","ar":"تُدخَل بمعدل Column 2"}],"e":{"en":"An absolute (quantitative) quota permits no entries for consumption beyond the set quantity once it is filled; excess merchandise must be held in a bonded warehouse or foreign-trade zone, exported, or destroyed. A tariff-rate quota, by contrast, allows unlimited quantity but at a higher over-quota rate. See 19 CFR part 132.","es":"Un contingente absoluto (cuantitativo) no permite entradas para consumo más allá de la cantidad establecida una vez que se ha llenado; la mercancía excedente debe mantenerse en un almacén afianzado o zona de comercio exterior, exportarse o destruirse. Un contingente arancelario, en cambio, permite cantidad ilimitada pero a una tasa más alta por encima del cupo. Véase 19 CFR part 132.","ru":"Абсолютная (количественная) квота не допускает оформления для потребления сверх установленного количества, как только оно исчерпано; избыточные товары должны храниться на таможенном складе или в зоне внешней торговли (FTZ), экспортироваться или уничтожаться. Тарифная квота, напротив, допускает неограниченное количество, но по более высокой сверхквотной ставке. См. 19 CFR part 132.","tr":"Mutlak (miktarsal) kota, dolduktan sonra belirlenen miktarın ötesinde tüketim için hiçbir beyana izin vermez; fazla mallar bir gümrük antreposunda veya foreign-trade zone'da tutulmalı, ihraç edilmeli veya imha edilmelidir. Buna karşılık tarife kotası, sınırsız miktara izin verir ancak daha yüksek bir kota üstü oranla. Bakınız 19 CFR part 132.","hi":"एक absolute (मात्रात्मक) quota, एक बार भर जाने पर, निर्धारित मात्रा से अधिक उपभोग के लिए कोई एंट्री की अनुमति नहीं देता; अतिरिक्त माल को bonded warehouse या foreign-trade zone में रखा जाना चाहिए, निर्यात किया जाना चाहिए, या नष्ट किया जाना चाहिए। इसके विपरीत, एक tariff-rate quota असीमित मात्रा की अनुमति देता है लेकिन अधिक over-quota दर पर। देखें 19 CFR part 132।","ar":"لا تسمح الحصة المطلقة (الكمّية) بأي إدخالات للاستهلاك تتجاوز الكمية المحددة بمجرد استيفائها؛ ويجب الاحتفاظ بالبضاعة الزائدة في مستودع جمركي مضمون أو منطقة تجارة خارجية FTZ، أو تصديرها، أو إتلافها. أما حصة معدل التعريفة فتسمح بكمية غير محدودة لكن بمعدل أعلى لتجاوز الحصة. انظر 19 CFR part 132."}},{"cat":"duties","a":3,"q":{"en":"Imported components are used to manufacture an article in the United States, and the finished article is then exported. What type of drawback is available, and what is the general time limit?","es":"Se usan componentes importados para fabricar un artículo en Estados Unidos, y el artículo terminado se exporta después. ¿Qué tipo de drawback está disponible y cuál es el límite de tiempo general?","ru":"Импортированные компоненты используются для изготовления изделия в Соединенных Штатах, после чего готовое изделие экспортируется. Какой тип возврата пошлин (drawback) доступен, и каков общий срок?","tr":"İthal edilen bileşenler, Amerika Birleşik Devletleri'nde bir ürün imal etmek için kullanılıyor ve bitmiş ürün daha sonra ihraç ediliyor. Ne tür bir gümrük vergisi iadesi (drawback) mevcuttur ve genel süre sınırı nedir?","hi":"आयातित घटकों का उपयोग संयुक्त राज्य अमेरिका में एक वस्तु के निर्माण के लिए किया जाता है, और फिर तैयार वस्तु को निर्यात किया जाता है। किस प्रकार का drawback (शुल्क वापसी) उपलब्ध है, और सामान्य समय-सीमा क्या है?","ar":"تُستخدَم مكوّنات مستورَدة لتصنيع مادة في الولايات المتحدة، ثم تُصدَّر المادة المصنوعة. ما نوع استرداد الرسوم (drawback) المتاح، وما الحد الزمني العام؟"},"o":[{"en":"Unused merchandise drawback; the goods must be exported within three years of importation","es":"Drawback de mercancía no usada; las mercancías deben exportarse dentro de los tres años posteriores a la importación","ru":"Возврат за неиспользованные товары (unused merchandise drawback); товары должны быть экспортированы в течение трех лет с момента импорта","tr":"Kullanılmamış mal iadesi (unused merchandise drawback); malların ithalattan itibaren üç yıl içinde ihraç edilmesi gerekir","hi":"unused merchandise drawback; माल को आयात के तीन वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة غير المستخدمة؛ يجب تصدير البضائع خلال ثلاث سنوات من الاستيراد"},{"en":"Rejected merchandise drawback; the article must be exported within three years of importation","es":"Drawback de mercancía rechazada; el artículo debe exportarse dentro de los tres años posteriores a la importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); изделие должно быть экспортировано в течение трех лет с момента импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); ürünün ithalattan itibaren üç yıl içinde ihraç edilmesi gerekir","hi":"rejected merchandise drawback; वस्तु को आयात के तीन वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير المادة خلال ثلاث سنوات من الاستيراد"},{"en":"Manufacturing drawback; the article must be exported within two years and the claim filed within three years of exportation","es":"Drawback de manufactura; el artículo debe exportarse dentro de dos años y la reclamación presentarse dentro de tres años de la exportación","ru":"Производственный возврат (manufacturing drawback); изделие должно быть экспортировано в течение двух лет, а требование подано в течение трех лет с момента экспорта","tr":"İmalat iadesi (manufacturing drawback); ürünün iki yıl içinde ihraç edilmesi ve talebin ihracattan itibaren üç yıl içinde sunulması gerekir","hi":"manufacturing drawback; वस्तु को दो वर्ष के भीतर निर्यात किया जाना चाहिए और दावा निर्यात के तीन वर्ष के भीतर दाखिल किया जाना चाहिए","ar":"استرداد رسوم التصنيع؛ يجب تصدير المادة خلال سنتين وتقديم المطالبة خلال ثلاث سنوات من التصدير"},{"en":"Manufacturing drawback; the article must be exported or destroyed within five years of importation, and the claim filed within five years of importation","es":"Drawback de manufactura; el artículo debe exportarse o destruirse dentro de los cinco años posteriores a la importación, y la reclamación presentarse dentro de los cinco años posteriores a la importación","ru":"Производственный возврат (manufacturing drawback); изделие должно быть экспортировано или уничтожено в течение пяти лет с момента импорта, а требование подано в течение пяти лет с момента импорта","tr":"İmalat iadesi (manufacturing drawback); ürünün ithalattan itibaren beş yıl içinde ihraç edilmesi veya imha edilmesi ve talebin ithalattan itibaren beş yıl içinde sunulması gerekir","hi":"manufacturing drawback; वस्तु को आयात के पाँच वर्ष के भीतर निर्यात या नष्ट किया जाना चाहिए, और दावा आयात के पाँच वर्ष के भीतर दाखिल किया जाना चाहिए","ar":"استرداد رسوم التصنيع؛ يجب تصدير المادة أو إتلافها خلال خمس سنوات من الاستيراد، وتقديم المطالبة خلال خمس سنوات من الاستيراد"}],"e":{"en":"Manufacturing drawback (19 U.S.C. 1313(a)/(b)) applies when imported merchandise is used to make an exported or destroyed article. Under the modernized rules, the exportation/destruction and the filing of the claim must occur within five years of the date of importation of the designated merchandise. See 19 U.S.C. 1313(r) and 19 CFR part 190 (subpart B).","es":"El drawback de manufactura (reintegro de derechos) (19 U.S.C. 1313(a)/(b)) se aplica cuando se usa mercancía importada para fabricar un artículo exportado o destruido. Conforme a las reglas modernizadas, la exportación/destrucción y la presentación de la reclamación deben ocurrir dentro de los cinco años posteriores a la fecha de importación de la mercancía designada. Véanse 19 U.S.C. 1313(r) y 19 CFR part 190 (subpart B).","ru":"Производственный возврат (manufacturing drawback) (19 U.S.C. 1313(a)/(b)) применяется, когда импортированные товары используются для изготовления экспортируемого или уничтожаемого изделия. Согласно модернизированным правилам, экспорт/уничтожение и подача требования должны произойти в течение пяти лет с даты импорта обозначенных товаров. См. 19 U.S.C. 1313(r) и 19 CFR part 190 (subpart B).","tr":"İmalat iadesi (manufacturing drawback) (19 U.S.C. 1313(a)/(b)), ithal edilen malların ihraç edilen veya imha edilen bir ürün yapmak için kullanıldığı durumlarda geçerlidir. Modernize edilmiş kurallar uyarınca, ihracat/imha ile talebin sunulması, belirlenen malın ithalat tarihinden itibaren beş yıl içinde gerçekleşmelidir. Bakınız 19 U.S.C. 1313(r) ve 19 CFR part 190 (subpart B).","hi":"manufacturing drawback (19 U.S.C. 1313(a)/(b)) तब लागू होता है जब आयातित माल का उपयोग एक निर्यातित या नष्ट की गई वस्तु बनाने के लिए किया जाता है। आधुनिकीकृत नियमों के तहत, निर्यात/विनाश और दावे की दाखिल करना निर्दिष्ट माल के आयात की तारीख के पाँच वर्ष के भीतर होना चाहिए। देखें 19 U.S.C. 1313(r) और 19 CFR part 190 (subpart B)।","ar":"ينطبق استرداد رسوم التصنيع (manufacturing drawback) بموجب 19 U.S.C. 1313(a)/(b) عند استخدام بضاعة مستورَدة لصنع مادة مصدَّرة أو مُتلَفة. وبموجب القواعد المحدَّثة، يجب أن يقع التصدير/الإتلاف وتقديم المطالبة خلال خمس سنوات من تاريخ استيراد البضاعة المعيّنة. انظر 19 U.S.C. 1313(r) و19 CFR part 190 (subpart B)."}},{"cat":"duties","a":0,"q":{"en":"An importer pays duties, taxes, and fees on goods, then exports the identical goods without using them in the United States. The importer files an unused merchandise drawback claim. What portion of the eligible duties, taxes, and fees may be refunded?","es":"Un importador paga derechos, impuestos y tarifas sobre mercancías, y luego exporta las mercancías idénticas sin haberlas usado en Estados Unidos. El importador presenta una reclamación de drawback por mercancía no usada. ¿Qué porción de los derechos, impuestos y tarifas elegibles puede reembolsarse?","ru":"Импортер уплачивает пошлины, налоги и сборы за товары, затем экспортирует те же самые товары, не использовав их в Соединенных Штатах. Импортер подает требование о возврате за неиспользованные товары (unused merchandise drawback). Какая часть подлежащих возврату пошлин, налогов и сборов может быть возвращена?","tr":"Bir ithalatçı, mallar üzerinden vergileri, vergileri (taxes) ve ücretleri öder, ardından aynı malları Amerika Birleşik Devletleri'nde kullanmadan ihraç eder. İthalatçı, kullanılmamış mal iadesi (unused merchandise drawback) talebinde bulunur. Uygun vergilerin, vergilerin (taxes) ve ücretlerin ne kadarlık kısmı iade edilebilir?","hi":"एक आयातकर्ता माल पर शुल्क, कर और फीस का भुगतान करता है, फिर संयुक्त राज्य अमेरिका में उनका उपयोग किए बिना समान माल को निर्यात करता है। आयातकर्ता एक unused merchandise drawback दावा दाखिल करता है। पात्र शुल्क, कर और फीस का कितना हिस्सा वापस किया जा सकता है?","ar":"يدفع مستورد الرسوم والضرائب والأتعاب على بضائع، ثم يصدّر البضائع نفسها دون استخدامها في الولايات المتحدة. ويقدّم المستورد مطالبة باسترداد رسوم البضاعة غير المستخدمة. ما الجزء الذي يجوز ردّه من الرسوم والضرائب والأتعاب المؤهلة؟"},"o":[{"en":"Ninety-nine percent","es":"Noventa y nueve por ciento","ru":"Девяносто девять процентов","tr":"Yüzde doksan dokuz","hi":"निन्यानवे प्रतिशत","ar":"تسعة وتسعون بالمئة"},{"en":"One hundred percent","es":"Cien por ciento","ru":"Сто процентов","tr":"Yüzde yüz","hi":"एक सौ प्रतिशत","ar":"مئة بالمئة"},{"en":"Ninety percent","es":"Noventa por ciento","ru":"Девяносто процентов","tr":"Yüzde doksan","hi":"नब्बे प्रतिशत","ar":"تسعون بالمئة"},{"en":"Ninety-five percent","es":"Noventa y cinco por ciento","ru":"Девяносто пять процентов","tr":"Yüzde doksan beş","hi":"पंचानवे प्रतिशत","ar":"خمسة وتسعون بالمئة"}],"e":{"en":"Drawback, including unused merchandise drawback under 19 U.S.C. 1313(j), refunds 99 percent of the duties, taxes, and fees paid on the imported merchandise (CBP retains 1 percent). Eligible amounts can include ordinary duties, certain Section 301 duties, MPF, and HMF. See 19 U.S.C. 1313(l) and 19 CFR part 190.","es":"El drawback (reintegro de derechos), incluido el drawback de mercancía no usada conforme a 19 U.S.C. 1313(j), reembolsa el 99 por ciento de los derechos, impuestos y tarifas pagados sobre la mercancía importada (CBP retiene el 1 por ciento). Los montos elegibles pueden incluir derechos ordinarios, ciertos derechos de la Section 301, el MPF y el HMF. Véanse 19 U.S.C. 1313(l) y 19 CFR part 190.","ru":"Возврат пошлин (drawback), включая возврат за неиспользованные товары согласно 19 U.S.C. 1313(j), возвращает 99 процентов пошлин, налогов и сборов, уплаченных за импортированные товары (CBP удерживает 1 процент). Подлежащие возврату суммы могут включать обычные пошлины, некоторые пошлины Section 301, MPF и HMF. См. 19 U.S.C. 1313(l) и 19 CFR part 190.","tr":"19 U.S.C. 1313(j) kapsamındaki kullanılmamış mal iadesi (unused merchandise drawback) dahil olmak üzere drawback, ithal edilen mallar üzerinden ödenen vergilerin, vergilerin (taxes) ve ücretlerin yüzde 99'unu iade eder (CBP yüzde 1'ini alıkoyar). Uygun tutarlar; olağan vergileri, belirli Section 301 vergilerini, MPF ve HMF'yi içerebilir. Bakınız 19 U.S.C. 1313(l) ve 19 CFR part 190.","hi":"drawback (शुल्क वापसी), जिसमें 19 U.S.C. 1313(j) के तहत unused merchandise drawback शामिल है, आयातित माल पर भुगतान किए गए शुल्क, कर और फीस का 99 प्रतिशत वापस करता है (CBP 1 प्रतिशत रखता है)। पात्र राशियों में सामान्य शुल्क, कुछ Section 301 शुल्क, MPF, और HMF शामिल हो सकते हैं। देखें 19 U.S.C. 1313(l) और 19 CFR part 190।","ar":"يردّ استرداد الرسوم، بما فيه استرداد رسوم البضاعة غير المستخدمة بموجب 19 U.S.C. 1313(j)، نسبة 99 بالمئة من الرسوم والضرائب والأتعاب المدفوعة على البضاعة المستورَدة (تحتفظ CBP بنسبة 1 بالمئة). ويمكن أن تشمل المبالغ المؤهلة الرسوم العادية، وبعض رسوم Section 301، و MPF، و HMF. انظر 19 U.S.C. 1313(l) و19 CFR part 190."}},{"cat":"duties","a":3,"q":{"en":"Merchandise was entered and duty-paid, but it does not conform to the buyer's specifications and is exported without having been used. Which drawback type applies, and what is the controlling time limit for exportation or destruction?","es":"La mercancía fue declarada y se pagaron sus derechos, pero no se ajusta a las especificaciones del comprador y se exporta sin haber sido usada. ¿Qué tipo de drawback aplica y cuál es el límite de tiempo determinante para la exportación o destrucción?","ru":"Товары были оформлены с уплатой пошлины, но они не соответствуют спецификациям покупателя и экспортируются, не будучи использованными. Какой тип возврата пошлин (drawback) применяется, и каков определяющий срок для экспорта или уничтожения?","tr":"Mallar beyan edilip vergileri ödenmiş, ancak alıcının spesifikasyonlarına uymadığı ve kullanılmadan ihraç edildiği ortaya çıkıyor. Hangi drawback türü geçerlidir ve ihracat veya imha için belirleyici süre sınırı nedir?","hi":"माल एंटर किया गया और शुल्क-चुकता था, लेकिन यह खरीदार के विनिर्देशों के अनुरूप नहीं है और उपयोग किए बिना निर्यात किया जाता है। कौन-सा drawback प्रकार लागू होता है, और निर्यात या विनाश के लिए नियंत्रक समय-सीमा क्या है?","ar":"أُدخلت بضاعة ودُفعت رسومها، لكنها لا تطابق مواصفات المشتري وتُصدَّر دون استخدامها. أي نوع من استرداد الرسوم ينطبق، وما الحد الزمني الحاكم للتصدير أو الإتلاف؟"},"o":[{"en":"Substitution manufacturing drawback; within five years of importation","es":"Drawback de manufactura por sustitución; dentro de los cinco años posteriores a la importación","ru":"Замещающий производственный возврат (substitution manufacturing drawback); в течение пяти лет с момента импорта","tr":"İkame imalat iadesi (substitution manufacturing drawback); ithalattan itibaren beş yıl içinde","hi":"substitution manufacturing drawback; आयात के पाँच वर्ष के भीतर","ar":"استرداد رسوم التصنيع بالاستبدال؛ خلال خمس سنوات من الاستيراد"},{"en":"Rejected merchandise drawback; the goods must be exported or destroyed within three years after the date of importation","es":"Drawback de mercancía rechazada; las mercancías deben exportarse o destruirse dentro de los tres años posteriores a la fecha de importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); товары должны быть экспортированы или уничтожены в течение трех лет после даты импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); malların ithalat tarihinden itibaren üç yıl içinde ihraç edilmesi veya imha edilmesi gerekir","hi":"rejected merchandise drawback; माल को आयात की तारीख के बाद तीन वर्ष के भीतर निर्यात या नष्ट किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير البضائع أو إتلافها خلال ثلاث سنوات بعد تاريخ الاستيراد"},{"en":"Direct identification unused merchandise drawback; within two years of importation","es":"Drawback de mercancía no usada por identificación directa; dentro de los dos años posteriores a la importación","ru":"Возврат за неиспользованные товары с прямой идентификацией (direct identification unused merchandise drawback); в течение двух лет с момента импорта","tr":"Doğrudan tanımlama kullanılmamış mal iadesi (direct identification unused merchandise drawback); ithalattan itibaren iki yıl içinde","hi":"direct identification unused merchandise drawback; आयात के दो वर्ष के भीतर","ar":"استرداد رسوم البضاعة غير المستخدمة بالتحديد المباشر؛ خلال سنتين من الاستيراد"},{"en":"Rejected merchandise drawback; the goods must be exported within five years after the date of importation","es":"Drawback de mercancía rechazada; las mercancías deben exportarse dentro de los cinco años posteriores a la fecha de importación","ru":"Возврат за отбракованные товары (rejected merchandise drawback); товары должны быть экспортированы в течение пяти лет после даты импорта","tr":"Reddedilmiş mal iadesi (rejected merchandise drawback); malların ithalat tarihinden itibaren beş yıl içinde ihraç edilmesi gerekir","hi":"rejected merchandise drawback; माल को आयात की तारीख के बाद पाँच वर्ष के भीतर निर्यात किया जाना चाहिए","ar":"استرداد رسوم البضاعة المرفوضة؛ يجب تصدير البضائع خلال خمس سنوات بعد تاريخ الاستيراد"}],"e":{"en":"Rejected merchandise drawback under 19 U.S.C. 1313(c) covers duty-paid goods that do not conform to sample or specifications, were shipped without consent, or were defective at importation. The merchandise must be exported or destroyed under CBP supervision within five years (modernized law, 19 CFR 190.42 / 19 USC 1313(c)) after the date of importation. See 19 U.S.C. 1313(c) and 19 CFR part 190 (subpart D).","es":"El drawback de mercancía rechazada conforme a 19 U.S.C. 1313(c) cubre las mercancías con derechos pagados que no se ajustan a la muestra o las especificaciones, fueron enviadas sin consentimiento o estaban defectuosas al momento de la importación. La mercancía debe exportarse o destruirse bajo supervisión de CBP dentro de los cinco años (ley modernizada, 19 CFR 190.42 / 19 USC 1313(c)) posteriores a la fecha de importación. Véanse 19 U.S.C. 1313(c) y 19 CFR part 190 (subpart D).","ru":"Возврат за отбракованные товары (rejected merchandise drawback) согласно 19 U.S.C. 1313(c) охватывает товары с уплаченной пошлиной, которые не соответствуют образцу или спецификациям, были отгружены без согласия или были дефектными при импорте. Товары должны быть экспортированы или уничтожены под надзором CBP в течение пяти лет (модернизированное законодательство, 19 CFR 190.42 / 19 USC 1313(c)) после даты импорта. См. 19 U.S.C. 1313(c) и 19 CFR part 190 (subpart D).","tr":"19 U.S.C. 1313(c) kapsamındaki reddedilmiş mal iadesi (rejected merchandise drawback); numuneye veya spesifikasyonlara uymayan, rıza olmadan sevk edilen veya ithalat anında kusurlu olan, vergisi ödenmiş malları kapsar. Mallar, CBP gözetimi altında ithalat tarihinden itibaren beş yıl içinde (modernize edilmiş yasa, 19 CFR 190.42 / 19 USC 1313(c)) ihraç edilmeli veya imha edilmelidir. Bakınız 19 U.S.C. 1313(c) ve 19 CFR part 190 (subpart D).","hi":"19 U.S.C. 1313(c) के तहत rejected merchandise drawback उन शुल्क-चुकता माल को कवर करता है जो नमूने या विनिर्देशों के अनुरूप नहीं हैं, सहमति के बिना भेजे गए थे, या आयात के समय दोषपूर्ण थे। माल को CBP की देखरेख में आयात की तारीख के बाद पाँच वर्ष के भीतर (आधुनिकीकृत कानून, 19 CFR 190.42 / 19 USC 1313(c)) निर्यात या नष्ट किया जाना चाहिए। देखें 19 U.S.C. 1313(c) और 19 CFR part 190 (subpart D)।","ar":"يشمل استرداد رسوم البضاعة المرفوضة (rejected merchandise drawback) بموجب 19 U.S.C. 1313(c) البضائع المدفوعة رسومها التي لا تطابق العينة أو المواصفات، أو شُحنت دون موافقة، أو كانت معيبة عند الاستيراد. ويجب تصدير البضاعة أو إتلافها تحت إشراف CBP خلال خمس سنوات (القانون المحدَّث، 19 CFR 190.42 / 19 USC 1313(c)) بعد تاريخ الاستيراد. انظر 19 U.S.C. 1313(c) و19 CFR part 190 (subpart D)."}},{"cat":"compliance","a":1,"q":{"en":"A licensed individual broker who is an employee of a corporate broker wants to file entries on the corporation's behalf at a port located outside the corporation's home district. Under the current regulations, what authorization permits the corporate broker to transact customs business throughout the customs territory of the United States?","es":"Un agente de aduanas individual con licencia que es empleado de un agente corporativo desea presentar entradas en nombre de la corporación en un puerto ubicado fuera del distrito de origen de la corporación. Conforme a la normativa actual, ¿qué autorización permite al agente corporativo realizar negocios aduaneros en todo el territorio aduanero de Estados Unidos?","ru":"Лицензированный индивидуальный брокер, являющийся работником корпоративного брокера, хочет подавать оформления от имени корпорации в порту, расположенном за пределами родного округа корпорации. Согласно действующим нормам, какое разрешение позволяет корпоративному брокеру вести таможенную деятельность на всей таможенной территории Соединенных Штатов?","tr":"Bir kurumsal gümrük müşaviri (corporate broker) bünyesinde çalışan, lisanslı bir bireysel gümrük müşaviri, şirketin ana bölgesi (district) dışında bulunan bir limanda şirket adına beyanlar sunmak istiyor. Mevcut düzenlemeler kapsamında, kurumsal gümrük müşavirinin Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işlemleri yürütmesine hangi yetki izin verir?","hi":"एक लाइसेंस-प्राप्त व्यक्तिगत ब्रोकर जो एक कॉर्पोरेट ब्रोकर का कर्मचारी है, कॉर्पोरेशन की ओर से कॉर्पोरेशन के home district के बाहर स्थित एक बंदरगाह पर एंट्री दाखिल करना चाहता है। वर्तमान नियमों के तहत, कौन-सा प्राधिकरण कॉर्पोरेट ब्रोकर को संयुक्त राज्य अमेरिका के पूरे कस्टम क्षेत्र में customs business करने की अनुमति देता है?","ar":"يرغب وسيط فرد مرخَّص يعمل لدى وسيط مؤسسي في تقديم إدخالات نيابةً عن المؤسسة في ميناء يقع خارج المنطقة الإدارية الأم للمؤسسة. بموجب اللوائح الحالية، ما التفويض الذي يتيح للوسيط المؤسسي مزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة؟"},"o":[{"en":"A separate district permit must be obtained for each port of entry where the broker files","es":"Debe obtenerse un permiso de distrito separado para cada puerto de entrada donde el agente presente declaraciones","ru":"Для каждого порта ввоза, где брокер подает оформления, необходимо получить отдельное окружное разрешение","tr":"Gümrük müşavirinin beyan sunduğu her giriş limanı için ayrı bir bölge (district) izni alınmalıdır","hi":"जहाँ ब्रोकर दाखिल करता है, उस प्रत्येक port of entry के लिए एक अलग district permit प्राप्त करना होगा","ar":"يجب الحصول على تصريح منطقة منفصل لكل ميناء دخول يقدّم فيه الوسيط"},{"en":"A single national permit issued under 19 CFR 111.19","es":"Un único permiso nacional emitido conforme a 19 CFR 111.19","ru":"Единое национальное разрешение, выдаваемое согласно 19 CFR 111.19","tr":"19 CFR 111.19 kapsamında verilen tek bir ulusal izin (national permit)","hi":"19 CFR 111.19 के तहत जारी एक एकल national permit","ar":"تصريح وطني واحد يصدر بموجب 19 CFR 111.19"},{"en":"The individual employee's broker license alone, with no permit needed","es":"La licencia de agente del empleado individual por sí sola, sin necesidad de permiso","ru":"Только брокерская лицензия самого индивидуального работника, без необходимости разрешения","tr":"Tek başına bireysel çalışanın gümrük müşaviri lisansı, herhangi bir izne gerek yoktur","hi":"अकेले व्यक्तिगत कर्मचारी का ब्रोकर लाइसेंस, बिना किसी permit की आवश्यकता के","ar":"رخصة الموظف الفرد للوساطة وحدها، دون حاجة إلى تصريح"},{"en":"A waiver of permit requirements granted by the port director at each location","es":"Una exención de los requisitos de permiso otorgada por el director del puerto en cada ubicación","ru":"Освобождение от требований к разрешению, предоставляемое директором порта в каждом месте","tr":"Her bir konumda liman müdürü tarafından verilen izin gerekliliklerinden feragat","hi":"प्रत्येक स्थान पर port director द्वारा प्रदान की गई permit आवश्यकताओं की छूट","ar":"تنازل عن متطلبات التصريح يمنحه مدير الميناء في كل موقع"}],"e":{"en":"Under 19 CFR 111.19, a national permit authorizes a broker to conduct customs business throughout the customs territory of the United States. The 2022 modernization rule eliminated district permits, so a single national permit now covers all ports. A license alone does not authorize transacting customs business; a permit is also required.","es":"Conforme a 19 CFR 111.19, un permiso nacional autoriza a un agente a realizar negocios aduaneros en todo el territorio aduanero de Estados Unidos. La regla de modernización de 2022 eliminó los permisos de distrito, por lo que un único permiso nacional ahora cubre todos los puertos. Una licencia por sí sola no autoriza a realizar negocios aduaneros; también se requiere un permiso.","ru":"Согласно 19 CFR 111.19, национальное разрешение уполномочивает брокера вести таможенную деятельность на всей таможенной территории Соединенных Штатов. Правило модернизации 2022 года упразднило окружные разрешения, поэтому единое национальное разрешение теперь охватывает все порты. Одна лицензия не уполномочивает вести таможенную деятельность; также требуется разрешение.","tr":"19 CFR 111.19 kapsamında, bir ulusal izin (national permit), bir gümrük müşavirinin Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işlemleri yürütmesine yetki verir. 2022 modernizasyon kuralı bölge (district) izinlerini kaldırdığından, artık tek bir ulusal izin tüm limanları kapsar. Tek başına bir lisans, gümrük işlemleri yürütmeye yetki vermez; ayrıca bir izin de gereklidir.","hi":"19 CFR 111.19 के तहत, एक national permit ब्रोकर को संयुक्त राज्य अमेरिका के पूरे कस्टम क्षेत्र में customs business करने के लिए अधिकृत करता है। 2022 के आधुनिकीकरण नियम ने district permits को समाप्त कर दिया, इसलिए अब एक एकल national permit सभी बंदरगाहों को कवर करता है। अकेला लाइसेंस customs business करने के लिए अधिकृत नहीं करता; एक permit की भी आवश्यकता होती है।","ar":"بموجب 19 CFR 111.19، يُفوّض التصريح الوطني الوسيط بمزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة. وقد ألغت قاعدة التحديث لعام 2022 تصاريح المناطق، فأصبح التصريح الوطني الواحد يغطي جميع الموانئ. ولا تخوّل الرخصة وحدها مزاولة الأعمال الجمركية؛ بل يلزم تصريح أيضاً."}},{"cat":"compliance","a":1,"q":{"en":"Which statement most accurately distinguishes a customs broker's license from a permit?","es":"¿Qué afirmación distingue con mayor precisión la licencia de un agente de aduanas de su permiso?","ru":"Какое утверждение наиболее точно отличает лицензию таможенного брокера от разрешения?","tr":"Aşağıdaki ifadelerden hangisi, bir gümrük müşavirinin lisansını izninden en doğru şekilde ayırt eder?","hi":"कौन-सा कथन एक customs broker के लाइसेंस को permit से सबसे सटीक रूप से अलग करता है?","ar":"أي عبارة تميّز بدقة أكبر رخصة الوسيط الجمركي عن تصريحه؟"},"o":[{"en":"A license authorizes a person to transact customs business at a specific port, while a permit authorizes nationwide activity","es":"Una licencia autoriza a una persona a realizar negocios aduaneros en un puerto específico, mientras que un permiso autoriza la actividad a nivel nacional","ru":"Лицензия уполномочивает лицо вести таможенную деятельность в конкретном порту, тогда как разрешение уполномочивает на деятельность по всей стране","tr":"Lisans, bir kişiye belirli bir limanda gümrük işlemleri yürütme yetkisi verirken, izin ülke çapında faaliyete yetki verir","hi":"एक लाइसेंस किसी व्यक्ति को एक विशिष्ट बंदरगाह पर customs business करने के लिए अधिकृत करता है, जबकि एक permit देशव्यापी गतिविधि के लिए अधिकृत करता है","ar":"تخوّل الرخصة الشخص مزاولة الأعمال الجمركية في ميناء محدد، بينما يخوّل التصريح النشاط على المستوى الوطني"},{"en":"A license confers the personal authority to engage in customs business, while a permit authorizes the licensee or organization to actually conduct that business","es":"Una licencia confiere la autoridad personal para dedicarse a negocios aduaneros, mientras que un permiso autoriza al titular de la licencia o a la organización a realizar efectivamente ese negocio","ru":"Лицензия предоставляет личное право заниматься таможенной деятельностью, тогда как разрешение уполномочивает лицензиата или организацию фактически вести эту деятельность","tr":"Lisans, kişiye gümrük işlemlerine girişme şeklindeki kişisel yetkiyi verirken, izin lisans sahibine veya kuruluşa bu işi fiilen yürütme yetkisi verir","hi":"एक लाइसेंस customs business में संलग्न होने का व्यक्तिगत अधिकार प्रदान करता है, जबकि एक permit लाइसेंसधारी या संगठन को वास्तव में वह व्यवसाय करने के लिए अधिकृत करता है","ar":"تمنح الرخصة الصلاحية الشخصية لممارسة الأعمال الجمركية، بينما يخوّل التصريح المرخَّص له أو المنظمة المزاولة الفعلية لتلك الأعمال"},{"en":"A permit is issued only to individuals, while a license is issued only to organizations","es":"Un permiso se emite solo a individuos, mientras que una licencia se emite solo a organizaciones","ru":"Разрешение выдается только физическим лицам, тогда как лицензия выдается только организациям","tr":"İzin yalnızca bireylere verilirken, lisans yalnızca kuruluşlara verilir","hi":"एक permit केवल व्यक्तियों को जारी किया जाता है, जबकि एक लाइसेंस केवल संगठनों को जारी किया जाता है","ar":"يُصدَر التصريح للأفراد فقط، بينما تُصدَر الرخصة للمنظمات فقط"},{"en":"A license must be renewed annually, while a permit is valid for the life of the holder","es":"Una licencia debe renovarse anualmente, mientras que un permiso es válido por toda la vida del titular","ru":"Лицензия должна продлеваться ежегодно, тогда как разрешение действительно в течение всей жизни держателя","tr":"Lisans yıllık olarak yenilenmelidir, izin ise sahibinin ömrü boyunca geçerlidir","hi":"एक लाइसेंस को सालाना नवीनीकृत किया जाना चाहिए, जबकि एक permit धारक के जीवनकाल के लिए वैध होता है","ar":"يجب تجديد الرخصة سنوياً، بينما يكون التصريح صالحاً مدى حياة حامله"}],"e":{"en":"Under 19 CFR Part 111, the license (111.11 et seq.) grants a person or organization the authority to engage in customs business, while the permit (111.19) is the separate authorization required to actually conduct that business. Both individuals and organizations can hold licenses and permits; neither is renewed annually (status reports are triennial under 111.30).","es":"Conforme a 19 CFR Part 111, la licencia (111.11 y siguientes) otorga a una persona u organización la autoridad para dedicarse a negocios aduaneros, mientras que el permiso (111.19) es la autorización separada requerida para realizar efectivamente ese negocio. Tanto los individuos como las organizaciones pueden tener licencias y permisos; ninguno se renueva anualmente (los informes de estatus son trienales conforme a 111.30).","ru":"Согласно 19 CFR Part 111, лицензия (111.11 и далее) предоставляет лицу или организации право заниматься таможенной деятельностью, тогда как разрешение (111.19) является отдельным полномочием, необходимым для фактического ведения этой деятельности. И физические лица, и организации могут иметь лицензии и разрешения; ни одно из них не продлевается ежегодно (отчеты о статусе подаются раз в три года согласно 111.30).","tr":"19 CFR Part 111 kapsamında, lisans (111.11 ve devamı) bir kişiye veya kuruluşa gümrük işlemlerine girişme yetkisi verirken, izin (111.19) bu işi fiilen yürütmek için gerekli olan ayrı bir yetkidir. Hem bireyler hem de kuruluşlar lisans ve izin sahibi olabilir; hiçbiri yıllık olarak yenilenmez (durum raporları 111.30 uyarınca üç yılda birdir).","hi":"19 CFR Part 111 के तहत, लाइसेंस (111.11 et seq.) किसी व्यक्ति या संगठन को customs business में संलग्न होने का अधिकार देता है, जबकि permit (111.19) वास्तव में वह व्यवसाय करने के लिए आवश्यक अलग प्राधिकरण है। व्यक्ति और संगठन दोनों लाइसेंस और permits धारण कर सकते हैं; इनमें से कोई भी सालाना नवीनीकृत नहीं होता (status reports 111.30 के तहत त्रैवार्षिक हैं)।","ar":"بموجب 19 CFR Part 111، تمنح الرخصة (111.11 وما يليها) الشخص أو المنظمة صلاحية ممارسة الأعمال الجمركية، بينما التصريح (111.19) هو التفويض المنفصل اللازم للمزاولة الفعلية لتلك الأعمال. ويمكن للأفراد والمنظمات حيازة الرخص والتصاريح؛ ولا يُجدَّد أيٌّ منهما سنوياً (تقارير الحالة تُقدَّم كل ثلاث سنوات بموجب 111.30)."}},{"cat":"compliance","a":2,"q":{"en":"An applicant for an individual customs broker license must satisfy several statutory requirements. Which of the following is NOT a requirement to obtain an individual license under 19 CFR 111.11?","es":"Un solicitante de una licencia individual de agente de aduanas debe cumplir varios requisitos legales. ¿Cuál de los siguientes NO es un requisito para obtener una licencia individual conforme a 19 CFR 111.11?","ru":"Заявитель на получение индивидуальной лицензии таможенного брокера должен удовлетворять нескольким установленным законом требованиям. Что из перечисленного НЕ является требованием для получения индивидуальной лицензии согласно 19 CFR 111.11?","tr":"Bir bireysel gümrük müşaviri lisansı başvuru sahibi, çeşitli yasal gereklilikleri karşılamalıdır. Aşağıdakilerden hangisi 19 CFR 111.11 kapsamında bireysel bir lisans almak için gerekli DEĞİLDİR?","hi":"एक व्यक्तिगत customs broker लाइसेंस के आवेदक को कई वैधानिक आवश्यकताओं को पूरा करना होता है। 19 CFR 111.11 के तहत व्यक्तिगत लाइसेंस प्राप्त करने के लिए निम्नलिखित में से कौन-सी आवश्यकता नहीं है?","ar":"يجب على طالب رخصة وسيط جمركي فردي استيفاء عدة متطلبات قانونية. أي مما يلي ليس شرطاً للحصول على رخصة فردية بموجب 19 CFR 111.11؟"},"o":[{"en":"Be a citizen of the United States","es":"Ser ciudadano de Estados Unidos","ru":"Быть гражданином Соединенных Штатов","tr":"Amerika Birleşik Devletleri vatandaşı olmak","hi":"संयुक्त राज्य अमेरिका का नागरिक होना","ar":"أن يكون مواطناً من مواطني الولايات المتحدة"},{"en":"Attain the age of 21 prior to submission of the application","es":"Cumplir 21 años de edad antes de la presentación de la solicitud","ru":"Достичь возраста 21 года до подачи заявления","tr":"Başvurunun sunulmasından önce 21 yaşını doldurmak","hi":"आवेदन जमा करने से पहले 21 वर्ष की आयु प्राप्त करना","ar":"أن يبلغ سن 21 قبل تقديم الطلب"},{"en":"Have at least three years of prior experience as a customs broker employee","es":"Tener al menos tres años de experiencia previa como empleado de un agente de aduanas","ru":"Иметь не менее трех лет предшествующего опыта работы в качестве сотрудника таможенного брокера","tr":"Gümrük müşaviri çalışanı olarak en az üç yıl önceden deneyime sahip olmak","hi":"customs broker कर्मचारी के रूप में कम से कम तीन वर्ष का पूर्व अनुभव होना","ar":"أن يكون لديه ما لا يقل عن ثلاث سنوات من الخبرة السابقة كموظف لدى وسيط جمركي"},{"en":"Not be an officer or employee of the United States Government","es":"No ser funcionario ni empleado del Gobierno de Estados Unidos","ru":"Не быть должностным лицом или работником Правительства Соединенных Штатов","tr":"Amerika Birleşik Devletleri Hükümetinin bir memuru veya çalışanı olmamak","hi":"संयुक्त राज्य सरकार का अधिकारी या कर्मचारी न होना","ar":"ألا يكون مسؤولاً أو موظفاً في حكومة الولايات المتحدة"}],"e":{"en":"Under 19 CFR 111.11(a), an individual applicant must be a U.S. citizen, be 21 years old before applying, not be a Federal officer or employee, demonstrate good moral character, and have passed the examination. There is no minimum prior-experience requirement to obtain the license.","es":"Conforme a 19 CFR 111.11(a), un solicitante individual debe ser ciudadano de Estados Unidos, tener 21 años antes de solicitar, no ser funcionario ni empleado federal, demostrar buen carácter moral y haber aprobado el examen. No existe un requisito mínimo de experiencia previa para obtener la licencia.","ru":"Согласно 19 CFR 111.11(a), индивидуальный заявитель должен быть гражданином США, достичь возраста 21 года до подачи заявления, не быть федеральным должностным лицом или работником, продемонстрировать добропорядочный нравственный облик и сдать экзамен. Требования к минимальному предшествующему опыту для получения лицензии нет.","tr":"19 CFR 111.11(a) kapsamında, bireysel bir başvuru sahibi ABD vatandaşı olmalı, başvurmadan önce 21 yaşında olmalı, bir Federal memur veya çalışan olmamalı, iyi ahlaki karakter sergilemeli ve sınavı geçmiş olmalıdır. Lisans almak için asgari önceden deneyim gerekliliği yoktur.","hi":"19 CFR 111.11(a) के तहत, एक व्यक्तिगत आवेदक को U.S. नागरिक होना चाहिए, आवेदन से पहले 21 वर्ष का होना चाहिए, Federal अधिकारी या कर्मचारी नहीं होना चाहिए, अच्छे नैतिक चरित्र का प्रदर्शन करना चाहिए, और परीक्षा उत्तीर्ण की होनी चाहिए। लाइसेंस प्राप्त करने के लिए कोई न्यूनतम पूर्व-अनुभव आवश्यकता नहीं है।","ar":"بموجب 19 CFR 111.11(a)، يجب أن يكون الطالب الفرد مواطناً أمريكياً، وأن يبلغ 21 عاماً قبل التقديم، وألا يكون مسؤولاً أو موظفاً اتحادياً، وأن يثبت حسن الخلق، وأن يكون قد اجتاز الامتحان. ولا يوجد شرط حدّ أدنى للخبرة السابقة للحصول على الرخصة."}},{"cat":"compliance","a":0,"q":{"en":"Regarding the written examination for an individual broker's license, which statement is correct under 19 CFR 111.13?","es":"Respecto al examen escrito para una licencia individual de agente, ¿qué afirmación es correcta conforme a 19 CFR 111.13?","ru":"Относительно письменного экзамена на получение индивидуальной брокерской лицензии, какое утверждение верно согласно 19 CFR 111.13?","tr":"Bir bireysel gümrük müşaviri lisansı için yazılı sınavla ilgili olarak, 19 CFR 111.13 kapsamında hangi ifade doğrudur?","hi":"एक व्यक्तिगत ब्रोकर लाइसेंस के लिए लिखित परीक्षा के संबंध में, 19 CFR 111.13 के तहत कौन-सा कथन सही है?","ar":"فيما يتعلق بالامتحان التحريري لرخصة الوسيط الفردي، أي عبارة صحيحة بموجب 19 CFR 111.13؟"},"o":[{"en":"An applicant must attain a grade of 75 percent or higher to pass the examination","es":"Un solicitante debe obtener una calificación de 75 por ciento o más para aprobar el examen","ru":"Заявитель должен набрать оценку 75 процентов или выше, чтобы сдать экзамен","tr":"Bir başvuru sahibi, sınavı geçmek için yüzde 75 veya daha yüksek bir not almalıdır","hi":"आवेदक को परीक्षा उत्तीर्ण करने के लिए 75 प्रतिशत या उससे अधिक का ग्रेड प्राप्त करना होगा","ar":"يجب أن يحصل الطالب على درجة 75 بالمئة أو أعلى لاجتياز الامتحان"},{"en":"The examination is offered three times per year and a passing grade of 70 percent is required","es":"El examen se ofrece tres veces al año y se requiere una calificación aprobatoria del 70 por ciento","ru":"Экзамен проводится три раза в год, и проходной балл составляет 70 процентов","tr":"Sınav yılda üç kez yapılır ve geçer not olarak yüzde 70 gerekir","hi":"परीक्षा वर्ष में तीन बार आयोजित की जाती है और 70 प्रतिशत का उत्तीर्ण ग्रेड आवश्यक है","ar":"يُقدَّم الامتحان ثلاث مرات في السنة وتُشترط درجة نجاح قدرها 70 بالمئة"},{"en":"Only individuals who are already employed by a licensed broker are eligible to sit for the examination","es":"Solo los individuos que ya están empleados por un agente con licencia son elegibles para presentar el examen","ru":"Только лица, уже трудоустроенные у лицензированного брокера, имеют право сдавать экзамен","tr":"Sınava girmeye yalnızca halihazırda lisanslı bir gümrük müşaviri tarafından istihdam edilen bireyler uygundur","hi":"केवल वे व्यक्ति जो पहले से ही एक लाइसेंस-प्राप्त ब्रोकर द्वारा नियोजित हैं, परीक्षा में बैठने के लिए पात्र हैं","ar":"لا يحقّ سوى للأفراد العاملين بالفعل لدى وسيط مرخَّص التقدّم لأداء الامتحان"},{"en":"An applicant must be at least 21 years old on the date of the examination to be eligible to take it","es":"Un solicitante debe tener al menos 21 años en la fecha del examen para ser elegible para presentarlo","ru":"Заявитель должен быть не моложе 21 года на дату экзамена, чтобы иметь право его сдавать","tr":"Bir başvuru sahibi, sınava girmeye uygun olmak için sınav tarihinde en az 21 yaşında olmalıdır","hi":"परीक्षा देने के पात्र होने के लिए आवेदक को परीक्षा की तारीख पर कम से कम 21 वर्ष का होना चाहिए","ar":"يجب أن يكون الطالب قد بلغ 21 عاماً على الأقل في تاريخ الامتحان ليحقّ له أداؤه"}],"e":{"en":"Under 19 CFR 111.11(a)(4) and 111.13, an applicant must attain a grade of at least 75 percent on the examination. The exam is generally given twice a year (the fourth Wednesday in April and October). One need not be employed by a broker to sit for the exam, and the age 21 requirement applies to obtaining the license, not taking the exam.","es":"Conforme a 19 CFR 111.11(a)(4) y 111.13, un solicitante debe obtener una calificación de al menos 75 por ciento en el examen. El examen generalmente se aplica dos veces al año (el cuarto miércoles de abril y de octubre). No es necesario estar empleado por un agente para presentar el examen, y el requisito de los 21 años aplica para obtener la licencia, no para presentar el examen.","ru":"Согласно 19 CFR 111.11(a)(4) и 111.13, заявитель должен набрать оценку не менее 75 процентов на экзамене. Экзамен обычно проводится дважды в год (четвертая среда апреля и октября). Не обязательно быть трудоустроенным у брокера, чтобы сдавать экзамен, а требование о возрасте 21 года применяется к получению лицензии, а не к сдаче экзамена.","tr":"19 CFR 111.11(a)(4) ve 111.13 kapsamında, bir başvuru sahibi sınavda en az yüzde 75 not almalıdır. Sınav genellikle yılda iki kez yapılır (Nisan ve Ekim aylarının dördüncü Çarşamba günü). Sınava girmek için bir gümrük müşaviri tarafından istihdam edilmek gerekli değildir ve 21 yaş gerekliliği, sınava girmek için değil, lisans almak için geçerlidir.","hi":"19 CFR 111.11(a)(4) और 111.13 के तहत, एक आवेदक को परीक्षा में कम से कम 75 प्रतिशत का ग्रेड प्राप्त करना होगा। परीक्षा आम तौर पर वर्ष में दो बार दी जाती है (April और October का चौथा Wednesday)। परीक्षा में बैठने के लिए किसी ब्रोकर द्वारा नियोजित होने की आवश्यकता नहीं है, और 21 वर्ष की आयु की आवश्यकता लाइसेंस प्राप्त करने पर लागू होती है, परीक्षा देने पर नहीं।","ar":"بموجب 19 CFR 111.11(a)(4) و111.13، يجب أن يحصل الطالب على درجة لا تقلّ عن 75 بالمئة في الامتحان. ويُقدَّم الامتحان عموماً مرتين في السنة (يوم الأربعاء الرابع من April وOctober). ولا يلزم أن يكون الشخص موظفاً لدى وسيط لأداء الامتحان، وينطبق شرط سن 21 على الحصول على الرخصة لا على أداء الامتحان."}},{"cat":"compliance","a":1,"q":{"en":"A freight forwarder asks a licensed broker to handle entries for an importer of record that the forwarder serves. How must the broker obtain its power of attorney to comply with 19 CFR 111.36?","es":"Un agente de carga (freight forwarder) le pide a un agente de aduanas con licencia que maneje las entradas de un importador registrado al que el agente de carga atiende. ¿Cómo debe obtener el agente de aduanas su power of attorney para cumplir con 19 CFR 111.36?","ru":"Экспедитор просит лицензированного брокера оформить ввоз для импортера-получателя (importer of record), которого обслуживает экспедитор. Как брокер должен получить свою доверенность (POA) для соблюдения 19 CFR 111.36?","tr":"Bir freight forwarder (nakliye komisyoncusu), lisanslı bir gümrük müşavirinden, hizmet verdiği bir importer of record (kayıtlı ithalatçı) için beyanları işlemesini istiyor. 19 CFR 111.36'ya uymak için gümrük müşaviri vekaletini (power of attorney) nasıl almalıdır?","hi":"एक freight forwarder एक लाइसेंस-प्राप्त ब्रोकर से एक importer of record के लिए एंट्री संभालने को कहता है जिसकी forwarder सेवा करता है। 19 CFR 111.36 का पालन करने के लिए ब्रोकर को अपना power of attorney कैसे प्राप्त करना चाहिए?","ar":"يطلب وكيل شحن من وسيط مرخَّص معالجة إدخالات لمستورد مسجَّل يخدمه الوكيل. كيف يجب على الوسيط الحصول على توكيله الرسمي (POA) امتثالاً لـ 19 CFR 111.36؟"},"o":[{"en":"The broker may accept a power of attorney from the freight forwarder acting as the importer's agent","es":"El agente de aduanas puede aceptar un power of attorney del agente de carga actuando como representante del importador","ru":"Брокер может принять доверенность от экспедитора, действующего в качестве агента импортера","tr":"Gümrük müşaviri, ithalatçının vekili olarak hareket eden freight forwarder'dan bir vekaletname kabul edebilir","hi":"ब्रोकर आयातकर्ता के एजेंट के रूप में कार्य करने वाले freight forwarder से power of attorney स्वीकार कर सकता है","ar":"يجوز للوسيط قبول توكيل رسمي من وكيل الشحن بوصفه وكيلاً للمستورد"},{"en":"The broker must execute a customs power of attorney directly with the importer of record, not through the freight forwarder","es":"El agente de aduanas debe ejecutar un power of attorney aduanero directamente con el importador registrado, no a través del agente de carga","ru":"Брокер должен оформить таможенную доверенность непосредственно с импортером-получателем (importer of record), а не через экспедитора","tr":"Gümrük müşaviri, freight forwarder aracılığıyla değil, doğrudan importer of record ile bir gümrük vekaletnamesi (POA) düzenlemelidir","hi":"ब्रोकर को सीधे importer of record के साथ एक customs power of attorney निष्पादित करना चाहिए, freight forwarder के माध्यम से नहीं","ar":"يجب على الوسيط إبرام توكيل رسمي جمركي مباشرةً مع المستورد المسجَّل، لا عبر وكيل الشحن"},{"en":"No power of attorney is required because the forwarder already holds one from the importer","es":"No se requiere power of attorney porque el agente de carga ya tiene uno del importador","ru":"Доверенность не требуется, поскольку у экспедитора уже есть доверенность от импортера","tr":"Vekaletname gerekli değildir, çünkü forwarder zaten ithalatçıdan bir tane almıştır","hi":"किसी power of attorney की आवश्यकता नहीं है क्योंकि forwarder के पास पहले से ही आयातकर्ता से एक है","ar":"لا يلزم توكيل رسمي لأن الوكيل يحوز بالفعل توكيلاً من المستورد"},{"en":"The broker may rely on a sub-power of attorney that the forwarder issues from its own master power of attorney","es":"El agente de aduanas puede basarse en un sub-power of attorney que el agente de carga emite a partir de su propio power of attorney maestro","ru":"Брокер может полагаться на субдоверенность, которую экспедитор выдает на основе своей собственной генеральной доверенности","tr":"Gümrük müşaviri, forwarder'ın kendi ana vekaletnamesinden düzenlediği bir alt vekaletnameye (sub-power of attorney) dayanabilir","hi":"ब्रोकर एक sub-power of attorney पर भरोसा कर सकता है जो forwarder अपने स्वयं के master power of attorney से जारी करता है","ar":"يجوز للوسيط الاعتماد على توكيل فرعي يصدره الوكيل من توكيله الرئيسي الخاص"}],"e":{"en":"Under 19 CFR 111.36(c)(3), when a broker transacts business as the agent of an importer of record, it must execute a customs power of attorney directly with that importer of record (or drawback claimant), and not via a freight forwarder or other third party. The agreement also may not bar direct communication between the broker and the importer.","es":"Conforme a 19 CFR 111.36(c)(3), cuando un agente de aduanas realiza negocios como representante de un importador registrado, debe ejecutar un power of attorney aduanero directamente con ese importador registrado (o reclamante de drawback), y no a través de un agente de carga u otro tercero. El acuerdo tampoco puede prohibir la comunicación directa entre el agente de aduanas y el importador.","ru":"Согласно 19 CFR 111.36(c)(3), когда брокер ведет деятельность в качестве агента импортера-получателя (importer of record), он должен оформить таможенную доверенность непосредственно с этим импортером-получателем (или заявителем на возврат пошлин), а не через экспедитора или иную третью сторону. Соглашение также не может запрещать прямое общение между брокером и импортером.","tr":"19 CFR 111.36(c)(3) kapsamında, bir gümrük müşaviri bir importer of record'un vekili olarak iş yürüttüğünde, doğrudan o importer of record (veya drawback talep eden) ile bir gümrük vekaletnamesi (POA) düzenlemeli, bir freight forwarder veya başka bir üçüncü taraf aracılığıyla değil. Anlaşma ayrıca gümrük müşaviri ile ithalatçı arasındaki doğrudan iletişimi de engelleyemez.","hi":"19 CFR 111.36(c)(3) के तहत, जब एक ब्रोकर एक importer of record के एजेंट के रूप में व्यवसाय करता है, तो उसे सीधे उस importer of record (या drawback claimant) के साथ एक customs power of attorney निष्पादित करना चाहिए, न कि किसी freight forwarder या अन्य तृतीय पक्ष के माध्यम से। समझौता ब्रोकर और आयातकर्ता के बीच सीधे संचार पर रोक भी नहीं लगा सकता।","ar":"بموجب 19 CFR 111.36(c)(3)، عندما يزاول وسيط الأعمال بوصفه وكيلاً لمستورد مسجَّل، يجب أن يبرم توكيلاً رسمياً جمركياً مباشرةً مع ذلك المستورد المسجَّل (أو مطالِب استرداد الرسوم)، لا عبر وكيل شحن أو طرف ثالث آخر. كما لا يجوز أن يمنع الاتفاق التواصل المباشر بين الوسيط والمستورد."}},{"cat":"compliance","a":1,"q":{"en":"A power of attorney executed by a partnership in favor of a customs broker is dated March 1, 2024, and contains no expiration date. For how long is that power of attorney valid?","es":"Un power of attorney ejecutado por una sociedad colectiva a favor de un agente de aduanas tiene fecha del March 1, 2024, y no contiene fecha de vencimiento. ¿Por cuánto tiempo es válido ese power of attorney?","ru":"Доверенность (POA), оформленная товариществом в пользу таможенного брокера, датирована March 1, 2024, и не содержит срока истечения. Как долго эта доверенность действительна?","tr":"Bir ortaklık (partnership) tarafından bir gümrük müşaviri lehine düzenlenen bir vekaletname (POA) 1 Mart 2024 tarihlidir ve herhangi bir sona erme tarihi içermemektedir. Bu vekaletname ne kadar süreyle geçerlidir?","hi":"एक साझेदारी (partnership) द्वारा एक customs broker के पक्ष में निष्पादित एक power of attorney की तारीख March 1, 2024 है, और इसमें कोई समाप्ति तिथि नहीं है। वह power of attorney कितने समय तक वैध है?","ar":"توكيل رسمي (POA) أبرمته شراكة لصالح وسيط جمركي مؤرَّخ في March 1, 2024، ولا يتضمّن تاريخ انتهاء. لأي مدة يكون هذا التوكيل الرسمي صالحاً؟"},"o":[{"en":"It is valid for an unlimited period because it states no expiration","es":"Es válido por un período ilimitado porque no establece vencimiento","ru":"Она действительна неограниченный срок, поскольку не указывает срока истечения","tr":"Sona erme tarihi belirtmediğinden sınırsız bir süre için geçerlidir","hi":"यह असीमित अवधि के लिए वैध है क्योंकि इसमें कोई समाप्ति नहीं बताई गई है","ar":"صالح لمدة غير محدودة لأنه لا يذكر تاريخ انتهاء"},{"en":"It is valid for a period not to exceed 2 years from the date of execution","es":"Es válido por un período que no exceda 2 años desde la fecha de ejecución","ru":"Она действительна на срок, не превышающий 2 года с даты оформления","tr":"Düzenleme tarihinden itibaren 2 yılı aşmayan bir süre için geçerlidir","hi":"यह निष्पादन की तारीख से 2 वर्ष से अधिक नहीं की अवधि के लिए वैध है","ar":"صالح لمدة لا تتجاوز سنتين من تاريخ الإبرام"},{"en":"It is valid for 5 years, matching the broker's recordkeeping retention period","es":"Es válido por 5 años, coincidiendo con el período de retención de registros del agente","ru":"Она действительна 5 лет, совпадая со сроком хранения документов брокера","tr":"Gümrük müşavirinin kayıt saklama süresine uygun olarak 5 yıl geçerlidir","hi":"यह 5 वर्ष के लिए वैध है, जो ब्रोकर की रिकॉर्ड-रखरखाव प्रतिधारण अवधि से मेल खाता है","ar":"صالح لمدة 5 سنوات، مطابقةً لمدة الاحتفاظ بالسجلات لدى الوسيط"},{"en":"It is valid for 3 years, corresponding to the triennial reporting cycle","es":"Es válido por 3 años, correspondiente al ciclo de informes trienales","ru":"Она действительна 3 года, соответствуя трехлетнему циклу отчетности","tr":"Üç yıllık raporlama döngüsüne karşılık gelecek şekilde 3 yıl geçerlidir","hi":"यह 3 वर्ष के लिए वैध है, जो त्रैवार्षिक रिपोर्टिंग चक्र के अनुरूप है","ar":"صالح لمدة 3 سنوات، بما يوافق دورة الإبلاغ كل ثلاث سنوات"}],"e":{"en":"Under 19 CFR 141.34, a power of attorney issued by a partnership is limited to a period not to exceed 2 years from the date of execution; all other powers of attorney may be granted for an unlimited period. The 5-year retention rule (111.23) and the 3-year status cycle (111.30) are unrelated to POA duration.","es":"Conforme a 19 CFR 141.34, un power of attorney emitido por una sociedad colectiva se limita a un período que no exceda 2 años desde la fecha de ejecución; todos los demás powers of attorney pueden otorgarse por un período ilimitado. La regla de retención de 5 años (111.23) y el ciclo de estatus de 3 años (111.30) no están relacionados con la duración del POA.","ru":"Согласно 19 CFR 141.34, доверенность, выданная товариществом, ограничена сроком, не превышающим 2 года с даты оформления; все остальные доверенности могут выдаваться на неограниченный срок. Правило о 5-летнем хранении (111.23) и 3-летний цикл статуса (111.30) не связаны со сроком действия POA.","tr":"19 CFR 141.34 kapsamında, bir ortaklık (partnership) tarafından düzenlenen bir vekaletname (POA), düzenleme tarihinden itibaren 2 yılı aşmayan bir süreyle sınırlıdır; diğer tüm vekaletnameler sınırsız bir süre için verilebilir. 5 yıllık saklama kuralı (111.23) ve 3 yıllık durum döngüsü (111.30), POA süresiyle ilgisizdir.","hi":"19 CFR 141.34 के तहत, एक साझेदारी द्वारा जारी किया गया power of attorney निष्पादन की तारीख से 2 वर्ष से अधिक नहीं की अवधि तक सीमित है; अन्य सभी powers of attorney असीमित अवधि के लिए दिए जा सकते हैं। 5-वर्षीय प्रतिधारण नियम (111.23) और 3-वर्षीय स्थिति चक्र (111.30) POA की अवधि से असंबंधित हैं।","ar":"بموجب 19 CFR 141.34، يقتصر التوكيل الرسمي الصادر عن شراكة على مدة لا تتجاوز سنتين من تاريخ الإبرام؛ أما سائر التوكيلات الرسمية فيجوز منحها لمدة غير محدودة. وقاعدة الاحتفاظ لمدة 5 سنوات (111.23) ودورة الحالة كل 3 سنوات (111.30) لا صلة لهما بمدة POA."}},{"cat":"compliance","a":2,"q":{"en":"Under 19 CFR 141.36, a power of attorney executed by a nonresident principal will NOT be accepted unless which condition is met?","es":"Conforme a 19 CFR 141.36, un power of attorney ejecutado por un mandante no residente NO será aceptado a menos que se cumpla qué condición?","ru":"Согласно 19 CFR 141.36, доверенность (POA), оформленная нерезидентом-доверителем, НЕ будет принята, если не выполнено какое условие?","tr":"19 CFR 141.36 kapsamında, yurt dışında mukim bir asıl (nonresident principal) tarafından düzenlenen bir vekaletname (POA), hangi koşul karşılanmadıkça kabul edilMEZ?","hi":"19 CFR 141.36 के तहत, एक गैर-निवासी प्रधान (nonresident principal) द्वारा निष्पादित power of attorney तब तक स्वीकार नहीं किया जाएगा जब तक कि कौन-सी शर्त पूरी न हो?","ar":"بموجب 19 CFR 141.36، لن يُقبل توكيل رسمي (POA) أبرمه موكِّل غير مقيم ما لم يُستوفَ أي شرط؟"},"o":[{"en":"The power of attorney is filed in advance with the processing Center","es":"El power of attorney se presenta por anticipado ante el Center que lo procesa","ru":"Доверенность заранее подается в обрабатывающий Центр (Center)","tr":"Vekaletname, işlemleri yürüten Center'a önceden sunulur","hi":"power of attorney processing Center के पास अग्रिम रूप से दाखिल किया गया हो","ar":"أن يُودَع التوكيل الرسمي مسبقاً لدى Center المعالج"},{"en":"The nonresident principal posts a separate single-transaction bond","es":"El mandante no residente constituye una fianza separada de transacción única","ru":"Нерезидент-доверитель вносит отдельную гарантию на разовую сделку (single-transaction bond)","tr":"Yurt dışında mukim asıl, ayrı bir tek işlem teminatı (single-transaction bond) yatırır","hi":"गैर-निवासी प्रधान एक अलग single-transaction bond जमा करे","ar":"أن يقدّم الموكِّل غير المقيم سند ضمان منفصل لمعاملة واحدة"},{"en":"The agent designated in the power of attorney is a resident authorized to accept service of process on behalf of the nonresident","es":"El representante designado en el power of attorney es un residente autorizado para aceptar la notificación de procesos legales en nombre del no residente","ru":"Агент, назначенный в доверенности, является резидентом, уполномоченным принимать судебные извещения от имени нерезидента","tr":"Vekaletnamede belirlenen vekil, yurt dışında mukim olan adına tebligat (service of process) kabul etmeye yetkili, ülkede mukim bir kişidir","hi":"power of attorney में नामित एजेंट एक निवासी हो जो गैर-निवासी की ओर से service of process स्वीकार करने के लिए अधिकृत हो","ar":"أن يكون الوكيل المعيَّن في التوكيل الرسمي مقيماً مفوّضاً بقبول تبليغ الإجراءات القضائية نيابةً عن غير المقيم"},{"en":"The power of attorney is limited to a single entry and expires after one year","es":"El power of attorney se limita a una sola entrada y vence después de un año","ru":"Доверенность ограничена одним оформлением и истекает через один год","tr":"Vekaletname tek bir beyanla sınırlıdır ve bir yıl sonra sona erer","hi":"power of attorney एक एकल एंट्री तक सीमित हो और एक वर्ष बाद समाप्त हो जाए","ar":"أن يقتصر التوكيل الرسمي على إدخال واحد وأن ينتهي بعد سنة واحدة"}],"e":{"en":"Under 19 CFR 141.36, a power of attorney from a nonresident principal is not accepted unless the designated agent is a resident who is authorized to accept service of process against the nonresident. POAs need not be filed with CBP (141.46), and there is no special bond or one-entry/one-year limitation imposed by this rule.","es":"Conforme a 19 CFR 141.36, un power of attorney de un mandante no residente no se acepta a menos que el representante designado sea un residente autorizado para aceptar la notificación de procesos legales contra el no residente. Los POA no necesitan presentarse ante CBP (141.46), y esta regla no impone ninguna fianza especial ni limitación de una entrada/un año.","ru":"Согласно 19 CFR 141.36, доверенность от нерезидента-доверителя не принимается, если назначенный агент не является резидентом, уполномоченным принимать судебные извещения в отношении нерезидента. Доверенности не обязательно подавать в CBP (141.46), и данное правило не накладывает специальной гарантии или ограничения в одно оформление / один год.","tr":"19 CFR 141.36 kapsamında, yurt dışında mukim bir asıldan (nonresident principal) gelen bir vekaletname (POA), belirlenen vekil, yurt dışında mukim olana karşı tebligat (service of process) kabul etmeye yetkili, ülkede mukim bir kişi olmadıkça kabul edilmez. POA'ların CBP'ye sunulması gerekmez (141.46) ve bu kural tarafından dayatılan özel bir teminat veya tek beyan/bir yıl sınırlaması yoktur.","hi":"19 CFR 141.36 के तहत, एक गैर-निवासी प्रधान से power of attorney तब तक स्वीकार नहीं किया जाता जब तक कि नामित एजेंट एक निवासी न हो जो गैर-निवासी के विरुद्ध service of process स्वीकार करने के लिए अधिकृत हो। POAs को CBP के पास दाखिल करने की आवश्यकता नहीं है (141.46), और इस नियम द्वारा कोई विशेष bond या एक-एंट्री/एक-वर्ष की सीमा नहीं लगाई गई है।","ar":"بموجب 19 CFR 141.36، لا يُقبل التوكيل الرسمي من موكِّل غير مقيم ما لم يكن الوكيل المعيَّن مقيماً مفوّضاً بقبول تبليغ الإجراءات القضائية ضد غير المقيم. ولا يلزم إيداع التوكيلات الرسمية لدى CBP (141.46)، ولا تفرض هذه القاعدة سند ضمان خاصاً أو قيد إدخال واحد/سنة واحدة."}},{"cat":"compliance","a":2,"q":{"en":"In assessing whether a broker is exercising 'responsible supervision and control,' which of the following would CBP consider under 19 CFR 111.28?","es":"Al evaluar si un agente de aduanas ejerce 'supervisión y control responsables', ¿cuál de los siguientes consideraría CBP conforme a 19 CFR 111.28?","ru":"При оценке того, осуществляет ли брокер 'ответственный надзор и контроль', что из перечисленного CBP будет учитывать согласно 19 CFR 111.28?","tr":"Bir gümrük müşavirinin 'sorumlu gözetim ve kontrol' (responsible supervision and control) uygulayıp uygulamadığını değerlendirirken, CBP 19 CFR 111.28 kapsamında aşağıdakilerden hangisini dikkate alır?","hi":"यह आकलन करने में कि क्या एक ब्रोकर 'responsible supervision and control' का प्रयोग कर रहा है, 19 CFR 111.28 के तहत CBP निम्नलिखित में से किस पर विचार करेगा?","ar":"عند تقييم ما إذا كان الوسيط يمارس \"الإشراف والرقابة المسؤولين\"، أي مما يلي ستأخذه CBP في الاعتبار بموجب 19 CFR 111.28؟"},"o":[{"en":"Only the total dollar value of duties the broker remits to CBP each year","es":"Únicamente el valor total en dólares de los derechos que el agente remite a CBP cada año","ru":"Только общую сумму пошлин в долларах, которую брокер перечисляет в CBP ежегодно","tr":"Yalnızca gümrük müşavirinin her yıl CBP'ye aktardığı toplam vergi tutarını","hi":"केवल उन शुल्कों का कुल डॉलर मूल्य जो ब्रोकर हर साल CBP को भेजता है","ar":"فقط إجمالي القيمة الدولارية للرسوم التي يحوّلها الوسيط إلى CBP كل عام"},{"en":"Solely whether the broker maintains a physical office in every port served","es":"Únicamente si el agente mantiene una oficina física en cada puerto atendido","ru":"Исключительно то, поддерживает ли брокер физический офис в каждом обслуживаемом порту","tr":"Yalnızca gümrük müşavirinin hizmet verdiği her limanda fiziksel bir ofis bulundurup bulundurmadığını","hi":"केवल यह कि क्या ब्रोकर हर सेवित बंदरगाह में एक भौतिक कार्यालय बनाए रखता है","ar":"فقط ما إذا كان الوسيط يحتفظ بمكتب مادي في كل ميناء يخدمه"},{"en":"A range of factors including the broker's reject rate, training provided to employees, and the availability of a qualifying broker for consultation","es":"Una gama de factores que incluye la tasa de rechazo del agente, la capacitación brindada a los empleados y la disponibilidad de un agente calificado para consulta","ru":"Ряд факторов, включая долю отклонений (reject rate) у брокера, обучение, предоставляемое работникам, и доступность квалифицированного брокера для консультаций","tr":"Gümrük müşavirinin ret oranı, çalışanlara verilen eğitim ve danışma için nitelikli bir gümrük müşavirinin bulunabilirliği dahil bir dizi faktörü","hi":"कारकों की एक श्रृंखला जिसमें ब्रोकर की reject rate, कर्मचारियों को प्रदान किया गया प्रशिक्षण, और परामर्श के लिए एक योग्य ब्रोकर की उपलब्धता शामिल है","ar":"مجموعة من العوامل تشمل معدل الرفض لدى الوسيط، والتدريب المقدَّم للموظفين، وتوافر وسيط مؤهَّل للاستشارة"},{"en":"Exclusively the number of years the qualifying broker has held a license","es":"Exclusivamente el número de años que el agente calificado ha tenido una licencia","ru":"Исключительно количество лет, в течение которых квалифицированный брокер имеет лицензию","tr":"Yalnızca nitelikli gümrük müşavirinin lisansa kaç yıldır sahip olduğunu","hi":"केवल वर्षों की संख्या जिनके लिए योग्य ब्रोकर के पास लाइसेंस रहा है","ar":"حصراً عدد السنوات التي حاز فيها الوسيط المؤهِّل الرخصة"}],"e":{"en":"Under 19 CFR 111.28(a), CBP weighs numerous non-exclusive factors, such as the reject rate for the broker's transactions, training and written instructions provided to employees, the availability of a licensed broker for employee consultation, audit frequency, and the qualifying broker's involvement. No single factor (duties paid, office locations, or years licensed) is dispositive.","es":"Conforme a 19 CFR 111.28(a), CBP pondera numerosos factores no exclusivos, como la tasa de rechazo de las transacciones del agente, la capacitación e instrucciones escritas brindadas a los empleados, la disponibilidad de un agente con licencia para consulta de los empleados, la frecuencia de auditorías y la participación del agente calificado. Ningún factor por sí solo (derechos pagados, ubicaciones de oficinas o años con licencia) es determinante.","ru":"Согласно 19 CFR 111.28(a), CBP взвешивает многочисленные неисчерпывающие факторы, такие как доля отклонений (reject rate) по сделкам брокера, обучение и письменные инструкции, предоставляемые работникам, доступность лицензированного брокера для консультаций работников, частота аудита и вовлеченность квалифицированного брокера. Ни один отдельный фактор (уплаченные пошлины, расположение офисов или стаж лицензии) не является определяющим.","tr":"19 CFR 111.28(a) kapsamında, CBP; gümrük müşavirinin işlemlerine ilişkin ret oranı, çalışanlara verilen eğitim ve yazılı talimatlar, çalışanların danışması için lisanslı bir gümrük müşavirinin bulunabilirliği, denetim sıklığı ve nitelikli gümrük müşavirinin katılımı gibi çok sayıda münhasır olmayan faktörü tartar. Hiçbir tek faktör (ödenen vergiler, ofis konumları veya lisans yılı) belirleyici değildir.","hi":"19 CFR 111.28(a) के तहत, CBP कई गैर-विशिष्ट कारकों को तौलता है, जैसे ब्रोकर के लेनदेन के लिए reject rate, कर्मचारियों को प्रदान किए गए प्रशिक्षण और लिखित निर्देश, कर्मचारी परामर्श के लिए एक लाइसेंस-प्राप्त ब्रोकर की उपलब्धता, audit आवृत्ति, और योग्य ब्रोकर की भागीदारी। कोई एकल कारक (चुकाए गए शुल्क, कार्यालय स्थान, या लाइसेंस के वर्ष) निर्णायक नहीं है।","ar":"بموجب 19 CFR 111.28(a)، توازن CBP بين عوامل عديدة غير حصرية، مثل معدل الرفض لمعاملات الوسيط، والتدريب والتعليمات المكتوبة المقدَّمة للموظفين، وتوافر وسيط مرخَّص لاستشارة الموظفين، وتواتر التدقيق، ومدى مشاركة الوسيط المؤهِّل. ولا يكون أي عامل منفرد (الرسوم المدفوعة، أو مواقع المكاتب، أو سنوات الترخيص) حاسماً."}},{"cat":"compliance","a":1,"q":{"en":"A corporation that hires a new employee to assist in transacting customs business must report certain employee information to CBP. Under 19 CFR 111.28, within what time frame must the broker notify CBP of a newly hired employee?","es":"Una corporación que contrata a un nuevo empleado para ayudar a realizar negocios aduaneros debe reportar cierta información del empleado a CBP. Conforme a 19 CFR 111.28, ¿dentro de qué plazo debe el agente notificar a CBP sobre un empleado recién contratado?","ru":"Корпорация, нанимающая нового работника для содействия ведению таможенной деятельности, должна сообщить определенную информацию о работнике в CBP. Согласно 19 CFR 111.28, в какой срок брокер должен уведомить CBP о вновь нанятом работнике?","tr":"Gümrük işlemlerinin yürütülmesine yardımcı olmak üzere yeni bir çalışan işe alan bir şirket, belirli çalışan bilgilerini CBP'ye bildirmelidir. 19 CFR 111.28 kapsamında, gümrük müşaviri yeni işe alınan bir çalışanı CBP'ye hangi süre içinde bildirmelidir?","hi":"एक कॉर्पोरेशन जो customs business करने में सहायता के लिए एक नए कर्मचारी को नियुक्त करता है, उसे कुछ कर्मचारी जानकारी CBP को रिपोर्ट करनी होती है। 19 CFR 111.28 के तहत, ब्रोकर को किस समय-सीमा के भीतर नए नियुक्त कर्मचारी के बारे में CBP को सूचित करना चाहिए?","ar":"يجب على مؤسسة توظّف موظفاً جديداً للمساعدة في مزاولة الأعمال الجمركية إبلاغ CBP بمعلومات معيّنة عن الموظف. بموجب 19 CFR 111.28، خلال أي إطار زمني يجب على الوسيط إخطار CBP بموظف عُيِّن حديثاً؟"},"o":[{"en":"Within 10 calendar days of the hire","es":"Dentro de 10 días calendario de la contratación","ru":"В течение 10 календарных дней с момента найма","tr":"İşe alımdan itibaren 10 takvim günü içinde","hi":"नियुक्ति के 10 कैलेंडर दिनों के भीतर","ar":"خلال 10 أيام تقويمية من التعيين"},{"en":"Within 30 calendar days of the hire","es":"Dentro de 30 días calendario de la contratación","ru":"В течение 30 календарных дней с момента найма","tr":"İşe alımdan itibaren 30 takvim günü içinde","hi":"नियुक्ति के 30 कैलेंडर दिनों के भीतर","ar":"خلال 30 يوماً تقويمياً من التعيين"},{"en":"Within 60 calendar days of the hire","es":"Dentro de 60 días calendario de la contratación","ru":"В течение 60 календарных дней с момента найма","tr":"İşe alımdan itibaren 60 takvim günü içinde","hi":"नियुक्ति के 60 कैलेंडर दिनों के भीतर","ar":"خلال 60 يوماً تقويمياً من التعيين"},{"en":"Only once per year, in the annual employee list","es":"Solo una vez al año, en la lista anual de empleados","ru":"Только один раз в год, в ежегодном списке работников","tr":"Yalnızca yılda bir kez, yıllık çalışan listesinde","hi":"केवल वर्ष में एक बार, वार्षिक कर्मचारी सूची में","ar":"مرة واحدة فقط في السنة، ضمن قائمة الموظفين السنوية"}],"e":{"en":"Under 19 CFR 111.28(b), a broker must submit to CBP a list of employee information and must report new hires, terminations, and changes within 30 calendar days. (Contrast this with the 10-day rule in 111.30 for changes in the broker's own address or organization.)","es":"Conforme a 19 CFR 111.28(b), un agente debe presentar a CBP una lista de información de empleados y debe reportar nuevas contrataciones, despidos y cambios dentro de 30 días calendario. (Compárese esto con la regla de 10 días en 111.30 para cambios en la propia dirección u organización del agente).","ru":"Согласно 19 CFR 111.28(b), брокер должен представить в CBP список информации о работниках и обязан сообщать о новых наймах, увольнениях и изменениях в течение 30 календарных дней. (Сравните это с правилом 10 дней в 111.30 для изменений в собственном адресе или организации брокера.)","tr":"19 CFR 111.28(b) kapsamında, bir gümrük müşaviri CBP'ye bir çalışan bilgisi listesi sunmalı ve yeni işe alımları, işten çıkarmaları ve değişiklikleri 30 takvim günü içinde bildirmelidir. (Bunu, gümrük müşavirinin kendi adresindeki veya organizasyonundaki değişiklikler için 111.30'daki 10 günlük kuralla karşılaştırın.)","hi":"19 CFR 111.28(b) के तहत, एक ब्रोकर को CBP को कर्मचारी जानकारी की एक सूची प्रस्तुत करनी होती है और नई नियुक्तियों, समाप्तियों और परिवर्तनों को 30 कैलेंडर दिनों के भीतर रिपोर्ट करना होता है। (इसकी तुलना ब्रोकर के अपने पते या संगठन में परिवर्तनों के लिए 111.30 में 10-दिन के नियम से करें।)","ar":"بموجب 19 CFR 111.28(b)، يجب على الوسيط تقديم قائمة بمعلومات الموظفين إلى CBP، والإبلاغ عن التعيينات الجديدة وإنهاءات الخدمة والتغييرات خلال 30 يوماً تقويمياً. (قارن ذلك بقاعدة 10 أيام في 111.30 للتغييرات في عنوان الوسيط نفسه أو تنظيمه.)"}},{"cat":"compliance","a":1,"q":{"en":"Except for powers of attorney, for how long must a broker retain the records described in 19 CFR 111.23, and from what event does the period run?","es":"Salvo los powers of attorney, ¿por cuánto tiempo debe un agente de aduanas conservar los registros descritos en 19 CFR 111.23, y a partir de qué evento corre el período?","ru":"За исключением доверенностей, как долго брокер должен хранить документы, описанные в 19 CFR 111.23, и от какого события отсчитывается срок?","tr":"Vekaletnameler hariç olmak üzere, bir gümrük müşaviri 19 CFR 111.23'te tanımlanan kayıtları ne kadar süreyle saklamalıdır ve bu süre hangi olaydan itibaren başlar?","hi":"powers of attorney को छोड़कर, एक ब्रोकर को 19 CFR 111.23 में वर्णित रिकॉर्ड कितने समय तक रखने चाहिए, और यह अवधि किस घटना से शुरू होती है?","ar":"باستثناء التوكيلات الرسمية، إلى متى يجب على الوسيط الاحتفاظ بالسجلات الموصوفة في 19 CFR 111.23، ومن أي حدث تبدأ المدة؟"},"o":[{"en":"Three years after the date the triennial status report is filed","es":"Tres años después de la fecha en que se presenta el informe de estatus trienal","ru":"Три года после даты подачи трехлетнего отчета о статусе","tr":"Üç yıllık durum raporunun sunulduğu tarihten itibaren üç yıl","hi":"त्रैवार्षिक status report दाखिल करने की तारीख के तीन वर्ष बाद","ar":"ثلاث سنوات بعد تاريخ تقديم تقرير الحالة الذي يُقدَّم كل ثلاث سنوات"},{"en":"Five years after the date of entry","es":"Cinco años después de la fecha de entrada","ru":"Пять лет после даты оформления (entry)","tr":"Beyan tarihinden itibaren beş yıl","hi":"एंट्री की तारीख के पाँच वर्ष बाद","ar":"خمس سنوات بعد تاريخ الإدخال"},{"en":"Six years after the close of the calendar year in which the entry was filed","es":"Seis años después del cierre del año calendario en que se presentó la entrada","ru":"Шесть лет после окончания календарного года, в котором было подано оформление","tr":"Beyanın sunulduğu takvim yılının kapanmasından itibaren altı yıl","hi":"उस कैलेंडर वर्ष की समाप्ति के छह वर्ष बाद जिसमें एंट्री दाखिल की गई थी","ar":"ست سنوات بعد انتهاء السنة التقويمية التي قُدِّم فيها الإدخال"},{"en":"Indefinitely, until CBP authorizes destruction in writing","es":"Indefinidamente, hasta que CBP autorice la destrucción por escrito","ru":"Бессрочно, пока CBP не разрешит уничтожение в письменной форме","tr":"Süresiz olarak, CBP imha için yazılı izin verene kadar","hi":"अनिश्चित काल तक, जब तक CBP लिखित रूप में विनाश को अधिकृत न करे","ar":"إلى أجل غير مسمّى، إلى أن تأذن CBP بالإتلاف كتابةً"}],"e":{"en":"Under 19 CFR 111.23(b), records (other than powers of attorney) must be retained for at least 5 years after the date of entry. Powers of attorney have their own rule (retained until revoked, then 5 years after revocation or after the client ceases to be active, whichever is later). The 6-year/close-of-year period applies to certain other recordkeeping contexts, not 111.23.","es":"Conforme a 19 CFR 111.23(b), los registros (distintos de los powers of attorney) deben conservarse durante al menos 5 años después de la fecha de entrada. Los powers of attorney tienen su propia regla (conservados hasta su revocación y luego 5 años después de la revocación o de que el cliente deje de estar activo, lo que ocurra más tarde). El período de 6 años/cierre de año aplica a ciertos otros contextos de conservación de registros, no a 111.23.","ru":"Согласно 19 CFR 111.23(b), документы (кроме доверенностей) должны храниться не менее 5 лет после даты оформления (entry). Доверенности имеют собственное правило (хранятся до отзыва, затем 5 лет после отзыва или после того, как клиент перестает быть активным, в зависимости от того, что наступит позже). Срок 6 лет / окончание года применяется к некоторым другим контекстам ведения документации, а не к 111.23.","tr":"19 CFR 111.23(b) kapsamında, kayıtlar (vekaletnameler hariç) beyan tarihinden itibaren en az 5 yıl saklanmalıdır. Vekaletnamelerin kendine ait bir kuralı vardır (iptal edilene kadar saklanır, ardından iptalden sonra 5 yıl veya müşterinin aktif olmayı bırakmasından sonra 5 yıl, hangisi daha sonraysa). 6 yıl/yıl kapanışı süresi, 111.23'e değil, belirli diğer kayıt saklama bağlamlarına uygulanır.","hi":"19 CFR 111.23(b) के तहत, रिकॉर्ड (powers of attorney के अलावा) को एंट्री की तारीख के बाद कम से कम 5 वर्ष तक रखा जाना चाहिए। Powers of attorney का अपना नियम है (रद्द होने तक रखे जाते हैं, फिर रद्दीकरण के 5 वर्ष बाद या ग्राहक के सक्रिय न रहने के बाद, जो भी बाद में हो)। 6-वर्ष/वर्ष-समाप्ति अवधि कुछ अन्य रिकॉर्ड-रखरखाव संदर्भों पर लागू होती है, 111.23 पर नहीं।","ar":"بموجب 19 CFR 111.23(b)، يجب الاحتفاظ بالسجلات (عدا التوكيلات الرسمية) لمدة لا تقل عن 5 سنوات بعد تاريخ الإدخال. وللتوكيلات الرسمية قاعدتها الخاصة (تُحفظ إلى أن تُلغى، ثم 5 سنوات بعد الإلغاء أو بعد توقّف نشاط العميل، أيهما أبعد). وتنطبق مدة 6 سنوات/انتهاء السنة على سياقات حفظ سجلات أخرى معيّنة، لا على 111.23."}},{"cat":"compliance","a":1,"q":{"en":"Under 19 CFR 111.23, where must a licensed broker maintain the originals of the records required by Part 111, including records stored in electronic format?","es":"Conforme a 19 CFR 111.23, ¿dónde debe un agente de aduanas con licencia conservar los originales de los registros requeridos por la Part 111, incluidos los registros almacenados en formato electrónico?","ru":"Согласно 19 CFR 111.23, где лицензированный брокер должен хранить оригиналы документов, требуемых Part 111, включая документы в электронном формате?","tr":"19 CFR 111.23 kapsamında, lisanslı bir gümrük müşaviri, elektronik formatta saklananlar dahil olmak üzere Part 111 tarafından gerekli kılınan kayıtların asıllarını nerede saklamalıdır?","hi":"19 CFR 111.23 के तहत, एक लाइसेंस-प्राप्त ब्रोकर को Part 111 द्वारा आवश्यक रिकॉर्ड के मूल (originals), जिसमें इलेक्ट्रॉनिक प्रारूप में संग्रहीत रिकॉर्ड शामिल हैं, कहाँ बनाए रखने चाहिए?","ar":"بموجب 19 CFR 111.23، أين يجب على الوسيط المرخَّص الاحتفاظ بأصول السجلات المطلوبة بموجب Part 111، بما فيها السجلات المحفوظة بصيغة إلكترونية؟"},"o":[{"en":"At the broker's office of record only, never in electronic form","es":"Únicamente en la oficina de registro del agente, nunca en forma electrónica","ru":"Только в учетном офисе брокера, никогда в электронной форме","tr":"Yalnızca gümrük müşavirinin kayıtlı ofisinde, asla elektronik biçimde değil","hi":"केवल ब्रोकर के office of record पर, कभी भी इलेक्ट्रॉनिक रूप में नहीं","ar":"في مكتب الوسيط المسجَّل فقط، وليس بصيغة إلكترونية أبداً"},{"en":"Within the customs territory of the United States","es":"Dentro del territorio aduanero de Estados Unidos","ru":"В пределах таможенной территории Соединенных Штатов","tr":"Amerika Birleşik Devletleri gümrük bölgesi içinde","hi":"संयुक्त राज्य अमेरिका के कस्टम क्षेत्र के भीतर","ar":"داخل الإقليم الجمركي للولايات المتحدة"},{"en":"At any location worldwide, provided the records are retrievable within 30 days","es":"En cualquier ubicación del mundo, siempre que los registros puedan recuperarse dentro de 30 días","ru":"В любом месте по всему миру, при условии, что документы доступны для извлечения в течение 30 дней","tr":"Kayıtların 30 gün içinde erişilebilir olması şartıyla, dünya çapında herhangi bir konumda","hi":"दुनिया में कहीं भी, बशर्ते रिकॉर्ड 30 दिनों के भीतर पुनर्प्राप्त किए जा सकें","ar":"في أي موقع حول العالم، شريطة إمكانية استرجاع السجلات خلال 30 يوماً"},{"en":"Only at a CBP-approved bonded warehouse","es":"Únicamente en un almacén afianzado aprobado por CBP","ru":"Только на утвержденном CBP таможенном складе","tr":"Yalnızca CBP onaylı bir gümrük antreposunda","hi":"केवल एक CBP-अनुमोदित bonded warehouse पर","ar":"فقط في مستودع جمركي مضمون معتمد من CBP"}],"e":{"en":"Under 19 CFR 111.23(a), a broker must maintain the originals of records, including any records stored in electronic formats, within the customs territory of the United States, in accordance with Part 111 and Part 163. Records may be kept electronically and need not be confined to a single office or a bonded warehouse.","es":"Conforme a 19 CFR 111.23(a), un agente debe conservar los originales de los registros, incluidos los registros almacenados en formatos electrónicos, dentro del territorio aduanero de Estados Unidos, de acuerdo con la Part 111 y la Part 163. Los registros pueden conservarse electrónicamente y no necesitan limitarse a una sola oficina o a un almacén afianzado.","ru":"Согласно 19 CFR 111.23(a), брокер должен хранить оригиналы документов, включая любые документы в электронном формате, в пределах таможенной территории Соединенных Штатов, в соответствии с Part 111 и Part 163. Документы могут храниться в электронном виде и не обязаны ограничиваться одним офисом или таможенным складом.","tr":"19 CFR 111.23(a) kapsamında, bir gümrük müşaviri, elektronik formatlarda saklanan kayıtlar dahil olmak üzere kayıtların asıllarını, Part 111 ve Part 163 uyarınca Amerika Birleşik Devletleri gümrük bölgesi içinde saklamalıdır. Kayıtlar elektronik olarak tutulabilir ve tek bir ofisle veya bir gümrük antreposuyla sınırlı olması gerekmez.","hi":"19 CFR 111.23(a) के तहत, एक ब्रोकर को रिकॉर्ड के मूल, जिसमें इलेक्ट्रॉनिक प्रारूपों में संग्रहीत कोई भी रिकॉर्ड शामिल है, Part 111 और Part 163 के अनुसार संयुक्त राज्य अमेरिका के कस्टम क्षेत्र के भीतर बनाए रखना चाहिए। रिकॉर्ड इलेक्ट्रॉनिक रूप से रखे जा सकते हैं और उन्हें एक एकल कार्यालय या bonded warehouse तक सीमित रखने की आवश्यकता नहीं है।","ar":"بموجب 19 CFR 111.23(a)، يجب على الوسيط الاحتفاظ بأصول السجلات، بما فيها أي سجلات محفوظة بصيغ إلكترونية، داخل الإقليم الجمركي للولايات المتحدة، وفقاً لـ Part 111 وPart 163. ويجوز حفظ السجلات إلكترونياً ولا يلزم حصرها في مكتب واحد أو مستودع جمركي مضمون."}},{"cat":"compliance","a":0,"q":{"en":"When a broker receives client funds to pay duties to the Government but does not receive them until after the due date, what does 19 CFR 111.29 require the broker to do?","es":"Cuando un agente de aduanas recibe fondos del cliente para pagar derechos al Gobierno pero no los recibe sino hasta después de la fecha de vencimiento, ¿qué exige 19 CFR 111.29 que haga el agente?","ru":"Когда брокер получает средства клиента для уплаты пошлин Правительству, но получает их только после установленного срока, что требует от брокера 19 CFR 111.29?","tr":"Bir gümrük müşaviri, Hükümete vergi ödemek üzere müşteri fonlarını alır ancak bunları ödeme tarihinden sonraya kadar almazsa, 19 CFR 111.29 gümrük müşavirinin ne yapmasını gerektirir?","hi":"जब एक ब्रोकर सरकार को शुल्क का भुगतान करने के लिए ग्राहक के धन प्राप्त करता है लेकिन उन्हें देय तिथि के बाद तक प्राप्त नहीं करता, तो 19 CFR 111.29 ब्रोकर से क्या करने की आवश्यकता रखता है?","ar":"عندما يتلقّى وسيط أموال عميل لدفع رسوم للحكومة لكنه لا يتلقّاها إلا بعد تاريخ الاستحقاق، ماذا يقتضي 19 CFR 111.29 من الوسيط فعله؟"},"o":[{"en":"Pay the funds to the Government within 5 working days from receipt","es":"Pagar los fondos al Gobierno dentro de 5 días hábiles desde su recepción","ru":"Уплатить средства Правительству в течение 5 рабочих дней с момента получения","tr":"Fonları, alındığı tarihten itibaren 5 iş günü içinde Hükümete ödemek","hi":"प्राप्ति से 5 कार्य दिवसों के भीतर सरकार को धन का भुगतान करना","ar":"دفع الأموال للحكومة خلال 5 أيام عمل من تسلّمها"},{"en":"Hold the funds for 30 days and then remit them with the next entry","es":"Conservar los fondos por 30 días y luego remitirlos con la siguiente entrada","ru":"Удерживать средства 30 дней, а затем перечислить их со следующим оформлением","tr":"Fonları 30 gün tutup ardından bir sonraki beyanla birlikte aktarmak","hi":"धन को 30 दिनों तक रखना और फिर उसे अगली एंट्री के साथ भेजना","ar":"الاحتفاظ بالأموال 30 يوماً ثم تحويلها مع الإدخال التالي"},{"en":"Return the funds to the client and instruct the client to pay CBP directly","es":"Devolver los fondos al cliente e indicarle que pague directamente a CBP","ru":"Вернуть средства клиенту и поручить клиенту уплатить CBP напрямую","tr":"Fonları müşteriye iade etmek ve müşteriye doğrudan CBP'ye ödeme yapmasını söylemek","hi":"धन ग्राहक को वापस करना और ग्राहक को सीधे CBP को भुगतान करने का निर्देश देना","ar":"إعادة الأموال إلى العميل وإرشاده إلى الدفع لـ CBP مباشرةً"},{"en":"Deposit the funds in an interest-bearing escrow account until the next quarter","es":"Depositar los fondos en una cuenta de garantía que devengue intereses hasta el siguiente trimestre","ru":"Внести средства на процентный счет условного депонирования (эскроу) до следующего квартала","tr":"Fonları bir sonraki çeyreğe kadar faiz getiren bir emanet (escrow) hesabına yatırmak","hi":"अगली तिमाही तक धन को एक ब्याज-वाले escrow खाते में जमा करना","ar":"إيداع الأموال في حساب ضمان مُدِرّ للفائدة إلى الربع التالي"}],"e":{"en":"Under 19 CFR 111.29(a), a broker must pay duties, taxes, or other debts owed to the Government on or before the due date; if the broker receives client funds after that date, it must transmit the funds to the Government within 5 working days of receipt. The broker must also advise clients that they may pay CBP directly.","es":"Conforme a 19 CFR 111.29(a), un agente debe pagar los derechos, impuestos u otras deudas adeudadas al Gobierno en o antes de la fecha de vencimiento; si el agente recibe fondos del cliente después de esa fecha, debe transmitir los fondos al Gobierno dentro de 5 días hábiles desde su recepción. El agente también debe informar a los clientes que pueden pagar directamente a CBP.","ru":"Согласно 19 CFR 111.29(a), брокер должен уплатить пошлины, налоги или иные долги перед Правительством в установленный срок или до него; если брокер получает средства клиента после этой даты, он должен перечислить средства Правительству в течение 5 рабочих дней с момента получения. Брокер также должен уведомить клиентов о том, что они могут уплатить CBP напрямую.","tr":"19 CFR 111.29(a) kapsamında, bir gümrük müşaviri, Hükümete borçlu olunan vergileri, vergileri (taxes) veya diğer borçları ödeme tarihinde veya öncesinde ödemelidir; gümrük müşaviri müşteri fonlarını bu tarihten sonra alırsa, fonları alındıktan itibaren 5 iş günü içinde Hükümete aktarmalıdır. Gümrük müşaviri ayrıca müşterilere doğrudan CBP'ye ödeme yapabileceklerini de bildirmelidir.","hi":"19 CFR 111.29(a) के तहत, एक ब्रोकर को सरकार को देय शुल्क, कर, या अन्य ऋण देय तिथि पर या उससे पहले भुगतान करना चाहिए; यदि ब्रोकर उस तारीख के बाद ग्राहक का धन प्राप्त करता है, तो उसे प्राप्ति के 5 कार्य दिवसों के भीतर सरकार को धन भेजना चाहिए। ब्रोकर को ग्राहकों को यह भी सलाह देनी चाहिए कि वे सीधे CBP को भुगतान कर सकते हैं।","ar":"بموجب 19 CFR 111.29(a)، يجب على الوسيط دفع الرسوم أو الضرائب أو غيرها من الديون المستحقة للحكومة في تاريخ الاستحقاق أو قبله؛ وإذا تلقّى الوسيط أموال العميل بعد ذلك التاريخ، وجب عليه تحويل الأموال إلى الحكومة خلال 5 أيام عمل من تسلّمها. ويجب على الوسيط أيضاً إبلاغ العملاء بأنه يجوز لهم الدفع لـ CBP مباشرةً."}},{"cat":"compliance","a":1,"q":{"en":"Each broker must file a triennial status report with CBP. Which statement correctly describes the timing and consequence rules under 19 CFR 111.30 (as modernized)?","es":"Cada agente de aduanas debe presentar un informe de estatus trienal ante CBP. ¿Qué afirmación describe correctamente las reglas de plazos y consecuencias conforme a 19 CFR 111.30 (según su modernización)?","ru":"Каждый брокер должен подавать в CBP трехлетний отчет о статусе. Какое утверждение правильно описывает правила о сроках и последствиях согласно 19 CFR 111.30 (в модернизированном виде)?","tr":"Her gümrük müşaviri, CBP'ye üç yılda bir durum raporu (triennial status report) sunmalıdır. Hangi ifade, 19 CFR 111.30 (modernize edilmiş haliyle) kapsamındaki zamanlama ve sonuç kurallarını doğru şekilde tanımlamaktadır?","hi":"प्रत्येक ब्रोकर को CBP के पास एक त्रैवार्षिक status report दाखिल करनी होती है। कौन-सा कथन 19 CFR 111.30 (आधुनिकीकृत) के तहत समय और परिणाम नियमों का सही वर्णन करता है?","ar":"يجب على كل وسيط تقديم تقرير حالة كل ثلاث سنوات إلى CBP. أي عبارة تصف بشكل صحيح قواعد التوقيت والنتائج بموجب 19 CFR 111.30 (بصيغته المحدَّثة)؟"},"o":[{"en":"The report is due July 1 of each third year, and late filing results in an automatic monetary penalty of $1,000","es":"El informe vence el July 1 de cada tercer año, y la presentación tardía resulta en una multa monetaria automática de $1,000","ru":"Отчет подается до July 1 каждого третьего года, и просрочка подачи влечет автоматический денежный штраф в размере $1,000","tr":"Rapor her üçüncü yılın 1 Temmuz'unda sunulur ve geç sunum, $1,000 tutarında otomatik bir para cezasıyla sonuçlanır","hi":"रिपोर्ट प्रत्येक तीसरे वर्ष की July 1 को देय है, और देर से दाखिल करने पर $1,000 का स्वचालित मौद्रिक जुर्माना लगता है","ar":"يُستحقّ التقرير في July 1 من كل سنة ثالثة، ويترتّب على التقديم المتأخر غرامة مالية تلقائية قدرها $1,000"},{"en":"The report is due February 1 of each third year, and failure to file by March 1 suspends the license by operation of law","es":"El informe vence el February 1 de cada tercer año, y no presentarlo antes del March 1 suspende la licencia por imperio de la ley","ru":"Отчет подается до February 1 каждого третьего года, и непредставление к March 1 приостанавливает действие лицензии в силу закона","tr":"Rapor her üçüncü yılın 1 Şubat'ında sunulur ve 1 Mart'a kadar sunulmaması lisansı kanun gereği askıya alır","hi":"रिपोर्ट प्रत्येक तीसरे वर्ष की February 1 को देय है, और March 1 तक दाखिल करने में विफलता कानून के संचालन द्वारा लाइसेंस को निलंबित कर देती है","ar":"يُستحقّ التقرير في February 1 من كل سنة ثالثة، ويؤدي عدم التقديم بحلول March 1 إلى تعليق الرخصة بحكم القانون"},{"en":"The report is due annually on the anniversary of license issuance, with a 90-day grace period","es":"El informe vence anualmente en el aniversario de la emisión de la licencia, con un período de gracia de 90 días","ru":"Отчет подается ежегодно в годовщину выдачи лицензии, с льготным периодом в 90 дней","tr":"Rapor, lisansın verildiği tarihin yıldönümünde her yıl, 90 günlük bir ek süreyle sunulur","hi":"रिपोर्ट लाइसेंस जारी होने की वर्षगांठ पर सालाना देय है, जिसमें 90-दिन की रियायत अवधि है","ar":"يُستحقّ التقرير سنوياً في ذكرى إصدار الرخصة، مع مهلة سماح قدرها 90 يوماً"},{"en":"The report is due February 1 each year, and failure to file results in immediate revocation without any opportunity for reinstatement","es":"El informe vence el February 1 de cada año, y no presentarlo resulta en revocación inmediata sin oportunidad alguna de reinstalación","ru":"Отчет подается до February 1 каждого года, и непредставление влечет немедленный отзыв без какой-либо возможности восстановления","tr":"Rapor her yıl 1 Şubat'ta sunulur ve sunulmaması, yeniden tesis imkanı olmaksızın derhal iptalle sonuçlanır","hi":"रिपोर्ट प्रत्येक वर्ष February 1 को देय है, और दाखिल करने में विफलता के परिणामस्वरूप बहाली के किसी अवसर के बिना तत्काल निरस्तीकरण होता है","ar":"يُستحقّ التقرير في February 1 كل سنة، ويؤدي عدم التقديم إلى الإلغاء الفوري دون أي فرصة لإعادة الاعتبار"}],"e":{"en":"Under 19 CFR 111.30(d), the triennial status report is due on February 1 of each third year. If a broker fails to file by March 1 of the reporting year, the license is suspended by operation of law; if the broker still has not filed and paid within 60 days of the suspension, the license is revoked by operation of law without prejudice to applying for a new one.","es":"Conforme a 19 CFR 111.30(d), el informe de estatus trienal vence el February 1 de cada tercer año. Si un agente no lo presenta antes del March 1 del año de informe, la licencia queda suspendida por imperio de la ley; si el agente aún no ha presentado y pagado dentro de los 60 días de la suspensión, la licencia se revoca por imperio de la ley sin perjuicio de poder solicitar una nueva.","ru":"Согласно 19 CFR 111.30(d), трехлетний отчет о статусе подается до February 1 каждого третьего года. Если брокер не подает отчет к March 1 отчетного года, действие лицензии приостанавливается в силу закона; если брокер по-прежнему не подал отчет и не уплатил в течение 60 дней с момента приостановления, лицензия отзывается в силу закона без ущерба для права подать заявление на новую.","tr":"19 CFR 111.30(d) kapsamında, üç yılda bir durum raporu (triennial status report) her üçüncü yılın 1 Şubat'ında sunulur. Bir gümrük müşaviri raporlama yılının 1 Mart'ına kadar sunmazsa, lisans kanun gereği (by operation of law) askıya alınır; gümrük müşaviri askıdan itibaren 60 gün içinde hâlâ sunmamış ve ödememişse, lisans, yeni bir lisans için başvurma hakkına halel gelmeksizin kanun gereği iptal edilir.","hi":"19 CFR 111.30(d) के तहत, त्रैवार्षिक status report प्रत्येक तीसरे वर्ष की February 1 को देय है। यदि एक ब्रोकर रिपोर्टिंग वर्ष की March 1 तक दाखिल करने में विफल रहता है, तो लाइसेंस कानून के संचालन द्वारा निलंबित हो जाता है; यदि ब्रोकर अभी भी निलंबन के 60 दिनों के भीतर दाखिल और भुगतान नहीं करता है, तो लाइसेंस कानून के संचालन द्वारा निरस्त हो जाता है, बिना नए के लिए आवेदन करने में पूर्वाग्रह के।","ar":"بموجب 19 CFR 111.30(d)، يُستحقّ تقرير الحالة الذي يُقدَّم كل ثلاث سنوات في February 1 من كل سنة ثالثة. وإذا تخلّف الوسيط عن التقديم بحلول March 1 من سنة الإبلاغ، تُعلَّق الرخصة بحكم القانون؛ وإذا ظلّ الوسيط دون تقديم ودفع خلال 60 يوماً من التعليق، تُلغى الرخصة بحكم القانون دون المساس بحق التقدّم لرخصة جديدة."}},{"cat":"compliance","a":1,"q":{"en":"What is the maximum aggregate monetary penalty that may be assessed against a licensed broker under 19 CFR 111.91 for one or more of the grounds listed in 19 CFR 111.53(a) through (g)?","es":"¿Cuál es la multa monetaria agregada máxima que puede imponerse a un agente de aduanas con licencia conforme a 19 CFR 111.91 por uno o más de los motivos enumerados en 19 CFR 111.53(a) a (g)?","ru":"Каков максимальный совокупный денежный штраф, который может быть наложен на лицензированного брокера согласно 19 CFR 111.91 за одно или несколько оснований, перечисленных в 19 CFR 111.53(a)–(g)?","tr":"19 CFR 111.53(a) ila (g)'de sıralanan gerekçelerden biri veya birkaçı nedeniyle, 19 CFR 111.91 kapsamında lisanslı bir gümrük müşavirine uygulanabilecek azami toplam para cezası nedir?","hi":"19 CFR 111.53(a) से (g) में सूचीबद्ध एक या अधिक आधारों के लिए 19 CFR 111.91 के तहत एक लाइसेंस-प्राप्त ब्रोकर पर लगाया जा सकने वाला अधिकतम कुल मौद्रिक जुर्माना क्या है?","ar":"ما الحد الأقصى للغرامة المالية الإجمالية التي يجوز فرضها على وسيط مرخَّص بموجب 19 CFR 111.91 عن سبب أو أكثر من الأسباب المدرجة في 19 CFR 111.53(a) إلى (g)؟"},"o":[{"en":"$10,000","es":"$10,000","ru":"$10,000","tr":"$10,000","hi":"$10,000","ar":"$10,000"},{"en":"$30,000","es":"$30,000","ru":"$30,000","tr":"$30,000","hi":"$30,000","ar":"$30,000"},{"en":"$100,000","es":"$100,000","ru":"$100,000","tr":"$100,000","hi":"$100,000","ar":"$100,000"},{"en":"An amount equal to twice the duties lost to the Government","es":"Un monto igual al doble de los derechos perdidos por el Gobierno","ru":"Сумма, равная двойному размеру пошлин, потерянных Правительством","tr":"Hükümetin kaybettiği vergilerin iki katına eşit bir tutar","hi":"सरकार को हुई शुल्क हानि के दोगुने के बराबर राशि","ar":"مبلغ يعادل ضعف الرسوم التي خسرتها الحكومة"}],"e":{"en":"Under 19 CFR 111.91(a), a broker may be assessed a monetary penalty in an amount not to exceed an aggregate of $30,000 for one or more of the reasons set forth in 19 CFR 111.53(a) through (g). A non-broker faces up to $10,000 per transaction (also capped at a $30,000 aggregate). There is no twice-the-duties formula in this section.","es":"Conforme a 19 CFR 111.91(a), a un agente puede imponérsele una multa monetaria por un monto que no exceda un agregado de $30,000 por uno o más de los motivos establecidos en 19 CFR 111.53(a) a (g). Una persona que no sea agente enfrenta hasta $10,000 por transacción (también con tope de $30,000 agregados). No existe una fórmula del doble de los derechos en esta sección.","ru":"Согласно 19 CFR 111.91(a), на брокера может быть наложен денежный штраф в размере, не превышающем в совокупности $30,000 за одну или несколько причин, изложенных в 19 CFR 111.53(a)–(g). Не-брокеру грозит до $10,000 за сделку (также с совокупным потолком $30,000). В данном разделе нет формулы двойного размера пошлин.","tr":"19 CFR 111.91(a) kapsamında, bir gümrük müşavirine, 19 CFR 111.53(a) ila (g)'de belirtilen nedenlerden biri veya birkaçı için toplam $30,000'i aşmayan bir tutarda para cezası uygulanabilir. Gümrük müşaviri olmayan bir kişi, işlem başına $10,000'e kadar (yine $30,000'lik toplamla sınırlı) ceza ile karşı karşıyadır. Bu bölümde vergilerin iki katı şeklinde bir formül yoktur.","hi":"19 CFR 111.91(a) के तहत, 19 CFR 111.53(a) से (g) में निर्धारित एक या अधिक कारणों के लिए एक ब्रोकर पर कुल $30,000 से अधिक नहीं की राशि का मौद्रिक जुर्माना लगाया जा सकता है। एक गैर-ब्रोकर को प्रति लेनदेन $10,000 तक का सामना करना पड़ता है (कुल $30,000 पर भी सीमित)। इस खंड में शुल्क-के-दोगुने का कोई सूत्र नहीं है।","ar":"بموجب 19 CFR 111.91(a)، يجوز فرض غرامة مالية على الوسيط بمبلغ لا يتجاوز إجمالاً ‎$30,000‎ عن سبب أو أكثر من الأسباب المبيّنة في 19 CFR 111.53(a) إلى (g). أما غير الوسيط فيواجه ما يصل إلى ‎$10,000‎ لكل معاملة (وبحد أقصى إجمالي قدره ‎$30,000‎ أيضاً). ولا توجد صيغة ضعف الرسوم في هذا القسم."}},{"cat":"compliance","a":1,"q":{"en":"Which of the following is an enumerated ground on which CBP may suspend or revoke a customs broker's license or permit under 19 CFR 111.53?","es":"¿Cuál de los siguientes es un motivo enumerado por el cual CBP puede suspender o revocar la licencia o permiso de un agente de aduanas conforme a 19 CFR 111.53?","ru":"Что из перечисленного является прямо указанным основанием, по которому CBP может приостановить или отозвать лицензию или разрешение таможенного брокера согласно 19 CFR 111.53?","tr":"Aşağıdakilerden hangisi, CBP'nin 19 CFR 111.53 kapsamında bir gümrük müşavirinin lisansını veya iznini askıya alabileceği veya iptal edebileceği sayılı gerekçelerden biridir?","hi":"निम्नलिखित में से कौन-सा एक गणित आधार है जिस पर CBP 19 CFR 111.53 के तहत एक customs broker के लाइसेंस या permit को निलंबित या निरस्त कर सकता है?","ar":"أي مما يلي يُعدّ سبباً منصوصاً عليه يجوز بموجبه لـ CBP تعليق أو إلغاء رخصة وسيط جمركي أو تصريحه بموجب 19 CFR 111.53؟"},"o":[{"en":"Charging a client a fee that exceeds the broker's published rate schedule","es":"Cobrarle a un cliente una tarifa que excede el listado de tarifas publicado del agente","ru":"Взимание с клиента платы, превышающей опубликованный тарифный перечень брокера","tr":"Bir müşteriye, gümrük müşavirinin yayımlanmış fiyat tarifesini aşan bir ücret talep etmek","hi":"किसी ग्राहक से ऐसी फीस वसूलना जो ब्रोकर की प्रकाशित दर अनुसूची से अधिक हो","ar":"تقاضي رسم من عميل يتجاوز جدول الأسعار المنشور للوسيط"},{"en":"Knowingly employing a person convicted of a felony without written approval from CBP","es":"Emplear a sabiendas a una persona condenada por un delito grave sin la aprobación escrita de CBP","ru":"Заведомый наем лица, осужденного за тяжкое преступление (felony), без письменного одобрения CBP","tr":"CBP'nin yazılı onayı olmadan, bir suçtan (felony) mahkûm olmuş bir kişiyi bilerek istihdam etmek","hi":"CBP से लिखित अनुमोदन के बिना किसी अपराध (felony) के दोषी व्यक्ति को जानबूझकर नियोजित करना","ar":"تشغيل شخص أُدين بجناية عن علم دون موافقة كتابية من CBP"},{"en":"Filing an entry summary more than five business days after the merchandise is released","es":"Presentar un resumen de entrada más de cinco días hábiles después de que se libera la mercancía","ru":"Подача итоговой декларации (entry summary) более чем через пять рабочих дней после выпуска товаров","tr":"Malların serbest bırakılmasından beş iş gününden fazla süre sonra bir entry summary sunmak","hi":"माल जारी होने के पाँच कार्य दिवसों से अधिक बाद एक entry summary दाखिल करना","ar":"تقديم بيان إدخال بعد أكثر من خمسة أيام عمل من الإفراج عن البضاعة"},{"en":"Maintaining a single national permit instead of separate district permits","es":"Mantener un único permiso nacional en lugar de permisos de distrito separados","ru":"Наличие единого национального разрешения вместо отдельных окружных разрешений","tr":"Ayrı bölge (district) izinleri yerine tek bir ulusal izin (national permit) bulundurmak","hi":"अलग district permits के बजाय एक एकल national permit बनाए रखना","ar":"الاحتفاظ بتصريح وطني واحد بدلاً من تصاريح مناطق منفصلة"}],"e":{"en":"Under 19 CFR 111.53(e), knowingly employing, or continuing to employ, a person convicted of a felony without CBP's written approval is a ground for suspension or revocation. Other grounds include false material statements, certain criminal convictions, violating CBP laws, aiding violations, and defrauding clients. The other options are not enumerated 111.53 grounds, and a single national permit is the current norm.","es":"Conforme a 19 CFR 111.53(e), emplear a sabiendas, o continuar empleando, a una persona condenada por un delito grave sin la aprobación escrita de CBP es un motivo de suspensión o revocación. Otros motivos incluyen declaraciones materiales falsas, ciertas condenas penales, infringir las leyes de CBP, ayudar a infracciones y defraudar a los clientes. Las demás opciones no son motivos enumerados en 111.53, y un único permiso nacional es la norma actual.","ru":"Согласно 19 CFR 111.53(e), заведомый наем или продолжение найма лица, осужденного за тяжкое преступление (felony), без письменного одобрения CBP является основанием для приостановления или отзыва. Другие основания включают ложные существенные заявления, определенные уголовные судимости, нарушение законов CBP, содействие нарушениям и обман клиентов. Остальные варианты не являются прямо указанными основаниями 111.53, а единое национальное разрешение является текущей нормой.","tr":"19 CFR 111.53(e) kapsamında, bir suçtan (felony) mahkûm olmuş bir kişiyi CBP'nin yazılı onayı olmadan bilerek istihdam etmek veya istihdam etmeye devam etmek, askıya alma veya iptal için bir gerekçedir. Diğer gerekçeler arasında esaslı yanlış beyanlar, belirli cezai mahkumiyetler, CBP yasalarını ihlal etmek, ihlallere yardım etmek ve müşterileri dolandırmak yer alır. Diğer seçenekler 111.53'te sayılı gerekçeler değildir ve tek bir ulusal izin mevcut normdur.","hi":"19 CFR 111.53(e) के तहत, CBP के लिखित अनुमोदन के बिना किसी अपराध (felony) के दोषी व्यक्ति को जानबूझकर नियोजित करना, या नियोजित रखना, निलंबन या निरस्तीकरण का एक आधार है। अन्य आधारों में झूठे भौतिक बयान, कुछ आपराधिक दोषसिद्धियाँ, CBP कानूनों का उल्लंघन, उल्लंघनों में सहायता, और ग्राहकों को धोखा देना शामिल हैं। अन्य विकल्प 111.53 के गणित आधार नहीं हैं, और एक एकल national permit वर्तमान मानदंड है।","ar":"بموجب 19 CFR 111.53(e)، يُعدّ تشغيل شخص أُدين بجناية، أو الاستمرار في تشغيله، عن علم ودون موافقة كتابية من CBP، سبباً للتعليق أو الإلغاء. وتشمل أسباباً أخرى البيانات الجوهرية الكاذبة، وبعض الإدانات الجنائية، ومخالفة قوانين CBP، والمساعدة على المخالفات، والاحتيال على العملاء. أما الخيارات الأخرى فليست أسباباً منصوصاً عليها في 111.53، والتصريح الوطني الواحد هو المعتمَد حالياً."}},{"cat":"trade","a":1,"q":{"en":"An importer brings in unmarked aluminum sheet that a U.S. fabricator will cut and form into finished window frames having a new name, character, and use before retail sale. Under the marking regulations, who is treated as the ultimate purchaser of the imported aluminum sheet, and what marking is required?","es":"Un importador trae lámina de aluminio sin marcar que un fabricante estadounidense cortará y conformará en marcos de ventana terminados que tendrán un nuevo nombre, carácter y uso antes de la venta minorista. Conforme a la normativa de marcado, ¿quién es considerado el comprador final de la lámina de aluminio importada, y qué marcado se requiere?","ru":"Импортер ввозит немаркированный алюминиевый лист, который американский производитель будет резать и формовать в готовые оконные рамы с новым наименованием, характером и назначением до розничной продажи. Согласно правилам маркировки, кто рассматривается как конечный покупатель импортированного алюминиевого листа, и какая маркировка требуется?","tr":"Bir ithalatçı, bir ABD imalatçısının perakende satıştan önce kesip şekillendirerek yeni bir isim, karakter ve kullanıma sahip bitmiş pencere çerçevelerine dönüştüreceği işaretsiz alüminyum levha getiriyor. İşaretleme düzenlemeleri kapsamında, ithal edilen alüminyum levhanın nihai alıcısı (ultimate purchaser) kim olarak kabul edilir ve hangi işaretleme gereklidir?","hi":"एक आयातकर्ता बिना अंकन वाली aluminum sheet लाता है जिसे एक U.S. fabricator खुदरा बिक्री से पहले काटकर और आकार देकर एक नए नाम, चरित्र और उपयोग वाले तैयार window frames में बदल देगा। अंकन नियमों के तहत, आयातित aluminum sheet का ultimate purchaser किसे माना जाता है, और कौन-सा अंकन आवश्यक है?","ar":"يستورد مستورد ألواح ألمنيوم غير موسومة سيقوم مصنّع أمريكي بقطعها وتشكيلها إلى إطارات نوافذ مكتملة لها اسم وطابع واستخدام جديدة قبل البيع بالتجزئة. بموجب لوائح الوسم، من يُعامَل بوصفه المشتري النهائي لألواح الألمنيوم المستورَدة، وما الوسم المطلوب؟"},"o":[{"en":"The retail consumer is the ultimate purchaser, so each finished window frame must be individually marked with the country of origin of the aluminum.","es":"El consumidor minorista es el comprador final, por lo que cada marco de ventana terminado debe marcarse individualmente con el país de origen del aluminio.","ru":"Конечным покупателем является розничный потребитель, поэтому каждая готовая оконная рама должна быть индивидуально маркирована страной происхождения алюминия.","tr":"Nihai alıcı perakende tüketicidir, dolayısıyla her bitmiş pencere çerçevesi, alüminyumun menşe ülkesi (country of origin) ile ayrı ayrı işaretlenmelidir.","hi":"खुदरा उपभोक्ता ultimate purchaser है, इसलिए प्रत्येक तैयार window frame को aluminum के मूल देश के साथ व्यक्तिगत रूप से अंकित किया जाना चाहिए।","ar":"المستهلك بالتجزئة هو المشتري النهائي، لذا يجب وسم كل إطار نافذة مكتمل بشكل فردي ببلد منشأ الألمنيوم."},{"en":"The U.S. fabricator is the ultimate purchaser; the imported sheet need not be individually marked, but the outermost containers in which it is imported must be marked.","es":"El fabricante estadounidense es el comprador final; la lámina importada no necesita marcarse individualmente, pero los contenedores más externos en los que se importa deben marcarse.","ru":"Конечным покупателем является американский производитель; импортированный лист не обязательно маркировать индивидуально, но внешние контейнеры, в которых он импортируется, должны быть маркированы.","tr":"ABD imalatçısı nihai alıcıdır; ithal edilen levhanın ayrı ayrı işaretlenmesi gerekmez, ancak içinde ithal edildiği en dıştaki kaplar işaretlenmelidir.","hi":"U.S. fabricator ultimate purchaser है; आयातित sheet को व्यक्तिगत रूप से अंकित करने की आवश्यकता नहीं है, लेकिन जिन सबसे बाहरी कंटेनरों में इसे आयात किया जाता है उन्हें अंकित किया जाना चाहिए।","ar":"المصنّع الأمريكي هو المشتري النهائي؛ فلا يلزم وسم الألواح المستورَدة بشكل فردي، لكن يجب وسم الحاويات الخارجية التي تُستورَد فيها."},{"en":"The importer is the ultimate purchaser, and no marking of any kind is required because the goods are not for resale in their imported form.","es":"El importador es el comprador final, y no se requiere marcado de ningún tipo porque las mercancías no son para reventa en su forma importada.","ru":"Конечным покупателем является импортер, и никакой маркировки не требуется, поскольку товары не предназначены для перепродажи в их импортированном виде.","tr":"İthalatçı nihai alıcıdır ve mallar ithal edildikleri haliyle yeniden satış için olmadığından hiçbir şekilde işaretleme gerekmez.","hi":"आयातकर्ता ultimate purchaser है, और किसी भी प्रकार के अंकन की आवश्यकता नहीं है क्योंकि माल अपने आयातित रूप में पुनर्विक्रय के लिए नहीं है।","ar":"المستورد هو المشتري النهائي، ولا يلزم أي وسم لأن البضائع ليست للبيع بصيغتها المستورَدة."},{"en":"CBP is the ultimate purchaser, so the goods may be released only after a marking duty of 10 percent is paid.","es":"CBP es el comprador final, por lo que las mercancías pueden liberarse solo después de pagar un derecho de marcado del 10 por ciento.","ru":"Конечным покупателем является CBP, поэтому товары могут быть выпущены только после уплаты маркировочной пошлины в размере 10 процентов.","tr":"Nihai alıcı CBP'dir, dolayısıyla mallar ancak yüzde 10'luk bir işaretleme vergisi ödendikten sonra serbest bırakılabilir.","hi":"CBP ultimate purchaser है, इसलिए माल केवल 10 प्रतिशत के marking duty का भुगतान करने के बाद ही जारी किया जा सकता है।","ar":"CBP هي المشتري النهائي، فلا يجوز الإفراج عن البضائع إلا بعد دفع رسم وسم قدره 10 بالمئة."}],"e":{"en":"Under 19 CFR 134.35, when an imported article is substantially transformed in the U.S. into an article with a new name, character, or use, the U.S. manufacturer/processor is the ultimate purchaser. The transformed article need not be individually marked, but the outermost containers of the imported articles must be marked (per 19 CFR 134.35 and the ultimate-purchaser definition in 19 CFR 134.1).","es":"Conforme a 19 CFR 134.35, cuando un artículo importado se transforma sustancialmente en Estados Unidos en un artículo con un nuevo nombre, carácter o uso, el fabricante/procesador estadounidense es el comprador final. El artículo transformado no necesita marcarse individualmente, pero los contenedores más externos de los artículos importados deben marcarse (según 19 CFR 134.35 y la definición de comprador final en 19 CFR 134.1).","ru":"Согласно 19 CFR 134.35, когда импортированное изделие подвергается существенной трансформации (substantial transformation) в США в изделие с новым наименованием, характером или назначением, конечным покупателем является американский производитель/переработчик. Трансформированное изделие не обязательно маркировать индивидуально, но внешние контейнеры импортированных изделий должны быть маркированы (согласно 19 CFR 134.35 и определению конечного покупателя в 19 CFR 134.1).","tr":"19 CFR 134.35 kapsamında, ithal edilen bir ürün ABD'de yeni bir isim, karakter veya kullanıma sahip bir ürüne esaslı şekilde dönüştürüldüğünde (substantially transformed), ABD imalatçısı/işleyicisi nihai alıcıdır (ultimate purchaser). Dönüştürülen ürünün ayrı ayrı işaretlenmesi gerekmez, ancak ithal edilen ürünlerin en dıştaki kapları işaretlenmelidir (19 CFR 134.35 ve 19 CFR 134.1'deki nihai alıcı tanımı uyarınca).","hi":"19 CFR 134.35 के तहत, जब एक आयातित वस्तु को U.S. में पर्याप्त रूप से रूपांतरित (substantially transformed) करके एक नए नाम, चरित्र, या उपयोग वाली वस्तु में बदल दिया जाता है, तो U.S. निर्माता/प्रोसेसर ultimate purchaser होता है। रूपांतरित वस्तु को व्यक्तिगत रूप से अंकित करने की आवश्यकता नहीं है, लेकिन आयातित वस्तुओं के सबसे बाहरी कंटेनरों को अंकित किया जाना चाहिए (19 CFR 134.35 और 19 CFR 134.1 में ultimate-purchaser की परिभाषा के अनुसार)।","ar":"بموجب 19 CFR 134.35، عندما تخضع مادة مستورَدة لتحوّل جوهري في الولايات المتحدة إلى مادة لها اسم أو طابع أو استخدام جديد، يكون المصنّع/المعالِج الأمريكي هو المشتري النهائي. ولا يلزم وسم المادة المتحوّلة بشكل فردي، لكن يجب وسم الحاويات الخارجية للمواد المستورَدة (وفق 19 CFR 134.35 وتعريف المشتري النهائي في 19 CFR 134.1)."}},{"cat":"trade","a":3,"q":{"en":"Imported articles arrive that were not legibly marked with the country of origin at the time of importation. The importer does not export, destroy, or properly mark the goods under CBP supervision before liquidation. What is the consequence under 19 U.S.C. 1304 / 19 CFR Part 134?","es":"Llegan artículos importados que no estaban marcados de forma legible con el país de origen al momento de la importación. El importador no exporta, destruye ni marca debidamente las mercancías bajo supervisión de CBP antes de la liquidación. ¿Cuál es la consecuencia conforme a 19 U.S.C. 1304 / 19 CFR Part 134?","ru":"Прибывают импортированные изделия, которые на момент импорта не были разборчиво маркированы страной происхождения. Импортер не экспортирует, не уничтожает и не маркирует надлежащим образом товары под надзором CBP до ликвидации. Каковы последствия согласно 19 U.S.C. 1304 / 19 CFR Part 134?","tr":"İthalat anında menşe ülkesi (country of origin) ile okunaklı şekilde işaretlenmemiş ithal mallar geliyor. İthalatçı, malları kesinleştirme (likidasyon) öncesinde CBP gözetimi altında ihraç etmiyor, imha etmiyor veya uygun şekilde işaretlemiyor. 19 U.S.C. 1304 / 19 CFR Part 134 kapsamında sonuç nedir?","hi":"ऐसी आयातित वस्तुएँ पहुँचती हैं जो आयात के समय मूल देश के साथ सुपाठ्य रूप से अंकित नहीं थीं। आयातकर्ता परिसमापन से पहले CBP की देखरेख में माल को निर्यात, नष्ट, या ठीक से अंकित नहीं करता। 19 U.S.C. 1304 / 19 CFR Part 134 के तहत क्या परिणाम होता है?","ar":"تصل مواد مستورَدة لم تكن موسومة بوضوح ببلد المنشأ وقت الاستيراد. ولا يقوم المستورد بتصدير البضائع أو إتلافها أو وسمها على نحو سليم تحت إشراف CBP قبل التصفية. ما العاقبة بموجب 19 U.S.C. 1304 / 19 CFR Part 134؟"},"o":[{"en":"The goods are automatically seized and forfeited as a prohibited importation.","es":"Las mercancías se incautan y decomisan automáticamente como una importación prohibida.","ru":"Товары автоматически изымаются и конфискуются как запрещенный к ввозу импорт.","tr":"Mallar, yasak bir ithalat olarak otomatik olarak el konulur ve müsadere edilir.","hi":"माल को एक निषिद्ध आयात के रूप में स्वचालित रूप से जब्त और जब्ती (forfeit) कर लिया जाता है।","ar":"تُضبَط البضائع وتُصادَر تلقائياً بوصفها استيراداً محظوراً."},{"en":"A flat penalty equal to twice the appraised value is assessed as a section 592 penalty.","es":"Se impone una multa fija igual al doble del valor avaluado como una multa de la section 592.","ru":"Налагается фиксированный штраф, равный двойной оцененной стоимости, как штраф по разделу 592.","tr":"section 592 cezası olarak, takdir edilen değerin iki katına eşit sabit bir ceza tahakkuk ettirilir.","hi":"मूल्यांकित मूल्य के दोगुने के बराबर एक समान जुर्माना एक section 592 जुर्माने के रूप में लगाया जाता है।","ar":"تُفرض غرامة ثابتة تعادل ضعف القيمة المقدَّرة بوصفها غرامة section 592."},{"en":"The entry is rejected and the merchandise must be returned to the country of export within 15 days.","es":"La entrada se rechaza y la mercancía debe devolverse al país de exportación dentro de 15 días.","ru":"Оформление отклоняется, и товары должны быть возвращены в страну экспорта в течение 15 дней.","tr":"Beyan reddedilir ve mallar 15 gün içinde ihracat ülkesine iade edilmelidir.","hi":"एंट्री को अस्वीकार कर दिया जाता है और माल को 15 दिनों के भीतर निर्यात के देश में वापस किया जाना चाहिए।","ar":"يُرفَض الإدخال ويجب إعادة البضاعة إلى بلد التصدير خلال 15 يوماً."},{"en":"A marking duty of 10 percent ad valorem is assessed in addition to any other applicable duty.","es":"Se impone un derecho de marcado del 10 por ciento ad valorem adicional a cualquier otro derecho aplicable.","ru":"Налагается маркировочная пошлина в размере 10 процентов адвалорно в дополнение к любой другой применимой пошлине.","tr":"Diğer uygulanabilir vergilere ek olarak yüzde 10 ad valorem işaretleme vergisi tahakkuk ettirilir.","hi":"किसी भी अन्य लागू शुल्क के अतिरिक्त 10 प्रतिशत ad valorem का एक marking duty लगाया जाता है।","ar":"يُفرَض رسم وسم قيمي قدره 10 بالمئة إضافةً إلى أي رسم آخر مطبّق."}],"e":{"en":"Under 19 U.S.C. 1304(i) and 19 CFR 134.2, articles not properly marked at importation that are not exported, destroyed, or marked under CBP supervision prior to liquidation are subject to a marking duty of 10 percent ad valorem, in addition to any other duty. This is a special marking duty, not a 592 penalty or seizure.","es":"Conforme a 19 U.S.C. 1304(i) y 19 CFR 134.2, los artículos que no están debidamente marcados al momento de la importación y que no se exportan, destruyen ni marcan bajo supervisión de CBP antes de la liquidación están sujetos a un derecho de marcado del 10 por ciento ad valorem, adicional a cualquier otro derecho. Este es un derecho especial de marcado, no una multa de la 592 ni una incautación.","ru":"Согласно 19 U.S.C. 1304(i) и 19 CFR 134.2, изделия, не маркированные надлежащим образом при импорте, которые не были экспортированы, уничтожены или маркированы под надзором CBP до ликвидации, подлежат маркировочной пошлине в размере 10 процентов адвалорно, в дополнение к любой другой пошлине. Это специальная маркировочная пошлина, а не штраф по разделу 592 и не изъятие.","tr":"19 U.S.C. 1304(i) ve 19 CFR 134.2 kapsamında, ithalat anında uygun şekilde işaretlenmemiş ve kesinleştirme (likidasyon) öncesinde CBP gözetimi altında ihraç edilmeyen, imha edilmeyen veya işaretlenmeyen ürünler, diğer herhangi bir vergiye ek olarak yüzde 10 ad valorem işaretleme vergisine tabidir. Bu özel bir işaretleme vergisidir, 592 cezası veya el koyma değildir.","hi":"19 U.S.C. 1304(i) और 19 CFR 134.2 के तहत, आयात के समय ठीक से अंकित न की गई वस्तुएँ जिन्हें परिसमापन से पहले CBP की देखरेख में निर्यात, नष्ट, या अंकित नहीं किया जाता, किसी भी अन्य शुल्क के अतिरिक्त 10 प्रतिशत ad valorem के marking duty के अधीन हैं। यह एक विशेष marking duty है, न कि 592 जुर्माना या जब्ती।","ar":"بموجب 19 U.S.C. 1304(i) و19 CFR 134.2، تخضع المواد غير الموسومة على نحو سليم عند الاستيراد، والتي لا تُصدَّر أو تُتلَف أو تُوسَم تحت إشراف CBP قبل التصفية، لرسم وسم قيمي قدره 10 بالمئة، إضافةً إلى أي رسم آخر. وهذا رسم وسم خاص، وليس غرامة 592 أو ضبطاً."}},{"cat":"trade","a":2,"q":{"en":"Which of the following articles falls under the J-list (19 CFR 134.33) and is therefore excepted from individual country-of-origin marking, with only its outermost container required to be marked?","es":"¿Cuál de los siguientes artículos cae bajo la J-list (19 CFR 134.33) y por lo tanto está exceptuado del marcado individual de país de origen, requiriéndose marcar solo su contenedor más externo?","ru":"Что из перечисленного подпадает под J-list (19 CFR 134.33) и потому исключается из индивидуальной маркировки страной происхождения, при этом маркировке подлежит только его внешний контейнер?","tr":"Aşağıdaki ürünlerden hangisi J-list'in (19 CFR 134.33) kapsamına girer ve bu nedenle ayrı menşe ülkesi (country of origin) işaretlemesinden muaftır; yalnızca en dıştaki kabının işaretlenmesi gerekir?","hi":"निम्नलिखित में से कौन-सी वस्तु J-list (19 CFR 134.33) के अंतर्गत आती है और इसलिए व्यक्तिगत मूल-देश अंकन से छूट प्राप्त है, जिसमें केवल इसके सबसे बाहरी कंटेनर को अंकित करना आवश्यक है?","ar":"أي من المواد التالية يقع ضمن J-list (19 CFR 134.33) ويكون بذلك مستثنى من وسم بلد المنشأ الفردي، مع الاكتفاء بوسم حاويته الخارجية؟"},"o":[{"en":"A pair of imported leather shoes sold at retail in a labeled box.","es":"Un par de zapatos de cuero importados vendidos al menudeo en una caja etiquetada.","ru":"Пара импортированных кожаных туфель, продаваемых в розницу в маркированной коробке.","tr":"Etiketli bir kutuda perakende satılan ithal bir çift deri ayakkabı.","hi":"एक लेबल वाले डिब्बे में खुदरा बिक्री में बेचे गए आयातित चमड़े के जूतों की एक जोड़ी।","ar":"زوج من الأحذية الجلدية المستورَدة يُباع بالتجزئة في علبة موسومة."},{"en":"An imported wristwatch movement assembled abroad.","es":"Un movimiento de reloj de pulsera importado ensamblado en el extranjero.","ru":"Импортированный часовой механизм, собранный за рубежом.","tr":"Yurt dışında monte edilmiş ithal bir kol saati mekanizması.","hi":"विदेश में असेंबल किया गया एक आयातित wristwatch movement।","ar":"حركة ساعة يد مستورَدة مجمَّعة في الخارج."},{"en":"Imported screws (nuts and bolts) of a type listed on the J-list.","es":"Tornillos importados (tuercas y pernos) de un tipo listado en la J-list.","ru":"Импортированные винты (гайки и болты) того типа, что указан в J-list.","tr":"J-list'te listelenen türden ithal vidalar (somunlar ve cıvatalar).","hi":"J-list पर सूचीबद्ध प्रकार के आयातित screws (nuts और bolts)।","ar":"براغي مستورَدة (صواميل ومسامير ملولبة) من النوع المدرَج على J-list."},{"en":"An imported electric motor incorporated into a U.S.-assembled appliance.","es":"Un motor eléctrico importado incorporado a un electrodoméstico ensamblado en Estados Unidos.","ru":"Импортированный электродвигатель, встроенный в собранный в США бытовой прибор.","tr":"ABD'de monte edilen bir cihaza dahil edilmiş ithal bir elektrik motoru.","hi":"एक U.S.-असेंबल किए गए उपकरण में शामिल एक आयातित electric motor।","ar":"محرك كهربائي مستورَد مُدمَج في جهاز مجمَّع في الولايات المتحدة."}],"e":{"en":"The J-list in 19 CFR 134.33 enumerates articles that are excepted from individual marking (Customs has determined marking is impracticable or the article is of a class historically exempt), such as screws, nuts, bolts, eggs, and similar items. Only the containers reaching the ultimate purchaser must be marked. Shoes and watch movements are not J-list exceptions.","es":"La J-list en 19 CFR 134.33 enumera artículos que están exceptuados del marcado individual (Customs ha determinado que el marcado es impracticable o que el artículo pertenece a una clase históricamente exenta), tales como tornillos, tuercas, pernos, huevos y artículos similares. Solo los contenedores que llegan al comprador final deben marcarse. Los zapatos y los movimientos de reloj no son excepciones de la J-list.","ru":"J-list в 19 CFR 134.33 перечисляет изделия, исключенные из индивидуальной маркировки (Таможня определила, что маркировка нецелесообразна или изделие относится к категории, исторически освобожденной), такие как винты, гайки, болты, яйца и подобные предметы. Маркировке подлежат только контейнеры, доходящие до конечного покупателя. Туфли и часовые механизмы не являются исключениями J-list.","tr":"19 CFR 134.33'teki J-list, ayrı işaretlemeden muaf tutulan ürünleri (Gümrük, işaretlemenin pratik olmadığını veya ürünün tarihsel olarak muaf bir sınıfa ait olduğunu belirlemiştir) sıralar; bunlar arasında vidalar, somunlar, cıvatalar, yumurtalar ve benzeri kalemler bulunur. Yalnızca nihai alıcıya ulaşan kapların işaretlenmesi gerekir. Ayakkabılar ve saat mekanizmaları J-list istisnaları değildir.","hi":"19 CFR 134.33 में J-list उन वस्तुओं को सूचीबद्ध करती है जिन्हें व्यक्तिगत अंकन से छूट प्राप्त है (Customs ने निर्धारित किया है कि अंकन अव्यावहारिक है या वस्तु एक ऐसी श्रेणी की है जो ऐतिहासिक रूप से छूट प्राप्त है), जैसे screws, nuts, bolts, अंडे, और इसी तरह की वस्तुएँ। केवल ultimate purchaser तक पहुँचने वाले कंटेनरों को अंकित किया जाना चाहिए। जूते और watch movements J-list अपवाद नहीं हैं।","ar":"تعدّد J-list في 19 CFR 134.33 المواد المستثناة من الوسم الفردي (حيث قرّرت الجمارك أن الوسم غير عملي أو أن المادة من فئة معفاة تاريخياً)، مثل البراغي والصواميل والمسامير الملولبة والبيض وما شابهها. ولا يلزم وسم سوى الحاويات التي تصل إلى المشتري النهائي. أما الأحذية وحركات الساعات فليست من استثناءات J-list."}},{"cat":"trade","a":1,"q":{"en":"An importer wishes to claim USMCA preferential tariff treatment for goods imported from Mexico. Regarding the certification of origin under 19 CFR Part 182, which statement is correct?","es":"Un importador desea reclamar trato arancelario preferencial bajo el USMCA para mercancías importadas de México. Respecto a la certificación de origen conforme a 19 CFR Part 182, ¿qué afirmación es correcta?","ru":"Импортер желает заявить преференциальный тарифный режим USMCA для товаров, импортируемых из Мексики. Относительно сертификата происхождения согласно 19 CFR Part 182, какое утверждение верно?","tr":"Bir ithalatçı, Meksika'dan ithal edilen mallar için USMCA tercihli tarife muamelesi talep etmek istiyor. 19 CFR Part 182 kapsamında menşe sertifikasyonu (certification of origin) ile ilgili olarak hangi ifade doğrudur?","hi":"एक आयातकर्ता Mexico से आयातित माल के लिए USMCA अधिमान्य टैरिफ उपचार का दावा करना चाहता है। 19 CFR Part 182 के तहत certification of origin के संबंध में, कौन-सा कथन सही है?","ar":"يرغب مستورد في المطالبة بالمعاملة التعريفية التفضيلية بموجب USMCA لبضائع مستورَدة من المكسيك. فيما يتعلق بشهادة المنشأ بموجب 19 CFR Part 182، أي عبارة صحيحة؟"},"o":[{"en":"The certification must be made on CBP Form 434 and may be completed only by the exporter or producer.","es":"La certificación debe hacerse en el CBP Form 434 y solo puede completarla el exportador o el productor.","ru":"Сертификация должна оформляться на CBP Form 434 и может быть заполнена только экспортером или производителем.","tr":"Sertifikasyon CBP Form 434 üzerinde yapılmalıdır ve yalnızca ihracatçı veya üretici tarafından tamamlanabilir.","hi":"certification CBP Form 434 पर की जानी चाहिए और केवल exporter या producer द्वारा ही पूरी की जा सकती है।","ar":"يجب إعداد الشهادة على CBP Form 434 ولا يجوز إكمالها إلا من المصدّر أو المنتج."},{"en":"The certification need not be in a prescribed format and may be completed by the importer, exporter, or producer.","es":"La certificación no necesita tener un formato prescrito y puede completarla el importador, el exportador o el productor.","ru":"Сертификация не обязана иметь установленный формат и может быть заполнена импортером, экспортером или производителем.","tr":"Sertifikasyonun belirli bir formatta olması gerekmez ve ithalatçı, ihracatçı veya üretici tarafından tamamlanabilir.","hi":"certification को किसी निर्धारित प्रारूप में होने की आवश्यकता नहीं है और इसे importer, exporter, या producer द्वारा पूरा किया जा सकता है।","ar":"لا يلزم أن تكون الشهادة بصيغة محددة ويجوز إكمالها من المستورد أو المصدّر أو المنتج."},{"en":"Only the producer may complete the certification, and it must accompany the goods at the time of entry.","es":"Solo el productor puede completar la certificación, y esta debe acompañar a las mercancías al momento de la entrada.","ru":"Только производитель может заполнить сертификацию, и она должна сопровождать товары на момент оформления.","tr":"Sertifikasyonu yalnızca üretici tamamlayabilir ve beyan anında mallara eşlik etmelidir.","hi":"केवल producer ही certification पूरी कर सकता है, और यह एंट्री के समय माल के साथ होनी चाहिए।","ar":"لا يجوز إكمال الشهادة إلا من المنتج، ويجب أن ترافق البضائع وقت الإدخال."},{"en":"A certification is not required if the goods are valued under $2,500; otherwise only the exporter may certify.","es":"No se requiere certificación si las mercancías tienen un valor inferior a $2,500; de lo contrario, solo el exportador puede certificar.","ru":"Сертификация не требуется, если товары оценены менее чем в $2,500; в противном случае сертифицировать может только экспортер.","tr":"Mallar $2,500'ün altında değerlendiyse sertifikasyon gerekmez; aksi takdirde yalnızca ihracatçı sertifikalandırabilir.","hi":"यदि माल का मूल्य $2,500 से कम है तो certification आवश्यक नहीं है; अन्यथा केवल exporter ही प्रमाणित कर सकता है।","ar":"لا تُشترط الشهادة إذا كانت قيمة البضائع دون $2,500؛ وإلا فلا يجوز التصديق إلا من المصدّر."}],"e":{"en":"Under USMCA (Article 5.2) and 19 CFR 182.12, the certification of origin need not be in a prescribed format (no required form) and may be completed by the importer, exporter, or producer. This differs from NAFTA, which used CBP Form 434 and did not allow importer certification.","es":"Conforme al USMCA (Article 5.2) y 19 CFR 182.12, la certificación de origen no necesita tener un formato prescrito (no hay formulario requerido) y puede completarla el importador, el exportador o el productor. Esto difiere del NAFTA, que usaba el CBP Form 434 y no permitía la certificación por parte del importador.","ru":"Согласно USMCA (Article 5.2) и 19 CFR 182.12, сертификат происхождения не обязан иметь установленный формат (нет обязательной формы) и может быть заполнен импортером, экспортером или производителем. Это отличается от NAFTA, где использовалась CBP Form 434 и не допускалась сертификация импортером.","tr":"USMCA (Article 5.2) ve 19 CFR 182.12 kapsamında, menşe sertifikasyonunun (certification of origin) belirli bir formatta olması gerekmez (gerekli bir form yoktur) ve ithalatçı, ihracatçı veya üretici tarafından tamamlanabilir. Bu, CBP Form 434 kullanan ve ithalatçı sertifikasyonuna izin vermeyen NAFTA'dan farklıdır.","hi":"USMCA (Article 5.2) और 19 CFR 182.12 के तहत, certification of origin को किसी निर्धारित प्रारूप में होने की आवश्यकता नहीं है (कोई आवश्यक फॉर्म नहीं) और इसे importer, exporter, या producer द्वारा पूरा किया जा सकता है। यह NAFTA से अलग है, जो CBP Form 434 का उपयोग करता था और importer प्रमाणन की अनुमति नहीं देता था।","ar":"بموجب USMCA (Article 5.2) و19 CFR 182.12، لا يلزم أن تكون شهادة المنشأ بصيغة محددة (لا نموذج مطلوب) ويجوز إكمالها من المستورد أو المصدّر أو المنتج. ويختلف ذلك عن NAFTA، الذي كان يستخدم CBP Form 434 ولا يسمح بتصديق المستورد."}},{"cat":"trade","a":2,"q":{"en":"Foreign merchandise is admitted to a foreign-trade zone, and the operator timely files an application on the admission form to fix its tariff classification and rate of duty as of that date so that later manufacturing in the zone will not change them. What FTZ status has been elected?","es":"Mercancía extranjera se admite a una zona de comercio exterior (FTZ), y el operador presenta oportunamente una solicitud en el formulario de admisión para fijar su clasificación arancelaria y tasa de derechos a esa fecha, de modo que la manufactura posterior en la zona no las cambie. ¿Qué estatus de FTZ se ha elegido?","ru":"Иностранные товары допускаются в зону внешней торговли (FTZ), и оператор своевременно подает заявление на форме допуска, чтобы зафиксировать их тарифную классификацию и ставку пошлины по состоянию на эту дату, так чтобы последующее производство в зоне их не изменило. Какой статус FTZ был выбран?","tr":"Yabancı mallar bir foreign-trade zone'a kabul ediliyor ve işletici, bölgede daha sonra yapılacak imalatın bunları değiştirmemesi için tarife sınıflandırmasını ve vergi oranını o tarih itibarıyla sabitlemek üzere kabul formu üzerinde zamanında bir başvuru sunuyor. Hangi FTZ statüsü seçilmiştir?","hi":"विदेशी माल को एक foreign-trade zone में प्रवेश दिया जाता है, और ऑपरेटर admission form पर समय पर एक आवेदन दाखिल करता है ताकि उसके tariff classification और शुल्क दर को उस तारीख के अनुसार स्थिर किया जा सके, ताकि zone में बाद का निर्माण उन्हें न बदले। कौन-सा FTZ status चुना गया है?","ar":"تُدخَل بضاعة أجنبية إلى منطقة تجارة خارجية، ويقدّم المشغّل في الوقت المناسب طلباً على نموذج الإدخال لتثبيت تصنيفها التعريفي ومعدل رسومها اعتباراً من ذلك التاريخ بحيث لا يغيّرهما التصنيع اللاحق في المنطقة. أي وضع FTZ تمّ اختياره؟"},"o":[{"en":"Zone-restricted status.","es":"Estatus restringido de zona.","ru":"Зонально-ограниченный статус (zone-restricted status).","tr":"Zone-restricted status (bölge kısıtlamalı statü).","hi":"Zone-restricted status।","ar":"الوضع المقيّد بالمنطقة (Zone-restricted)."},{"en":"Nonprivileged foreign status.","es":"Estatus extranjero no privilegiado.","ru":"Непривилегированный иностранный статус (nonprivileged foreign status).","tr":"Nonprivileged foreign status (ayrıcalıklı olmayan yabancı statü).","hi":"Nonprivileged foreign status।","ar":"الوضع الأجنبي غير المميَّز (Nonprivileged foreign)."},{"en":"Privileged foreign status.","es":"Estatus extranjero privilegiado.","ru":"Привилегированный иностранный статус (privileged foreign status).","tr":"Privileged foreign status (ayrıcalıklı yabancı statü).","hi":"Privileged foreign status।","ar":"الوضع الأجنبي المميَّز (Privileged foreign)."},{"en":"Domestic status.","es":"Estatus doméstico.","ru":"Внутренний статус (domestic status).","tr":"Domestic status (yerli statü).","hi":"Domestic status।","ar":"الوضع المحلي (Domestic)."}],"e":{"en":"Under 19 CFR 146.41, privileged foreign status is elected by application (on the CBP Form 214 admission application, before any manipulation/manufacture that changes the tariff classification). It fixes the tariff classification and duty rate as of the date of the application, regardless of later processing in the zone.","es":"Conforme a 19 CFR 146.41, el estatus extranjero privilegiado se elige mediante solicitud (en la solicitud de admisión CBP Form 214, antes de cualquier manipulación/manufactura que cambie la clasificación arancelaria). Fija la clasificación arancelaria y la tasa de derechos a la fecha de la solicitud, independientemente del procesamiento posterior en la zona.","ru":"Согласно 19 CFR 146.41, привилегированный иностранный статус (privileged foreign status) выбирается путем подачи заявления (на заявлении о допуске CBP Form 214, до какой-либо манипуляции/производства, изменяющего тарифную классификацию). Он фиксирует тарифную классификацию и ставку пошлины по состоянию на дату заявления, независимо от последующей переработки в зоне.","tr":"19 CFR 146.41 kapsamında, privileged foreign status (ayrıcalıklı yabancı statü), başvuru ile (tarife sınıflandırmasını değiştiren herhangi bir manipülasyon/imalattan önce CBP Form 214 kabul başvurusu üzerinde) seçilir. Tarife sınıflandırmasını ve vergi oranını, bölgede daha sonra yapılacak işlemden bağımsız olarak başvuru tarihi itibarıyla sabitler.","hi":"19 CFR 146.41 के तहत, privileged foreign status को आवेदन द्वारा चुना जाता है (CBP Form 214 admission application पर, किसी ऐसे manipulation/manufacture से पहले जो tariff classification को बदलता है)। यह tariff classification और शुल्क दर को आवेदन की तारीख के अनुसार स्थिर कर देता है, zone में बाद की प्रोसेसिंग की परवाह किए बिना।","ar":"بموجب 19 CFR 146.41، يُختار الوضع الأجنبي المميَّز بطلب (على طلب الإدخال CBP Form 214، قبل أي معالجة/تصنيع يغيّر التصنيف التعريفي). ويثبّت التصنيف التعريفي ومعدل الرسوم اعتباراً من تاريخ الطلب، بصرف النظر عن المعالجة اللاحقة في المنطقة."}},{"cat":"trade","a":2,"q":{"en":"Merchandise is taken into a foreign-trade zone for the sole purpose of exportation (or storage pending exportation, or destruction). Which FTZ status applies, and what is its key restriction?","es":"Se introduce mercancía a una zona de comercio exterior (FTZ) con el único propósito de exportación (o almacenamiento en espera de exportación, o destrucción). ¿Qué estatus de FTZ aplica, y cuál es su restricción clave?","ru":"Товары ввозятся в зону внешней торговли (FTZ) исключительно с целью экспорта (либо хранения в ожидании экспорта, либо уничтожения). Какой статус FTZ применяется, и каково его ключевое ограничение?","tr":"Mallar yalnızca ihracat (veya ihracat beklemedeki depolama ya da imha) amacıyla bir foreign-trade zone'a alınıyor. Hangi FTZ statüsü geçerlidir ve temel kısıtlaması nedir?","hi":"माल को केवल निर्यात के उद्देश्य से (या निर्यात के लंबित भंडारण, या विनाश के लिए) एक foreign-trade zone में लिया जाता है। कौन-सा FTZ status लागू होता है, और इसका मुख्य प्रतिबंध क्या है?","ar":"تُؤخَذ بضاعة إلى منطقة تجارة خارجية لغرض التصدير حصراً (أو التخزين تمهيداً للتصدير، أو الإتلاف). أي وضع FTZ ينطبق، وما قيده الأساسي؟"},"o":[{"en":"Nonprivileged foreign status; it may be entered for consumption at the nonprivileged duty rate at any time.","es":"Estatus extranjero no privilegiado; puede declararse para consumo a la tasa de derechos no privilegiada en cualquier momento.","ru":"Непривилегированный иностранный статус; они могут быть оформлены для потребления по непривилегированной ставке пошлины в любое время.","tr":"Nonprivileged foreign status; herhangi bir zamanda ayrıcalıksız vergi oranıyla tüketim için beyan edilebilir.","hi":"Nonprivileged foreign status; इसे किसी भी समय nonprivileged शुल्क दर पर उपभोग के लिए एंटर किया जा सकता है।","ar":"الوضع الأجنبي غير المميَّز؛ يجوز إدخالها للاستهلاك بمعدل الرسوم غير المميَّز في أي وقت."},{"en":"Privileged foreign status; its classification is frozen but it may freely enter U.S. commerce.","es":"Estatus extranjero privilegiado; su clasificación queda congelada pero puede entrar libremente al comercio de Estados Unidos.","ru":"Привилегированный иностранный статус; их классификация зафиксирована, но они могут свободно поступать в торговый оборот США.","tr":"Privileged foreign status; sınıflandırması dondurulur ancak serbestçe ABD ticaretine girebilir.","hi":"Privileged foreign status; इसका classification स्थिर है लेकिन यह स्वतंत्र रूप से U.S. वाणिज्य में प्रवेश कर सकता है।","ar":"الوضع الأجنبي المميَّز؛ يُثبَّت تصنيفها لكن يجوز إدخالها بحرية إلى التجارة الأمريكية."},{"en":"Zone-restricted status; it generally may not be returned to U.S. customs territory for domestic consumption.","es":"Estatus restringido de zona; generalmente no puede devolverse al territorio aduanero de Estados Unidos para consumo doméstico.","ru":"Зонально-ограниченный статус; они, как правило, не могут быть возвращены на таможенную территорию США для внутреннего потребления.","tr":"Zone-restricted status; genellikle yurt içi tüketim için ABD gümrük bölgesine geri getirilemez.","hi":"Zone-restricted status; इसे आम तौर पर घरेलू उपभोग के लिए U.S. कस्टम क्षेत्र में वापस नहीं किया जा सकता।","ar":"الوضع المقيّد بالمنطقة؛ لا يجوز عموماً إعادتها إلى الإقليم الجمركي الأمريكي للاستهلاك المحلي."},{"en":"Domestic status; it is treated as already entered for consumption and bears no restriction.","es":"Estatus doméstico; se trata como ya declarada para consumo y no tiene ninguna restricción.","ru":"Внутренний статус; они рассматриваются как уже оформленные для потребления и не несут ограничений.","tr":"Domestic status; halihazırda tüketim için beyan edilmiş gibi muamele görür ve hiçbir kısıtlama taşımaz.","hi":"Domestic status; इसे पहले से ही उपभोग के लिए एंटर किया गया माना जाता है और इस पर कोई प्रतिबंध नहीं है।","ar":"الوضع المحلي؛ تُعامَل كأنها أُدخلت بالفعل للاستهلاك ولا تخضع لأي قيد."}],"e":{"en":"Under 19 CFR 146.44, merchandise taken into a zone for exportation, storage pending exportation, or destruction is given zone-restricted status on application. Such merchandise may not be removed to U.S. customs territory for domestic consumption except where the FTZ Board finds the return to be in the public interest.","es":"Conforme a 19 CFR 146.44, la mercancía introducida a una zona para exportación, almacenamiento en espera de exportación o destrucción recibe estatus restringido de zona mediante solicitud. Dicha mercancía no puede trasladarse al territorio aduanero de Estados Unidos para consumo doméstico, excepto cuando el FTZ Board determine que el retorno es de interés público.","ru":"Согласно 19 CFR 146.44, товары, ввезенные в зону для экспорта, хранения в ожидании экспорта или уничтожения, получают зонально-ограниченный статус (zone-restricted status) по заявлению. Такие товары не могут быть перемещены на таможенную территорию США для внутреннего потребления, за исключением случаев, когда Совет FTZ признает возврат соответствующим общественным интересам.","tr":"19 CFR 146.44 kapsamında, ihracat, ihracat beklemedeki depolama veya imha amacıyla bir bölgeye alınan mallara, başvuru üzerine zone-restricted status (bölge kısıtlamalı statü) verilir. Bu tür mallar, FTZ Board'un iadeyi kamu yararına bulduğu durumlar dışında, yurt içi tüketim için ABD gümrük bölgesine geri taşınamaz.","hi":"19 CFR 146.44 के तहत, निर्यात, निर्यात के लंबित भंडारण, या विनाश के लिए zone में लिए गए माल को आवेदन पर zone-restricted status दिया जाता है। ऐसे माल को घरेलू उपभोग के लिए U.S. कस्टम क्षेत्र में नहीं हटाया जा सकता, सिवाय जहाँ FTZ Board यह पाता है कि वापसी जनहित में है।","ar":"بموجب 19 CFR 146.44، تُمنَح البضاعة المأخوذة إلى منطقة بغرض التصدير أو التخزين تمهيداً للتصدير أو الإتلاف الوضع المقيّد بالمنطقة بناءً على طلب. ولا يجوز نقل هذه البضاعة إلى الإقليم الجمركي الأمريكي للاستهلاك المحلي إلا حيث يجد مجلس FTZ أن إعادتها تخدم المصلحة العامة."}},{"cat":"trade","a":3,"q":{"en":"On a CBP bond, the named importer of record whose obligations are secured by the bond is referred to as the principal, and the bonding company guaranteeing those obligations to CBP is the surety. Which of the following is true under 19 CFR Part 113?","es":"En una fianza de CBP, el importador registrado nombrado cuyas obligaciones están garantizadas por la fianza se denomina el principal, y la compañía afianzadora que garantiza esas obligaciones ante CBP es el fiador (surety). ¿Cuál de las siguientes afirmaciones es verdadera conforme a 19 CFR Part 113?","ru":"В таможенной гарантии (bond) CBP поименованный импортер-получатель (importer of record), чьи обязательства обеспечены гарантией, именуется принципалом (principal), а гарантийная компания, гарантирующая эти обязательства перед CBP, является поручителем (surety). Что из перечисленного верно согласно 19 CFR Part 113?","tr":"Bir CBP teminatında (bond), yükümlülükleri teminatla güvence altına alınan, adı geçen importer of record (kayıtlı ithalatçı) asıl (principal) olarak adlandırılır ve bu yükümlülükleri CBP'ye garanti eden teminat şirketi kefildir (surety). 19 CFR Part 113 kapsamında aşağıdakilerden hangisi doğrudur?","hi":"एक CBP bond पर, नामित importer of record जिसके दायित्व bond द्वारा सुरक्षित हैं, उसे principal कहा जाता है, और bonding कंपनी जो उन दायित्वों की CBP को गारंटी देती है, surety है। 19 CFR Part 113 के तहत निम्नलिखित में से कौन-सा सत्य है?","ar":"في سند ضمان CBP، يُشار إلى المستورد المسجَّل المسمّى الذي يضمن السند التزاماته بوصفه الموكِّل (principal)، وتُعدّ شركة الضمان التي تكفل تلك الالتزامات لـ CBP الكفيل (surety). أي مما يلي صحيح بموجب 19 CFR Part 113؟"},"o":[{"en":"The same corporation may act as both principal and surety on the bond to reduce cost.","es":"La misma corporación puede actuar como principal y como fiador en la fianza para reducir costos.","ru":"Одна и та же корпорация может выступать одновременно принципалом и поручителем по гарантии для снижения затрат.","tr":"Aynı şirket, maliyeti azaltmak için teminatta hem asıl hem de kefil olarak hareket edebilir.","hi":"वही कॉर्पोरेशन लागत कम करने के लिए bond पर principal और surety दोनों के रूप में कार्य कर सकता है।","ar":"يجوز للشركة نفسها أن تتصرّف كموكِّل وكفيل معاً على السند لخفض التكلفة."},{"en":"A continuous bond secures only one specified entry, while a single transaction bond covers all entries for one year.","es":"Una fianza continua garantiza solo una entrada específica, mientras que una fianza de transacción única cubre todas las entradas durante un año.","ru":"Непрерывная гарантия (continuous bond) обеспечивает только одно указанное оформление, тогда как гарантия на разовую сделку (single transaction bond) покрывает все оформления за один год.","tr":"Bir sürekli teminat (continuous bond) yalnızca belirtilen bir beyanı güvence altına alırken, tek işlem teminatı (single transaction bond) bir yıl boyunca tüm beyanları kapsar.","hi":"एक continuous bond केवल एक निर्दिष्ट एंट्री को सुरक्षित करता है, जबकि एक single transaction bond एक वर्ष के लिए सभी एंट्री को कवर करता है।","ar":"يضمن السند المستمر إدخالاً واحداً محدداً فقط، بينما يغطي سند المعاملة الواحدة جميع الإدخالات لمدة سنة."},{"en":"Only CBP, not the surety, is liable to importers for losses arising from a defaulted entry.","es":"Solo CBP, y no el fiador, es responsable ante los importadores por las pérdidas derivadas de una entrada en incumplimiento.","ru":"Только CBP, а не поручитель, несет ответственность перед импортерами за убытки, возникающие из-за неисполненного оформления.","tr":"Temerrüde düşmüş bir beyandan kaynaklanan zararlardan dolayı ithalatçılara karşı yalnızca CBP, kefil değil, sorumludur.","hi":"केवल CBP, surety नहीं, एक डिफ़ॉल्ट एंट्री से उत्पन्न नुकसान के लिए आयातकर्ताओं के प्रति उत्तरदायी है।","ar":"CBP وحدها، لا الكفيل، مسؤولة تجاه المستوردين عن الخسائر الناشئة عن إدخال متعثّر."},{"en":"The same person or corporation may not be both principal and surety on a bond.","es":"La misma persona o corporación no puede ser a la vez principal y fiador en una fianza.","ru":"Одно и то же лицо или корпорация не может быть одновременно принципалом и поручителем по гарантии.","tr":"Aynı kişi veya şirket, bir teminatta hem asıl hem de kefil olamaz.","hi":"वही व्यक्ति या कॉर्पोरेशन एक bond पर principal और surety दोनों नहीं हो सकता।","ar":"لا يجوز أن يكون الشخص أو الشركة نفسها موكِّلاً وكفيلاً على السند معاً."}],"e":{"en":"Under 19 CFR Part 113 (subpart D), the same person, partnership, or corporation cannot be both principal and surety on the same bond. A single transaction bond secures one transaction; a continuous bond secures multiple transactions over a one-year (renewable) period -- the reverse of option B.","es":"Conforme a 19 CFR Part 113 (subpart D), la misma persona, sociedad colectiva o corporación no puede ser a la vez principal y fiador en la misma fianza. Una fianza de transacción única garantiza una transacción; una fianza continua garantiza múltiples transacciones durante un período de un año (renovable), lo inverso de la opción B.","ru":"Согласно 19 CFR Part 113 (subpart D), одно и то же лицо, товарищество или корпорация не может быть одновременно принципалом и поручителем по одной и той же гарантии. Гарантия на разовую сделку (single transaction bond) обеспечивает одну сделку; непрерывная гарантия (continuous bond) обеспечивает множество сделок в течение годового (возобновляемого) периода — обратное варианту B.","tr":"19 CFR Part 113 (subpart D) kapsamında, aynı kişi, ortaklık veya şirket aynı teminatta hem asıl (principal) hem de kefil (surety) olamaz. Tek işlem teminatı (single transaction bond) bir işlemi güvence altına alır; sürekli teminat (continuous bond) ise bir yıllık (yenilenebilir) süre boyunca birden çok işlemi güvence altına alır -- B seçeneğinin tersi.","hi":"19 CFR Part 113 (subpart D) के तहत, वही व्यक्ति, साझेदारी, या कॉर्पोरेशन एक ही bond पर principal और surety दोनों नहीं हो सकता। एक single transaction bond एक लेनदेन को सुरक्षित करता है; एक continuous bond एक वर्ष (नवीकरणीय) अवधि में कई लेनदेन को सुरक्षित करता है -- विकल्प B के विपरीत।","ar":"بموجب 19 CFR Part 113 (subpart D)، لا يجوز أن يكون الشخص أو الشراكة أو الشركة نفسها موكِّلاً وكفيلاً على السند نفسه. ويضمن سند المعاملة الواحدة معاملة واحدة؛ بينما يضمن السند المستمر معاملات متعددة على مدى فترة سنة واحدة (قابلة للتجديد) — عكس الخيار B."}},{"cat":"trade","a":3,"q":{"en":"An importer expects to make numerous entries at multiple ports throughout the year and wants the most cost-effective bond arrangement. Which bond type is appropriate, and how long is it generally effective under 19 CFR Part 113?","es":"Un importador espera realizar numerosas entradas en múltiples puertos a lo largo del año y desea el arreglo de fianza más rentable. ¿Qué tipo de fianza es apropiado, y por cuánto tiempo es generalmente efectivo conforme a 19 CFR Part 113?","ru":"Импортер ожидает совершить многочисленные оформления в нескольких портах в течение года и хочет наиболее экономичную схему гарантирования. Какой тип гарантии (bond) подходит, и как долго она обычно действует согласно 19 CFR Part 113?","tr":"Bir ithalatçı, yıl boyunca birden çok limanda çok sayıda beyan yapmayı bekliyor ve en uygun maliyetli teminat düzenlemesini istiyor. Hangi teminat türü uygundur ve 19 CFR Part 113 kapsamında genellikle ne kadar süreyle geçerlidir?","hi":"एक आयातकर्ता पूरे वर्ष कई बंदरगाहों पर अनेक एंट्री करने की उम्मीद करता है और सबसे लागत-प्रभावी bond व्यवस्था चाहता है। कौन-सा bond प्रकार उपयुक्त है, और 19 CFR Part 113 के तहत यह आम तौर पर कितने समय तक प्रभावी रहता है?","ar":"يتوقّع مستورد إجراء إدخالات عديدة في موانئ متعددة على مدار السنة ويريد ترتيب سند الضمان الأكثر فعالية من حيث التكلفة. أي نوع من السندات مناسب، وإلى متى يكون نافذاً عموماً بموجب 19 CFR Part 113؟"},"o":[{"en":"A single transaction bond, effective for the life of the one entry it secures.","es":"Una fianza de transacción única, efectiva por la vida de la única entrada que garantiza.","ru":"Гарантия на разовую сделку (single transaction bond), действующая в течение срока одного оформления, которое она обеспечивает.","tr":"Tek işlem teminatı (single transaction bond), güvence altına aldığı tek beyanın ömrü boyunca geçerli.","hi":"एक single transaction bond, जो एक एंट्री के जीवनकाल के लिए प्रभावी है जिसे यह सुरक्षित करता है।","ar":"سند معاملة واحدة، نافذ طوال عمر الإدخال الوحيد الذي يضمنه."},{"en":"A single transaction bond, effective for one year and automatically renewing.","es":"Una fianza de transacción única, efectiva por un año y de renovación automática.","ru":"Гарантия на разовую сделку (single transaction bond), действующая один год и автоматически возобновляемая.","tr":"Tek işlem teminatı (single transaction bond), bir yıl geçerli ve otomatik olarak yenilenen.","hi":"एक single transaction bond, जो एक वर्ष के लिए प्रभावी है और स्वचालित रूप से नवीनीकृत होता है।","ar":"سند معاملة واحدة، نافذ لمدة سنة ويتجدّد تلقائياً."},{"en":"A continuous bond, effective only at the single port where it is filed.","es":"Una fianza continua, efectiva solo en el único puerto donde se presenta.","ru":"Непрерывная гарантия (continuous bond), действующая только в одном порту, где она подана.","tr":"Sürekli teminat (continuous bond), yalnızca sunulduğu tek limanda geçerli.","hi":"एक continuous bond, जो केवल उस एकल बंदरगाह पर प्रभावी है जहाँ इसे दाखिल किया जाता है।","ar":"سند مستمر، نافذ فقط في الميناء الوحيد المُودَع فيه."},{"en":"A continuous bond, effective for one year from its effective date and each succeeding annual period until terminated.","es":"Una fianza continua, efectiva por un año a partir de su fecha de vigencia y por cada período anual sucesivo hasta su terminación.","ru":"Непрерывная гарантия (continuous bond), действующая один год с даты вступления в силу и каждый последующий годовой период до прекращения.","tr":"Sürekli teminat (continuous bond), yürürlük tarihinden itibaren bir yıl ve sona erdirilene kadar her takip eden yıllık dönem için geçerli.","hi":"एक continuous bond, जो अपनी प्रभावी तिथि से एक वर्ष के लिए और प्रत्येक बाद की वार्षिक अवधि के लिए तब तक प्रभावी है जब तक समाप्त न किया जाए।","ar":"سند مستمر، نافذ لمدة سنة من تاريخ نفاذه ولكل فترة سنوية تالية إلى أن يُنهى."}],"e":{"en":"Under 19 CFR 113.11-113.12, a continuous bond secures multiple transactions and remains in force for one year beginning with the effective date, and for each succeeding annual period, or until terminated. It applies nationally, making it cost-effective for high-volume importers.","es":"Conforme a 19 CFR 113.11-113.12, una fianza continua garantiza múltiples transacciones y permanece en vigor por un año a partir de la fecha de vigencia, y por cada período anual sucesivo, o hasta su terminación. Se aplica a nivel nacional, lo que la hace rentable para importadores de alto volumen.","ru":"Согласно 19 CFR 113.11–113.12, непрерывная гарантия (continuous bond) обеспечивает множество сделок и остается в силе в течение одного года, начиная с даты вступления в силу, и в каждый последующий годовой период, или до прекращения. Она действует на всей территории страны, что делает ее экономичной для импортеров с большим объемом.","tr":"19 CFR 113.11-113.12 kapsamında, sürekli teminat (continuous bond) birden çok işlemi güvence altına alır ve yürürlük tarihinden başlayarak bir yıl boyunca ve her takip eden yıllık dönem için veya sona erdirilene kadar geçerli kalır. Ulusal düzeyde uygulanır, bu da yüksek hacimli ithalatçılar için onu uygun maliyetli kılar.","hi":"19 CFR 113.11-113.12 के तहत, एक continuous bond कई लेनदेन को सुरक्षित करता है और प्रभावी तिथि से शुरू होकर एक वर्ष के लिए, और प्रत्येक बाद की वार्षिक अवधि के लिए, या समाप्त होने तक प्रभावी रहता है। यह राष्ट्रीय स्तर पर लागू होता है, जो इसे उच्च-मात्रा वाले आयातकर्ताओं के लिए लागत-प्रभावी बनाता है।","ar":"بموجب 19 CFR 113.11-113.12، يضمن السند المستمر معاملات متعددة ويظلّ نافذاً لمدة سنة تبدأ بتاريخ النفاذ، ولكل فترة سنوية تالية، أو إلى أن يُنهى. وينطبق على المستوى الوطني، مما يجعله فعّالاً من حيث التكلفة للمستوردين ذوي الحجم الكبير."}},{"cat":"trade","a":0,"q":{"en":"A shipment arrives at the port of New York but the importer wants to clear and enter it for consumption at an inland port (e.g., Chicago). Which in-bond movement type is used to move the merchandise under bond to the inland port for entry there?","es":"Un embarque llega al puerto de Nueva York pero el importador desea despacharlo y declararlo para consumo en un puerto interior (por ejemplo, Chicago). ¿Qué tipo de movimiento in-bond se usa para mover la mercancía bajo fianza al puerto interior para declararla allí?","ru":"Партия прибывает в порт Нью-Йорк, но импортер хочет растаможить и оформить ее для потребления во внутреннем порту (например, в Чикаго). Какой тип перемещения под гарантией (in-bond) используется для перемещения товаров под гарантией во внутренний порт для оформления там?","tr":"Bir sevkiyat New York limanına geliyor ancak ithalatçı bunu bir iç limandan (örneğin Chicago) gümrükleyip tüketim için beyan etmek istiyor. Malları teminat altında iç limana orada beyan edilmek üzere taşımak için hangi in-bond hareket türü kullanılır?","hi":"एक शिपमेंट port of New York पर पहुँचता है लेकिन आयातकर्ता इसे एक अंतर्देशीय बंदरगाह (जैसे Chicago) पर उपभोग के लिए क्लियर और एंटर करना चाहता है। माल को bond के तहत अंतर्देशीय बंदरगाह तक वहाँ एंट्री के लिए ले जाने के लिए किस in-bond संचलन प्रकार का उपयोग किया जाता है?","ar":"تصل شحنة إلى ميناء نيويورك لكن المستورد يريد تخليصها وإدخالها للاستهلاك في ميناء داخلي (مثل شيكاغو). أي نوع من حركة النقل تحت الضمان (in-bond) يُستخدَم لنقل البضاعة تحت الضمان إلى الميناء الداخلي لإدخالها هناك؟"},"o":[{"en":"Immediate Transportation (I.T.) entry.","es":"Entrada de Immediate Transportation (I.T.).","ru":"Оформление немедленной транспортировки (Immediate Transportation, I.T.).","tr":"Immediate Transportation (I.T.) beyanı.","hi":"Immediate Transportation (I.T.) एंट्री।","ar":"إدخال النقل الفوري (Immediate Transportation - I.T.)."},{"en":"Transportation and Exportation (T&E) entry.","es":"Entrada de Transportation and Exportation (T&E).","ru":"Оформление транспортировки и экспорта (Transportation and Exportation, T&E).","tr":"Transportation and Exportation (T&E) beyanı.","hi":"Transportation and Exportation (T&E) एंट्री।","ar":"إدخال النقل والتصدير (Transportation and Exportation - T&E)."},{"en":"Immediate Exportation (I.E.) entry.","es":"Entrada de Immediate Exportation (I.E.).","ru":"Оформление немедленного экспорта (Immediate Exportation, I.E.).","tr":"Immediate Exportation (I.E.) beyanı.","hi":"Immediate Exportation (I.E.) एंट्री।","ar":"إدخال التصدير الفوري (Immediate Exportation - I.E.)."},{"en":"Warehouse withdrawal for transportation.","es":"Retiro de almacén para transportación.","ru":"Изъятие со склада для транспортировки (warehouse withdrawal for transportation).","tr":"Taşıma için antrepodan çekim (warehouse withdrawal for transportation).","hi":"परिवहन के लिए warehouse withdrawal।","ar":"سحب من المستودع لغرض النقل."}],"e":{"en":"Under 19 CFR Part 18, an Immediate Transportation (I.T.) in-bond entry moves merchandise under bond from the port of arrival to another U.S. port where it will be entered. A T&E moves goods in-bond to a port for exportation; an I.E. exports goods directly from the port of arrival without further inland transit.","es":"Conforme a 19 CFR Part 18, una entrada in-bond de Immediate Transportation (I.T.) mueve la mercancía bajo fianza desde el puerto de llegada a otro puerto de Estados Unidos donde se declarará. Una T&E mueve las mercancías in-bond a un puerto para su exportación; una I.E. exporta las mercancías directamente desde el puerto de llegada sin tránsito interior adicional.","ru":"Согласно 19 CFR Part 18, оформление немедленной транспортировки под гарантией (Immediate Transportation, I.T.) перемещает товары под гарантией из порта прибытия в другой порт США, где они будут оформлены. T&E перемещает товары под гарантией в порт для экспорта; I.E. экспортирует товары непосредственно из порта прибытия без дальнейшего внутреннего транзита.","tr":"19 CFR Part 18 kapsamında, bir Immediate Transportation (I.T.) in-bond beyanı, malları teminat altında varış limanından beyan edilecekleri başka bir ABD limanına taşır. Bir T&E, malları ihracat için bir limana in-bond olarak taşır; bir I.E. ise malları daha fazla iç taşıma olmaksızın varış limanından doğrudan ihraç eder.","hi":"19 CFR Part 18 के तहत, एक Immediate Transportation (I.T.) in-bond एंट्री माल को bond के तहत पहुँचने के बंदरगाह से दूसरे U.S. बंदरगाह तक ले जाती है जहाँ इसे एंटर किया जाएगा। एक T&E माल को निर्यात के लिए एक बंदरगाह तक in-bond ले जाती है; एक I.E. माल को आगे के अंतर्देशीय पारगमन के बिना पहुँचने के बंदरगाह से सीधे निर्यात करती है।","ar":"بموجب 19 CFR Part 18، ينقل إدخال النقل الفوري (I.T.) تحت الضمان البضاعة من ميناء الوصول إلى ميناء أمريكي آخر حيث ستُدخَل. أما T&E فينقل البضائع تحت الضمان إلى ميناء بغرض التصدير؛ وأما I.E. فيصدّر البضائع مباشرةً من ميناء الوصول دون نقل داخلي إضافي."}},{"cat":"trade","a":2,"q":{"en":"Foreign merchandise lands at a U.S. port and the consignee decides to ship it under bond to a different U.S. port for export from there, with no intention of entering it into U.S. commerce. Which in-bond movement applies under 19 CFR Part 18?","es":"Mercancía extranjera arriba a un puerto de Estados Unidos y el consignatario decide enviarla bajo fianza a un puerto diferente de Estados Unidos para exportarla desde allí, sin intención de introducirla al comercio de Estados Unidos. ¿Qué movimiento in-bond aplica conforme a 19 CFR Part 18?","ru":"Иностранные товары прибывают в порт США, и грузополучатель решает отправить их под гарантией в другой порт США для экспорта оттуда, не намереваясь вводить их в торговый оборот США. Какое перемещение под гарантией (in-bond) применяется согласно 19 CFR Part 18?","tr":"Yabancı mallar bir ABD limanına iniyor ve alıcı, bunları ABD ticaretine sokma niyeti olmaksızın, oradan ihraç edilmek üzere farklı bir ABD limanına teminat altında göndermeye karar veriyor. 19 CFR Part 18 kapsamında hangi in-bond hareketi uygulanır?","hi":"विदेशी माल एक U.S. बंदरगाह पर उतरता है और consignee इसे वहाँ से निर्यात के लिए एक अलग U.S. बंदरगाह तक bond के तहत भेजने का निर्णय लेता है, इसे U.S. वाणिज्य में एंटर करने के किसी इरादे के बिना। 19 CFR Part 18 के तहत कौन-सा in-bond संचलन लागू होता है?","ar":"تَرسو بضاعة أجنبية في ميناء أمريكي ويقرّر المرسَل إليه شحنها تحت الضمان إلى ميناء أمريكي مختلف لتصديرها من هناك، دون نية إدخالها إلى التجارة الأمريكية. أي حركة نقل تحت الضمان تنطبق بموجب 19 CFR Part 18؟"},"o":[{"en":"Immediate Exportation (I.E.), since the goods will leave from the port of arrival.","es":"Immediate Exportation (I.E.), ya que las mercancías saldrán desde el puerto de llegada.","ru":"Немедленный экспорт (Immediate Exportation, I.E.), поскольку товары покинут страну из порта прибытия.","tr":"Immediate Exportation (I.E.), çünkü mallar varış limanından ayrılacaktır.","hi":"Immediate Exportation (I.E.), क्योंकि माल पहुँचने के बंदरगाह से रवाना होगा।","ar":"التصدير الفوري (I.E.)، لأن البضائع ستغادر من ميناء الوصول."},{"en":"Immediate Transportation (I.T.), since the goods move to another port.","es":"Immediate Transportation (I.T.), ya que las mercancías se mueven a otro puerto.","ru":"Немедленная транспортировка (Immediate Transportation, I.T.), поскольку товары перемещаются в другой порт.","tr":"Immediate Transportation (I.T.), çünkü mallar başka bir limana taşınır.","hi":"Immediate Transportation (I.T.), क्योंकि माल दूसरे बंदरगाह तक जाता है।","ar":"النقل الفوري (I.T.)، لأن البضائع تنتقل إلى ميناء آخر."},{"en":"Transportation and Exportation (T&E), since the goods move in-bond to another port and are then exported.","es":"Transportation and Exportation (T&E), ya que las mercancías se mueven in-bond a otro puerto y luego se exportan.","ru":"Транспортировка и экспорт (Transportation and Exportation, T&E), поскольку товары перемещаются под гарантией в другой порт и затем экспортируются.","tr":"Transportation and Exportation (T&E), çünkü mallar in-bond olarak başka bir limana taşınır ve ardından ihraç edilir.","hi":"Transportation and Exportation (T&E), क्योंकि माल in-bond दूसरे बंदरगाह तक जाता है और फिर निर्यात किया जाता है।","ar":"النقل والتصدير (T&E)، لأن البضائع تنتقل تحت الضمان إلى ميناء آخر ثم تُصدَّر."},{"en":"Permanent Exhibition entry, since the goods are not entered for consumption.","es":"Entrada de Exhibición Permanente, ya que las mercancías no se declaran para consumo.","ru":"Оформление постоянной выставки (Permanent Exhibition), поскольку товары не оформляются для потребления.","tr":"Kalıcı Sergi beyanı (Permanent Exhibition entry), çünkü mallar tüketim için beyan edilmez.","hi":"Permanent Exhibition एंट्री, क्योंकि माल उपभोग के लिए एंटर नहीं किया गया है।","ar":"إدخال المعرض الدائم، لأن البضائع لا تُدخَل للاستهلاك."}],"e":{"en":"Under 19 CFR Part 18 (subpart D), a Transportation and Exportation (T&E) entry covers merchandise transported in-bond from the port of arrival to another U.S. port for exportation. An I.E. would export the goods from the port of arrival itself without inland movement.","es":"Conforme a 19 CFR Part 18 (subpart D), una entrada de Transportation and Exportation (T&E) cubre la mercancía transportada in-bond desde el puerto de llegada a otro puerto de Estados Unidos para su exportación. Una I.E. exportaría las mercancías desde el propio puerto de llegada sin movimiento interior.","ru":"Согласно 19 CFR Part 18 (subpart D), оформление транспортировки и экспорта (Transportation and Exportation, T&E) охватывает товары, перевозимые под гарантией из порта прибытия в другой порт США для экспорта. I.E. экспортировало бы товары из самого порта прибытия без внутреннего перемещения.","tr":"19 CFR Part 18 (subpart D) kapsamında, bir Transportation and Exportation (T&E) beyanı, varış limanından ihracat için başka bir ABD limanına in-bond olarak taşınan malları kapsar. Bir I.E. ise malları, iç hareket olmaksızın varış limanının kendisinden ihraç eder.","hi":"19 CFR Part 18 (subpart D) के तहत, एक Transportation and Exportation (T&E) एंट्री उस माल को कवर करती है जो पहुँचने के बंदरगाह से दूसरे U.S. बंदरगाह तक निर्यात के लिए in-bond परिवहन किया जाता है। एक I.E. माल को बिना अंतर्देशीय संचलन के पहुँचने के बंदरगाह से ही निर्यात करेगी।","ar":"بموجب 19 CFR Part 18 (subpart D)، يغطي إدخال النقل والتصدير (T&E) البضاعة المنقولة تحت الضمان من ميناء الوصول إلى ميناء أمريكي آخر بغرض التصدير. أما I.E. فيصدّر البضائع من ميناء الوصول نفسه دون نقل داخلي."}},{"cat":"trade","a":3,"q":{"en":"An importer is bringing a shipment of commercially packaged human food into the United States. Beyond CBP's requirements, which Partner Government Agency requirement most directly applies before the food can be admitted?","es":"Un importador está trayendo un embarque de alimento humano empacado comercialmente a Estados Unidos. Más allá de los requisitos de CBP, ¿qué requisito de una Partner Government Agency aplica más directamente antes de que el alimento pueda admitirse?","ru":"Импортер ввозит партию коммерчески упакованных продуктов питания для человека в Соединенные Штаты. Помимо требований CBP, какое требование Партнерского правительственного агентства (PGA) наиболее непосредственно применяется до того, как продукты могут быть допущены?","tr":"Bir ithalatçı, ticari ambalajlı insan gıdasından oluşan bir sevkiyatı Amerika Birleşik Devletleri'ne getiriyor. CBP'nin gerekliliklerinin ötesinde, gıdanın kabul edilebilmesi için en doğrudan hangi Partner Government Agency (PGA) gerekliliği geçerlidir?","hi":"एक आयातकर्ता संयुक्त राज्य अमेरिका में वाणिज्यिक रूप से पैकेज्ड मानव भोजन का एक शिपमेंट ला रहा है। CBP की आवश्यकताओं से परे, भोजन को प्रवेश दिए जाने से पहले कौन-सी Partner Government Agency आवश्यकता सबसे सीधे लागू होती है?","ar":"يستورد مستورد شحنة من الأغذية البشرية المعبّأة تجارياً إلى الولايات المتحدة. إلى جانب متطلبات CBP، أي متطلب من متطلبات وكالة حكومية شريكة (PGA) ينطبق بشكل مباشر أكثر قبل أن يُسمح بدخول الغذاء؟"},"o":[{"en":"An EPA pesticide registration notice must be filed for the food.","es":"Debe presentarse un aviso de registro de pesticidas de la EPA para el alimento.","ru":"Должно быть подано уведомление о регистрации пестицида EPA для продуктов.","tr":"Gıda için bir EPA pestisit kayıt bildirimi sunulmalıdır.","hi":"भोजन के लिए एक EPA pesticide registration नोटिस दाखिल किया जाना चाहिए।","ar":"يجب تقديم إشعار تسجيل مبيد آفات لدى EPA للغذاء."},{"en":"A Fish and Wildlife Service Form 3-177 declaration must be filed.","es":"Debe presentarse una declaración Form 3-177 del Fish and Wildlife Service.","ru":"Должна быть подана декларация Fish and Wildlife Service по Form 3-177.","tr":"Bir Fish and Wildlife Service Form 3-177 beyanı sunulmalıdır.","hi":"एक Fish and Wildlife Service Form 3-177 घोषणा दाखिल की जानी चाहिए।","ar":"يجب تقديم إقرار Fish and Wildlife Service Form 3-177."},{"en":"A USDA APHIS plant pest permit is required for all packaged human food.","es":"Se requiere un permiso de plaga vegetal de USDA APHIS para todo alimento humano empacado.","ru":"Для всех упакованных продуктов питания для человека требуется разрешение USDA APHIS на ввоз растительных вредителей.","tr":"Tüm ambalajlı insan gıdası için bir USDA APHIS bitki zararlısı izni gereklidir.","hi":"सभी पैकेज्ड मानव भोजन के लिए एक USDA APHIS plant pest permit आवश्यक है।","ar":"يلزم تصريح آفات نباتية من USDA APHIS لجميع الأغذية البشرية المعبّأة."},{"en":"FDA Prior Notice of the imported food shipment must be submitted and confirmed.","es":"Debe presentarse y confirmarse el FDA Prior Notice del embarque de alimento importado.","ru":"Должно быть подано и подтверждено предварительное уведомление FDA (Prior Notice) о ввозимой партии продуктов питания.","tr":"İthal edilen gıda sevkiyatına ilişkin FDA Prior Notice (Ön Bildirim) sunulmalı ve onaylanmalıdır.","hi":"आयातित भोजन शिपमेंट की FDA Prior Notice प्रस्तुत और पुष्टि की जानी चाहिए।","ar":"يجب تقديم Prior Notice من FDA لشحنة الغذاء المستورَدة وتأكيده."}],"e":{"en":"Under the FDA's authority (21 CFR Part 1, Subpart I, implementing the Bioterrorism Act), Prior Notice must be submitted to and confirmed by FDA for food for humans or animals imported or offered for import. CBP enforces admissibility, but the controlling PGA requirement for food is FDA Prior Notice. Form 3-177 is a Fish and Wildlife wildlife declaration, not a general food requirement.","es":"Bajo la autoridad de la FDA (21 CFR Part 1, Subpart I, que implementa la Bioterrorism Act), debe presentarse y ser confirmado por la FDA el Prior Notice para alimentos para humanos o animales importados u ofrecidos para importación. CBP hace cumplir la admisibilidad, pero el requisito determinante de la PGA para los alimentos es el FDA Prior Notice. El Form 3-177 es una declaración de vida silvestre del Fish and Wildlife, no un requisito general de alimentos.","ru":"В рамках полномочий FDA (21 CFR Part 1, Subpart I, реализующий Bioterrorism Act) предварительное уведомление (Prior Notice) должно быть подано в FDA и подтверждено им для продуктов питания для людей или животных, импортируемых или предлагаемых к импорту. CBP обеспечивает соблюдение допустимости ввоза, но определяющим требованием PGA для продуктов питания является Prior Notice FDA. Form 3-177 — это декларация Fish and Wildlife на дикую природу, а не общее требование к продуктам питания.","tr":"FDA'nın yetkisi kapsamında (Bioterrorism Act'i uygulayan 21 CFR Part 1, Subpart I), ithal edilen veya ithal için sunulan insan ya da hayvan gıdaları için FDA'ya Prior Notice (Ön Bildirim) sunulmalı ve FDA tarafından onaylanmalıdır. CBP kabul edilebilirliği uygular, ancak gıda için belirleyici PGA gerekliliği FDA Prior Notice'tir. Form 3-177, genel bir gıda gerekliliği değil, bir Fish and Wildlife yaban hayatı beyanıdır.","hi":"FDA के प्राधिकरण के तहत (21 CFR Part 1, Subpart I, Bioterrorism Act को लागू करते हुए), मानव या पशु के लिए आयातित या आयात के लिए प्रस्तुत भोजन के लिए FDA को Prior Notice प्रस्तुत और पुष्टि की जानी चाहिए। CBP प्रवेश-योग्यता लागू करता है, लेकिन भोजन के लिए नियंत्रक PGA आवश्यकता FDA Prior Notice है। Form 3-177 एक Fish and Wildlife वन्यजीव घोषणा है, सामान्य भोजन आवश्यकता नहीं।","ar":"بموجب صلاحية FDA (21 CFR Part 1, Subpart I، تنفيذاً لـ Bioterrorism Act)، يجب تقديم Prior Notice إلى FDA وتأكيده بشأن الأغذية المخصّصة للبشر أو الحيوانات المستورَدة أو المعروضة للاستيراد. وتنفّذ CBP أحكام الأهلية للدخول، لكن متطلب PGA الحاكم للغذاء هو FDA Prior Notice. أما Form 3-177 فهو إقرار حياة برية لدى Fish and Wildlife، وليس متطلباً عاماً للغذاء."}},{"cat":"trade","a":0,"q":{"en":"A broker is clearing an importation of live tropical aquarium fish and certain wildlife-derived products. Which Partner Government Agency's declaration requirement is most directly implicated, and what form is typically used?","es":"Un agente de aduanas está despachando una importación de peces tropicales vivos de acuario y ciertos productos derivados de vida silvestre. ¿El requisito de declaración de qué Partner Government Agency está más directamente implicado, y qué formulario se usa típicamente?","ru":"Брокер растаможивает ввоз живых тропических аквариумных рыб и определенных продуктов, полученных из дикой природы. Требование о декларации какого Партнерского правительственного агентства (PGA) наиболее непосредственно затрагивается, и какая форма обычно используется?","tr":"Bir gümrük müşaviri, canlı tropikal akvaryum balıkları ve belirli yaban hayatı kaynaklı ürünlerden oluşan bir ithalatı gümrüklüyor. En doğrudan hangi Partner Government Agency'nin beyan gerekliliği söz konusudur ve tipik olarak hangi form kullanılır?","hi":"एक ब्रोकर जीवित उष्णकटिबंधीय aquarium मछलियों और कुछ वन्यजीव-व्युत्पन्न उत्पादों के आयात को क्लियर कर रहा है। किस Partner Government Agency की घोषणा आवश्यकता सबसे सीधे निहित है, और आम तौर पर कौन-सा फॉर्म उपयोग किया जाता है?","ar":"يخلّص وسيط استيراد أسماك زينة استوائية حيّة وبعض المنتجات المشتقّة من الحياة البرية. أي متطلب إقرار لدى وكالة حكومية شريكة (PGA) يتعلق بالأمر بشكل مباشر أكثر، وما النموذج المستخدَم عادةً؟"},"o":[{"en":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","es":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","ru":"U.S. Fish and Wildlife Service; Декларация на ввоз или вывоз рыбы или дикой природы (Form 3-177).","tr":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177).","hi":"U.S. Fish and Wildlife Service; Declaration for Importation or Exportation of Fish or Wildlife (Form 3-177)।","ar":"U.S. Fish and Wildlife Service؛ إقرار استيراد أو تصدير الأسماك أو الحياة البرية (Form 3-177)."},{"en":"Consumer Product Safety Commission; a certificate of conformity.","es":"Consumer Product Safety Commission; un certificado de conformidad.","ru":"Consumer Product Safety Commission; сертификат соответствия.","tr":"Consumer Product Safety Commission; bir uygunluk belgesi.","hi":"Consumer Product Safety Commission; एक certificate of conformity।","ar":"Consumer Product Safety Commission؛ شهادة مطابقة."},{"en":"Environmental Protection Agency; EPA Form 3520-1.","es":"Environmental Protection Agency; EPA Form 3520-1.","ru":"Environmental Protection Agency; EPA Form 3520-1.","tr":"Environmental Protection Agency; EPA Form 3520-1.","hi":"Environmental Protection Agency; EPA Form 3520-1।","ar":"Environmental Protection Agency؛ EPA Form 3520-1."},{"en":"USDA Agricultural Marketing Service; a PPQ Form 587 permit.","es":"USDA Agricultural Marketing Service; un permiso PPQ Form 587.","ru":"USDA Agricultural Marketing Service; разрешение PPQ Form 587.","tr":"USDA Agricultural Marketing Service; bir PPQ Form 587 izni.","hi":"USDA Agricultural Marketing Service; एक PPQ Form 587 permit।","ar":"USDA Agricultural Marketing Service؛ تصريح PPQ Form 587."}],"e":{"en":"Imports of fish and wildlife (including many live aquatic organisms and wildlife-derived products) are regulated by the U.S. Fish and Wildlife Service, which generally requires a Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177). EPA Form 3520-1 applies to motor vehicles/engines; CPSC certificates apply to consumer products.","es":"Las importaciones de peces y vida silvestre (incluidos muchos organismos acuáticos vivos y productos derivados de vida silvestre) están reguladas por el U.S. Fish and Wildlife Service, que generalmente requiere una Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177). El EPA Form 3520-1 aplica a vehículos automotores/motores; los certificados de la CPSC aplican a productos de consumo.","ru":"Импорт рыбы и дикой природы (включая многие живые водные организмы и продукты, полученные из дикой природы) регулируется U.S. Fish and Wildlife Service, который обычно требует Декларацию на ввоз или вывоз рыбы или дикой природы (FWS Form 3-177). EPA Form 3520-1 применяется к автотранспортным средствам/двигателям; сертификаты CPSC применяются к потребительским товарам.","tr":"Balık ve yaban hayatı ithalatı (birçok canlı su organizması ve yaban hayatı kaynaklı ürün dahil) U.S. Fish and Wildlife Service tarafından düzenlenir ve genellikle bir Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177) gerektirir. EPA Form 3520-1, motorlu taşıtlara/motorlara uygulanır; CPSC belgeleri ise tüketici ürünlerine uygulanır.","hi":"मछली और वन्यजीव (जिसमें कई जीवित जलीय जीव और वन्यजीव-व्युत्पन्न उत्पाद शामिल हैं) के आयात को U.S. Fish and Wildlife Service द्वारा विनियमित किया जाता है, जिसके लिए आम तौर पर एक Declaration for Importation or Exportation of Fish or Wildlife (FWS Form 3-177) आवश्यक होती है। EPA Form 3520-1 motor vehicles/engines पर लागू होता है; CPSC certificates उपभोक्ता उत्पादों पर लागू होते हैं।","ar":"تخضع واردات الأسماك والحياة البرية (بما في ذلك كثير من الكائنات المائية الحيّة والمنتجات المشتقّة من الحياة البرية) لتنظيم U.S. Fish and Wildlife Service، التي تشترط عموماً إقرار استيراد أو تصدير الأسماك أو الحياة البرية (FWS Form 3-177). أما EPA Form 3520-1 فينطبق على المركبات/المحركات الآلية؛ وشهادات CPSC تنطبق على المنتجات الاستهلاكية."}},{"cat":"trade","a":1,"q":{"en":"A trademark owner whose mark is registered with the USPTO wants CBP to detain and seize infringing imports at the border. What is the threshold step required for CBP border enforcement under 19 CFR Part 133?","es":"Un titular de una marca registrada cuya marca está registrada en la USPTO quiere que CBP detenga e incaute importaciones infractoras en la frontera. ¿Cuál es el paso umbral requerido para la aplicación fronteriza de CBP conforme a 19 CFR Part 133?","ru":"Владелец товарного знака, чей знак зарегистрирован в USPTO, хочет, чтобы CBP задерживала и изымала контрафактный импорт на границе. Каков пороговый шаг, необходимый для пограничного контроля CBP согласно 19 CFR Part 133?","tr":"Markası USPTO'da tescilli olan bir marka sahibi, CBP'nin ihlal eden ithalatı sınırda alıkoymasını ve el koymasını istiyor. 19 CFR Part 133 kapsamında CBP sınır uygulaması için gereken eşik adım nedir?","hi":"एक ट्रेडमार्क मालिक जिसका चिह्न USPTO के साथ पंजीकृत है, चाहता है कि CBP सीमा पर उल्लंघनकारी आयातों को रोके और जब्त करे। 19 CFR Part 133 के तहत CBP सीमा प्रवर्तन के लिए आवश्यक सीमा-कदम क्या है?","ar":"يرغب مالك علامة تجارية مسجَّلة لدى USPTO في أن تحتجز CBP الواردات المخالِفة وتضبطها عند الحدود. ما الخطوة الأولية المطلوبة لإنفاذ CBP الحدودي بموجب 19 CFR Part 133؟"},"o":[{"en":"Filing a civil infringement suit in federal district court before any CBP action can occur.","es":"Presentar una demanda civil por infracción ante un tribunal federal de distrito antes de que pueda ocurrir cualquier acción de CBP.","ru":"Подача гражданского иска о нарушении в федеральный окружной суд до того, как могут быть предприняты какие-либо действия CBP.","tr":"Herhangi bir CBP işlemi gerçekleşmeden önce federal bölge mahkemesinde bir hukuk ihlal davası açmak.","hi":"किसी भी CBP कार्रवाई के होने से पहले federal district court में एक civil infringement मुकदमा दाखिल करना।","ar":"رفع دعوى مدنية بالمخالفة في محكمة اتحادية ابتدائية قبل أن يتسنّى أي إجراء من CBP."},{"en":"Recording the registered trademark with CBP through its e-Recordation program.","es":"Registrar la marca registrada ante CBP a través de su programa e-Recordation.","ru":"Регистрация зарегистрированного товарного знака в CBP через ее программу e-Recordation.","tr":"Tescilli markayı, e-Recordation programı aracılığıyla CBP'ye kaydettirmek.","hi":"CBP के साथ इसके e-Recordation कार्यक्रम के माध्यम से पंजीकृत ट्रेडमार्क को recording करना।","ar":"تسجيل العلامة التجارية المسجَّلة لدى CBP عبر برنامج e-Recordation الخاص بها."},{"en":"Obtaining an exclusion order from the International Trade Commission under Section 337.","es":"Obtener una orden de exclusión de la International Trade Commission conforme a la Section 337.","ru":"Получение запретительного приказа от Комиссии по международной торговле (ITC) согласно Section 337.","tr":"Section 337 kapsamında International Trade Commission'dan bir dışlama emri (exclusion order) almak.","hi":"Section 337 के तहत International Trade Commission से एक exclusion order प्राप्त करना।","ar":"الحصول على أمر استبعاد من International Trade Commission بموجب Section 337."},{"en":"Posting a single transaction bond equal to the value of the suspected counterfeit goods.","es":"Constituir una fianza de transacción única igual al valor de las mercancías presuntamente falsificadas.","ru":"Внесение гарантии на разовую сделку (single transaction bond), равной стоимости предполагаемых контрафактных товаров.","tr":"Şüpheli sahte malların değerine eşit bir tek işlem teminatı (single transaction bond) yatırmak.","hi":"संदिग्ध नकली माल के मूल्य के बराबर एक single transaction bond जमा करना।","ar":"تقديم سند معاملة واحدة يعادل قيمة البضائع المقلَّدة المشتبه بها."}],"e":{"en":"Under 19 CFR Part 133 (subpart A), CBP border enforcement of trademarks (and copyrights) requires that the USPTO-registered mark be recorded with CBP via its recordation/e-Recordation program. Recordation, not litigation or an ITC order, is the threshold for routine CBP detention/seizure of infringing goods.","es":"Conforme a 19 CFR Part 133 (subpart A), la aplicación fronteriza de CBP respecto a marcas (y derechos de autor) requiere que la marca registrada en la USPTO sea registrada ante CBP a través de su programa de registro/e-Recordation. El registro, no el litigio ni una orden de la ITC, es el umbral para la detención/incautación de rutina de mercancías infractoras por parte de CBP.","ru":"Согласно 19 CFR Part 133 (subpart A), пограничный контроль CBP в отношении товарных знаков (и авторских прав) требует, чтобы зарегистрированный в USPTO знак был зарегистрирован в CBP через ее программу регистрации/e-Recordation. Регистрация, а не судебный процесс или приказ ITC, является пороговым условием для обычного задержания/изъятия CBP контрафактных товаров.","tr":"19 CFR Part 133 (subpart A) kapsamında, markaların (ve telif haklarının) CBP sınır uygulaması, USPTO'da tescilli markanın CBP'ye kayıt/e-Recordation programı aracılığıyla kaydedilmesini gerektirir. İhlal eden malların olağan CBP alıkonması/el konması için eşik, dava veya bir ITC emri değil, kayıttır.","hi":"19 CFR Part 133 (subpart A) के तहत, ट्रेडमार्क (और copyrights) के CBP सीमा प्रवर्तन के लिए आवश्यक है कि USPTO-पंजीकृत चिह्न को CBP के साथ इसके recordation/e-Recordation कार्यक्रम के माध्यम से recorded किया जाए। Recordation, न कि मुकदमेबाजी या एक ITC order, उल्लंघनकारी माल की नियमित CBP रोकथाम/जब्ती के लिए सीमा-कदम है।","ar":"بموجب 19 CFR Part 133 (subpart A)، يقتضي إنفاذ CBP الحدودي للعلامات التجارية (وحقوق النشر) أن تكون العلامة المسجَّلة لدى USPTO مسجَّلةً لدى CBP عبر برنامج التسجيل/e-Recordation الخاص بها. فالتسجيل، لا التقاضي أو أمر ITC، هو الخطوة الأولية للاحتجاز/الضبط الاعتيادي من CBP للبضائع المخالِفة."}},{"cat":"trade","a":2,"q":{"en":"CBP examines a shipment and determines the articles bear a counterfeit version of a trademark that is registered and recorded with CBP, and the recordation owner has not consented to the importation. Absent consent, what is CBP's action under 19 CFR Part 133?","es":"CBP examina un embarque y determina que los artículos llevan una versión falsificada de una marca que está registrada y inscrita ante CBP, y el titular del registro no ha consentido la importación. En ausencia de consentimiento, ¿cuál es la acción de CBP conforme a 19 CFR Part 133?","ru":"CBP досматривает партию и определяет, что изделия несут контрафактную версию товарного знака, который зарегистрирован и внесен в реестр CBP, при этом владелец регистрации не дал согласия на ввоз. При отсутствии согласия каковы действия CBP согласно 19 CFR Part 133?","tr":"CBP bir sevkiyatı inceliyor ve ürünlerin, CBP'de tescilli ve kayıtlı bir markanın sahte bir versiyonunu taşıdığını ve kayıt sahibinin ithalata rıza göstermediğini belirliyor. Rıza yokluğunda, CBP'nin 19 CFR Part 133 kapsamındaki işlemi nedir?","hi":"CBP एक शिपमेंट की जाँच करता है और निर्धारित करता है कि वस्तुओं पर एक ऐसे ट्रेडमार्क का नकली संस्करण है जो CBP के साथ पंजीकृत और recorded है, और recordation मालिक ने आयात के लिए सहमति नहीं दी है। सहमति के अभाव में, 19 CFR Part 133 के तहत CBP की कार्रवाई क्या है?","ar":"تفحص CBP شحنة وتقرّر أن المواد تحمل نسخة مقلَّدة من علامة تجارية مسجَّلة ومسجَّلة لدى CBP، وأن مالك التسجيل لم يوافق على الاستيراد. في غياب الموافقة، ما إجراء CBP بموجب 19 CFR Part 133؟"},"o":[{"en":"Release the goods after assessment of a 10 percent marking duty.","es":"Liberar las mercancías tras la imposición de un derecho de marcado del 10 por ciento.","ru":"Выпустить товары после начисления маркировочной пошлины в размере 10 процентов.","tr":"Yüzde 10'luk bir işaretleme vergisinin tahakkukundan sonra malları serbest bırakır.","hi":"10 प्रतिशत marking duty के आकलन के बाद माल जारी करना।","ar":"الإفراج عن البضائع بعد فرض رسم وسم قدره 10 بالمئة."},{"en":"Permit the importer to obliterate the mark and then enter the goods for consumption.","es":"Permitir al importador borrar la marca y luego declarar las mercancías para consumo.","ru":"Разрешить импортеру удалить знак и затем оформить товары для потребления.","tr":"İthalatçının markayı silmesine ve ardından malları tüketim için beyan etmesine izin verir.","hi":"आयातकर्ता को चिह्न मिटाने और फिर माल को उपभोग के लिए एंटर करने की अनुमति देना।","ar":"السماح للمستورد بطمس العلامة ثم إدخال البضائع للاستهلاك."},{"en":"Seize the merchandise and, absent the owner's written consent, forfeit it under the customs laws.","es":"Incautar la mercancía y, en ausencia del consentimiento escrito del titular, decomisarla conforme a las leyes aduaneras.","ru":"Изъять товары и, при отсутствии письменного согласия владельца, конфисковать их согласно таможенному законодательству.","tr":"Mallara el koyar ve sahibinin yazılı rızası yokluğunda, gümrük yasaları uyarınca müsadere eder.","hi":"माल को जब्त करना और, मालिक की लिखित सहमति के अभाव में, कस्टम कानूनों के तहत उसे जब्ती (forfeit) करना।","ar":"ضبط البضاعة و، في غياب الموافقة الكتابية للمالك، مصادرتها بموجب القوانين الجمركية."},{"en":"Detain the goods for 30 days and then release them if no court order is obtained.","es":"Detener las mercancías por 30 días y luego liberarlas si no se obtiene una orden judicial.","ru":"Задержать товары на 30 дней и затем выпустить их, если не будет получен судебный приказ.","tr":"Malları 30 gün alıkoyar ve ardından herhangi bir mahkeme kararı alınmazsa serbest bırakır.","hi":"माल को 30 दिनों के लिए रोकना और फिर यदि कोई court order प्राप्त न हो तो उसे जारी करना।","ar":"احتجاز البضائع 30 يوماً ثم الإفراج عنها إذا لم يصدر أمر قضائي."}],"e":{"en":"Under 19 CFR 133.21, merchandise bearing a counterfeit mark (a mark identical to or substantially indistinguishable from a registered, recorded mark) is seized and, absent the written consent of the recordation owner, forfeited in accordance with the customs laws. Counterfeit-mark goods are treated more strictly than merely confusingly similar (infringing) goods.","es":"Conforme a 19 CFR 133.21, la mercancía que lleva una marca falsificada (una marca idéntica o sustancialmente indistinguible de una marca registrada e inscrita) se incauta y, en ausencia del consentimiento escrito del titular del registro, se decomisa de acuerdo con las leyes aduaneras. Las mercancías con marca falsificada reciben un trato más estricto que las mercancías meramente similares de manera confusa (infractoras).","ru":"Согласно 19 CFR 133.21, товары, несущие контрафактный знак (знак, идентичный или практически неотличимый от зарегистрированного, внесенного в реестр знака), изымаются и, при отсутствии письменного согласия владельца регистрации, конфискуются в соответствии с таможенным законодательством. Товары с контрафактным знаком рассматриваются строже, чем товары, лишь смешиваемо схожие (нарушающие).","tr":"19 CFR 133.21 kapsamında, sahte bir marka (tescilli, kayıtlı bir markayla aynı veya esaslı olarak ayırt edilemez bir marka) taşıyan mallara el konulur ve kayıt sahibinin yazılı rızası yokluğunda, gümrük yasaları uyarınca müsadere edilir. Sahte markalı mallar, yalnızca karıştırılacak derecede benzer (ihlal eden) mallardan daha katı şekilde ele alınır.","hi":"19 CFR 133.21 के तहत, एक नकली चिह्न (एक पंजीकृत, recorded चिह्न के समान या काफी हद तक अप्रभेद्य चिह्न) वाला माल जब्त किया जाता है और, recordation मालिक की लिखित सहमति के अभाव में, कस्टम कानूनों के अनुसार जब्ती (forfeit) किया जाता है। नकली-चिह्न माल को केवल भ्रामक रूप से समान (उल्लंघनकारी) माल की तुलना में अधिक सख्ती से व्यवहार किया जाता है।","ar":"بموجب 19 CFR 133.21، تُضبَط البضاعة الحاملة لعلامة مقلَّدة (علامة مطابقة أو لا يمكن تمييزها جوهرياً عن علامة مسجَّلة ومسجَّلة لدى CBP) و، في غياب الموافقة الكتابية لمالك التسجيل، تُصادَر وفقاً للقوانين الجمركية. وتُعامَل بضائع العلامات المقلَّدة بصرامة أكبر من البضائع المتشابهة إلى حدّ مربك (المخالِفة) فحسب."}},{"cat":"trade","a":2,"q":{"en":"An importer discovers it underpaid duties due to a classification error and, before CBP has commenced or notified it of any investigation, voluntarily reports the violation and tenders the lost duties. Under 19 CFR 162.74, what is the principal benefit of a valid prior disclosure?","es":"Un importador descubre que pagó derechos de menos debido a un error de clasificación y, antes de que CBP haya iniciado o le haya notificado de cualquier investigación, reporta voluntariamente la infracción y entrega los derechos perdidos. Conforme a 19 CFR 162.74, ¿cuál es el principal beneficio de una divulgación previa (prior disclosure) válida?","ru":"Импортер обнаруживает, что недоплатил пошлины из-за ошибки классификации, и до того, как CBP начала или уведомила его о каком-либо расследовании, добровольно сообщает о нарушении и вносит потерянные пошлины. Согласно 19 CFR 162.74, в чем основная выгода действительного предварительного раскрытия (prior disclosure)?","tr":"Bir ithalatçı, bir sınıflandırma hatası nedeniyle vergileri eksik ödediğini keşfediyor ve CBP herhangi bir soruşturma başlatmadan veya kendisine bildirmeden önce, ihlali gönüllü olarak bildirip kaybedilen vergileri ödüyor. 19 CFR 162.74 kapsamında, geçerli bir önceden açıklamanın (prior disclosure) temel faydası nedir?","hi":"एक आयातकर्ता पता लगाता है कि उसने classification त्रुटि के कारण शुल्क कम चुकाया, और, CBP द्वारा किसी जाँच को शुरू करने या उसे सूचित करने से पहले, स्वेच्छा से उल्लंघन की रिपोर्ट करता है और खोए हुए शुल्क प्रस्तुत करता है। 19 CFR 162.74 के तहत, एक वैध prior disclosure का प्रमुख लाभ क्या है?","ar":"يكتشف مستورد أنه دفع رسوماً أقل من المستحقّ بسبب خطأ في التصنيف، وقبل أن تبدأ CBP أي تحقيق أو تخطره به، يبلّغ طوعاً عن المخالفة ويسدّد الرسوم المفقودة. بموجب 19 CFR 162.74، ما الفائدة الرئيسية للإفصاح المسبق الصحيح؟"},"o":[{"en":"All duties owed are waived entirely as a reward for self-reporting.","es":"Todos los derechos adeudados se condonan por completo como recompensa por autorreportarse.","ru":"Все причитающиеся пошлины полностью прощаются в качестве вознаграждения за самостоятельное сообщение.","tr":"Kendini bildirmenin ödülü olarak borçlu olunan tüm vergiler tamamen affedilir.","hi":"स्व-रिपोर्टिंग के पुरस्कार के रूप में सभी देय शुल्क पूरी तरह से माफ कर दिए जाते हैं।","ar":"يُعفى من جميع الرسوم المستحقة بالكامل مكافأةً على الإبلاغ الذاتي."},{"en":"It eliminates any possibility of a penalty regardless of the level of culpability.","es":"Elimina toda posibilidad de multa sin importar el nivel de culpabilidad.","ru":"Оно устраняет любую возможность штрафа независимо от степени виновности.","tr":"Kusur düzeyinden bağımsız olarak herhangi bir ceza olasılığını ortadan kaldırır.","hi":"यह दोषीता के स्तर की परवाह किए बिना किसी भी जुर्माने की संभावना को समाप्त कर देता है।","ar":"يلغي أي احتمال لفرض غرامة بصرف النظر عن مستوى الذنب."},{"en":"It substantially limits the penalty (e.g., for negligence/gross negligence, to the interest on the loss of duties), provided the actual loss of duties is also tendered.","es":"Limita sustancialmente la multa (por ejemplo, en caso de negligencia/negligencia grave, al interés sobre la pérdida de derechos), siempre que también se entregue la pérdida real de derechos.","ru":"Оно существенно ограничивает штраф (например, при небрежности/грубой небрежности — до процентов на сумму потери пошлин), при условии, что также вносится фактическая сумма потери пошлин.","tr":"Cezayı önemli ölçüde sınırlar (örneğin, ihmal/ağır ihmal için, vergi kaybına ilişkin faizle), gerçek vergi kaybının da ödenmesi şartıyla.","hi":"यह जुर्माने को काफी हद तक सीमित कर देता है (जैसे, negligence/gross negligence के लिए, शुल्क हानि पर ब्याज तक), बशर्ते वास्तविक शुल्क हानि भी प्रस्तुत की जाए।","ar":"يحدّ بشكل كبير من الغرامة (مثلاً، في حالة الإهمال/الإهمال الجسيم، إلى الفائدة على خسارة الرسوم)، شريطة سداد خسارة الرسوم الفعلية أيضاً."},{"en":"It converts a fraud violation into a negligence violation but does not affect the penalty amount.","es":"Convierte una infracción por fraude en una infracción por negligencia pero no afecta el monto de la multa.","ru":"Оно превращает нарушение в форме мошенничества в нарушение в форме небрежности, но не влияет на размер штрафа.","tr":"Bir dolandırıcılık (fraud) ihlalini bir ihmal ihlaline dönüştürür ancak ceza tutarını etkilemez.","hi":"यह एक fraud उल्लंघन को एक negligence उल्लंघन में बदल देता है लेकिन जुर्माने की राशि को प्रभावित नहीं करता।","ar":"يحوّل مخالفة الاحتيال إلى مخالفة إهمال لكنه لا يؤثر في مقدار الغرامة."}],"e":{"en":"Under 19 U.S.C. 1592(c)(4) and 19 CFR 162.74, a valid prior disclosure (made before CBP commences/notifies of a formal investigation), with tender of the actual loss of duties, sharply limits the penalty. For negligence and gross negligence the penalty is limited to the interest on the loss of revenue; for fraud it is reduced to the duty loss (or, for non-revenue cases, a percentage of value). It does not waive the duties themselves.","es":"Conforme a 19 U.S.C. 1592(c)(4) y 19 CFR 162.74, una divulgación previa (prior disclosure) válida (hecha antes de que CBP inicie/notifique una investigación formal), con la entrega de la pérdida real de derechos, limita drásticamente la multa. Para la negligencia y la negligencia grave, la multa se limita al interés sobre la pérdida de ingresos; para el fraude se reduce a la pérdida de derechos (o, en casos sin pérdida de ingresos, a un porcentaje del valor). No condona los derechos en sí.","ru":"Согласно 19 U.S.C. 1592(c)(4) и 19 CFR 162.74, действительное предварительное раскрытие (prior disclosure), сделанное до того, как CBP начинает/уведомляет о формальном расследовании, с внесением фактической суммы потери пошлин, резко ограничивает штраф. При небрежности и грубой небрежности штраф ограничивается процентами на сумму потери доходов; при мошенничестве он снижается до суммы потери пошлин (или, для случаев, не связанных с доходами, до процента от стоимости). Оно не отменяет сами пошлины.","tr":"19 U.S.C. 1592(c)(4) ve 19 CFR 162.74 kapsamında, geçerli bir önceden açıklama (prior disclosure) (CBP resmi bir soruşturma başlatmadan/bildirmeden önce yapılan), gerçek vergi kaybının ödenmesiyle birlikte, cezayı keskin şekilde sınırlar. İhmal ve ağır ihmal için ceza, gelir kaybına ilişkin faizle sınırlıdır; dolandırıcılık (fraud) için ise vergi kaybına indirilir (veya gelir dışı durumlarda, değerin bir yüzdesine). Bu, vergilerin kendisini ortadan kaldırmaz.","hi":"19 U.S.C. 1592(c)(4) और 19 CFR 162.74 के तहत, एक वैध prior disclosure (CBP द्वारा औपचारिक जाँच शुरू/सूचित करने से पहले की गई), वास्तविक शुल्क हानि की प्रस्तुति के साथ, जुर्माने को तेजी से सीमित कर देती है। negligence और gross negligence के लिए जुर्माना राजस्व हानि पर ब्याज तक सीमित है; fraud के लिए इसे शुल्क हानि तक घटा दिया जाता है (या, गैर-राजस्व मामलों के लिए, मूल्य के एक प्रतिशत तक)। यह शुल्कों को स्वयं माफ नहीं करता।","ar":"بموجب 19 U.S.C. 1592(c)(4) و19 CFR 162.74، يحدّ الإفصاح المسبق الصحيح (المُقدَّم قبل أن تبدأ CBP تحقيقاً رسمياً أو تخطر به)، مع سداد خسارة الرسوم الفعلية، من الغرامة حدّاً كبيراً. ففي حالة الإهمال والإهمال الجسيم تقتصر الغرامة على الفائدة على خسارة الإيرادات؛ وفي حالة الاحتيال تُخفَّض إلى خسارة الرسوم (أو، في القضايا غير الإيرادية، نسبة مئوية من القيمة). ولا يعفي ذلك من الرسوم نفسها."}},{"cat":"entry","a":3,"q":{"en":"Which CBP form is the standard form used to file the entry summary for merchandise formally entered for consumption?","es":"¿Qué formulario de CBP es el formulario estándar utilizado para presentar el resumen de entrada de mercancía formalmente ingresada para consumo?","ru":"Какая форма CBP является стандартной формой, используемой для подачи итоговой декларации (entry summary) на товары, формально ввезённые для потребления?","tr":"Tüketim için resmi olarak giriş yapılan eşyaya ilişkin giriş özetini (entry summary) sunmak için kullanılan standart CBP formu hangisidir?","hi":"उपभोग के लिए औपचारिक रूप से प्रविष्ट माल के लिए एंट्री सारांश (entry summary) दाखिल करने हेतु उपयोग किया जाने वाला मानक CBP फॉर्म कौन सा है?","ar":"ما هي استمارة CBP القياسية المستخدمة لتقديم ملخص الإدخال (entry summary) للبضائع المُدخلة رسميًا بغرض الاستهلاك؟"},"o":[{"en":"CBP Form 301","es":"CBP Form 301","ru":"CBP Form 301","tr":"CBP Form 301","hi":"CBP Form 301","ar":"CBP Form 301"},{"en":"CBP Form 3461","es":"CBP Form 3461","ru":"CBP Form 3461","tr":"CBP Form 3461","hi":"CBP Form 3461","ar":"CBP Form 3461"},{"en":"CBP Form 7533","es":"CBP Form 7533","ru":"CBP Form 7533","tr":"CBP Form 7533","hi":"CBP Form 7533","ar":"CBP Form 7533"},{"en":"CBP Form 7501","es":"CBP Form 7501","ru":"CBP Form 7501","tr":"CBP Form 7501","hi":"CBP Form 7501","ar":"CBP Form 7501"}],"e":{"en":"Under 19 CFR 142.11 and 142.3(b), the entry summary for formal consumption entries must be on CBP Form 7501 (or its electronic equivalent). CBP Form 3461 is the entry/release document, 7533 is used for in-bond entries from contiguous countries, and 301 is the bond form.","es":"Conforme a 19 CFR 142.11 y 142.3(b), el resumen de entrada para las entradas formales de consumo debe presentarse en el CBP Form 7501 (o su equivalente electrónico). El CBP Form 3461 es el documento de entrada/liberación, el 7533 se usa para entradas en tránsito aduanero (in-bond) desde países contiguos, y el 301 es el formulario de fianza.","ru":"Согласно 19 CFR 142.11 и 142.3(b), итоговая декларация для формальных потребительских деклараций должна оформляться на CBP Form 7501 (или его электронном эквиваленте). CBP Form 3461 — это документ ввоза/выпуска, 7533 используется для транзитных (in-bond) деклараций из сопредельных стран, а 301 — это форма поручительства (bond).","tr":"19 CFR 142.11 ve 142.3(b) uyarınca, resmi tüketim girişlerine ait giriş özeti CBP Form 7501 (veya elektronik eşdeğeri) üzerinde olmalıdır. CBP Form 3461 giriş/teslim belgesidir, 7533 komşu ülkelerden gelen in-bond (gümrük gözetiminde taşıma) girişleri için kullanılır ve 301 teminat (bond) formudur.","hi":"19 CFR 142.11 और 142.3(b) के अंतर्गत, औपचारिक उपभोग प्रविष्टियों के लिए एंट्री सारांश CBP Form 7501 (या उसके इलेक्ट्रॉनिक समतुल्य) पर होना चाहिए। CBP Form 3461 प्रविष्टि/रिलीज़ दस्तावेज़ है, 7533 का उपयोग संलग्न देशों से इन-बॉन्ड प्रविष्टियों के लिए होता है, और 301 बॉन्ड फॉर्म है।","ar":"بموجب 19 CFR 142.11 و142.3(b)، يجب أن يكون ملخص الإدخال لإدخالات الاستهلاك الرسمية على استمارة CBP Form 7501 (أو ما يعادلها إلكترونيًا). أما CBP Form 3461 فهي مستند الإدخال/الإفراج، و7533 تُستخدم للإدخالات تحت التعهد (in-bond) من الدول المتاخمة، و301 هي استمارة التعهد (bond)."}},{"cat":"entry","a":1,"q":{"en":"Generally, merchandise valued at what amount or less may be entered under an informal entry rather than a formal entry?","es":"En general, ¿la mercancía valorada en qué monto o menos puede ingresarse mediante una entrada informal en lugar de una entrada formal?","ru":"Как правило, товары стоимостью какой суммы или менее могут быть оформлены по неформальной декларации (informal entry) вместо формальной?","tr":"Genel olarak, hangi tutar veya daha az değerdeki eşya, resmi giriş yerine gayri resmi giriş (informal entry) ile giriş yapılabilir?","hi":"सामान्यतः, किस मूल्य या उससे कम के माल को औपचारिक प्रविष्टि के बजाय अनौपचारिक प्रविष्टि (informal entry) के अंतर्गत प्रविष्ट किया जा सकता है?","ar":"بشكل عام، ما هي قيمة البضائع التي تساوي مبلغًا معينًا أو أقل والتي يمكن إدخالها عبر إدخال غير رسمي (informal entry) بدلًا من الإدخال الرسمي؟"},"o":[{"en":"$10,000 or less","es":"$10,000 o menos","ru":"$10,000 или менее","tr":"$10,000 veya daha az","hi":"$10,000 या उससे कम","ar":"$10,000 أو أقل"},{"en":"$2,500 or less","es":"$2,500 o menos","ru":"$2,500 или менее","tr":"$2,500 veya daha az","hi":"$2,500 या उससे कम","ar":"$2,500 أو أقل"},{"en":"$2,000 or less","es":"$2,000 o menos","ru":"$2,000 или менее","tr":"$2,000 veya daha az","hi":"$2,000 या उससे कम","ar":"$2,000 أو أقل"},{"en":"$800 or less","es":"$800 o menos","ru":"$800 или менее","tr":"$800 veya daha az","hi":"$800 या उससे कम","ar":"$800 أو أقل"}],"e":{"en":"Under 19 CFR 143.21, shipments not exceeding $2,500 in value generally may be entered informally (subject to exceptions for certain Chapter 99 articles and goods needing examination). The $800 figure is the Section 321 de minimis administrative exemption, a separate concept.","es":"Conforme a 19 CFR 143.21, los envíos cuyo valor no exceda de $2,500 generalmente pueden ingresarse de manera informal (con excepciones para ciertos artículos del Capítulo 99 y mercancías que requieren examen). La cifra de $800 corresponde a la exención administrativa de minimis de la Sección 321, un concepto distinto.","ru":"Согласно 19 CFR 143.21, партии стоимостью не более $2,500, как правило, могут оформляться неформально (за исключением некоторых товаров Главы 99 и товаров, требующих досмотра). Сумма $800 относится к административному освобождению de minimis по Section 321 — это отдельное понятие.","tr":"19 CFR 143.21 uyarınca, değeri $2,500'ı aşmayan sevkiyatlar genellikle gayri resmi olarak giriş yapılabilir (belirli Bölüm 99 eşyaları ve muayene gerektiren mallar için istisnalara tabidir). $800 rakamı, Section 321 de minimis idari muafiyeti olup ayrı bir kavramdır.","hi":"19 CFR 143.21 के अंतर्गत, $2,500 से अधिक मूल्य न रखने वाले शिपमेंट सामान्यतः अनौपचारिक रूप से प्रविष्ट किए जा सकते हैं (कुछ अध्याय 99 के सामान और जाँच की आवश्यकता वाले माल के अपवादों के अधीन)। $800 का आँकड़ा Section 321 की de minimis प्रशासनिक छूट है, जो एक अलग अवधारणा है।","ar":"بموجب 19 CFR 143.21، يجوز عمومًا إدخال الشحنات التي لا تتجاوز قيمتها $2,500 بشكل غير رسمي (مع استثناءات لبعض أصناف الفصل 99 والبضائع التي تحتاج إلى فحص). أما رقم $800 فهو الإعفاء الإداري الأدنى (de minimis) بموجب Section 321، وهو مفهوم منفصل."}},{"cat":"entry","a":2,"q":{"en":"Within how many calendar days after landing (or after arrival at the port of destination for in-bond merchandise) must entry generally be made?","es":"¿Dentro de cuántos días calendario después del desembarque (o después de la llegada al puerto de destino para mercancía in-bond) debe hacerse generalmente la entrada?","ru":"В течение скольких календарных дней после выгрузки (или после прибытия в порт назначения для транзитных in-bond товаров) обычно должна быть оформлена декларация?","tr":"Giriş genellikle, eşyanın karaya çıkarılmasından (veya in-bond eşya için varış limanına ulaşılmasından) sonra kaç takvim günü içinde yapılmalıdır?","hi":"उतराई के बाद (या इन-बॉन्ड माल के लिए गंतव्य बंदरगाह पर आगमन के बाद) सामान्यतः कितने कैलेंडर दिनों के भीतर प्रविष्टि की जानी चाहिए?","ar":"خلال كم يومًا تقويميًا بعد التفريغ (أو بعد الوصول إلى ميناء الوجهة بالنسبة للبضائع تحت التعهد in-bond) يجب عمومًا إجراء الإدخال؟"},"o":[{"en":"20 calendar days","es":"20 días calendario","ru":"20 календарных дней","tr":"20 takvim günü","hi":"20 कैलेंडर दिन","ar":"20 يومًا تقويميًا"},{"en":"10 calendar days","es":"10 días calendario","ru":"10 календарных дней","tr":"10 takvim günü","hi":"10 कैलेंडर दिन","ar":"10 أيام تقويمية"},{"en":"15 calendar days","es":"15 días calendario","ru":"15 календарных дней","tr":"15 takvim günü","hi":"15 कैलेंडर दिन","ar":"15 يومًا تقويميًا"},{"en":"30 calendar days","es":"30 días calendario","ru":"30 календарных дней","tr":"30 takvim günü","hi":"30 कैलेंडर दिन","ar":"30 يومًا تقويميًا"}],"e":{"en":"19 CFR 141.5 requires that merchandise for which entry is required be entered within 15 calendar days after landing from a vessel, aircraft, or vehicle, or after arrival at the port of destination for in-bond merchandise. Merchandise not timely entered goes to general order.","es":"19 CFR 141.5 exige que la mercancía para la cual se requiere entrada sea ingresada dentro de los 15 días calendario después del desembarque de una embarcación, aeronave o vehículo, o después de la llegada al puerto de destino para mercancía in-bond. La mercancía no ingresada a tiempo pasa a orden general (general order).","ru":"19 CFR 141.5 требует, чтобы товары, подлежащие декларированию, были задекларированы в течение 15 календарных дней после выгрузки с судна, воздушного судна или транспортного средства, либо после прибытия в порт назначения для транзитных in-bond товаров. Товары, не задекларированные своевременно, передаются на хранение (general order).","tr":"19 CFR 141.5, giriş yapılması gereken eşyanın bir gemi, hava aracı veya kara aracından karaya çıkarılmasından sonra ya da in-bond eşya için varış limanına ulaşılmasından sonra 15 takvim günü içinde giriş yapılmasını gerektirir. Zamanında giriş yapılmayan eşya genel ambara (general order) alınır.","hi":"19 CFR 141.5 के अनुसार जिस माल के लिए प्रविष्टि आवश्यक है, उसे जहाज, विमान या वाहन से उतारने के बाद, या इन-बॉन्ड माल के लिए गंतव्य बंदरगाह पर आगमन के बाद 15 कैलेंडर दिनों के भीतर प्रविष्ट किया जाना चाहिए। समय पर प्रविष्ट न किया गया माल सामान्य आदेश (general order) में चला जाता है।","ar":"تتطلب 19 CFR 141.5 أن تُدخل البضائع التي يلزم إدخالها خلال 15 يومًا تقويميًا بعد تفريغها من سفينة أو طائرة أو مركبة، أو بعد الوصول إلى ميناء الوجهة بالنسبة للبضائع تحت التعهد in-bond. والبضائع التي لا تُدخل في الوقت المناسب تُحال إلى الأمر العام (general order)."}},{"cat":"entry","a":0,"q":{"en":"When entry documentation is filed in proper form WITHOUT an entry summary, within how many working days after the time of entry must the entry summary documentation be filed with estimated duties attached?","es":"Cuando la documentación de entrada se presenta en forma debida SIN un resumen de entrada, ¿dentro de cuántos días hábiles después del momento de la entrada debe presentarse la documentación del resumen de entrada con los derechos estimados adjuntos?","ru":"Если документация ввоза подаётся в надлежащей форме БЕЗ итоговой декларации, в течение скольких рабочих дней после момента ввоза должна быть подана документация итоговой декларации с приложенными оценочными пошлинами?","tr":"Giriş belgeleri usulüne uygun olarak ancak giriş özeti OLMADAN sunulduğunda, giriş özeti belgeleri tahmini gümrük vergileri eklenmiş olarak giriş anından sonra kaç iş günü içinde sunulmalıdır?","hi":"जब प्रविष्टि दस्तावेज़ उचित रूप में एंट्री सारांश के बिना दाखिल किए जाते हैं, तो प्रविष्टि के समय के बाद कितने कार्य दिवसों के भीतर अनुमानित शुल्क संलग्न करके एंट्री सारांश दस्तावेज़ दाखिल किए जाने चाहिए?","ar":"عندما تُقدَّم مستندات الإدخال بالشكل الصحيح دون ملخص إدخال، خلال كم يوم عمل بعد وقت الإدخال يجب تقديم مستندات ملخص الإدخال مع الرسوم المقدَّرة المرفقة؟"},"o":[{"en":"10 working days","es":"10 días hábiles","ru":"10 рабочих дней","tr":"10 iş günü","hi":"10 कार्य दिवस","ar":"10 أيام عمل"},{"en":"15 working days","es":"15 días hábiles","ru":"15 рабочих дней","tr":"15 iş günü","hi":"15 कार्य दिवस","ar":"15 يوم عمل"},{"en":"5 working days","es":"5 días hábiles","ru":"5 рабочих дней","tr":"5 iş günü","hi":"5 कार्य दिवस","ar":"5 أيام عمل"},{"en":"30 working days","es":"30 días hábiles","ru":"30 рабочих дней","tr":"30 iş günü","hi":"30 कार्य दिवस","ar":"30 يوم عمل"}],"e":{"en":"Under 19 CFR 142.12(b)(1), if the entry summary is not filed at the time of entry, it must be filed, with estimated duties attached, within 10 working days after the time of entry.","es":"Conforme a 19 CFR 142.12(b)(1), si el resumen de entrada no se presenta en el momento de la entrada, debe presentarse, con los derechos estimados adjuntos, dentro de los 10 días hábiles después del momento de la entrada.","ru":"Согласно 19 CFR 142.12(b)(1), если итоговая декларация не подана в момент ввоза, она должна быть подана с приложенными оценочными пошлинами в течение 10 рабочих дней после момента ввоза.","tr":"19 CFR 142.12(b)(1) uyarınca, giriş özeti giriş anında sunulmazsa, tahmini gümrük vergileri eklenmiş olarak giriş anından sonra 10 iş günü içinde sunulmalıdır.","hi":"19 CFR 142.12(b)(1) के अंतर्गत, यदि एंट्री सारांश प्रविष्टि के समय दाखिल नहीं किया जाता, तो उसे अनुमानित शुल्क संलग्न करके प्रविष्टि के समय के बाद 10 कार्य दिवसों के भीतर दाखिल किया जाना चाहिए।","ar":"بموجب 19 CFR 142.12(b)(1)، إذا لم يُقدَّم ملخص الإدخال في وقت الإدخال، فيجب تقديمه مع الرسوم المقدَّرة المرفقة خلال 10 أيام عمل بعد وقت الإدخال."}},{"cat":"entry","a":1,"q":{"en":"An entry that is not liquidated within what period from the date of entry is, absent extension or suspension, deemed liquidated at the rate, value, quantity, and duty asserted by the importer of record?","es":"Una entrada que no se liquida dentro de qué período a partir de la fecha de entrada, en ausencia de prórroga o suspensión, se considera liquidada según la tasa, el valor, la cantidad y el derecho declarados por el importador registrado (importer of record)?","ru":"Декларация, не ликвидированная (liquidated) в течение какого срока с даты ввоза, при отсутствии продления или приостановления считается ликвидированной по ставке, стоимости, количеству и пошлине, заявленным импортёром-регистрантом (importer of record)?","tr":"Giriş tarihinden itibaren hangi süre içinde tasfiye (liquidation) edilmeyen bir giriş, uzatma veya askıya alma olmaması halinde, kayıtlı ithalatçının (importer of record) beyan ettiği oran, değer, miktar ve gümrük vergisi üzerinden tasfiye edilmiş sayılır?","hi":"जो प्रविष्टि प्रविष्टि की तारीख से किस अवधि के भीतर परिनिर्धारित (liquidated) नहीं की जाती, उसे विस्तार या निलंबन के अभाव में, रिकॉर्ड के आयातक (importer of record) द्वारा घोषित दर, मूल्य, मात्रा और शुल्क पर परिनिर्धारित माना जाता है?","ar":"الإدخال الذي لا تتم تصفيته (liquidation) خلال أي مدة من تاريخ الإدخال، في حال عدم وجود تمديد أو تعليق، يُعتبر مُصفّى وفقًا للمعدل والقيمة والكمية والرسم الذي أعلنه المستورد المسجّل (importer of record)؟"},"o":[{"en":"4 years","es":"4 años","ru":"4 года","tr":"4 yıl","hi":"4 वर्ष","ar":"4 سنوات"},{"en":"1 year","es":"1 año","ru":"1 год","tr":"1 yıl","hi":"1 वर्ष","ar":"سنة واحدة"},{"en":"6 months","es":"6 meses","ru":"6 месяцев","tr":"6 ay","hi":"6 महीने","ar":"6 أشهر"},{"en":"2 years","es":"2 años","ru":"2 года","tr":"2 yıl","hi":"2 वर्ष","ar":"سنتان"}],"e":{"en":"Under 19 USC 1504(a), an entry not liquidated within 1 year from the date of entry is deemed liquidated by operation of law at the rate, value, quantity, and amount of duty asserted by the importer of record at the time of entry, unless extended or suspended.","es":"Conforme a 19 USC 1504(a), una entrada no liquidada dentro de 1 año a partir de la fecha de entrada se considera liquidada por ministerio de la ley según la tasa, el valor, la cantidad y el monto del derecho declarados por el importador registrado al momento de la entrada, salvo que se prorrogue o suspenda.","ru":"Согласно 19 USC 1504(a), декларация, не ликвидированная в течение 1 года с даты ввоза, считается ликвидированной в силу закона по ставке, стоимости, количеству и сумме пошлины, заявленным импортёром-регистрантом на момент ввоза, если срок не продлён или не приостановлен.","tr":"19 USC 1504(a) uyarınca, giriş tarihinden itibaren 1 yıl içinde tasfiye edilmeyen bir giriş, uzatılmadıkça veya askıya alınmadıkça, kayıtlı ithalatçının giriş anında beyan ettiği oran, değer, miktar ve gümrük vergisi tutarı üzerinden kanun gereği tasfiye edilmiş sayılır.","hi":"19 USC 1504(a) के अंतर्गत, जो प्रविष्टि प्रविष्टि की तारीख से 1 वर्ष के भीतर परिनिर्धारित नहीं की जाती, उसे विधि के प्रवर्तन से, रिकॉर्ड के आयातक द्वारा प्रविष्टि के समय घोषित दर, मूल्य, मात्रा और शुल्क की राशि पर परिनिर्धारित माना जाता है, जब तक कि उसे विस्तारित या निलंबित न किया गया हो।","ar":"بموجب 19 USC 1504(a)، فإن الإدخال الذي لا تتم تصفيته خلال سنة واحدة من تاريخ الإدخال يُعتبر مُصفّى بحكم القانون وفقًا للمعدل والقيمة والكمية ومقدار الرسم الذي أعلنه المستورد المسجّل وقت الإدخال، ما لم يُمدَّد أو يُعلَّق."}},{"cat":"entry","a":2,"q":{"en":"A power of attorney granted by a partnership to a customs broker for the purpose of making entry is limited to a maximum period of:","es":"Un poder otorgado por una sociedad colectiva (partnership) a un agente de aduanas con el fin de hacer la entrada está limitado a un período máximo de:","ru":"Доверенность, выданная партнёрством (partnership) таможенному брокеру для целей оформления декларации, ограничена максимальным сроком:","tr":"Bir ortaklığın (partnership) giriş yapma amacıyla bir gümrük müşavirine verdiği vekaletname en fazla şu süre ile sınırlıdır:","hi":"प्रविष्टि करने के उद्देश्य से किसी साझेदारी (partnership) द्वारा सीमा शुल्क दलाल को दिया गया मुख्तारनामा (power of attorney) अधिकतम किस अवधि तक सीमित होता है:","ar":"إن التوكيل الممنوح من شركة تضامن (partnership) لوسيط جمركي بغرض إجراء الإدخال يكون محدودًا بمدة أقصاها:"},"o":[{"en":"1 year from the date of execution","es":"1 año a partir de la fecha de su otorgamiento","ru":"1 год с даты оформления","tr":"düzenlendiği tarihten itibaren 1 yıl","hi":"निष्पादन की तारीख से 1 वर्ष","ar":"سنة واحدة من تاريخ التحرير"},{"en":"An unlimited period","es":"Un período ilimitado","ru":"Неограниченный срок","tr":"Sınırsız bir süre","hi":"एक असीमित अवधि","ar":"مدة غير محدودة"},{"en":"2 years from the date of execution","es":"2 años a partir de la fecha de su otorgamiento","ru":"2 года с даты оформления","tr":"düzenlendiği tarihten itibaren 2 yıl","hi":"निष्पादन की तारीख से 2 वर्ष","ar":"سنتان من تاريخ التحرير"},{"en":"5 years from the date of execution","es":"5 años a partir de la fecha de su otorgamiento","ru":"5 лет с даты оформления","tr":"düzenlendiği tarihten itibaren 5 yıl","hi":"निष्पादन की तारीख से 5 वर्ष","ar":"5 سنوات من تاريخ التحرير"}],"e":{"en":"Under 19 CFR 141.34, a power of attorney issued by a partnership is limited to a period not to exceed 2 years from the date of execution. Powers of attorney granted by corporations and other principals may be for an unlimited period.","es":"Conforme a 19 CFR 141.34, un poder emitido por una sociedad colectiva está limitado a un período que no exceda de 2 años a partir de la fecha de su otorgamiento. Los poderes otorgados por sociedades anónimas y otros poderdantes pueden ser por un período ilimitado.","ru":"Согласно 19 CFR 141.34, доверенность, выданная партнёрством, ограничена сроком, не превышающим 2 года с даты оформления. Доверенности, выданные корпорациями и иными доверителями, могут быть бессрочными.","tr":"19 CFR 141.34 uyarınca, bir ortaklık tarafından düzenlenen vekaletname, düzenlendiği tarihten itibaren 2 yılı aşmayacak bir süreyle sınırlıdır. Şirketler ve diğer asiller tarafından verilen vekaletnameler sınırsız bir süre için olabilir.","hi":"19 CFR 141.34 के अंतर्गत, किसी साझेदारी द्वारा जारी मुख्तारनामा निष्पादन की तारीख से 2 वर्ष से अधिक न होने वाली अवधि तक सीमित होता है। निगमों और अन्य मूलधारकों द्वारा दिए गए मुख्तारनामे असीमित अवधि के लिए हो सकते हैं।","ar":"بموجب 19 CFR 141.34، فإن التوكيل الصادر عن شركة تضامن يكون محدودًا بمدة لا تتجاوز سنتين من تاريخ التحرير. أما التوكيلات الممنوحة من الشركات المساهمة وغيرها من الموكِّلين فيمكن أن تكون لمدة غير محدودة."}},{"cat":"entry","a":1,"q":{"en":"Which CBP form is used as the application for a special permit for immediate delivery?","es":"¿Qué formulario de CBP se utiliza como solicitud de un permiso especial para entrega inmediata (immediate delivery)?","ru":"Какая форма CBP используется в качестве заявления на специальное разрешение на немедленную выдачу (immediate delivery)?","tr":"Acil teslim (immediate delivery) için özel izin başvurusu olarak hangi CBP formu kullanılır?","hi":"तत्काल सुपुर्दगी (immediate delivery) के लिए विशेष परमिट के आवेदन के रूप में कौन सा CBP फॉर्म उपयोग किया जाता है?","ar":"ما هي استمارة CBP المستخدمة كطلب للحصول على تصريح خاص بالتسليم الفوري (immediate delivery)؟"},"o":[{"en":"CBP Form 7512","es":"CBP Form 7512","ru":"CBP Form 7512","tr":"CBP Form 7512","hi":"CBP Form 7512","ar":"CBP Form 7512"},{"en":"CBP Form 3461","es":"CBP Form 3461","ru":"CBP Form 3461","tr":"CBP Form 3461","hi":"CBP Form 3461","ar":"CBP Form 3461"},{"en":"CBP Form 5106","es":"CBP Form 5106","ru":"CBP Form 5106","tr":"CBP Form 5106","hi":"CBP Form 5106","ar":"CBP Form 5106"},{"en":"CBP Form 7501","es":"CBP Form 7501","ru":"CBP Form 7501","tr":"CBP Form 7501","hi":"CBP Form 7501","ar":"CBP Form 7501"}],"e":{"en":"Under 19 CFR 142.22(a), an application for a special permit for immediate delivery is made on CBP Form 3461 (or its electronic equivalent), supported by the documentation provided for in 19 CFR 142.3. The 7501 is the entry summary; 7512 is the in-bond transportation form.","es":"Conforme a 19 CFR 142.22(a), la solicitud de un permiso especial para entrega inmediata se hace en el CBP Form 3461 (o su equivalente electrónico), respaldada por la documentación prevista en 19 CFR 142.3. El 7501 es el resumen de entrada; el 7512 es el formulario de transporte in-bond.","ru":"Согласно 19 CFR 142.22(a), заявление на специальное разрешение на немедленную выдачу подаётся на CBP Form 3461 (или его электронном эквиваленте) с документацией, предусмотренной в 19 CFR 142.3. Форма 7501 — это итоговая декларация; 7512 — форма транзитной перевозки (in-bond).","tr":"19 CFR 142.22(a) uyarınca, acil teslim için özel izin başvurusu, 19 CFR 142.3'te öngörülen belgelerle desteklenerek CBP Form 3461 (veya elektronik eşdeğeri) üzerinde yapılır. 7501 giriş özetidir; 7512 ise in-bond taşıma formudur.","hi":"19 CFR 142.22(a) के अंतर्गत, तत्काल सुपुर्दगी के लिए विशेष परमिट का आवेदन CBP Form 3461 (या उसके इलेक्ट्रॉनिक समतुल्य) पर किया जाता है, जो 19 CFR 142.3 में प्रावधानित दस्तावेज़ों द्वारा समर्थित होता है। 7501 एंट्री सारांश है; 7512 इन-बॉन्ड परिवहन फॉर्म है।","ar":"بموجب 19 CFR 142.22(a)، يُقدَّم طلب التصريح الخاص بالتسليم الفوري على استمارة CBP Form 3461 (أو ما يعادلها إلكترونيًا)، مدعومًا بالمستندات المنصوص عليها في 19 CFR 142.3. واستمارة 7501 هي ملخص الإدخال؛ و7512 هي استمارة النقل تحت التعهد (in-bond)."}},{"cat":"entry","a":3,"q":{"en":"Under the immediate delivery procedure, within how many working days after merchandise is authorized for release must the entry summary documentation be filed and estimated duties deposited (or within the quota period, whichever expires first)?","es":"Bajo el procedimiento de entrega inmediata, ¿dentro de cuántos días hábiles después de que la mercancía sea autorizada para su liberación debe presentarse la documentación del resumen de entrada y depositarse los derechos estimados (o dentro del período de cuota, lo que expire primero)?","ru":"В рамках процедуры немедленной выдачи в течение скольких рабочих дней после того, как товары разрешены к выпуску, должна быть подана документация итоговой декларации и внесены оценочные пошлины (или в пределах квотного периода, в зависимости от того, что истечёт раньше)?","tr":"Acil teslim prosedürü kapsamında, eşyanın teslimine izin verilmesinden sonra giriş özeti belgeleri kaç iş günü içinde sunulmalı ve tahmini gümrük vergileri yatırılmalıdır (veya kota süresi içinde, hangisi önce sona ererse)?","hi":"तत्काल सुपुर्दगी प्रक्रिया के अंतर्गत, माल को रिलीज़ के लिए अधिकृत किए जाने के बाद कितने कार्य दिवसों के भीतर एंट्री सारांश दस्तावेज़ दाखिल किए जाने और अनुमानित शुल्क जमा किए जाने चाहिए (या कोटा अवधि के भीतर, जो भी पहले समाप्त हो)?","ar":"في إطار إجراء التسليم الفوري، خلال كم يوم عمل بعد الإذن بالإفراج عن البضائع يجب تقديم مستندات ملخص الإدخال وإيداع الرسوم المقدَّرة (أو خلال فترة الحصة الكمية، أيهما ينتهي أولًا)؟"},"o":[{"en":"15 working days","es":"15 días hábiles","ru":"15 рабочих дней","tr":"15 iş günü","hi":"15 कार्य दिवस","ar":"15 يوم عمل"},{"en":"5 working days","es":"5 días hábiles","ru":"5 рабочих дней","tr":"5 iş günü","hi":"5 कार्य दिवस","ar":"5 أيام عمل"},{"en":"20 working days","es":"20 días hábiles","ru":"20 рабочих дней","tr":"20 iş günü","hi":"20 कार्य दिवस","ar":"20 يوم عمل"},{"en":"10 working days","es":"10 días hábiles","ru":"10 рабочих дней","tr":"10 iş günü","hi":"10 कार्य दिवस","ar":"10 أيام عمل"}],"e":{"en":"Under 19 CFR 142.23, after release under a special permit for immediate delivery, the entry summary documentation must be filed and estimated duties deposited within 10 working days after release, or within the quota period for quota-class merchandise, whichever expires first.","es":"Conforme a 19 CFR 142.23, tras la liberación bajo un permiso especial para entrega inmediata, la documentación del resumen de entrada debe presentarse y los derechos estimados depositarse dentro de los 10 días hábiles después de la liberación, o dentro del período de cuota para mercancía sujeta a cuota, lo que expire primero.","ru":"Согласно 19 CFR 142.23, после выпуска по специальному разрешению на немедленную выдачу документация итоговой декларации должна быть подана и оценочные пошлины внесены в течение 10 рабочих дней после выпуска или в пределах квотного периода для товаров квотного класса, в зависимости от того, что истечёт раньше.","tr":"19 CFR 142.23 uyarınca, acil teslim için özel izin kapsamında yapılan teslimden sonra, giriş özeti belgeleri sunulmalı ve tahmini gümrük vergileri teslimden sonra 10 iş günü içinde veya kota sınıfı eşya için kota süresi içinde, hangisi önce sona ererse, yatırılmalıdır.","hi":"19 CFR 142.23 के अंतर्गत, तत्काल सुपुर्दगी के विशेष परमिट के तहत रिलीज़ के बाद, एंट्री सारांश दस्तावेज़ दाखिल किए जाने और अनुमानित शुल्क रिलीज़ के बाद 10 कार्य दिवसों के भीतर, या कोटा-श्रेणी के माल के लिए कोटा अवधि के भीतर, जो भी पहले समाप्त हो, जमा किए जाने चाहिए।","ar":"بموجب 19 CFR 142.23، بعد الإفراج بموجب تصريح خاص بالتسليم الفوري، يجب تقديم مستندات ملخص الإدخال وإيداع الرسوم المقدَّرة خلال 10 أيام عمل بعد الإفراج، أو خلال فترة الحصة الكمية بالنسبة للبضائع الخاضعة للحصص، أيهما ينتهي أولًا."}},{"cat":"entry","a":1,"q":{"en":"The liability for duties accruing on imported merchandise constitutes, as to the importer, what kind of obligation to the United States?","es":"La responsabilidad por los derechos que se devengan sobre la mercancía importada constituye, respecto del importador, ¿qué tipo de obligación frente a los Estados Unidos?","ru":"Обязательство по уплате пошлин, начисляемых на импортируемые товары, представляет собой для импортёра какого рода обязательство перед Соединёнными Штатами?","tr":"İthal edilen eşya üzerinde tahakkuk eden gümrük vergilerine ilişkin sorumluluk, ithalatçı açısından Amerika Birleşik Devletleri'ne karşı ne tür bir yükümlülük oluşturur?","hi":"आयातित माल पर अर्जित होने वाले शुल्कों का दायित्व, आयातक के संबंध में, संयुक्त राज्य अमेरिका के प्रति किस प्रकार का दायित्व बनाता है?","ar":"إن المسؤولية عن الرسوم المستحقة على البضائع المستوردة تشكّل، بالنسبة للمستورد، أي نوع من الالتزام تجاه الولايات المتحدة؟"},"o":[{"en":"A contingent obligation of the surety alone","es":"Una obligación contingente únicamente del fiador (surety)","ru":"Условное обязательство одного лишь поручителя (surety)","tr":"Yalnızca kefilin (surety) koşullu bir yükümlülüğü","hi":"केवल जमानतदार (surety) का एक आकस्मिक दायित्व","ar":"التزام مشروط يقع على الكفيل (surety) وحده"},{"en":"A personal debt dischargeable only by payment in full","es":"Una deuda personal que solo puede saldarse mediante el pago total","ru":"Личный долг, погашаемый только полной оплатой","tr":"Yalnızca tam ödeme ile ifa edilebilen kişisel bir borç","hi":"एक व्यक्तिगत ऋण जो केवल पूर्ण भुगतान द्वारा ही चुकाया जा सकता है","ar":"دين شخصي لا يُسدَّد إلا بالدفع الكامل"},{"en":"A lien limited to the value of the goods","es":"Un gravamen limitado al valor de la mercancía","ru":"Залоговое право, ограниченное стоимостью товара","tr":"Eşyanın değeriyle sınırlı bir rehin hakkı","hi":"माल के मूल्य तक सीमित एक ग्रहणाधिकार (lien)","ar":"حق امتياز محدود بقيمة البضائع"},{"en":"A penalty subject to mitigation","es":"Una sanción sujeta a mitigación","ru":"Штраф, подлежащий смягчению","tr":"Hafifletmeye tabi bir ceza","hi":"शमन (mitigation) के अधीन एक दंड","ar":"غرامة قابلة للتخفيف"}],"e":{"en":"Under 19 CFR 141.1(b), the liability for duties, both regular and additional, constitutes a personal debt due from the importer to the United States that can be discharged only by payment in full of all duties legally accruing, unless relieved by law or regulation; payment to a broker does not relieve the importer.","es":"Conforme a 19 CFR 141.1(b), la responsabilidad por los derechos, tanto regulares como adicionales, constituye una deuda personal del importador frente a los Estados Unidos que solo puede saldarse mediante el pago total de todos los derechos legalmente devengados, salvo que la ley o el reglamento la exoneren; el pago a un agente no exonera al importador.","ru":"Согласно 19 CFR 141.1(b), обязательство по уплате пошлин, как обычных, так и дополнительных, представляет собой личный долг импортёра перед Соединёнными Штатами, который может быть погашен только полной уплатой всех законно начисленных пошлин, если он не освобождён законом или нормативным актом; оплата брокеру не освобождает импортёра.","tr":"19 CFR 141.1(b) uyarınca, hem olağan hem de ek gümrük vergilerine ilişkin sorumluluk, ithalatçının Amerika Birleşik Devletleri'ne karşı kişisel bir borcunu oluşturur ve bu borç, kanun veya yönetmelikle muaf tutulmadıkça, yalnızca yasal olarak tahakkuk eden tüm vergilerin tam ödenmesiyle ifa edilebilir; bir müşavire yapılan ödeme ithalatçıyı sorumluluktan kurtarmaz.","hi":"19 CFR 141.1(b) के अंतर्गत, शुल्कों का दायित्व, चाहे नियमित हो या अतिरिक्त, आयातक का संयुक्त राज्य अमेरिका के प्रति एक व्यक्तिगत ऋण बनाता है, जिसे केवल विधिक रूप से अर्जित सभी शुल्कों के पूर्ण भुगतान द्वारा ही चुकाया जा सकता है, जब तक कि कानून या विनियमन द्वारा छूट न दी गई हो; दलाल को भुगतान करने से आयातक मुक्त नहीं होता।","ar":"بموجب 19 CFR 141.1(b)، تشكّل المسؤولية عن الرسوم، العادية والإضافية على حد سواء، دينًا شخصيًا مستحقًا على المستورد للولايات المتحدة لا يمكن سداده إلا بالدفع الكامل لجميع الرسوم المستحقة قانونًا، ما لم يُعفَ منها بموجب قانون أو لائحة؛ والدفع لوسيط لا يُعفي المستورد."}},{"cat":"entry","a":0,"q":{"en":"When an entry summary on CBP Form 7501 serves as both the entry and the entry summary documentation, the time of entry is the time that:","es":"Cuando un resumen de entrada en el CBP Form 7501 sirve a la vez como la entrada y la documentación del resumen de entrada, el momento de la entrada es el momento en que:","ru":"Когда итоговая декларация на CBP Form 7501 служит одновременно и ввозом, и документацией итоговой декларации, моментом ввоза является момент, когда:","tr":"CBP Form 7501 üzerindeki bir giriş özeti hem giriş hem de giriş özeti belgesi olarak hizmet ettiğinde, giriş anı şu andır:","hi":"जब CBP Form 7501 पर एक एंट्री सारांश एक साथ प्रविष्टि और एंट्री सारांश दस्तावेज़ दोनों के रूप में कार्य करता है, तो प्रविष्टि का समय वह समय होता है जब:","ar":"عندما يقوم ملخص الإدخال على استمارة CBP Form 7501 بدور الإدخال ومستند ملخص الإدخال معًا، فإن وقت الإدخال هو الوقت الذي:"},"o":[{"en":"The entry summary is filed in proper form with estimated duties attached","es":"El resumen de entrada se presenta en forma debida con los derechos estimados adjuntos","ru":"Итоговая декларация подаётся в надлежащей форме с приложенными оценочными пошлинами","tr":"Giriş özetinin tahmini gümrük vergileri eklenmiş olarak usulüne uygun şekilde sunulduğu an","hi":"एंट्री सारांश अनुमानित शुल्क संलग्न करके उचित रूप में दाखिल किया जाता है","ar":"يُقدَّم فيه ملخص الإدخال بالشكل الصحيح مع الرسوم المقدَّرة المرفقة"},{"en":"The CBP officer authorizes release of the merchandise","es":"El funcionario de CBP autoriza la liberación de la mercancía","ru":"Сотрудник CBP разрешает выпуск товаров","tr":"CBP memurunun eşyanın teslimine izin verdiği an","hi":"CBP अधिकारी माल की रिलीज़ को अधिकृत करता है","ar":"يأذن فيه موظف CBP بالإفراج عن البضائع"},{"en":"The merchandise arrives within the port limits","es":"La mercancía llega dentro de los límites del puerto","ru":"Товары прибывают в пределы порта","tr":"Eşyanın liman sınırları içine ulaştığı an","hi":"माल बंदरगाह की सीमा के भीतर पहुँचता है","ar":"تصل فيه البضائع إلى داخل حدود الميناء"},{"en":"The carrier files the manifest with CBP","es":"El transportista presenta el manifiesto ante CBP","ru":"Перевозчик подаёт манифест в CBP","tr":"Taşıyıcının manifestoyu CBP'ye sunduğu an","hi":"वाहक CBP के पास मैनिफेस्ट दाखिल करता है","ar":"يقدّم فيه الناقل البيان (manifest) إلى CBP"}],"e":{"en":"Under 19 CFR 141.68(c), when the entry summary serves as both the entry documentation and the entry summary, the time of entry is the time the entry summary is filed in proper form with estimated duties attached (except as provided in 142.13(b)).","es":"Conforme a 19 CFR 141.68(c), cuando el resumen de entrada sirve a la vez como la documentación de entrada y el resumen de entrada, el momento de la entrada es el momento en que el resumen de entrada se presenta en forma debida con los derechos estimados adjuntos (excepto según lo previsto en 142.13(b)).","ru":"Согласно 19 CFR 141.68(c), когда итоговая декларация служит одновременно документацией ввоза и итоговой декларацией, моментом ввоза является момент подачи итоговой декларации в надлежащей форме с приложенными оценочными пошлинами (за исключением случаев, предусмотренных в 142.13(b)).","tr":"19 CFR 141.68(c) uyarınca, giriş özeti hem giriş belgesi hem de giriş özeti olarak hizmet ettiğinde, giriş anı, giriş özetinin tahmini gümrük vergileri eklenmiş olarak usulüne uygun şekilde sunulduğu andır (142.13(b)'de öngörülen haller hariç).","hi":"19 CFR 141.68(c) के अंतर्गत, जब एंट्री सारांश एक साथ प्रविष्टि दस्तावेज़ और एंट्री सारांश दोनों के रूप में कार्य करता है, तो प्रविष्टि का समय वह समय होता है जब एंट्री सारांश अनुमानित शुल्क संलग्न करके उचित रूप में दाखिल किया जाता है (142.13(b) में प्रावधानित को छोड़कर)।","ar":"بموجب 19 CFR 141.68(c)، عندما يقوم ملخص الإدخال بدور مستند الإدخال وملخص الإدخال معًا، فإن وقت الإدخال هو الوقت الذي يُقدَّم فيه ملخص الإدخال بالشكل الصحيح مع الرسوم المقدَّرة المرفقة (باستثناء ما هو منصوص عليه في 142.13(b))."}},{"cat":"entry","a":1,"q":{"en":"Which type of entry permits dutiable merchandise to be stored under bond without payment of duty, with duty paid only upon withdrawal for consumption?","es":"¿Qué tipo de entrada permite que la mercancía sujeta a derechos se almacene bajo fianza sin pago de derechos, pagándose el derecho solo al retirarla para consumo?","ru":"Какой вид декларации позволяет хранить облагаемые пошлиной товары под поручительством без уплаты пошлины, при этом пошлина уплачивается только при изъятии для потребления?","tr":"Hangi tür giriş, gümrük vergisine tabi eşyanın vergi ödenmeden teminat altında depolanmasına ve verginin yalnızca tüketim için çekilişte ödenmesine izin verir?","hi":"किस प्रकार की प्रविष्टि शुल्क-योग्य माल को शुल्क के भुगतान के बिना बॉन्ड के अंतर्गत संग्रहीत करने की अनुमति देती है, जिसमें शुल्क केवल उपभोग के लिए निकासी पर ही चुकाया जाता है?","ar":"أي نوع من الإدخال يسمح بتخزين البضائع الخاضعة للرسوم تحت تعهد دون دفع الرسوم، بحيث تُدفع الرسوم فقط عند السحب بغرض الاستهلاك؟"},"o":[{"en":"Informal entry","es":"Entrada informal","ru":"Неформальная декларация","tr":"Gayri resmi giriş","hi":"अनौपचारिक प्रविष्टि","ar":"الإدخال غير الرسمي"},{"en":"Warehouse entry","es":"Entrada de almacén (warehouse)","ru":"Складская декларация (warehouse entry)","tr":"Antrepo girişi (warehouse)","hi":"गोदाम प्रविष्टि (warehouse)","ar":"إدخال المستودع (warehouse)"},{"en":"Consumption entry","es":"Entrada de consumo","ru":"Потребительская декларация (consumption entry)","tr":"Tüketim girişi","hi":"उपभोग प्रविष्टि","ar":"إدخال الاستهلاك"},{"en":"Temporary importation under bond entry","es":"Entrada de importación temporal bajo fianza (TIB)","ru":"Декларация временного ввоза под поручительство (TIB)","tr":"Teminat altında geçici ithalat girişi (TIB)","hi":"बॉन्ड के अंतर्गत अस्थायी आयात प्रविष्टि (TIB)","ar":"إدخال الاستيراد المؤقت تحت التعهد (TIB)"}],"e":{"en":"A warehouse entry (19 CFR Part 144) allows merchandise to be deposited in a bonded warehouse without immediate payment of duty; duties and taxes are assessed when the goods are withdrawn for consumption (19 CFR 144.11, 144.38). A TIB entry is for goods admitted duty-free for a limited time under bond, not for storage.","es":"Una entrada de almacén (19 CFR Part 144) permite depositar la mercancía en un almacén afianzado sin pago inmediato de derechos; los derechos e impuestos se determinan cuando la mercancía se retira para consumo (19 CFR 144.11, 144.38). Una entrada TIB es para mercancía admitida libre de derechos por tiempo limitado bajo fianza, no para almacenamiento.","ru":"Складская декларация (19 CFR Part 144) позволяет помещать товары на таможенный склад без немедленной уплаты пошлины; пошлины и налоги начисляются при изъятии товаров для потребления (19 CFR 144.11, 144.38). Декларация TIB предназначена для товаров, ввозимых беспошлинно на ограниченный срок под поручительство, а не для хранения.","tr":"Bir antrepo girişi (19 CFR Part 144), eşyanın derhal vergi ödemeksizin teminatlı bir antrepoya konulmasına izin verir; vergiler ve harçlar, eşya tüketim için çekildiğinde tahakkuk ettirilir (19 CFR 144.11, 144.38). Bir TIB girişi ise depolama için değil, teminat altında sınırlı bir süre için gümrük vergisinden muaf olarak kabul edilen eşya içindir.","hi":"एक गोदाम प्रविष्टि (19 CFR Part 144) माल को बिना तत्काल शुल्क भुगतान के बॉन्डेड गोदाम में जमा करने की अनुमति देती है; शुल्क और कर तब निर्धारित किए जाते हैं जब माल उपभोग के लिए निकाला जाता है (19 CFR 144.11, 144.38)। एक TIB प्रविष्टि बॉन्ड के अंतर्गत सीमित समय के लिए शुल्क-मुक्त रूप से प्रविष्ट किए गए माल के लिए होती है, भंडारण के लिए नहीं।","ar":"يسمح إدخال المستودع (19 CFR Part 144) بإيداع البضائع في مستودع خاضع للتعهد دون دفع الرسوم فورًا؛ وتُحتسب الرسوم والضرائب عند سحب البضائع بغرض الاستهلاك (19 CFR 144.11، 144.38). أما إدخال TIB فهو للبضائع المسموح بدخولها معفاة من الرسوم لمدة محدودة تحت تعهد، وليس للتخزين."}},{"cat":"entry","a":2,"q":{"en":"Under 19 USC 1484, which of the following parties is NOT among those entitled to make entry as the importer of record?","es":"Conforme a 19 USC 1484, ¿cuál de las siguientes partes NO está entre las facultadas para hacer la entrada como importador registrado (importer of record)?","ru":"Согласно 19 USC 1484, какая из следующих сторон НЕ относится к тем, кто вправе оформлять декларацию в качестве импортёра-регистранта (importer of record)?","tr":"19 USC 1484 uyarınca, aşağıdaki taraflardan hangisi kayıtlı ithalatçı (importer of record) olarak giriş yapma hakkına sahip olanlar arasında DEĞİLDİR?","hi":"19 USC 1484 के अंतर्गत, निम्नलिखित में से कौन सा पक्ष रिकॉर्ड के आयातक (importer of record) के रूप में प्रविष्टि करने के हकदार पक्षों में से नहीं है?","ar":"بموجب 19 USC 1484، أي من الأطراف التالية ليس من بين الجهات المخوّلة بإجراء الإدخال بصفته المستورد المسجّل (importer of record)؟"},"o":[{"en":"The owner or purchaser of the merchandise","es":"El propietario o comprador de la mercancía","ru":"Владелец или покупатель товара","tr":"Eşyanın sahibi veya satın alıcısı","hi":"माल का मालिक या क्रेता","ar":"مالك البضاعة أو مشتريها"},{"en":"A licensed customs broker appointed by the owner or purchaser","es":"Un agente de aduanas con licencia designado por el propietario o comprador","ru":"Лицензированный таможенный брокер, назначенный владельцем или покупателем","tr":"Sahip veya satın alıcı tarafından atanan lisanslı bir gümrük müşaviri","hi":"मालिक या क्रेता द्वारा नियुक्त एक लाइसेंसप्राप्त सीमा शुल्क दलाल","ar":"وسيط جمركي مرخّص يعيّنه المالك أو المشتري"},{"en":"A nominal consignee who is not a licensed broker","es":"Un consignatario nominal que no es un agente con licencia","ru":"Номинальный грузополучатель, не являющийся лицензированным брокером","tr":"Lisanslı müşavir olmayan nominal (sözde) bir alıcı","hi":"एक नाममात्र परेषिती (consignee) जो लाइसेंसप्राप्त दलाल नहीं है","ar":"مرسَل إليه اسمي ليس وسيطًا مرخّصًا"},{"en":"A consignee holding a financial interest in the transaction","es":"Un consignatario que tiene un interés financiero en la transacción","ru":"Грузополучатель, имеющий финансовый интерес в сделке","tr":"İşlemde mali menfaati bulunan bir alıcı","hi":"एक परेषिती जिसका लेनदेन में वित्तीय हित है","ar":"مرسَل إليه له مصلحة مالية في المعاملة"}],"e":{"en":"Under 19 USC 1484(a) and 19 CFR 141.11, only the owner, purchaser, or a licensed customs broker appointed by such owner, purchaser, or consignee may make entry. A purpose of the statute is to prevent nominal consignees (other than licensed brokers) from filing entries and transacting customs business.","es":"Conforme a 19 USC 1484(a) y 19 CFR 141.11, solo el propietario, el comprador o un agente de aduanas con licencia designado por dicho propietario, comprador o consignatario puede hacer la entrada. Un propósito de la ley es impedir que los consignatarios nominales (que no sean agentes con licencia) presenten entradas y realicen negocios aduaneros.","ru":"Согласно 19 USC 1484(a) и 19 CFR 141.11, оформлять декларацию могут только владелец, покупатель или лицензированный таможенный брокер, назначенный таким владельцем, покупателем или грузополучателем. Цель закона — не допустить, чтобы номинальные грузополучатели (кроме лицензированных брокеров) подавали декларации и вели таможенные дела.","tr":"19 USC 1484(a) ve 19 CFR 141.11 uyarınca, yalnızca sahip, satın alıcı veya bu sahip, satın alıcı ya da alıcı tarafından atanan lisanslı bir gümrük müşaviri giriş yapabilir. Kanunun amaçlarından biri, nominal alıcıların (lisanslı müşavirler dışında) giriş yapmasını ve gümrük işi yürütmesini önlemektir.","hi":"19 USC 1484(a) और 19 CFR 141.11 के अंतर्गत, केवल मालिक, क्रेता, या ऐसे मालिक, क्रेता या परेषिती द्वारा नियुक्त लाइसेंसप्राप्त सीमा शुल्क दलाल ही प्रविष्टि कर सकता है। इस कानून का एक उद्देश्य नाममात्र परेषितियों (लाइसेंसप्राप्त दलालों के अतिरिक्त) को प्रविष्टियाँ दाखिल करने और सीमा शुल्क व्यवसाय करने से रोकना है।","ar":"بموجب 19 USC 1484(a) و19 CFR 141.11، لا يجوز إجراء الإدخال إلا للمالك أو المشتري أو وسيط جمركي مرخّص يعيّنه هذا المالك أو المشتري أو المرسَل إليه. ومن أغراض القانون منع المرسَل إليهم الاسميين (من غير الوسطاء المرخّصين) من تقديم الإدخالات ومزاولة الأعمال الجمركية."}},{"cat":"entry","a":1,"q":{"en":"A commercial invoice presented for entry must generally contain all of the following EXCEPT:","es":"Una factura comercial presentada para la entrada generalmente debe contener todo lo siguiente, EXCEPTO:","ru":"Коммерческий счёт-фактура, представляемый для оформления декларации, как правило, должен содержать всё перечисленное, КРОМЕ:","tr":"Giriş için sunulan bir ticari fatura genellikle aşağıdakilerin tümünü içermelidir, ŞU HARİÇ:","hi":"प्रविष्टि के लिए प्रस्तुत वाणिज्यिक चालान में सामान्यतः निम्नलिखित सभी होने चाहिए, सिवाय:","ar":"يجب أن تتضمن الفاتورة التجارية المقدَّمة للإدخال عمومًا كل ما يلي، باستثناء:"},"o":[{"en":"The quantities in the weights and measures of the country of shipment or of the United States","es":"Las cantidades en los pesos y medidas del país de embarque o de los Estados Unidos","ru":"Количества в мерах веса и измерения страны отгрузки или Соединённых Штатов","tr":"Sevkiyat ülkesinin veya Amerika Birleşik Devletleri'nin ağırlık ve ölçü birimlerine göre miktarlar","hi":"शिपमेंट के देश या संयुक्त राज्य अमेरिका के वज़न और मापों में मात्राएँ","ar":"الكميات بأوزان ومقاييس بلد الشحن أو الولايات المتحدة"},{"en":"The retail selling price anticipated by the U.S. buyer","es":"El precio de venta al por menor previsto por el comprador estadounidense","ru":"Розничная продажная цена, ожидаемая покупателем в США","tr":"ABD'li alıcının öngördüğü perakende satış fiyatı","hi":"अमेरिकी क्रेता द्वारा अनुमानित खुदरा विक्रय मूल्य","ar":"سعر البيع بالتجزئة المتوقع من قِبل المشتري الأمريكي"},{"en":"The purchase price of each item in the currency of the purchase","es":"El precio de compra de cada artículo en la moneda de la compra","ru":"Покупная цена каждого товара в валюте покупки","tr":"Her bir kalemin satın alma para biriminde satın alma fiyatı","hi":"खरीद की मुद्रा में प्रत्येक वस्तु का क्रय मूल्य","ar":"سعر شراء كل صنف بعملة الشراء"},{"en":"A detailed description of the merchandise, including grade or quality","es":"Una descripción detallada de la mercancía, incluyendo grado o calidad","ru":"Подробное описание товара, включая сорт или качество","tr":"Eşyanın sınıf veya kalitesi dahil ayrıntılı bir tanımı","hi":"माल का विस्तृत विवरण, जिसमें ग्रेड या गुणवत्ता शामिल हो","ar":"وصف تفصيلي للبضاعة، بما في ذلك الدرجة أو الجودة"}],"e":{"en":"Under 19 CFR 141.86(a), the commercial invoice must include a detailed description, quantities, purchase price in the currency of purchase, and similar data. The anticipated U.S. retail selling price is not a required invoice element; CBP requires transaction-related data, not the importer's resale price.","es":"Conforme a 19 CFR 141.86(a), la factura comercial debe incluir una descripción detallada, las cantidades, el precio de compra en la moneda de la compra y datos similares. El precio de venta al por menor previsto en EE. UU. no es un elemento obligatorio de la factura; CBP exige datos relacionados con la transacción, no el precio de reventa del importador.","ru":"Согласно 19 CFR 141.86(a), коммерческий счёт-фактура должен включать подробное описание, количества, покупную цену в валюте покупки и аналогичные данные. Ожидаемая розничная цена продажи в США не является обязательным элементом счёта-фактуры; CBP требует данные, относящиеся к сделке, а не цену перепродажи импортёра.","tr":"19 CFR 141.86(a) uyarınca, ticari fatura ayrıntılı bir tanım, miktarlar, satın alma para birimindeki satın alma fiyatı ve benzeri verileri içermelidir. Öngörülen ABD perakende satış fiyatı, faturanın zorunlu bir unsuru değildir; CBP, ithalatçının yeniden satış fiyatını değil, işlemle ilgili verileri talep eder.","hi":"19 CFR 141.86(a) के अंतर्गत, वाणिज्यिक चालान में विस्तृत विवरण, मात्राएँ, खरीद की मुद्रा में क्रय मूल्य और समान डेटा शामिल होना चाहिए। अनुमानित अमेरिकी खुदरा विक्रय मूल्य चालान का आवश्यक तत्व नहीं है; CBP लेनदेन से संबंधित डेटा चाहता है, न कि आयातक का पुनर्विक्रय मूल्य।","ar":"بموجب 19 CFR 141.86(a)، يجب أن تتضمن الفاتورة التجارية وصفًا تفصيليًا والكميات وسعر الشراء بعملة الشراء وبيانات مماثلة. أما سعر البيع بالتجزئة المتوقع في الولايات المتحدة فليس عنصرًا مطلوبًا في الفاتورة؛ إذ تطلب CBP البيانات المتعلقة بالمعاملة، وليس سعر إعادة بيع المستورد."}},{"cat":"entry","a":2,"q":{"en":"A shipment of textiles valued at $40,000 arrives by vessel. The importer wishes to obtain release of the goods before filing the full entry summary. Which document set is appropriate to secure release?","es":"Un envío de textiles valorado en $40,000 llega por embarcación. El importador desea obtener la liberación de la mercancía antes de presentar el resumen de entrada completo. ¿Qué conjunto de documentos es apropiado para asegurar la liberación?","ru":"Партия текстиля стоимостью $40,000 прибывает морским судном. Импортёр желает получить выпуск товаров до подачи полной итоговой декларации. Какой комплект документов подходит для обеспечения выпуска?","tr":"$40,000 değerinde bir tekstil sevkiyatı gemiyle gelir. İthalatçı, tam giriş özetini sunmadan önce eşyanın teslimini almak ister. Teslimi sağlamak için hangi belge seti uygundur?","hi":"$40,000 मूल्य का एक वस्त्र शिपमेंट जहाज द्वारा आता है। आयातक पूर्ण एंट्री सारांश दाखिल करने से पहले माल की रिलीज़ प्राप्त करना चाहता है। रिलीज़ सुनिश्चित करने के लिए कौन सा दस्तावेज़ सेट उपयुक्त है?","ar":"تصل شحنة منسوجات بقيمة $40,000 عن طريق سفينة. يرغب المستورد في الحصول على الإفراج عن البضائع قبل تقديم ملخص الإدخال الكامل. أي مجموعة من المستندات مناسبة لتأمين الإفراج؟"},"o":[{"en":"CBP Form 5106 establishing the importer of record number","es":"CBP Form 5106 que establece el número de importador registrado","ru":"CBP Form 5106, устанавливающий номер импортёра-регистранта","tr":"Kayıtlı ithalatçı numarasını oluşturan CBP Form 5106","hi":"रिकॉर्ड के आयातक का नंबर स्थापित करने वाला CBP Form 5106","ar":"CBP Form 5106 الذي يُنشئ رقم المستورد المسجّل"},{"en":"CBP Form 7533 in duplicate for the consumption entry","es":"CBP Form 7533 por duplicado para la entrada de consumo","ru":"CBP Form 7533 в двух экземплярах для потребительской декларации","tr":"Tüketim girişi için iki nüsha hâlinde CBP Form 7533","hi":"उपभोग प्रविष्टि के लिए दो प्रतियों में CBP Form 7533","ar":"CBP Form 7533 من نسختين لإدخال الاستهلاك"},{"en":"CBP Form 3461 with supporting documentation under 19 CFR 142.3","es":"CBP Form 3461 con la documentación de respaldo conforme a 19 CFR 142.3","ru":"CBP Form 3461 с подтверждающей документацией согласно 19 CFR 142.3","tr":"19 CFR 142.3 kapsamında destekleyici belgelerle CBP Form 3461","hi":"19 CFR 142.3 के अंतर्गत सहायक दस्तावेज़ों के साथ CBP Form 3461","ar":"CBP Form 3461 مع المستندات الداعمة بموجب 19 CFR 142.3"},{"en":"CBP Form 7501 with estimated duties deposited at release","es":"CBP Form 7501 con los derechos estimados depositados al momento de la liberación","ru":"CBP Form 7501 с оценочными пошлинами, внесёнными при выпуске","tr":"Teslimde tahmini gümrük vergileri yatırılmış CBP Form 7501","hi":"रिलीज़ पर अनुमानित शुल्क जमा करके CBP Form 7501","ar":"CBP Form 7501 مع إيداع الرسوم المقدَّرة عند الإفراج"}],"e":{"en":"Under 19 CFR 142.3 and 142.4, release is secured by filing CBP Form 3461 (or electronic equivalent) with required supporting documentation and an adequate bond; the entry summary (7501) is then filed within 10 working days under 142.12. Form 7533 is for contiguous-country in-bond goods; 5106 only creates an importer identity record.","es":"Conforme a 19 CFR 142.3 y 142.4, la liberación se asegura presentando el CBP Form 3461 (o equivalente electrónico) con la documentación de respaldo requerida y una fianza adecuada; el resumen de entrada (7501) se presenta luego dentro de los 10 días hábiles conforme a 142.12. El Form 7533 es para mercancía in-bond de países contiguos; el 5106 solo crea un registro de identidad del importador.","ru":"Согласно 19 CFR 142.3 и 142.4, выпуск обеспечивается подачей CBP Form 3461 (или электронного эквивалента) с необходимой подтверждающей документацией и надлежащим поручительством; итоговая декларация (7501) затем подаётся в течение 10 рабочих дней согласно 142.12. Форма 7533 предназначена для транзитных in-bond товаров из сопредельных стран; 5106 лишь создаёт запись об идентификации импортёра.","tr":"19 CFR 142.3 ve 142.4 uyarınca, teslim, gerekli destekleyici belgeler ve yeterli bir teminat ile birlikte CBP Form 3461 (veya elektronik eşdeğeri) sunularak sağlanır; giriş özeti (7501) ise 142.12 uyarınca 10 iş günü içinde sunulur. Form 7533 komşu ülkelerden gelen in-bond eşya içindir; 5106 yalnızca bir ithalatçı kimlik kaydı oluşturur.","hi":"19 CFR 142.3 और 142.4 के अंतर्गत, रिलीज़ आवश्यक सहायक दस्तावेज़ और पर्याप्त बॉन्ड के साथ CBP Form 3461 (या इलेक्ट्रॉनिक समतुल्य) दाखिल करके सुनिश्चित की जाती है; फिर एंट्री सारांश (7501) 142.12 के अंतर्गत 10 कार्य दिवसों के भीतर दाखिल किया जाता है। फॉर्म 7533 संलग्न-देश के इन-बॉन्ड माल के लिए है; 5106 केवल आयातक पहचान रिकॉर्ड बनाता है।","ar":"بموجب 19 CFR 142.3 و142.4، يُؤمَّن الإفراج بتقديم CBP Form 3461 (أو ما يعادلها إلكترونيًا) مع المستندات الداعمة المطلوبة وتعهد كافٍ؛ ثم يُقدَّم ملخص الإدخال (7501) خلال 10 أيام عمل بموجب 142.12. واستمارة 7533 مخصصة للبضائع تحت التعهد in-bond من الدول المتاخمة؛ أما 5106 فينشئ سجل هوية المستورد فقط."}},{"cat":"entry","a":0,"q":{"en":"Which statement concerning a continuous bond versus a single transaction bond at entry is TRUE?","es":"¿Cuál de las siguientes afirmaciones sobre una fianza continua (continuous bond) frente a una fianza de transacción única (single transaction bond) en la entrada es VERDADERA?","ru":"Какое из утверждений относительно непрерывного поручительства (continuous bond) в сравнении с разовым поручительством (single transaction bond) при оформлении декларации ВЕРНО?","tr":"Giriş sırasında sürekli teminat (continuous bond) ile tek işlem teminatı (single transaction bond) hakkındaki hangi ifade DOĞRUDUR?","hi":"प्रविष्टि पर निरंतर बॉन्ड (continuous bond) बनाम एकल लेनदेन बॉन्ड (single transaction bond) के संबंध में कौन सा कथन सत्य है?","ar":"أي عبارة بشأن التعهد المستمر (continuous bond) مقابل تعهد المعاملة الواحدة (single transaction bond) عند الإدخال صحيحة؟"},"o":[{"en":"A continuous bond remains in effect for one year and covers multiple entries until terminated","es":"Una fianza continua permanece vigente durante un año y cubre múltiples entradas hasta su terminación","ru":"Непрерывное поручительство действует в течение одного года и покрывает несколько деклараций до его прекращения","tr":"Sürekli teminat bir yıl boyunca yürürlükte kalır ve sonlandırılana kadar birden fazla girişi kapsar","hi":"निरंतर बॉन्ड एक वर्ष तक प्रभावी रहता है और समाप्त किए जाने तक अनेक प्रविष्टियों को कवर करता है","ar":"يبقى التعهد المستمر ساري المفعول لمدة سنة ويغطي إدخالات متعددة حتى يُنهى"},{"en":"A single transaction bond covers all of an importer's entries at all ports for one year","es":"Una fianza de transacción única cubre todas las entradas de un importador en todos los puertos durante un año","ru":"Разовое поручительство покрывает все декларации импортёра во всех портах в течение одного года","tr":"Tek işlem teminatı, bir ithalatçının tüm limanlardaki tüm girişlerini bir yıl boyunca kapsar","hi":"एकल लेनदेन बॉन्ड एक वर्ष के लिए सभी बंदरगाहों पर आयातक की सभी प्रविष्टियों को कवर करता है","ar":"يغطي تعهد المعاملة الواحدة جميع إدخالات المستورد في جميع الموانئ لمدة سنة"},{"en":"A single transaction bond is filed on CBP Form 5106","es":"Una fianza de transacción única se presenta en el CBP Form 5106","ru":"Разовое поручительство подаётся на CBP Form 5106","tr":"Tek işlem teminatı CBP Form 5106 üzerinde sunulur","hi":"एकल लेनदेन बॉन्ड CBP Form 5106 पर दाखिल किया जाता है","ar":"يُقدَّم تعهد المعاملة الواحدة على استمارة CBP Form 5106"},{"en":"A continuous bond may only be used for warehouse entries","es":"Una fianza continua solo puede usarse para entradas de almacén","ru":"Непрерывное поручительство может использоваться только для складских деклараций","tr":"Sürekli teminat yalnızca antrepo girişleri için kullanılabilir","hi":"निरंतर बॉन्ड का उपयोग केवल गोदाम प्रविष्टियों के लिए किया जा सकता है","ar":"لا يجوز استخدام التعهد المستمر إلا لإدخالات المستودع"}],"e":{"en":"Under 19 CFR 113.11 and 113.12, a continuous bond remains in effect (typically annually renewing) and secures multiple transactions until terminated, while a single transaction bond covers only one specified entry. Both are filed on CBP Form 301; Form 5106 is the importer identity form, not a bond.","es":"Conforme a 19 CFR 113.11 y 113.12, una fianza continua permanece vigente (por lo general con renovación anual) y garantiza múltiples transacciones hasta su terminación, mientras que una fianza de transacción única cubre solo una entrada específica. Ambas se presentan en el CBP Form 301; el Form 5106 es el formulario de identidad del importador, no una fianza.","ru":"Согласно 19 CFR 113.11 и 113.12, непрерывное поручительство действует (как правило, с ежегодным продлением) и обеспечивает множество сделок до его прекращения, тогда как разовое поручительство покрывает только одну конкретную декларацию. Оба оформляются на CBP Form 301; форма 5106 — это форма идентификации импортёра, а не поручительство.","tr":"19 CFR 113.11 ve 113.12 uyarınca, sürekli teminat (genellikle yıllık yenilenerek) yürürlükte kalır ve sonlandırılana kadar birden fazla işlemi güvence altına alır; tek işlem teminatı ise yalnızca belirli bir girişi kapsar. Her ikisi de CBP Form 301 üzerinde sunulur; Form 5106 ise teminat değil, ithalatçı kimlik formudur.","hi":"19 CFR 113.11 और 113.12 के अंतर्गत, निरंतर बॉन्ड (आमतौर पर वार्षिक रूप से नवीनीकृत होते हुए) प्रभावी रहता है और समाप्त किए जाने तक अनेक लेनदेनों को सुरक्षित करता है, जबकि एकल लेनदेन बॉन्ड केवल एक निर्दिष्ट प्रविष्टि को कवर करता है। दोनों CBP Form 301 पर दाखिल किए जाते हैं; फॉर्म 5106 आयातक पहचान फॉर्म है, बॉन्ड नहीं।","ar":"بموجب 19 CFR 113.11 و113.12، يبقى التعهد المستمر ساري المفعول (عادةً بتجديد سنوي) ويضمن معاملات متعددة حتى يُنهى، بينما لا يغطي تعهد المعاملة الواحدة سوى إدخال واحد محدد. وكلاهما يُقدَّم على استمارة CBP Form 301؛ أما الاستمارة 5106 فهي استمارة هوية المستورد، وليست تعهدًا."}},{"cat":"entry","a":1,"q":{"en":"Under 19 CFR 142.21, merchandise arriving by land from Canada or Mexico may be released under a special permit for immediate delivery provided that:","es":"Conforme a 19 CFR 142.21, la mercancía que llega por tierra desde Canadá o México puede liberarse bajo un permiso especial para entrega inmediata siempre que:","ru":"Согласно 19 CFR 142.21, товары, прибывающие по суше из Канады или Мексики, могут быть выпущены по специальному разрешению на немедленную выдачу при условии, что:","tr":"19 CFR 142.21 uyarınca, Kanada veya Meksika'dan kara yoluyla gelen eşya, aşağıdaki şart yerine getirildiği takdirde acil teslim için özel izinle teslim edilebilir:","hi":"19 CFR 142.21 के अंतर्गत, कनाडा या मेक्सिको से भूमि मार्ग से आने वाले माल को तत्काल सुपुर्दगी के विशेष परमिट के तहत रिलीज़ किया जा सकता है, बशर्ते कि:","ar":"بموجب 19 CFR 142.21، يجوز الإفراج عن البضائع الواصلة برًا من كندا أو المكسيك بموجب تصريح خاص بالتسليم الفوري بشرط أن:"},"o":[{"en":"The importer files a single transaction bond on Form 7501 for each crossing","es":"El importador presente una fianza de transacción única en el Form 7501 por cada cruce","ru":"Импортёр подаёт разовое поручительство на Form 7501 для каждого пересечения границы","tr":"İthalatçı her geçiş için Form 7501 üzerinde tek işlem teminatı sunmalı","hi":"आयातक प्रत्येक क्रॉसिंग के लिए Form 7501 पर एकल लेनदेन बॉन्ड दाखिल करे","ar":"يقدّم المستورد تعهد معاملة واحدة على Form 7501 عن كل عبور"},{"en":"The importer has on file a bond on CBP Form 301 containing the 113.62 conditions","es":"El importador tenga registrada una fianza en el CBP Form 301 que contenga las condiciones del 113.62","ru":"У импортёра имеется поданное поручительство на CBP Form 301, содержащее условия 113.62","tr":"İthalatçının dosyasında, 113.62 koşullarını içeren CBP Form 301 üzerinde bir teminat bulunmalı","hi":"आयातक के पास 113.62 की शर्तों वाला CBP Form 301 पर एक बॉन्ड फाइल में हो","ar":"يكون لدى المستورد تعهد مُودَع على CBP Form 301 يتضمن شروط 113.62"},{"en":"The merchandise is unconditionally free of duty under the HTSUS","es":"La mercancía esté incondicionalmente libre de derechos conforme al HTSUS","ru":"Товары безусловно освобождены от пошлины согласно HTSUS","tr":"Eşya HTSUS uyarınca koşulsuz olarak gümrük vergisinden muaf olmalı","hi":"माल HTSUS के अंतर्गत बिना शर्त शुल्क-मुक्त हो","ar":"تكون البضائع معفاة من الرسوم دون قيد أو شرط بموجب HTSUS"},{"en":"The port director waives the requirement for any bond","es":"El director del puerto exima del requisito de cualquier fianza","ru":"Директор порта отменяет требование о каком-либо поручительстве","tr":"Liman müdürü herhangi bir teminat şartından feragat etmeli","hi":"बंदरगाह निदेशक किसी भी बॉन्ड की आवश्यकता को माफ कर दे","ar":"يتنازل مدير الميناء عن اشتراط أي تعهد"}],"e":{"en":"Under 19 CFR 142.21(a), merchandise arriving by land from Canada or Mexico may be released under a special permit for immediate delivery at the port director's discretion if the importer has on file a bond on CBP Form 301 containing the bond conditions set forth in 19 CFR 113.62.","es":"Conforme a 19 CFR 142.21(a), la mercancía que llega por tierra desde Canadá o México puede liberarse bajo un permiso especial para entrega inmediata, a discreción del director del puerto, si el importador tiene registrada una fianza en el CBP Form 301 que contenga las condiciones de fianza establecidas en 19 CFR 113.62.","ru":"Согласно 19 CFR 142.21(a), товары, прибывающие по суше из Канады или Мексики, могут быть выпущены по специальному разрешению на немедленную выдачу по усмотрению директора порта, если у импортёра имеется поданное поручительство на CBP Form 301, содержащее условия поручительства, изложенные в 19 CFR 113.62.","tr":"19 CFR 142.21(a) uyarınca, Kanada veya Meksika'dan kara yoluyla gelen eşya, ithalatçının dosyasında 19 CFR 113.62'de belirtilen teminat koşullarını içeren CBP Form 301 üzerinde bir teminat bulunması halinde, liman müdürünün takdirine bağlı olarak acil teslim için özel izinle teslim edilebilir.","hi":"19 CFR 142.21(a) के अंतर्गत, कनाडा या मेक्सिको से भूमि मार्ग से आने वाले माल को बंदरगाह निदेशक के विवेक पर तत्काल सुपुर्दगी के विशेष परमिट के तहत रिलीज़ किया जा सकता है, यदि आयातक के पास 19 CFR 113.62 में निर्धारित बॉन्ड शर्तों वाला CBP Form 301 पर एक बॉन्ड फाइल में हो।","ar":"بموجب 19 CFR 142.21(a)، يجوز الإفراج عن البضائع الواصلة برًا من كندا أو المكسيك بموجب تصريح خاص بالتسليم الفوري وفقًا لتقدير مدير الميناء، إذا كان لدى المستورد تعهد مُودَع على CBP Form 301 يتضمن شروط التعهد المنصوص عليها في 19 CFR 113.62."}},{"cat":"entry","a":3,"q":{"en":"Which of the following is NOT a class of merchandise generally eligible for release under a special permit for immediate delivery under 19 CFR 142.21?","es":"¿Cuál de las siguientes NO es una clase de mercancía generalmente elegible para liberación bajo un permiso especial para entrega inmediata conforme a 19 CFR 142.21?","ru":"Какой из следующих классов товаров, как правило, НЕ имеет права на выпуск по специальному разрешению на немедленную выдачу согласно 19 CFR 142.21?","tr":"Aşağıdakilerden hangisi, 19 CFR 142.21 uyarınca acil teslim için özel izinle teslime genellikle uygun OLMAYAN bir eşya sınıfıdır?","hi":"निम्नलिखित में से कौन सा 19 CFR 142.21 के अंतर्गत तत्काल सुपुर्दगी के विशेष परमिट के तहत रिलीज़ के लिए सामान्यतः पात्र माल की श्रेणी नहीं है?","ar":"أي مما يلي ليس فئة من البضائع المؤهلة عمومًا للإفراج بموجب تصريح خاص بالتسليم الفوري وفقًا لـ 19 CFR 142.21؟"},"o":[{"en":"Merchandise arriving by land from Canada or Mexico for a bonded importer","es":"Mercancía que llega por tierra desde Canadá o México para un importador afianzado","ru":"Товары, прибывающие по суше из Канады или Мексики для импортёра, имеющего поручительство","tr":"Teminatlı bir ithalatçı için Kanada veya Meksika'dan kara yoluyla gelen eşya","hi":"बॉन्डेड आयातक के लिए कनाडा या मेक्सिको से भूमि मार्ग से आने वाला माल","ar":"بضائع واصلة برًا من كندا أو المكسيك لمستورد لديه تعهد"},{"en":"Fresh fruits and vegetables for human consumption from contiguous countries","es":"Frutas y verduras frescas para consumo humano provenientes de países contiguos","ru":"Свежие фрукты и овощи для потребления человеком из сопредельных стран","tr":"Komşu ülkelerden gelen, insan tüketimine yönelik taze meyve ve sebzeler","hi":"संलग्न देशों से मानव उपभोग के लिए ताज़े फल और सब्जियाँ","ar":"فواكه وخضروات طازجة للاستهلاك البشري من الدول المتاخمة"},{"en":"Merchandise specifically authorized by Headquarters as a test","es":"Mercancía específicamente autorizada por la Sede (Headquarters) como prueba","ru":"Товары, специально разрешённые Главным управлением (Headquarters) в качестве эксперимента","tr":"Genel Merkez (Headquarters) tarafından deneme amacıyla özel olarak yetkilendirilen eşya","hi":"मुख्यालय (Headquarters) द्वारा परीक्षण के रूप में विशेष रूप से अधिकृत माल","ar":"بضائع مصرّح بها تحديدًا من المقر الرئيسي (Headquarters) على سبيل التجربة"},{"en":"Prohibited merchandise pending an admissibility determination","es":"Mercancía prohibida pendiente de una determinación de admisibilidad","ru":"Запрещённые товары, ожидающие определения допустимости ввоза","tr":"Kabul edilebilirlik kararı beklenen yasaklı eşya","hi":"स्वीकार्यता निर्धारण के लंबित प्रतिबंधित माल","ar":"بضائع محظورة في انتظار البت في قبولها"}],"e":{"en":"19 CFR 142.21 lists eligible classes including land arrivals from Canada/Mexico, fresh fruits and vegetables, agency-authorized goods, quota-class merchandise (with limits), and goods for a U.S. government agency. Prohibited merchandise pending an admissibility decision is not eligible for immediate-delivery release.","es":"19 CFR 142.21 enumera clases elegibles que incluyen llegadas por tierra desde Canadá/México, frutas y verduras frescas, mercancía autorizada por una agencia, mercancía sujeta a cuota (con límites) y mercancía para una agencia del gobierno de EE. UU. La mercancía prohibida pendiente de una decisión de admisibilidad no es elegible para liberación por entrega inmediata.","ru":"19 CFR 142.21 перечисляет подходящие классы, включая сухопутные прибытия из Канады/Мексики, свежие фрукты и овощи, товары, разрешённые ведомством, товары квотного класса (с ограничениями) и товары для государственного ведомства США. Запрещённые товары, ожидающие решения о допустимости ввоза, не подлежат выпуску по немедленной выдаче.","tr":"19 CFR 142.21, uygun sınıfları sıralar: Kanada/Meksika'dan kara girişleri, taze meyve ve sebzeler, kurum tarafından yetkilendirilen mallar, kota sınıfı eşya (sınırlamalarla) ve bir ABD devlet kurumu için mallar. Kabul edilebilirlik kararı beklenen yasaklı eşya, acil teslim yoluyla teslime uygun değildir.","hi":"19 CFR 142.21 पात्र श्रेणियों को सूचीबद्ध करता है, जिनमें कनाडा/मेक्सिको से भूमि आगमन, ताज़े फल और सब्जियाँ, एजेंसी-अधिकृत माल, कोटा-श्रेणी का माल (सीमाओं के साथ), और अमेरिकी सरकारी एजेंसी के लिए माल शामिल हैं। स्वीकार्यता निर्णय के लंबित प्रतिबंधित माल तत्काल-सुपुर्दगी रिलीज़ के लिए पात्र नहीं है।","ar":"تُعدّد 19 CFR 142.21 الفئات المؤهلة، ومنها الوصول البري من كندا/المكسيك، والفواكه والخضروات الطازجة، والبضائع المصرّح بها من جهة حكومية، والبضائع الخاضعة للحصص (ضمن حدود)، والبضائع المخصصة لجهة حكومية أمريكية. أما البضائع المحظورة التي تنتظر قرار قبولها فليست مؤهلة للإفراج بالتسليم الفوري."}},{"cat":"entry","a":1,"q":{"en":"An importer files a CBP Form 3461 to obtain release on June 1, and CBP authorizes release on June 3. Using a 10-working-day period and no intervening holidays, by which date must the entry summary and estimated duties be filed?","es":"Un importador presenta un CBP Form 3461 para obtener la liberación el 1 de junio, y CBP autoriza la liberación el 3 de junio. Usando un período de 10 días hábiles y sin días feriados intermedios, ¿para qué fecha deben presentarse el resumen de entrada y los derechos estimados?","ru":"Импортёр подаёт CBP Form 3461 для получения выпуска 1 июня, и CBP разрешает выпуск 3 июня. При сроке в 10 рабочих дней и отсутствии промежуточных праздников, к какой дате должны быть поданы итоговая декларация и оценочные пошлины?","tr":"Bir ithalatçı 1 Haziran'da teslim almak için bir CBP Form 3461 sunar ve CBP 3 Haziran'da teslime izin verir. 10 iş günlük bir süre kullanıldığında ve arada tatil günü olmadığında, giriş özeti ve tahmini gümrük vergileri hangi tarihe kadar sunulmalıdır?","hi":"एक आयातक 1 जून को रिलीज़ प्राप्त करने के लिए CBP Form 3461 दाखिल करता है, और CBP 3 जून को रिलीज़ को अधिकृत करता है। 10-कार्य-दिवस की अवधि और बीच में कोई अवकाश न होने पर, एंट्री सारांश और अनुमानित शुल्क किस तारीख तक दाखिल किए जाने चाहिए?","ar":"يقدّم مستورد استمارة CBP Form 3461 للحصول على الإفراج في 1 يونيو، وتأذن CBP بالإفراج في 3 يونيو. باستخدام مدة 10 أيام عمل ودون عطلات في الأثناء، بأي تاريخ يجب تقديم ملخص الإدخال والرسوم المقدَّرة؟"},"o":[{"en":"By June 30 (within the same month of release)","es":"Para el 30 de junio (dentro del mismo mes de la liberación)","ru":"К 30 июня (в пределах того же месяца выпуска)","tr":"30 Haziran'a kadar (teslimin yapıldığı aynı ay içinde)","hi":"30 जून तक (रिलीज़ के उसी महीने के भीतर)","ar":"بحلول 30 يونيو (خلال نفس شهر الإفراج)"},{"en":"By June 17 (10 working days from June 3)","es":"Para el 17 de junio (10 días hábiles desde el 3 de junio)","ru":"К 17 июня (10 рабочих дней с 3 июня)","tr":"17 Haziran'a kadar (3 Haziran'dan itibaren 10 iş günü)","hi":"17 जून तक (3 जून से 10 कार्य दिवस)","ar":"بحلول 17 يونيو (10 أيام عمل من 3 يونيو)"},{"en":"By June 13 (10 calendar days from June 3)","es":"Para el 13 de junio (10 días calendario desde el 3 de junio)","ru":"К 13 июня (10 календарных дней с 3 июня)","tr":"13 Haziran'a kadar (3 Haziran'dan itibaren 10 takvim günü)","hi":"13 जून तक (3 जून से 10 कैलेंडर दिन)","ar":"بحلول 13 يونيو (10 أيام تقويمية من 3 يونيو)"},{"en":"By June 11 (10 calendar days from June 1)","es":"Para el 11 de junio (10 días calendario desde el 1 de junio)","ru":"К 11 июня (10 календарных дней с 1 июня)","tr":"11 Haziran'a kadar (1 Haziran'dan itibaren 10 takvim günü)","hi":"11 जून तक (1 जून से 10 कैलेंडर दिन)","ar":"بحلول 11 يونيو (10 أيام تقويمية من 1 يونيو)"}],"e":{"en":"Under 19 CFR 142.12(b), the entry summary with estimated duties is due within 10 WORKING days after the time of entry. The time of entry is release (June 3), so counting 10 working days (excluding weekends) yields June 17. Working days, not calendar days, control.","es":"Conforme a 19 CFR 142.12(b), el resumen de entrada con los derechos estimados vence dentro de los 10 días HÁBILES después del momento de la entrada. El momento de la entrada es la liberación (3 de junio), por lo que contar 10 días hábiles (excluyendo fines de semana) da el 17 de junio. Rigen los días hábiles, no los días calendario.","ru":"Согласно 19 CFR 142.12(b), итоговая декларация с оценочными пошлинами должна быть подана в течение 10 РАБОЧИХ дней после момента ввоза. Момент ввоза — это выпуск (3 июня), поэтому отсчёт 10 рабочих дней (исключая выходные) даёт 17 июня. Действуют рабочие, а не календарные дни.","tr":"19 CFR 142.12(b) uyarınca, tahmini gümrük vergileriyle birlikte giriş özeti, giriş anından sonra 10 İŞ günü içinde verilmelidir. Giriş anı teslimdir (3 Haziran), bu nedenle 10 iş günü sayıldığında (hafta sonları hariç) 17 Haziran elde edilir. Takvim günleri değil, iş günleri geçerlidir.","hi":"19 CFR 142.12(b) के अंतर्गत, अनुमानित शुल्क के साथ एंट्री सारांश प्रविष्टि के समय के बाद 10 कार्य दिवसों के भीतर देय होता है। प्रविष्टि का समय रिलीज़ है (3 जून), इसलिए 10 कार्य दिवस गिनने पर (सप्ताहांत को छोड़कर) 17 जून आता है। कैलेंडर दिन नहीं, बल्कि कार्य दिवस लागू होते हैं।","ar":"بموجب 19 CFR 142.12(b)، يجب تقديم ملخص الإدخال مع الرسوم المقدَّرة خلال 10 أيام عمل بعد وقت الإدخال. ووقت الإدخال هو الإفراج (3 يونيو)، لذا فإن احتساب 10 أيام عمل (باستثناء عطلات نهاية الأسبوع) يؤدي إلى 17 يونيو. والمعتبر هو أيام العمل، وليس الأيام التقويمية."}},{"cat":"entry","a":2,"q":{"en":"Which statement about powers of attorney for making entry is FALSE?","es":"¿Cuál de las siguientes afirmaciones sobre los poderes para hacer la entrada es FALSA?","ru":"Какое из утверждений о доверенностях на оформление декларации ЛОЖНО?","tr":"Giriş yapmak için verilen vekaletnamelerle ilgili hangi ifade YANLIŞTIR?","hi":"प्रविष्टि करने के लिए मुख्तारनामों के बारे में कौन सा कथन असत्य है?","ar":"أي عبارة بشأن التوكيلات الخاصة بإجراء الإدخال غير صحيحة؟"},"o":[{"en":"A broker must retain the power of attorney and make it available to CBP upon request","es":"Un agente debe conservar el poder y ponerlo a disposición de CBP cuando lo solicite","ru":"Брокер должен хранить доверенность и предоставлять её CBP по запросу","tr":"Bir müşavir vekaletnameyi saklamalı ve talep üzerine CBP'ye sunmalıdır","hi":"एक दलाल को मुख्तारनामा बनाए रखना चाहिए और अनुरोध पर इसे CBP को उपलब्ध कराना चाहिए","ar":"يجب على الوسيط الاحتفاظ بالتوكيل وإتاحته لـ CBP عند الطلب"},{"en":"A power of attorney granted by a corporation may be for an unlimited period","es":"Un poder otorgado por una sociedad anónima puede ser por un período ilimitado","ru":"Доверенность, выданная корпорацией, может быть бессрочной","tr":"Bir şirket tarafından verilen vekaletname sınırsız bir süre için olabilir","hi":"किसी निगम द्वारा दिया गया मुख्तारनामा असीमित अवधि के लिए हो सकता है","ar":"يجوز أن يكون التوكيل الممنوح من شركة مساهمة لمدة غير محدودة"},{"en":"A power of attorney must always be witnessed by two CBP officers to be valid","es":"Un poder siempre debe ser presenciado por dos funcionarios de CBP para ser válido","ru":"Доверенность всегда должна быть засвидетельствована двумя сотрудниками CBP, чтобы быть действительной","tr":"Bir vekaletnamenin geçerli olması için her zaman iki CBP memuru tarafından tanıklık edilmesi gerekir","hi":"एक मुख्तारनामा वैध होने के लिए हमेशा दो CBP अधिकारियों द्वारा साक्ष्यांकित होना चाहिए","ar":"يجب دائمًا أن يشهد على التوكيل موظفان من CBP حتى يكون صحيحًا"},{"en":"A nonresident principal must include a designation of an agent for service of process","es":"Un poderdante no residente debe incluir la designación de un agente para la notificación de procesos legales","ru":"Доверитель-нерезидент должен включить назначение агента для вручения процессуальных документов","tr":"Mukim olmayan bir asil, tebligat için bir vekil tayinini içermelidir","hi":"एक अनिवासी मूलधारक को कानूनी प्रक्रिया की तामील के लिए एक एजेंट का पदनाम शामिल करना चाहिए","ar":"يجب أن يتضمن الموكِّل غير المقيم تعيين وكيل لتسلّم الإجراءات القانونية"}],"e":{"en":"There is no requirement that a power of attorney be witnessed by CBP officers. Under 19 CFR 141.36-141.39 and 141.46, nonresidents must designate an agent for service of process, corporate POAs may be unlimited in duration (141.34), and the broker must retain the POA and produce it on demand (141.46).","es":"No existe ningún requisito de que un poder sea presenciado por funcionarios de CBP. Conforme a 19 CFR 141.36-141.39 y 141.46, los no residentes deben designar un agente para la notificación de procesos legales, los poderes corporativos pueden ser de duración ilimitada (141.34), y el agente debe conservar el poder (POA) y presentarlo cuando se le requiera (141.46).","ru":"Не существует требования, чтобы доверенность была засвидетельствована сотрудниками CBP. Согласно 19 CFR 141.36-141.39 и 141.46, нерезиденты должны назначить агента для вручения процессуальных документов, корпоративные доверенности (POA) могут быть бессрочными (141.34), а брокер должен хранить доверенность и предъявлять её по требованию (141.46).","tr":"Bir vekaletnamenin CBP memurlarınca tanıklanması yönünde bir şart yoktur. 19 CFR 141.36-141.39 ve 141.46 uyarınca, mukim olmayanlar tebligat için bir vekil tayin etmeli, şirket vekaletnameleri (POA) süresiz olabilir (141.34) ve müşavir vekaletnameyi saklayıp talep üzerine ibraz etmelidir (141.46).","hi":"ऐसी कोई आवश्यकता नहीं है कि किसी मुख्तारनामे को CBP अधिकारियों द्वारा साक्ष्यांकित किया जाए। 19 CFR 141.36-141.39 और 141.46 के अंतर्गत, अनिवासियों को कानूनी प्रक्रिया की तामील के लिए एक एजेंट नियुक्त करना चाहिए, निगम के मुख्तारनामे (POA) असीमित अवधि के हो सकते हैं (141.34), और दलाल को मुख्तारनामा बनाए रखना चाहिए तथा माँगे जाने पर इसे प्रस्तुत करना चाहिए (141.46)।","ar":"لا يوجد اشتراط بأن يشهد موظفو CBP على التوكيل. وبموجب 19 CFR 141.36-141.39 و141.46، يجب على غير المقيمين تعيين وكيل لتسلّم الإجراءات القانونية، ويجوز أن تكون توكيلات الشركات (POA) غير محدودة المدة (141.34)، ويجب على الوسيط الاحتفاظ بالتوكيل وإبرازه عند الطلب (141.46)."}},{"cat":"entry","a":3,"q":{"en":"For merchandise entered under the immediate delivery procedure, an application supported by a pro forma invoice may be accepted in lieu of a commercial invoice. Which statement best describes this rule?","es":"Para la mercancía ingresada bajo el procedimiento de entrega inmediata, puede aceptarse una solicitud respaldada por una factura pro forma en lugar de una factura comercial. ¿Cuál de las siguientes afirmaciones describe mejor esta regla?","ru":"Для товаров, оформляемых по процедуре немедленной выдачи, заявление, подкреплённое проформа-инвойсом, может быть принято вместо коммерческого счёта-фактуры. Какое утверждение лучше всего описывает это правило?","tr":"Acil teslim prosedürü kapsamında giriş yapılan eşya için, ticari fatura yerine bir proforma fatura ile desteklenen bir başvuru kabul edilebilir. Bu kuralı en iyi hangi ifade tanımlar?","hi":"तत्काल सुपुर्दगी प्रक्रिया के अंतर्गत प्रविष्ट माल के लिए, वाणिज्यिक चालान के स्थान पर प्रो फॉर्मा चालान द्वारा समर्थित एक आवेदन स्वीकार किया जा सकता है। कौन सा कथन इस नियम का सर्वोत्तम वर्णन करता है?","ar":"بالنسبة للبضائع المُدخلة بموجب إجراء التسليم الفوري، يجوز قبول طلب مدعوم بفاتورة مبدئية (pro forma) بدلًا من الفاتورة التجارية. أي عبارة تصف هذه القاعدة على أفضل وجه؟"},"o":[{"en":"A commercial invoice is required and a pro forma invoice is never accepted at release","es":"Se requiere una factura comercial y nunca se acepta una factura pro forma al momento de la liberación","ru":"Коммерческий счёт-фактура обязателен, и проформа-инвойс никогда не принимается при выпуске","tr":"Ticari fatura zorunludur ve teslimde asla proforma fatura kabul edilmez","hi":"वाणिज्यिक चालान आवश्यक है और रिलीज़ पर प्रो फॉर्मा चालान कभी स्वीकार नहीं किया जाता","ar":"الفاتورة التجارية مطلوبة ولا تُقبل الفاتورة المبدئية أبدًا عند الإفراج"},{"en":"A commercial invoice must be filed but values may be omitted at release","es":"Debe presentarse una factura comercial, pero pueden omitirse los valores al momento de la liberación","ru":"Коммерческий счёт-фактура должен быть подан, но стоимости могут быть опущены при выпуске","tr":"Ticari fatura sunulmalıdır ancak teslimde değerler atlanabilir","hi":"वाणिज्यिक चालान दाखिल किया जाना चाहिए लेकिन रिलीज़ पर मूल्य छोड़े जा सकते हैं","ar":"يجب تقديم فاتورة تجارية لكن يجوز إغفال القيم عند الإفراج"},{"en":"A pro forma invoice may be substituted only for warehouse entries","es":"Una factura pro forma puede sustituirse solo para entradas de almacén","ru":"Проформа-инвойс может заменяться только для складских деклараций","tr":"Proforma fatura yalnızca antrepo girişleri için ikame edilebilir","hi":"प्रो फॉर्मा चालान केवल गोदाम प्रविष्टियों के लिए प्रतिस्थापित किया जा सकता है","ar":"لا يجوز استبدال الفاتورة المبدئية إلا لإدخالات المستودع"},{"en":"A pro forma or other document adequately describing the goods may be delivered in place of a commercial invoice","es":"Una factura pro forma u otro documento que describa adecuadamente la mercancía puede entregarse en lugar de una factura comercial","ru":"Проформа-инвойс или иной документ, адекватно описывающий товары, может быть представлен вместо коммерческого счёта-фактуры","tr":"Eşyayı yeterince tanımlayan bir proforma veya başka bir belge, ticari fatura yerine teslim edilebilir","hi":"माल का पर्याप्त वर्णन करने वाला प्रो फॉर्मा या अन्य दस्तावेज़ वाणिज्यिक चालान के स्थान पर दिया जा सकता है","ar":"يجوز تقديم فاتورة مبدئية أو مستند آخر يصف البضائع وصفًا كافيًا بدلًا من الفاتورة التجارية"}],"e":{"en":"Under 19 CFR 142.22(b), for immediate delivery a commercial invoice generally is not required; instead the importer may deliver a pro forma invoice, waybill, or other document setting forth an adequate description of the merchandise and quantities, with values when needed for examination.","es":"Conforme a 19 CFR 142.22(b), para la entrega inmediata generalmente no se requiere una factura comercial; en su lugar, el importador puede entregar una factura pro forma, una carta de porte (waybill) u otro documento que exponga una descripción adecuada de la mercancía y las cantidades, con los valores cuando sean necesarios para el examen.","ru":"Согласно 19 CFR 142.22(b), для немедленной выдачи коммерческий счёт-фактура, как правило, не требуется; вместо этого импортёр может представить проформа-инвойс, транспортную накладную (waybill) или иной документ с адекватным описанием товаров и количеств, со стоимостями, когда они необходимы для досмотра.","tr":"19 CFR 142.22(b) uyarınca, acil teslim için genellikle ticari fatura gerekmez; bunun yerine ithalatçı, eşyanın ve miktarların yeterli bir tanımını ortaya koyan bir proforma fatura, taşıma senedi (waybill) veya başka bir belge ile birlikte, muayene için gerektiğinde değerleri de sunabilir.","hi":"19 CFR 142.22(b) के अंतर्गत, तत्काल सुपुर्दगी के लिए सामान्यतः वाणिज्यिक चालान की आवश्यकता नहीं होती; इसके बजाय आयातक प्रो फॉर्मा चालान, वेबिल (waybill) या अन्य दस्तावेज़ दे सकता है जो माल और मात्राओं का पर्याप्त वर्णन प्रस्तुत करे, तथा जाँच के लिए आवश्यक होने पर मूल्यों के साथ।","ar":"بموجب 19 CFR 142.22(b)، لا تُطلب عادةً فاتورة تجارية للتسليم الفوري؛ وبدلًا من ذلك يجوز للمستورد تقديم فاتورة مبدئية أو بوليصة شحن (waybill) أو مستند آخر يبيّن وصفًا كافيًا للبضائع والكميات، مع القيم عند الحاجة إليها للفحص."}},{"cat":"entry","a":1,"q":{"en":"Which scenario correctly reflects the relationship between a TIB (temporary importation under bond) entry and duty liability?","es":"¿Qué escenario refleja correctamente la relación entre una entrada TIB (importación temporal bajo fianza) y la responsabilidad por derechos?","ru":"Какой сценарий правильно отражает связь между декларацией TIB (временный ввоз под поручительство) и обязательством по уплате пошлины?","tr":"Hangi senaryo, bir TIB (teminat altında geçici ithalat) girişi ile gümrük vergisi sorumluluğu arasındaki ilişkiyi doğru şekilde yansıtır?","hi":"कौन सा परिदृश्य TIB (बॉन्ड के अंतर्गत अस्थायी आयात) प्रविष्टि और शुल्क दायित्व के बीच के संबंध को सही ढंग से दर्शाता है?","ar":"أي سيناريو يعكس بشكل صحيح العلاقة بين إدخال TIB (الاستيراد المؤقت تحت التعهد) والمسؤولية عن الرسوم؟"},"o":[{"en":"Duty is collected at entry and refunded only after exportation","es":"El derecho se cobra en la entrada y se reembolsa solo después de la exportación","ru":"Пошлина взимается при ввозе и возмещается только после вывоза","tr":"Gümrük vergisi girişte tahsil edilir ve yalnızca ihracattan sonra iade edilir","hi":"शुल्क प्रविष्टि पर वसूला जाता है और केवल निर्यात के बाद वापस किया जाता है","ar":"تُحصَّل الرسوم عند الإدخال وتُرَدّ فقط بعد التصدير"},{"en":"No duty is collected because the goods are admitted under bond for a limited period and must be exported or destroyed","es":"No se cobra derecho porque la mercancía se admite bajo fianza por un período limitado y debe exportarse o destruirse","ru":"Пошлина не взимается, поскольку товары допускаются под поручительство на ограниченный срок и должны быть вывезены или уничтожены","tr":"Eşya sınırlı bir süre için teminat altında kabul edildiğinden ve ihraç edilmesi veya imha edilmesi gerektiğinden gümrük vergisi tahsil edilmez","hi":"कोई शुल्क नहीं वसूला जाता क्योंकि माल सीमित अवधि के लिए बॉन्ड के अंतर्गत प्रविष्ट किया जाता है और इसे निर्यात या नष्ट किया जाना चाहिए","ar":"لا تُحصَّل أي رسوم لأن البضائع تُقبل تحت تعهد لمدة محدودة ويجب تصديرها أو إتلافها"},{"en":"Duty is deferred and paid when the goods are withdrawn for consumption","es":"El derecho se difiere y se paga cuando la mercancía se retira para consumo","ru":"Пошлина отсрочивается и уплачивается при изъятии товаров для потребления","tr":"Gümrük vergisi ertelenir ve eşya tüketim için çekildiğinde ödenir","hi":"शुल्क स्थगित किया जाता है और तब चुकाया जाता है जब माल उपभोग के लिए निकाला जाता है","ar":"تُؤجَّل الرسوم وتُدفع عند سحب البضائع بغرض الاستهلاك"},{"en":"Duty is collected at double the normal rate as security for re-export","es":"El derecho se cobra al doble de la tasa normal como garantía para la reexportación","ru":"Пошлина взимается по двойной обычной ставке в качестве обеспечения для реэкспорта","tr":"Gümrük vergisi, yeniden ihracat için teminat olarak normal oranın iki katı tahsil edilir","hi":"पुनर्निर्यात के लिए प्रतिभूति के रूप में शुल्क सामान्य दर से दोगुना वसूला जाता है","ar":"تُحصَّل الرسوم بضعف المعدل العادي كضمان لإعادة التصدير"}],"e":{"en":"A TIB entry under HTSUS Chapter 98, Subchapter XIII (and 19 CFR 10.31-10.40) admits qualifying goods free of duty under bond, conditioned on exportation or destruction within the bonded period (generally one year, extendable to three). Failure to export results in liquidated damages, typically twice the estimated duties.","es":"Una entrada TIB conforme al Capítulo 98, Subcapítulo XIII del HTSUS (y 19 CFR 10.31-10.40) admite la mercancía elegible libre de derechos bajo fianza, condicionada a la exportación o destrucción dentro del período afianzado (por lo general un año, prorrogable a tres). El incumplimiento de la exportación da lugar a daños liquidados, típicamente el doble de los derechos estimados.","ru":"Декларация TIB согласно HTSUS Глава 98, Подглава XIII (и 19 CFR 10.31-10.40) допускает соответствующие требованиям товары беспошлинно под поручительство при условии вывоза или уничтожения в течение срока поручительства (как правило, один год с продлением до трёх). Невывоз влечёт за собой неустойку (liquidated damages), обычно в двойном размере оценочных пошлин.","tr":"HTSUS Bölüm 98, Alt Bölüm XIII (ve 19 CFR 10.31-10.40) kapsamındaki bir TIB girişi, uygun eşyayı teminat süresi içinde (genellikle bir yıl, üç yıla kadar uzatılabilir) ihraç edilmesi veya imha edilmesi şartıyla teminat altında gümrük vergisinden muaf olarak kabul eder. İhracatın gerçekleşmemesi, genellikle tahmini gümrük vergilerinin iki katı tutarında tasfiye edilmiş tazminata (liquidated damages) yol açar.","hi":"HTSUS अध्याय 98, उप-अध्याय XIII (और 19 CFR 10.31-10.40) के अंतर्गत एक TIB प्रविष्टि पात्र माल को बॉन्ड के अंतर्गत शुल्क-मुक्त प्रविष्ट करती है, जो बॉन्ड अवधि के भीतर (आमतौर पर एक वर्ष, तीन वर्ष तक विस्तार योग्य) निर्यात या विनाश की शर्त पर होती है। निर्यात न करने पर परिनिर्धारित क्षति (liquidated damages) होती है, जो आमतौर पर अनुमानित शुल्क का दोगुना होती है।","ar":"يقوم إدخال TIB بموجب الفصل 98، الفصل الفرعي XIII من HTSUS (و19 CFR 10.31-10.40) بقبول البضائع المؤهلة معفاة من الرسوم تحت تعهد، بشرط تصديرها أو إتلافها خلال مدة التعهد (سنة واحدة عمومًا، قابلة للتمديد إلى ثلاث سنوات). ويؤدي عدم التصدير إلى تعويضات مقطوعة (liquidated damages)، عادةً ضعف الرسوم المقدَّرة."}},{"cat":"entry","a":0,"q":{"en":"Which statement regarding the deposit of estimated duties at entry is TRUE?","es":"¿Cuál de las siguientes afirmaciones sobre el depósito de los derechos estimados en la entrada es VERDADERA?","ru":"Какое из утверждений относительно внесения оценочных пошлин при оформлении декларации ВЕРНО?","tr":"Giriş sırasında tahmini gümrük vergilerinin yatırılmasıyla ilgili hangi ifade DOĞRUDUR?","hi":"प्रविष्टि पर अनुमानित शुल्क के जमा करने के संबंध में कौन सा कथन सत्य है?","ar":"أي عبارة بشأن إيداع الرسوم المقدَّرة عند الإدخال صحيحة؟"},"o":[{"en":"Estimated duties must be deposited in accordance with subpart G of Part 141 when the entry summary is filed","es":"Los derechos estimados deben depositarse de conformidad con la subparte G de la Parte 141 cuando se presenta el resumen de entrada","ru":"Оценочные пошлины должны вноситься в соответствии с подразделом G Части 141 при подаче итоговой декларации","tr":"Tahmini gümrük vergileri, giriş özeti sunulduğunda Bölüm 141'in G alt bölümü uyarınca yatırılmalıdır","hi":"अनुमानित शुल्क भाग 141 के उपभाग G के अनुसार तब जमा किए जाने चाहिए जब एंट्री सारांश दाखिल किया जाता है","ar":"يجب إيداع الرسوم المقدَّرة وفقًا للجزء الفرعي G من الباب 141 عند تقديم ملخص الإدخال"},{"en":"Estimated duties are never required until after liquidation","es":"Los derechos estimados nunca se requieren hasta después de la liquidación","ru":"Оценочные пошлины никогда не требуются до ликвидации","tr":"Tahmini gümrük vergileri tasfiyeden önce hiçbir zaman talep edilmez","hi":"अनुमानित शुल्क परिनिर्धारण के बाद तक कभी आवश्यक नहीं होते","ar":"لا تُطلب الرسوم المقدَّرة أبدًا إلا بعد التصفية"},{"en":"Estimated duties are deposited only for warehouse withdrawals, not consumption entries","es":"Los derechos estimados se depositan solo para retiros de almacén, no para entradas de consumo","ru":"Оценочные пошлины вносятся только при изъятии со склада, а не при потребительских декларациях","tr":"Tahmini gümrük vergileri yalnızca antrepo çekilişleri için yatırılır, tüketim girişleri için değil","hi":"अनुमानित शुल्क केवल गोदाम निकासी के लिए जमा किए जाते हैं, उपभोग प्रविष्टियों के लिए नहीं","ar":"تُودَع الرسوم المقدَّرة فقط لعمليات السحب من المستودع، وليس لإدخالات الاستهلاك"},{"en":"Estimated duties must be deposited at the time the carrier files the manifest","es":"Los derechos estimados deben depositarse al momento en que el transportista presenta el manifiesto","ru":"Оценочные пошлины должны вноситься в момент подачи перевозчиком манифеста","tr":"Tahmini gümrük vergileri, taşıyıcının manifestoyu sunduğu anda yatırılmalıdır","hi":"अनुमानित शुल्क उस समय जमा किए जाने चाहिए जब वाहक मैनिफेस्ट दाखिल करता है","ar":"يجب إيداع الرسوم المقدَّرة وقت تقديم الناقل للبيان (manifest)"}],"e":{"en":"Under 19 CFR 142.12(b) and 142.13, estimated duties, if any, must be deposited in accordance with the provisions of subpart G of Part 141 of the regulations, generally when the entry summary documentation is filed (at entry or within the applicable time limit after release).","es":"Conforme a 19 CFR 142.12(b) y 142.13, los derechos estimados, si los hubiera, deben depositarse de conformidad con las disposiciones de la subparte G de la Parte 141 del reglamento, por lo general cuando se presenta la documentación del resumen de entrada (en la entrada o dentro del plazo aplicable después de la liberación).","ru":"Согласно 19 CFR 142.12(b) и 142.13, оценочные пошлины, при их наличии, должны вноситься в соответствии с положениями подраздела G Части 141 правил, как правило, при подаче документации итоговой декларации (при ввозе или в пределах применимого срока после выпуска).","tr":"19 CFR 142.12(b) ve 142.13 uyarınca, varsa, tahmini gümrük vergileri, yönetmeliğin Bölüm 141'in G alt bölümü hükümleri uyarınca, genellikle giriş özeti belgeleri sunulduğunda (girişte veya teslimden sonra geçerli süre içinde) yatırılmalıdır.","hi":"19 CFR 142.12(b) और 142.13 के अंतर्गत, यदि कोई हो, तो अनुमानित शुल्क विनियमों के भाग 141 के उपभाग G के प्रावधानों के अनुसार जमा किए जाने चाहिए, सामान्यतः तब जब एंट्री सारांश दस्तावेज़ दाखिल किए जाते हैं (प्रविष्टि पर या रिलीज़ के बाद लागू समय-सीमा के भीतर)।","ar":"بموجب 19 CFR 142.12(b) و142.13، يجب إيداع الرسوم المقدَّرة، إن وُجدت، وفقًا لأحكام الجزء الفرعي G من الباب 141 من اللوائح، وذلك عمومًا عند تقديم مستندات ملخص الإدخال (عند الإدخال أو خلال المهلة المعمول بها بعد الإفراج)."}},{"cat":"entry","a":1,"q":{"en":"Goods released under a special permit for immediate delivery are considered to remain in CBP custody until the filing of which document?","es":"La mercancía liberada bajo un permiso especial para entrega inmediata se considera que permanece bajo custodia de CBP hasta la presentación de ¿cuál documento?","ru":"Товары, выпущенные по специальному разрешению на немедленную выдачу, считаются остающимися под охраной CBP до подачи какого документа?","tr":"Acil teslim için özel izinle teslim edilen eşya, hangi belgenin sunulmasına kadar CBP gözetiminde kalmış sayılır?","hi":"तत्काल सुपुर्दगी के विशेष परमिट के तहत रिलीज़ किया गया माल किस दस्तावेज़ के दाखिल होने तक CBP की अभिरक्षा में रहना माना जाता है?","ar":"تُعتبر البضائع المُفرَج عنها بموجب تصريح خاص بالتسليم الفوري باقية في عهدة CBP حتى تقديم أي مستند؟"},"o":[{"en":"A protest under 19 USC 1514","es":"Una protesta conforme a 19 USC 1514","ru":"Протест согласно 19 USC 1514","tr":"19 USC 1514 uyarınca bir itiraz","hi":"19 USC 1514 के अंतर्गत एक विरोध (protest)","ar":"اعتراض بموجب 19 USC 1514"},{"en":"An entry summary for consumption, warehouse, or TIB, or an entry for transportation and exportation","es":"Un resumen de entrada para consumo, almacén o TIB, o una entrada para transporte y exportación","ru":"Итоговая декларация для потребления, склада или TIB, либо декларация на транспортировку и вывоз","tr":"Tüketim, antrepo veya TIB için bir giriş özeti ya da taşıma ve ihracat için bir giriş","hi":"उपभोग, गोदाम या TIB के लिए एक एंट्री सारांश, या परिवहन और निर्यात के लिए एक प्रविष्टि","ar":"ملخص إدخال للاستهلاك أو المستودع أو TIB، أو إدخال للنقل والتصدير"},{"en":"The carrier's outbound manifest","es":"El manifiesto de salida del transportista","ru":"Исходящий манифест перевозчика","tr":"Taşıyıcının çıkış manifestosu","hi":"वाहक का जावक मैनिफेस्ट","ar":"بيان المغادرة الخاص بالناقل"},{"en":"A drawback claim under 19 USC 1313","es":"Una reclamación de devolución (drawback) conforme a 19 USC 1313","ru":"Требование о возврате пошлины (drawback) согласно 19 USC 1313","tr":"19 USC 1313 uyarınca bir geri ödeme (drawback) talebi","hi":"19 USC 1313 के अंतर्गत एक ड्रॉबैक दावा","ar":"مطالبة بالاسترداد (drawback) بموجب 19 USC 1313"}],"e":{"en":"Under 19 CFR 142.22(c), merchandise for which a special permit for immediate delivery has been issued is considered to remain in CBP custody until the filing of an entry summary for consumption, for warehouse, or for entry temporarily under bond (TIB), or an entry for transportation and exportation.","es":"Conforme a 19 CFR 142.22(c), la mercancía para la cual se ha emitido un permiso especial para entrega inmediata se considera que permanece bajo custodia de CBP hasta la presentación de un resumen de entrada para consumo, para almacén o para importación temporal bajo fianza (TIB), o una entrada para transporte y exportación.","ru":"Согласно 19 CFR 142.22(c), товары, на которые выдано специальное разрешение на немедленную выдачу, считаются остающимися под охраной CBP до подачи итоговой декларации для потребления, для склада или для временного ввоза под поручительство (TIB), либо декларации на транспортировку и вывоз.","tr":"19 CFR 142.22(c) uyarınca, acil teslim için özel izin düzenlenen eşya, tüketim, antrepo veya teminat altında geçici ithalat (TIB) için bir giriş özeti ya da taşıma ve ihracat için bir giriş sunulana kadar CBP gözetiminde kalmış sayılır.","hi":"19 CFR 142.22(c) के अंतर्गत, जिस माल के लिए तत्काल सुपुर्दगी का विशेष परमिट जारी किया गया है, उसे उपभोग, गोदाम या बॉन्ड के अंतर्गत अस्थायी आयात (TIB) के लिए एक एंट्री सारांश, या परिवहन और निर्यात के लिए एक प्रविष्टि दाखिल होने तक CBP की अभिरक्षा में रहना माना जाता है।","ar":"بموجب 19 CFR 142.22(c)، تُعتبر البضائع التي صدر بشأنها تصريح خاص بالتسليم الفوري باقية في عهدة CBP حتى تقديم ملخص إدخال للاستهلاك أو للمستودع أو للاستيراد المؤقت تحت التعهد (TIB)، أو إدخال للنقل والتصدير."}},{"cat":"entry","a":0,"q":{"en":"An importer requests, on the entry documentation at the time of filing, that the time of entry be the time the documentation is filed. Under 19 CFR 141.68, this is permissible only if:","es":"Un importador solicita, en la documentación de entrada al momento de su presentación, que el momento de la entrada sea el momento en que se presenta la documentación. Conforme a 19 CFR 141.68, esto se permite solo si:","ru":"Импортёр запрашивает в документации ввоза при подаче, чтобы моментом ввоза считался момент подачи документации. Согласно 19 CFR 141.68, это допустимо только если:","tr":"Bir ithalatçı, sunum sırasında giriş belgeleri üzerinde, giriş anının belgelerin sunulduğu an olmasını talep eder. 19 CFR 141.68 uyarınca, bu yalnızca şu durumda mümkündür:","hi":"एक आयातक दाखिल करने के समय प्रविष्टि दस्तावेज़ पर अनुरोध करता है कि प्रविष्टि का समय वह समय हो जब दस्तावेज़ दाखिल किए जाते हैं। 19 CFR 141.68 के अंतर्गत, यह केवल तभी अनुमेय है यदि:","ar":"يطلب مستورد، على مستندات الإدخال وقت التقديم، أن يكون وقت الإدخال هو وقت تقديم المستندات. وبموجب 19 CFR 141.68، لا يُسمح بذلك إلا إذا:"},"o":[{"en":"The merchandise has already arrived within the port limits","es":"La mercancía ya ha llegado dentro de los límites del puerto","ru":"Товары уже прибыли в пределы порта","tr":"Eşya liman sınırları içine zaten ulaşmışsa","hi":"माल पहले से ही बंदरगाह की सीमा के भीतर पहुँच चुका हो","ar":"تكون البضائع قد وصلت بالفعل إلى داخل حدود الميناء"},{"en":"The port director personally signs the release","es":"El director del puerto firma personalmente la liberación","ru":"Директор порта лично подписывает выпуск","tr":"Liman müdürü teslimi bizzat imzalarsa","hi":"बंदरगाह निदेशक व्यक्तिगत रूप से रिलीज़ पर हस्ताक्षर करे","ar":"يوقّع مدير الميناء شخصيًا على الإفراج"},{"en":"A continuous bond is converted to a single transaction bond","es":"Una fianza continua se convierte en una fianza de transacción única","ru":"Непрерывное поручительство преобразуется в разовое поручительство","tr":"Sürekli teminat tek işlem teminatına dönüştürülürse","hi":"एक निरंतर बॉन्ड को एकल लेनदेन बॉन्ड में परिवर्तित किया जाए","ar":"يُحوَّل تعهد مستمر إلى تعهد معاملة واحدة"},{"en":"The estimated duties have been paid in cash","es":"Los derechos estimados se han pagado en efectivo","ru":"Оценочные пошлины уплачены наличными","tr":"Tahmini gümrük vergileri nakit olarak ödenmişse","hi":"अनुमानित शुल्क नकद में चुका दिए गए हों","ar":"تكون الرسوم المقدَّرة قد دُفعت نقدًا"}],"e":{"en":"Under 19 CFR 141.68(a), when entry documentation is filed without an entry summary, the time of entry may be the time the documentation is filed if requested by the importer at filing AND the merchandise has already arrived within the port limits. If filed before arrival, the time of entry can be set as the time of arrival.","es":"Conforme a 19 CFR 141.68(a), cuando la documentación de entrada se presenta sin un resumen de entrada, el momento de la entrada puede ser el momento en que se presenta la documentación si lo solicita el importador al presentarla Y la mercancía ya ha llegado dentro de los límites del puerto. Si se presenta antes de la llegada, el momento de la entrada puede fijarse como el momento de la llegada.","ru":"Согласно 19 CFR 141.68(a), когда документация ввоза подаётся без итоговой декларации, моментом ввоза может считаться момент подачи документации, если об этом просит импортёр при подаче И товары уже прибыли в пределы порта. Если подано до прибытия, моментом ввоза может быть установлен момент прибытия.","tr":"19 CFR 141.68(a) uyarınca, giriş belgeleri bir giriş özeti olmadan sunulduğunda, ithalatçı sunum sırasında talep ederse VE eşya liman sınırları içine zaten ulaşmışsa, giriş anı belgelerin sunulduğu an olabilir. Varıştan önce sunulursa, giriş anı varış anı olarak belirlenebilir.","hi":"19 CFR 141.68(a) के अंतर्गत, जब प्रविष्टि दस्तावेज़ एंट्री सारांश के बिना दाखिल किए जाते हैं, तो प्रविष्टि का समय दस्तावेज़ दाखिल होने का समय हो सकता है यदि आयातक दाखिल करते समय इसका अनुरोध करे और माल पहले से ही बंदरगाह की सीमा के भीतर पहुँच चुका हो। यदि आगमन से पहले दाखिल किया जाता है, तो प्रविष्टि का समय आगमन के समय के रूप में निर्धारित किया जा सकता है।","ar":"بموجب 19 CFR 141.68(a)، عندما تُقدَّم مستندات الإدخال دون ملخص إدخال، يجوز أن يكون وقت الإدخال هو وقت تقديم المستندات إذا طلب المستورد ذلك عند التقديم وكانت البضائع قد وصلت بالفعل إلى داخل حدود الميناء. وإذا قُدِّمت قبل الوصول، فيمكن تحديد وقت الإدخال على أنه وقت الوصول."}},{"cat":"entry","a":2,"q":{"en":"Country of origin marking most directly affects entry release in which way?","es":"¿De qué manera afecta más directamente el marcado del país de origen a la liberación de la entrada?","ru":"Каким образом маркировка страны происхождения наиболее непосредственно влияет на выпуск при оформлении декларации?","tr":"Menşe ülke işaretlemesi, giriş teslimini en doğrudan hangi şekilde etkiler?","hi":"मूल देश का अंकन (marking) प्रविष्टि रिलीज़ को किस प्रकार सबसे प्रत्यक्ष रूप से प्रभावित करता है?","ar":"كيف يؤثر وضع علامة بلد المنشأ على الإفراج عند الإدخال بشكل مباشر أكثر من غيره؟"},"o":[{"en":"Marking duties are deposited in lieu of regular estimated duties at entry","es":"Los derechos de marcado se depositan en lugar de los derechos estimados regulares en la entrada","ru":"Пошлины за маркировку вносятся вместо обычных оценочных пошлин при оформлении декларации","tr":"İşaretleme vergileri, girişte olağan tahmini gümrük vergileri yerine yatırılır","hi":"अंकन शुल्क प्रविष्टि पर नियमित अनुमानित शुल्क के स्थान पर जमा किए जाते हैं","ar":"تُودَع رسوم وضع العلامة بدلًا من الرسوم المقدَّرة العادية عند الإدخال"},{"en":"Marking requirements apply only after liquidation and never affect release","es":"Los requisitos de marcado se aplican solo después de la liquidación y nunca afectan la liberación","ru":"Требования к маркировке применяются только после ликвидации и никогда не влияют на выпуск","tr":"İşaretleme şartları yalnızca tasfiyeden sonra uygulanır ve teslimi asla etkilemez","hi":"अंकन आवश्यकताएँ केवल परिनिर्धारण के बाद लागू होती हैं और कभी रिलीज़ को प्रभावित नहीं करतीं","ar":"تنطبق متطلبات وضع العلامة فقط بعد التصفية ولا تؤثر أبدًا على الإفراج"},{"en":"Unmarked or improperly marked goods may be denied release or subject to marking/redelivery requirements before they are conditionally released","es":"La mercancía sin marcar o marcada incorrectamente puede que se le niegue la liberación o quedar sujeta a requisitos de marcado/reentrega antes de ser liberada condicionalmente","ru":"Немаркированным или неправильно маркированным товарам может быть отказано в выпуске либо они могут подлежать требованиям маркировки/возврата до их условного выпуска","tr":"İşaretlenmemiş veya yanlış işaretlenmiş mallar, koşullu olarak teslim edilmeden önce teslimleri reddedilebilir ya da işaretleme/yeniden teslim şartlarına tabi tutulabilir","hi":"बिना अंकित या गलत अंकित माल को रिलीज़ से वंचित किया जा सकता है या सशर्त रूप से रिलीज़ किए जाने से पहले अंकन/पुनर्सुपुर्दगी आवश्यकताओं के अधीन किया जा सकता है","ar":"قد يُرفض الإفراج عن البضائع غير المعلَّمة أو المعلَّمة بشكل غير صحيح، أو تخضع لمتطلبات وضع العلامة/إعادة التسليم قبل الإفراج عنها بشكل مشروط"},{"en":"Marking is satisfied solely by the commercial invoice and never affects the goods themselves","es":"El marcado se cumple únicamente mediante la factura comercial y nunca afecta a la mercancía en sí","ru":"Маркировка обеспечивается исключительно коммерческим счётом-фактурой и никогда не затрагивает сами товары","tr":"İşaretleme yalnızca ticari fatura ile yerine getirilir ve eşyanın kendisini asla etkilemez","hi":"अंकन केवल वाणिज्यिक चालान द्वारा पूरा होता है और कभी स्वयं माल को प्रभावित नहीं करता","ar":"يُستوفى وضع العلامة بالفاتورة التجارية وحدها ولا يؤثر أبدًا على البضائع نفسها"}],"e":{"en":"Under 19 USC 1304 and 19 CFR Part 134, imported articles must be legibly and conspicuously marked with country of origin. At entry, improperly marked goods may be held, conditionally released subject to marking, or subject to redelivery, and marking duties (10%) may apply under 19 CFR 134.51-134.55 if not properly marked or redelivered.","es":"Conforme a 19 USC 1304 y 19 CFR Part 134, los artículos importados deben marcarse de manera legible y visible con el país de origen. En la entrada, la mercancía marcada incorrectamente puede ser retenida, liberada condicionalmente sujeta a marcado, o quedar sujeta a reentrega, y pueden aplicarse derechos de marcado (10%) conforme a 19 CFR 134.51-134.55 si no se marca o reentrega correctamente.","ru":"Согласно 19 USC 1304 и 19 CFR Part 134, импортируемые изделия должны быть разборчиво и заметно маркированы страной происхождения. При оформлении декларации неправильно маркированные товары могут быть задержаны, условно выпущены при условии маркировки или подлежать возврату, а пошлины за маркировку (10%) могут применяться согласно 19 CFR 134.51-134.55, если они не маркированы или не возвращены надлежащим образом.","tr":"19 USC 1304 ve 19 CFR Part 134 uyarınca, ithal edilen eşyanın menşe ülkesi okunaklı ve göze çarpacak şekilde işaretlenmelidir. Girişte, yanlış işaretlenmiş mallar alıkonulabilir, işaretleme şartıyla koşullu olarak teslim edilebilir veya yeniden teslime tabi tutulabilir; ve düzgün şekilde işaretlenmez ya da yeniden teslim edilmezse 19 CFR 134.51-134.55 uyarınca işaretleme vergileri (10%) uygulanabilir.","hi":"19 USC 1304 और 19 CFR Part 134 के अंतर्गत, आयातित वस्तुओं पर मूल देश का अंकन सुपाठ्य और स्पष्ट रूप से होना चाहिए। प्रविष्टि पर, गलत अंकित माल को रोका जा सकता है, अंकन की शर्त पर सशर्त रूप से रिलीज़ किया जा सकता है, या पुनर्सुपुर्दगी के अधीन किया जा सकता है, और यदि उचित रूप से अंकित या पुनर्सुपुर्द न किया जाए तो 19 CFR 134.51-134.55 के अंतर्गत अंकन शुल्क (10%) लागू हो सकता है।","ar":"بموجب 19 USC 1304 و19 CFR Part 134، يجب وضع علامة بلد المنشأ على السلع المستوردة بشكل واضح وبارز. وعند الإدخال، يجوز احتجاز البضائع المعلَّمة بشكل غير صحيح، أو الإفراج عنها بشكل مشروط رهنًا بوضع العلامة، أو إخضاعها لإعادة التسليم، وقد تُطبَّق رسوم وضع العلامة (10%) بموجب 19 CFR 134.51-134.55 إذا لم تُعلَّم أو تُعَد تسليمها بشكل صحيح."}},{"cat":"entry","a":1,"q":{"en":"Which of the following statements about the entry summary (CBP Form 7501) is FALSE?","es":"¿Cuál de las siguientes afirmaciones sobre el resumen de entrada (CBP Form 7501) es FALSA?","ru":"Какое из следующих утверждений об итоговой декларации (CBP Form 7501) ЛОЖНО?","tr":"Giriş özeti (CBP Form 7501) hakkındaki aşağıdaki ifadelerden hangisi YANLIŞTIR?","hi":"एंट्री सारांश (CBP Form 7501) के बारे में निम्नलिखित में से कौन सा कथन असत्य है?","ar":"أي من العبارات التالية بشأن ملخص الإدخال (CBP Form 7501) غير صحيحة؟"},"o":[{"en":"It is used for merchandise formally entered for consumption","es":"Se utiliza para mercancía formalmente ingresada para consumo","ru":"Она используется для товаров, формально ввезённых для потребления","tr":"Tüketim için resmi olarak giriş yapılan eşya için kullanılır","hi":"इसका उपयोग उपभोग के लिए औपचारिक रूप से प्रविष्ट माल के लिए किया जाता है","ar":"تُستخدم للبضائع المُدخلة رسميًا بغرض الاستهلاك"},{"en":"It may never serve as both the entry and the entry summary documentation","es":"Nunca puede servir a la vez como la entrada y la documentación del resumen de entrada","ru":"Она никогда не может служить одновременно и ввозом, и документацией итоговой декларации","tr":"Hiçbir zaman hem giriş hem de giriş özeti belgesi olarak hizmet edemez","hi":"यह कभी भी एक साथ प्रविष्टि और एंट्री सारांश दस्तावेज़ दोनों के रूप में कार्य नहीं कर सकता","ar":"لا يمكن أبدًا أن تقوم بدور الإدخال ومستند ملخص الإدخال معًا"},{"en":"It is used for merchandise formally entered temporarily under bond","es":"Se utiliza para mercancía formalmente ingresada temporalmente bajo fianza","ru":"Она используется для товаров, формально ввезённых временно под поручительство","tr":"Teminat altında geçici olarak resmi şekilde giriş yapılan eşya için kullanılır","hi":"इसका उपयोग बॉन्ड के अंतर्गत अस्थायी रूप से औपचारिक रूप से प्रविष्ट माल के लिए किया जाता है","ar":"تُستخدم للبضائع المُدخلة رسميًا بشكل مؤقت تحت تعهد"},{"en":"It is used for merchandise formally entered for warehouse under 19 CFR 144.11","es":"Se utiliza para mercancía formalmente ingresada para almacén conforme a 19 CFR 144.11","ru":"Она используется для товаров, формально ввезённых для склада согласно 19 CFR 144.11","tr":"19 CFR 144.11 uyarınca antrepo için resmi olarak giriş yapılan eşya için kullanılır","hi":"इसका उपयोग 19 CFR 144.11 के अंतर्गत गोदाम के लिए औपचारिक रूप से प्रविष्ट माल के लिए किया जाता है","ar":"تُستخدم للبضائع المُدخلة رسميًا للمستودع بموجب 19 CFR 144.11"}],"e":{"en":"Under 19 CFR 142.3(b) and 142.12(a)(1), when the entry summary is filed at the time of entry, CBP Form 7501 may serve as BOTH the entry and the entry summary. The form is used for formal consumption, warehouse (144.11), and TIB entries, so only the last statement is false.","es":"Conforme a 19 CFR 142.3(b) y 142.12(a)(1), cuando el resumen de entrada se presenta en el momento de la entrada, el CBP Form 7501 puede servir a la vez como la entrada Y el resumen de entrada. El formulario se utiliza para entradas formales de consumo, de almacén (144.11) y TIB, por lo que solo la última afirmación es falsa.","ru":"Согласно 19 CFR 142.3(b) и 142.12(a)(1), когда итоговая декларация подаётся в момент ввоза, CBP Form 7501 может служить ОДНОВРЕМЕННО и ввозом, и итоговой декларацией. Форма используется для формальных потребительских, складских (144.11) и TIB-деклараций, поэтому ложно только последнее утверждение.","tr":"19 CFR 142.3(b) ve 142.12(a)(1) uyarınca, giriş özeti giriş anında sunulduğunda, CBP Form 7501 hem giriş HEM DE giriş özeti olarak hizmet edebilir. Form, resmi tüketim, antrepo (144.11) ve TIB girişleri için kullanılır, bu nedenle yalnızca son ifade yanlıştır.","hi":"19 CFR 142.3(b) और 142.12(a)(1) के अंतर्गत, जब एंट्री सारांश प्रविष्टि के समय दाखिल किया जाता है, तो CBP Form 7501 एक साथ प्रविष्टि और एंट्री सारांश दोनों के रूप में कार्य कर सकता है। यह फॉर्म औपचारिक उपभोग, गोदाम (144.11), और TIB प्रविष्टियों के लिए उपयोग किया जाता है, इसलिए केवल अंतिम कथन असत्य है।","ar":"بموجب 19 CFR 142.3(b) و142.12(a)(1)، عندما يُقدَّم ملخص الإدخال في وقت الإدخال، يجوز أن تقوم استمارة CBP Form 7501 بدور الإدخال وملخص الإدخال معًا. وتُستخدم الاستمارة لإدخالات الاستهلاك الرسمية والمستودع (144.11) وTIB، ولذا فإن العبارة الأخيرة وحدها هي غير الصحيحة."}},{"cat":"entry","a":2,"q":{"en":"An entry is flagged and CBP extends liquidation because information needed for proper appraisement is not yet available. What is the maximum total period, measured from the date of entry, before the entry must be treated as liquidated as entered?","es":"Una entrada se marca y CBP prorroga la liquidación porque la información necesaria para una correcta valoración aún no está disponible. ¿Cuál es el período total máximo, contado desde la fecha de entrada, antes de que la entrada deba tratarse como liquidada según se ingresó?","ru":"Декларация помечена, и CBP продлевает ликвидацию, поскольку информация, необходимая для надлежащей оценки, ещё недоступна. Каков максимальный общий срок, отсчитываемый от даты ввоза, до того как декларация должна считаться ликвидированной в заявленном виде?","tr":"Bir giriş işaretlenir ve uygun değerlendirme için gereken bilgi henüz mevcut olmadığından CBP tasfiyeyi uzatır. Girişin, beyan edildiği şekliyle tasfiye edilmiş sayılması gerekmeden önce, giriş tarihinden itibaren ölçülen azami toplam süre nedir?","hi":"एक प्रविष्टि को फ्लैग किया जाता है और CBP परिनिर्धारण को विस्तारित करता है क्योंकि उचित मूल्यांकन के लिए आवश्यक जानकारी अभी उपलब्ध नहीं है। प्रविष्टि की तारीख से मापा गया अधिकतम कुल अवधि क्या है, इससे पहले कि प्रविष्टि को प्रविष्ट किए अनुसार परिनिर्धारित माना जाए?","ar":"يُعلَّم إدخال وتمدّد CBP التصفية لأن المعلومات اللازمة للتقييم الصحيح غير متوفرة بعد. ما هي المدة الإجمالية القصوى، محسوبة من تاريخ الإدخال، قبل أن يُعامل الإدخال على أنه مُصفّى كما أُدخل؟"},"o":[{"en":"2 years","es":"2 años","ru":"2 года","tr":"2 yıl","hi":"2 वर्ष","ar":"سنتان"},{"en":"5 years","es":"5 años","ru":"5 лет","tr":"5 yıl","hi":"5 वर्ष","ar":"5 سنوات"},{"en":"4 years","es":"4 años","ru":"4 года","tr":"4 yıl","hi":"4 वर्ष","ar":"4 سنوات"},{"en":"3 years","es":"3 años","ru":"3 года","tr":"3 yıl","hi":"3 वर्ष","ar":"3 سنوات"}],"e":{"en":"Under 19 USC 1504(b) and (d), liquidation may be extended in one-year increments, but the total period of extensions generally cannot push liquidation beyond 4 years from the date of entry, at which point the entry is treated as liquidated at the rate, value, quantity, and duty asserted by the importer at entry.","es":"Conforme a 19 USC 1504(b) y (d), la liquidación puede prorrogarse en incrementos de un año, pero el período total de prórrogas generalmente no puede extender la liquidación más allá de 4 años a partir de la fecha de entrada, momento en el cual la entrada se trata como liquidada según la tasa, el valor, la cantidad y el derecho declarados por el importador en la entrada.","ru":"Согласно 19 USC 1504(b) и (d), ликвидация может продлеваться с шагом в один год, но общий срок продлений, как правило, не может отодвинуть ликвидацию более чем на 4 года с даты ввоза, после чего декларация считается ликвидированной по ставке, стоимости, количеству и пошлине, заявленным импортёром при ввозе.","tr":"19 USC 1504(b) ve (d) uyarınca, tasfiye birer yıllık artışlarla uzatılabilir, ancak uzatmaların toplam süresi genellikle tasfiyeyi giriş tarihinden itibaren 4 yılın ötesine taşıyamaz; bu noktada giriş, ithalatçının girişte beyan ettiği oran, değer, miktar ve gümrük vergisi üzerinden tasfiye edilmiş sayılır.","hi":"19 USC 1504(b) और (d) के अंतर्गत, परिनिर्धारण को एक-एक वर्ष की वृद्धि में विस्तारित किया जा सकता है, लेकिन विस्तारों की कुल अवधि सामान्यतः परिनिर्धारण को प्रविष्टि की तारीख से 4 वर्ष से आगे नहीं बढ़ा सकती, जिस बिंदु पर प्रविष्टि को आयातक द्वारा प्रविष्टि पर घोषित दर, मूल्य, मात्रा और शुल्क पर परिनिर्धारित माना जाता है।","ar":"بموجب 19 USC 1504(b) و(d)، يجوز تمديد التصفية بزيادات قدرها سنة واحدة، لكن المدة الإجمالية للتمديدات لا يمكن عمومًا أن تدفع التصفية إلى ما بعد 4 سنوات من تاريخ الإدخال، وعندها يُعامل الإدخال على أنه مُصفّى وفقًا للمعدل والقيمة والكمية والرسم الذي أعلنه المستورد عند الإدخال."}},{"cat":"entry","a":2,"q":{"en":"Which statement correctly distinguishes the documents used to RELEASE merchandise from the document used to account for it (the entry summary)?","es":"¿Cuál de las siguientes afirmaciones distingue correctamente los documentos utilizados para LIBERAR la mercancía del documento utilizado para declararla (el resumen de entrada)?","ru":"Какое из утверждений правильно различает документы, используемые для ВЫПУСКА товаров, и документ, используемый для их учёта (итоговая декларация)?","tr":"Hangi ifade, eşyayı TESLİM ETMEK için kullanılan belgeleri, onu hesaba katmak için kullanılan belgeden (giriş özeti) doğru şekilde ayırır?","hi":"कौन सा कथन माल को रिलीज़ करने के लिए उपयोग किए जाने वाले दस्तावेज़ों को उसका लेखा-जोखा करने के लिए उपयोग किए जाने वाले दस्तावेज़ (एंट्री सारांश) से सही ढंग से अलग करता है?","ar":"أي عبارة تميّز بشكل صحيح بين المستندات المستخدمة للإفراج عن البضائع والمستند المستخدم لحسابها (ملخص الإدخال)؟"},"o":[{"en":"CBP Form 7501 releases the goods, while CBP Form 3461 accounts for duties owed","es":"El CBP Form 7501 libera la mercancía, mientras que el CBP Form 3461 declara los derechos adeudados","ru":"CBP Form 7501 выпускает товары, тогда как CBP Form 3461 учитывает причитающиеся пошлины","tr":"CBP Form 7501 eşyayı teslim eder, CBP Form 3461 ise ödenecek gümrük vergilerini hesaba katar","hi":"CBP Form 7501 माल को रिलीज़ करता है, जबकि CBP Form 3461 देय शुल्कों का लेखा-जोखा करता है","ar":"تُفرج CBP Form 7501 عن البضائع، بينما تحسب CBP Form 3461 الرسوم المستحقة"},{"en":"Both release and accounting are accomplished only by CBP Form 5106","es":"Tanto la liberación como la declaración se logran únicamente mediante el CBP Form 5106","ru":"И выпуск, и учёт осуществляются только посредством CBP Form 5106","tr":"Hem teslim hem de hesaba katma yalnızca CBP Form 5106 ile gerçekleştirilir","hi":"रिलीज़ और लेखा-जोखा दोनों केवल CBP Form 5106 द्वारा पूरे किए जाते हैं","ar":"يتم كل من الإفراج والحساب فقط بواسطة CBP Form 5106"},{"en":"CBP Form 3461 (or 7533 for contiguous in-bond goods) secures release, while CBP Form 7501 is the entry summary that accounts for the goods and duties","es":"El CBP Form 3461 (o el 7533 para mercancía in-bond de países contiguos) asegura la liberación, mientras que el CBP Form 7501 es el resumen de entrada que declara la mercancía y los derechos","ru":"CBP Form 3461 (или 7533 для транзитных in-bond товаров из сопредельных стран) обеспечивает выпуск, тогда как CBP Form 7501 — это итоговая декларация, учитывающая товары и пошлины","tr":"CBP Form 3461 (veya komşu ülkelerden gelen in-bond eşya için 7533) teslimi sağlar, CBP Form 7501 ise eşyayı ve gümrük vergilerini hesaba katan giriş özetidir","hi":"CBP Form 3461 (या संलग्न देशों के इन-बॉन्ड माल के लिए 7533) रिलीज़ सुनिश्चित करता है, जबकि CBP Form 7501 एंट्री सारांश है जो माल और शुल्कों का लेखा-जोखा करता है","ar":"تؤمّن CBP Form 3461 (أو 7533 للبضائع تحت التعهد من الدول المتاخمة) الإفراج، بينما CBP Form 7501 هي ملخص الإدخال الذي يحسب البضائع والرسوم"},{"en":"CBP Form 301 releases the goods, while CBP Form 3461 is the entry summary","es":"El CBP Form 301 libera la mercancía, mientras que el CBP Form 3461 es el resumen de entrada","ru":"CBP Form 301 выпускает товары, тогда как CBP Form 3461 — это итоговая декларация","tr":"CBP Form 301 eşyayı teslim eder, CBP Form 3461 ise giriş özetidir","hi":"CBP Form 301 माल को रिलीज़ करता है, जबकि CBP Form 3461 एंट्री सारांश है","ar":"تُفرج CBP Form 301 عن البضائع، بينما CBP Form 3461 هي ملخص الإدخال"}],"e":{"en":"Under 19 CFR 142.3 and 142.11, release ('entry') is secured by CBP Form 3461 (or 7533 for merchandise from a contiguous country moving in bond), while the entry summary that accounts for the merchandise, classification, and duties is CBP Form 7501. Form 301 is the bond; 5106 is the importer ID record.","es":"Conforme a 19 CFR 142.3 y 142.11, la liberación ('entrada') se asegura mediante el CBP Form 3461 (o el 7533 para mercancía de un país contiguo que se mueve in-bond), mientras que el resumen de entrada que declara la mercancía, la clasificación y los derechos es el CBP Form 7501. El Form 301 es la fianza; el 5106 es el registro de identidad del importador.","ru":"Согласно 19 CFR 142.3 и 142.11, выпуск («ввоз») обеспечивается CBP Form 3461 (или 7533 для товаров из сопредельной страны, перемещаемых in-bond), тогда как итоговой декларацией, учитывающей товары, классификацию и пошлины, является CBP Form 7501. Форма 301 — это поручительство; 5106 — запись об идентификации импортёра.","tr":"19 CFR 142.3 ve 142.11 uyarınca, teslim ('giriş'), CBP Form 3461 (veya in-bond hareket eden komşu bir ülkeden gelen eşya için 7533) ile sağlanır; eşyayı, sınıflandırmayı ve gümrük vergilerini hesaba katan giriş özeti ise CBP Form 7501'dir. Form 301 teminattır; 5106 ithalatçı kimlik kaydıdır.","hi":"19 CFR 142.3 और 142.11 के अंतर्गत, रिलीज़ ('प्रविष्टि') CBP Form 3461 (या इन-बॉन्ड चलने वाले संलग्न देश के माल के लिए 7533) द्वारा सुनिश्चित की जाती है, जबकि माल, वर्गीकरण और शुल्कों का लेखा-जोखा करने वाला एंट्री सारांश CBP Form 7501 है। फॉर्म 301 बॉन्ड है; 5106 आयातक पहचान रिकॉर्ड है।","ar":"بموجب 19 CFR 142.3 و142.11، يُؤمَّن الإفراج ('الإدخال') بواسطة CBP Form 3461 (أو 7533 للبضائع القادمة من دولة متاخمة وتتحرك تحت التعهد in-bond)، بينما ملخص الإدخال الذي يحسب البضائع والتصنيف والرسوم هو CBP Form 7501. والاستمارة 301 هي التعهد؛ و5106 هي سجل هوية المستورد."}},{"cat":"entry","a":3,"q":{"en":"Regarding documentation required to secure release of merchandise under 19 CFR 142.3, which of the following is required to be filed as part of the entry documentation?","es":"Respecto a la documentación requerida para asegurar la liberación de la mercancía conforme a 19 CFR 142.3, ¿cuál de los siguientes se requiere presentar como parte de la documentación de entrada?","ru":"Что касается документации, необходимой для обеспечения выпуска товаров согласно 19 CFR 142.3, какой из следующих документов обязателен к подаче в составе документации ввоза?","tr":"19 CFR 142.3 uyarınca eşyanın teslimini sağlamak için gereken belgelerle ilgili olarak, aşağıdakilerden hangisinin giriş belgelerinin bir parçası olarak sunulması gerekir?","hi":"19 CFR 142.3 के अंतर्गत माल की रिलीज़ सुनिश्चित करने के लिए आवश्यक दस्तावेज़ों के संबंध में, निम्नलिखित में से कौन सा प्रविष्टि दस्तावेज़ के भाग के रूप में दाखिल करना आवश्यक है?","ar":"فيما يتعلق بالمستندات المطلوبة لتأمين الإفراج عن البضائع بموجب 19 CFR 142.3، أي مما يلي يجب تقديمه كجزء من مستندات الإدخال؟"},"o":[{"en":"An invoice as required by 19 CFR 142.6 (or a bond for missing documents)","es":"Una factura conforme a lo requerido por 19 CFR 142.6 (o una fianza por documentos faltantes)","ru":"Счёт-фактура, как требуется по 19 CFR 142.6 (или поручительство за отсутствующие документы)","tr":"19 CFR 142.6 tarafından gerekli görülen bir fatura (veya eksik belgeler için bir teminat)","hi":"19 CFR 142.6 द्वारा आवश्यक एक चालान (या अनुपस्थित दस्तावेज़ों के लिए एक बॉन्ड)","ar":"فاتورة كما تتطلبها 19 CFR 142.6 (أو تعهد عن المستندات الناقصة)"},{"en":"Evidence of the right to make entry","es":"Prueba del derecho a hacer la entrada","ru":"Доказательство права на оформление декларации","tr":"Giriş yapma hakkının kanıtı","hi":"प्रविष्टि करने के अधिकार का प्रमाण","ar":"إثبات الحق في إجراء الإدخال"},{"en":"The entry/entry summary or application for special permit, as applicable","es":"La entrada/resumen de entrada o la solicitud de permiso especial, según corresponda","ru":"Ввоз/итоговая декларация или заявление на специальное разрешение, в зависимости от случая","tr":"Duruma göre giriş/giriş özeti veya özel izin başvurusu","hi":"प्रविष्टि/एंट्री सारांश या विशेष परमिट का आवेदन, जैसा लागू हो","ar":"الإدخال/ملخص الإدخال أو طلب التصريح الخاص، حسب الاقتضاء"},{"en":"All of the above","es":"Todas las anteriores","ru":"Все вышеперечисленное","tr":"Yukarıdakilerin tümü","hi":"उपरोक्त सभी","ar":"كل ما سبق"}],"e":{"en":"Under 19 CFR 142.3(a), the entry documentation required to secure release must consist of the entry (CBP 3461 or 7501 serving as both), evidence of the right to make entry, a commercial invoice or its acceptable substitute as provided in 19 CFR 142.6, packing lists where appropriate, and other documents necessary to determine admissibility. All listed items are required.","es":"Conforme a 19 CFR 142.3(a), la documentación de entrada requerida para asegurar la liberación debe consistir en la entrada (CBP 3461 o 7501 sirviendo como ambas), la prueba del derecho a hacer la entrada, una factura comercial o su sustituto aceptable según lo previsto en 19 CFR 142.6, las listas de empaque cuando corresponda, y otros documentos necesarios para determinar la admisibilidad. Todos los elementos enumerados son requeridos.","ru":"Согласно 19 CFR 142.3(a), документация ввоза, необходимая для обеспечения выпуска, должна состоять из ввоза (CBP 3461 или 7501, служащий обоими), доказательства права на оформление декларации, коммерческого счёта-фактуры или его допустимого заменителя согласно 19 CFR 142.6, упаковочных листов при необходимости и других документов, необходимых для определения допустимости. Все перечисленные элементы обязательны.","tr":"19 CFR 142.3(a) uyarınca, teslimi sağlamak için gereken giriş belgeleri şunlardan oluşmalıdır: giriş (her ikisi olarak hizmet eden CBP 3461 veya 7501), giriş yapma hakkının kanıtı, 19 CFR 142.6'da öngörülen şekilde bir ticari fatura veya kabul edilebilir ikamesi, uygun olduğunda çeki listeleri ve kabul edilebilirliği belirlemek için gerekli diğer belgeler. Sıralanan tüm unsurlar gereklidir.","hi":"19 CFR 142.3(a) के अंतर्गत, रिलीज़ सुनिश्चित करने के लिए आवश्यक प्रविष्टि दस्तावेज़ में प्रविष्टि (CBP 3461 या 7501 जो दोनों के रूप में कार्य करे), प्रविष्टि करने के अधिकार का प्रमाण, 19 CFR 142.6 में प्रावधानित एक वाणिज्यिक चालान या उसका स्वीकार्य विकल्प, उपयुक्त होने पर पैकिंग सूचियाँ, और स्वीकार्यता निर्धारित करने के लिए आवश्यक अन्य दस्तावेज़ शामिल होने चाहिए। सभी सूचीबद्ध मदें आवश्यक हैं।","ar":"بموجب 19 CFR 142.3(a)، يجب أن تتكون مستندات الإدخال المطلوبة لتأمين الإفراج من الإدخال (CBP 3461 أو 7501 الذي يقوم بالدورين)، وإثبات الحق في إجراء الإدخال، وفاتورة تجارية أو بديلها المقبول كما هو منصوص عليه في 19 CFR 142.6، وقوائم التعبئة عند الاقتضاء، وغيرها من المستندات اللازمة لتحديد قبول البضائع. وجميع البنود المذكورة مطلوبة."}},{"cat":"entry","a":3,"q":{"en":"A customs broker holds a valid continuous power of attorney from a U.S. corporate importer and files a consumption entry, listing the corporation as importer of record. CBP later cannot collect duties from the corporation. Which statement most accurately states duty liability?","es":"Un agente de aduanas tiene un poder continuo válido de un importador corporativo estadounidense y presenta una entrada de consumo, indicando a la sociedad como importador registrado. CBP posteriormente no puede cobrar los derechos a la sociedad. ¿Cuál de las siguientes afirmaciones establece con mayor exactitud la responsabilidad por derechos?","ru":"Таможенный брокер располагает действующей непрерывной доверенностью от корпоративного импортёра из США и подаёт потребительскую декларацию, указывая корпорацию в качестве импортёра-регистранта. Позднее CBP не может взыскать пошлины с корпорации. Какое утверждение наиболее точно отражает обязательство по уплате пошлины?","tr":"Bir gümrük müşaviri, bir ABD şirket ithalatçısından geçerli bir sürekli vekaletnameye sahiptir ve şirketi kayıtlı ithalatçı olarak göstererek bir tüketim girişi sunar. CBP daha sonra şirketten gümrük vergilerini tahsil edemez. Gümrük vergisi sorumluluğunu en doğru şekilde hangi ifade belirtir?","hi":"एक सीमा शुल्क दलाल के पास एक अमेरिकी निगम आयातक से एक वैध निरंतर मुख्तारनामा है और वह निगम को रिकॉर्ड के आयातक के रूप में सूचीबद्ध करते हुए एक उपभोग प्रविष्टि दाखिल करता है। CBP बाद में निगम से शुल्क वसूल नहीं कर पाता। कौन सा कथन शुल्क दायित्व को सबसे सटीक रूप से बताता है?","ar":"يمتلك وسيط جمركي توكيلًا مستمرًا ساريًا من شركة مستوردة أمريكية ويقدّم إدخال استهلاك، مدرجًا الشركة بصفتها المستورد المسجّل. ولاحقًا لا تستطيع CBP تحصيل الرسوم من الشركة. أي عبارة تبيّن المسؤولية عن الرسوم بأكثر دقة؟"},"o":[{"en":"Neither party is liable once the entry is deemed liquidated as entered","es":"Ninguna de las partes es responsable una vez que la entrada se considera liquidada según se ingresó","ru":"Ни одна из сторон не несёт ответственности после того, как декларация считается ликвидированной в заявленном виде","tr":"Giriş, beyan edildiği şekliyle tasfiye edilmiş sayıldığında hiçbir taraf sorumlu olmaz","hi":"एक बार प्रविष्टि को प्रविष्ट किए अनुसार परिनिर्धारित मान लिए जाने पर कोई भी पक्ष उत्तरदायी नहीं रहता","ar":"لا يكون أي طرف مسؤولًا بمجرد أن يُعتبر الإدخال مُصفّى كما أُدخل"},{"en":"Liability shifts entirely to the surety once the bond is filed, discharging both parties","es":"La responsabilidad se transfiere por completo al fiador una vez que se presenta la fianza, liberando a ambas partes","ru":"Ответственность полностью переходит к поручителю после подачи поручительства, освобождая обе стороны","tr":"Teminat sunulduğunda sorumluluk tamamen kefile geçer ve her iki taraf da ibra edilir","hi":"बॉन्ड दाखिल होते ही दायित्व पूरी तरह जमानतदार को स्थानांतरित हो जाता है, जिससे दोनों पक्ष मुक्त हो जाते हैं","ar":"تنتقل المسؤولية بالكامل إلى الكفيل بمجرد تقديم التعهد، مما يبرئ الطرفين معًا"},{"en":"The broker is automatically liable for the duties because the broker filed the entry","es":"El agente es automáticamente responsable de los derechos porque el agente presentó la entrada","ru":"Брокер автоматически несёт ответственность за пошлины, поскольку брокер подал декларацию","tr":"Müşavir, girişi sunduğu için gümrük vergilerinden otomatik olarak sorumludur","hi":"दलाल स्वतः शुल्कों के लिए उत्तरदायी है क्योंकि दलाल ने प्रविष्टि दाखिल की","ar":"يكون الوسيط مسؤولًا تلقائيًا عن الرسوم لأنه هو من قدّم الإدخال"},{"en":"The importer of record remains personally liable for the duties as a personal debt to the United States","es":"El importador registrado sigue siendo personalmente responsable de los derechos como una deuda personal frente a los Estados Unidos","ru":"Импортёр-регистрант остаётся лично ответственным за пошлины как за личный долг перед Соединёнными Штатами","tr":"Kayıtlı ithalatçı, gümrük vergilerinden Amerika Birleşik Devletleri'ne karşı kişisel bir borç olarak şahsen sorumlu kalır","hi":"रिकॉर्ड का आयातक संयुक्त राज्य अमेरिका के प्रति एक व्यक्तिगत ऋण के रूप में शुल्कों के लिए व्यक्तिगत रूप से उत्तरदायी बना रहता है","ar":"يبقى المستورد المسجّل مسؤولًا شخصيًا عن الرسوم بصفتها دينًا شخصيًا للولايات المتحدة"}],"e":{"en":"Under 19 CFR 141.1(b), duty liability is a personal debt of the importer of record dischargeable only by payment in full. A broker who merely files entry as agent for a disclosed principal does not thereby become the importer of record or assume duty liability; the corporation remains liable. The surety's bond provides security but does not extinguish the importer's underlying debt (19 USC 1484, 19 CFR 141.1).","es":"Conforme a 19 CFR 141.1(b), la responsabilidad por derechos es una deuda personal del importador registrado que solo puede saldarse mediante el pago total. Un agente que simplemente presenta la entrada como apoderado de un poderdante revelado no se convierte por ello en el importador registrado ni asume la responsabilidad por derechos; la sociedad sigue siendo responsable. La fianza del fiador proporciona una garantía, pero no extingue la deuda subyacente del importador (19 USC 1484, 19 CFR 141.1).","ru":"Согласно 19 CFR 141.1(b), обязательство по уплате пошлины является личным долгом импортёра-регистранта, погашаемым только полной оплатой. Брокер, который лишь подаёт декларацию как агент раскрытого доверителя, тем самым не становится импортёром-регистрантом и не принимает на себя обязательство по уплате пошлины; корпорация остаётся ответственной. Поручительство обеспечивает гарантию, но не погашает основной долг импортёра (19 USC 1484, 19 CFR 141.1).","tr":"19 CFR 141.1(b) uyarınca, gümrük vergisi sorumluluğu, kayıtlı ithalatçının yalnızca tam ödeme ile ifa edilebilen kişisel bir borcudur. Açıklanan bir asil adına yalnızca vekil sıfatıyla giriş sunan bir müşavir, bu nedenle kayıtlı ithalatçı haline gelmez veya gümrük vergisi sorumluluğunu üstlenmez; şirket sorumlu kalmaya devam eder. Kefilin teminatı güvence sağlar ancak ithalatçının asıl borcunu ortadan kaldırmaz (19 USC 1484, 19 CFR 141.1).","hi":"19 CFR 141.1(b) के अंतर्गत, शुल्क दायित्व रिकॉर्ड के आयातक का एक व्यक्तिगत ऋण है जो केवल पूर्ण भुगतान द्वारा ही चुकाया जा सकता है। एक दलाल जो केवल एक प्रकट मूलधारक के अभिकर्ता के रूप में प्रविष्टि दाखिल करता है, वह इसके कारण रिकॉर्ड का आयातक नहीं बन जाता और न ही शुल्क दायित्व ग्रहण करता है; निगम उत्तरदायी बना रहता है। जमानतदार का बॉन्ड प्रतिभूति प्रदान करता है लेकिन आयातक के अंतर्निहित ऋण को समाप्त नहीं करता (19 USC 1484, 19 CFR 141.1)।","ar":"بموجب 19 CFR 141.1(b)، فإن المسؤولية عن الرسوم دين شخصي على المستورد المسجّل لا يُسدَّد إلا بالدفع الكامل. والوسيط الذي يكتفي بتقديم الإدخال بصفته وكيلًا عن موكِّل معلوم لا يصبح بذلك المستورد المسجّل ولا يتحمل المسؤولية عن الرسوم؛ بل تبقى الشركة مسؤولة. ويوفّر تعهد الكفيل ضمانًا لكنه لا يُسقط الدين الأساسي على المستورد (19 USC 1484، 19 CFR 141.1)."}},{"cat":"classification","a":2,"q":{"en":"A retail box contains a single barbecue cooking implement set: a stainless-steel spatula, a pair of tongs, and a basting brush, all packed together for sale directly to consumers without repacking. The three articles fall in different headings, and no single article gives the whole its essential character. How is the set classified?","es":"Una caja minorista contiene un único juego de utensilios de cocina para barbacoa: una espátula de acero inoxidable, unas pinzas y una brocha para untar, todos empaquetados juntos para su venta directa a los consumidores sin reembalaje. Los tres artículos se clasifican en partidas diferentes, y ningún artículo por sí solo confiere al conjunto su carácter esencial. ¿Cómo se clasifica el juego?","ru":"Розничная коробка содержит единый набор кухонных принадлежностей для барбекю: лопатку из нержавеющей стали, щипцы и кисть для смазывания, упакованные вместе для продажи непосредственно потребителям без переупаковки. Три изделия относятся к разным товарным позициям, и ни одно отдельное изделие не придает всему набору его основное свойство. Как классифицируется этот набор?","tr":"Bir perakende kutu, tek bir barbekü pişirme aleti setini içerir: paslanmaz çelikten bir spatula, bir maşa ve bir yağlama fırçası; hepsi tüketicilere doğrudan satış için yeniden paketlenmeden bir arada paketlenmiştir. Üç ürün farklı pozisyonlara girer ve tek bir ürün bütüne esas karakterini vermez. Set nasıl sınıflandırılır?","hi":"एक खुदरा बॉक्स में एक एकल बारबेक्यू पाक उपकरण सेट है: एक स्टेनलेस-स्टील स्पैटुला, एक चिमटा जोड़ी, और एक बेस्टिंग ब्रश, सभी को बिना दोबारा पैक किए सीधे उपभोक्ताओं को बिक्री के लिए एक साथ पैक किया गया है। तीनों वस्तुएं अलग-अलग शीर्षकों में आती हैं, और कोई एक वस्तु पूरे को उसका आवश्यक चरित्र नहीं देती। सेट को कैसे वर्गीकृत किया जाता है?","ar":"تحتوي علبة بيع بالتجزئة على طقم واحد من أدوات الطهي للشواء: ملعقة تقليب من الفولاذ المقاوم للصدأ، وزوج من الملاقط، وفرشاة دهن، جميعها معبأة معاً للبيع مباشرة للمستهلكين دون إعادة تعبئة. تندرج المواد الثلاث في بنود مختلفة، ولا تمنح أي مادة بمفردها الطقم بأكمله طابعه الأساسي. كيف يُصنّف الطقم؟"},"o":[{"en":"Each article is separately classified in its own heading because GRI 3(b) cannot resolve a three-item set.","es":"Cada artículo se clasifica por separado en su propia partida porque la GRI 3(b) no puede resolver un juego de tres elementos.","ru":"Каждое изделие классифицируется отдельно в своей товарной позиции, поскольку GRI 3(b) не может разрешить набор из трех предметов.","tr":"GRI 3(b) üç parçalı bir seti çözemediği için her ürün kendi pozisyonunda ayrı ayrı sınıflandırılır.","hi":"प्रत्येक वस्तु को उसके अपने शीर्षक में अलग से वर्गीकृत किया जाता है क्योंकि GRI 3(b) तीन-वस्तु सेट को हल नहीं कर सकती।","ar":"تُصنّف كل مادة على حدة في بندها الخاص لأن GRI 3(b) لا يمكنها حل طقم مكوّن من ثلاث مواد."},{"en":"Under GRI 5(b), the entire set follows the classification of its packing container.","es":"Conforme a la GRI 5(b), todo el juego sigue la clasificación de su envase de embalaje.","ru":"Согласно GRI 5(b), весь набор следует классификации своей упаковочной тары.","tr":"GRI 5(b) uyarınca, tüm set ambalaj kabının sınıflandırmasını izler.","hi":"GRI 5(b) के तहत, पूरा सेट अपने पैकिंग कंटेनर के वर्गीकरण का अनुसरण करता है।","ar":"بموجب GRI 5(b)، يتبع الطقم بأكمله تصنيف وعاء التعبئة الخاص به."},{"en":"Under GRI 3(c), the set is classified in the heading that occurs last in numerical order among those that equally merit consideration.","es":"Conforme a la GRI 3(c), el juego se clasifica en la partida que figure en último lugar por orden numérico entre las que igualmente merezcan consideración.","ru":"Согласно GRI 3(c), набор классифицируется в товарной позиции, которая является последней в порядке возрастания среди тех, что в равной степени заслуживают рассмотрения.","tr":"GRI 3(c) uyarınca, set eşit derecede dikkate alınmayı hak edenler arasında sayısal sırada en son gelen pozisyonda sınıflandırılır.","hi":"GRI 3(c) के तहत, सेट को उस शीर्षक में वर्गीकृत किया जाता है जो समान रूप से विचार के योग्य शीर्षकों में संख्यात्मक क्रम में अंतिम में आता है।","ar":"بموجب GRI 3(c)، يُصنّف الطقم في البند الأخير في الترتيب العددي من بين البنود التي تستحق النظر فيها على قدم المساواة."},{"en":"Under GRI 3(a), the set is classified in the heading providing the most specific description of the spatula.","es":"Conforme a la GRI 3(a), el juego se clasifica en la partida que ofrece la descripción más específica de la espátula.","ru":"Согласно GRI 3(a), набор классифицируется в товарной позиции, дающей наиболее конкретное описание лопатки.","tr":"GRI 3(a) uyarınca, set spatulanın en spesifik tanımını sağlayan pozisyonda sınıflandırılır.","hi":"GRI 3(a) के तहत, सेट को उस शीर्षक में वर्गीकृत किया जाता है जो स्पैटुला का सबसे विशिष्ट विवरण प्रदान करता है।","ar":"بموجب GRI 3(a)، يُصنّف الطقم في البند الذي يقدّم الوصف الأكثر تحديداً لملعقة التقليب."}],"e":{"en":"The goods form a 'set put up for retail sale' (GRI 3(b) criteria met). When no component imparts essential character, GRI 3(b) fails and you proceed to GRI 3(c), classifying under the heading that occurs last in numerical order among those equally meriting consideration.","es":"Las mercancías constituyen un \"juego acondicionado para la venta al por menor\" (se cumplen los criterios de la GRI 3(b)). Cuando ningún componente confiere el carácter esencial, la GRI 3(b) no resuelve y se procede a la GRI 3(c), clasificando en la partida que figure en último lugar por orden numérico entre las que igualmente merezcan consideración.","ru":"Товары образуют «набор, расфасованный для розничной продажи» (критерии GRI 3(b) выполнены). Когда ни один компонент не придает основное свойство, GRI 3(b) не срабатывает, и вы переходите к GRI 3(c), классифицируя в товарной позиции, последней в порядке возрастания среди тех, что в равной степени заслуживают рассмотрения.","tr":"Eşyalar bir 'perakende satış için hazırlanmış set' oluşturur (GRI 3(b) kriterleri karşılanır). Hiçbir bileşen esas karakteri vermediğinde, GRI 3(b) sonuç vermez ve GRI 3(c)'ye geçilir; eşit derecede dikkate alınmayı hak edenler arasında sayısal sırada en son gelen pozisyonda sınıflandırılır.","hi":"माल एक 'खुदरा बिक्री के लिए तैयार किया गया सेट' बनाता है (GRI 3(b) मानदंड पूरे होते हैं)। जब कोई घटक आवश्यक चरित्र प्रदान नहीं करता, तो GRI 3(b) विफल हो जाती है और आप GRI 3(c) पर आगे बढ़ते हैं, समान रूप से विचार के योग्य शीर्षकों में संख्यात्मक क्रम में अंतिम में आने वाले शीर्षक के तहत वर्गीकरण करते हैं।","ar":"تشكّل البضائع 'طقماً معدّاً للبيع بالتجزئة' (استُوفيت معايير GRI 3(b)). وعندما لا يمنح أي مكوّن الطابع الأساسي، يتعذّر تطبيق GRI 3(b) فتنتقل إلى GRI 3(c)، مصنّفاً في البند الأخير في الترتيب العددي من بين البنود التي تستحق النظر فيها على قدم المساواة."}},{"cat":"classification","a":0,"q":{"en":"A retail-packaged kit consists of dry spaghetti pasta, a sachet of grated cheese, and a small can of tomato sauce, put up together to make a spaghetti dish and sold as one unit to consumers. Which GRI provision and basis governs the classification of this kit?","es":"Un kit empaquetado para la venta al por menor consiste en pasta de espagueti seca, un sobre de queso rallado y una pequeña lata de salsa de tomate, acondicionados juntos para preparar un plato de espagueti y vendidos como una sola unidad a los consumidores. ¿Qué disposición de la GRI y qué fundamento rige la clasificación de este kit?","ru":"Расфасованный для розничной продажи набор состоит из сухих спагетти, пакетика тертого сыра и небольшой банки томатного соуса, упакованных вместе для приготовления блюда из спагетти и продаваемых потребителям как единое целое. Какое положение GRI и на каком основании регулирует классификацию этого набора?","tr":"Perakende ambalajlı bir kit, kuru spagetti makarnası, bir poşet rendelenmiş peynir ve küçük bir kutu domates sosundan oluşur; bir spagetti yemeği yapmak için bir arada hazırlanmış ve tüketicilere tek bir birim olarak satılmaktadır. Bu kitin sınıflandırmasını hangi GRI hükmü ve dayanağı yönetir?","hi":"एक खुदरा-पैक किट में सूखी स्पैगेटी पास्ता, कद्दूकस किए पनीर का एक पाउच, और टमाटर सॉस का एक छोटा डिब्बा होता है, जो स्पैगेटी व्यंजन बनाने के लिए एक साथ तैयार किया गया है और उपभोक्ताओं को एक इकाई के रूप में बेचा जाता है। इस किट के वर्गीकरण को कौन सा GRI प्रावधान और आधार नियंत्रित करता है?","ar":"تتكوّن مجموعة معبأة للبيع بالتجزئة من معكرونة سباغيتي جافة، وكيس من الجبن المبشور، وعلبة صغيرة من صلصة الطماطم، معدّة معاً لتحضير طبق سباغيتي وتُباع كوحدة واحدة للمستهلكين. أي حكم من أحكام GRI وأي أساس يحكم تصنيف هذه المجموعة؟"},"o":[{"en":"GRI 3(b), classified by the component that gives the set its essential character — generally the pasta.","es":"La GRI 3(b), clasificado por el componente que confiere al juego su carácter esencial, generalmente la pasta.","ru":"GRI 3(b), классифицируется по компоненту, придающему набору основное свойство, — как правило, по макаронным изделиям.","tr":"GRI 3(b), sete esas karakterini veren bileşene göre sınıflandırılır — genellikle makarna.","hi":"GRI 3(b), उस घटक के अनुसार वर्गीकृत जो सेट को उसका आवश्यक चरित्र देता है — आम तौर पर पास्ता।","ar":"GRI 3(b)، يُصنّف حسب المكوّن الذي يمنح الطقم طابعه الأساسي — وهو عادةً المعكرونة."},{"en":"GRI 3(c), because the three foods equally merit consideration and none predominates.","es":"La GRI 3(c), porque los tres alimentos merecen igual consideración y ninguno predomina.","ru":"GRI 3(c), поскольку три продукта в равной степени заслуживают рассмотрения и ни один не преобладает.","tr":"GRI 3(c), çünkü üç gıda da eşit derecede dikkate alınmayı hak eder ve hiçbiri baskın değildir.","hi":"GRI 3(c), क्योंकि तीनों खाद्य पदार्थ समान रूप से विचार के योग्य हैं और कोई प्रबल नहीं है।","ar":"GRI 3(c)، لأن الأطعمة الثلاثة تستحق النظر فيها على قدم المساواة ولا يغلب أيٌّ منها."},{"en":"GRI 1, because food preparations are always classified by their constituent of greatest weight.","es":"La GRI 1, porque las preparaciones alimenticias siempre se clasifican por su constituyente de mayor peso.","ru":"GRI 1, поскольку пищевые продукты всегда классифицируются по компоненту наибольшего веса.","tr":"GRI 1, çünkü gıda müstahzarları her zaman en fazla ağırlığa sahip bileşenlerine göre sınıflandırılır.","hi":"GRI 1, क्योंकि खाद्य तैयारियों को हमेशा उनके सबसे अधिक वजन वाले घटक के अनुसार वर्गीकृत किया जाता है।","ar":"GRI 1، لأن المحضّرات الغذائية تُصنّف دائماً حسب مكوّنها الأكبر وزناً."},{"en":"GRI 2(b), because it is a mixture of different food materials.","es":"La GRI 2(b), porque es una mezcla de distintos materiales alimenticios.","ru":"GRI 2(b), поскольку это смесь различных пищевых материалов.","tr":"GRI 2(b), çünkü farklı gıda malzemelerinin bir karışımıdır.","hi":"GRI 2(b), क्योंकि यह विभिन्न खाद्य सामग्रियों का मिश्रण है।","ar":"GRI 2(b)، لأنه خليط من مواد غذائية مختلفة."}],"e":{"en":"This meets the three-part GRI 3(b) test for goods put up together to meet a particular need (a meal). It is classified by the component imparting essential character; for a spaghetti-dish kit the pasta is generally treated as the essential-character good. GRI 3(b) is reached because GRI 3(a) yields headings each describing only part.","es":"Esto cumple el criterio tripartito de la GRI 3(b) para mercancías acondicionadas juntas para satisfacer una necesidad concreta (una comida). Se clasifica por el componente que confiere el carácter esencial; para un kit de plato de espagueti, la pasta se trata generalmente como la mercancía que determina el carácter esencial. Se llega a la GRI 3(b) porque la GRI 3(a) da lugar a partidas que describen cada una solo una parte.","ru":"Это удовлетворяет трехчастному критерию GRI 3(b) для товаров, скомпонованных вместе для удовлетворения конкретной потребности (приема пищи). Он классифицируется по компоненту, придающему основное свойство; для набора блюда из спагетти макаронные изделия обычно рассматриваются как товар, определяющий основное свойство. К GRI 3(b) переходят потому, что GRI 3(a) дает товарные позиции, каждая из которых описывает лишь часть.","tr":"Bu, belirli bir ihtiyacı (bir öğün) karşılamak üzere bir arada hazırlanan eşya için GRI 3(b)'nin üç bölümlü testini karşılar. Esas karakteri veren bileşene göre sınıflandırılır; bir spagetti yemeği kiti için makarna genellikle esas karakteri belirleyen eşya olarak kabul edilir. GRI 3(a) her biri yalnızca bir kısmı tanımlayan pozisyonlar verdiği için GRI 3(b)'ye ulaşılır.","hi":"यह किसी विशेष आवश्यकता (एक भोजन) को पूरा करने के लिए एक साथ तैयार किए गए माल के लिए GRI 3(b) के तीन-भागीय परीक्षण को पूरा करता है। इसे आवश्यक चरित्र प्रदान करने वाले घटक के अनुसार वर्गीकृत किया जाता है; स्पैगेटी-व्यंजन किट के लिए पास्ता को आम तौर पर आवश्यक-चरित्र वाला माल माना जाता है। GRI 3(b) तक इसलिए पहुंचा जाता है क्योंकि GRI 3(a) ऐसे शीर्षक देती है जिनमें से प्रत्येक केवल एक भाग का वर्णन करता है।","ar":"يستوفي هذا اختبار GRI 3(b) ثلاثي الأجزاء للبضائع المعدّة معاً لتلبية حاجة معيّنة (وجبة). ويُصنّف حسب المكوّن الذي يمنح الطابع الأساسي؛ وبالنسبة لمجموعة طبق السباغيتي تُعامَل المعكرونة عموماً باعتبارها البضاعة المحدِّدة للطابع الأساسي. ويُلجأ إلى GRI 3(b) لأن GRI 3(a) تُفضي إلى بنود يصف كل منها جزءاً فقط."}},{"cat":"classification","a":3,"q":{"en":"Two headings remain after GRI 3(a) and 3(b) are exhausted, and they equally merit consideration: heading 4202 and heading 6307. Applying GRI 3(c), which heading is selected?","es":"Quedan dos partidas tras agotarse la GRI 3(a) y la 3(b), y ambas merecen igual consideración: la partida 4202 y la partida 6307. Aplicando la GRI 3(c), ¿qué partida se selecciona?","ru":"После исчерпания GRI 3(a) и 3(b) остаются две товарные позиции, в равной степени заслуживающие рассмотрения: товарная позиция 4202 и товарная позиция 6307. Применяя GRI 3(c), какая товарная позиция выбирается?","tr":"GRI 3(a) ve 3(b) tükendikten sonra iki pozisyon kalır ve bunlar eşit derecede dikkate alınmayı hak eder: pozisyon 4202 ve pozisyon 6307. GRI 3(c) uygulandığında hangi pozisyon seçilir?","hi":"GRI 3(a) और 3(b) समाप्त होने के बाद दो शीर्षक रहते हैं, और वे समान रूप से विचार के योग्य हैं: शीर्षक 4202 और शीर्षक 6307। GRI 3(c) लागू करने पर, कौन सा शीर्षक चुना जाता है?","ar":"يتبقى بندان بعد استنفاد GRI 3(a) و3(b)، وكلاهما يستحق النظر فيه على قدم المساواة: البند 4202 والبند 6307. بتطبيق GRI 3(c)، أي بند يُختار؟"},"o":[{"en":"Heading 4202, because it appears first and first-listed provisions prevail.","es":"La partida 4202, porque aparece primero y prevalecen las disposiciones enumeradas en primer lugar.","ru":"Товарная позиция 4202, поскольку она стоит первой, а положения, перечисленные первыми, имеют преимущество.","tr":"Pozisyon 4202, çünkü ilk sırada yer alır ve ilk listelenen hükümler üstün gelir.","hi":"शीर्षक 4202, क्योंकि यह पहले आता है और पहले सूचीबद्ध प्रावधान प्रबल होते हैं।","ar":"البند 4202، لأنه يظهر أولاً والأحكام المدرجة أولاً هي التي تغلب."},{"en":"Heading 4202, because it is the more specific of the two descriptions.","es":"La partida 4202, porque es la más específica de las dos descripciones.","ru":"Товарная позиция 4202, поскольку она является более конкретным из двух описаний.","tr":"Pozisyon 4202, çünkü iki tanımdan daha spesifik olanıdır.","hi":"शीर्षक 4202, क्योंकि यह दोनों विवरणों में से अधिक विशिष्ट है।","ar":"البند 4202، لأنه الأكثر تحديداً من بين الوصفين."},{"en":"Whichever heading carries the higher duty rate, to protect the revenue.","es":"La partida que tenga el tipo arancelario más alto, para proteger los ingresos.","ru":"Та товарная позиция, которая имеет более высокую ставку пошлины, для защиты доходов.","tr":"Geliri korumak için daha yüksek gümrük vergisi oranını taşıyan pozisyon hangisiyse o.","hi":"जिस शीर्षक में उच्चतर शुल्क दर हो, राजस्व की रक्षा के लिए।","ar":"البند الذي يحمل معدل الرسوم الأعلى، حمايةً للإيرادات."},{"en":"Heading 6307, because it occurs last in numerical order.","es":"La partida 6307, porque figura en último lugar por orden numérico.","ru":"Товарная позиция 6307, поскольку она является последней в порядке возрастания.","tr":"Pozisyon 6307, çünkü sayısal sırada en son gelir.","hi":"शीर्षक 6307, क्योंकि यह संख्यात्मक क्रम में अंतिम में आता है।","ar":"البند 6307، لأنه يأتي أخيراً في الترتيب العددي."}],"e":{"en":"GRI 3(c) is a pure tie-breaker: when GRI 3(a) and 3(b) do not resolve the matter, the goods are classified under the heading which occurs last in numerical order among those equally meriting consideration. 6307 > 4202, so heading 6307 controls. Duty rate and specificity play no role in 3(c).","es":"La GRI 3(c) es un puro criterio de desempate: cuando la GRI 3(a) y la 3(b) no resuelven la cuestión, las mercancías se clasifican en la partida que figure en último lugar por orden numérico entre las que igualmente merezcan consideración. 6307 > 4202, por lo que rige la partida 6307. El tipo arancelario y la especificidad no desempeñan ningún papel en la 3(c).","ru":"GRI 3(c) — это чисто разрешающее ничью правило: когда GRI 3(a) и 3(b) не решают вопрос, товары классифицируются в товарной позиции, последней в порядке возрастания среди тех, что в равной степени заслуживают рассмотрения. 6307 > 4202, поэтому действует товарная позиция 6307. Ставка пошлины и конкретность не играют роли в 3(c).","tr":"GRI 3(c) saf bir eşitlik bozucudur: GRI 3(a) ve 3(b) meseleyi çözmediğinde, eşyalar eşit derecede dikkate alınmayı hak edenler arasında sayısal sırada en son gelen pozisyonda sınıflandırılır. 6307 > 4202 olduğundan, pozisyon 6307 geçerlidir. Gümrük vergisi oranı ve spesifiklik 3(c)'de hiçbir rol oynamaz.","hi":"GRI 3(c) एक शुद्ध टाई-ब्रेकर है: जब GRI 3(a) और 3(b) मामले को हल नहीं करते, तो माल को समान रूप से विचार के योग्य शीर्षकों में संख्यात्मक क्रम में अंतिम में आने वाले शीर्षक के तहत वर्गीकृत किया जाता है। 6307 > 4202, इसलिए शीर्षक 6307 नियंत्रित करता है। शुल्क दर और विशिष्टता 3(c) में कोई भूमिका नहीं निभाते।","ar":"GRI 3(c) هو مرجّح خالص لفض التعادل: عندما لا تحسم GRI 3(a) و3(b) المسألة، تُصنّف البضائع في البند الأخير في الترتيب العددي من بين البنود التي تستحق النظر فيها على قدم المساواة. 6307 > 4202، لذا يسري البند 6307. ولا يلعب معدل الرسوم والتحديد أي دور في 3(c)."}},{"cat":"classification","a":0,"q":{"en":"An importer enters the components of a wooden chair completely unassembled (legs, seat, back, and the screws to join them) in a single shipment, requiring only screwing together with no further working. Under which rule is this entry classified as a chair, and what is the controlling concept?","es":"Un importador presenta los componentes de una silla de madera completamente sin ensamblar (patas, asiento, respaldo y los tornillos para unirlos) en un único envío, que solo requiere atornillarse sin ningún trabajo adicional. ¿Con arreglo a qué regla se clasifica esta entrada como una silla y cuál es el concepto rector?","ru":"Импортер ввозит компоненты деревянного стула в полностью несобранном виде (ножки, сиденье, спинка и винты для их соединения) одной партией, требующие лишь свинчивания без какой-либо дальнейшей обработки. По какому правилу эта поставка классифицируется как стул и какова определяющая концепция?","tr":"Bir ithalatçı, ahşap bir sandalyenin bileşenlerini tamamen monte edilmemiş halde (bacaklar, oturak, sırtlık ve bunları birleştirecek vidalar) tek bir sevkiyatta beyan eder; yalnızca vidalanması gerekir, başka bir işlem gerekmez. Bu giriş hangi kural uyarınca sandalye olarak sınıflandırılır ve belirleyici kavram nedir?","hi":"एक आयातक एक लकड़ी की कुर्सी के घटकों को पूरी तरह से बिना जोड़े (पैर, सीट, पीठ, और उन्हें जोड़ने के लिए पेंच) एक ही शिपमेंट में दर्ज करता है, जिसमें बिना किसी अतिरिक्त कार्य के केवल पेंच लगाने की आवश्यकता होती है। इस प्रविष्टि को किस नियम के तहत एक कुर्सी के रूप में वर्गीकृत किया जाता है, और नियंत्रक अवधारणा क्या है?","ar":"يقدّم مستورد مكوّنات كرسي خشبي غير مجمّعة بالكامل (الأرجل، والمقعد، والظهر، والبراغي لربطها) في شحنة واحدة، تتطلّب فقط الربط بالبراغي دون أي تشغيل إضافي. بموجب أي قاعدة يُصنّف هذا الإدخال ككرسي، وما هو المفهوم الحاكم؟"},"o":[{"en":"GRI 2(a), because an article presented unassembled or disassembled is classified as the complete article.","es":"La GRI 2(a), porque un artículo presentado sin ensamblar o desmontado se clasifica como el artículo completo.","ru":"GRI 2(a), поскольку изделие, представленное в несобранном или разобранном виде, классифицируется как комплектное изделие.","tr":"GRI 2(a), çünkü monte edilmemiş veya sökülmüş olarak sunulan bir eşya tam eşya olarak sınıflandırılır.","hi":"GRI 2(a), क्योंकि बिना जोड़े या अलग किए प्रस्तुत किए गए लेख को पूर्ण लेख के रूप में वर्गीकृत किया जाता है।","ar":"GRI 2(a)، لأن المادة المقدّمة غير مجمّعة أو مفكّكة تُصنّف باعتبارها المادة الكاملة."},{"en":"GRI 1, because chairs are eo nomine provided for regardless of assembly state.","es":"La GRI 1, porque las sillas están previstas eo nomine con independencia del estado de ensamblaje.","ru":"GRI 1, поскольку стулья предусмотрены eo nomine независимо от состояния сборки.","tr":"GRI 1, çünkü sandalyeler montaj durumuna bakılmaksızın eo nomine olarak öngörülmüştür.","hi":"GRI 1, क्योंकि कुर्सियां असेंबली स्थिति की परवाह किए बिना eo nomine प्रदान की गई हैं।","ar":"GRI 1، لأن الكراسي منصوص عليها eo nomine بغض النظر عن حالة التجميع."},{"en":"GRI 3(b), because the components together form a set put up for retail sale.","es":"La GRI 3(b), porque los componentes en conjunto forman un juego acondicionado para la venta al por menor.","ru":"GRI 3(b), поскольку компоненты вместе образуют набор, расфасованный для розничной продажи.","tr":"GRI 3(b), çünkü bileşenler birlikte perakende satış için hazırlanmış bir set oluşturur.","hi":"GRI 3(b), क्योंकि घटक मिलकर खुदरा बिक्री के लिए तैयार किया गया सेट बनाते हैं।","ar":"GRI 3(b)، لأن المكوّنات تشكّل معاً طقماً معدّاً للبيع بالتجزئة."},{"en":"GRI 2(b), because the chair is a mixture of wood and metal materials.","es":"La GRI 2(b), porque la silla es una mezcla de materiales de madera y metal.","ru":"GRI 2(b), поскольку стул представляет собой смесь деревянных и металлических материалов.","tr":"GRI 2(b), çünkü sandalye ahşap ve metal malzemelerin bir karışımıdır.","hi":"GRI 2(b), क्योंकि कुर्सी लकड़ी और धातु सामग्री का मिश्रण है।","ar":"GRI 2(b)، لأن الكرسي خليط من مواد خشبية ومعدنية."}],"e":{"en":"GRI 2(a), second part, provides that goods presented unassembled or disassembled are classified as the assembled article, provided assembly involves only fixing operations (e.g., screws, bolts) and no further working of components. The unassembled chair is therefore classified as a complete chair.","es":"La GRI 2(a), segunda parte, dispone que las mercancías presentadas sin ensamblar o desmontadas se clasifican como el artículo ensamblado, siempre que el ensamblaje implique únicamente operaciones de fijación (por ejemplo, tornillos, pernos) y ningún trabajo adicional de los componentes. Por tanto, la silla sin ensamblar se clasifica como una silla completa.","ru":"GRI 2(a), вторая часть, предусматривает, что товары, представленные в несобранном или разобранном виде, классифицируются как собранное изделие при условии, что сборка включает только операции крепления (например, винты, болты) и никакой дальнейшей обработки компонентов. Поэтому несобранный стул классифицируется как комплектный стул.","tr":"GRI 2(a)'nın ikinci kısmı, monte edilmemiş veya sökülmüş olarak sunulan eşyanın, montajın yalnızca sabitleme işlemlerini (örneğin vidalar, cıvatalar) içermesi ve bileşenlerin başka bir işleme tabi tutulmaması koşuluyla, monte edilmiş eşya olarak sınıflandırılacağını öngörür. Bu nedenle monte edilmemiş sandalye tam bir sandalye olarak sınıflandırılır.","hi":"GRI 2(a), दूसरा भाग, यह प्रावधान करता है कि बिना जोड़े या अलग किए प्रस्तुत किया गया माल असेंबल किए गए लेख के रूप में वर्गीकृत किया जाता है, बशर्ते असेंबली में केवल फिक्सिंग संचालन (जैसे, पेंच, बोल्ट) शामिल हों और घटकों का कोई अतिरिक्त कार्य न हो। इसलिए बिना जोड़ी कुर्सी को एक पूर्ण कुर्सी के रूप में वर्गीकृत किया जाता है।","ar":"ينص الجزء الثاني من GRI 2(a) على أن البضائع المقدّمة غير مجمّعة أو مفكّكة تُصنّف باعتبارها المادة المجمّعة، شريطة أن يقتصر التجميع على عمليات التثبيت (مثل البراغي والمسامير) دون أي تشغيل إضافي للمكوّنات. ولذلك يُصنّف الكرسي غير المجمّع ككرسي كامل."}},{"cat":"classification","a":2,"q":{"en":"A manufacturer imports forged steel blanks that already have the approximate outline and proportions of finished crankshafts but still require machining of the journals before use. They cannot yet function as crankshafts. How does GRI 2(a) treat these blanks?","es":"Un fabricante importa piezas en bruto de acero forjado que ya tienen el contorno y las proporciones aproximados de cigüeñales acabados, pero que aún requieren el mecanizado de los muñones antes de su uso. Todavía no pueden funcionar como cigüeñales. ¿Cómo trata la GRI 2(a) estas piezas en bruto?","ru":"Производитель импортирует кованые стальные заготовки, которые уже имеют приблизительный контур и пропорции готовых коленчатых валов, но все еще требуют механической обработки шеек перед использованием. Они пока не могут функционировать как коленчатые валы. Как GRI 2(a) трактует эти заготовки?","tr":"Bir üretici, bitmiş krank millerinin yaklaşık dış hatlarına ve oranlarına sahip olan ancak kullanımdan önce muylularının işlenmesini gerektiren dövme çelik taslakları ithal eder. Henüz krank mili olarak işlev göremezler. GRI 2(a) bu taslakları nasıl ele alır?","hi":"एक निर्माता जाली स्टील के रिक्त स्थान आयात करता है जिनमें पहले से ही तैयार क्रैंकशाफ्ट की अनुमानित रूपरेखा और अनुपात होते हैं लेकिन उपयोग से पहले अभी भी जर्नल की मशीनिंग की आवश्यकता होती है। वे अभी तक क्रैंकशाफ्ट के रूप में कार्य नहीं कर सकते। GRI 2(a) इन रिक्त स्थानों के साथ कैसा व्यवहार करती है?","ar":"يستورد مصنّع مصوغات فولاذية مطروقة لها بالفعل الشكل الخارجي والأبعاد التقريبية لأعمدة المرفق المنتهية الصنع، لكنها لا تزال تتطلب تشغيلاً آلياً لمحاور الارتكاز قبل الاستخدام. ولا يمكنها بعد أن تعمل كأعمدة مرفق. كيف تتعامل GRI 2(a) مع هذه المصوغات؟"},"o":[{"en":"They cannot be classified until machining is finished, so classification is deferred.","es":"No pueden clasificarse hasta que se termine el mecanizado, por lo que la clasificación se aplaza.","ru":"Они не могут быть классифицированы до завершения механической обработки, поэтому классификация откладывается.","tr":"İşleme tamamlanana kadar sınıflandırılamazlar, bu nedenle sınıflandırma ertelenir.","hi":"मशीनिंग समाप्त होने तक इन्हें वर्गीकृत नहीं किया जा सकता, इसलिए वर्गीकरण स्थगित किया जाता है।","ar":"لا يمكن تصنيفها حتى ينتهي التشغيل الآلي، لذا يُؤجّل التصنيف."},{"en":"They are classified under GRI 3(c) as the last heading in numerical order.","es":"Se clasifican conforme a la GRI 3(c) como la última partida por orden numérico.","ru":"Они классифицируются согласно GRI 3(c) как последняя товарная позиция в порядке возрастания.","tr":"GRI 3(c) uyarınca sayısal sırada en son pozisyon olarak sınıflandırılırlar.","hi":"इन्हें GRI 3(c) के तहत संख्यात्मक क्रम में अंतिम शीर्षक के रूप में वर्गीकृत किया जाता है।","ar":"تُصنّف بموجب GRI 3(c) باعتبارها البند الأخير في الترتيب العددي."},{"en":"They are classified as complete crankshafts, because as imported they have the essential character of the finished article.","es":"Se clasifican como cigüeñales completos, porque tal como se importan tienen el carácter esencial del artículo acabado.","ru":"Они классифицируются как комплектные коленчатые валы, поскольку в импортируемом виде они обладают основным свойством готового изделия.","tr":"Tam krank milleri olarak sınıflandırılırlar, çünkü ithal edildikleri haliyle bitmiş eşyanın esas karakterine sahiptirler.","hi":"इन्हें पूर्ण क्रैंकशाफ्ट के रूप में वर्गीकृत किया जाता है, क्योंकि आयात के समय इनमें तैयार लेख का आवश्यक चरित्र होता है।","ar":"تُصنّف كأعمدة مرفق كاملة، لأنها كما استُوردت تحمل الطابع الأساسي للمادة المنتهية الصنع."},{"en":"They are classified as raw forgings of steel because machining remains to be done.","es":"Se clasifican como forjas en bruto de acero porque queda mecanizado por realizar.","ru":"Они классифицируются как стальные поковки в необработанном виде, поскольку механическая обработка еще не выполнена.","tr":"İşlenmesi gereken kısım kaldığından, ham çelik dövme parçalar olarak sınıflandırılırlar.","hi":"इन्हें कच्ची स्टील फोर्जिंग के रूप में वर्गीकृत किया जाता है क्योंकि मशीनिंग अभी बाकी है।","ar":"تُصنّف كمطروقات فولاذية خام لأنه لا يزال هناك تشغيل آلي يتعيّن إنجازه."}],"e":{"en":"GRI 2(a), first part, extends a heading for a complete article to an incomplete or unfinished article that has the essential character of the complete article. A blank with the approximate shape/outline of the finished crankshaft has that essential character and is classified as a crankshaft, even though machining remains.","es":"La GRI 2(a), primera parte, extiende una partida para un artículo completo a un artículo incompleto o sin terminar que tenga el carácter esencial del artículo completo. Una pieza en bruto con la forma/contorno aproximados del cigüeñal acabado tiene ese carácter esencial y se clasifica como cigüeñal, aunque quede mecanizado por realizar.","ru":"GRI 2(a), первая часть, распространяет товарную позицию для комплектного изделия на некомплектное или незавершенное изделие, обладающее основным свойством комплектного изделия. Заготовка с приблизительной формой/контуром готового коленчатого вала обладает этим основным свойством и классифицируется как коленчатый вал, даже если механическая обработка еще не выполнена.","tr":"GRI 2(a)'nın ilk kısmı, tam bir eşyaya ait bir pozisyonu, tam eşyanın esas karakterine sahip olan tamamlanmamış veya eksik bir eşyaya teşmil eder. Bitmiş krank milinin yaklaşık şekline/dış hattına sahip bir taslak bu esas karaktere sahiptir ve işleme kalmış olsa bile krank mili olarak sınıflandırılır.","hi":"GRI 2(a), पहला भाग, एक पूर्ण लेख के लिए एक शीर्षक को एक अपूर्ण या अधूरे लेख तक विस्तारित करता है जिसमें पूर्ण लेख का आवश्यक चरित्र होता है। तैयार क्रैंकशाफ्ट के अनुमानित आकार/रूपरेखा वाले रिक्त स्थान में वह आवश्यक चरित्र होता है और इसे क्रैंकशाफ्ट के रूप में वर्गीकृत किया जाता है, भले ही मशीनिंग बाकी हो।","ar":"يوسّع الجزء الأول من GRI 2(a) نطاق البند الخاص بمادة كاملة ليشمل مادة غير كاملة أو غير منتهية الصنع تحمل الطابع الأساسي للمادة الكاملة. والمصوغ الذي له الشكل/الخط الخارجي التقريبي لعمود المرفق المنتهي الصنع يحمل ذلك الطابع الأساسي ويُصنّف كعمود مرفق، حتى وإن بقي تشغيل آلي."}},{"cat":"classification","a":2,"q":{"en":"A product is a beverage consisting of natural orange juice blended with a small added quantity of mango juice, where the orange juice clearly predominates and gives the drink its character. After GRI 2(b) brings both materials into consideration, how is the final heading chosen?","es":"Un producto es una bebida que consiste en jugo de naranja natural mezclado con una pequeña cantidad añadida de jugo de mango, donde el jugo de naranja predomina claramente y confiere a la bebida su carácter. Tras la GRI 2(b) traer ambos materiales a consideración, ¿cómo se elige la partida final?","ru":"Продукт представляет собой напиток, состоящий из натурального апельсинового сока, смешанного с небольшим добавленным количеством сока манго, где апельсиновый сок явно преобладает и придает напитку его характер. После того как GRI 2(b) вводит оба материала в рассмотрение, как выбирается окончательная товарная позиция?","tr":"Bir ürün, doğal portakal suyunun az miktarda eklenmiş mango suyuyla karıştırılmasından oluşan bir içecektir; burada portakal suyu açıkça baskındır ve içeceğe karakterini verir. GRI 2(b) her iki malzemeyi de değerlendirmeye aldıktan sonra, nihai pozisyon nasıl seçilir?","hi":"एक उत्पाद एक पेय है जिसमें प्राकृतिक संतरे का रस थोड़ी मात्रा में जोड़े गए आम के रस के साथ मिश्रित होता है, जहां संतरे का रस स्पष्ट रूप से प्रबल होता है और पेय को उसका चरित्र देता है। GRI 2(b) द्वारा दोनों सामग्रियों को विचार में लाने के बाद, अंतिम शीर्षक कैसे चुना जाता है?","ar":"المنتج عبارة عن مشروب يتكوّن من عصير برتقال طبيعي ممزوج بكمية صغيرة مضافة من عصير المانجو، حيث يغلب عصير البرتقال بوضوح ويمنح المشروب طابعه. بعد أن تُدخل GRI 2(b) كلتا المادتين في الاعتبار، كيف يُختار البند النهائي؟"},"o":[{"en":"By GRI 3(c), choosing the juice heading last in numerical order.","es":"Por la GRI 3(c), eligiendo la partida de jugo que figure en último lugar por orden numérico.","ru":"По GRI 3(c), выбирая товарную позицию сока, последнюю в порядке возрастания.","tr":"GRI 3(c) ile, sayısal sırada en son gelen meyve suyu pozisyonunu seçerek.","hi":"GRI 3(c) द्वारा, संख्यात्मक क्रम में अंतिम रस शीर्षक को चुनते हुए।","ar":"بموجب GRI 3(c)، باختيار بند العصير الأخير في الترتيب العددي."},{"en":"By GRI 1 only, ignoring the mango content entirely.","es":"Por la GRI 1 únicamente, ignorando por completo el contenido de mango.","ru":"Только по GRI 1, полностью игнорируя содержание манго.","tr":"Yalnızca GRI 1 ile, mango içeriğini tamamen göz ardı ederek.","hi":"केवल GRI 1 द्वारा, आम की मात्रा को पूरी तरह से अनदेखा करते हुए।","ar":"بموجب GRI 1 فقط، مع تجاهل محتوى المانجو تماماً."},{"en":"By GRI 3, applied because GRI 2(b) results in goods classifiable under more than one heading; essential character (orange juice) governs under GRI 3(b).","es":"Por la GRI 3, aplicada porque la GRI 2(b) da lugar a mercancías clasificables en más de una partida; el carácter esencial (jugo de naranja) rige conforme a la GRI 3(b).","ru":"По GRI 3, применяемой потому, что GRI 2(b) приводит к товарам, классифицируемым более чем в одной товарной позиции; основное свойство (апельсиновый сок) определяет классификацию согласно GRI 3(b).","tr":"GRI 3 ile; bu, GRI 2(b)'nin eşyayı birden fazla pozisyonda sınıflandırılabilir hale getirmesi nedeniyle uygulanır; esas karakter (portakal suyu) GRI 3(b) uyarınca belirleyicidir.","hi":"GRI 3 द्वारा, जो इसलिए लागू होती है क्योंकि GRI 2(b) के परिणामस्वरूप माल एक से अधिक शीर्षक में वर्गीकरण योग्य हो जाता है; आवश्यक चरित्र (संतरे का रस) GRI 3(b) के तहत नियंत्रित करता है।","ar":"بموجب GRI 3، التي تُطبّق لأن GRI 2(b) تجعل البضائع قابلة للتصنيف في أكثر من بند؛ ويحكم الطابع الأساسي (عصير البرتقال) بموجب GRI 3(b)."},{"en":"By GRI 2(b) alone, which directs classification by the predominant material.","es":"Por la GRI 2(b) por sí sola, que dirige la clasificación según el material predominante.","ru":"Только по GRI 2(b), которая направляет классификацию по преобладающему материалу.","tr":"Yalnızca GRI 2(b) ile, ki bu sınıflandırmayı baskın malzemeye göre yönlendirir.","hi":"केवल GRI 2(b) द्वारा, जो प्रबल सामग्री के अनुसार वर्गीकरण निर्देशित करती है।","ar":"بموجب GRI 2(b) وحدها، التي توجّه التصنيف حسب المادة الغالبة."}],"e":{"en":"GRI 2(b) says references to a material include mixtures of that material, but expressly states that classification of goods consisting of more than one material is according to GRI 3. Under GRI 3(b), essential character controls; the predominant orange juice imparts it. GRI 2(b) itself does not pick the heading.","es":"La GRI 2(b) establece que las referencias a un material incluyen las mezclas de ese material, pero dispone expresamente que la clasificación de las mercancías constituidas por más de un material se realiza conforme a la GRI 3. Conforme a la GRI 3(b), rige el carácter esencial; el jugo de naranja predominante lo confiere. La propia GRI 2(b) no elige la partida.","ru":"GRI 2(b) гласит, что ссылки на материал включают смеси этого материала, но прямо указывает, что классификация товаров, состоящих более чем из одного материала, осуществляется согласно GRI 3. Согласно GRI 3(b), определяющим является основное свойство; его придает преобладающий апельсиновый сок. Сама GRI 2(b) не выбирает товарную позицию.","tr":"GRI 2(b), bir malzemeye yapılan atıfların o malzemenin karışımlarını da kapsadığını belirtir, ancak birden fazla malzemeden oluşan eşyanın sınıflandırılmasının GRI 3'e göre yapılacağını açıkça ifade eder. GRI 3(b) uyarınca esas karakter belirleyicidir; baskın portakal suyu bunu verir. GRI 2(b)'nin kendisi pozisyonu seçmez.","hi":"GRI 2(b) कहती है कि किसी सामग्री के संदर्भ में उस सामग्री के मिश्रण शामिल हैं, लेकिन स्पष्ट रूप से बताती है कि एक से अधिक सामग्री से बने माल का वर्गीकरण GRI 3 के अनुसार होता है। GRI 3(b) के तहत, आवश्यक चरित्र नियंत्रित करता है; प्रबल संतरे का रस इसे प्रदान करता है। GRI 2(b) स्वयं शीर्षक नहीं चुनती।","ar":"تنص GRI 2(b) على أن الإشارات إلى مادة ما تشمل مخاليط تلك المادة، لكنها تنص صراحة على أن تصنيف البضائع المكوّنة من أكثر من مادة يتم وفقاً لـ GRI 3. وبموجب GRI 3(b)، يحكم الطابع الأساسي؛ ويمنحه عصير البرتقال الغالب. أما GRI 2(b) نفسها فلا تختار البند."}},{"cat":"classification","a":1,"q":{"en":"GRI 5(a) governs certain specially shaped containers. Which combination of conditions must ALL be met for a case (e.g., a fitted violin case) to be classified WITH the article it holds rather than separately?","es":"La GRI 5(a) rige ciertos estuches con forma especial. ¿Qué combinación de condiciones debe cumplirse en su TOTALIDAD para que un estuche (por ejemplo, un estuche ajustado para violín) se clasifique JUNTO con el artículo que contiene en lugar de por separado?","ru":"GRI 5(a) регулирует определенные футляры специальной формы. Какое сочетание условий должно быть выполнено ПОЛНОСТЬЮ, чтобы футляр (например, подогнанный футляр для скрипки) классифицировался ВМЕСТЕ с изделием, которое он содержит, а не отдельно?","tr":"GRI 5(a), özel şekilli belirli kapları düzenler. Bir kabın (örneğin, bir keman için özel yapılmış kutu) içindeki eşyayla AYRI değil BİRLİKTE sınıflandırılması için hangi koşulların TÜMÜ karşılanmalıdır?","hi":"GRI 5(a) कुछ विशेष रूप से आकार वाले कंटेनरों को नियंत्रित करती है। किसी डिब्बे (उदाहरण के लिए, फिट किया गया वायलिन डिब्बा) को अलग के बजाय उस वस्तु के साथ वर्गीकृत करने के लिए शर्तों का कौन सा संयोजन सभी को पूरा करना होगा जिसे वह रखता है?","ar":"تحكم GRI 5(a) أنواعاً معينة من الأوعية ذات الشكل الخاص. ما هو مزيج الشروط الذي يجب استيفاؤه بالكامل لكي تُصنّف العلبة (مثل علبة كمان مصمّمة خصيصاً) مع المادة التي تحتويها بدلاً من تصنيفها على حدة؟"},"o":[{"en":"It must be made of leather, of durable construction, and sold separately.","es":"Debe ser de cuero, de construcción duradera y venderse por separado.","ru":"Он должен быть изготовлен из кожи, иметь прочную конструкцию и продаваться отдельно.","tr":"Deriden yapılmış, dayanıklı yapıda ve ayrı satılıyor olmalıdır.","hi":"इसे चमड़े से बना, टिकाऊ निर्माण का, और अलग से बेचा जाने वाला होना चाहिए।","ar":"يجب أن تكون مصنوعة من الجلد، ومتينة الصنع، وتُباع على حدة."},{"en":"It must be specially shaped or fitted for the article, suitable for long-term use, presented with the article, of a kind normally sold with it, and not give the whole its essential character.","es":"Debe tener una forma especial o estar adaptado para el artículo, ser apto para uso prolongado, presentarse con el artículo, ser de una clase que normalmente se venda con él y no conferir al conjunto su carácter esencial.","ru":"Он должен иметь специальную форму или быть подогнан для изделия, быть пригодным для длительного использования, представляться вместе с изделием, относиться к типу, обычно продаваемому с ним, и не придавать всему набору его основное свойство.","tr":"Eşya için özel olarak şekillendirilmiş veya uyarlanmış, uzun süreli kullanıma uygun, eşyayla birlikte sunulan, normalde onunla birlikte satılan türden olmalı ve bütüne esas karakterini vermemelidir.","hi":"इसे वस्तु के लिए विशेष रूप से आकार दिया गया या फिट किया गया, दीर्घकालिक उपयोग के लिए उपयुक्त, वस्तु के साथ प्रस्तुत, उस प्रकार का जो आम तौर पर इसके साथ बेचा जाता है, और पूरे को उसका आवश्यक चरित्र न देने वाला होना चाहिए।","ar":"يجب أن تكون مصمّمة أو مهيّأة خصيصاً للمادة، وصالحة للاستخدام طويل الأمد، ومقدّمة مع المادة، ومن النوع الذي يُباع عادةً معها، وألا تمنح المجموعة بأكملها طابعها الأساسي."},{"en":"It must be specially shaped for the article and be of a higher value than the article inside.","es":"Debe tener una forma especial para el artículo y tener un valor superior al del artículo que contiene.","ru":"Он должен иметь специальную форму для изделия и иметь более высокую стоимость, чем изделие внутри.","tr":"Eşya için özel olarak şekillendirilmiş ve içindeki eşyadan daha yüksek değerde olmalıdır.","hi":"इसे वस्तु के लिए विशेष रूप से आकार दिया गया और अंदर की वस्तु से अधिक मूल्य का होना चाहिए।","ar":"يجب أن تكون مصمّمة خصيصاً للمادة وأن تكون أعلى قيمة من المادة الموجودة بداخلها."},{"en":"It must merely be presented at the same time as the article and be reusable.","es":"Basta con que se presente al mismo tiempo que el artículo y que sea reutilizable.","ru":"Достаточно, чтобы он был представлен одновременно с изделием и был пригоден для повторного использования.","tr":"Yalnızca eşyayla aynı anda sunulması ve yeniden kullanılabilir olması yeterlidir.","hi":"इसे केवल वस्तु के साथ एक ही समय पर प्रस्तुत किया जाना और पुन: प्रयोज्य होना चाहिए।","ar":"يكفي أن تُقدَّم في الوقت نفسه مع المادة وأن تكون قابلة لإعادة الاستخدام."}],"e":{"en":"GRI 5(a) requires that the container be specially shaped or fitted for the specific article, suitable for long-term use, presented with the article, of a kind normally sold with such articles, and that it not give the whole its essential character. All conditions must be satisfied; a container imparting essential character (e.g., a silver presentation case) is excluded.","es":"La GRI 5(a) exige que el estuche tenga una forma especial o esté adaptado para el artículo específico, sea apto para uso prolongado, se presente con el artículo, sea de una clase que normalmente se venda con tales artículos y que no confiera al conjunto su carácter esencial. Deben cumplirse todas las condiciones; un estuche que confiera el carácter esencial (por ejemplo, un estuche de presentación de plata) queda excluido.","ru":"GRI 5(a) требует, чтобы футляр имел специальную форму или был подогнан для конкретного изделия, был пригоден для длительного использования, представлялся вместе с изделием, относился к типу, обычно продаваемому с такими изделиями, и не придавал всему набору его основное свойство. Все условия должны быть выполнены; футляр, придающий основное свойство (например, серебряный подарочный футляр), исключается.","tr":"GRI 5(a), kabın belirli eşya için özel olarak şekillendirilmiş veya uyarlanmış, uzun süreli kullanıma uygun, eşyayla birlikte sunulan, bu tür eşyalarla normalde birlikte satılan türden olmasını ve bütüne esas karakterini vermemesini gerektirir. Tüm koşullar karşılanmalıdır; esas karakteri veren bir kap (örneğin gümüş bir sunum kutusu) hariç tutulur.","hi":"GRI 5(a) के लिए आवश्यक है कि कंटेनर विशिष्ट वस्तु के लिए विशेष रूप से आकार दिया गया या फिट किया गया हो, दीर्घकालिक उपयोग के लिए उपयुक्त हो, वस्तु के साथ प्रस्तुत किया गया हो, उस प्रकार का हो जो आम तौर पर ऐसी वस्तुओं के साथ बेचा जाता है, और यह कि वह पूरे को उसका आवश्यक चरित्र न दे। सभी शर्तें पूरी होनी चाहिए; आवश्यक चरित्र प्रदान करने वाला कंटेनर (उदाहरण के लिए, चांदी का प्रस्तुति डिब्बा) बाहर रखा जाता है।","ar":"تشترط GRI 5(a) أن يكون الوعاء مصمّماً أو مهيّأً خصيصاً للمادة المحدّدة، وصالحاً للاستخدام طويل الأمد، ومقدّماً مع المادة، ومن النوع الذي يُباع عادةً مع مثل هذه المواد، وألا يمنح المجموعة بأكملها طابعها الأساسي. ويجب استيفاء جميع الشروط؛ ويُستثنى الوعاء الذي يمنح الطابع الأساسي (مثل علبة عرض من الفضة)."}},{"cat":"classification","a":0,"q":{"en":"Steel pressure tanks of compressed gas are imported in reusable, specially constructed steel cylinders clearly suitable for repetitive use to transport the gas. Considering GRI 5(b)'s proviso, how are these packing containers treated?","es":"Se importan tanques de presión de acero con gas comprimido en cilindros de acero reutilizables, especialmente construidos y claramente aptos para uso repetido en el transporte del gas. Considerando la salvedad de la GRI 5(b), ¿cómo se tratan estos envases de embalaje?","ru":"Стальные баллоны со сжатым газом импортируются в многоразовых, специально изготовленных стальных цилиндрах, явно пригодных для повторного использования при транспортировке газа. Учитывая оговорку GRI 5(b), как трактуются эти упаковочные контейнеры?","tr":"Sıkıştırılmış gazlı çelik basınç tankları, gazı taşımak için tekrarlanan kullanıma açıkça uygun, yeniden kullanılabilir, özel olarak yapılmış çelik silindirler içinde ithal edilir. GRI 5(b)'nin koşulu dikkate alındığında, bu ambalaj kapları nasıl ele alınır?","hi":"संपीड़ित गैस के स्टील दबाव टैंक पुन: प्रयोज्य, विशेष रूप से निर्मित स्टील सिलेंडरों में आयात किए जाते हैं जो गैस के परिवहन के लिए बार-बार उपयोग के लिए स्पष्ट रूप से उपयुक्त हैं। GRI 5(b) के परंतुक को ध्यान में रखते हुए, इन पैकिंग कंटेनरों के साथ कैसा व्यवहार किया जाता है?","ar":"تُستورد خزانات ضغط فولاذية من الغاز المضغوط في أسطوانات فولاذية قابلة لإعادة الاستخدام ومصنوعة خصيصاً وصالحة بوضوح للاستخدام المتكرر في نقل الغاز. بالنظر إلى شرط GRI 5(b)، كيف تُعامَل أوعية التعبئة هذه؟"},"o":[{"en":"They are NOT classified with the gas under GRI 5(b) because the rule does not apply to packing containers clearly suitable for repetitive use.","es":"NO se clasifican con el gas conforme a la GRI 5(b) porque la regla no se aplica a los envases de embalaje claramente aptos para uso repetido.","ru":"Они НЕ классифицируются вместе с газом согласно GRI 5(b), поскольку правило не применяется к упаковочным контейнерам, явно пригодным для повторного использования.","tr":"GRI 5(b) uyarınca gazla birlikte sınıflandırılMAZlar, çünkü kural, tekrarlanan kullanıma açıkça uygun ambalaj kaplarına uygulanmaz.","hi":"इन्हें GRI 5(b) के तहत गैस के साथ वर्गीकृत नहीं किया जाता क्योंकि यह नियम बार-बार उपयोग के लिए स्पष्ट रूप से उपयुक्त पैकिंग कंटेनरों पर लागू नहीं होता।","ar":"لا تُصنّف مع الغاز بموجب GRI 5(b) لأن القاعدة لا تنطبق على أوعية التعبئة الصالحة بوضوح للاستخدام المتكرر."},{"en":"They follow GRI 5(a) and are classified as fitted cases for the gas.","es":"Siguen la GRI 5(a) y se clasifican como estuches adaptados para el gas.","ru":"Они следуют GRI 5(a) и классифицируются как подогнанные футляры для газа.","tr":"GRI 5(a)'yı izler ve gaz için özel yapılmış kutular olarak sınıflandırılırlar.","hi":"ये GRI 5(a) का अनुसरण करते हैं और गैस के लिए फिट किए गए डिब्बों के रूप में वर्गीकृत किए जाते हैं।","ar":"تتبع GRI 5(a) وتُصنّف كعلب مهيّأة للغاز."},{"en":"They are always separately dutiable as steel articles regardless of any rule.","es":"Siempre están sujetos a derechos por separado como artículos de acero con independencia de cualquier regla.","ru":"Они всегда облагаются пошлиной отдельно как изделия из стали независимо от какого-либо правила.","tr":"Herhangi bir kurala bakılmaksızın her zaman çelik eşya olarak ayrı ayrı gümrük vergisine tabidir.","hi":"ये किसी भी नियम की परवाह किए बिना हमेशा स्टील वस्तुओं के रूप में अलग से शुल्क योग्य होते हैं।","ar":"تخضع دائماً للرسوم على حدة باعتبارها مواد فولاذية بغض النظر عن أي قاعدة."},{"en":"They are classified with the gas under GRI 5(b) in every case because they are presented together.","es":"Se clasifican con el gas conforme a la GRI 5(b) en todos los casos porque se presentan juntos.","ru":"Они классифицируются вместе с газом согласно GRI 5(b) в любом случае, поскольку представляются вместе.","tr":"Birlikte sunuldukları için her durumda GRI 5(b) uyarınca gazla birlikte sınıflandırılırlar.","hi":"इन्हें हर मामले में GRI 5(b) के तहत गैस के साथ वर्गीकृत किया जाता है क्योंकि इन्हें एक साथ प्रस्तुत किया जाता है।","ar":"تُصنّف مع الغاز بموجب GRI 5(b) في كل حالة لأنها تُقدَّم معاً."}],"e":{"en":"GRI 5(b) classifies packing materials/containers with the goods if of a kind normally used for packing, BUT it expressly does not apply when the packing is clearly suitable for repetitive use. Reusable steel gas cylinders fall under that exception, so GRI 5(b) does not sweep them in with the gas.","es":"La GRI 5(b) clasifica los materiales/envases de embalaje con las mercancías si son de una clase normalmente utilizada para el embalaje, PERO expresamente no se aplica cuando el embalaje es claramente apto para uso repetido. Los cilindros de acero para gas reutilizables entran en esa excepción, por lo que la GRI 5(b) no los engloba con el gas.","ru":"GRI 5(b) классифицирует упаковочные материалы/контейнеры вместе с товарами, если они относятся к типу, обычно используемому для упаковки, НО прямо не применяется, когда упаковка явно пригодна для повторного использования. Многоразовые стальные газовые баллоны подпадают под это исключение, поэтому GRI 5(b) не объединяет их с газом.","tr":"GRI 5(b), ambalaj malzemelerini/kaplarını, normalde ambalaj için kullanılan türdense eşyayla birlikte sınıflandırır, ANCAK ambalaj tekrarlanan kullanıma açıkça uygun olduğunda açıkça uygulanmaz. Yeniden kullanılabilir çelik gaz silindirleri bu istisnaya girer, bu nedenle GRI 5(b) onları gazla birlikte kapsamaz.","hi":"GRI 5(b) पैकिंग सामग्री/कंटेनरों को माल के साथ वर्गीकृत करती है यदि वे उस प्रकार के हैं जो आम तौर पर पैकिंग के लिए उपयोग किए जाते हैं, लेकिन यह स्पष्ट रूप से तब लागू नहीं होती जब पैकिंग बार-बार उपयोग के लिए स्पष्ट रूप से उपयुक्त हो। पुन: प्रयोज्य स्टील गैस सिलेंडर उस अपवाद के अंतर्गत आते हैं, इसलिए GRI 5(b) उन्हें गैस के साथ शामिल नहीं करती।","ar":"تُصنّف GRI 5(b) مواد/أوعية التعبئة مع البضائع إذا كانت من النوع المستخدم عادةً للتعبئة، لكنها لا تنطبق صراحةً عندما تكون التعبئة صالحة بوضوح للاستخدام المتكرر. وتندرج أسطوانات الغاز الفولاذية القابلة لإعادة الاستخدام ضمن هذا الاستثناء، لذا لا تُدخلها GRI 5(b) مع الغاز."}},{"cat":"classification","a":1,"q":{"en":"After GRI 1-5 have established that goods fall in heading 8516, the classifier must choose between two competing subheadings within 8516. Under GRI 6, which subheadings may be directly compared with each other?","es":"Tras haber establecido la GRI 1 a 5 que las mercancías se clasifican en la partida 8516, el clasificador debe elegir entre dos subpartidas en competencia dentro de 8516. Conforme a la GRI 6, ¿qué subpartidas pueden compararse directamente entre sí?","ru":"После того как GRI 1–5 установили, что товары относятся к товарной позиции 8516, классификатор должен выбрать между двумя конкурирующими субпозициями в пределах 8516. Согласно GRI 6, какие субпозиции могут напрямую сравниваться друг с другом?","tr":"GRI 1-5, eşyanın pozisyon 8516'ya girdiğini belirledikten sonra, sınıflandırıcı 8516 içindeki birbiriyle yarışan iki alt pozisyon arasında seçim yapmalıdır. GRI 6 uyarınca, hangi alt pozisyonlar birbiriyle doğrudan karşılaştırılabilir?","hi":"GRI 1-5 द्वारा यह स्थापित करने के बाद कि माल शीर्षक 8516 में आता है, वर्गीकरणकर्ता को 8516 के भीतर दो प्रतिस्पर्धी उपशीर्षकों के बीच चयन करना होगा। GRI 6 के तहत, कौन से उपशीर्षक एक-दूसरे के साथ सीधे तुलना किए जा सकते हैं?","ar":"بعد أن أثبتت GRI 1-5 أن البضائع تندرج في البند 8516، يتعيّن على المصنِّف الاختيار بين بندين فرعيين متنافسين ضمن 8516. بموجب GRI 6، أي البنود الفرعية يمكن مقارنتها مباشرةً ببعضها البعض؟"},"o":[{"en":"Only the first and last subheadings of the heading.","es":"Únicamente la primera y la última subpartida de la partida.","ru":"Только первая и последняя субпозиции товарной позиции.","tr":"Yalnızca pozisyonun ilk ve son alt pozisyonları.","hi":"केवल शीर्षक के पहले और अंतिम उपशीर्षक।","ar":"البندان الفرعيان الأول والأخير فقط من البند."},{"en":"Only subheadings at the same level (e.g., two one-dash subheadings, or two two-dash subheadings under the same superior subheading).","es":"Únicamente subpartidas del mismo nivel (por ejemplo, dos subpartidas de un guion, o dos subpartidas de dos guiones bajo la misma subpartida superior).","ru":"Только субпозиции одного уровня (например, две субпозиции с одним дефисом или две субпозиции с двумя дефисами в пределах одной вышестоящей субпозиции).","tr":"Yalnızca aynı seviyedeki alt pozisyonlar (örneğin, iki tek tireli alt pozisyon veya aynı üst alt pozisyon altındaki iki çift tireli alt pozisyon).","hi":"केवल समान स्तर के उपशीर्षक (उदाहरण के लिए, दो एक-डैश उपशीर्षक, या एक ही उच्चतर उपशीर्षक के अंतर्गत दो दो-डैश उपशीर्षक)।","ar":"البنود الفرعية في المستوى نفسه فقط (مثل بندين فرعيين بشَرطة واحدة، أو بندين فرعيين بشَرطتين تحت البند الفرعي الأعلى نفسه)."},{"en":"Any subheadings anywhere in chapter 85, regardless of level.","es":"Cualquier subpartida en cualquier parte del capítulo 85, con independencia del nivel.","ru":"Любые субпозиции в любом месте группы 85, независимо от уровня.","tr":"Seviyeye bakılmaksızın fasıl 85'in herhangi bir yerindeki herhangi bir alt pozisyon.","hi":"अध्याय 85 में कहीं भी कोई भी उपशीर्षक, स्तर की परवाह किए बिना।","ar":"أي بنود فرعية في أي موضع من الفصل 85، بغض النظر عن المستوى."},{"en":"Subheadings and headings interchangeably, since the GRIs apply uniformly.","es":"Subpartidas y partidas indistintamente, ya que las GRI se aplican de manera uniforme.","ru":"Субпозиции и товарные позиции взаимозаменяемо, поскольку GRI применяются единообразно.","tr":"GRI'ler tekdüze uygulandığından, alt pozisyonlar ve pozisyonlar birbirinin yerine.","hi":"उपशीर्षक और शीर्षक परस्पर विनिमेय रूप से, क्योंकि GRI समान रूप से लागू होती हैं।","ar":"البنود الفرعية والبنود بشكل متبادل، بما أن قواعد GRI تُطبّق بشكل موحّد."}],"e":{"en":"GRI 6 requires that subheadings be compared only at the same level: only subheadings at the same level are comparable, and a one-dash subheading must first be selected before its subordinate two-dash subheadings are considered. The relative section/chapter notes also apply unless context requires otherwise.","es":"La GRI 6 exige que las subpartidas se comparen únicamente al mismo nivel: solo son comparables las subpartidas del mismo nivel, y debe seleccionarse primero una subpartida de un guion antes de considerar sus subpartidas subordinadas de dos guiones. Las notas de sección/capítulo pertinentes también se aplican, salvo que el contexto disponga otra cosa.","ru":"GRI 6 требует, чтобы субпозиции сравнивались только на одном уровне: сравнимы только субпозиции одного уровня, и сначала должна быть выбрана субпозиция с одним дефисом, прежде чем будут рассмотрены подчиненные ей субпозиции с двумя дефисами. Соответствующие примечания к разделу/группе также применяются, если контекст не требует иного.","tr":"GRI 6, alt pozisyonların yalnızca aynı seviyede karşılaştırılmasını gerektirir: yalnızca aynı seviyedeki alt pozisyonlar karşılaştırılabilir ve bağlı çift tireli alt pozisyonları değerlendirilmeden önce bir tek tireli alt pozisyon seçilmelidir. Bağlam aksini gerektirmedikçe ilgili bölüm/fasıl notları da uygulanır.","hi":"GRI 6 के लिए आवश्यक है कि उपशीर्षकों की तुलना केवल समान स्तर पर की जाए: केवल समान स्तर के उपशीर्षक तुलनीय हैं, और इसके अधीनस्थ दो-डैश उपशीर्षकों पर विचार करने से पहले एक एक-डैश उपशीर्षक का चयन किया जाना चाहिए। जब तक संदर्भ अन्यथा अपेक्षित न हो, संबंधित खंड/अध्याय टिप्पणियां भी लागू होती हैं।","ar":"تشترط GRI 6 ألا تُقارَن البنود الفرعية إلا في المستوى نفسه: فلا تُقارَن إلا البنود الفرعية في المستوى نفسه، ويجب أولاً اختيار بند فرعي بشَرطة واحدة قبل النظر في بنوده الفرعية التابعة بشَرطتين. كما تُطبّق ملاحظات القسم/الفصل ذات الصلة ما لم يقتضِ السياق خلاف ذلك."}},{"cat":"classification","a":1,"q":{"en":"An article is solely and principally used as a part of a sewing machine, but a separate HTSUS heading provides eo nomine for that very article (e.g., it is itself a needle of heading 8452/related provision context). Under Additional U.S. Rule of Interpretation 1(c), how is it classified?","es":"Un artículo se utiliza única y principalmente como parte de una máquina de coser, pero una partida distinta del HTSUS lo prevé eo nomine para ese mismo artículo (por ejemplo, es en sí mismo una aguja de la partida 8452/contexto de disposición relacionada). Conforme a la Additional U.S. Rule of Interpretation 1(c), ¿cómo se clasifica?","ru":"Изделие используется исключительно и главным образом как часть швейной машины, но отдельная товарная позиция HTSUS предусматривает eo nomine именно это изделие (например, оно само является иглой товарной позиции 8452/в контексте соответствующего положения). Согласно Additional U.S. Rule of Interpretation 1(c), как оно классифицируется?","tr":"Bir eşya yalnızca ve esas olarak bir dikiş makinesinin parçası olarak kullanılır, ancak ayrı bir HTSUS pozisyonu tam da o eşya için eo nomine hüküm öngörür (örneğin, kendisi pozisyon 8452'nin bir iğnesidir/ilgili hüküm bağlamı). Additional U.S. Rule of Interpretation 1(c) uyarınca nasıl sınıflandırılır?","hi":"एक वस्तु का उपयोग पूरी तरह और मुख्य रूप से सिलाई मशीन के एक हिस्से के रूप में किया जाता है, लेकिन एक अलग HTSUS शीर्षक उसी वस्तु के लिए eo nomine प्रावधान करता है (उदाहरण के लिए, यह स्वयं शीर्षक 8452 की एक सुई है/संबंधित प्रावधान संदर्भ)। Additional U.S. Rule of Interpretation 1(c) के तहत, इसे कैसे वर्गीकृत किया जाता है?","ar":"تُستخدم مادة ما حصراً وبشكل رئيسي كجزء من آلة خياطة، لكن بنداً منفصلاً في HTSUS ينص eo nomine على تلك المادة بعينها (مثلاً، هي نفسها إبرة من البند 8452/سياق حكم ذي صلة). بموجب Additional U.S. Rule of Interpretation 1(c)، كيف تُصنّف؟"},"o":[{"en":"Under GRI 3(c) in the heading last in numerical order between the two.","es":"Conforme a la GRI 3(c), en la partida que figure en último lugar por orden numérico entre las dos.","ru":"Согласно GRI 3(c), в товарной позиции, последней в порядке возрастания из двух.","tr":"GRI 3(c) uyarınca, ikisi arasında sayısal sırada en son gelen pozisyonda.","hi":"GRI 3(c) के तहत, दोनों के बीच संख्यात्मक क्रम में अंतिम शीर्षक में।","ar":"بموجب GRI 3(c) في البند الأخير في الترتيب العددي بين البندين."},{"en":"In the eo nomine provision, because a provision for parts does not prevail over a specific provision naming the article (unless the language or context requires otherwise).","es":"En la disposición eo nomine, porque una disposición para partes no prevalece sobre una disposición específica que nombre el artículo (salvo que el texto o el contexto exijan otra cosa).","ru":"В положении eo nomine, поскольку положение для частей не имеет преимущества над конкретным положением, называющим изделие (если только формулировка или контекст не требуют иного).","tr":"eo nomine hükmünde, çünkü parçalara ilişkin bir hüküm, eşyayı adıyla belirten spesifik bir hükme üstün gelmez (metin veya bağlam aksini gerektirmedikçe).","hi":"eo nomine प्रावधान में, क्योंकि भागों के लिए कोई प्रावधान वस्तु को नाम से निर्दिष्ट करने वाले विशिष्ट प्रावधान पर प्रबल नहीं होता (जब तक कि भाषा या संदर्भ अन्यथा अपेक्षित न हो)।","ar":"في الحكم eo nomine، لأن الحكم الخاص بالأجزاء لا يغلب على حكم محدّد يسمّي المادة (ما لم يقتضِ النص أو السياق خلاف ذلك)."},{"en":"In whichever heading carries the lower rate of duty.","es":"En la partida que tenga el tipo arancelario más bajo.","ru":"В той товарной позиции, которая имеет более низкую ставку пошлины.","tr":"Daha düşük gümrük vergisi oranını taşıyan pozisyonda.","hi":"जिस शीर्षक में निम्नतर शुल्क दर हो।","ar":"في البند الذي يحمل معدل الرسوم الأدنى."},{"en":"As a part of the sewing machine, because principal-use parts always prevail.","es":"Como parte de la máquina de coser, porque las partes de uso principal siempre prevalecen.","ru":"Как часть швейной машины, поскольку части основного использования всегда имеют преимущество.","tr":"Dikiş makinesinin bir parçası olarak, çünkü esas kullanım parçaları her zaman üstün gelir.","hi":"सिलाई मशीन के एक हिस्से के रूप में, क्योंकि मुख्य-उपयोग वाले भाग हमेशा प्रबल होते हैं।","ar":"كجزء من آلة الخياطة، لأن أجزاء الاستخدام الرئيسي تغلب دائماً."}],"e":{"en":"Additional U.S. Rule of Interpretation 1(c): a provision for 'parts' or 'parts and accessories' shall not prevail over a specific provision for such part or accessory, unless context or the language otherwise requires. The eo nomine (specific named) provision controls over the parts provision.","es":"Additional U.S. Rule of Interpretation 1(c): una disposición para \"partes\" o \"partes y accesorios\" no prevalecerá sobre una disposición específica para tal parte o accesorio, salvo que el contexto o el texto exijan otra cosa. La disposición eo nomine (que nombra específicamente) prevalece sobre la disposición de partes.","ru":"Additional U.S. Rule of Interpretation 1(c): положение для «частей» или «частей и принадлежностей» не имеет преимущества над конкретным положением для такой части или принадлежности, если только контекст или формулировка не требуют иного. Положение eo nomine (с конкретным наименованием) имеет преимущество над положением о частях.","tr":"Additional U.S. Rule of Interpretation 1(c): 'parçalar' veya 'parçalar ve aksesuarlar' için bir hüküm, böyle bir parça veya aksesuar için spesifik bir hükme üstün gelmez, meğerki bağlam veya metin aksini gerektirsin. eo nomine (özel olarak adı belirtilen) hüküm, parçalar hükmüne üstün gelir.","hi":"Additional U.S. Rule of Interpretation 1(c): 'भागों' या 'भागों और सहायक उपकरणों' के लिए कोई प्रावधान ऐसे भाग या सहायक उपकरण के लिए किसी विशिष्ट प्रावधान पर प्रबल नहीं होगा, जब तक कि संदर्भ या भाषा अन्यथा अपेक्षित न हो। eo nomine (विशिष्ट रूप से नामित) प्रावधान भागों के प्रावधान पर नियंत्रण रखता है।","ar":"Additional U.S. Rule of Interpretation 1(c): لا يغلب الحكم الخاص بـ 'الأجزاء' أو 'الأجزاء واللوازم' على حكم محدّد لذلك الجزء أو اللازمة، ما لم يقتضِ السياق أو النص خلاف ذلك. ويسري الحكم eo nomine (المحدّد بالاسم) على حكم الأجزاء."}},{"cat":"classification","a":1,"q":{"en":"A tariff provision is a 'principal use' provision (a use provision other than 'actual use'). Under Additional U.S. Rule of Interpretation 1(a), classification is controlled by the use of which group?","es":"Una disposición arancelaria es una disposición de 'uso principal' (una disposición de uso distinta del 'uso real'). Conforme a la Additional U.S. Rule of Interpretation 1(a), la clasificación se rige por el uso de cuál grupo?","ru":"Тарифная позиция является положением об 'основном использовании' (положение об использовании, отличное от 'фактического использования'). Согласно Additional U.S. Rule of Interpretation 1(a), классификация определяется использованием какой группы?","tr":"Bir tarife hükmü, 'temel kullanım' hükmüdür ('fiili kullanım' dışındaki bir kullanım hükmü). Additional U.S. Rule of Interpretation 1(a) uyarınca sınıflandırma hangi grubun kullanımına göre belirlenir?","hi":"एक टैरिफ प्रावधान 'मुख्य उपयोग' का प्रावधान है ('वास्तविक उपयोग' के अलावा एक उपयोग प्रावधान)। Additional U.S. Rule of Interpretation 1(a) के अंतर्गत, वर्गीकरण किस समूह के उपयोग से नियंत्रित होता है?","ar":"حكم التعرفة هو حكم 'الاستخدام الرئيسي' (حكم استخدام بخلاف 'الاستخدام الفعلي'). بموجب Additional U.S. Rule of Interpretation 1(a)، يُحدَّد التصنيف باستخدام أي مجموعة؟"},"o":[{"en":"The use predominant in the country of exportation.","es":"El uso predominante en el país de exportación.","ru":"Использование, преобладающее в стране экспорта.","tr":"İhracat ülkesinde baskın olan kullanım.","hi":"निर्यात के देश में प्रमुख उपयोग।","ar":"الاستخدام السائد في بلد التصدير."},{"en":"The use of goods of that class or kind to which the imported goods belong in the United States at or immediately prior to the date of importation.","es":"El uso de las mercancías de la clase o tipo al que pertenecen las mercancías importadas en los Estados Unidos en la fecha de importación o inmediatamente antes de ella.","ru":"Использование товаров того класса или вида, к которому относятся импортируемые товары, в Соединённых Штатах на дату импорта или непосредственно перед ней.","tr":"İthal edilen malların ait olduğu sınıf veya türdeki malların Birleşik Devletler'de ithalat tarihinde veya hemen öncesindeki kullanımı.","hi":"उस वर्ग या प्रकार की वस्तुओं का उपयोग जिससे आयातित वस्तुएं संबंधित हैं, संयुक्त राज्य अमेरिका में आयात की तिथि पर या उसके ठीक पहले।","ar":"استخدام البضائع من نفس الفئة أو النوع الذي تنتمي إليه البضائع المستوردة في الولايات المتحدة في تاريخ الاستيراد أو قبله مباشرة."},{"en":"The actual use to which the specific imported shipment is put after entry.","es":"El uso real que se da a la remesa importada específica después de su entrada.","ru":"Фактическое использование, которому подвергается конкретная импортируемая партия после ввоза.","tr":"İthal edilen belirli sevkiyatın girişten sonra tabi tutulduğu fiili kullanım.","hi":"विशिष्ट आयातित खेप का प्रवेश के बाद किया जाने वाला वास्तविक उपयोग।","ar":"الاستخدام الفعلي الذي توضع فيه الشحنة المستوردة المحددة بعد الإدخال."},{"en":"The use intended by the importer as stated on the entry documents.","es":"El uso previsto por el importador según se indica en los documentos de entrada.","ru":"Использование, предполагаемое импортёром, как указано во ввозных документах.","tr":"İthalatçının giriş belgelerinde belirttiği amaçlanan kullanım.","hi":"प्रवेश दस्तावेजों में बताए अनुसार आयातक द्वारा इच्छित उपयोग।","ar":"الاستخدام المقصود من جانب المستورد كما هو مذكور في مستندات الإدخال."}],"e":{"en":"Additional U.S. Rule of Interpretation 1(a): a 'principal use' provision is controlled by the principal use, in the United States at or immediately prior to importation, of goods of that class or kind to which the imported goods belong. Actual use of the particular shipment is not the test for a principal-use provision.","es":"Additional U.S. Rule of Interpretation 1(a): una disposición de 'uso principal' se rige por el uso principal, en los Estados Unidos en la importación o inmediatamente antes de ella, de las mercancías de la clase o tipo al que pertenecen las mercancías importadas. El uso real de la remesa concreta no es el criterio para una disposición de uso principal.","ru":"Additional U.S. Rule of Interpretation 1(a): положение об 'основном использовании' определяется основным использованием в Соединённых Штатах на момент импорта или непосредственно перед ним товаров того класса или вида, к которому относятся импортируемые товары. Фактическое использование конкретной партии не является критерием для положения об основном использовании.","tr":"Additional U.S. Rule of Interpretation 1(a): 'temel kullanım' hükmü, ithal edilen malların ait olduğu sınıf veya türdeki malların Birleşik Devletler'de ithalatta veya hemen öncesindeki temel kullanımına göre belirlenir. Belirli sevkiyatın fiili kullanımı, temel kullanım hükmü için ölçüt değildir.","hi":"Additional U.S. Rule of Interpretation 1(a): 'मुख्य उपयोग' का प्रावधान उस वर्ग या प्रकार की वस्तुओं के मुख्य उपयोग से नियंत्रित होता है जिससे आयातित वस्तुएं संबंधित हैं, संयुक्त राज्य अमेरिका में आयात पर या उसके ठीक पहले। विशिष्ट खेप का वास्तविक उपयोग मुख्य-उपयोग प्रावधान के लिए कसौटी नहीं है।","ar":"Additional U.S. Rule of Interpretation 1(a): يُحدَّد حكم 'الاستخدام الرئيسي' بالاستخدام الرئيسي، في الولايات المتحدة عند الاستيراد أو قبله مباشرة، للبضائع من نفس الفئة أو النوع الذي تنتمي إليه البضائع المستوردة. الاستخدام الفعلي للشحنة المعينة ليس المعيار لحكم الاستخدام الرئيسي."}},{"cat":"classification","a":2,"q":{"en":"A heading reads, in its terms, to cover 'machines for a particular function,' and a relevant chapter note defines or limits the scope of that heading. According to GRI 1, what is the relationship between the heading text and that chapter note?","es":"Una partida, según sus términos, abarca 'máquinas para una función determinada', y una nota de capítulo pertinente define o limita el alcance de esa partida. Según GRI 1, cuál es la relación entre el texto de la partida y esa nota de capítulo?","ru":"Товарная позиция по своему тексту охватывает 'машины для определённой функции', а соответствующее примечание к группе определяет или ограничивает сферу действия этой позиции. Согласно GRI 1, каково соотношение между текстом позиции и этим примечанием к группе?","tr":"Bir pozisyon, kendi ifadesiyle 'belirli bir işlev için makineleri' kapsamaktadır ve ilgili bir fasıl notu o pozisyonun kapsamını tanımlamakta veya sınırlamaktadır. GRI 1'e göre, pozisyon metni ile söz konusu fasıl notu arasındaki ilişki nedir?","hi":"एक शीर्षक, अपने शब्दों में, 'किसी विशेष कार्य के लिए मशीनों' को शामिल करता है, और एक संबंधित अध्याय टिप्पणी उस शीर्षक के दायरे को परिभाषित या सीमित करती है। GRI 1 के अनुसार, शीर्षक के पाठ और उस अध्याय टिप्पणी के बीच क्या संबंध है?","ar":"ينص بند، بمنطوقه، على تغطية 'آلات لوظيفة معينة'، وتُعرّف ملاحظة فصل ذات صلة نطاق ذلك البند أو تُقيّده. وفقًا لـ GRI 1، ما العلاقة بين نص البند وملاحظة الفصل المذكورة؟"},"o":[{"en":"The heading text always overrides any chapter note that conflicts with it.","es":"El texto de la partida siempre prevalece sobre cualquier nota de capítulo que entre en conflicto con él.","ru":"Текст товарной позиции всегда имеет преимущество над любым примечанием к группе, которое ему противоречит.","tr":"Pozisyon metni, kendisiyle çelişen herhangi bir fasıl notunun her zaman üzerinde gelir.","hi":"शीर्षक का पाठ हमेशा उससे टकराने वाली किसी भी अध्याय टिप्पणी पर वरीयता रखता है।","ar":"يُرجَّح نص البند دائمًا على أي ملاحظة فصل تتعارض معه."},{"en":"The chapter note applies only if the GRIs 2 through 6 fail to resolve the matter.","es":"La nota de capítulo solo se aplica si las GRI 2 a 6 no logran resolver la cuestión.","ru":"Примечание к группе применяется только в том случае, если GRI 2–6 не позволяют решить вопрос.","tr":"Fasıl notu yalnızca GRI 2 ila 6 konuyu çözmekte başarısız olursa uygulanır.","hi":"अध्याय टिप्पणी केवल तभी लागू होती है जब GRI 2 से 6 तक मामले को हल करने में विफल रहें।","ar":"تُطبَّق ملاحظة الفصل فقط إذا فشلت GRI 2 إلى 6 في حل المسألة."},{"en":"Classification is determined according to the terms of the headings and any relative section or chapter notes, which have equal legal force with the heading text.","es":"La clasificación se determina conforme a los términos de las partidas y de las notas de sección o de capítulo pertinentes, las cuales tienen igual fuerza jurídica que el texto de la partida.","ru":"Классификация определяется согласно текстам товарных позиций и соответствующим примечаниям к разделам или группам, которые имеют равную юридическую силу с текстом позиции.","tr":"Sınıflandırma, pozisyonların ifadelerine ve ilgili bölüm veya fasıl notlarına göre belirlenir; bunlar pozisyon metniyle eşit hukuki güce sahiptir.","hi":"वर्गीकरण शीर्षकों के शब्दों और किसी भी संबंधित खंड या अध्याय टिप्पणियों के अनुसार निर्धारित होता है, जिनका शीर्षक के पाठ के बराबर कानूनी बल होता है।","ar":"يُحدَّد التصنيف وفقًا لنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة، والتي لها القوة القانونية نفسها لنص البند."},{"en":"The chapter note is merely advisory, like a section title.","es":"La nota de capítulo es meramente orientativa, como un título de sección.","ru":"Примечание к группе носит исключительно рекомендательный характер, как заголовок раздела.","tr":"Fasıl notu, bir bölüm başlığı gibi yalnızca tavsiye niteliğindedir.","hi":"अध्याय टिप्पणी केवल सलाहकारी होती है, खंड के शीर्षक की तरह।","ar":"ملاحظة الفصل ذات طابع استرشادي فقط، مثل عنوان القسم."}],"e":{"en":"GRI 1 states classification is determined according to the terms of the headings AND any relative section or chapter notes. Notes are legally binding and read together with the heading text; they are not advisory. Titles of sections/chapters are for reference only, but notes are operative law.","es":"GRI 1 establece que la clasificación se determina conforme a los términos de las partidas Y a las notas de sección o de capítulo pertinentes. Las notas son jurídicamente vinculantes y se leen junto con el texto de la partida; no son orientativas. Los títulos de secciones/capítulos son solo de referencia, pero las notas son derecho operativo.","ru":"GRI 1 устанавливает, что классификация определяется согласно текстам товарных позиций И любым соответствующим примечаниям к разделам или группам. Примечания юридически обязательны и читаются вместе с текстом позиции; они не носят рекомендательного характера. Заголовки разделов/групп служат только для справки, но примечания являются действующим правом.","tr":"GRI 1, sınıflandırmanın pozisyonların ifadelerine VE ilgili herhangi bir bölüm veya fasıl notuna göre belirlendiğini belirtir. Notlar hukuken bağlayıcıdır ve pozisyon metniyle birlikte okunur; tavsiye niteliğinde değildir. Bölüm/fasıl başlıkları yalnızca referans içindir, ancak notlar yürürlükteki hukuktur.","hi":"GRI 1 कहता है कि वर्गीकरण शीर्षकों के शब्दों और किसी भी संबंधित खंड या अध्याय टिप्पणियों के अनुसार निर्धारित होता है। टिप्पणियां कानूनी रूप से बाध्यकारी हैं और शीर्षक के पाठ के साथ पढ़ी जाती हैं; वे सलाहकारी नहीं हैं। खंडों/अध्यायों के शीर्षक केवल संदर्भ के लिए हैं, परंतु टिप्पणियां प्रभावी कानून हैं।","ar":"تنص GRI 1 على أن التصنيف يُحدَّد وفقًا لنصوص البنود وأي ملاحظات أقسام أو فصول ذات صلة. الملاحظات مُلزِمة قانونًا وتُقرأ مع نص البند؛ وهي ليست استرشادية. عناوين الأقسام/الفصول للمرجعية فقط، لكن الملاحظات قانون نافذ."}},{"cat":"classification","a":1,"q":{"en":"Which statement most accurately describes the legal status of the WCO Explanatory Notes (ENs) in U.S. tariff classification?","es":"Cuál enunciado describe con mayor exactitud el estatus jurídico de las Notas Explicativas (ENs) de la WCO en la clasificación arancelaria de los Estados Unidos?","ru":"Какое утверждение наиболее точно описывает правовой статус Пояснительных примечаний (ENs) WCO в тарифной классификации США?","tr":"WCO Açıklayıcı Notlarının (ENs) ABD tarife sınıflandırmasındaki hukuki statüsünü en doğru şekilde hangi ifade tanımlar?","hi":"कौन सा कथन अमेरिकी टैरिफ वर्गीकरण में WCO Explanatory Notes (ENs) की कानूनी स्थिति का सबसे सटीक वर्णन करता है?","ar":"أي عبارة تصف بأكبر قدر من الدقة الوضع القانوني لـ WCO Explanatory Notes (ENs) في التصنيف الجمركي للولايات المتحدة؟"},"o":[{"en":"They override the General Rules of Interpretation when they conflict.","es":"Prevalecen sobre las Reglas Generales de Interpretación cuando entran en conflicto.","ru":"Они имеют преимущество над Общими правилами интерпретации в случае противоречия.","tr":"Çeliştiklerinde Yorum Genel Kurallarının üzerinde gelirler.","hi":"टकराव की स्थिति में वे General Rules of Interpretation पर वरीयता रखती हैं।","ar":"تُرجَّح على القواعد العامة للتفسير عند التعارض."},{"en":"They are not legally binding but are generally indicative of proper interpretation and may be consulted as persuasive authority.","es":"No son jurídicamente vinculantes, pero por lo general son indicativas de la interpretación correcta y pueden consultarse como autoridad persuasiva.","ru":"Они не являются юридически обязательными, но обычно указывают на правильное толкование и могут использоваться в качестве убедительного авторитетного источника.","tr":"Hukuken bağlayıcı değildirler ancak genellikle doğru yorumun göstergesidir ve ikna edici otorite olarak başvurulabilir.","hi":"वे कानूनी रूप से बाध्यकारी नहीं हैं, परंतु आम तौर पर उचित व्याख्या की द्योतक हैं और प्रेरक प्राधिकार के रूप में परामर्श किए जा सकते हैं।","ar":"إنها ليست مُلزِمة قانونًا لكنها بشكل عام دالة على التفسير الصحيح ويمكن الرجوع إليها بوصفها سلطة مُقنِعة."},{"en":"They have no relevance to HTSUS classification and may not be cited.","es":"No tienen relevancia para la clasificación en el HTSUS y no pueden citarse.","ru":"Они не имеют отношения к классификации HTSUS и не могут цитироваться.","tr":"HTSUS sınıflandırmasıyla hiçbir ilgileri yoktur ve alıntılanamazlar.","hi":"उनका HTSUS वर्गीकरण से कोई संबंध नहीं है और उन्हें उद्धृत नहीं किया जा सकता।","ar":"ليست لها صلة بتصنيف HTSUS ولا يجوز الاستشهاد بها."},{"en":"They are legally binding on CBP and the courts in the same way as the section and chapter notes.","es":"Son jurídicamente vinculantes para la CBP y los tribunales del mismo modo que las notas de sección y de capítulo.","ru":"Они юридически обязательны для CBP и судов так же, как примечания к разделам и группам.","tr":"Bölüm ve fasıl notlarıyla aynı şekilde CBP ve mahkemeler için hukuken bağlayıcıdırlar.","hi":"वे CBP और अदालतों के लिए उसी तरह कानूनी रूप से बाध्यकारी हैं जैसे खंड और अध्याय टिप्पणियां।","ar":"إنها مُلزِمة قانونًا لـ CBP والمحاكم بالطريقة نفسها التي تكون بها ملاحظات الأقسام والفصول."}],"e":{"en":"The Explanatory Notes are the WCO's official interpretation of the Harmonized System. They are not legally binding in the U.S. but are persuasive and generally indicative of the proper interpretation of the headings. The legally binding texts are the headings, subheadings, and the section/chapter notes.","es":"Las Notas Explicativas son la interpretación oficial de la WCO del Sistema Armonizado. No son jurídicamente vinculantes en los Estados Unidos, pero son persuasivas y por lo general indicativas de la interpretación correcta de las partidas. Los textos jurídicamente vinculantes son las partidas, subpartidas y las notas de sección/capítulo.","ru":"Пояснительные примечания являются официальным толкованием Гармонизированной системы со стороны WCO. В США они не являются юридически обязательными, но убедительны и обычно указывают на правильное толкование товарных позиций. Юридически обязательными текстами являются товарные позиции, субпозиции и примечания к разделам/группам.","tr":"Açıklayıcı Notlar, WCO'nun Armonize Sisteme ilişkin resmi yorumudur. ABD'de hukuken bağlayıcı değildirler ancak ikna edicidir ve genellikle pozisyonların doğru yorumunun göstergesidir. Hukuken bağlayıcı metinler pozisyonlar, alt pozisyonlar ve bölüm/fasıl notlarıdır.","hi":"Explanatory Notes, Harmonized System की WCO द्वारा आधिकारिक व्याख्या हैं। वे अमेरिका में कानूनी रूप से बाध्यकारी नहीं हैं, परंतु प्रेरक हैं और आम तौर पर शीर्षकों की उचित व्याख्या की द्योतक हैं। कानूनी रूप से बाध्यकारी पाठ शीर्षक, उप-शीर्षक और खंड/अध्याय टिप्पणियां हैं।","ar":"الملاحظات التفسيرية هي التفسير الرسمي لـ WCO للنظام المنسق. وهي ليست مُلزِمة قانونًا في الولايات المتحدة لكنها مُقنِعة وبشكل عام دالة على التفسير الصحيح للبنود. النصوص المُلزِمة قانونًا هي البنود والبنود الفرعية وملاحظات الأقسام/الفصول."}},{"cat":"classification","a":3,"q":{"en":"In the HTSUS, General Note 3 establishes the rates of duty by columns. Column 1 'General' rates apply to which goods?","es":"En el HTSUS, la General Note 3 establece los tipos de derechos por columnas. Los tipos de la Column 1 'General' se aplican a cuáles mercancías?","ru":"В HTSUS General Note 3 устанавливает ставки пошлин по колонкам. Ставки Column 1 'General' применяются к каким товарам?","tr":"HTSUS'ta General Note 3, gümrük vergisi oranlarını sütunlar halinde belirler. Column 1 'General' oranları hangi mallara uygulanır?","hi":"HTSUS में, General Note 3 स्तंभों के अनुसार शुल्क दरें स्थापित करता है। Column 1 'General' दरें किन वस्तुओं पर लागू होती हैं?","ar":"في HTSUS، تُحدِّد General Note 3 معدلات الرسوم حسب الأعمدة. تُطبَّق معدلات Column 1 'General' على أي بضائع؟"},"o":[{"en":"Goods of countries afforded preferential (free trade agreement) treatment only.","es":"Únicamente mercancías de países a los que se otorga trato preferencial (de acuerdo de libre comercio).","ru":"Только товары стран, которым предоставлен преференциальный режим (соглашения о свободной торговле).","tr":"Yalnızca tercihli (serbest ticaret anlaşması) muamele tanınan ülkelerin malları.","hi":"केवल उन देशों की वस्तुएं जिन्हें तरजीही (मुक्त व्यापार समझौता) व्यवहार दिया जाता है।","ar":"بضائع البلدان التي تُمنَح معاملة تفضيلية (اتفاقية تجارة حرة) فقط."},{"en":"Only goods imported for the personal use of the importer.","es":"Únicamente mercancías importadas para el uso personal del importador.","ru":"Только товары, ввезённые для личного использования импортёром.","tr":"Yalnızca ithalatçının kişisel kullanımı için ithal edilen mallar.","hi":"केवल आयातक के व्यक्तिगत उपयोग के लिए आयातित वस्तुएं।","ar":"البضائع المستوردة للاستخدام الشخصي للمستورد فقط."},{"en":"Goods of countries listed in column 2 (e.g., subject to statutory non-NTR rates).","es":"Mercancías de países enumerados en la column 2 (p. ej., sujetos a tipos legales que no son de NTR).","ru":"Товары стран, перечисленных в column 2 (например, облагаемых установленными законом ставками не NTR).","tr":"Column 2'de listelenen ülkelerin malları (örneğin, yasal non-NTR oranlarına tabi olanlar).","hi":"column 2 में सूचीबद्ध देशों की वस्तुएं (जैसे, वैधानिक non-NTR दरों के अधीन)।","ar":"بضائع البلدان المدرجة في column 2 (مثلاً، الخاضعة لمعدلات non-NTR القانونية)."},{"en":"Goods of countries entitled to most-favored-nation (normal trade relations) treatment that do not qualify for a Special program.","es":"Mercancías de países con derecho al trato de nación más favorecida (relaciones comerciales normales) que no reúnen los requisitos para un programa Special.","ru":"Товары стран, имеющих право на режим наибольшего благоприятствования (нормальные торговые отношения), которые не подпадают под программу Special.","tr":"En çok kayrılan ülke (normal ticari ilişkiler) muamelesine hak kazanan ancak bir Special programa uygun olmayan ülkelerin malları.","hi":"उन देशों की वस्तुएं जो सर्वाधिक तरजीही राष्ट्र (सामान्य व्यापार संबंध) व्यवहार के हकदार हैं परंतु किसी Special कार्यक्रम के योग्य नहीं हैं।","ar":"بضائع البلدان المستحقة لمعاملة الدولة الأولى بالرعاية (العلاقات التجارية الطبيعية) التي لا تستوفي شروط برنامج Special."}],"e":{"en":"Per General Note 3, Column 1 'General' subcolumn rates apply to products of countries with normal trade relations (most-favored-nation) status that are not eligible for a 'Special' preferential rate. Column 1 'Special' covers FTA/preference programs; Column 2 covers the few countries denied NTR treatment.","es":"Conforme a la General Note 3, los tipos de la subcolumna Column 1 'General' se aplican a los productos de países con estatus de relaciones comerciales normales (nación más favorecida) que no son elegibles para un tipo preferencial 'Special'. La Column 1 'Special' abarca los programas de FTA/preferencias; la Column 2 abarca los pocos países a los que se niega el trato de NTR.","ru":"Согласно General Note 3, ставки подколонки Column 1 'General' применяются к товарам стран со статусом нормальных торговых отношений (наибольшего благоприятствования), которые не имеют права на преференциальную ставку 'Special'. Column 1 'Special' охватывает программы FTA/преференций; Column 2 охватывает те немногие страны, которым отказано в режиме NTR.","tr":"General Note 3 uyarınca, Column 1 'General' alt sütun oranları, 'Special' tercihli orana uygun olmayan normal ticari ilişkiler (en çok kayrılan ülke) statüsündeki ülkelerin ürünlerine uygulanır. Column 1 'Special' FTA/tercih programlarını kapsar; Column 2 ise NTR muamelesi reddedilen az sayıdaki ülkeyi kapsar.","hi":"General Note 3 के अनुसार, Column 1 'General' उप-स्तंभ की दरें सामान्य व्यापार संबंध (सर्वाधिक तरजीही राष्ट्र) दर्जे वाले देशों के उत्पादों पर लागू होती हैं जो 'Special' तरजीही दर के लिए पात्र नहीं हैं। Column 1 'Special' में FTA/तरजीह कार्यक्रम शामिल हैं; Column 2 में वे कुछ देश शामिल हैं जिन्हें NTR व्यवहार से वंचित किया गया है।","ar":"بموجب General Note 3، تُطبَّق معدلات العمود الفرعي Column 1 'General' على منتجات البلدان ذات وضع العلاقات التجارية الطبيعية (الدولة الأولى بالرعاية) غير المؤهلة لمعدل تفضيلي 'Special'. ويشمل Column 1 'Special' برامج FTA/التفضيلات؛ بينما يشمل Column 2 البلدان القليلة المحرومة من معاملة NTR."}},{"cat":"classification","a":0,"q":{"en":"In the HTSUS, Column 2 rates of duty (per General Note 3) apply to products of which countries?","es":"En el HTSUS, los tipos de derechos de la Column 2 (conforme a la General Note 3) se aplican a los productos de cuáles países?","ru":"В HTSUS ставки пошлин Column 2 (согласно General Note 3) применяются к товарам каких стран?","tr":"HTSUS'ta Column 2 gümrük vergisi oranları (General Note 3 uyarınca) hangi ülkelerin ürünlerine uygulanır?","hi":"HTSUS में, Column 2 शुल्क दरें (General Note 3 के अनुसार) किन देशों के उत्पादों पर लागू होती हैं?","ar":"في HTSUS، تُطبَّق معدلات الرسوم في Column 2 (بموجب General Note 3) على منتجات أي بلدان؟"},"o":[{"en":"A small enumerated group of countries to which normal trade relations (NTR/MFN) treatment is not extended.","es":"Un pequeño grupo enumerado de países a los que no se extiende el trato de relaciones comerciales normales (NTR/MFN).","ru":"Небольшая перечисленная группа стран, на которые не распространяется режим нормальных торговых отношений (NTR/MFN).","tr":"Normal ticari ilişkiler (NTR/MFN) muamelesinin tanınmadığı, listelenmiş küçük bir ülke grubu.","hi":"देशों का एक छोटा सूचीबद्ध समूह जिन्हें सामान्य व्यापार संबंध (NTR/MFN) व्यवहार नहीं दिया जाता।","ar":"مجموعة صغيرة محددة من البلدان التي لا تُمنَح معاملة العلاقات التجارية الطبيعية (NTR/MFN)."},{"en":"Countries party to a free trade agreement with the United States.","es":"Países parte de un acuerdo de libre comercio con los Estados Unidos.","ru":"Страны — участницы соглашения о свободной торговле с Соединёнными Штатами.","tr":"Birleşik Devletler ile bir serbest ticaret anlaşmasına taraf olan ülkeler.","hi":"संयुक्त राज्य अमेरिका के साथ मुक्त व्यापार समझौते के पक्षकार देश।","ar":"البلدان الأطراف في اتفاقية تجارة حرة مع الولايات المتحدة."},{"en":"Any country whose goods are subject to antidumping duties.","es":"Cualquier país cuyas mercancías estén sujetas a derechos antidumping.","ru":"Любая страна, товары которой облагаются антидемпинговыми пошлинами.","tr":"Malları antidamping vergilerine tabi olan herhangi bir ülke.","hi":"कोई भी देश जिसकी वस्तुएं प्रतिडंपिंग शुल्क के अधीन हैं।","ar":"أي بلد تخضع بضائعه لرسوم مكافحة الإغراق."},{"en":"All developing countries under the Generalized System of Preferences.","es":"Todos los países en desarrollo bajo el Sistema Generalizado de Preferencias.","ru":"Все развивающиеся страны в рамках Всеобщей системы преференций.","tr":"Genelleştirilmiş Tercihler Sistemi kapsamındaki tüm gelişmekte olan ülkeler.","hi":"Generalized System of Preferences के अंतर्गत सभी विकासशील देश।","ar":"جميع البلدان النامية في إطار نظام الأفضليات المعمم."}],"e":{"en":"General Note 3 provides that Column 2 rates apply to products of those countries enumerated as not entitled to normal trade relations (e.g., historically Cuba and North Korea). Column 2 rates are typically the higher statutory rates. FTA and GSP countries are dealt with under Column 1 'Special.'","es":"La General Note 3 dispone que los tipos de la Column 2 se aplican a los productos de aquellos países enumerados como no con derecho a relaciones comerciales normales (p. ej., históricamente Cuba y Corea del Norte). Los tipos de la Column 2 suelen ser los tipos legales más altos. Los países con FTA y GSP se tratan bajo la Column 1 'Special'.","ru":"General Note 3 предусматривает, что ставки Column 2 применяются к товарам тех стран, которые перечислены как не имеющие права на нормальные торговые отношения (например, исторически Куба и Северная Корея). Ставки Column 2 обычно являются более высокими установленными законом ставками. Страны FTA и GSP рассматриваются в рамках Column 1 'Special'.","tr":"General Note 3, Column 2 oranlarının, normal ticari ilişkilere hak kazanmadığı belirtilen ülkelerin (örneğin, tarihsel olarak Küba ve Kuzey Kore) ürünlerine uygulandığını öngörür. Column 2 oranları genellikle daha yüksek yasal oranlardır. FTA ve GSP ülkeleri Column 1 'Special' kapsamında ele alınır.","hi":"General Note 3 यह प्रावधान करता है कि Column 2 दरें उन देशों के उत्पादों पर लागू होती हैं जिन्हें सामान्य व्यापार संबंधों का हकदार नहीं माना गया है (जैसे, ऐतिहासिक रूप से क्यूबा और उत्तर कोरिया)। Column 2 दरें आम तौर पर उच्चतर वैधानिक दरें होती हैं। FTA और GSP देशों को Column 1 'Special' के अंतर्गत निपटाया जाता है।","ar":"تنص General Note 3 على أن معدلات Column 2 تُطبَّق على منتجات تلك البلدان المُدرَجة بوصفها غير مستحقة للعلاقات التجارية الطبيعية (مثلاً، تاريخيًا كوبا وكوريا الشمالية). ومعدلات Column 2 عادةً ما تكون المعدلات القانونية الأعلى. وتُعالَج بلدان FTA وGSP بموجب Column 1 'Special'."}},{"cat":"classification","a":1,"q":{"en":"Two distinct fabrics are combined: a knit cotton outer shell quilted to a nonwoven insulating batting, presented as a single composite material in the piece. After GRI 1 fails to point to one heading and the materials fall in different headings, which sequence correctly resolves classification?","es":"Se combinan dos tejidos distintos: una cubierta exterior de punto de algodón acolchada a un guata aislante no tejido, presentada como un solo material compuesto en pieza. Después de que la GRI 1 no logra señalar una sola partida y los materiales corresponden a partidas diferentes, cuál secuencia resuelve correctamente la clasificación?","ru":"Объединены два разных текстильных материала: вязаная хлопчатобумажная внешняя оболочка, простёганная с нетканым изоляционным ватином, представленные как единый композитный материал в куске. После того как GRI 1 не указывает на одну позицию, а материалы относятся к разным позициям, какая последовательность правильно решает классификацию?","tr":"İki farklı kumaş birleştirilir: örme pamuklu bir dış kabuk, dokumasız yalıtkan bir elyaf tabakasına kapitone edilmiş ve parça halinde tek bir bileşik malzeme olarak sunulmuştur. GRI 1 tek bir pozisyonu göstermekte başarısız olduktan ve malzemeler farklı pozisyonlara girdikten sonra, sınıflandırmayı hangi sıra doğru şekilde çözer?","hi":"दो भिन्न कपड़े संयोजित किए जाते हैं: एक बुना हुआ कपास बाहरी आवरण जो एक गैर-बुने हुए इन्सुलेटिंग बैटिंग से रजाई की तरह सिला गया है, टुकड़े में एकल संयुक्त सामग्री के रूप में प्रस्तुत। GRI 1 के एक शीर्षक की ओर इंगित करने में विफल होने और सामग्रियों के भिन्न शीर्षकों में आने के बाद, कौन सा क्रम वर्गीकरण को सही ढंग से हल करता है?","ar":"يُدمَج نسيجان متمايزان: غلاف خارجي مصنوع من قطن محبوك ومُبطَّن (مخيَّط) على حشوة عازلة غير منسوجة، يُقدَّم كمادة مركبة واحدة في القطعة. بعد أن تفشل GRI 1 في الإشارة إلى بند واحد وتقع المواد في بنود مختلفة، أي تسلسل يحل التصنيف بشكل صحيح؟"},"o":[{"en":"Apply GRI 6 directly to compare subheadings before any heading is chosen.","es":"Aplicar la GRI 6 directamente para comparar subpartidas antes de elegir cualquier partida.","ru":"Применить GRI 6 напрямую для сравнения субпозиций, прежде чем выбрана какая-либо позиция.","tr":"Herhangi bir pozisyon seçilmeden önce alt pozisyonları karşılaştırmak için doğrudan GRI 6'yı uygulamak.","hi":"किसी भी शीर्षक के चुने जाने से पहले उप-शीर्षकों की तुलना के लिए सीधे GRI 6 लागू करें।","ar":"تطبيق GRI 6 مباشرةً لمقارنة البنود الفرعية قبل اختيار أي بند."},{"en":"Apply GRI 3(a) (most specific) first; if unresolved, GRI 3(b) essential character; if still unresolved, GRI 3(c) last in numerical order.","es":"Aplicar primero la GRI 3(a) (la más específica); si no se resuelve, la GRI 3(b) carácter esencial; si aún no se resuelve, la GRI 3(c) la última en orden numérico.","ru":"Сначала применить GRI 3(a) (наиболее конкретное описание); если не решено — GRI 3(b) основной характер; если всё ещё не решено — GRI 3(c) последняя в числовом порядке.","tr":"Önce GRI 3(a)'yı (en spesifik) uygulamak; çözülmezse GRI 3(b) esas karakter; yine çözülmezse GRI 3(c) numara sırasına göre sonuncu.","hi":"पहले GRI 3(a) (सर्वाधिक विशिष्ट) लागू करें; यदि हल न हो, तो GRI 3(b) अनिवार्य विशेषता; यदि फिर भी हल न हो, तो GRI 3(c) संख्यात्मक क्रम में अंतिम।","ar":"تطبيق GRI 3(a) (الأكثر تحديدًا) أولاً؛ وإذا لم يُحَل، فـ GRI 3(b) الطابع الأساسي؛ وإذا ظل دون حل، فـ GRI 3(c) الأخير في الترتيب الرقمي."},{"en":"Apply GRI 2(b) to choose the heading of the predominant fiber, ending the analysis.","es":"Aplicar la GRI 2(b) para elegir la partida de la fibra predominante, poniendo fin al análisis.","ru":"Применить GRI 2(b), чтобы выбрать позицию преобладающего волокна, завершив анализ.","tr":"Baskın lifin pozisyonunu seçmek için GRI 2(b)'yi uygulayarak analizi sonlandırmak.","hi":"प्रमुख रेशे का शीर्षक चुनने के लिए GRI 2(b) लागू करें, और विश्लेषण समाप्त करें।","ar":"تطبيق GRI 2(b) لاختيار بند الألياف الغالبة، وإنهاء التحليل."},{"en":"Apply GRI 5(b) because the batting is packing material for the shell.","es":"Aplicar la GRI 5(b) porque la guata es material de embalaje para la cubierta.","ru":"Применить GRI 5(b), потому что ватин является упаковочным материалом для оболочки.","tr":"Elyaf tabakası kabuk için ambalaj malzemesi olduğundan GRI 5(b)'yi uygulamak.","hi":"GRI 5(b) लागू करें क्योंकि बैटिंग आवरण के लिए पैकिंग सामग्री है।","ar":"تطبيق GRI 5(b) لأن الحشوة مادة تغليف للغلاف."}],"e":{"en":"A composite good made up of different materials/components classifiable under different headings is resolved under GRI 3 in order: 3(a) most-specific description, then 3(b) essential character, then 3(c) last numerical heading. GRI 2(b) merely directs you to GRI 3; GRI 6 operates only after the heading is fixed.","es":"Una mercancía compuesta hecha de distintos materiales/componentes clasificables en partidas diferentes se resuelve conforme a la GRI 3 en orden: 3(a) descripción más específica, luego 3(b) carácter esencial, luego 3(c) la última partida en orden numérico. La GRI 2(b) simplemente remite a la GRI 3; la GRI 6 opera solo después de fijar la partida.","ru":"Составной товар, состоящий из разных материалов/компонентов, классифицируемых по разным позициям, разрешается согласно GRI 3 в порядке: 3(a) наиболее конкретное описание, затем 3(b) основной характер, затем 3(c) последняя позиция в числовом порядке. GRI 2(b) лишь отсылает к GRI 3; GRI 6 действует только после того, как позиция определена.","tr":"Farklı pozisyonlarda sınıflandırılabilen farklı malzemelerden/bileşenlerden oluşan bileşik bir mal, GRI 3'e göre sırasıyla çözülür: 3(a) en spesifik tanım, ardından 3(b) esas karakter, ardından 3(c) numara sırasına göre son pozisyon. GRI 2(b) sizi yalnızca GRI 3'e yönlendirir; GRI 6 yalnızca pozisyon belirlendikten sonra işler.","hi":"विभिन्न शीर्षकों के अंतर्गत वर्गीकरण योग्य भिन्न सामग्रियों/घटकों से बनी एक संयुक्त वस्तु को GRI 3 के अंतर्गत क्रम में हल किया जाता है: 3(a) सर्वाधिक विशिष्ट विवरण, फिर 3(b) अनिवार्य विशेषता, फिर 3(c) संख्यात्मक क्रम में अंतिम शीर्षक। GRI 2(b) केवल आपको GRI 3 की ओर निर्देशित करता है; GRI 6 केवल शीर्षक तय होने के बाद ही कार्य करता है।","ar":"البضاعة المركبة المكونة من مواد/مكونات مختلفة قابلة للتصنيف في بنود مختلفة تُحَل بموجب GRI 3 بالترتيب: 3(a) الوصف الأكثر تحديدًا، ثم 3(b) الطابع الأساسي، ثم 3(c) البند الأخير في الترتيب الرقمي. وتوجّهك GRI 2(b) إلى GRI 3 فحسب؛ ولا تعمل GRI 6 إلا بعد تثبيت البند."}},{"cat":"classification","a":0,"q":{"en":"Under GRI 3(a), the rule that the most specific description is preferred has an explicit limitation. When does GRI 3(a) NOT resolve the choice, forcing a move to GRI 3(b)?","es":"Conforme a la GRI 3(a), la regla de que se prefiere la descripción más específica tiene una limitación explícita. Cuándo NO resuelve la GRI 3(a) la elección, obligando a pasar a la GRI 3(b)?","ru":"Согласно GRI 3(a), правило о предпочтении наиболее конкретного описания имеет явное ограничение. Когда GRI 3(a) НЕ решает выбор, заставляя перейти к GRI 3(b)?","tr":"GRI 3(a) uyarınca, en spesifik tanımın tercih edildiği kuralın açık bir sınırlaması vardır. GRI 3(a) seçimi hangi durumda çözMEZ ve GRI 3(b)'ye geçişi zorunlu kılar?","hi":"GRI 3(a) के अंतर्गत, यह नियम कि सर्वाधिक विशिष्ट विवरण को वरीयता दी जाती है, की एक स्पष्ट सीमा है। GRI 3(a) कब चयन को हल नहीं करता, जिससे GRI 3(b) की ओर बढ़ना अनिवार्य हो जाता है?","ar":"بموجب GRI 3(a)، فإن قاعدة تفضيل الوصف الأكثر تحديدًا لها قيد صريح. متى لا تحل GRI 3(a) الاختيار، مما يستلزم الانتقال إلى GRI 3(b)؟"},"o":[{"en":"When two or more headings each refer to only part of the materials in a composite good or only part of the items in a retail set — they are then regarded as equally specific.","es":"Cuando dos o más partidas se refieren cada una solo a parte de los materiales de una mercancía compuesta o solo a parte de los artículos de un surtido para la venta al por menor —entonces se consideran igualmente específicas.","ru":"Когда две или более позиции каждая относится лишь к части материалов составного товара или лишь к части предметов в наборе для розничной продажи — тогда они считаются равно конкретными.","tr":"İki veya daha fazla pozisyonun her biri bileşik bir maldaki malzemelerin yalnızca bir kısmına veya perakende satış setindeki ürünlerin yalnızca bir kısmına atıfta bulunduğunda — bu durumda eşit derecede spesifik kabul edilirler.","hi":"जब दो या अधिक शीर्षक प्रत्येक किसी संयुक्त वस्तु की सामग्रियों के केवल एक भाग को या खुदरा सेट की वस्तुओं के केवल एक भाग को संदर्भित करते हैं — तब उन्हें समान रूप से विशिष्ट माना जाता है।","ar":"عندما يشير كل من بندين أو أكثر إلى جزء فقط من المواد في بضاعة مركبة أو إلى جزء فقط من الأصناف في طقم للبيع بالتجزئة — تُعتبَر عندئذٍ متساوية في التحديد."},{"en":"Whenever an Explanatory Note is silent on the matter.","es":"Siempre que una Nota Explicativa guarde silencio sobre la cuestión.","ru":"Всякий раз, когда Пояснительное примечание умалчивает по данному вопросу.","tr":"Bir Açıklayıcı Notun konu hakkında sessiz kaldığı her durumda.","hi":"जब भी कोई Explanatory Note उस मामले पर मौन हो।","ar":"كلما كانت إحدى الملاحظات التفسيرية صامتة بشأن المسألة."},{"en":"Whenever the goods are made of plastic.","es":"Siempre que las mercancías estén hechas de plástico.","ru":"Всякий раз, когда товары изготовлены из пластмассы.","tr":"Mallar plastikten yapıldığında.","hi":"जब भी वस्तुएं प्लास्टिक से बनी हों।","ar":"كلما كانت البضائع مصنوعة من البلاستيك."},{"en":"Only when the headings carry identical duty rates.","es":"Únicamente cuando las partidas tienen tipos de derechos idénticos.","ru":"Только когда позиции имеют одинаковые ставки пошлин.","tr":"Yalnızca pozisyonların aynı gümrük vergisi oranlarını taşıdığı durumda.","hi":"केवल तब जब शीर्षकों की शुल्क दरें समान हों।","ar":"فقط عندما تحمل البنود معدلات رسوم متطابقة."}],"e":{"en":"GRI 3(a), last sentence: when two or more headings each refer to part only of the materials in a mixture/composite good, or to part only of the items in a retail set, those headings are regarded as equally specific even if one is more complete or precise. GRI 3(a) cannot break the tie, so GRI 3(b) (essential character) is applied next.","es":"GRI 3(a), última oración: cuando dos o más partidas se refieren cada una solo a parte de los materiales de una mezcla/mercancía compuesta, o solo a parte de los artículos de un surtido para la venta al por menor, esas partidas se consideran igualmente específicas aunque una sea más completa o precisa. La GRI 3(a) no puede deshacer el empate, por lo que a continuación se aplica la GRI 3(b) (carácter esencial).","ru":"GRI 3(a), последнее предложение: когда две или более позиции каждая относится лишь к части материалов смеси/составного товара или лишь к части предметов в наборе для розничной продажи, эти позиции считаются равно конкретными, даже если одна более полная или точная. GRI 3(a) не может разрешить равенство, поэтому далее применяется GRI 3(b) (основной характер).","tr":"GRI 3(a), son cümle: iki veya daha fazla pozisyonun her biri bir karışım/bileşik maldaki malzemelerin yalnızca bir kısmına veya perakende satış setindeki ürünlerin yalnızca bir kısmına atıfta bulunduğunda, biri daha eksiksiz veya kesin olsa bile bu pozisyonlar eşit derecede spesifik kabul edilir. GRI 3(a) eşitliği bozamaz, bu nedenle bir sonraki adımda GRI 3(b) (esas karakter) uygulanır.","hi":"GRI 3(a), अंतिम वाक्य: जब दो या अधिक शीर्षक प्रत्येक किसी मिश्रण/संयुक्त वस्तु की सामग्रियों के केवल एक भाग को, या खुदरा सेट की वस्तुओं के केवल एक भाग को संदर्भित करते हैं, तो उन शीर्षकों को समान रूप से विशिष्ट माना जाता है, भले ही एक अधिक पूर्ण या सटीक हो। GRI 3(a) इस गतिरोध को नहीं तोड़ सकता, इसलिए आगे GRI 3(b) (अनिवार्य विशेषता) लागू किया जाता है।","ar":"GRI 3(a)، الجملة الأخيرة: عندما يشير كل من بندين أو أكثر إلى جزء فقط من المواد في خليط/بضاعة مركبة، أو إلى جزء فقط من الأصناف في طقم للبيع بالتجزئة، تُعتبَر تلك البنود متساوية في التحديد حتى لو كان أحدها أكثر اكتمالاً أو دقة. ولا تستطيع GRI 3(a) حسم التعادل، لذا تُطبَّق بعدها GRI 3(b) (الطابع الأساسي)."}},{"cat":"classification","a":2,"q":{"en":"An importer must report a unit of quantity for an entry line. Where in the HTSUS is the required statistical 'unit of quantity' for each statistical reporting number specified?","es":"Un importador debe declarar una unidad de cantidad para una línea de entrada. Dónde en el HTSUS se especifica la 'unit of quantity' estadística requerida para cada número de declaración estadística?","ru":"Импортёр должен указать единицу количества для строки ввоза. Где в HTSUS указана требуемая статистическая 'unit of quantity' для каждого статистического отчётного номера?","tr":"Bir ithalatçı, bir giriş satırı için bir miktar birimi bildirmek zorundadır. HTSUS'ta her istatistiksel raporlama numarası için gerekli istatistiksel 'unit of quantity' nerede belirtilmiştir?","hi":"एक आयातक को प्रवेश लाइन के लिए मात्रा की एक इकाई की रिपोर्ट करनी होती है। HTSUS में प्रत्येक सांख्यिकीय रिपोर्टिंग संख्या के लिए आवश्यक सांख्यिकीय 'unit of quantity' कहां निर्दिष्ट है?","ar":"يجب على المستورد الإبلاغ عن وحدة كمية لسطر الإدخال. أين في HTSUS تُحدَّد 'unit of quantity' الإحصائية المطلوبة لكل رقم إبلاغ إحصائي؟"},"o":[{"en":"It is determined by the General Rules of Interpretation.","es":"La determinan las Reglas Generales de Interpretación.","ru":"Она определяется Общими правилами интерпретации.","tr":"Yorum Genel Kuralları tarafından belirlenir.","hi":"इसे General Rules of Interpretation द्वारा निर्धारित किया जाता है।","ar":"تُحدَّد بموجب القواعد العامة للتفسير."},{"en":"It is defined only in the General Notes and never per line item.","es":"Se define únicamente en las General Notes y nunca por partida individual.","ru":"Она определена только в General Notes и никогда по отдельной позиции.","tr":"Yalnızca General Notes'ta tanımlanır ve asla satır kalemi başına değildir.","hi":"इसे केवल General Notes में परिभाषित किया गया है और कभी भी प्रति लाइन आइटम नहीं।","ar":"تُعرَّف فقط في General Notes ولا تُحدَّد أبدًا لكل بند سطري."},{"en":"It is prescribed in the 'Unit of Quantity' column of the tariff schedule for each statistical reporting (10-digit) number.","es":"Está prescrita en la columna 'Unit of Quantity' de la nomenclatura arancelaria para cada número de declaración estadística (de 10 dígitos).","ru":"Она предписана в колонке 'Unit of Quantity' тарифного расписания для каждого статистического отчётного (10-значного) номера.","tr":"Her istatistiksel raporlama (10 haneli) numarası için tarife cetvelinin 'Unit of Quantity' sütununda belirlenmiştir.","hi":"यह प्रत्येक सांख्यिकीय रिपोर्टिंग (10-अंकीय) संख्या के लिए टैरिफ अनुसूची के 'Unit of Quantity' स्तंभ में निर्धारित है।","ar":"إنها محددة في عمود 'Unit of Quantity' من جدول التعرفة لكل رقم إبلاغ إحصائي (من 10 خانات)."},{"en":"It is chosen freely by the importer based on the commercial invoice.","es":"La elige libremente el importador con base en la factura comercial.","ru":"Она свободно выбирается импортёром на основании коммерческого счёта-фактуры.","tr":"İthalatçı tarafından ticari fatura esas alınarak serbestçe seçilir.","hi":"इसे आयातक द्वारा वाणिज्यिक चालान के आधार पर स्वतंत्र रूप से चुना जाता है।","ar":"يختارها المستورد بحرية بناءً على الفاتورة التجارية."}],"e":{"en":"The HTSUS tariff columns include a 'Unit of Quantity' column that prescribes the statistical unit (e.g., 'No.', 'kg', 'doz.', 'm2') to be reported for each 10-digit statistical reporting number. The importer must report in that prescribed unit; it is not freely chosen. The GRIs govern classification, not the reporting unit.","es":"Las columnas arancelarias del HTSUS incluyen una columna 'Unit of Quantity' que prescribe la unidad estadística (p. ej., 'No.', 'kg', 'doz.', 'm2') que debe declararse para cada número de declaración estadística de 10 dígitos. El importador debe declarar en esa unidad prescrita; no se elige libremente. Las GRI rigen la clasificación, no la unidad de declaración.","ru":"Тарифные колонки HTSUS включают колонку 'Unit of Quantity', которая предписывает статистическую единицу (например, 'No.', 'kg', 'doz.', 'm2'), подлежащую указанию для каждого 10-значного статистического отчётного номера. Импортёр должен отчитываться в этой предписанной единице; она не выбирается свободно. GRI регулируют классификацию, а не единицу отчётности.","tr":"HTSUS tarife sütunları, her 10 haneli istatistiksel raporlama numarası için bildirilecek istatistiksel birimi (örneğin, 'No.', 'kg', 'doz.', 'm2') belirleyen bir 'Unit of Quantity' sütunu içerir. İthalatçı bu belirlenen birimle bildirim yapmak zorundadır; serbestçe seçilmez. GRI'ler sınıflandırmayı yönetir, raporlama birimini değil.","hi":"HTSUS टैरिफ स्तंभों में एक 'Unit of Quantity' स्तंभ शामिल है जो प्रत्येक 10-अंकीय सांख्यिकीय रिपोर्टिंग संख्या के लिए रिपोर्ट की जाने वाली सांख्यिकीय इकाई (जैसे, 'No.', 'kg', 'doz.', 'm2') निर्धारित करता है। आयातक को उसी निर्धारित इकाई में रिपोर्ट करनी होगी; इसे स्वतंत्र रूप से नहीं चुना जाता। GRIs वर्गीकरण को नियंत्रित करते हैं, रिपोर्टिंग इकाई को नहीं।","ar":"تتضمن أعمدة تعرفة HTSUS عمود 'Unit of Quantity' الذي يحدد الوحدة الإحصائية (مثلاً، 'No.'، 'kg'، 'doz.'، 'm2') المطلوب الإبلاغ عنها لكل رقم إبلاغ إحصائي من 10 خانات. يجب على المستورد الإبلاغ بتلك الوحدة المحددة؛ ولا تُختار بحرية. وتحكم GRIs التصنيف وليس وحدة الإبلاغ."}},{"cat":"classification","a":3,"q":{"en":"A statistical reporting number shows 'X' in the Unit of Quantity column. What does this indicate to the filer?","es":"Un número de declaración estadística muestra 'X' en la columna Unit of Quantity. Qué indica esto al declarante?","ru":"Статистический отчётный номер показывает 'X' в колонке Unit of Quantity. Что это указывает подающему декларацию?","tr":"Bir istatistiksel raporlama numarası, Unit of Quantity sütununda 'X' gösterir. Bu, beyanı yapan kişiye neyi gösterir?","hi":"एक सांख्यिकीय रिपोर्टिंग संख्या Unit of Quantity स्तंभ में 'X' दर्शाती है। यह दाखिल करने वाले को क्या इंगित करता है?","ar":"يُظهِر رقم إبلاغ إحصائي 'X' في عمود Unit of Quantity. ماذا يشير هذا إلى مقدم البيان؟"},"o":[{"en":"The quantity must be reported in both kilograms and number.","es":"La cantidad debe declararse tanto en kilogramos como en número.","ru":"Количество должно указываться как в килограммах, так и в штуках.","tr":"Miktar hem kilogram hem de adet olarak bildirilmelidir.","hi":"मात्रा की रिपोर्ट किलोग्राम और संख्या दोनों में करनी होगी।","ar":"يجب الإبلاغ عن الكمية بالكيلوغرامات والعدد معًا."},{"en":"The line is restricted and requires a special permit.","es":"La línea está restringida y requiere un permiso especial.","ru":"Строка ограничена и требует специального разрешения.","tr":"Satır kısıtlıdır ve özel bir izin gerektirir.","hi":"यह लाइन प्रतिबंधित है और इसके लिए विशेष परमिट की आवश्यकता है।","ar":"السطر مقيَّد ويتطلب تصريحًا خاصًا."},{"en":"The quantity is unknown and may be left blank.","es":"La cantidad es desconocida y puede dejarse en blanco.","ru":"Количество неизвестно и может быть оставлено пустым.","tr":"Miktar bilinmiyor ve boş bırakılabilir.","hi":"मात्रा अज्ञात है और इसे रिक्त छोड़ा जा सकता है।","ar":"الكمية غير معروفة ويمكن تركها فارغة."},{"en":"No quantity (other than the standard requirement) is to be reported for that statistical reporting number.","es":"No debe declararse ninguna cantidad (aparte del requisito estándar) para ese número de declaración estadística.","ru":"Для этого статистического отчётного номера не должно указываться никакого количества (помимо стандартного требования).","tr":"Söz konusu istatistiksel raporlama numarası için (standart gereklilik dışında) hiçbir miktar bildirilmeyecektir.","hi":"उस सांख्यिकीय रिपोर्टिंग संख्या के लिए कोई मात्रा (मानक आवश्यकता के अलावा) रिपोर्ट नहीं की जानी है।","ar":"لا يُبلَّغ عن أي كمية (بخلاف المتطلب القياسي) لرقم الإبلاغ الإحصائي المذكور."}],"e":{"en":"In the HTSUS Unit of Quantity column, the symbol 'X' indicates that no statistical quantity is required to be reported for that line (beyond any standard requirements such as value). It is a recognized HTSUS convention, not a placeholder for an unknown quantity.","es":"En la columna Unit of Quantity del HTSUS, el símbolo 'X' indica que no se requiere declarar ninguna cantidad estadística para esa línea (más allá de los requisitos estándar como el valor). Es una convención reconocida del HTSUS, no un marcador de posición para una cantidad desconocida.","ru":"В колонке Unit of Quantity HTSUS символ 'X' указывает, что для этой строки не требуется указывать никакого статистического количества (помимо любых стандартных требований, таких как стоимость). Это признанное соглашение HTSUS, а не заполнитель для неизвестного количества.","tr":"HTSUS Unit of Quantity sütununda 'X' sembolü, o satır için (değer gibi standart gereklilikler dışında) hiçbir istatistiksel miktarın bildirilmesinin gerekmediğini gösterir. Bu, bilinmeyen bir miktar için yer tutucu değil, tanınmış bir HTSUS kuralıdır.","hi":"HTSUS Unit of Quantity स्तंभ में, प्रतीक 'X' इंगित करता है कि उस लाइन के लिए कोई सांख्यिकीय मात्रा रिपोर्ट करना आवश्यक नहीं है (मूल्य जैसी किसी भी मानक आवश्यकता से परे)। यह HTSUS की एक मान्यता प्राप्त परंपरा है, न कि किसी अज्ञात मात्रा के लिए स्थानधारक।","ar":"في عمود Unit of Quantity في HTSUS، يشير الرمز 'X' إلى عدم اشتراط الإبلاغ عن أي كمية إحصائية لذلك السطر (بخلاف أي متطلبات قياسية مثل القيمة). وهو عُرف معترف به في HTSUS، وليس عنصرًا نائبًا عن كمية غير معروفة."}},{"cat":"classification","a":3,"q":{"en":"A composite article consists of an electric hair clipper with a permanently attached comb-guide that cannot be removed without tools. The clipper and the comb fall in different headings. After determining it is a composite good made up of different components, which rule and basis applies?","es":"Un artículo compuesto consiste en una maquinilla eléctrica para cortar el cabello con una guía-peine fijada de forma permanente que no puede retirarse sin herramientas. La maquinilla y el peine corresponden a partidas diferentes. Después de determinar que se trata de una mercancía compuesta formada por componentes diferentes, cuál regla y fundamento se aplica?","ru":"Составное изделие состоит из электрической машинки для стрижки волос с постоянно прикреплённой гребёнчатой насадкой, которую нельзя снять без инструментов. Машинка и гребёнка относятся к разным позициям. После определения того, что это составной товар из разных компонентов, какое правило и основание применяется?","tr":"Bileşik bir eşya, aletsiz çıkarılamayan kalıcı olarak takılmış bir tarak-kılavuzuna sahip elektrikli bir saç kesme makinesinden oluşur. Makine ve tarak farklı pozisyonlara girer. Bunun farklı bileşenlerden oluşan bileşik bir mal olduğunu belirledikten sonra, hangi kural ve dayanak uygulanır?","hi":"एक संयुक्त वस्तु में एक विद्युत बाल कतरनी होती है जिसमें स्थायी रूप से जुड़ी एक कंघी-गाइड होती है जिसे औजारों के बिना हटाया नहीं जा सकता। कतरनी और कंघी भिन्न शीर्षकों में आती हैं। यह निर्धारित करने के बाद कि यह भिन्न घटकों से बनी एक संयुक्त वस्तु है, कौन सा नियम और आधार लागू होता है?","ar":"تتكون مادة مركبة من ماكينة قص شعر كهربائية مزودة بدليل-مشط مثبَّت بشكل دائم لا يمكن إزالته دون أدوات. تقع الماكينة والمشط في بنود مختلفة. بعد تحديد أنها بضاعة مركبة مكونة من مكونات مختلفة، أي قاعدة وأساس ينطبق؟"},"o":[{"en":"GRI 2(a), as an unfinished clipper.","es":"GRI 2(a), como una maquinilla sin terminar.","ru":"GRI 2(a), как незавершённая машинка.","tr":"GRI 2(a), tamamlanmamış bir makine olarak.","hi":"GRI 2(a), एक अधूरी कतरनी के रूप में।","ar":"GRI 2(a)، بوصفها ماكينة غير مكتملة."},{"en":"GRI 5(a), treating the comb as a fitted case for the clipper.","es":"GRI 5(a), tratando el peine como un estuche ajustado para la maquinilla.","ru":"GRI 5(a), рассматривая гребёнку как футляр, подогнанный для машинки.","tr":"GRI 5(a), tarağı makine için özel yapılmış bir kutu olarak değerlendirerek.","hi":"GRI 5(a), कंघी को कतरनी के लिए अनुकूलित डिब्बे के रूप में मानते हुए।","ar":"GRI 5(a)، باعتبار المشط علبة مُصمَّمة للماكينة."},{"en":"GRI 3(c), choosing the heading last in numerical order between clipper and comb.","es":"GRI 3(c), eligiendo la partida que figure en último lugar en orden numérico entre la maquinilla y el peine.","ru":"GRI 3(c), выбирая позицию, последнюю в числовом порядке между машинкой и гребёнкой.","tr":"GRI 3(c), makine ile tarak arasında numara sırasına göre sonuncu pozisyonu seçerek.","hi":"GRI 3(c), कतरनी और कंघी के बीच संख्यात्मक क्रम में अंतिम शीर्षक का चयन करते हुए।","ar":"GRI 3(c)، باختيار البند الأخير في الترتيب الرقمي بين الماكينة والمشط."},{"en":"GRI 3(b), classifying by essential character — the clipper component imparts it.","es":"GRI 3(b), clasificando por carácter esencial —el componente de la maquinilla lo confiere.","ru":"GRI 3(b), классификация по основному характеру — его придаёт компонент машинки.","tr":"GRI 3(b), esas karaktere göre sınıflandırma — onu makine bileşeni verir.","hi":"GRI 3(b), अनिवार्य विशेषता के अनुसार वर्गीकरण — इसे कतरनी घटक प्रदान करता है।","ar":"GRI 3(b)، التصنيف حسب الطابع الأساسي — يضفيه مكوّن الماكينة."}],"e":{"en":"Components attached together to form a practically inseparable whole are a 'composite good' under GRI 3(b). Classification is by essential character; the electric clipper, being the functional core, imparts it. GRI 3(c) is only reached if essential character cannot be determined.","es":"Los componentes unidos entre sí para formar un todo prácticamente inseparable constituyen una 'mercancía compuesta' conforme a la GRI 3(b). La clasificación se hace por carácter esencial; la maquinilla eléctrica, al ser el núcleo funcional, lo confiere. Solo se llega a la GRI 3(c) si no puede determinarse el carácter esencial.","ru":"Компоненты, соединённые вместе так, что образуют практически неразделимое целое, являются 'составным товаром' согласно GRI 3(b). Классификация осуществляется по основному характеру; его придаёт электрическая машинка, будучи функциональной основой. GRI 3(c) применяется только в том случае, если основной характер определить невозможно.","tr":"Pratik olarak ayrılamaz bir bütün oluşturacak şekilde birbirine bağlanmış bileşenler, GRI 3(b) uyarınca bir 'bileşik mal'dır. Sınıflandırma esas karaktere göre yapılır; işlevsel çekirdek olan elektrikli makine bunu verir. GRI 3(c)'ye yalnızca esas karakter belirlenemediğinde başvurulur.","hi":"व्यावहारिक रूप से अविभाज्य पूर्ण बनाने के लिए एक साथ जुड़े घटक GRI 3(b) के अंतर्गत एक 'संयुक्त वस्तु' होते हैं। वर्गीकरण अनिवार्य विशेषता के अनुसार होता है; विद्युत कतरनी, कार्यात्मक केंद्र होने के नाते, इसे प्रदान करती है। GRI 3(c) तक केवल तभी पहुंचा जाता है जब अनिवार्य विशेषता निर्धारित नहीं की जा सकती।","ar":"المكونات الموصولة معًا لتشكيل كلٍّ غير قابل للفصل عمليًا تُعَد 'بضاعة مركبة' بموجب GRI 3(b). ويكون التصنيف حسب الطابع الأساسي؛ وتضفيه الماكينة الكهربائية بوصفها النواة الوظيفية. ولا يُلجأ إلى GRI 3(c) إلا إذا تعذّر تحديد الطابع الأساسي."}},{"cat":"classification","a":1,"q":{"en":"Within heading 9503 (toys), an importer must decide between a one-dash subheading and a more detailed two-dash subheading beneath a DIFFERENT one-dash provision. Under GRI 6, what is the correct procedural step?","es":"Dentro de la partida 9503 (juguetes), un importador debe decidir entre una subpartida de un guion y una subpartida de dos guiones más detallada que se encuentra bajo una disposición de un guion DIFERENTE. Conforme a la GRI 6, ¿cuál es el paso procedimental correcto?","ru":"В рамках товарной позиции 9503 (игрушки) импортёр должен выбрать между субпозицией с одним дефисом и более детализированной субпозицией с двумя дефисами, находящейся под ДРУГОЙ субпозицией с одним дефисом. Согласно GRI 6, каков правильный процедурный шаг?","tr":"9503 pozisyonu (oyuncaklar) içinde, bir ithalatçı tek tireli bir alt pozisyon ile FARKLI bir tek tireli hüküm altında yer alan daha ayrıntılı iki tireli bir alt pozisyon arasında karar vermek zorundadır. GRI 6 uyarınca doğru usul adımı nedir?","hi":"शीर्षक 9503 (खिलौने) के भीतर, एक आयातक को एक-डैश उपशीर्षक और एक भिन्न (DIFFERENT) एक-डैश प्रावधान के अंतर्गत आने वाले अधिक विस्तृत दो-डैश उपशीर्षक के बीच निर्णय लेना होता है। GRI 6 के अंतर्गत सही प्रक्रियात्मक कदम क्या है?","ar":"ضمن البند 9503 (لعب الأطفال)، يجب على المستورد أن يختار بين بند فرعي بشرطة واحدة وبند فرعي أكثر تفصيلاً بشرطتين يقع تحت حكم مختلف بشرطة واحدة. بموجب GRI 6، ما هي الخطوة الإجرائية الصحيحة؟"},"o":[{"en":"Apply GRI 3(c) to pick the subheading last in numerical order.","es":"Aplicar la GRI 3(c) para elegir la subpartida que figure en último lugar en orden numérico.","ru":"Применить GRI 3(c) для выбора субпозиции, последней в числовом порядке.","tr":"Sayısal sırada son gelen alt pozisyonu seçmek için GRI 3(c) uygulamak.","hi":"संख्यात्मक क्रम में अंतिम आने वाले उपशीर्षक को चुनने के लिए GRI 3(c) लागू करना।","ar":"تطبيق GRI 3(c) لاختيار البند الفرعي الأخير في الترتيب الرقمي."},{"en":"First determine the correct one-dash subheading; only then compare the two-dash subheadings subordinate to that selected one-dash provision.","es":"Determinar primero la subpartida de un guion correcta; solo entonces comparar las subpartidas de dos guiones subordinadas a esa disposición de un guion seleccionada.","ru":"Сначала определить правильную субпозицию с одним дефисом; только затем сравнивать субпозиции с двумя дефисами, подчинённые этой выбранной субпозиции с одним дефисом.","tr":"Önce doğru tek tireli alt pozisyonu belirlemek; ancak ondan sonra seçilen bu tek tireli hükme tabi iki tireli alt pozisyonları karşılaştırmak.","hi":"पहले सही एक-डैश उपशीर्षक निर्धारित करना; उसके बाद ही उस चयनित एक-डैश प्रावधान के अधीनस्थ दो-डैश उपशीर्षकों की तुलना करना।","ar":"تحديد البند الفرعي الصحيح ذي الشرطة الواحدة أولاً؛ وبعد ذلك فقط مقارنة البنود الفرعية ذات الشرطتين التابعة لذلك الحكم المختار ذي الشرطة الواحدة."},{"en":"Always choose the two-dash subheading because it is more detailed.","es":"Elegir siempre la subpartida de dos guiones porque es más detallada.","ru":"Всегда выбирать субпозицию с двумя дефисами, потому что она более детализирована.","tr":"Daha ayrıntılı olduğu için her zaman iki tireli alt pozisyonu seçmek.","hi":"हमेशा दो-डैश उपशीर्षक चुनना क्योंकि वह अधिक विस्तृत है।","ar":"اختيار البند الفرعي ذي الشرطتين دائماً لأنه أكثر تفصيلاً."},{"en":"Compare all two-dash subheadings throughout the heading at once and pick the most specific.","es":"Comparar todas las subpartidas de dos guiones de la partida a la vez y elegir la más específica.","ru":"Сравнить сразу все субпозиции с двумя дефисами во всей товарной позиции и выбрать наиболее конкретную.","tr":"Pozisyon boyunca tüm iki tireli alt pozisyonları aynı anda karşılaştırmak ve en spesifik olanı seçmek.","hi":"पूरे शीर्षक में सभी दो-डैश उपशीर्षकों की एक साथ तुलना करना और सबसे विशिष्ट को चुनना।","ar":"مقارنة جميع البنود الفرعية ذات الشرطتين في كامل البند دفعة واحدة واختيار الأكثر تحديداً."}],"e":{"en":"GRI 6 requires comparison only of subheadings at the same level. You must first select the proper one-dash subheading, then descend to compare the two-dash subheadings that fall under it. Two-dash subheadings under a non-selected one-dash provision are not eligible for comparison.","es":"La GRI 6 exige comparar únicamente subpartidas del mismo nivel. Primero debe seleccionar la subpartida de un guion adecuada y luego descender para comparar las subpartidas de dos guiones que caen bajo ella. Las subpartidas de dos guiones bajo una disposición de un guion no seleccionada no son elegibles para la comparación.","ru":"GRI 6 требует сравнения только субпозиций одного уровня. Сначала необходимо выбрать надлежащую субпозицию с одним дефисом, а затем спуститься для сравнения субпозиций с двумя дефисами, относящихся к ней. Субпозиции с двумя дефисами под невыбранной субпозицией с одним дефисом не подлежат сравнению.","tr":"GRI 6 yalnızca aynı düzeydeki alt pozisyonların karşılaştırılmasını gerektirir. Önce uygun tek tireli alt pozisyonu seçmeli, sonra onun altına düşen iki tireli alt pozisyonları karşılaştırmak için aşağı inmelisiniz. Seçilmemiş bir tek tireli hüküm altındaki iki tireli alt pozisyonlar karşılaştırmaya uygun değildir.","hi":"GRI 6 केवल समान स्तर के उपशीर्षकों की तुलना की अपेक्षा करता है। आपको पहले उचित एक-डैश उपशीर्षक चुनना होगा, फिर उसके अंतर्गत आने वाले दो-डैश उपशीर्षकों की तुलना करने के लिए नीचे उतरना होगा। किसी अचयनित एक-डैश प्रावधान के अंतर्गत दो-डैश उपशीर्षक तुलना के लिए पात्र नहीं हैं।","ar":"يقتضي GRI 6 مقارنة البنود الفرعية التي تقع في المستوى نفسه فقط. يجب أولاً اختيار البند الفرعي المناسب ذي الشرطة الواحدة، ثم النزول لمقارنة البنود الفرعية ذات الشرطتين التي تقع تحته. أما البنود الفرعية ذات الشرطتين الواقعة تحت حكم غير مختار ذي شرطة واحدة فلا تكون مؤهلة للمقارنة."}},{"cat":"classification","a":3,"q":{"en":"An 'eo nomine' provision names a commodity directly (e.g., 'umbrellas'). As a general principle of classification, an eo nomine provision without limiting language includes which goods?","es":"Una disposición 'eo nomine' designa una mercancía directamente (p. ej., 'paraguas'). Como principio general de clasificación, ¿qué mercancías incluye una disposición eo nomine sin lenguaje limitativo?","ru":"Положение 'eo nomine' прямо называет товар (например, 'зонты'). В качестве общего принципа классификации, какие товары охватывает положение eo nomine без ограничивающих формулировок?","tr":"Bir 'eo nomine' hükmü bir ürünü doğrudan adlandırır (örneğin, 'şemsiyeler'). Genel bir sınıflandırma ilkesi olarak, sınırlayıcı ifade içermeyen bir eo nomine hükmü hangi eşyaları kapsar?","hi":"एक 'eo nomine' प्रावधान किसी वस्तु का सीधे नाम लेता है (जैसे, 'छाते')। वर्गीकरण के एक सामान्य सिद्धांत के रूप में, बिना सीमित करने वाली भाषा के एक eo nomine प्रावधान में कौन-सी वस्तुएं शामिल होती हैं?","ar":"يسمّي الحكم 'eo nomine' السلعة مباشرةً (مثلاً، 'المظلات'). كمبدأ عام في التصنيف، ما هي البضائع التي يشملها حكم eo nomine الخالي من أي صيغة تقييدية؟"},"o":[{"en":"Only the specific model of the commodity that existed when the provision was enacted.","es":"Únicamente el modelo específico de la mercancía que existía cuando se promulgó la disposición.","ru":"Только конкретную модель товара, существовавшую на момент принятия положения.","tr":"Yalnızca hüküm yürürlüğe girdiğinde mevcut olan ürünün belirli modeli.","hi":"केवल वस्तु का वह विशिष्ट मॉडल जो प्रावधान के अधिनियमित होने के समय मौजूद था।","ar":"فقط الطراز المحدّد من السلعة الذي كان موجوداً عند سنّ الحكم."},{"en":"Only goods that also satisfy a separate parts provision.","es":"Únicamente las mercancías que también cumplen una disposición separada de partes.","ru":"Только товары, которые также удовлетворяют отдельному положению о частях.","tr":"Yalnızca ayrı bir aksam hükmünü de karşılayan eşyalar.","hi":"केवल वे वस्तुएं जो एक अलग पुर्जा (parts) प्रावधान को भी पूरा करती हैं।","ar":"فقط البضائع التي تستوفي أيضاً حكماً مستقلاً خاصاً بالأجزاء."},{"en":"Only goods principally used for the named purpose, regardless of form.","es":"Únicamente las mercancías utilizadas principalmente para el fin designado, con independencia de su forma.","ru":"Только товары, преимущественно используемые для названной цели, независимо от формы.","tr":"Biçimine bakılmaksızın yalnızca adı geçen amaç için esas olarak kullanılan eşyalar.","hi":"रूप की परवाह किए बिना केवल वे वस्तुएं जो मुख्यतः नामित प्रयोजन के लिए उपयोग की जाती हैं।","ar":"فقط البضائع المستخدمة بصفة رئيسية للغرض المُسمّى، بصرف النظر عن شكلها."},{"en":"All forms of the named article, including improved or later-developed versions, unless a contrary legislative intent or limiting language appears.","es":"Todas las formas del artículo designado, incluidas las versiones mejoradas o desarrolladas posteriormente, salvo que aparezca una intención legislativa contraria o un lenguaje limitativo.","ru":"Все формы названного изделия, включая улучшенные или разработанные позднее версии, если не выражено противоположное намерение законодателя или ограничивающая формулировка.","tr":"Aksi yönde bir yasama iradesi veya sınırlayıcı bir ifade bulunmadıkça, geliştirilmiş veya sonradan ortaya çıkan sürümler dahil olmak üzere adı geçen eşyanın tüm biçimleri.","hi":"नामित वस्तु के सभी रूप, जिनमें सुधरे हुए या बाद में विकसित संस्करण शामिल हैं, जब तक कि कोई विपरीत विधायी मंशा या सीमित करने वाली भाषा प्रकट न हो।","ar":"جميع أشكال الصنف المُسمّى، بما في ذلك النسخ المحسّنة أو المطوّرة لاحقاً، ما لم تظهر نية تشريعية مخالفة أو صيغة تقييدية."}],"e":{"en":"Under established classification principles, an eo nomine designation, absent limitation or contrary intent, includes all forms of the named article — including improved versions and later technological variants. This contrasts with 'use' provisions (governed by Add'l U.S. Rule 1(a)), which turn on principal use rather than name.","es":"Conforme a los principios de clasificación establecidos, una designación eo nomine, en ausencia de limitación o intención contraria, incluye todas las formas del artículo designado, incluidas las versiones mejoradas y las variantes tecnológicas posteriores. Esto contrasta con las disposiciones de 'uso' (regidas por la Additional U.S. Rule of Interpretation 1(a)), que dependen del uso principal y no del nombre.","ru":"Согласно устоявшимся принципам классификации, обозначение eo nomine при отсутствии ограничения или противоположного намерения охватывает все формы названного изделия, включая улучшенные версии и более поздние технологические варианты. Это отличается от положений 'по использованию' (регулируемых Additional U.S. Rule of Interpretation 1(a)), которые зависят от основного использования, а не от наименования.","tr":"Yerleşik sınıflandırma ilkeleri uyarınca, bir sınırlama veya aksi yönde bir irade bulunmadığında, eo nomine bir tanımlama, geliştirilmiş sürümler ve sonraki teknolojik türevler dahil olmak üzere adı geçen eşyanın tüm biçimlerini kapsar. Bu, addan ziyade esas kullanıma dayanan 'kullanım' hükümlerinden (Additional U.S. Rule of Interpretation 1(a) tarafından yönetilen) farklıdır.","hi":"स्थापित वर्गीकरण सिद्धांतों के अनुसार, किसी सीमा या विपरीत मंशा के अभाव में, एक eo nomine पदनाम में नामित वस्तु के सभी रूप शामिल होते हैं — जिनमें सुधरे हुए संस्करण और बाद के तकनीकी प्रकार भी शामिल हैं। यह 'उपयोग' प्रावधानों (Additional U.S. Rule of Interpretation 1(a) द्वारा शासित) से भिन्न है, जो नाम के बजाय मुख्य उपयोग पर आधारित होते हैं।","ar":"بموجب مبادئ التصنيف الراسخة، فإن التسمية eo nomine، في غياب أي تقييد أو نية مخالفة، تشمل جميع أشكال الصنف المُسمّى — بما في ذلك النسخ المحسّنة والأنواع التقنية اللاحقة. ويتباين هذا مع أحكام 'الاستخدام' (التي تحكمها Additional U.S. Rule of Interpretation 1(a))، والتي تتوقف على الاستخدام الرئيسي وليس على الاسم."}},{"cat":"classification","a":0,"q":{"en":"A retail set for sale to consumers comprises a hairbrush (heading 9603) and a hand mirror (heading 7009), packed together in a printed sleeve, with neither article clearly predominating in role or value. Applying the GRI 3 sequence, what is the result?","es":"Un surtido para la venta al por menor a consumidores comprende un cepillo para el cabello (partida 9603) y un espejo de mano (partida 7009), empacados juntos en una funda impresa, sin que ninguno de los dos artículos predomine claramente en función o valor. Aplicando la secuencia de la GRI 3, ¿cuál es el resultado?","ru":"Набор для розничной продажи потребителям состоит из щётки для волос (товарная позиция 9603) и ручного зеркала (товарная позиция 7009), упакованных вместе в печатный чехол, причём ни одно из изделий явно не преобладает по роли или стоимости. Применяя последовательность GRI 3, каков результат?","tr":"Tüketicilere perakende satış için bir takım, bir saç fırçası (pozisyon 9603) ve bir el aynasından (pozisyon 7009) oluşur; baskılı bir kılıf içinde birlikte ambalajlanmıştır ve iki eşyadan hiçbiri rol veya değer bakımından açıkça baskın değildir. GRI 3 sırası uygulandığında sonuç nedir?","hi":"उपभोक्ताओं को खुदरा बिक्री के लिए एक सेट में एक हेयरब्रश (शीर्षक 9603) और एक हाथ का दर्पण (शीर्षक 7009) शामिल हैं, जो एक मुद्रित स्लीव में एक साथ पैक किए गए हैं, और दोनों में से कोई भी वस्तु भूमिका या मूल्य में स्पष्ट रूप से प्रमुख नहीं है। GRI 3 अनुक्रम लागू करने पर परिणाम क्या होगा?","ar":"تتكوّن مجموعة للبيع بالتجزئة للمستهلكين من فرشاة شعر (البند 9603) ومرآة يدوية (البند 7009)، معبّأتين معاً في غلاف مطبوع، دون أن يكون لأي من الصنفين غلبة واضحة في الدور أو القيمة. بتطبيق تسلسل GRI 3، ما هي النتيجة؟"},"o":[{"en":"GRI 3(b) fails for want of essential character, so under GRI 3(c) the set is classified in heading 9603, the heading occurring last in numerical order.","es":"La GRI 3(b) falla por falta de carácter esencial, por lo que, conforme a la GRI 3(c), el surtido se clasifica en la partida 9603, la partida que figura en último lugar en orden numérico.","ru":"GRI 3(b) неприменимо из-за отсутствия основного свойства, поэтому согласно GRI 3(c) набор классифицируется в товарной позиции 9603 — позиции, последней в числовом порядке.","tr":"GRI 3(b), esas karakter bulunmaması nedeniyle başarısız olur; bu nedenle GRI 3(c) uyarınca takım, sayısal sırada son gelen pozisyon olan 9603 pozisyonunda sınıflandırılır.","hi":"आवश्यक लक्षण के अभाव में GRI 3(b) विफल हो जाता है, इसलिए GRI 3(c) के अंतर्गत सेट को शीर्षक 9603 में वर्गीकृत किया जाता है, जो संख्यात्मक क्रम में अंतिम आने वाला शीर्षक है।","ar":"يفشل GRI 3(b) لانعدام الطابع الأساسي، لذا تُصنَّف المجموعة بموجب GRI 3(c) في البند 9603، وهو البند الأخير في الترتيب الرقمي."},{"en":"Each article is separately classified because a two-article retail set cannot be classified as a unit.","es":"Cada artículo se clasifica por separado porque un surtido para la venta al por menor de dos artículos no puede clasificarse como una unidad.","ru":"Каждое изделие классифицируется отдельно, поскольку розничный набор из двух изделий не может классифицироваться как единое целое.","tr":"İki eşyalı bir perakende takım bir bütün olarak sınıflandırılamayacağından her eşya ayrı ayrı sınıflandırılır.","hi":"प्रत्येक वस्तु को अलग-अलग वर्गीकृत किया जाता है क्योंकि दो-वस्तु वाले खुदरा सेट को एक इकाई के रूप में वर्गीकृत नहीं किया जा सकता।","ar":"يُصنَّف كل صنف على حدة لأن مجموعة التجزئة المكوّنة من صنفين لا يمكن تصنيفها كوحدة واحدة."},{"en":"GRI 3(a) resolves it in favor of heading 7009 as the more specific provision.","es":"La GRI 3(a) lo resuelve a favor de la partida 7009 por ser la disposición más específica.","ru":"GRI 3(a) разрешает это в пользу товарной позиции 7009 как более конкретного положения.","tr":"GRI 3(a), daha spesifik hüküm olarak 7009 pozisyonu lehine çözer.","hi":"GRI 3(a) इसे अधिक विशिष्ट प्रावधान के रूप में शीर्षक 7009 के पक्ष में हल करता है।","ar":"يحسمه GRI 3(a) لصالح البند 7009 باعتباره الحكم الأكثر تحديداً."},{"en":"Under GRI 3(c), the set is classified in heading 7009, the heading occurring first in numerical order.","es":"Conforme a la GRI 3(c), el surtido se clasifica en la partida 7009, la partida que figura en primer lugar en orden numérico.","ru":"Согласно GRI 3(c), набор классифицируется в товарной позиции 7009 — позиции, первой в числовом порядке.","tr":"GRI 3(c) uyarınca takım, sayısal sırada ilk gelen pozisyon olan 7009 pozisyonunda sınıflandırılır.","hi":"GRI 3(c) के अंतर्गत, सेट को शीर्षक 7009 में वर्गीकृत किया जाता है, जो संख्यात्मक क्रम में पहला आने वाला शीर्षक है।","ar":"بموجب GRI 3(c)، تُصنَّف المجموعة في البند 7009، وهو البند الأول في الترتيب الرقمي."}],"e":{"en":"It is a retail set (GRI 3(b)). With no essential character, GRI 3(c) controls: the heading occurring last in numerical order governs. Between 7009 and 9603, heading 9603 is last in numerical order, so the set is classified there. GRI 3(c) selects the LAST heading (not the first), and a retail set is classified as a unit, not separately.","es":"Se trata de un surtido para la venta al por menor (GRI 3(b)). Al no existir carácter esencial, rige la GRI 3(c): prevalece la partida que figura en último lugar en orden numérico. Entre 7009 y 9603, la partida 9603 es la última en orden numérico, por lo que el surtido se clasifica allí. La GRI 3(c) selecciona la ÚLTIMA partida (no la primera), y un surtido para la venta al por menor se clasifica como una unidad, no por separado.","ru":"Это розничный набор (GRI 3(b)). При отсутствии основного свойства действует GRI 3(c): применяется товарная позиция, последняя в числовом порядке. Между 7009 и 9603 товарная позиция 9603 является последней в числовом порядке, поэтому набор классифицируется в ней. GRI 3(c) выбирает ПОСЛЕДНЮЮ позицию (а не первую), а розничный набор классифицируется как единое целое, а не отдельно.","tr":"Bu bir perakende takımdır (GRI 3(b)). Esas karakter bulunmadığından GRI 3(c) geçerlidir: sayısal sırada son gelen pozisyon hükmeder. 7009 ile 9603 arasında, sayısal sırada son gelen 9603 pozisyonudur; bu nedenle takım orada sınıflandırılır. GRI 3(c), İLK değil SON pozisyonu seçer ve bir perakende takım ayrı ayrı değil, bir bütün olarak sınıflandırılır.","hi":"यह एक खुदरा सेट है (GRI 3(b))। आवश्यक लक्षण न होने पर GRI 3(c) नियंत्रित करता है: संख्यात्मक क्रम में अंतिम आने वाला शीर्षक लागू होता है। 7009 और 9603 के बीच, शीर्षक 9603 संख्यात्मक क्रम में अंतिम है, इसलिए सेट को वहीं वर्गीकृत किया जाता है। GRI 3(c) अंतिम (LAST) शीर्षक चुनता है (पहला नहीं), और एक खुदरा सेट को एक इकाई के रूप में वर्गीकृत किया जाता है, अलग-अलग नहीं।","ar":"إنها مجموعة بيع بالتجزئة (GRI 3(b)). ولانعدام الطابع الأساسي، يحكمها GRI 3(c): يسود البند الأخير في الترتيب الرقمي. وبين 7009 و9603، يكون البند 9603 هو الأخير في الترتيب الرقمي، لذا تُصنَّف المجموعة فيه. ويختار GRI 3(c) البند الأخير (لا الأول)، وتُصنَّف مجموعة البيع بالتجزئة كوحدة واحدة لا على حدة."}},{"cat":"classification","a":3,"q":{"en":"GRI 2(b) addresses references in a heading to a 'material or substance.' What does GRI 2(b) extend such a reference to include?","es":"La GRI 2(b) trata de las referencias en una partida a una 'materia o sustancia'. ¿Qué hace la GRI 2(b) que dicha referencia incluya?","ru":"GRI 2(b) касается ссылок в товарной позиции на 'материал или вещество'. На что GRI 2(b) распространяет такую ссылку?","tr":"GRI 2(b), bir pozisyonda 'malzeme veya maddeye' yapılan atıfları ele alır. GRI 2(b), böyle bir atfı neleri kapsayacak şekilde genişletir?","hi":"GRI 2(b) किसी शीर्षक में 'किसी सामग्री या पदार्थ' के संदर्भों को संबोधित करता है। GRI 2(b) ऐसे संदर्भ को क्या शामिल करने के लिए विस्तारित करता है?","ar":"يتناول GRI 2(b) الإشارات الواردة في بند ما إلى 'مادة أو خامة'. إلى ماذا يوسّع GRI 2(b) هذه الإشارة لتشمله؟"},"o":[{"en":"Only the pure material in unmixed form.","es":"Únicamente la materia pura en forma no mezclada.","ru":"Только чистый материал в несмешанном виде.","tr":"Yalnızca karıştırılmamış halde saf malzeme.","hi":"केवल बिना मिश्रित रूप में शुद्ध सामग्री।","ar":"فقط المادة النقية في صورتها غير المخلوطة."},{"en":"Any finished article whatsoever, regardless of composition.","es":"Cualquier artículo terminado, sin importar su composición.","ru":"Любое готовое изделие, независимо от состава.","tr":"Bileşimine bakılmaksızın herhangi bir bitmiş eşya.","hi":"संरचना की परवाह किए बिना कोई भी तैयार वस्तु।","ar":"أي صنف تام الصنع كان، بصرف النظر عن تركيبه."},{"en":"Only goods of the same material imported in the same shipment.","es":"Únicamente las mercancías de la misma materia importadas en el mismo envío.","ru":"Только товары из того же материала, ввезённые в той же партии.","tr":"Yalnızca aynı sevkiyatta ithal edilen aynı malzemeden eşyalar.","hi":"केवल उसी खेप में आयातित उसी सामग्री की वस्तुएं।","ar":"فقط البضائع المصنوعة من المادة نفسها والمستوردة في الشحنة نفسها."},{"en":"Mixtures or combinations of that material or substance with other materials or substances, and goods consisting wholly or partly of that material — with classification of multi-material goods then governed by GRI 3.","es":"Las mezclas o combinaciones de esa materia o sustancia con otras materias o sustancias, y las mercancías constituidas total o parcialmente por esa materia, rigiéndose entonces la clasificación de las mercancías de varias materias por la GRI 3.","ru":"Смеси или сочетания этого материала или вещества с другими материалами или веществами, а также товары, состоящие полностью или частично из этого материала, при этом классификация товаров из нескольких материалов далее регулируется GRI 3.","tr":"O malzeme veya maddenin diğer malzeme veya maddelerle karışım ya da bileşimlerini ve tamamen veya kısmen o malzemeden oluşan eşyaları — çok malzemeli eşyaların sınıflandırılması ise GRI 3 tarafından yönetilir.","hi":"उस सामग्री या पदार्थ के अन्य सामग्रियों या पदार्थों के साथ मिश्रण या संयोजन, और पूर्णतः या आंशिक रूप से उस सामग्री से बनी वस्तुएं — और तब बहु-सामग्री वस्तुओं का वर्गीकरण GRI 3 द्वारा शासित होता है।","ar":"خلائط أو تركيبات تلك المادة أو الخامة مع مواد أو خامات أخرى، والبضائع المكوّنة كلياً أو جزئياً من تلك المادة — على أن يحكم GRI 3 عندئذٍ تصنيف البضائع متعددة المواد."}],"e":{"en":"GRI 2(b) provides that a reference to a material/substance includes mixtures or combinations of it with other materials, and a reference to goods of a given material includes goods consisting wholly or partly of that material. It then directs that goods of more than one material be classified per GRI 3.","es":"La GRI 2(b) dispone que una referencia a una materia o sustancia incluye sus mezclas o combinaciones con otras materias, y que una referencia a mercancías de una materia determinada incluye las mercancías constituidas total o parcialmente por esa materia. Luego ordena que las mercancías compuestas por más de una materia se clasifiquen conforme a la GRI 3.","ru":"GRI 2(b) предусматривает, что ссылка на материал или вещество включает его смеси или сочетания с другими материалами, а ссылка на товары из определённого материала включает товары, состоящие полностью или частично из этого материала. Затем оно предписывает, что товары более чем из одного материала классифицируются согласно GRI 3.","tr":"GRI 2(b), bir malzemeye/maddeye yapılan atfın onun diğer malzemelerle karışım veya bileşimlerini içerdiğini ve belirli bir malzemeden eşyalara yapılan atfın tamamen veya kısmen o malzemeden oluşan eşyaları içerdiğini öngörür. Ardından, birden fazla malzemeden oluşan eşyaların GRI 3 uyarınca sınıflandırılmasını yönlendirir.","hi":"GRI 2(b) यह प्रावधान करता है कि किसी सामग्री/पदार्थ का संदर्भ अन्य सामग्रियों के साथ उसके मिश्रणों या संयोजनों को शामिल करता है, और किसी दी गई सामग्री की वस्तुओं का संदर्भ पूर्णतः या आंशिक रूप से उस सामग्री से बनी वस्तुओं को शामिल करता है। फिर यह निर्देशित करता है कि एक से अधिक सामग्री की वस्तुओं को GRI 3 के अनुसार वर्गीकृत किया जाए।","ar":"ينص GRI 2(b) على أن الإشارة إلى مادة/خامة تشمل خلائطها أو تركيباتها مع مواد أخرى، وأن الإشارة إلى بضائع من مادة معينة تشمل البضائع المكوّنة كلياً أو جزئياً من تلك المادة. ثم يوجّه بأن تُصنَّف البضائع المكوّنة من أكثر من مادة وفقاً لـ GRI 3."}},{"cat":"classification","a":2,"q":{"en":"An importer classifies goods entirely by GRI 1 because the heading text and chapter notes fully describe the product, making GRIs 2-6 unnecessary at the heading level. Which statement reflects the proper hierarchy?","es":"Un importador clasifica las mercancías íntegramente por la GRI 1 porque el texto de la partida y las notas de capítulo describen plenamente el producto, lo que hace innecesarias las GRI 2 a 6 a nivel de partida. ¿Qué afirmación refleja la jerarquía correcta?","ru":"Импортёр классифицирует товары полностью по GRI 1, поскольку текст товарной позиции и примечания к группе полностью описывают продукт, что делает GRI 2-6 ненужными на уровне товарной позиции. Какое утверждение отражает правильную иерархию?","tr":"Bir ithalatçı, pozisyon metni ve fasıl notları ürünü tam olarak tanımladığından ve bu da pozisyon düzeyinde GRI 2-6'yı gereksiz kıldığından, eşyaları tamamen GRI 1 ile sınıflandırır. Hangi ifade doğru hiyerarşiyi yansıtır?","hi":"एक आयातक वस्तुओं को पूरी तरह GRI 1 द्वारा वर्गीकृत करता है क्योंकि शीर्षक का पाठ और अध्याय नोट उत्पाद का पूर्ण वर्णन करते हैं, जिससे शीर्षक स्तर पर GRI 2-6 अनावश्यक हो जाते हैं। कौन-सा कथन सही पदानुक्रम को दर्शाता है?","ar":"يصنّف مستورد البضائع بالكامل بموجب GRI 1 لأن نص البند وملاحظات الفصل يصفان المنتج وصفاً كاملاً، مما يجعل GRI 2-6 غير ضرورية على مستوى البند. أي عبارة تعكس التسلسل الهرمي الصحيح؟"},"o":[{"en":"GRI 3 must always be checked before relying on GRI 1.","es":"Siempre debe comprobarse la GRI 3 antes de basarse en la GRI 1.","ru":"GRI 3 всегда необходимо проверять перед тем, как опираться на GRI 1.","tr":"GRI 1'e dayanmadan önce her zaman GRI 3 kontrol edilmelidir.","hi":"GRI 1 पर निर्भर रहने से पहले हमेशा GRI 3 की जांच की जानी चाहिए।","ar":"يجب دائماً التحقق من GRI 3 قبل الاعتماد على GRI 1."},{"en":"GRIs must always be applied in full from 1 through 5 for every entry.","es":"Las GRI deben aplicarse siempre en su totalidad, de la 1 a la 5, para cada entrada.","ru":"GRI всегда должны применяться в полном объёме с 1 по 5 для каждой ввозимой партии.","tr":"GRI'ler her giriş için her zaman 1'den 5'e kadar tam olarak uygulanmalıdır.","hi":"प्रत्येक प्रविष्टि के लिए GRI को हमेशा 1 से 5 तक पूर्ण रूप से लागू किया जाना चाहिए।","ar":"يجب دائماً تطبيق GRIs بالكامل من 1 إلى 5 لكل بيان جمركي."},{"en":"The GRIs are applied in order, and if GRI 1 alone determines the heading, you do not resort to GRIs 2-4; the later rules apply only when needed.","es":"Las GRI se aplican en orden, y si la GRI 1 por sí sola determina la partida, no se recurre a las GRI 2 a 4; las reglas posteriores se aplican únicamente cuando es necesario.","ru":"GRI применяются по порядку, и если одно лишь GRI 1 определяет товарную позицию, то к GRI 2-4 не прибегают; последующие правила применяются только при необходимости.","tr":"GRI'ler sırayla uygulanır ve pozisyonu tek başına GRI 1 belirliyorsa GRI 2-4'e başvurulmaz; sonraki kurallar yalnızca gerektiğinde uygulanır.","hi":"GRI को क्रम में लागू किया जाता है, और यदि अकेला GRI 1 शीर्षक निर्धारित कर देता है, तो आप GRI 2-4 का सहारा नहीं लेते; बाद के नियम केवल आवश्यकता पड़ने पर लागू होते हैं।","ar":"تُطبَّق GRIs بالترتيب، وإذا حدّد GRI 1 وحده البند، فلا تلجأ إلى GRI 2-4؛ ولا تُطبَّق القواعد اللاحقة إلا عند الحاجة."},{"en":"GRI 6 must be applied before GRI 1 to fix the subheading.","es":"La GRI 6 debe aplicarse antes que la GRI 1 para fijar la subpartida.","ru":"GRI 6 необходимо применять до GRI 1 для определения субпозиции.","tr":"Alt pozisyonu belirlemek için GRI 6, GRI 1'den önce uygulanmalıdır.","hi":"उपशीर्षक निर्धारित करने के लिए GRI 6 को GRI 1 से पहले लागू किया जाना चाहिए।","ar":"يجب تطبيق GRI 6 قبل GRI 1 لتحديد البند الفرعي."}],"e":{"en":"The GRIs operate in strict sequential order. GRI 1 is applied first; only if the headings and notes do not settle the classification do you proceed to GRI 2, then 3, then 4. GRI 5 concerns containers/packing and GRI 6 governs subheadings (after the heading is set). You never skip ahead unnecessarily.","es":"Las GRI operan en un orden secuencial estricto. La GRI 1 se aplica primero; solo si las partidas y las notas no resuelven la clasificación se procede a la GRI 2, luego a la 3 y luego a la 4. La GRI 5 se refiere a los envases y embalajes, y la GRI 6 rige las subpartidas (después de fijada la partida). Nunca se salta adelante innecesariamente.","ru":"GRI действуют в строгом последовательном порядке. Сначала применяется GRI 1; только если товарные позиции и примечания не позволяют определить классификацию, переходят к GRI 2, затем к 3, затем к 4. GRI 5 касается контейнеров/упаковки, а GRI 6 регулирует субпозиции (после определения товарной позиции). Никогда не следует забегать вперёд без необходимости.","tr":"GRI'ler kesin bir sıralı düzende işler. Önce GRI 1 uygulanır; yalnızca pozisyonlar ve notlar sınıflandırmayı çözmezse GRI 2'ye, sonra 3'e, sonra 4'e geçilir. GRI 5 kaplar/ambalajlarla ilgilenir ve GRI 6 alt pozisyonları yönetir (pozisyon belirlendikten sonra). Asla gereksiz yere ileriye atlanmaz.","hi":"GRI सख्त क्रमिक क्रम में काम करते हैं। पहले GRI 1 लागू किया जाता है; केवल यदि शीर्षक और नोट वर्गीकरण को तय नहीं करते, तो आप GRI 2, फिर 3, फिर 4 की ओर बढ़ते हैं। GRI 5 कंटेनरों/पैकिंग से संबंधित है और GRI 6 उपशीर्षकों को शासित करता है (शीर्षक तय होने के बाद)। आप कभी भी अनावश्यक रूप से आगे नहीं कूदते।","ar":"تعمل GRIs بترتيب تسلسلي صارم. يُطبَّق GRI 1 أولاً؛ ولا تنتقل إلى GRI 2 ثم 3 ثم 4 إلا إذا لم تحسم البنود والملاحظات التصنيف. ويتعلق GRI 5 بالأوعية/التغليف، ويحكم GRI 6 البنود الفرعية (بعد تحديد البند). ولا تتخطّى أبداً إلى ما هو أبعد دون ضرورة."}},{"cat":"classification","a":1,"q":{"en":"After exhausting GRIs 1 through 3, an article still cannot be classified (no heading describes it and it is not a set, mixture, or composite resolvable under GRI 3). What does GRI 4 direct?","es":"Tras agotar las GRI 1 a 3, un artículo aún no puede clasificarse (ninguna partida lo describe y no es un surtido, mezcla ni artículo compuesto resoluble conforme a la GRI 3). ¿Qué ordena la GRI 4?","ru":"После исчерпания GRI 1-3 изделие всё ещё не может быть классифицировано (ни одна товарная позиция его не описывает, и оно не является набором, смесью или составным товаром, разрешимым по GRI 3). Что предписывает GRI 4?","tr":"GRI 1 ila 3 tüketildikten sonra bir eşya hâlâ sınıflandırılamıyorsa (hiçbir pozisyon onu tanımlamıyor ve GRI 3 ile çözülebilecek bir takım, karışım veya bileşik değil), GRI 4 neyi yönlendirir?","hi":"GRI 1 से 3 तक समाप्त करने के बाद भी कोई वस्तु वर्गीकृत नहीं हो पाती (कोई शीर्षक इसका वर्णन नहीं करता और यह GRI 3 के अंतर्गत हल किए जा सकने वाला सेट, मिश्रण या संयुक्त वस्तु नहीं है)। GRI 4 क्या निर्देशित करता है?","ar":"بعد استنفاد GRI 1 إلى 3، لا يزال يتعذّر تصنيف صنف ما (لا يصفه أي بند، وليس مجموعة أو خليطاً أو صنفاً مركباً يمكن حلّه بموجب GRI 3). فماذا يوجّه GRI 4؟"},"o":[{"en":"Defer classification pending a binding ruling from CBP.","es":"Aplazar la clasificación a la espera de una resolución vinculante de CBP.","ru":"Отложить классификацию до получения обязывающего решения от CBP.","tr":"CBP'den bağlayıcı bir karar gelene kadar sınıflandırmayı ertelemek.","hi":"CBP से एक बाध्यकारी रूलिंग की प्रतीक्षा में वर्गीकरण को स्थगित करना।","ar":"تأجيل التصنيف لحين صدور قرار مُلزم من CBP."},{"en":"Classify the goods under the heading appropriate to the goods to which they are most akin (most similar).","es":"Clasificar las mercancías en la partida correspondiente a las mercancías con las que tengan mayor analogía (mayor similitud).","ru":"Классифицировать товары в товарной позиции, соответствующей товарам, которым они наиболее сродни (наиболее схожи).","tr":"Eşyaları, en çok benzedikleri (en yakın oldukları) eşyalara uygun pozisyonda sınıflandırmak.","hi":"वस्तुओं को उन वस्तुओं के लिए उपयुक्त शीर्षक के अंतर्गत वर्गीकृत करना जिनसे वे सर्वाधिक मिलती-जुलती (सबसे समान) हैं।","ar":"تصنيف البضائع في البند المناسب للبضائع التي تكون أكثر شبهاً (أكثر تماثلاً) بها."},{"en":"Classify the goods under the basket 'other' provision of chapter 99.","es":"Clasificar las mercancías en la disposición residual 'los demás' del chapter 99.","ru":"Классифицировать товары в остаточном положении 'прочие' chapter 99.","tr":"Eşyaları chapter 99'un 'diğerleri' adlı sepet hükmünde sınıflandırmak.","hi":"वस्तुओं को chapter 99 के 'अन्य' (other) बास्केट प्रावधान के अंतर्गत वर्गीकृत करना।","ar":"تصنيف البضائع في الحكم الجامع 'غير ذلك' (other) من chapter 99."},{"en":"Classify the goods under the heading carrying the lowest rate of duty.","es":"Clasificar las mercancías en la partida que tenga el tipo de derecho más bajo.","ru":"Классифицировать товары в товарной позиции с наименьшей ставкой пошлины.","tr":"Eşyaları en düşük gümrük vergisi oranına sahip pozisyonda sınıflandırmak.","hi":"वस्तुओं को सबसे कम शुल्क दर वाले शीर्षक के अंतर्गत वर्गीकृत करना।","ar":"تصنيف البضائع في البند ذي معدل الرسوم الأدنى."}],"e":{"en":"GRI 4 is the rule of last resort before GRI 5/6 considerations: goods that cannot be classified under GRIs 1-3 are classified under the heading appropriate to the goods to which they are most akin. Akin-ness can be judged by description, character, purpose, etc. It is rarely reached in practice.","es":"La GRI 4 es la regla de último recurso antes de las consideraciones de las GRI 5/6: las mercancías que no pueden clasificarse conforme a las GRI 1 a 3 se clasifican en la partida correspondiente a las mercancías con las que tengan mayor analogía. La analogía puede apreciarse por la descripción, el carácter, la finalidad, etc. En la práctica rara vez se llega a ella.","ru":"GRI 4 — это правило последней инстанции перед рассмотрением GRI 5/6: товары, которые не могут быть классифицированы по GRI 1-3, классифицируются в товарной позиции, соответствующей товарам, которым они наиболее сродни. Сходство может оцениваться по описанию, свойствам, назначению и т. д. На практике до него доходят редко.","tr":"GRI 4, GRI 5/6 değerlendirmelerinden önceki son çare kuralıdır: GRI 1-3'e göre sınıflandırılamayan eşyalar, en çok benzedikleri eşyalara uygun pozisyonda sınıflandırılır. Benzerlik; tanım, karakter, amaç vb. ile değerlendirilebilir. Uygulamada nadiren bu noktaya ulaşılır.","hi":"GRI 4, GRI 5/6 के विचारों से पहले अंतिम उपाय का नियम है: जिन वस्तुओं को GRI 1-3 के अंतर्गत वर्गीकृत नहीं किया जा सकता, उन्हें उन वस्तुओं के लिए उपयुक्त शीर्षक के अंतर्गत वर्गीकृत किया जाता है जिनसे वे सर्वाधिक मिलती-जुलती हैं। समानता को विवरण, लक्षण, प्रयोजन आदि से आंका जा सकता है। व्यवहार में इस तक शायद ही कभी पहुंचा जाता है।","ar":"يُعدّ GRI 4 قاعدة الملاذ الأخير قبل اعتبارات GRI 5/6: فالبضائع التي لا يمكن تصنيفها بموجب GRI 1-3 تُصنَّف في البند المناسب للبضائع التي تكون أكثر شبهاً بها. ويمكن تقدير الشبه من خلال الوصف والطابع والغرض وما إلى ذلك. ونادراً ما يُصار إليه في الممارسة العملية."}},{"cat":"classification","a":3,"q":{"en":"A laptop computer is imported together with its specially fitted carrying sleeve. The sleeve is shaped for the laptop, suitable for long-term use, of a kind normally sold with such computers, and presented with it, and it does not give the whole its essential character. Under GRI 5(a), how is the sleeve classified?","es":"Una computadora portátil se importa junto con su funda de transporte especialmente ajustada. La funda está conformada para la computadora portátil, es apta para uso prolongado, es del tipo que normalmente se vende con tales computadoras y se presenta con ella, y no confiere al conjunto su carácter esencial. Conforme a la GRI 5(a), ¿cómo se clasifica la funda?","ru":"Портативный компьютер ввозится вместе со специально подогнанным чехлом для переноски. Чехол имеет форму для портативного компьютера, пригоден для длительного использования, относится к виду, обычно продаваемому с такими компьютерами, представлен вместе с ним и не придаёт всему изделию его основного свойства. Согласно GRI 5(a), как классифицируется чехол?","tr":"Bir dizüstü bilgisayar, özel olarak biçimlendirilmiş taşıma kılıfıyla birlikte ithal edilir. Kılıf, dizüstü bilgisayar için biçimlendirilmiştir, uzun süreli kullanıma uygundur, bu tür bilgisayarlarla normalde satılan türdendir, onunla birlikte sunulmaktadır ve bütüne esas karakterini vermez. GRI 5(a) uyarınca kılıf nasıl sınıflandırılır?","hi":"एक लैपटॉप कंप्यूटर अपने विशेष रूप से फिट किए गए कैरींग स्लीव के साथ आयात किया जाता है। स्लीव लैपटॉप के अनुरूप आकार का है, दीर्घकालिक उपयोग के लिए उपयुक्त है, ऐसे कंप्यूटरों के साथ सामान्यतः बेचे जाने वाले प्रकार का है, और इसके साथ प्रस्तुत किया गया है, तथा यह पूरे को इसका आवश्यक लक्षण प्रदान नहीं करता। GRI 5(a) के अंतर्गत स्लीव को कैसे वर्गीकृत किया जाता है?","ar":"يُستورد حاسوب محمول مع غلاف الحمل المصمَّم خصيصاً له. والغلاف مُشكَّل ليناسب الحاسوب المحمول، وصالح للاستعمال الطويل الأمد، ومن النوع الذي يُباع عادةً مع مثل هذه الحواسيب، ويُقدَّم معه، ولا يُكسب المجموع طابعه الأساسي. بموجب GRI 5(a)، كيف يُصنَّف الغلاف؟"},"o":[{"en":"With the laptop only if the sleeve's value is lower than the laptop's.","es":"Con la computadora portátil únicamente si el valor de la funda es inferior al de la computadora portátil.","ru":"Вместе с портативным компьютером только если стоимость чехла ниже стоимости компьютера.","tr":"Yalnızca kılıfın değeri dizüstü bilgisayarınkinden düşükse dizüstü bilgisayarla birlikte.","hi":"लैपटॉप के साथ केवल तभी यदि स्लीव का मूल्य लैपटॉप के मूल्य से कम हो।","ar":"مع الحاسوب المحمول فقط إذا كانت قيمة الغلاف أقل من قيمة الحاسوب المحمول."},{"en":"Separately, in the heading for textile/plastic cases, because cases are always separately dutiable.","es":"Por separado, en la partida correspondiente a los estuches de materia textil o de plástico, porque los estuches siempre tributan por separado.","ru":"Отдельно, в товарной позиции для текстильных/пластиковых футляров, поскольку футляры всегда облагаются пошлиной отдельно.","tr":"Ayrı olarak, dokuma/plastik kutu pozisyonunda, çünkü kutular her zaman ayrı olarak gümrüğe tabidir.","hi":"अलग से, टेक्सटाइल/प्लास्टिक केसों के शीर्षक में, क्योंकि केसों पर हमेशा अलग से शुल्क लगता है।","ar":"على حدة، في بند الحافظات النسيجية/البلاستيكية، لأن الحافظات تخضع للرسوم دائماً على حدة."},{"en":"Under GRI 3(c) as the heading last in numerical order between the laptop and the sleeve.","es":"Conforme a la GRI 3(c), como la partida que figura en último lugar en orden numérico entre la computadora portátil y la funda.","ru":"Согласно GRI 3(c) — в товарной позиции, последней в числовом порядке между портативным компьютером и чехлом.","tr":"GRI 3(c) uyarınca, dizüstü bilgisayar ile kılıf arasında sayısal sırada son gelen pozisyon olarak.","hi":"GRI 3(c) के अंतर्गत, लैपटॉप और स्लीव के बीच संख्यात्मक क्रम में अंतिम आने वाले शीर्षक के रूप में।","ar":"بموجب GRI 3(c)، باعتباره البند الأخير في الترتيب الرقمي بين الحاسوب المحمول والغلاف."},{"en":"With the laptop, taking the laptop's classification.","es":"Con la computadora portátil, adoptando la clasificación de la computadora portátil.","ru":"Вместе с портативным компьютером, принимая классификацию компьютера.","tr":"Dizüstü bilgisayarla birlikte, dizüstü bilgisayarın sınıflandırmasını alarak.","hi":"लैपटॉप के साथ, लैपटॉप का वर्गीकरण अपनाते हुए।","ar":"مع الحاسوب المحمول، آخذاً تصنيف الحاسوب المحمول."}],"e":{"en":"All GRI 5(a) conditions are met (specially fitted, long-term use, presented with, normally sold with, not imparting essential character), so the fitted case is classified with the article it contains — i.e., as the laptop. Relative value is not a GRI 5(a) condition.","es":"Se cumplen todas las condiciones de la GRI 5(a) (especialmente ajustada, uso prolongado, presentada con, normalmente vendida con, sin conferir el carácter esencial), de modo que el estuche ajustado se clasifica con el artículo que contiene, es decir, como la computadora portátil. El valor relativo no es una condición de la GRI 5(a).","ru":"Все условия GRI 5(a) соблюдены (специально подогнан, длительное использование, представлен вместе, обычно продаётся вместе, не придаёт основного свойства), поэтому подогнанный футляр классифицируется вместе с изделием, которое он содержит, то есть как портативный компьютер. Относительная стоимость не является условием GRI 5(a).","tr":"Tüm GRI 5(a) koşulları sağlanmıştır (özel olarak biçimlendirilmiş, uzun süreli kullanım, birlikte sunulan, normalde birlikte satılan, esas karakter vermeyen); bu nedenle biçimlendirilmiş kutu, içerdiği eşyayla birlikte, yani dizüstü bilgisayar olarak sınıflandırılır. Göreli değer, bir GRI 5(a) koşulu değildir.","hi":"GRI 5(a) की सभी शर्तें पूरी होती हैं (विशेष रूप से फिट, दीर्घकालिक उपयोग, साथ प्रस्तुत, सामान्यतः साथ बेचा गया, आवश्यक लक्षण प्रदान न करने वाला), इसलिए फिट किए गए केस को उस वस्तु के साथ वर्गीकृत किया जाता है जिसे वह रखता है — अर्थात लैपटॉप के रूप में। सापेक्ष मूल्य GRI 5(a) की कोई शर्त नहीं है।","ar":"تتحقق جميع شروط GRI 5(a) (مصمَّم خصيصاً، استعمال طويل الأمد، مُقدَّم معه، يُباع عادةً معه، لا يُكسب الطابع الأساسي)، لذا تُصنَّف الحافظة المصممة مع الصنف الذي تحتويه — أي بوصفها الحاسوب المحمول. والقيمة النسبية ليست شرطاً من شروط GRI 5(a)."}},{"cat":"classification","a":2,"q":{"en":"Goods of a single heading are presented, but the importer must distinguish between two competing eight-digit subheadings created by U.S. legal notes. Which authority, beyond the GRIs, may apply at this level under GRI 6?","es":"Se presentan mercancías de una sola partida, pero el importador debe distinguir entre dos subpartidas de ocho dígitos en competencia, creadas por notas legales estadounidenses. ¿Qué autoridad, además de las GRI, puede aplicarse en este nivel conforme a la GRI 6?","ru":"Представлены товары одной товарной позиции, но импортёр должен разграничить две конкурирующие восьмизначные субпозиции, созданные правовыми примечаниями США. Какой источник, помимо GRI, может применяться на этом уровне согласно GRI 6?","tr":"Tek bir pozisyona ait eşyalar sunulur, ancak ithalatçının ABD yasal notlarıyla oluşturulan, birbiriyle yarışan iki adet sekiz haneli alt pozisyon arasında ayrım yapması gerekir. GRI 6 uyarınca bu düzeyde, GRI'lerin ötesinde hangi mevzuat uygulanabilir?","hi":"एकल शीर्षक की वस्तुएं प्रस्तुत की जाती हैं, परंतु आयातक को अमेरिकी विधिक नोटों द्वारा निर्मित दो प्रतिस्पर्धी आठ-अंकीय उपशीर्षकों के बीच अंतर करना होता है। GRI 6 के अंतर्गत इस स्तर पर, GRI के अतिरिक्त, कौन-सा प्राधिकार लागू हो सकता है?","ar":"تُقدَّم بضائع من بند واحد، لكن على المستورد التمييز بين بندين فرعيين متنافسين من ثمانية أرقام أنشأتهما الملاحظات القانونية الأمريكية. أي مرجع، إلى جانب GRIs، يمكن أن يُطبَّق على هذا المستوى بموجب GRI 6؟"},"o":[{"en":"The section titles, which become binding at the subheading level.","es":"Los títulos de sección, que se vuelven vinculantes a nivel de subpartida.","ru":"Названия разделов, которые становятся обязательными на уровне субпозиций.","tr":"Alt pozisyon düzeyinde bağlayıcı hâle gelen bölüm başlıkları.","hi":"खंड के शीर्षक, जो उपशीर्षक स्तर पर बाध्यकारी हो जाते हैं।","ar":"عناوين الأقسام، التي تصبح مُلزمة على مستوى البند الفرعي."},{"en":"Nothing further; subheading choice is made solely by duty rate.","es":"Nada más; la elección de la subpartida se hace únicamente por el tipo de derecho.","ru":"Ничего больше; выбор субпозиции делается исключительно по ставке пошлины.","tr":"Başka hiçbir şey; alt pozisyon seçimi yalnızca gümrük vergisi oranına göre yapılır.","hi":"और कुछ नहीं; उपशीर्षक का चयन केवल शुल्क दर के आधार पर किया जाता है।","ar":"لا شيء آخر؛ يتم اختيار البند الفرعي بناءً على معدل الرسوم وحده."},{"en":"The relative subheading notes (including Additional U.S. Notes), applied mutatis mutandis, govern the choice between subheadings at the same level.","es":"Las notas de subpartida pertinentes (incluidas las Additional U.S. Notes), aplicadas mutatis mutandis, rigen la elección entre subpartidas del mismo nivel.","ru":"Соответствующие примечания к субпозициям (включая Additional U.S. Notes), применяемые mutatis mutandis, регулируют выбор между субпозициями одного уровня.","tr":"İlgili alt pozisyon notları (Additional U.S. Notes dahil), mutatis mutandis uygulanarak, aynı düzeydeki alt pozisyonlar arasındaki seçimi yönetir.","hi":"संबंधित उपशीर्षक नोट (Additional U.S. Notes सहित), mutatis mutandis लागू किए जाने पर, समान स्तर के उपशीर्षकों के बीच चयन को शासित करते हैं।","ar":"تحكم ملاحظات البنود الفرعية ذات الصلة (بما في ذلك Additional U.S. Notes)، المطبَّقة mutatis mutandis، الاختيار بين البنود الفرعية في المستوى نفسه."},{"en":"Only the Explanatory Notes, since U.S. notes do not reach the subheading level.","es":"Únicamente las Notas Explicativas, dado que las notas estadounidenses no alcanzan el nivel de subpartida.","ru":"Только Пояснения, поскольку примечания США не распространяются на уровень субпозиций.","tr":"Yalnızca Açıklayıcı Notlar, çünkü ABD notları alt pozisyon düzeyine ulaşmaz.","hi":"केवल व्याख्यात्मक नोट, क्योंकि अमेरिकी नोट उपशीर्षक स्तर तक नहीं पहुंचते।","ar":"فقط الملاحظات التفسيرية، إذ إن الملاحظات الأمريكية لا تصل إلى مستوى البند الفرعي."}],"e":{"en":"GRI 6 directs that subheadings are determined according to the terms of the subheadings and any related subheading notes, and the other GRIs apply mutatis mutandis. In the HTSUS this includes Additional U.S. Notes (which can function as subheading/chapter notes). Section titles remain non-operative; duty rate is irrelevant to classification.","es":"La GRI 6 ordena que las subpartidas se determinen según los términos de las subpartidas y cualesquiera notas de subpartida relacionadas, y que las demás GRI se apliquen mutatis mutandis. En el HTSUS esto incluye las Additional U.S. Notes (que pueden funcionar como notas de subpartida o de capítulo). Los títulos de sección permanecen sin valor operativo; el tipo de derecho es irrelevante para la clasificación.","ru":"GRI 6 предписывает, что субпозиции определяются в соответствии с текстами субпозиций и любыми связанными примечаниями к субпозициям, а прочие GRI применяются mutatis mutandis. В HTSUS это включает Additional U.S. Notes (которые могут выполнять роль примечаний к субпозициям/группам). Названия разделов остаются недействующими; ставка пошлины не имеет значения для классификации.","tr":"GRI 6, alt pozisyonların, alt pozisyonların metinlerine ve ilgili alt pozisyon notlarına göre belirlendiğini ve diğer GRI'lerin mutatis mutandis uygulandığını yönlendirir. HTSUS'ta bu, Additional U.S. Notes'u (alt pozisyon/fasıl notu işlevi görebilen) içerir. Bölüm başlıkları işlevsel olmamaya devam eder; gümrük vergisi oranı sınıflandırma için önemsizdir.","hi":"GRI 6 निर्देशित करता है कि उपशीर्षक उपशीर्षकों के शब्दों और किसी भी संबंधित उपशीर्षक नोट के अनुसार निर्धारित किए जाते हैं, और अन्य GRI mutatis mutandis लागू होते हैं। HTSUS में इसमें Additional U.S. Notes शामिल हैं (जो उपशीर्षक/अध्याय नोट के रूप में कार्य कर सकते हैं)। खंड के शीर्षक निष्क्रिय रहते हैं; शुल्क दर वर्गीकरण के लिए अप्रासंगिक है।","ar":"يوجّه GRI 6 بأن تُحدَّد البنود الفرعية وفقاً لنصوص البنود الفرعية وأي ملاحظات بنود فرعية ذات صلة، وأن تُطبَّق سائر GRIs mutatis mutandis. وفي HTSUS يشمل ذلك Additional U.S. Notes (التي يمكن أن تعمل بمثابة ملاحظات بند فرعي/فصل). وتظل عناوين الأقسام غير عاملة؛ ومعدل الرسوم غير ذي صلة بالتصنيف."}},{"cat":"classification","a":3,"q":{"en":"A toolbox is imported empty as an ordinary article of commerce (not presented with any tools). It is a steel box not specially fitted to any particular article. How should it be classified?","es":"Una caja de herramientas se importa vacía como un artículo ordinario de comercio (no presentada con ninguna herramienta). Es una caja de acero no especialmente ajustada a ningún artículo en particular. ¿Cómo debe clasificarse?","ru":"Ящик для инструментов ввозится пустым как обычный предмет торговли (не представлен ни с какими инструментами). Это стальной ящик, не подогнанный специально под какое-либо конкретное изделие. Как его следует классифицировать?","tr":"Bir alet kutusu, sıradan bir ticari eşya olarak boş ithal edilir (hiçbir aletle birlikte sunulmaz). Belirli bir eşyaya özel olarak biçimlendirilmemiş çelik bir kutudur. Nasıl sınıflandırılmalıdır?","hi":"एक टूलबॉक्स एक सामान्य वाणिज्यिक वस्तु के रूप में खाली आयात किया जाता है (किसी उपकरण के साथ प्रस्तुत नहीं किया गया)। यह एक स्टील का बॉक्स है जो किसी विशेष वस्तु के लिए विशेष रूप से फिट नहीं किया गया है। इसे कैसे वर्गीकृत किया जाना चाहिए?","ar":"تُستورد صندوق عدّة فارغة بوصفها صنفاً تجارياً عادياً (لا تُقدَّم مع أي أدوات). وهي صندوق فولاذي غير مصمَّم خصيصاً لأي صنف بعينه. كيف ينبغي تصنيفها؟"},"o":[{"en":"Under GRI 3(b) by the essential character of the tools.","es":"Conforme a la GRI 3(b), por el carácter esencial de las herramientas.","ru":"Согласно GRI 3(b) — по основному свойству инструментов.","tr":"GRI 3(b) uyarınca, aletlerin esas karakterine göre.","hi":"GRI 3(b) के अंतर्गत, उपकरणों के आवश्यक लक्षण के आधार पर।","ar":"بموجب GRI 3(b)، حسب الطابع الأساسي للأدوات."},{"en":"With whatever tools it is designed to hold, under GRI 5(a).","es":"Con las herramientas que esté diseñada para contener, conforme a la GRI 5(a).","ru":"Вместе с теми инструментами, для хранения которых он предназначен, согласно GRI 5(a).","tr":"GRI 5(a) uyarınca, içine alacak şekilde tasarlandığı aletlerle birlikte.","hi":"GRI 5(a) के अंतर्गत, उन उपकरणों के साथ जिन्हें रखने के लिए इसे डिज़ाइन किया गया है।","ar":"مع أي أدوات صُمِّمت لحملها، بموجب GRI 5(a)."},{"en":"Under GRI 2(a) as an unfinished tool set.","es":"Conforme a la GRI 2(a), como un juego de herramientas incompleto.","ru":"Согласно GRI 2(a) — как незавершённый набор инструментов.","tr":"GRI 2(a) uyarınca, tamamlanmamış bir alet takımı olarak.","hi":"GRI 2(a) के अंतर्गत, एक अधूरे उपकरण सेट के रूप में।","ar":"بموجب GRI 2(a)، باعتبارها مجموعة أدوات غير تامة الصنع."},{"en":"On its own merits in the heading appropriate to the steel box (e.g., as an article of base metal), because GRI 5(a)/(b) apply only when a container is presented with its contents.","es":"Por sus propias características, en la partida correspondiente a la caja de acero (p. ej., como un artículo de metal común), porque la GRI 5(a)/(b) solo se aplica cuando un envase se presenta con su contenido.","ru":"По собственным признакам в товарной позиции, соответствующей стальному ящику (например, как изделие из недрагоценного металла), поскольку GRI 5(a)/(b) применяется только тогда, когда контейнер представлен со своим содержимым.","tr":"Kendi niteliklerine göre, çelik kutuya uygun pozisyonda (örneğin, adi metalden bir eşya olarak), çünkü GRI 5(a)/(b) yalnızca bir kap içeriğiyle birlikte sunulduğunda uygulanır.","hi":"अपने स्वयं के गुणों के आधार पर, स्टील बॉक्स के लिए उपयुक्त शीर्षक में (जैसे, क्षार धातु की वस्तु के रूप में), क्योंकि GRI 5(a)/(b) केवल तभी लागू होते हैं जब कोई कंटेनर अपनी सामग्री के साथ प्रस्तुत किया जाता है।","ar":"بحسب خصائصها الذاتية في البند المناسب للصندوق الفولاذي (مثلاً، بوصفه صنفاً من معدن عادي)، لأن GRI 5(a)/(b) لا يُطبَّق إلا عندما يُقدَّم الوعاء مع محتوياته."}],"e":{"en":"GRI 5(a) and 5(b) only operate when the container/packing is presented WITH the goods it contains. An empty container imported by itself is classified on its own merits under GRI 1 in its appropriate heading (here, as a base-metal box). The container rules do not apply to a standalone empty box.","es":"La GRI 5(a) y la 5(b) solo operan cuando el envase o embalaje se presenta CON las mercancías que contiene. Un envase vacío importado por sí solo se clasifica por sus propias características conforme a la GRI 1 en su partida correspondiente (aquí, como una caja de metal común). Las reglas sobre envases no se aplican a una caja vacía independiente.","ru":"GRI 5(a) и 5(b) действуют только тогда, когда контейнер/упаковка представлены ВМЕСТЕ с товарами, которые они содержат. Пустой контейнер, ввезённый сам по себе, классифицируется по собственным признакам согласно GRI 1 в соответствующей товарной позиции (здесь — как ящик из недрагоценного металла). Правила о контейнерах не применяются к отдельно стоящему пустому ящику.","tr":"GRI 5(a) ve 5(b) yalnızca kap/ambalaj, içerdiği eşyayla BİRLİKTE sunulduğunda işler. Tek başına ithal edilen boş bir kap, kendi niteliklerine göre GRI 1 uyarınca uygun pozisyonunda (burada adi metalden bir kutu olarak) sınıflandırılır. Kap kuralları, tek başına duran boş bir kutuya uygulanmaz.","hi":"GRI 5(a) और 5(b) केवल तभी काम करते हैं जब कंटेनर/पैकिंग को उसमें मौजूद वस्तुओं के साथ प्रस्तुत किया जाता है। अकेले आयातित एक खाली कंटेनर को उसके अपने गुणों के आधार पर GRI 1 के अंतर्गत उसके उपयुक्त शीर्षक में वर्गीकृत किया जाता है (यहां, क्षार धातु के बॉक्स के रूप में)। कंटेनर के नियम एक स्वतंत्र खाली बॉक्स पर लागू नहीं होते।","ar":"لا يعمل GRI 5(a) و5(b) إلا عندما يُقدَّم الوعاء/التغليف مع البضائع التي يحتويها. أما الوعاء الفارغ المستورد وحده فيُصنَّف بحسب خصائصه الذاتية بموجب GRI 1 في بنده المناسب (هنا، بوصفه صندوقاً من معدن عادي). ولا تنطبق قواعد الأوعية على صندوق فارغ قائم بذاته."}},{"cat":"classification","a":3,"q":{"en":"An article could be described both by a heading for the article by name (eo nomine) and by a separate principal-use provision. Which general classification principle governs the choice between an eo nomine provision and a use provision when both seem to apply?","es":"Un artículo podría estar descrito tanto por una partida que designa el artículo por su nombre (eo nomine) como por una disposición separada de uso principal. ¿Qué principio general de clasificación rige la elección entre una disposición eo nomine y una disposición de uso cuando ambas parecen aplicarse?","ru":"Изделие может описываться как товарной позицией для изделия по наименованию (eo nomine), так и отдельным положением об основном использовании. Какой общий принцип классификации регулирует выбор между положением eo nomine и положением об использовании, когда оба, по-видимому, применимы?","tr":"Bir eşya, hem eşyayı adıyla tanımlayan bir pozisyon (eo nomine) hem de ayrı bir esas kullanım hükmü tarafından tanımlanabilir. Her ikisi de uygulanabilir göründüğünde, bir eo nomine hükmü ile bir kullanım hükmü arasındaki seçimi hangi genel sınıflandırma ilkesi yönetir?","hi":"किसी वस्तु को नाम से वस्तु के लिए शीर्षक (eo nomine) और एक अलग मुख्य-उपयोग प्रावधान दोनों द्वारा वर्णित किया जा सकता है। जब दोनों लागू प्रतीत होते हैं, तो eo nomine प्रावधान और उपयोग प्रावधान के बीच चयन को कौन-सा सामान्य वर्गीकरण सिद्धांत शासित करता है?","ar":"يمكن وصف صنف ما بكلٍّ من بند يخص الصنف بالاسم (eo nomine) وحكم مستقل خاص بالاستخدام الرئيسي. أي مبدأ عام في التصنيف يحكم الاختيار بين حكم eo nomine وحكم الاستخدام عندما يبدو أن كليهما ينطبق؟"},"o":[{"en":"GRI 3(c) is applied immediately, choosing the heading last in numerical order.","es":"Se aplica de inmediato la GRI 3(c), eligiendo la partida que figura en último lugar en orden numérico.","ru":"GRI 3(c) применяется сразу, с выбором товарной позиции, последней в числовом порядке.","tr":"GRI 3(c) hemen uygulanır ve sayısal sırada son gelen pozisyon seçilir.","hi":"GRI 3(c) तुरंत लागू किया जाता है, संख्यात्मक क्रम में अंतिम आने वाले शीर्षक को चुनते हुए।","ar":"يُطبَّق GRI 3(c) فوراً، باختيار البند الأخير في الترتيب الرقمي."},{"en":"The eo nomine provision is always discarded in favor of the basket provision.","es":"La disposición eo nomine siempre se descarta en favor de la disposición residual.","ru":"Положение eo nomine всегда отбрасывается в пользу остаточного положения.","tr":"Eo nomine hüküm her zaman sepet hükmü lehine bir kenara bırakılır.","hi":"eo nomine प्रावधान को हमेशा बास्केट प्रावधान के पक्ष में त्याग दिया जाता है।","ar":"يُستبعَد حكم eo nomine دائماً لصالح الحكم الجامع."},{"en":"The use provision always prevails over the eo nomine provision.","es":"La disposición de uso siempre prevalece sobre la disposición eo nomine.","ru":"Положение об использовании всегда преобладает над положением eo nomine.","tr":"Kullanım hükmü her zaman eo nomine hükmüne üstün gelir.","hi":"उपयोग प्रावधान हमेशा eo nomine प्रावधान पर प्रबल होता है।","ar":"يسود حكم الاستخدام دائماً على حكم eo nomine."},{"en":"There is no fixed rule that one always wins; the relative specificity is assessed under GRI 3(a), and an eo nomine provision will often prevail unless the use provision more specifically describes the goods or a note directs otherwise.","es":"No hay una regla fija de que una prevalezca siempre; la especificidad relativa se evalúa conforme a la GRI 3(a), y una disposición eo nomine prevalecerá a menudo, salvo que la disposición de uso describa las mercancías de forma más específica o que una nota disponga lo contrario.","ru":"Нет жёсткого правила о том, что одно всегда побеждает; относительная конкретность оценивается согласно GRI 3(a), и положение eo nomine часто будет преобладать, если только положение об использовании не описывает товары более конкретно или примечание не предписывает иное.","tr":"Birinin her zaman üstün geleceğine dair sabit bir kural yoktur; göreli özgüllük GRI 3(a) uyarınca değerlendirilir ve kullanım hükmü eşyayı daha spesifik olarak tanımlamadıkça veya bir not aksini yönlendirmedikçe eo nomine hüküm çoğu zaman üstün gelir.","hi":"ऐसा कोई निश्चित नियम नहीं है कि एक हमेशा जीते; सापेक्ष विशिष्टता का मूल्यांकन GRI 3(a) के अंतर्गत किया जाता है, और एक eo nomine प्रावधान प्रायः प्रबल होगा, जब तक कि उपयोग प्रावधान वस्तुओं का अधिक विशिष्ट रूप से वर्णन न करे या कोई नोट अन्यथा निर्देश न दे।","ar":"لا توجد قاعدة ثابتة بأن أحدهما يسود دائماً؛ بل تُقيَّم درجة التحديد النسبية بموجب GRI 3(a)، وكثيراً ما يسود حكم eo nomine ما لم يصف حكم الاستخدام البضائع وصفاً أكثر تحديداً أو ما لم توجّه ملاحظة بخلاف ذلك."}],"e":{"en":"When a good is potentially described by both an eo nomine and a use provision, classification turns on relative specificity under GRI 1/GRI 3(a) and the statutory text, not a blanket rule. Courts have held neither category automatically defeats the other; the more specific or apt description (or a controlling note) governs.","es":"Cuando una mercancía está potencialmente descrita tanto por una disposición eo nomine como por una de uso, la clasificación depende de la especificidad relativa conforme a la GRI 1/GRI 3(a) y del texto legal, no de una regla general. Los tribunales han sostenido que ninguna categoría derrota automáticamente a la otra; rige la descripción más específica o apropiada (o una nota determinante).","ru":"Когда товар потенциально описывается как положением eo nomine, так и положением об использовании, классификация зависит от относительной конкретности согласно GRI 1/GRI 3(a) и от текста закона, а не от общего правила. Суды постановили, что ни одна из категорий автоматически не превосходит другую; решающим является более конкретное или подходящее описание (или определяющее примечание).","tr":"Bir eşya potansiyel olarak hem bir eo nomine hem de bir kullanım hükmüyle tanımlandığında, sınıflandırma genel bir kurala değil, GRI 1/GRI 3(a) uyarınca göreli özgüllüğe ve yasal metne dayanır. Mahkemeler, hiçbir kategorinin diğerini otomatik olarak geçersiz kılmadığına hükmetmiştir; daha spesifik veya daha uygun tanım (ya da belirleyici bir not) hükmeder.","hi":"जब किसी वस्तु को संभावित रूप से eo nomine और उपयोग प्रावधान दोनों द्वारा वर्णित किया जाता है, तो वर्गीकरण एक सर्वव्यापी नियम पर नहीं, बल्कि GRI 1/GRI 3(a) के अंतर्गत सापेक्ष विशिष्टता और वैधानिक पाठ पर निर्भर करता है। न्यायालयों ने माना है कि कोई भी श्रेणी स्वतः दूसरे को परास्त नहीं करती; अधिक विशिष्ट या उपयुक्त विवरण (या एक निर्णायक नोट) शासित करता है।","ar":"عندما يكون من المحتمل وصف بضاعة بكلٍّ من حكم eo nomine وحكم استخدام، يتوقف التصنيف على درجة التحديد النسبية بموجب GRI 1/GRI 3(a) والنص القانوني، لا على قاعدة شاملة. وقد قضت المحاكم بأن أياً من الفئتين لا يُلغي الأخرى تلقائياً؛ بل يحكم الوصف الأكثر تحديداً أو ملاءمةً (أو ملاحظة مُلزِمة)."}},{"cat":"valuation","a":2,"q":{"en":"Under the deductive value method, the price used is the unit price at which the imported merchandise is sold in the greatest aggregate quantity. The 'unit price in the greatest aggregate quantity' means the price at which:","es":"Bajo el método de valor deductivo, el precio utilizado es el precio unitario al que la mercancía importada se vende en la mayor cantidad agregada. El 'precio unitario en la mayor cantidad agregada' significa el precio al que:","ru":"При методе вычитаемой стоимости используется цена за единицу, по которой импортируемый товар продается в наибольшем совокупном количестве. 'Цена за единицу в наибольшем совокупном количестве' означает цену, по которой:","tr":"İndirgenmiş değer yönteminde kullanılan fiyat, ithal edilen malın en büyük toplam miktarda satıldığı birim fiyattır. 'En büyük toplam miktardaki birim fiyat' şu anlama gelir:","hi":"घटाव मूल्य पद्धति के तहत, उपयोग किया जाने वाला मूल्य वह इकाई मूल्य है जिस पर आयातित माल सबसे बड़ी कुल मात्रा में बेचा जाता है। 'सबसे बड़ी कुल मात्रा में इकाई मूल्य' का अर्थ वह मूल्य है जिस पर:","ar":"بموجب طريقة القيمة الاستنتاجية، يكون السعر المستخدم هو سعر الوحدة الذي تُباع به البضاعة المستوردة بأكبر كمية إجمالية. ويُقصد بـ 'سعر الوحدة بأكبر كمية إجمالية' السعر الذي:"},"o":[{"en":"the merchandise is first sold after importation, regardless of quantity","es":"la mercancía se vende por primera vez después de la importación, independientemente de la cantidad","ru":"товар впервые продается после ввоза, независимо от количества","tr":"malın ithalattan sonra ilk kez satıldığı, miktardan bağımsız olarak","hi":"माल आयात के बाद पहली बार बेचा जाता है, मात्रा की परवाह किए बिना","ar":"تُباع به البضاعة لأول مرة بعد الاستيراد، بصرف النظر عن الكمية"},{"en":"the greatest number of units is sold to related and unrelated persons combined, at the highest unit price","es":"se vende el mayor número de unidades a personas relacionadas y no relacionadas combinadas, al precio unitario más alto","ru":"наибольшее число единиц продается связанным и несвязанным лицам в совокупности по наивысшей цене за единицу","tr":"ilişkili ve ilişkisiz kişilere toplamda en fazla sayıda birimin en yüksek birim fiyatından satıldığı","hi":"संबंधित और असंबंधित व्यक्तियों को संयुक्त रूप से सबसे अधिक संख्या में इकाइयाँ उच्चतम इकाई मूल्य पर बेची जाती हैं","ar":"يُباع به أكبر عدد من الوحدات للأشخاص المرتبطين وغير المرتبطين مجتمعين، بأعلى سعر للوحدة"},{"en":"the greatest number of units is sold in sales to persons not related to the seller, at the first commercial level after importation","es":"se vende el mayor número de unidades en ventas a personas no relacionadas con el vendedor, en el primer nivel comercial después de la importación","ru":"наибольшее число единиц продается в сделках с лицами, не связанными с продавцом, на первом коммерческом уровне после ввоза","tr":"satıcıyla ilişkili olmayan kişilere yapılan satışlarda, ithalattan sonraki ilk ticari düzeyde en fazla sayıda birimin satıldığı","hi":"विक्रेता से असंबंधित व्यक्तियों को बिक्री में, आयात के बाद पहले वाणिज्यिक स्तर पर सबसे अधिक संख्या में इकाइयाँ बेची जाती हैं","ar":"يُباع به أكبر عدد من الوحدات في مبيعات لأشخاص غير مرتبطين بالبائع، عند أول مستوى تجاري بعد الاستيراد"},{"en":"the unit price equals the weighted average of all unit prices at which the merchandise is sold","es":"el precio unitario es igual al promedio ponderado de todos los precios unitarios a los que se vende la mercancía","ru":"цена за единицу равна средневзвешенному значению всех цен за единицу, по которым продается товар","tr":"birim fiyatın, malın satıldığı tüm birim fiyatların ağırlıklı ortalamasına eşit olduğu","hi":"इकाई मूल्य उन सभी इकाई मूल्यों के भारित औसत के बराबर होता है जिन पर माल बेचा जाता है","ar":"يساوي فيه سعر الوحدة المتوسط المرجح لجميع أسعار الوحدات التي تُباع بها البضاعة"}],"e":{"en":"Under 19 CFR 152.105(c), the 'unit price in the greatest aggregate quantity' is the price at which the greatest number of units is sold in sales to persons not related to the seller, at the first commercial level after importation. It is not a weighted average, the highest price, or the first sale. (19 CFR 152.105(c))","es":"Según 19 CFR 152.105(c), el 'precio unitario en la mayor cantidad agregada' es el precio al que se vende el mayor número de unidades en ventas a personas no relacionadas con el vendedor, en el primer nivel comercial después de la importación. No es un promedio ponderado, el precio más alto, ni la primera venta. (19 CFR 152.105(c))","ru":"Согласно 19 CFR 152.105(c), 'цена за единицу в наибольшем совокупном количестве' — это цена, по которой наибольшее число единиц продается в сделках с лицами, не связанными с продавцом, на первом коммерческом уровне после ввоза. Это не средневзвешенное значение, не наивысшая цена и не первая продажа. (19 CFR 152.105(c))","tr":"19 CFR 152.105(c) uyarınca, 'en büyük toplam miktardaki birim fiyat', satıcıyla ilişkili olmayan kişilere yapılan satışlarda, ithalattan sonraki ilk ticari düzeyde en fazla sayıda birimin satıldığı fiyattır. Bu, ağırlıklı ortalama, en yüksek fiyat veya ilk satış değildir. (19 CFR 152.105(c))","hi":"19 CFR 152.105(c) के तहत, 'सबसे बड़ी कुल मात्रा में इकाई मूल्य' वह मूल्य है जिस पर विक्रेता से असंबंधित व्यक्तियों को बिक्री में, आयात के बाद पहले वाणिज्यिक स्तर पर सबसे अधिक संख्या में इकाइयाँ बेची जाती हैं। यह भारित औसत, उच्चतम मूल्य, या पहली बिक्री नहीं है। (19 CFR 152.105(c))","ar":"بموجب 19 CFR 152.105(c)، فإن 'سعر الوحدة بأكبر كمية إجمالية' هو السعر الذي يُباع به أكبر عدد من الوحدات في مبيعات لأشخاص غير مرتبطين بالبائع، عند أول مستوى تجاري بعد الاستيراد. وهو ليس متوسطاً مرجحاً ولا أعلى سعر ولا أول عملية بيع. (19 CFR 152.105(c))"}},{"cat":"valuation","a":0,"q":{"en":"When merchandise is appraised under deductive value in its condition as imported but is NOT sold at or about the date of importation, the regulation permits use of a sale made within a specified period after importation. That period is:","es":"Cuando la mercancía se valora bajo valor deductivo en su condición tal como fue importada pero NO se vende en la fecha de importación o cerca de ella, la regulación permite el uso de una venta realizada dentro de un período específico después de la importación. Ese período es:","ru":"Когда товар оценивается по вычитаемой стоимости в его состоянии на момент ввоза, но НЕ продается на дату ввоза или примерно в это время, нормативный акт допускает использование продажи, совершенной в течение определенного периода после ввоза. Этот период составляет:","tr":"Mal, ithal edildiği haliyle indirgenmiş değere göre değerlenirken ancak ithalat tarihinde veya yaklaşık o tarihte satılMAdığında, mevzuat ithalattan sonra belirli bir süre içinde yapılan bir satışın kullanılmasına izin verir. Bu süre:","hi":"जब माल का मूल्यांकन उसकी आयातित स्थिति में घटाव मूल्य के तहत किया जाता है लेकिन आयात की तिथि पर या उसके आसपास नहीं बेचा जाता है, तो विनियमन आयात के बाद एक निर्दिष्ट अवधि के भीतर की गई बिक्री के उपयोग की अनुमति देता है। वह अवधि है:","ar":"عندما تُقيَّم البضاعة بموجب القيمة الاستنتاجية بحالتها كما استُوردت ولكن لا تُباع في تاريخ الاستيراد أو ما يقاربه، تسمح اللائحة باستخدام عملية بيع تتم خلال فترة محددة بعد الاستيراد. وتلك الفترة هي:"},"o":[{"en":"within 90 days after the date of importation","es":"dentro de los 90 días posteriores a la fecha de importación","ru":"в течение 90 дней после даты ввоза","tr":"ithalat tarihinden sonraki 90 gün içinde","hi":"आयात की तिथि के 90 दिनों के भीतर","ar":"خلال 90 يوماً بعد تاريخ الاستيراد"},{"en":"within 60 days after the date of importation","es":"dentro de los 60 días posteriores a la fecha de importación","ru":"в течение 60 дней после даты ввоза","tr":"ithalat tarihinden sonraki 60 gün içinde","hi":"आयात की तिथि के 60 दिनों के भीतर","ar":"خلال 60 يوماً بعد تاريخ الاستيراد"},{"en":"within 30 days after the date of entry","es":"dentro de los 30 días posteriores a la fecha de entrada","ru":"в течение 30 дней после даты подачи декларации (entry)","tr":"giriş tarihinden sonraki 30 gün içinde","hi":"प्रवेश (entry) की तिथि के 30 दिनों के भीतर","ar":"خلال 30 يوماً بعد تاريخ الإدخال (entry)"},{"en":"within 180 days after the date of importation","es":"dentro de los 180 días posteriores a la fecha de importación","ru":"в течение 180 дней после даты ввоза","tr":"ithalat tarihinden sonraki 180 gün içinde","hi":"आयात की तिथि के 180 दिनों के भीतर","ar":"خلال 180 يوماً بعد تاريخ الاستيراد"}],"e":{"en":"For merchandise sold in the condition as imported but not at or about the date of importation, deductive value is based on the unit price at which it is sold in the greatest aggregate quantity within 90 days after the date of importation. (19 CFR 152.105(c))","es":"Para la mercancía vendida en la condición tal como fue importada pero no en la fecha de importación o cerca de ella, el valor deductivo se basa en el precio unitario al que se vende en la mayor cantidad agregada dentro de los 90 días posteriores a la fecha de importación. (19 CFR 152.105(c))","ru":"Для товара, проданного в состоянии на момент ввоза, но не на дату ввоза или примерно в это время, вычитаемая стоимость основывается на цене за единицу, по которой он продается в наибольшем совокупном количестве в течение 90 дней после даты ввоза. (19 CFR 152.105(c))","tr":"İthal edildiği haliyle satılan ancak ithalat tarihinde veya yaklaşık o tarihte satılmayan mallar için indirgenmiş değer, ithalat tarihinden sonraki 90 gün içinde en büyük toplam miktarda satıldığı birim fiyata dayanır. (19 CFR 152.105(c))","hi":"आयातित स्थिति में बेचे गए लेकिन आयात की तिथि पर या उसके आसपास नहीं बेचे गए माल के लिए, घटाव मूल्य उस इकाई मूल्य पर आधारित होता है जिस पर इसे आयात की तिथि के 90 दिनों के भीतर सबसे बड़ी कुल मात्रा में बेचा जाता है। (19 CFR 152.105(c))","ar":"بالنسبة للبضاعة المباعة بحالتها كما استُوردت ولكن ليس في تاريخ الاستيراد أو ما يقاربه، تستند القيمة الاستنتاجية إلى سعر الوحدة الذي تُباع به بأكبر كمية إجمالية خلال 90 يوماً بعد تاريخ الاستيراد. (19 CFR 152.105(c))"}},{"cat":"valuation","a":3,"q":{"en":"An importer elects to appraise goods under the 'further processing' variant of deductive value because the merchandise is not sold in the condition as imported. The earliest sale after further processing must occur within what period after importation?","es":"Un importador elige valorar las mercancías bajo la variante de 'procesamiento adicional' del valor deductivo porque la mercancía no se vende en la condición tal como fue importada. ¿La primera venta después del procesamiento adicional debe ocurrir dentro de qué período después de la importación?","ru":"Импортер выбирает оценку товаров по варианту 'дальнейшей переработки' вычитаемой стоимости, поскольку товар не продается в состоянии на момент ввоза. В течение какого периода после ввоза должна состояться самая ранняя продажа после дальнейшей переработки?","tr":"Bir ithalatçı, mal ithal edildiği haliyle satılmadığından, indirgenmiş değerin 'ileri işleme' varyantı altında malları değerlemeyi seçer. İleri işlemeden sonraki en erken satış, ithalattan sonra hangi süre içinde gerçekleşmelidir?","hi":"एक आयातकर्ता घटाव मूल्य के 'आगे की प्रक्रिया' संस्करण के तहत माल का मूल्यांकन करना चुनता है क्योंकि माल आयातित स्थिति में नहीं बेचा जाता है। आगे की प्रक्रिया के बाद सबसे पहली बिक्री आयात के बाद किस अवधि के भीतर होनी चाहिए?","ar":"يختار المستورد تقييم البضائع بموجب صيغة 'المعالجة الإضافية' للقيمة الاستنتاجية لأن البضاعة لا تُباع بحالتها كما استُوردت. خلال أي فترة بعد الاستيراد يجب أن تتم أول عملية بيع بعد المعالجة الإضافية؟"},"o":[{"en":"within 90 days after importation","es":"dentro de los 90 días posteriores a la importación","ru":"в течение 90 дней после ввоза","tr":"ithalattan sonraki 90 gün içinde","hi":"आयात के 90 दिनों के भीतर","ar":"خلال 90 يوماً بعد الاستيراد"},{"en":"within one year after importation","es":"dentro de un año después de la importación","ru":"в течение одного года после ввоза","tr":"ithalattan sonraki bir yıl içinde","hi":"आयात के एक वर्ष के भीतर","ar":"خلال سنة واحدة بعد الاستيراد"},{"en":"within 120 days after entry","es":"dentro de los 120 días posteriores a la entrada","ru":"в течение 120 дней после подачи декларации (entry)","tr":"girişten sonraki 120 gün içinde","hi":"प्रवेश (entry) के 120 दिनों के भीतर","ar":"خلال 120 يوماً بعد الإدخال (entry)"},{"en":"within 180 days after importation","es":"dentro de los 180 días posteriores a la importación","ru":"в течение 180 дней после ввоза","tr":"ithalattan sonraki 180 gün içinde","hi":"आयात के 180 दिनों के भीतर","ar":"خلال 180 يوماً بعد الاستيراد"}],"e":{"en":"Under the further-processing (superdeductive) variant, the importer may elect to base deductive value on the unit price of merchandise sold after further processing, provided the sale occurs within 180 days after the date of importation. (19 CFR 152.105(d))","es":"Bajo la variante de procesamiento adicional (superdeductivo), el importador puede optar por basar el valor deductivo en el precio unitario de la mercancía vendida después del procesamiento adicional, siempre que la venta ocurra dentro de los 180 días posteriores a la fecha de importación. (19 CFR 152.105(d))","ru":"По варианту дальнейшей переработки (супервычитаемому) импортер может выбрать определение вычитаемой стоимости на основе цены за единицу товара, проданного после дальнейшей переработки, при условии, что продажа состоится в течение 180 дней после даты ввоза. (19 CFR 152.105(d))","tr":"İleri işleme (süperindirgenmiş) varyantı altında, ithalatçı, satışın ithalat tarihinden sonraki 180 gün içinde gerçekleşmesi koşuluyla, indirgenmiş değeri ileri işlemeden sonra satılan malın birim fiyatına dayandırmayı seçebilir. (19 CFR 152.105(d))","hi":"आगे की प्रक्रिया (सुपरडिडक्टिव) संस्करण के तहत, आयातकर्ता आगे की प्रक्रिया के बाद बेचे गए माल के इकाई मूल्य पर घटाव मूल्य को आधारित करना चुन सकता है, बशर्ते बिक्री आयात की तिथि के 180 दिनों के भीतर हो। (19 CFR 152.105(d))","ar":"بموجب صيغة المعالجة الإضافية (فوق الاستنتاجية)، يجوز للمستورد أن يختار إسناد القيمة الاستنتاجية إلى سعر وحدة البضاعة المباعة بعد المعالجة الإضافية، شريطة أن تتم عملية البيع خلال 180 يوماً بعد تاريخ الاستيراد. (19 CFR 152.105(d))"}},{"cat":"valuation","a":0,"q":{"en":"Imported merchandise sold in the United States in its condition as imported has a unit price in the greatest aggregate quantity of one hundred dollars per unit, with five hundred units sold. The following are established by sufficient information: the addition usually made for profit and general expenses is twenty percent of the U.S. price; actual international transportation and insurance to the United States total three thousand dollars; the usual U.S. inland freight and insurance after importation total one thousand five hundred dollars; and customs duties and other federal taxes currently payable total two thousand five hundred dollars. What is the deductive value?","es":"La mercancía importada vendida en los Estados Unidos en su condición tal como fue importada tiene un precio unitario en la mayor cantidad agregada de cien dólares por unidad, con quinientas unidades vendidas. Lo siguiente se establece mediante información suficiente: la adición que usualmente se hace por ganancia y gastos generales es el veinte por ciento del precio en EE. UU.; el transporte internacional real y el seguro hasta los Estados Unidos suman tres mil dólares; el flete y seguro interno usual en EE. UU. después de la importación suman mil quinientos dólares; y los derechos de aduana y otros impuestos federales actualmente pagaderos suman dos mil quinientos dólares. ¿Cuál es el valor deductivo?","ru":"Импортный товар, проданный в Соединенных Штатах в его состоянии на момент ввоза, имеет цену за единицу в наибольшем совокупном количестве в сто долларов за единицу, при этом продано пятьсот единиц. Достаточной информацией установлено следующее: надбавка, обычно вносимая на прибыль и общие расходы, составляет двадцать процентов от цены в США; фактические международные транспортные расходы и страхование до Соединенных Штатов составляют три тысячи долларов; обычный внутренний фрахт и страхование в США после ввоза составляют одну тысячу пятьсот долларов; а таможенные пошлины и другие федеральные налоги, подлежащие уплате в настоящее время, составляют две тысячи пятьсот долларов. Какова вычитаемая стоимость?","tr":"ABD'de ithal edildiği haliyle satılan ithal malın, en büyük toplam miktardaki birim fiyatı birim başına yüz dolar olup, beş yüz birim satılmıştır. Aşağıdakiler yeterli bilgi ile tespit edilmiştir: kâr ve genel giderler için genellikle yapılan ekleme, ABD fiyatının yüzde yirmisidir; ABD'ye fiili uluslararası taşıma ve sigorta toplam üç bin dolardır; ithalattan sonra olağan ABD iç taşıma ve sigortası toplam bin beş yüz dolardır; ve hâlihazırda ödenecek gümrük vergileri ile diğer federal vergiler toplam iki bin beş yüz dolardır. İndirgenmiş değer nedir?","hi":"संयुक्त राज्य अमेरिका में आयातित स्थिति में बेचे गए आयातित माल का सबसे बड़ी कुल मात्रा में इकाई मूल्य प्रति इकाई एक सौ डॉलर है, जिसमें पाँच सौ इकाइयाँ बेची गईं। निम्नलिखित पर्याप्त जानकारी द्वारा स्थापित किए गए हैं: लाभ और सामान्य व्यय के लिए आमतौर पर की जाने वाली वृद्धि अमेरिकी मूल्य का बीस प्रतिशत है; संयुक्त राज्य अमेरिका तक वास्तविक अंतर्राष्ट्रीय परिवहन और बीमा कुल तीन हजार डॉलर हैं; आयात के बाद सामान्य अमेरिकी अंतर्देशीय माल ढुलाई और बीमा कुल एक हजार पाँच सौ डॉलर हैं; और वर्तमान में देय सीमा शुल्क और अन्य संघीय कर कुल दो हजार पाँच सौ डॉलर हैं। घटाव मूल्य क्या है?","ar":"البضاعة المستوردة المباعة في الولايات المتحدة بحالتها كما استُوردت لها سعر وحدة بأكبر كمية إجمالية يبلغ مائة دولار للوحدة، مع بيع خمسمائة وحدة. وقد تم إثبات ما يلي بمعلومات كافية: الإضافة التي تُجرى عادةً للربح والمصروفات العامة هي عشرون بالمائة من السعر في الولايات المتحدة؛ والنقل الدولي الفعلي والتأمين إلى الولايات المتحدة يبلغان ثلاثة آلاف دولار؛ والشحن الداخلي والتأمين المعتادان في الولايات المتحدة بعد الاستيراد يبلغان ألفاً وخمسمائة دولار؛ والرسوم الجمركية وغيرها من الضرائب الفيدرالية المستحقة حالياً تبلغ ألفين وخمسمائة دولار. ما هي القيمة الاستنتاجية؟"},"o":[{"en":"thirty-three thousand dollars","es":"treinta y tres mil dólares","ru":"тридцать три тысячи долларов","tr":"otuz üç bin dolar","hi":"तैंतीस हजार डॉलर","ar":"ثلاثة وثلاثون ألف دولار"},{"en":"thirty-five thousand five hundred dollars","es":"treinta y cinco mil quinientos dólares","ru":"тридцать пять тысяч пятьсот долларов","tr":"otuz beş bin beş yüz dolar","hi":"पैंतीस हजार पाँच सौ डॉलर","ar":"خمسة وثلاثون ألفاً وخمسمائة دولار"},{"en":"forty thousand dollars","es":"cuarenta mil dólares","ru":"сорок тысяч долларов","tr":"kırk bin dolar","hi":"चालीस हजार डॉलर","ar":"أربعون ألف دولار"},{"en":"thirty thousand five hundred dollars","es":"treinta mil quinientos dólares","ru":"тридцать тысяч пятьсот долларов","tr":"otuz bin beş yüz dolar","hi":"तीस हजार पाँच सौ डॉलर","ar":"ثلاثون ألفاً وخمسمائة دولار"}],"e":{"en":"Starting price = 100 x 500 = $50,000. Deduct profit/general expenses (20% x $50,000 = $10,000), international transport/insurance ($3,000), U.S. inland transport/insurance ($1,500), and duties/federal taxes ($2,500): $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))","es":"Precio inicial = 100 x 500 = $50,000. Deducir ganancia/gastos generales (20% x $50,000 = $10,000), transporte/seguro internacional ($3,000), transporte/seguro interno en EE. UU. ($1,500), y derechos/impuestos federales ($2,500): $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))","ru":"Начальная цена = 100 x 500 = $50,000. Вычесть прибыль/общие расходы (20% x $50,000 = $10,000), международный транспорт/страхование ($3,000), внутренний транспорт/страхование в США ($1,500) и пошлины/федеральные налоги ($2,500): $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))","tr":"Başlangıç fiyatı = 100 x 500 = $50,000. Kâr/genel giderler (20% x $50,000 = $10,000), uluslararası taşıma/sigorta ($3,000), ABD iç taşıma/sigorta ($1,500) ve vergiler/federal vergiler ($2,500) düşülür: $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))","hi":"प्रारंभिक मूल्य = 100 x 500 = $50,000. लाभ/सामान्य व्यय (20% x $50,000 = $10,000), अंतर्राष्ट्रीय परिवहन/बीमा ($3,000), अमेरिकी अंतर्देशीय परिवहन/बीमा ($1,500), और शुल्क/संघीय कर ($2,500) घटाएँ: $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))","ar":"السعر الابتدائي = 100 x 500 = $50,000. يُخصم الربح/المصروفات العامة (20% x $50,000 = $10,000)، والنقل/التأمين الدولي ($3,000)، والنقل/التأمين الداخلي في الولايات المتحدة ($1,500)، والرسوم/الضرائب الفيدرالية ($2,500): $50,000 - $10,000 - $3,000 - $1,500 - $2,500 = $33,000. (19 CFR 152.105(d))"}},{"cat":"valuation","a":3,"q":{"en":"Which of the following is NOT a permitted deduction from the U.S. price when computing deductive value?","es":"¿Cuál de las siguientes NO es una deducción permitida del precio en EE. UU. al calcular el valor deductivo?","ru":"Что из перечисленного НЕ является допустимым вычетом из цены в США при расчете вычитаемой стоимости?","tr":"İndirgenmiş değer hesaplanırken ABD fiyatından yapılan aşağıdaki indirimlerden hangisine izin VERİLMEZ?","hi":"घटाव मूल्य की गणना करते समय अमेरिकी मूल्य से निम्नलिखित में से कौन-सी अनुमत कटौती नहीं है?","ar":"أي مما يلي ليس خصماً مسموحاً به من السعر في الولايات المتحدة عند احتساب القيمة الاستنتاجية؟"},"o":[{"en":"the usual costs of transportation and insurance incurred for shipment within the United States after importation","es":"los costos usuales de transporte y seguro incurridos para el envío dentro de los Estados Unidos después de la importación","ru":"обычные расходы на транспортировку и страхование, понесенные при перевозке внутри Соединенных Штатов после ввоза","tr":"ithalattan sonra Amerika Birleşik Devletleri içinde sevkiyat için yapılan olağan taşıma ve sigorta maliyetleri","hi":"आयात के बाद संयुक्त राज्य अमेरिका के भीतर शिपमेंट के लिए किए गए सामान्य परिवहन और बीमा लागत","ar":"التكاليف المعتادة للنقل والتأمين المتكبدة للشحن داخل الولايات المتحدة بعد الاستيراد"},{"en":"the commission usually paid, or the addition usually made for profit and general expenses, in connection with U.S. sales of imported merchandise of the same class or kind","es":"la comisión que usualmente se paga, o la adición que usualmente se hace por ganancia y gastos generales, en relación con las ventas en EE. UU. de mercancía importada de la misma clase o tipo","ru":"комиссия, обычно уплачиваемая, или надбавка, обычно вносимая на прибыль и общие расходы, в связи с продажами в США импортного товара того же класса или вида","tr":"aynı sınıf veya türden ithal malın ABD satışlarıyla bağlantılı olarak genellikle ödenen komisyon veya kâr ve genel giderler için genellikle yapılan ekleme","hi":"समान वर्ग या प्रकार के आयातित माल की अमेरिकी बिक्री के संबंध में आमतौर पर भुगतान किया जाने वाला कमीशन, या लाभ और सामान्य व्यय के लिए आमतौर पर की जाने वाली वृद्धि","ar":"العمولة المدفوعة عادةً، أو الإضافة التي تُجرى عادةً للربح والمصروفات العامة، فيما يتعلق بمبيعات البضاعة المستوردة من نفس الفئة أو النوع في الولايات المتحدة"},{"en":"the customs duties and other federal taxes currently payable on the merchandise by reason of its importation","es":"los derechos de aduana y otros impuestos federales actualmente pagaderos sobre la mercancía en razón de su importación","ru":"таможенные пошлины и другие федеральные налоги, подлежащие уплате за товар в настоящее время по причине его ввоза","tr":"malın ithalatı nedeniyle hâlihazırda ödenecek gümrük vergileri ve diğer federal vergiler","hi":"माल के आयात के कारण उस पर वर्तमान में देय सीमा शुल्क और अन्य संघीय कर","ar":"الرسوم الجمركية وغيرها من الضرائب الفيدرالية المستحقة حالياً على البضاعة بسبب استيرادها"},{"en":"the cost of the assists supplied by the buyer to the foreign producer of the merchandise","es":"el costo de las asistencias suministradas por el comprador al productor extranjero de la mercancía","ru":"стоимость дополнительных средств (assists), предоставленных покупателем иностранному производителю товара","tr":"alıcı tarafından malın yabancı üreticisine sağlanan yardımların (assists) maliyeti","hi":"खरीदार द्वारा माल के विदेशी उत्पादक को आपूर्ति की गई सहायता (assists) की लागत","ar":"تكلفة المساعدات (assists) التي يقدمها المشتري إلى المنتج الأجنبي للبضاعة"}],"e":{"en":"Permitted deductions under deductive value are: commissions or profit and general expenses; international and U.S. transportation/insurance; customs duties and federal taxes; and (in the further-processing variant) the value added by processing. The cost of assists is not a deductive-value deduction. (19 CFR 152.105(d))","es":"Las deducciones permitidas bajo el valor deductivo son: comisiones o ganancia y gastos generales; transporte/seguro internacional y de EE. UU.; derechos de aduana e impuestos federales; y (en la variante de procesamiento adicional) el valor agregado por el procesamiento. El costo de las asistencias no es una deducción del valor deductivo. (19 CFR 152.105(d))","ru":"Допустимые вычеты по вычитаемой стоимости: комиссии либо прибыль и общие расходы; международный транспорт/страхование и транспорт/страхование в США; таможенные пошлины и федеральные налоги; и (в варианте дальнейшей переработки) стоимость, добавленная переработкой. Стоимость дополнительных средств (assists) не является вычетом из вычитаемой стоимости. (19 CFR 152.105(d))","tr":"İndirgenmiş değer altında izin verilen indirimler şunlardır: komisyonlar veya kâr ve genel giderler; uluslararası ve ABD taşıma/sigorta; gümrük vergileri ve federal vergiler; ve (ileri işleme varyantında) işleme ile katılan değer. Yardımların (assists) maliyeti, indirgenmiş değer indirimi değildir. (19 CFR 152.105(d))","hi":"घटाव मूल्य के तहत अनुमत कटौतियाँ हैं: कमीशन या लाभ और सामान्य व्यय; अंतर्राष्ट्रीय और अमेरिकी परिवहन/बीमा; सीमा शुल्क और संघीय कर; और (आगे की प्रक्रिया संस्करण में) प्रक्रिया द्वारा जोड़ा गया मूल्य। सहायता (assists) की लागत घटाव-मूल्य कटौती नहीं है। (19 CFR 152.105(d))","ar":"الخصومات المسموح بها بموجب القيمة الاستنتاجية هي: العمولات أو الربح والمصروفات العامة؛ والنقل/التأمين الدولي والأمريكي؛ والرسوم الجمركية والضرائب الفيدرالية؛ و(في صيغة المعالجة الإضافية) القيمة المضافة بالمعالجة. وليست تكلفة المساعدات (assists) خصماً من القيمة الاستنتاجية. (19 CFR 152.105(d))"}},{"cat":"valuation","a":2,"q":{"en":"Under the further-processing variant of deductive value, merchandise is sold in the United States after processing at ninety dollars per unit for one thousand units. Sufficient data establish: profit and general expenses of fifteen thousand dollars; transportation and insurance of five thousand dollars; customs duties and federal taxes of four thousand dollars; and the value added by the processing after importation of twenty thousand dollars. What is the deductive value?","es":"Bajo la variante de procesamiento adicional del valor deductivo, la mercancía se vende en los Estados Unidos después del procesamiento a noventa dólares por unidad por mil unidades. Datos suficientes establecen: ganancia y gastos generales de quince mil dólares; transporte y seguro de cinco mil dólares; derechos de aduana e impuestos federales de cuatro mil dólares; y el valor agregado por el procesamiento después de la importación de veinte mil dólares. ¿Cuál es el valor deductivo?","ru":"По варианту дальнейшей переработки вычитаемой стоимости товар продается в Соединенных Штатах после переработки по девяносто долларов за единицу за тысячу единиц. Достаточные данные устанавливают: прибыль и общие расходы в пятнадцать тысяч долларов; транспорт и страхование в пять тысяч долларов; таможенные пошлины и федеральные налоги в четыре тысячи долларов; и стоимость, добавленную переработкой после ввоза, в двадцать тысяч долларов. Какова вычитаемая стоимость?","tr":"İndirgenmiş değerin ileri işleme varyantı altında, mal işlemeden sonra ABD'de bin birim için birim başına doksan dolardan satılır. Yeterli veriler şunları tespit eder: kâr ve genel giderler on beş bin dolar; taşıma ve sigorta beş bin dolar; gümrük vergileri ve federal vergiler dört bin dolar; ve ithalattan sonra işleme ile katılan değer yirmi bin dolar. İndirgenmiş değer nedir?","hi":"घटाव मूल्य के आगे की प्रक्रिया संस्करण के तहत, माल को प्रक्रिया के बाद संयुक्त राज्य अमेरिका में एक हजार इकाइयों के लिए प्रति इकाई नब्बे डॉलर पर बेचा जाता है। पर्याप्त डेटा स्थापित करते हैं: पंद्रह हजार डॉलर का लाभ और सामान्य व्यय; पाँच हजार डॉलर का परिवहन और बीमा; चार हजार डॉलर का सीमा शुल्क और संघीय कर; और आयात के बाद प्रक्रिया द्वारा जोड़ा गया बीस हजार डॉलर का मूल्य। घटाव मूल्य क्या है?","ar":"بموجب صيغة المعالجة الإضافية للقيمة الاستنتاجية، تُباع البضاعة في الولايات المتحدة بعد المعالجة بسعر تسعين دولاراً للوحدة لألف وحدة. تُثبت البيانات الكافية ما يلي: ربح ومصروفات عامة بقيمة خمسة عشر ألف دولار؛ ونقل وتأمين بقيمة خمسة آلاف دولار؛ ورسوم جمركية وضرائب فيدرالية بقيمة أربعة آلاف دولار؛ والقيمة المضافة بالمعالجة بعد الاستيراد بقيمة عشرين ألف دولار. ما هي القيمة الاستنتاجية؟"},"o":[{"en":"sixty-six thousand dollars","es":"sesenta y seis mil dólares","ru":"шестьдесят шесть тысяч долларов","tr":"altmış altı bin dolar","hi":"छियासठ हजार डॉलर","ar":"ستة وستون ألف دولار"},{"en":"fifty-one thousand dollars","es":"cincuenta y un mil dólares","ru":"пятьдесят одна тысяча долларов","tr":"elli bir bin dolar","hi":"इक्यावन हजार डॉलर","ar":"واحد وخمسون ألف دولار"},{"en":"forty-six thousand dollars","es":"cuarenta y seis mil dólares","ru":"сорок шесть тысяч долларов","tr":"kırk altı bin dolar","hi":"छियालीस हजार डॉलर","ar":"ستة وأربعون ألف دولار"},{"en":"forty-two thousand dollars","es":"cuarenta y dos mil dólares","ru":"сорок две тысячи долларов","tr":"kırk iki bin dolar","hi":"बयालीस हजार डॉलर","ar":"اثنان وأربعون ألف دولار"}],"e":{"en":"U.S. price = 90 x 1,000 = $90,000. Deduct profit/general expenses ($15,000), transportation/insurance ($5,000), duties/taxes ($4,000), and the value added by processing after importation ($20,000): $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))","es":"Precio en EE. UU. = 90 x 1,000 = $90,000. Deducir ganancia/gastos generales ($15,000), transporte/seguro ($5,000), derechos/impuestos ($4,000), y el valor agregado por el procesamiento después de la importación ($20,000): $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))","ru":"Цена в США = 90 x 1,000 = $90,000. Вычесть прибыль/общие расходы ($15,000), транспорт/страхование ($5,000), пошлины/налоги ($4,000) и стоимость, добавленную переработкой после ввоза ($20,000): $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))","tr":"ABD fiyatı = 90 x 1,000 = $90,000. Kâr/genel giderler ($15,000), taşıma/sigorta ($5,000), vergiler/federal vergiler ($4,000) ve ithalattan sonra işleme ile katılan değer ($20,000) düşülür: $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))","hi":"अमेरिकी मूल्य = 90 x 1,000 = $90,000. लाभ/सामान्य व्यय ($15,000), परिवहन/बीमा ($5,000), शुल्क/कर ($4,000), और आयात के बाद प्रक्रिया द्वारा जोड़ा गया मूल्य ($20,000) घटाएँ: $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))","ar":"السعر في الولايات المتحدة = 90 x 1,000 = $90,000. يُخصم الربح/المصروفات العامة ($15,000)، والنقل/التأمين ($5,000)، والرسوم/الضرائب ($4,000)، والقيمة المضافة بالمعالجة بعد الاستيراد ($20,000): $90,000 - $15,000 - $5,000 - $4,000 - $20,000 = $46,000. (19 CFR 152.105(d))"}},{"cat":"valuation","a":0,"q":{"en":"Computed value is being used. The producer's records and sufficient data show: cost or value of materials of forty thousand dollars; fabrication and other processing of fifteen thousand dollars; an amount for profit and general expenses (consistent with sales of the same class or kind for export to the United States) of eleven thousand dollars; packing costs of one thousand two hundred dollars; and a mold supplied as an assist, not otherwise included, with a total value of eighteen thousand dollars that is apportioned over the entire anticipated production, of which this shipment represents one-third. What is the computed value?","es":"Se está utilizando el valor calculado. Los registros del productor y datos suficientes muestran: costo o valor de los materiales de cuarenta mil dólares; fabricación y otro procesamiento de quince mil dólares; un monto por ganancia y gastos generales (consistente con las ventas de la misma clase o tipo para exportación a los Estados Unidos) de once mil dólares; costos de embalaje de mil doscientos dólares; y un molde suministrado como asistencia, no incluido de otro modo, con un valor total de dieciocho mil dólares que se prorratea sobre toda la producción anticipada, de la cual este envío representa un tercio. ¿Cuál es el valor calculado?","ru":"Используется исчисленная стоимость. Записи производителя и достаточные данные показывают: стоимость или ценность материалов в сорок тысяч долларов; изготовление и иную обработку в пятнадцать тысяч долларов; сумму на прибыль и общие расходы (соответствующую продажам того же класса или вида на экспорт в Соединенные Штаты) в одиннадцать тысяч долларов; расходы на упаковку в одну тысячу двести долларов; и форму (mold), предоставленную как дополнительное средство (assist), иным образом не включенную, с общей стоимостью восемнадцать тысяч долларов, распределяемой по всему предполагаемому объему производства, из которого данная партия составляет одну треть. Какова исчисленная стоимость?","tr":"Hesaplanmış değer kullanılmaktadır. Üreticinin kayıtları ve yeterli veriler şunları gösterir: malzemelerin maliyeti veya değeri kırk bin dolar; imalat ve diğer işleme on beş bin dolar; kâr ve genel giderler için bir tutar (Amerika Birleşik Devletleri'ne ihracat için aynı sınıf veya türden satışlarla tutarlı) on bir bin dolar; ambalaj maliyetleri bin iki yüz dolar; ve başka şekilde dâhil edilmeyen, yardım (assist) olarak sağlanan ve toplam değeri on sekiz bin dolar olan, bu sevkiyatın üçte birini temsil ettiği toplam öngörülen üretime dağıtılan bir kalıp (mold). Hesaplanmış değer nedir?","hi":"गणना मूल्य का उपयोग किया जा रहा है। उत्पादक के रिकॉर्ड और पर्याप्त डेटा दिखाते हैं: चालीस हजार डॉलर की सामग्री की लागत या मूल्य; पंद्रह हजार डॉलर का निर्माण और अन्य प्रक्रिया; लाभ और सामान्य व्यय के लिए ग्यारह हजार डॉलर की राशि (संयुक्त राज्य अमेरिका को निर्यात के लिए समान वर्ग या प्रकार की बिक्री के अनुरूप); एक हजार दो सौ डॉलर की पैकिंग लागत; और सहायता (assist) के रूप में आपूर्ति किया गया एक साँचा (mold), अन्यथा शामिल नहीं, जिसका कुल मूल्य अठारह हजार डॉलर है जो पूरे अनुमानित उत्पादन पर आवंटित किया जाता है, जिसमें से यह शिपमेंट एक-तिहाई का प्रतिनिधित्व करता है। गणना मूल्य क्या है?","ar":"تُستخدم القيمة المحتسبة. تُظهر سجلات المنتج والبيانات الكافية ما يلي: تكلفة أو قيمة المواد أربعون ألف دولار؛ والتصنيع والمعالجة الأخرى خمسة عشر ألف دولار؛ ومبلغ للربح والمصروفات العامة (متسق مع مبيعات نفس الفئة أو النوع للتصدير إلى الولايات المتحدة) أحد عشر ألف دولار؛ وتكاليف التعبئة ألف ومائتا دولار؛ وقالب (mold) مقدَّم كمساعدة (assist)، غير مُدرَج بطريقة أخرى، بقيمة إجمالية تبلغ ثمانية عشر ألف دولار يُوزَّع على إجمالي الإنتاج المتوقع، الذي تمثل هذه الشحنة ثلثه. ما هي القيمة المحتسبة؟"},"o":[{"en":"seventy-three thousand two hundred dollars","es":"setenta y tres mil doscientos dólares","ru":"семьдесят три тысячи двести долларов","tr":"yetmiş üç bin iki yüz dolar","hi":"तिहत्तर हजार दो सौ डॉलर","ar":"ثلاثة وسبعون ألفاً ومائتا دولار"},{"en":"eighty-five thousand two hundred dollars","es":"ochenta y cinco mil doscientos dólares","ru":"восемьдесят пять тысяч двести долларов","tr":"seksen beş bin iki yüz dolar","hi":"पचासी हजार दो सौ डॉलर","ar":"خمسة وثمانون ألفاً ومائتا دولار"},{"en":"sixty-seven thousand two hundred dollars","es":"sesenta y siete mil doscientos dólares","ru":"шестьдесят семь тысяч двести долларов","tr":"altmış yedi bin iki yüz dolar","hi":"सरसठ हजार दो सौ डॉलर","ar":"سبعة وستون ألفاً ومائتا دولار"},{"en":"seventy thousand two hundred dollars","es":"setenta mil doscientos dólares","ru":"семьдесят тысяч двести долларов","tr":"yetmiş bin iki yüz dolar","hi":"सत्तर हजार दो सौ डॉलर","ar":"سبعون ألفاً ومائتا دولار"}],"e":{"en":"Computed value = materials + fabrication + profit/general expenses + assist (apportioned) + packing. Assist for this shipment = $18,000 / 3 = $6,000. Total = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))","es":"Valor calculado = materiales + fabricación + ganancia/gastos generales + asistencia (prorrateada) + embalaje. Asistencia para este envío = $18,000 / 3 = $6,000. Total = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))","ru":"Исчисленная стоимость = материалы + изготовление + прибыль/общие расходы + дополнительное средство (распределенное) + упаковка. Дополнительное средство для данной партии = $18,000 / 3 = $6,000. Итого = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))","tr":"Hesaplanmış değer = malzemeler + imalat + kâr/genel giderler + yardım (dağıtılmış) + ambalaj. Bu sevkiyat için yardım = $18,000 / 3 = $6,000. Toplam = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))","hi":"गणना मूल्य = सामग्री + निर्माण + लाभ/सामान्य व्यय + सहायता (आवंटित) + पैकिंग। इस शिपमेंट के लिए सहायता = $18,000 / 3 = $6,000. कुल = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))","ar":"القيمة المحتسبة = المواد + التصنيع + الربح/المصروفات العامة + المساعدة (الموزعة) + التعبئة. المساعدة لهذه الشحنة = $18,000 / 3 = $6,000. الإجمالي = $40,000 + $15,000 + $11,000 + $6,000 + $1,200 = $73,200. (19 CFR 152.106(b))"}},{"cat":"valuation","a":3,"q":{"en":"In computed value, the 'amount for profit and general expenses' is generally:","es":"En el valor calculado, el 'monto por ganancia y gastos generales' es generalmente:","ru":"В исчисленной стоимости 'сумма на прибыль и общие расходы', как правило, представляет собой:","tr":"Hesaplanmış değerde, 'kâr ve genel giderler için tutar' genellikle:","hi":"गणना मूल्य में, 'लाभ और सामान्य व्यय के लिए राशि' आमतौर पर है:","ar":"في القيمة المحتسبة، فإن 'مبلغ الربح والمصروفات العامة' هو عموماً:"},"o":[{"en":"the worldwide average profit of all producers of the merchandise regardless of country","es":"la ganancia promedio mundial de todos los productores de la mercancía sin importar el país","ru":"среднемировую прибыль всех производителей товара независимо от страны","tr":"ülke fark etmeksizin malın tüm üreticilerinin dünya çapındaki ortalama kârı","hi":"देश की परवाह किए बिना माल के सभी उत्पादकों का विश्वव्यापी औसत लाभ","ar":"متوسط الربح العالمي لجميع منتجي البضاعة بصرف النظر عن البلد"},{"en":"the profit the U.S. importer expects to realize on resale of the merchandise in the United States","es":"la ganancia que el importador estadounidense espera obtener en la reventa de la mercancía en los Estados Unidos","ru":"прибыль, которую импортер в США рассчитывает получить при перепродаже товара в Соединенных Штатах","tr":"ABD ithalatçısının malın Amerika Birleşik Devletleri'nde yeniden satışından elde etmeyi beklediği kâr","hi":"वह लाभ जो अमेरिकी आयातकर्ता संयुक्त राज्य अमेरिका में माल की पुनर्बिक्री पर प्राप्त करने की अपेक्षा करता है","ar":"الربح الذي يتوقع المستورد الأمريكي تحقيقه عند إعادة بيع البضاعة في الولايات المتحدة"},{"en":"a fixed eight percent of the cost of materials and fabrication in every case","es":"un ocho por ciento fijo del costo de los materiales y la fabricación en todos los casos","ru":"фиксированные восемь процентов от стоимости материалов и изготовления в каждом случае","tr":"her durumda malzeme ve imalat maliyetinin sabit yüzde sekizi","hi":"हर मामले में सामग्री और निर्माण की लागत का निश्चित आठ प्रतिशत","ar":"نسبة ثابتة قدرها ثمانية بالمائة من تكلفة المواد والتصنيع في كل حالة"},{"en":"the amount usually reflected in sales of merchandise of the same class or kind as the imported merchandise made by producers in the country of exportation for export to the United States","es":"el monto que usualmente se refleja en las ventas de mercancía de la misma clase o tipo que la mercancía importada realizadas por productores en el país de exportación para exportación a los Estados Unidos","ru":"сумму, обычно отражаемую в продажах товара того же класса или вида, что и импортный товар, осуществляемых производителями в стране вывоза на экспорт в Соединенные Штаты","tr":"ihracatçı ülkedeki üreticiler tarafından Amerika Birleşik Devletleri'ne ihracat için yapılan, ithal malla aynı sınıf veya türden mal satışlarında genellikle yansıtılan tutar","hi":"निर्यातक देश में उत्पादकों द्वारा संयुक्त राज्य अमेरिका को निर्यात के लिए की गई आयातित माल के समान वर्ग या प्रकार के माल की बिक्री में आमतौर पर परिलक्षित राशि","ar":"المبلغ المنعكس عادةً في مبيعات البضاعة من نفس فئة أو نوع البضاعة المستوردة التي يجريها المنتجون في بلد التصدير للتصدير إلى الولايات المتحدة"}],"e":{"en":"Under computed value, the amount for profit and general expenses is that usually reflected in sales of merchandise of the same class or kind as the imported merchandise made by producers in the country of exportation for export to the United States, taken together. (19 CFR 152.106(b)(2))","es":"Bajo el valor calculado, el monto por ganancia y gastos generales es el que usualmente se refleja en las ventas de mercancía de la misma clase o tipo que la mercancía importada realizadas por productores en el país de exportación para exportación a los Estados Unidos, tomados en conjunto. (19 CFR 152.106(b)(2))","ru":"При исчисленной стоимости сумма на прибыль и общие расходы — это сумма, обычно отражаемая в продажах товара того же класса или вида, что и импортный товар, осуществляемых производителями в стране вывоза на экспорт в Соединенные Штаты, рассматриваемых в совокупности. (19 CFR 152.106(b)(2))","tr":"Hesaplanmış değer altında, kâr ve genel giderler için tutar, ihracatçı ülkedeki üreticiler tarafından Amerika Birleşik Devletleri'ne ihracat için yapılan, ithal malla aynı sınıf veya türden mal satışlarında genellikle yansıtılan, birlikte ele alınan tutardır. (19 CFR 152.106(b)(2))","hi":"गणना मूल्य के तहत, लाभ और सामान्य व्यय के लिए राशि वह है जो निर्यातक देश में उत्पादकों द्वारा संयुक्त राज्य अमेरिका को निर्यात के लिए की गई आयातित माल के समान वर्ग या प्रकार के माल की बिक्री में आमतौर पर परिलक्षित होती है, एक साथ ली गई। (19 CFR 152.106(b)(2))","ar":"بموجب القيمة المحتسبة، فإن مبلغ الربح والمصروفات العامة هو المبلغ المنعكس عادةً في مبيعات البضاعة من نفس فئة أو نوع البضاعة المستوردة التي يجريها المنتجون في بلد التصدير للتصدير إلى الولايات المتحدة، مأخوذة مجتمعةً. (19 CFR 152.106(b)(2))"}},{"cat":"valuation","a":0,"q":{"en":"In computed value, the producer's own figures show a LOW profit but HIGH general expenses. Which statement is correct?","es":"En el valor calculado, las propias cifras del productor muestran una ganancia BAJA pero gastos generales ALTOS. ¿Cuál afirmación es correcta?","ru":"В исчисленной стоимости собственные показатели производителя демонстрируют НИЗКУЮ прибыль, но ВЫСОКИЕ общие расходы. Какое утверждение верно?","tr":"Hesaplanmış değerde, üreticinin kendi rakamları DÜŞÜK kâr ancak YÜKSEK genel giderler gösterir. Hangi ifade doğrudur?","hi":"गणना मूल्य में, उत्पादक के अपने आंकड़े कम लाभ लेकिन उच्च सामान्य व्यय दिखाते हैं। कौन-सा कथन सही है?","ar":"في القيمة المحتسبة، تُظهر أرقام المنتج نفسه ربحاً منخفضاً ولكن مصروفات عامة مرتفعة. أي العبارات صحيحة؟"},"o":[{"en":"the producer's profit and general expenses figures, taken together, may still be accepted if consistent with those usually reflected in sales of merchandise of the same class or kind","es":"las cifras de ganancia y gastos generales del productor, tomadas en conjunto, aún pueden aceptarse si son consistentes con las que usualmente se reflejan en las ventas de mercancía de la misma clase o tipo","ru":"показатели прибыли и общих расходов производителя, рассматриваемые в совокупности, все же могут быть приняты, если они соответствуют тем, что обычно отражаются в продажах товара того же класса или вида","tr":"üreticinin kâr ve genel giderler rakamları, birlikte ele alındığında, aynı sınıf veya türden mal satışlarında genellikle yansıtılanlarla tutarlıysa yine de kabul edilebilir","hi":"उत्पादक के लाभ और सामान्य व्यय के आंकड़े, एक साथ लिए जाने पर, फिर भी स्वीकार किए जा सकते हैं यदि वे समान वर्ग या प्रकार के माल की बिक्री में आमतौर पर परिलक्षित होने वाले आंकड़ों के अनुरूप हों","ar":"أرقام الربح والمصروفات العامة للمنتج، مأخوذة مجتمعةً، قد تُقبل مع ذلك إذا كانت متسقة مع تلك المنعكسة عادةً في مبيعات البضاعة من نفس الفئة أو النوع"},{"en":"computed value cannot be used and the appraiser must revert to deductive value","es":"el valor calculado no puede usarse y el tasador debe revertir al valor deductivo","ru":"исчисленная стоимость не может использоваться, и оценщик должен вернуться к вычитаемой стоимости","tr":"hesaplanmış değer kullanılamaz ve değerleme uzmanı indirgenmiş değere dönmelidir","hi":"गणना मूल्य का उपयोग नहीं किया जा सकता और मूल्यांकनकर्ता को घटाव मूल्य पर लौटना चाहिए","ar":"لا يمكن استخدام القيمة المحتسبة ويجب على المثمّن العودة إلى القيمة الاستنتاجية"},{"en":"only the profit figure may be used and the general expenses figure must be discarded","es":"solo puede usarse la cifra de ganancia y la cifra de gastos generales debe descartarse","ru":"может использоваться только показатель прибыли, а показатель общих расходов должен быть отброшен","tr":"yalnızca kâr rakamı kullanılabilir ve genel giderler rakamı atılmalıdır","hi":"केवल लाभ का आंकड़ा उपयोग किया जा सकता है और सामान्य व्यय का आंकड़ा त्याग दिया जाना चाहिए","ar":"يجوز استخدام رقم الربح فقط ويجب استبعاد رقم المصروفات العامة"},{"en":"the producer's figures must be rejected because profit must always be at least the industry average","es":"las cifras del productor deben rechazarse porque la ganancia siempre debe ser al menos el promedio de la industria","ru":"показатели производителя должны быть отклонены, поскольку прибыль всегда должна быть не ниже среднеотраслевой","tr":"üreticinin rakamları reddedilmelidir çünkü kâr her zaman en az sektör ortalaması kadar olmalıdır","hi":"उत्पादक के आंकड़े अस्वीकार किए जाने चाहिए क्योंकि लाभ हमेशा कम से कम उद्योग औसत के बराबर होना चाहिए","ar":"يجب رفض أرقام المنتج لأن الربح يجب أن يكون دائماً على الأقل متوسط الصناعة"}],"e":{"en":"The profit and general expenses are considered as a whole; a producer's low profit and high general expenses (or vice versa) may nevertheless be consistent with figures usual in the industry, for example when a producer is introducing the merchandise or meeting low demand. (19 CFR 152.106(b)(2))","es":"La ganancia y los gastos generales se consideran en conjunto; la baja ganancia y los altos gastos generales de un productor (o viceversa) pueden, no obstante, ser consistentes con las cifras usuales en la industria, por ejemplo cuando un productor está introduciendo la mercancía o atendiendo una baja demanda. (19 CFR 152.106(b)(2))","ru":"Прибыль и общие расходы рассматриваются как единое целое; низкая прибыль и высокие общие расходы производителя (или наоборот) могут тем не менее соответствовать обычным для отрасли показателям, например когда производитель выводит товар на рынок или удовлетворяет низкий спрос. (19 CFR 152.106(b)(2))","tr":"Kâr ve genel giderler bir bütün olarak değerlendirilir; bir üreticinin düşük kârı ve yüksek genel giderleri (veya tersi), örneğin bir üretici malı piyasaya sürerken ya da düşük talebi karşılarken, yine de sektörde olağan rakamlarla tutarlı olabilir. (19 CFR 152.106(b)(2))","hi":"लाभ और सामान्य व्यय को एक संपूर्ण के रूप में माना जाता है; किसी उत्पादक का कम लाभ और उच्च सामान्य व्यय (या इसके विपरीत) फिर भी उद्योग में सामान्य आंकड़ों के अनुरूप हो सकता है, उदाहरण के लिए जब कोई उत्पादक माल पेश कर रहा हो या कम मांग को पूरा कर रहा हो। (19 CFR 152.106(b)(2))","ar":"يُنظر إلى الربح والمصروفات العامة ككل؛ فقد يكون انخفاض ربح المنتج وارتفاع مصروفاته العامة (أو العكس) متسقاً مع ذلك مع الأرقام المعتادة في الصناعة، على سبيل المثال عندما يطرح منتج البضاعة أو يلبي طلباً منخفضاً. (19 CFR 152.106(b)(2))"}},{"cat":"valuation","a":0,"q":{"en":"In computing computed value, the value of engineering, development, artwork, design work, and plans and sketches undertaken in the United States is treated how?","es":"Al calcular el valor calculado, ¿cómo se trata el valor de la ingeniería, el desarrollo, el trabajo artístico, el trabajo de diseño, y los planos y bocetos realizados en los Estados Unidos?","ru":"При расчете исчисленной стоимости как трактуется стоимость инженерных, опытно-конструкторских, художественных, дизайнерских работ, а также планов и эскизов, выполненных в Соединенных Штатах?","tr":"Hesaplanmış değeri hesaplarken, Amerika Birleşik Devletleri'nde gerçekleştirilen mühendislik, geliştirme, sanat çalışması, tasarım çalışması ile plan ve eskizlerin değeri nasıl ele alınır?","hi":"गणना मूल्य की गणना करते समय, संयुक्त राज्य अमेरिका में किए गए इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, और योजनाओं तथा रेखाचित्रों के मूल्य को कैसे माना जाता है?","ar":"عند احتساب القيمة المحتسبة، كيف تُعامل قيمة الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسوم التخطيطية المنفذة في الولايات المتحدة؟"},"o":[{"en":"it is included in computed value only to the extent its value has been charged to the producer","es":"se incluye en el valor calculado solo en la medida en que su valor se haya cargado al productor","ru":"она включается в исчисленную стоимость только в той мере, в какой ее стоимость была отнесена на счет производителя","tr":"değeri üreticiye yansıtıldığı ölçüde yalnızca hesaplanmış değere dâhil edilir","hi":"इसे गणना मूल्य में केवल उस सीमा तक शामिल किया जाता है जिस सीमा तक इसका मूल्य उत्पादक पर लगाया गया हो","ar":"تُدرَج في القيمة المحتسبة فقط بالقدر الذي حُمِّلت به قيمتها على المنتج"},{"en":"it is added at fifty percent of its value to reflect U.S. content","es":"se agrega al cincuenta por ciento de su valor para reflejar el contenido estadounidense","ru":"она добавляется в размере пятидесяти процентов своей стоимости для отражения американского содержания","tr":"ABD içeriğini yansıtmak için değerinin yüzde ellisi oranında eklenir","hi":"अमेरिकी सामग्री को दर्शाने के लिए इसे इसके मूल्य के पचास प्रतिशत पर जोड़ा जाता है","ar":"تُضاف بنسبة خمسين بالمائة من قيمتها لتعكس المحتوى الأمريكي"},{"en":"it is excluded only if performed by a foreign engineering firm","es":"se excluye solo si la realiza una empresa de ingeniería extranjera","ru":"она исключается только если выполнена иностранной инженерной фирмой","tr":"yalnızca yabancı bir mühendislik firması tarafından yapılırsa hariç tutulur","hi":"इसे केवल तभी बाहर रखा जाता है जब इसे किसी विदेशी इंजीनियरिंग फर्म द्वारा किया गया हो","ar":"تُستبعد فقط إذا نفذتها شركة هندسية أجنبية"},{"en":"it is always added in full as an assist regardless of where it was performed","es":"siempre se agrega en su totalidad como una asistencia independientemente de dónde se haya realizado","ru":"она всегда добавляется в полном объеме как дополнительное средство (assist) независимо от того, где она была выполнена","tr":"nerede yapıldığına bakılmaksızın her zaman yardım (assist) olarak tam değeriyle eklenir","hi":"इसे हमेशा सहायता (assist) के रूप में पूर्ण रूप से जोड़ा जाता है चाहे यह कहीं भी किया गया हो","ar":"تُضاف دائماً بالكامل كمساعدة (assist) بصرف النظر عن مكان تنفيذها"}],"e":{"en":"Under computed value, the value of engineering, development, artwork, design work, and plans and sketches undertaken in the United States is included only to the extent that such value has been charged to the producer. (19 CFR 152.106(c))","es":"Bajo el valor calculado, el valor de la ingeniería, el desarrollo, el trabajo artístico, el trabajo de diseño, y los planos y bocetos realizados en los Estados Unidos se incluye solo en la medida en que dicho valor se haya cargado al productor. (19 CFR 152.106(c))","ru":"При исчисленной стоимости стоимость инженерных, опытно-конструкторских, художественных, дизайнерских работ, а также планов и эскизов, выполненных в Соединенных Штатах, включается только в той мере, в какой такая стоимость была отнесена на счет производителя. (19 CFR 152.106(c))","tr":"Hesaplanmış değer altında, Amerika Birleşik Devletleri'nde gerçekleştirilen mühendislik, geliştirme, sanat çalışması, tasarım çalışması ile plan ve eskizlerin değeri, yalnızca bu değerin üreticiye yansıtıldığı ölçüde dâhil edilir. (19 CFR 152.106(c))","hi":"गणना मूल्य के तहत, संयुक्त राज्य अमेरिका में किए गए इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, और योजनाओं तथा रेखाचित्रों के मूल्य को केवल उस सीमा तक शामिल किया जाता है जिस सीमा तक ऐसा मूल्य उत्पादक पर लगाया गया हो। (19 CFR 152.106(c))","ar":"بموجب القيمة المحتسبة، تُدرَج قيمة الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط والرسوم التخطيطية المنفذة في الولايات المتحدة فقط بالقدر الذي حُمِّلت به تلك القيمة على المنتج. (19 CFR 152.106(c))"}},{"cat":"valuation","a":3,"q":{"en":"To be used as the transaction value of identical or similar merchandise, the comparison merchandise must have been:","es":"Para ser utilizada como el valor de transacción de mercancía idéntica o similar, la mercancía de comparación debe haber sido:","ru":"Чтобы использоваться в качестве стоимости сделки с идентичным или подобным товаром, сравниваемый товар должен был быть:","tr":"Aynı veya benzer malın işlem değeri olarak kullanılabilmesi için, karşılaştırma malı şu şekilde olmalıdır:","hi":"समान या सदृश माल के लेनदेन मूल्य के रूप में उपयोग किए जाने के लिए, तुलना वाला माल अवश्य ही:","ar":"لكي يُستخدم كقيمة معاملة لبضاعة مطابقة أو مماثلة، يجب أن تكون بضاعة المقارنة قد:"},"o":[{"en":"entered at the same U.S. port as the merchandise being appraised","es":"ingresada en el mismo puerto estadounidense que la mercancía que se valora","ru":"оформленным в том же порту США, что и оцениваемый товар","tr":"değerlenen malla aynı ABD limanından giriş yapmış","hi":"उसी अमेरिकी बंदरगाह पर प्रवेश किया गया जिसमें मूल्यांकन किया जा रहा माल है","ar":"أُدخِلت من نفس الميناء الأمريكي الذي أُدخِلت منه البضاعة الجاري تقييمها"},{"en":"produced in any country so long as it is the same class or kind, and sold at any time","es":"producida en cualquier país siempre que sea de la misma clase o tipo, y vendida en cualquier momento","ru":"произведенным в любой стране, лишь бы он был того же класса или вида, и проданным в любое время","tr":"aynı sınıf veya türden olduğu sürece herhangi bir ülkede üretilmiş ve herhangi bir zamanda satılmış","hi":"किसी भी देश में उत्पादित जब तक कि वह समान वर्ग या प्रकार का हो, और किसी भी समय बेचा गया","ar":"أُنتِجت في أي بلد طالما كانت من نفس الفئة أو النوع، وبيعت في أي وقت"},{"en":"sold to the same U.S. importer that is importing the merchandise being appraised","es":"vendida al mismo importador estadounidense que está importando la mercancía que se valora","ru":"проданным тому же импортеру в США, который ввозит оцениваемый товар","tr":"değerlenen malı ithal eden aynı ABD ithalatçısına satılmış","hi":"उसी अमेरिकी आयातकर्ता को बेचा गया जो मूल्यांकन किए जा रहे माल का आयात कर रहा है","ar":"بيعت لنفس المستورد الأمريكي الذي يستورد البضاعة الجاري تقييمها"},{"en":"produced in the same country as, and exported to the United States at or about the same time as, the merchandise being appraised","es":"producida en el mismo país que la mercancía que se valora, y exportada a los Estados Unidos en la misma fecha o cerca de ella que dicha mercancía","ru":"произведенным в той же стране, что и оцениваемый товар, и вывезенным в Соединенные Штаты в то же время или примерно тогда же, что и оцениваемый товар","tr":"değerlenen malla aynı ülkede üretilmiş ve değerlenen malla aynı veya yaklaşık aynı zamanda Amerika Birleşik Devletleri'ne ihraç edilmiş","hi":"उसी देश में उत्पादित जिसमें मूल्यांकन किया जा रहा माल है, और मूल्यांकन किए जा रहे माल के समान या लगभग समान समय पर संयुक्त राज्य अमेरिका को निर्यात किया गया","ar":"أُنتِجت في نفس بلد البضاعة الجاري تقييمها، وصُدِّرت إلى الولايات المتحدة في نفس وقت تصدير البضاعة الجاري تقييمها أو ما يقاربه"}],"e":{"en":"Transaction value of identical or similar merchandise requires merchandise produced in the same country and by the same person, exported to the United States at or about the same time as the merchandise being appraised, and previously appraised under transaction value. (19 CFR 152.104(a); 152.102(d), (i))","es":"El valor de transacción de mercancía idéntica o similar requiere mercancía producida en el mismo país y por la misma persona, exportada a los Estados Unidos en la misma fecha o cerca de ella que la mercancía que se valora, y previamente valorada bajo valor de transacción. (19 CFR 152.104(a); 152.102(d), (i))","ru":"Стоимость сделки с идентичным или подобным товаром требует товара, произведенного в той же стране и тем же лицом, вывезенного в Соединенные Штаты в то же время или примерно тогда же, что и оцениваемый товар, и ранее оцененного по стоимости сделки. (19 CFR 152.104(a); 152.102(d), (i))","tr":"Aynı veya benzer malın işlem değeri, aynı ülkede ve aynı kişi tarafından üretilmiş, değerlenen malla aynı veya yaklaşık aynı zamanda Amerika Birleşik Devletleri'ne ihraç edilmiş ve daha önce işlem değeri altında değerlenmiş mal gerektirir. (19 CFR 152.104(a); 152.102(d), (i))","hi":"समान या सदृश माल का लेनदेन मूल्य ऐसे माल की आवश्यकता रखता है जो उसी देश में और उसी व्यक्ति द्वारा उत्पादित हो, मूल्यांकन किए जा रहे माल के समान या लगभग समान समय पर संयुक्त राज्य अमेरिका को निर्यात किया गया हो, और पहले लेनदेन मूल्य के तहत मूल्यांकित किया गया हो। (19 CFR 152.104(a); 152.102(d), (i))","ar":"تتطلب قيمة المعاملة لبضاعة مطابقة أو مماثلة بضاعةً أُنتِجت في نفس البلد وبواسطة نفس الشخص، وصُدِّرت إلى الولايات المتحدة في نفس وقت تصدير البضاعة الجاري تقييمها أو ما يقاربه، وسبق تقييمها بموجب قيمة المعاملة. (19 CFR 152.104(a); 152.102(d), (i))"}},{"cat":"valuation","a":3,"q":{"en":"Transaction values of identical or similar merchandise are to be based on sales at the same commercial level and in substantially the same quantity. If no such sale exists, the appraiser may use a sale at a different commercial level or quantity. In that case, the appraiser must:","es":"Los valores de transacción de mercancía idéntica o similar deben basarse en ventas al mismo nivel comercial y en sustancialmente la misma cantidad. Si no existe tal venta, el tasador puede usar una venta a un nivel comercial o cantidad diferente. En ese caso, el tasador debe:","ru":"Стоимости сделок с идентичным или подобным товаром должны основываться на продажах на том же коммерческом уровне и практически в том же количестве. Если такой продажи нет, оценщик может использовать продажу на ином коммерческом уровне или в ином количестве. В этом случае оценщик должен:","tr":"Aynı veya benzer malın işlem değerleri, aynı ticari düzeyde ve esasen aynı miktarda satışlara dayandırılmalıdır. Böyle bir satış yoksa, değerleme uzmanı farklı bir ticari düzeyde veya miktarda bir satış kullanabilir. Bu durumda, değerleme uzmanı:","hi":"समान या सदृश माल के लेनदेन मूल्य समान वाणिज्यिक स्तर पर और काफी हद तक समान मात्रा में बिक्री पर आधारित होने चाहिए। यदि ऐसी कोई बिक्री मौजूद नहीं है, तो मूल्यांकनकर्ता भिन्न वाणिज्यिक स्तर या मात्रा पर बिक्री का उपयोग कर सकता है। उस स्थिति में, मूल्यांकनकर्ता को अवश्य:","ar":"يجب أن تستند قيم المعاملة لبضاعة مطابقة أو مماثلة إلى مبيعات بنفس المستوى التجاري وبكمية مماثلة إلى حد كبير. وإذا لم توجد مثل هذه المبيعات، يجوز للمثمّن استخدام بيع بمستوى تجاري أو كمية مختلفة. وفي تلك الحالة، يجب على المثمّن:"},"o":[{"en":"reject the method entirely and proceed to deductive value","es":"rechazar el método por completo y proceder al valor deductivo","ru":"полностью отклонить этот метод и перейти к вычитаемой стоимости","tr":"yöntemi tamamen reddetmeli ve indirgenmiş değere geçmeli","hi":"पद्धति को पूरी तरह अस्वीकार करना और घटाव मूल्य की ओर बढ़ना","ar":"أن يرفض الطريقة بالكامل وينتقل إلى القيمة الاستنتاجية"},{"en":"add a flat ten percent to the value to account for the difference","es":"agregar un diez por ciento fijo al valor para tener en cuenta la diferencia","ru":"добавить фиксированные десять процентов к стоимости для учета разницы","tr":"farkı hesaba katmak için değere sabit yüzde on eklemeli","hi":"अंतर को ध्यान में रखने के लिए मूल्य में निश्चित दस प्रतिशत जोड़ना","ar":"أن يضيف نسبة ثابتة قدرها عشرة بالمائة إلى القيمة لمراعاة الفرق"},{"en":"use the sale without any change because commercial level is irrelevant","es":"usar la venta sin ningún cambio porque el nivel comercial es irrelevante","ru":"использовать продажу без каких-либо изменений, поскольку коммерческий уровень не имеет значения","tr":"ticari düzey önemsiz olduğundan satışı herhangi bir değişiklik yapmadan kullanmalı","hi":"बिक्री को बिना किसी बदलाव के उपयोग करना क्योंकि वाणिज्यिक स्तर अप्रासंगिक है","ar":"أن يستخدم البيع دون أي تغيير لأن المستوى التجاري غير ذي صلة"},{"en":"adjust the value to take account of the difference in commercial level or quantity, based on sufficient information such as valid price lists","es":"ajustar el valor para tener en cuenta la diferencia en el nivel comercial o la cantidad, basándose en información suficiente como listas de precios válidas","ru":"скорректировать стоимость с учетом разницы в коммерческом уровне или количестве на основе достаточной информации, такой как действительные прайс-листы","tr":"geçerli fiyat listeleri gibi yeterli bilgilere dayanarak ticari düzey veya miktar farkını dikkate almak için değeri ayarlamalı","hi":"वैध मूल्य सूचियों जैसी पर्याप्त जानकारी के आधार पर वाणिज्यिक स्तर या मात्रा में अंतर को ध्यान में रखते हुए मूल्य को समायोजित करना","ar":"أن يُعدِّل القيمة لمراعاة الفرق في المستوى التجاري أو الكمية، استناداً إلى معلومات كافية مثل قوائم الأسعار الصالحة"}],"e":{"en":"Where sales at the same commercial level and substantially the same quantity are unavailable, sales at a different commercial level or quantity (or both) may be used but must be adjusted to account for the difference, demonstrated by sufficient information (for example, valid price lists). (19 CFR 152.104(c), (d))","es":"Cuando no hay ventas disponibles al mismo nivel comercial y sustancialmente la misma cantidad, pueden usarse ventas a un nivel comercial o cantidad diferente (o ambos), pero deben ajustarse para tener en cuenta la diferencia, demostrada mediante información suficiente (por ejemplo, listas de precios válidas). (19 CFR 152.104(c), (d))","ru":"Когда продажи на том же коммерческом уровне и практически в том же количестве недоступны, могут использоваться продажи на ином коммерческом уровне или в ином количестве (либо и то, и другое), но они должны быть скорректированы для учета разницы, подтвержденной достаточной информацией (например, действительными прайс-листами). (19 CFR 152.104(c), (d))","tr":"Aynı ticari düzeyde ve esasen aynı miktarda satışların bulunmadığı durumlarda, farklı bir ticari düzey veya miktardaki (ya da her ikisindeki) satışlar kullanılabilir, ancak yeterli bilgiyle (örneğin geçerli fiyat listeleriyle) gösterilen farkı hesaba katmak için ayarlanmalıdır. (19 CFR 152.104(c), (d))","hi":"जहाँ समान वाणिज्यिक स्तर और काफी हद तक समान मात्रा में बिक्री उपलब्ध नहीं है, वहाँ भिन्न वाणिज्यिक स्तर या मात्रा (या दोनों) पर बिक्री का उपयोग किया जा सकता है लेकिन अंतर को ध्यान में रखने के लिए इसे समायोजित किया जाना चाहिए, जो पर्याप्त जानकारी (उदाहरण के लिए, वैध मूल्य सूचियाँ) द्वारा प्रदर्शित हो। (19 CFR 152.104(c), (d))","ar":"حيثما لا تتوفر مبيعات بنفس المستوى التجاري وبكمية مماثلة إلى حد كبير، يجوز استخدام مبيعات بمستوى تجاري أو كمية مختلفة (أو كليهما) ولكن يجب تعديلها لمراعاة الفرق، المُثبَت بمعلومات كافية (على سبيل المثال، قوائم أسعار صالحة). (19 CFR 152.104(c), (d))"}},{"cat":"valuation","a":1,"q":{"en":"If, in applying the transaction value of identical or similar merchandise, two or more qualifying transaction values are found, the merchandise being appraised is valued on the basis of:","es":"Si, al aplicar el valor de transacción de mercancía idéntica o similar, se encuentran dos o más valores de transacción que califican, la mercancía que se valora se valora sobre la base de:","ru":"Если при применении стоимости сделки с идентичным или подобным товаром обнаруживаются две или более подходящие стоимости сделки, оцениваемый товар оценивается на основе:","tr":"Aynı veya benzer malın işlem değeri uygulanırken, iki veya daha fazla uygun işlem değeri bulunursa, değerlenen mal şunun esasına göre değerlenir:","hi":"यदि समान या सदृश माल के लेनदेन मूल्य को लागू करते समय, दो या अधिक योग्य लेनदेन मूल्य पाए जाते हैं, तो मूल्यांकन किए जा रहे माल का मूल्यांकन इस आधार पर किया जाता है:","ar":"إذا وُجِدت، عند تطبيق قيمة المعاملة لبضاعة مطابقة أو مماثلة، قيمتا معاملة مؤهلتان أو أكثر، فإن البضاعة الجاري تقييمها تُقيَّم على أساس:"},"o":[{"en":"the most recent of the qualifying values","es":"el más reciente de los valores que califican","ru":"самой недавней из подходящих стоимостей","tr":"uygun değerlerin en günceli","hi":"योग्य मूल्यों में से सबसे हालिया","ar":"أحدث القيم المؤهلة"},{"en":"the lowest of the qualifying values","es":"el más bajo de los valores que califican","ru":"наименьшей из подходящих стоимостей","tr":"uygun değerlerin en düşüğü","hi":"योग्य मूल्यों में से सबसे कम","ar":"أدنى القيم المؤهلة"},{"en":"the highest of the qualifying values","es":"el más alto de los valores que califican","ru":"наибольшей из подходящих стоимостей","tr":"uygun değerlerin en yükseği","hi":"योग्य मूल्यों में से सबसे अधिक","ar":"أعلى القيم المؤهلة"},{"en":"the average of all the qualifying values","es":"el promedio de todos los valores que califican","ru":"среднего значения всех подходящих стоимостей","tr":"tüm uygun değerlerin ortalaması","hi":"सभी योग्य मूल्यों का औसत","ar":"متوسط جميع القيم المؤهلة"}],"e":{"en":"If two or more transaction values for identical merchandise, or for similar merchandise, are determined, the merchandise is appraised on the basis of the lower or lowest of those values. (19 CFR 152.104(e))","es":"Si se determinan dos o más valores de transacción para mercancía idéntica, o para mercancía similar, la mercancía se valora sobre la base del menor o el más bajo de esos valores. (19 CFR 152.104(e))","ru":"Если определены две или более стоимости сделки для идентичного товара или для подобного товара, товар оценивается на основе меньшей или наименьшей из этих стоимостей. (19 CFR 152.104(e))","tr":"Aynı mal veya benzer mal için iki veya daha fazla işlem değeri belirlenirse, mal bu değerlerin daha düşüğü veya en düşüğü esasına göre değerlenir. (19 CFR 152.104(e))","hi":"यदि समान माल, या सदृश माल के लिए दो या अधिक लेनदेन मूल्य निर्धारित किए जाते हैं, तो माल का मूल्यांकन उन मूल्यों में से निचले या सबसे निचले के आधार पर किया जाता है। (19 CFR 152.104(e))","ar":"إذا تم تحديد قيمتي معاملة أو أكثر لبضاعة مطابقة أو لبضاعة مماثلة، تُقيَّم البضاعة على أساس الأدنى أو أدنى تلك القيم. (19 CFR 152.104(e))"}},{"cat":"valuation","a":1,"q":{"en":"Merchandise is being appraised under the transaction value of identical merchandise. The only available identical-merchandise sale was at a higher commercial level and in a smaller quantity, with a transaction value of fifty-two dollars per unit. The producer's valid published price list shows that at the commercial level and quantity of the merchandise being appraised (one thousand units), the proper price is forty-eight dollars per unit. What is the appraised value of the shipment?","es":"La mercancía se valora bajo el valor de transacción de mercancía idéntica. La única venta de mercancía idéntica disponible fue a un nivel comercial superior y en una cantidad menor, con un valor de transacción de cincuenta y dos dólares por unidad. La lista de precios publicada válida del productor muestra que al nivel comercial y la cantidad de la mercancía que se valora (mil unidades), el precio correcto es cuarenta y ocho dólares por unidad. ¿Cuál es el valor de tasación del envío?","ru":"Товар оценивается по стоимости сделки с идентичным товаром. Единственная доступная продажа идентичного товара была на более высоком коммерческом уровне и в меньшем количестве, со стоимостью сделки пятьдесят два доллара за единицу. Действительный опубликованный прайс-лист производителя показывает, что на коммерческом уровне и в количестве оцениваемого товара (тысяча единиц) надлежащая цена составляет сорок восемь долларов за единицу. Какова оценочная стоимость партии?","tr":"Mal, aynı malın işlem değeri altında değerlenmektedir. Mevcut tek aynı mal satışı, daha yüksek bir ticari düzeyde ve daha küçük bir miktarda olup, birim başına elli iki dolar işlem değerine sahipti. Üreticinin geçerli yayımlanmış fiyat listesi, değerlenen malın ticari düzeyi ve miktarında (bin birim) doğru fiyatın birim başına kırk sekiz dolar olduğunu göstermektedir. Sevkiyatın değerlenen değeri nedir?","hi":"माल का मूल्यांकन समान माल के लेनदेन मूल्य के तहत किया जा रहा है। समान-माल की एकमात्र उपलब्ध बिक्री उच्च वाणिज्यिक स्तर पर और छोटी मात्रा में थी, जिसका लेनदेन मूल्य प्रति इकाई बावन डॉलर था। उत्पादक की वैध प्रकाशित मूल्य सूची दिखाती है कि मूल्यांकन किए जा रहे माल के वाणिज्यिक स्तर और मात्रा (एक हजार इकाइयाँ) पर, उचित मूल्य प्रति इकाई अड़तालीस डॉलर है। शिपमेंट का मूल्यांकित मूल्य क्या है?","ar":"تُقيَّم البضاعة بموجب قيمة المعاملة لبضاعة مطابقة. كان البيع الوحيد المتاح لبضاعة مطابقة عند مستوى تجاري أعلى وبكمية أصغر، بقيمة معاملة قدرها اثنان وخمسون دولاراً للوحدة. وتُظهر قائمة الأسعار المنشورة الصالحة للمنتج أنه عند المستوى التجاري وكمية البضاعة الجاري تقييمها (ألف وحدة)، يكون السعر الصحيح ثمانية وأربعين دولاراً للوحدة. ما هي القيمة المُثمَّنة للشحنة؟"},"o":[{"en":"fifty-two thousand dollars","es":"cincuenta y dos mil dólares","ru":"пятьдесят две тысячи долларов","tr":"elli iki bin dolar","hi":"बावन हजार डॉलर","ar":"اثنان وخمسون ألف دولار"},{"en":"forty-eight thousand dollars","es":"cuarenta y ocho mil dólares","ru":"сорок восемь тысяч долларов","tr":"kırk sekiz bin dolar","hi":"अड़तालीस हजार डॉलर","ar":"ثمانية وأربعون ألف دولار"},{"en":"fifty thousand dollars","es":"cincuenta mil dólares","ru":"пятьдесят тысяч долларов","tr":"elli bin dolar","hi":"पचास हजार डॉलर","ar":"خمسون ألف دولار"},{"en":"fifty-six thousand dollars","es":"cincuenta y seis mil dólares","ru":"пятьдесят шесть тысяч долларов","tr":"elli altı bin dolar","hi":"छप्पन हजार डॉलर","ar":"ستة وخمسون ألف دولار"}],"e":{"en":"The $52 value must be adjusted to the appraised merchandise's commercial level and quantity using the valid price list, giving $48 per unit. For 1,000 units: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))","es":"El valor de $52 debe ajustarse al nivel comercial y la cantidad de la mercancía que se valora usando la lista de precios válida, dando $48 por unidad. Para 1,000 unidades: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))","ru":"Стоимость $52 должна быть скорректирована к коммерческому уровню и количеству оцениваемого товара с использованием действительного прайс-листа, что дает $48 за единицу. Для 1,000 единиц: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))","tr":"$52 değeri, geçerli fiyat listesi kullanılarak değerlenen malın ticari düzeyine ve miktarına göre ayarlanmalı ve birim başına $48 verilmelidir. 1,000 birim için: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))","hi":"$52 मूल्य को वैध मूल्य सूची का उपयोग करके मूल्यांकन किए जा रहे माल के वाणिज्यिक स्तर और मात्रा के अनुसार समायोजित किया जाना चाहिए, जिससे प्रति इकाई $48 मिलता है। 1,000 इकाइयों के लिए: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))","ar":"يجب تعديل قيمة $52 إلى المستوى التجاري وكمية البضاعة الجاري تقييمها باستخدام قائمة الأسعار الصالحة، مما يعطي $48 للوحدة. لـ 1,000 وحدة: 48 x 1,000 = $48,000. (19 CFR 152.104(c), (d))"}},{"cat":"valuation","a":0,"q":{"en":"Which of the following best states the rule for a transaction value between related parties?","es":"¿Cuál de las siguientes enuncia mejor la regla para un valor de transacción entre partes relacionadas?","ru":"Что из перечисленного лучше всего формулирует правило для стоимости сделки между связанными сторонами?","tr":"Aşağıdakilerden hangisi ilişkili taraflar arasındaki işlem değerine ilişkin kuralı en iyi şekilde ifade eder?","hi":"निम्नलिखित में से कौन-सा संबंधित पक्षों के बीच लेनदेन मूल्य के नियम को सर्वोत्तम रूप से बताता है?","ar":"أي مما يلي يبيّن على أفضل وجه القاعدة الخاصة بقيمة المعاملة بين أطراف مرتبطة؟"},"o":[{"en":"transaction value is not rejected solely because the parties are related; it is acceptable if the relationship did not influence the price, or the value closely approximates a test value","es":"el valor de transacción no se rechaza únicamente porque las partes estén relacionadas; es aceptable si la relación no influyó en el precio, o el valor se aproxima estrechamente a un valor de prueba","ru":"стоимость сделки не отклоняется лишь потому, что стороны связаны; она приемлема, если связь не повлияла на цену или если стоимость близко приближается к проверочной стоимости","tr":"işlem değeri yalnızca taraflar ilişkili olduğu için reddedilmez; ilişki fiyatı etkilemediyse veya değer bir test değerine yakın şekilde yaklaşıyorsa kabul edilebilir","hi":"लेनदेन मूल्य केवल इसलिए अस्वीकार नहीं किया जाता क्योंकि पक्ष संबंधित हैं; यह स्वीकार्य है यदि संबंध ने मूल्य को प्रभावित नहीं किया, या मूल्य किसी परीक्षण मूल्य के निकट आता है","ar":"لا تُرفض قيمة المعاملة لمجرد أن الأطراف مرتبطة؛ فهي مقبولة إذا لم تؤثر العلاقة في السعر، أو إذا كانت القيمة تقترب بشكل وثيق من قيمة اختبارية"},{"en":"transaction value is acceptable only if the importer holds an advance ruling from CBP","es":"el valor de transacción es aceptable solo si el importador tiene una resolución anticipada de CBP","ru":"стоимость сделки приемлема только если у импортера есть предварительное решение от CBP","tr":"işlem değeri yalnızca ithalatçının CBP'den bir ön karar (advance ruling) almış olması durumunda kabul edilebilir","hi":"लेनदेन मूल्य केवल तभी स्वीकार्य है यदि आयातकर्ता के पास CBP से अग्रिम निर्णय (advance ruling) हो","ar":"تكون قيمة المعاملة مقبولة فقط إذا كان لدى المستورد قرار مسبق (advance ruling) من CBP"},{"en":"the relationship is disregarded entirely and the price is always accepted as filed","es":"la relación se ignora por completo y el precio siempre se acepta tal como se declaró","ru":"связь полностью игнорируется, и цена всегда принимается в том виде, в каком заявлена","tr":"ilişki tamamen göz ardı edilir ve fiyat her zaman beyan edildiği şekliyle kabul edilir","hi":"संबंध को पूरी तरह नज़रअंदाज़ किया जाता है और मूल्य हमेशा दाखिल किए अनुसार स्वीकार किया जाता है","ar":"تُتجاهل العلاقة بالكامل ويُقبل السعر دائماً كما هو مُقدَّم"},{"en":"transaction value between related parties is automatically rejected and computed value must be used","es":"el valor de transacción entre partes relacionadas se rechaza automáticamente y debe usarse el valor calculado","ru":"стоимость сделки между связанными сторонами автоматически отклоняется, и должна использоваться исчисленная стоимость","tr":"ilişkili taraflar arasındaki işlem değeri otomatik olarak reddedilir ve hesaplanmış değer kullanılmalıdır","hi":"संबंधित पक्षों के बीच लेनदेन मूल्य स्वतः अस्वीकार कर दिया जाता है और गणना मूल्य का उपयोग किया जाना चाहिए","ar":"تُرفض قيمة المعاملة بين الأطراف المرتبطة تلقائياً ويجب استخدام القيمة المحتسبة"}],"e":{"en":"A transaction value is not disregarded solely because the buyer and seller are related. It is acceptable if an examination of the circumstances of sale shows the relationship did not influence the price, or if the value closely approximates a test value. (19 CFR 152.103(j), (l))","es":"Un valor de transacción no se ignora únicamente porque el comprador y el vendedor estén relacionados. Es aceptable si un examen de las circunstancias de la venta muestra que la relación no influyó en el precio, o si el valor se aproxima estrechamente a un valor de prueba. (19 CFR 152.103(j), (l))","ru":"Стоимость сделки не игнорируется лишь потому, что покупатель и продавец связаны. Она приемлема, если изучение обстоятельств продажи показывает, что связь не повлияла на цену, или если стоимость близко приближается к проверочной стоимости. (19 CFR 152.103(j), (l))","tr":"Bir işlem değeri, yalnızca alıcı ve satıcının ilişkili olması nedeniyle göz ardı edilmez. Satış koşullarının incelenmesi ilişkinin fiyatı etkilemediğini gösteriyorsa veya değer bir test değerine yakın şekilde yaklaşıyorsa kabul edilebilir. (19 CFR 152.103(j), (l))","hi":"किसी लेनदेन मूल्य को केवल इसलिए नज़रअंदाज़ नहीं किया जाता क्योंकि खरीदार और विक्रेता संबंधित हैं। यह स्वीकार्य है यदि बिक्री की परिस्थितियों की जाँच दिखाती है कि संबंध ने मूल्य को प्रभावित नहीं किया, या यदि मूल्य किसी परीक्षण मूल्य के निकट आता है। (19 CFR 152.103(j), (l))","ar":"لا تُتجاهل قيمة المعاملة لمجرد أن المشتري والبائع مرتبطان. فهي مقبولة إذا أظهر فحص ظروف البيع أن العلاقة لم تؤثر في السعر، أو إذا كانت القيمة تقترب بشكل وثيق من قيمة اختبارية. (19 CFR 152.103(j), (l))"}},{"cat":"valuation","a":1,"q":{"en":"Which of the following is a 'test value' that a related-party importer may use to show its transaction value is acceptable?","es":"¿Cuál de las siguientes es un 'valor de prueba' que un importador de parte relacionada puede usar para demostrar que su valor de transacción es aceptable?","ru":"Что из перечисленного является 'проверочной стоимостью', которую импортер от связанной стороны может использовать, чтобы показать, что его стоимость сделки приемлема?","tr":"Aşağıdakilerden hangisi, ilişkili taraf konumundaki bir ithalatçının işlem değerinin kabul edilebilir olduğunu göstermek için kullanabileceği bir 'test değeri'dir?","hi":"निम्नलिखित में से कौन-सा एक 'परीक्षण मूल्य' है जिसका उपयोग संबंधित-पक्ष आयातकर्ता यह दिखाने के लिए कर सकता है कि उसका लेनदेन मूल्य स्वीकार्य है?","ar":"أي مما يلي يُعدّ 'قيمة اختبارية' يجوز لمستورد طرف مرتبط استخدامها لإثبات أن قيمة معاملته مقبولة؟"},"o":[{"en":"the published list price of the merchandise in any third country","es":"el precio de lista publicado de la mercancía en cualquier tercer país","ru":"опубликованная прейскурантная цена товара в любой третьей стране","tr":"malın herhangi bir üçüncü ülkedeki yayımlanmış liste fiyatı","hi":"किसी भी तीसरे देश में माल का प्रकाशित सूची मूल्य","ar":"سعر القائمة المنشور للبضاعة في أي بلد ثالث"},{"en":"the deductive value or computed value of identical merchandise or of similar merchandise","es":"el valor deductivo o el valor calculado de mercancía idéntica o de mercancía similar","ru":"вычитаемая стоимость или исчисленная стоимость идентичного товара или подобного товара","tr":"aynı malın veya benzer malın indirgenmiş değeri ya da hesaplanmış değeri","hi":"समान माल या सदृश माल का घटाव मूल्य या गणना मूल्य","ar":"القيمة الاستنتاجية أو القيمة المحتسبة لبضاعة مطابقة أو لبضاعة مماثلة"},{"en":"the price the importer charges to its own affiliated distributor in the United States","es":"el precio que el importador cobra a su propio distribuidor afiliado en los Estados Unidos","ru":"цена, которую импортер взимает со своего собственного аффилированного дистрибьютора в Соединенных Штатах","tr":"ithalatçının Amerika Birleşik Devletleri'ndeki kendi bağlı distribütörüne uyguladığı fiyat","hi":"वह मूल्य जो आयातकर्ता संयुक्त राज्य अमेरिका में अपने स्वयं के संबद्ध वितरक से वसूलता है","ar":"السعر الذي يفرضه المستورد على موزّعه التابع له في الولايات المتحدة"},{"en":"the wholesale price of the merchandise in the country of exportation","es":"el precio mayorista de la mercancía en el país de exportación","ru":"оптовая цена товара в стране вывоза","tr":"malın ihracatçı ülkedeki toptan fiyatı","hi":"निर्यातक देश में माल का थोक मूल्य","ar":"سعر الجملة للبضاعة في بلد التصدير"}],"e":{"en":"Test values include the transaction value of identical or similar merchandise in sales to unrelated buyers, and the deductive value or computed value of identical or similar merchandise, for merchandise exported at or about the same time. (19 CFR 152.103(j)(2)(i), (l))","es":"Los valores de prueba incluyen el valor de transacción de mercancía idéntica o similar en ventas a compradores no relacionados, y el valor deductivo o el valor calculado de mercancía idéntica o similar, para mercancía exportada en la misma fecha o cerca de ella. (19 CFR 152.103(j)(2)(i), (l))","ru":"Проверочные стоимости включают стоимость сделки с идентичным или подобным товаром в продажах несвязанным покупателям, а также вычитаемую стоимость или исчисленную стоимость идентичного или подобного товара для товара, вывезенного в то же время или примерно тогда же. (19 CFR 152.103(j)(2)(i), (l))","tr":"Test değerleri, ilişkisiz alıcılara yapılan satışlarda aynı veya benzer malın işlem değerini ve aynı veya yaklaşık aynı zamanda ihraç edilen mal için aynı veya benzer malın indirgenmiş değeri ya da hesaplanmış değerini içerir. (19 CFR 152.103(j)(2)(i), (l))","hi":"परीक्षण मूल्यों में असंबंधित खरीदारों को बिक्री में समान या सदृश माल का लेनदेन मूल्य, और समान या लगभग समान समय पर निर्यात किए गए माल के लिए समान या सदृश माल का घटाव मूल्य या गणना मूल्य शामिल हैं। (19 CFR 152.103(j)(2)(i), (l))","ar":"تشمل القيم الاختبارية قيمة المعاملة لبضاعة مطابقة أو مماثلة في مبيعات لمشترين غير مرتبطين، والقيمة الاستنتاجية أو القيمة المحتسبة لبضاعة مطابقة أو مماثلة، لبضاعة صُدِّرت في نفس الوقت أو ما يقاربه. (19 CFR 152.103(j)(2)(i), (l))"}},{"cat":"valuation","a":2,"q":{"en":"When CBP examines the 'circumstances of the sale' to test a related-party price, which fact would tend to support that the relationship did NOT influence the price?","es":"Cuando CBP examina las 'circunstancias de la venta' para probar un precio de parte relacionada, ¿qué hecho tendería a respaldar que la relación NO influyó en el precio?","ru":"Когда CBP изучает 'обстоятельства продажи' для проверки цены связанной стороны, какой факт скорее всего подтвердит, что связь НЕ повлияла на цену?","tr":"CBP, ilişkili taraf fiyatını test etmek için 'satış koşullarını' incelediğinde, hangi olgu ilişkinin fiyatı etkilemeDİĞİNİ destekleme eğiliminde olur?","hi":"जब CBP किसी संबंधित-पक्ष मूल्य का परीक्षण करने के लिए 'बिक्री की परिस्थितियों' की जाँच करता है, तो कौन-सा तथ्य इस बात का समर्थन करने की प्रवृत्ति रखेगा कि संबंध ने मूल्य को प्रभावित नहीं किया?","ar":"عندما تفحص CBP 'ظروف البيع' لاختبار سعر طرف مرتبط، أي حقيقة تميل إلى دعم أن العلاقة لم تؤثر في السعر؟"},"o":[{"en":"the price was set so that the seller would recover all costs plus a profit far below its overall corporate profit","es":"el precio se fijó de modo que el vendedor recuperara todos los costos más una ganancia muy por debajo de su ganancia corporativa general","ru":"цена была установлена так, чтобы продавец возместил все издержки плюс прибыль, значительно ниже его общей корпоративной прибыли","tr":"fiyat, satıcının tüm maliyetleri ve genel kurumsal kârının çok altında bir kâr elde edecek şekilde belirlendi","hi":"मूल्य इस प्रकार निर्धारित किया गया था कि विक्रेता सभी लागतों के साथ-साथ अपने समग्र कॉर्पोरेट लाभ से काफी कम लाभ वसूल करे","ar":"حُدِّد السعر بحيث يسترد البائع جميع التكاليف بالإضافة إلى ربح أقل بكثير من ربحه المؤسسي الإجمالي"},{"en":"the seller adjusted the price downward to recover only its own costs from the related buyer","es":"el vendedor ajustó el precio a la baja para recuperar solo sus propios costos del comprador relacionado","ru":"продавец снизил цену, чтобы возместить от связанного покупателя только свои собственные издержки","tr":"satıcı, ilişkili alıcıdan yalnızca kendi maliyetlerini geri almak için fiyatı aşağı yönlü ayarladı","hi":"विक्रेता ने संबंधित खरीदार से केवल अपनी लागत वसूल करने के लिए मूल्य को नीचे की ओर समायोजित किया","ar":"خفّض البائع السعر لاسترداد تكاليفه الخاصة فقط من المشتري المرتبط"},{"en":"the price was set in a manner consistent with the normal pricing practices of the industry in question","es":"el precio se fijó de una manera consistente con las prácticas normales de fijación de precios de la industria en cuestión","ru":"цена была установлена способом, соответствующим обычной практике ценообразования в данной отрасли","tr":"fiyat, söz konusu sektörün normal fiyatlandırma uygulamalarıyla tutarlı bir şekilde belirlendi","hi":"मूल्य संबंधित उद्योग की सामान्य मूल्य-निर्धारण प्रथाओं के अनुरूप तरीके से निर्धारित किया गया था","ar":"حُدِّد السعر بطريقة متسقة مع ممارسات التسعير العادية للصناعة المعنية"},{"en":"the buyer and seller share common officers and directors","es":"el comprador y el vendedor comparten funcionarios y directores comunes","ru":"у покупателя и продавца общие должностные лица и директора","tr":"alıcı ve satıcı ortak yöneticilere ve müdürlere sahiptir","hi":"खरीदार और विक्रेता के समान अधिकारी और निदेशक हैं","ar":"يتشارك المشتري والبائع في مسؤولين ومديرين مشتركين"}],"e":{"en":"Under the circumstances-of-sale test, indicators that the relationship did not influence the price include that the price was settled in a manner consistent with the normal pricing practices of the industry, or in a manner consistent with how the seller settles prices with unrelated buyers, or that the price is adequate to ensure recovery of all costs plus a profit equivalent to the firm's overall profit over a representative period. (19 CFR 152.103(l)(1))","es":"Bajo la prueba de las circunstancias de la venta, los indicadores de que la relación no influyó en el precio incluyen que el precio se fijó de una manera consistente con las prácticas normales de fijación de precios de la industria, o de una manera consistente con cómo el vendedor fija los precios con compradores no relacionados, o que el precio es adecuado para asegurar la recuperación de todos los costos más una ganancia equivalente a la ganancia general de la empresa durante un período representativo. (19 CFR 152.103(l)(1))","ru":"По тесту обстоятельств продажи показателями того, что связь не повлияла на цену, являются: цена была установлена способом, соответствующим обычной практике ценообразования в отрасли, или способом, соответствующим тому, как продавец устанавливает цены с несвязанными покупателями, либо цена достаточна для обеспечения возмещения всех издержек плюс прибыль, эквивалентная общей прибыли фирмы за представительный период. (19 CFR 152.103(l)(1))","tr":"Satış koşulları testi kapsamında, ilişkinin fiyatı etkilemediğine dair göstergeler şunları içerir: fiyatın sektörün normal fiyatlandırma uygulamalarıyla tutarlı bir şekilde belirlenmesi ya da satıcının ilişkisiz alıcılarla fiyat belirleme şekliyle tutarlı bir şekilde belirlenmesi veya fiyatın tüm maliyetlerin geri kazanılmasını ve temsili bir dönem boyunca firmanın genel kârına eşdeğer bir kârı sağlamaya yeterli olması. (19 CFR 152.103(l)(1))","hi":"बिक्री-की-परिस्थितियों के परीक्षण के तहत, इस बात के संकेतक कि संबंध ने मूल्य को प्रभावित नहीं किया, उनमें शामिल हैं कि मूल्य उद्योग की सामान्य मूल्य-निर्धारण प्रथाओं के अनुरूप तरीके से तय किया गया था, या जिस तरह से विक्रेता असंबंधित खरीदारों के साथ मूल्य तय करता है उसके अनुरूप तरीके से, या यह कि मूल्य सभी लागतों की वसूली के साथ-साथ एक प्रतिनिधि अवधि में फर्म के समग्र लाभ के समतुल्य लाभ सुनिश्चित करने के लिए पर्याप्त है। (19 CFR 152.103(l)(1))","ar":"بموجب اختبار ظروف البيع، تشمل المؤشرات على أن العلاقة لم تؤثر في السعر أن السعر سُوِّي بطريقة متسقة مع ممارسات التسعير العادية للصناعة، أو بطريقة متسقة مع كيفية تسوية البائع للأسعار مع المشترين غير المرتبطين، أو أن السعر كافٍ لضمان استرداد جميع التكاليف بالإضافة إلى ربح يعادل ربح الشركة الإجمالي خلال فترة تمثيلية. (19 CFR 152.103(l)(1))"}},{"cat":"valuation","a":2,"q":{"en":"If a related-party transaction value has been found to closely approximate a properly applicable test value, the Center director will:","es":"Si se ha determinado que un valor de transacción de parte relacionada se aproxima estrechamente a un valor de prueba debidamente aplicable, el director del Centro:","ru":"Если установлено, что стоимость сделки связанной стороны близко приближается к надлежащим образом применимой проверочной стоимости, директор Центра (Center director):","tr":"Bir ilişkili taraf işlem değerinin, uygun şekilde uygulanabilir bir test değerine yakın şekilde yaklaştığı tespit edilmişse, Merkez müdürü (Center director):","hi":"यदि किसी संबंधित-पक्ष लेनदेन मूल्य के बारे में पाया गया है कि वह उचित रूप से लागू परीक्षण मूल्य के निकट आता है, तो केंद्र निदेशक (Center director):","ar":"إذا تبيّن أن قيمة معاملة لطرف مرتبط تقترب بشكل وثيق من قيمة اختبارية قابلة للتطبيق بشكل صحيح، فإن مدير المركز (Center director):"},"o":[{"en":"require the importer to also submit a computed value before acceptance","es":"exigirá al importador que también presente un valor calculado antes de la aceptación","ru":"потребует от импортера также представить исчисленную стоимость до принятия","tr":"kabulden önce ithalatçının ayrıca bir hesaplanmış değer sunmasını isteyecektir","hi":"स्वीकृति से पहले आयातकर्ता से एक गणना मूल्य भी प्रस्तुत करने की मांग करेगा","ar":"سيطلب من المستورد أيضاً تقديم قيمة محتسبة قبل القبول"},{"en":"accept the value only for that single entry and re-test every subsequent entry","es":"aceptará el valor solo para esa entrada única y volverá a probar cada entrada posterior","ru":"примет стоимость только для этой одной декларации и будет повторно проверять каждую последующую декларацию","tr":"değeri yalnızca o tek giriş için kabul edecek ve sonraki her girişi yeniden test edecektir","hi":"मूल्य को केवल उस एकल प्रविष्टि के लिए स्वीकार करेगा और हर बाद की प्रविष्टि का पुनः परीक्षण करेगा","ar":"سيقبل القيمة لذلك الإدخال الواحد فقط ويعيد اختبار كل إدخال لاحق"},{"en":"not seek to determine whether the relationship influenced the price actually paid or payable","es":"no buscará determinar si la relación influyó en el precio efectivamente pagado o por pagar","ru":"не будет стремиться определить, повлияла ли связь на цену, фактически уплаченную или подлежащую уплате","tr":"ilişkinin fiilen ödenen veya ödenecek fiyatı etkileyip etkilemediğini belirlemeye çalışmayacaktır","hi":"यह निर्धारित करने का प्रयास नहीं करेगा कि क्या संबंध ने वास्तव में भुगतान किए गए या देय मूल्य को प्रभावित किया","ar":"لن يسعى إلى تحديد ما إذا كانت العلاقة قد أثرت في السعر المدفوع فعلاً أو المستحق الدفع"},{"en":"still independently determine whether the relationship influenced the price before accepting the value","es":"aún determinará de forma independiente si la relación influyó en el precio antes de aceptar el valor","ru":"все равно самостоятельно определит, повлияла ли связь на цену, прежде чем принять стоимость","tr":"değeri kabul etmeden önce ilişkinin fiyatı etkileyip etkilemediğini yine de bağımsız olarak belirleyecektir","hi":"मूल्य स्वीकार करने से पहले फिर भी स्वतंत्र रूप से यह निर्धारित करेगा कि क्या संबंध ने मूल्य को प्रभावित किया","ar":"سيظل يحدد بشكل مستقل ما إذا كانت العلاقة قد أثرت في السعر قبل قبول القيمة"}],"e":{"en":"If the transaction value closely approximates one of the test values, the relationship is deemed not to have influenced the price, and the Center director will not seek to determine whether the relationship influenced the price actually paid or payable. (19 CFR 152.103(l)(1))","es":"Si el valor de transacción se aproxima estrechamente a uno de los valores de prueba, se considera que la relación no influyó en el precio, y el director del Centro no buscará determinar si la relación influyó en el precio efectivamente pagado o por pagar. (19 CFR 152.103(l)(1))","ru":"Если стоимость сделки близко приближается к одной из проверочных стоимостей, считается, что связь не повлияла на цену, и директор Центра не будет стремиться определить, повлияла ли связь на цену, фактически уплаченную или подлежащую уплате. (19 CFR 152.103(l)(1))","tr":"İşlem değeri test değerlerinden birine yakın şekilde yaklaşıyorsa, ilişkinin fiyatı etkilemediği kabul edilir ve Merkez müdürü, ilişkinin fiilen ödenen veya ödenecek fiyatı etkileyip etkilemediğini belirlemeye çalışmaz. (19 CFR 152.103(l)(1))","hi":"यदि लेनदेन मूल्य परीक्षण मूल्यों में से किसी एक के निकट आता है, तो यह माना जाता है कि संबंध ने मूल्य को प्रभावित नहीं किया, और केंद्र निदेशक यह निर्धारित करने का प्रयास नहीं करेगा कि क्या संबंध ने वास्तव में भुगतान किए गए या देय मूल्य को प्रभावित किया। (19 CFR 152.103(l)(1))","ar":"إذا اقتربت قيمة المعاملة بشكل وثيق من إحدى القيم الاختبارية، تُعتبر العلاقة غير مؤثرة في السعر، ولن يسعى مدير المركز إلى تحديد ما إذا كانت العلاقة قد أثرت في السعر المدفوع فعلاً أو المستحق الدفع. (19 CFR 152.103(l)(1))"}},{"cat":"valuation","a":2,"q":{"en":"Which of the following items, supplied free of charge by the buyer to the foreign producer, is NOT an 'assist' under the customs valuation regulations?","es":"¿Cuál de los siguientes artículos, suministrados de forma gratuita por el comprador al productor extranjero, NO es una 'asistencia' bajo las regulaciones de valoración aduanera?","ru":"Какой из перечисленных предметов, предоставленных покупателем иностранному производителю бесплатно, НЕ является 'дополнительным средством' (assist) согласно правилам таможенной оценки?","tr":"Alıcı tarafından yabancı üreticiye ücretsiz olarak sağlanan aşağıdaki kalemlerden hangisi gümrük değerleme mevzuatına göre bir 'yardım' (assist) DEĞİLDİR?","hi":"खरीदार द्वारा विदेशी उत्पादक को निःशुल्क आपूर्ति किए गए निम्नलिखित में से कौन-सा आइटम सीमा शुल्क मूल्यांकन विनियमों के तहत 'सहायता' (assist) नहीं है?","ar":"أي من البنود التالية، المقدَّمة مجاناً من المشتري إلى المنتج الأجنبي، ليس 'مساعدة' (assist) بموجب لوائح التقييم الجمركي؟"},"o":[{"en":"tools, dies, and molds used in the production of the imported merchandise","es":"herramientas, troqueles y moldes utilizados en la producción de la mercancía importada","ru":"инструменты, штампы и формы, используемые в производстве импортного товара","tr":"ithal malın üretiminde kullanılan aletler, kalıplar ve döküm kalıpları","hi":"आयातित माल के उत्पादन में उपयोग किए जाने वाले उपकरण, डाई और साँचे","ar":"الأدوات والقوالب المعدنية (dies) والقوالب (molds) المستخدمة في إنتاج البضاعة المستوردة"},{"en":"engineering and design work necessary for the production of the merchandise and undertaken outside the United States","es":"el trabajo de ingeniería y diseño necesario para la producción de la mercancía y realizado fuera de los Estados Unidos","ru":"инженерные и дизайнерские работы, необходимые для производства товара и выполненные за пределами Соединенных Штатов","tr":"malın üretimi için gerekli olan ve Amerika Birleşik Devletleri dışında gerçekleştirilen mühendislik ve tasarım çalışması","hi":"माल के उत्पादन के लिए आवश्यक और संयुक्त राज्य अमेरिका के बाहर किया गया इंजीनियरिंग और डिज़ाइन कार्य","ar":"الأعمال الهندسية وأعمال التصميم اللازمة لإنتاج البضاعة والمنفذة خارج الولايات المتحدة"},{"en":"engineering and design work undertaken in the United States by a person domiciled in the United States","es":"el trabajo de ingeniería y diseño realizado en los Estados Unidos por una persona domiciliada en los Estados Unidos","ru":"инженерные и дизайнерские работы, выполненные в Соединенных Штатах лицом, проживающим в Соединенных Штатах","tr":"Amerika Birleşik Devletleri'nde ikamet eden bir kişi tarafından Amerika Birleşik Devletleri'nde gerçekleştirilen mühendislik ve tasarım çalışması","hi":"संयुक्त राज्य अमेरिका में अधिवासित किसी व्यक्ति द्वारा संयुक्त राज्य अमेरिका में किया गया इंजीनियरिंग और डिज़ाइन कार्य","ar":"الأعمال الهندسية وأعمال التصميم المنفذة في الولايات المتحدة من قِبل شخص مقيم في الولايات المتحدة"},{"en":"materials, components, and parts incorporated in the imported merchandise","es":"materiales, componentes y piezas incorporados en la mercancía importada","ru":"материалы, компоненты и детали, входящие в состав импортного товара","tr":"ithal mala dâhil edilen malzemeler, bileşenler ve parçalar","hi":"आयातित माल में शामिल सामग्री, घटक और पुर्ज़े","ar":"المواد والمكونات والأجزاء المدمجة في البضاعة المستوردة"}],"e":{"en":"The four assist categories are: (1) materials/components/parts; (2) tools/dies/molds; (3) merchandise consumed in production; and (4) engineering, development, artwork, design work, and plans/sketches undertaken elsewhere than the United States. Engineering/design undertaken in the United States is expressly excluded from the definition of assist. (19 CFR 152.102(a))","es":"Las cuatro categorías de asistencia son: (1) materiales/componentes/piezas; (2) herramientas/troqueles/moldes; (3) mercancía consumida en la producción; y (4) ingeniería, desarrollo, trabajo artístico, trabajo de diseño, y planos/bocetos realizados en un lugar distinto de los Estados Unidos. La ingeniería/diseño realizado en los Estados Unidos está expresamente excluido de la definición de asistencia. (19 CFR 152.102(a))","ru":"Четыре категории дополнительных средств (assist): (1) материалы/компоненты/детали; (2) инструменты/штампы/формы; (3) товары, потребленные в производстве; и (4) инженерные, опытно-конструкторские, художественные, дизайнерские работы и планы/эскизы, выполненные за пределами Соединенных Штатов. Инженерные/дизайнерские работы, выполненные в Соединенных Штатах, прямо исключены из определения дополнительного средства. (19 CFR 152.102(a))","tr":"Dört yardım (assist) kategorisi şunlardır: (1) malzemeler/bileşenler/parçalar; (2) aletler/kalıplar/döküm kalıpları; (3) üretimde tüketilen mal; ve (4) Amerika Birleşik Devletleri dışında bir yerde gerçekleştirilen mühendislik, geliştirme, sanat çalışması, tasarım çalışması ve plan/eskizler. Amerika Birleşik Devletleri'nde gerçekleştirilen mühendislik/tasarım, yardım tanımından açıkça hariç tutulmuştur. (19 CFR 152.102(a))","hi":"चार सहायता (assist) श्रेणियाँ हैं: (1) सामग्री/घटक/पुर्ज़े; (2) उपकरण/डाई/साँचे; (3) उत्पादन में उपभोग किया गया माल; और (4) संयुक्त राज्य अमेरिका के अलावा कहीं और किया गया इंजीनियरिंग, विकास, कलाकृति, डिज़ाइन कार्य, और योजनाएँ/रेखाचित्र। संयुक्त राज्य अमेरिका में किया गया इंजीनियरिंग/डिज़ाइन सहायता की परिभाषा से स्पष्ट रूप से बाहर रखा गया है। (19 CFR 152.102(a))","ar":"فئات المساعدة (assist) الأربع هي: (1) المواد/المكونات/الأجزاء؛ (2) الأدوات/القوالب المعدنية/القوالب؛ (3) البضاعة المستهلكة في الإنتاج؛ و(4) الأعمال الهندسية والتطوير والأعمال الفنية وأعمال التصميم والخطط/الرسوم التخطيطية المنفذة في مكان غير الولايات المتحدة. وتُستبعَد الأعمال الهندسية/التصميم المنفذة في الولايات المتحدة صراحةً من تعريف المساعدة. (19 CFR 152.102(a))"}},{"cat":"valuation","a":3,"q":{"en":"A buyer supplies, free of charge, a die used to produce the imported merchandise. The die cost the buyer sixty thousand dollars and is expected to produce twenty-five thousand units in total. The current entry covers five thousand of those units, and the importer apportions the die over the total anticipated production. What assist value is added for this entry?","es":"Un comprador suministra, de forma gratuita, un troquel utilizado para producir la mercancía importada. El troquel le costó al comprador sesenta mil dólares y se espera que produzca veinticinco mil unidades en total. La entrada actual cubre cinco mil de esas unidades, y el importador prorratea el troquel sobre la producción total anticipada. ¿Qué valor de asistencia se agrega para esta entrada?","ru":"Покупатель предоставляет бесплатно штамп, используемый для производства импортного товара. Штамп обошелся покупателю в шестьдесят тысяч долларов и, как ожидается, произведет в общей сложности двадцать пять тысяч единиц. Текущая декларация охватывает пять тысяч из этих единиц, и импортер распределяет штамп по всему предполагаемому объему производства. Какая стоимость дополнительного средства добавляется для этой декларации?","tr":"Bir alıcı, ithal malı üretmek için kullanılan bir kalıbı ücretsiz olarak sağlar. Kalıp alıcıya altmış bin dolara mal olmuştur ve toplamda yirmi beş bin birim üretmesi beklenmektedir. Mevcut giriş, bu birimlerden beş binini kapsar ve ithalatçı kalıbı toplam öngörülen üretime dağıtır. Bu giriş için hangi yardım değeri eklenir?","hi":"एक खरीदार आयातित माल के उत्पादन के लिए उपयोग किए जाने वाले एक डाई की निःशुल्क आपूर्ति करता है। डाई की लागत खरीदार को साठ हजार डॉलर पड़ी और इससे कुल पच्चीस हजार इकाइयाँ उत्पादित होने की उम्मीद है। वर्तमान प्रविष्टि उन इकाइयों में से पाँच हजार को कवर करती है, और आयातकर्ता डाई को कुल अनुमानित उत्पादन पर आवंटित करता है। इस प्रविष्टि के लिए कौन-सा सहायता मूल्य जोड़ा जाता है?","ar":"يقدّم مشترٍ، مجاناً، قالباً معدنياً (die) يُستخدم لإنتاج البضاعة المستوردة. كلّف القالب المشتري ستين ألف دولار، ومن المتوقع أن يُنتج خمسة وعشرين ألف وحدة إجمالاً. يغطي الإدخال الحالي خمسة آلاف من تلك الوحدات، ويوزّع المستورد القالب على إجمالي الإنتاج المتوقع. ما قيمة المساعدة التي تُضاف لهذا الإدخال؟"},"o":[{"en":"sixty thousand dollars","es":"sesenta mil dólares","ru":"шестьдесят тысяч долларов","tr":"altmış bin dolar","hi":"साठ हजार डॉलर","ar":"ستون ألف دولار"},{"en":"fifteen thousand dollars","es":"quince mil dólares","ru":"пятнадцать тысяч долларов","tr":"on beş bin dolar","hi":"पंद्रह हजार डॉलर","ar":"خمسة عشر ألف دولار"},{"en":"two thousand four hundred dollars","es":"dos mil cuatrocientos dólares","ru":"две тысячи четыреста долларов","tr":"iki bin dört yüz dolar","hi":"दो हजार चार सौ डॉलर","ar":"ألفان وأربعمائة دولار"},{"en":"twelve thousand dollars","es":"doce mil dólares","ru":"двенадцать тысяч долларов","tr":"on iki bin dolar","hi":"बारह हजार डॉलर","ar":"اثنا عشر ألف دولار"}],"e":{"en":"Apportioned per unit = $60,000 / 25,000 = $2.40 per unit. For the 5,000 units in this entry: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))","es":"Prorrateado por unidad = $60,000 / 25,000 = $2.40 por unidad. Para las 5,000 unidades en esta entrada: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))","ru":"Распределено на единицу = $60,000 / 25,000 = $2.40 за единицу. Для 5,000 единиц в этой декларации: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))","tr":"Birim başına dağıtılan = $60,000 / 25,000 = birim başına $2.40. Bu girişteki 5,000 birim için: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))","hi":"प्रति इकाई आवंटित = $60,000 / 25,000 = प्रति इकाई $2.40. इस प्रविष्टि की 5,000 इकाइयों के लिए: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))","ar":"الموزَّع لكل وحدة = $60,000 / 25,000 = $2.40 للوحدة. لـ 5,000 وحدة في هذا الإدخال: $2.40 x 5,000 = $12,000. (19 CFR 152.103(d), (e))"}},{"cat":"valuation","a":0,"q":{"en":"Regarding apportionment of an assist where the entire anticipated production is exported to the United States, which apportionment method is NOT among those expressly recognized by the regulation?","es":"Respecto al prorrateo de una asistencia cuando toda la producción anticipada se exporta a los Estados Unidos, ¿cuál método de prorrateo NO está entre los expresamente reconocidos por la regulación?","ru":"В отношении распределения дополнительного средства, когда весь предполагаемый объем производства вывозится в Соединенные Штаты, какой метод распределения НЕ входит в число прямо признанных нормативным актом?","tr":"Tüm öngörülen üretimin Amerika Birleşik Devletleri'ne ihraç edildiği durumda bir yardımın dağıtımıyla ilgili olarak, hangi dağıtım yöntemi mevzuat tarafından açıkça tanınanlar arasında DEĞİLDİR?","hi":"जहाँ संपूर्ण अनुमानित उत्पादन संयुक्त राज्य अमेरिका को निर्यात किया जाता है, वहाँ किसी सहायता के आवंटन के संबंध में, कौन-सी आवंटन पद्धति विनियमन द्वारा स्पष्ट रूप से मान्यता प्राप्त पद्धतियों में नहीं है?","ar":"فيما يتعلق بتوزيع مساعدة حيث يُصدَّر كامل الإنتاج المتوقع إلى الولايات المتحدة، أي طريقة توزيع ليست من بين الطرق المعترف بها صراحةً في اللائحة؟"},"o":[{"en":"apportioning the total value equally over a fixed period of five years regardless of units produced","es":"prorratear el valor total por igual sobre un período fijo de cinco años independientemente de las unidades producidas","ru":"равномерное распределение всей стоимости по фиксированному периоду в пять лет независимо от числа произведенных единиц","tr":"üretilen birimlerden bağımsız olarak toplam değeri sabit beş yıllık bir döneme eşit olarak dağıtmak","hi":"उत्पादित इकाइयों की परवाह किए बिना कुल मूल्य को पाँच वर्ष की निश्चित अवधि पर समान रूप से आवंटित करना","ar":"توزيع القيمة الإجمالية بالتساوي على فترة ثابتة مدتها خمس سنوات بصرف النظر عن الوحدات المنتَجة"},{"en":"apportioning the total value over the number of units produced up to the time of the first shipment","es":"prorratear el valor total sobre el número de unidades producidas hasta el momento del primer envío","ru":"распределение всей стоимости по числу единиц, произведенных до момента первой отгрузки","tr":"toplam değeri ilk sevkiyat zamanına kadar üretilen birim sayısına dağıtmak","hi":"कुल मूल्य को पहले शिपमेंट के समय तक उत्पादित इकाइयों की संख्या पर आवंटित करना","ar":"توزيع القيمة الإجمالية على عدد الوحدات المنتَجة حتى وقت الشحنة الأولى"},{"en":"apportioning the total value over the first shipment if the importer wishes to pay duty on the entire value at once","es":"prorratear el valor total sobre el primer envío si el importador desea pagar los derechos sobre el valor total de una sola vez","ru":"распределение всей стоимости по первой партии, если импортер желает уплатить пошлину со всей стоимости сразу","tr":"ithalatçı gümrük vergisini tüm değer üzerinden bir kerede ödemek isterse toplam değeri ilk sevkiyata dağıtmak","hi":"यदि आयातकर्ता पूरे मूल्य पर एक बार में शुल्क का भुगतान करना चाहता है तो कुल मूल्य को पहले शिपमेंट पर आवंटित करना","ar":"توزيع القيمة الإجمالية على الشحنة الأولى إذا رغب المستورد في دفع الرسوم على القيمة الكاملة دفعة واحدة"},{"en":"apportioning the total value over the entire anticipated production","es":"prorratear el valor total sobre toda la producción anticipada","ru":"распределение всей стоимости по всему предполагаемому объему производства","tr":"toplam değeri tüm öngörülen üretime dağıtmak","hi":"कुल मूल्य को संपूर्ण अनुमानित उत्पादन पर आवंटित करना","ar":"توزيع القيمة الإجمالية على كامل الإنتاج المتوقع"}],"e":{"en":"The regulation recognizes apportioning the assist over the first shipment (to pay duty at once), over the units produced up to the first shipment, or over the entire anticipated production; any other method must be in accordance with generally accepted accounting principles. A fixed five-year spread unrelated to production is not one of the stated methods. (19 CFR 152.103(e)(1))","es":"La regulación reconoce prorratear la asistencia sobre el primer envío (para pagar los derechos de una sola vez), sobre las unidades producidas hasta el primer envío, o sobre toda la producción anticipada; cualquier otro método debe ser conforme a los principios de contabilidad generalmente aceptados. Una distribución fija de cinco años no relacionada con la producción no es uno de los métodos establecidos. (19 CFR 152.103(e)(1))","ru":"Нормативный акт признает распределение дополнительного средства по первой партии (для единовременной уплаты пошлины), по единицам, произведенным до первой отгрузки, или по всему предполагаемому объему производства; любой иной метод должен соответствовать общепринятым принципам бухгалтерского учета. Фиксированное распределение на пять лет, не связанное с производством, не входит в число указанных методов. (19 CFR 152.103(e)(1))","tr":"Mevzuat, yardımın ilk sevkiyata (gümrük vergisini bir kerede ödemek için), ilk sevkiyata kadar üretilen birimlere veya tüm öngörülen üretime dağıtılmasını kabul eder; başka herhangi bir yöntem genel kabul görmüş muhasebe ilkelerine uygun olmalıdır. Üretimle ilgisi olmayan sabit beş yıllık bir dağıtım, belirtilen yöntemlerden biri değildir. (19 CFR 152.103(e)(1))","hi":"विनियमन सहायता को पहले शिपमेंट पर (एक बार में शुल्क भुगतान के लिए), पहले शिपमेंट तक उत्पादित इकाइयों पर, या संपूर्ण अनुमानित उत्पादन पर आवंटित करने को मान्यता देता है; कोई भी अन्य पद्धति आम तौर पर स्वीकृत लेखांकन सिद्धांतों के अनुरूप होनी चाहिए। उत्पादन से असंबंधित पाँच वर्ष का निश्चित विस्तार बताई गई पद्धतियों में से एक नहीं है। (19 CFR 152.103(e)(1))","ar":"تعترف اللائحة بتوزيع المساعدة على الشحنة الأولى (لدفع الرسوم دفعة واحدة)، أو على الوحدات المنتَجة حتى الشحنة الأولى، أو على كامل الإنتاج المتوقع؛ وأي طريقة أخرى يجب أن تكون وفقاً لمبادئ المحاسبة المقبولة عموماً. والتوزيع الثابت على خمس سنوات غير المرتبط بالإنتاج ليس إحدى الطرق المذكورة. (19 CFR 152.103(e)(1))"}},{"cat":"valuation","a":1,"q":{"en":"The value of an assist consisting of a mold that the buyer had previously used before supplying it free of charge to the producer is determined how?","es":"¿Cómo se determina el valor de una asistencia que consiste en un molde que el comprador había usado previamente antes de suministrarlo de forma gratuita al productor?","ru":"Как определяется стоимость дополнительного средства, состоящего из формы, которую покупатель ранее использовал, прежде чем предоставить ее бесплатно производителю?","tr":"Alıcının üreticiye ücretsiz olarak sağlamadan önce daha önce kullanmış olduğu bir kalıptan oluşan bir yardımın değeri nasıl belirlenir?","hi":"एक सहायता का मूल्य कैसे निर्धारित किया जाता है जिसमें एक ऐसा साँचा शामिल है जिसे खरीदार ने उत्पादक को निःशुल्क आपूर्ति करने से पहले पहले इस्तेमाल किया था?","ar":"كيف تُحدَّد قيمة مساعدة تتكوّن من قالب كان المشتري قد استخدمه سابقاً قبل تقديمه مجاناً إلى المنتج؟"},"o":[{"en":"at the replacement cost of a brand-new mold on the date of importation","es":"al costo de reemplazo de un molde completamente nuevo en la fecha de importación","ru":"по стоимости замены совершенно новой формы на дату ввоза","tr":"ithalat tarihinde yepyeni bir kalıbın yenileme maliyetinde","hi":"आयात की तिथि पर बिल्कुल नए साँचे की प्रतिस्थापन लागत पर","ar":"بتكلفة استبدال قالب جديد تماماً في تاريخ الاستيراد"},{"en":"at the cost of acquisition or production, adjusted downward to reflect its prior use","es":"al costo de adquisición o producción, ajustado a la baja para reflejar su uso previo","ru":"по стоимости приобретения или производства, скорректированной в сторону уменьшения для отражения предшествующего использования","tr":"edinim veya üretim maliyetinde, önceki kullanımını yansıtacak şekilde aşağı yönlü düzeltilmiş olarak","hi":"अधिग्रहण या उत्पादन की लागत पर, उसके पूर्व उपयोग को दर्शाने के लिए नीचे की ओर समायोजित","ar":"بتكلفة الاقتناء أو الإنتاج، مُعدَّلة بالخفض لتعكس استخدامه السابق"},{"en":"always at the buyer's original full acquisition cost with no adjustment","es":"siempre al costo de adquisición original completo del comprador sin ningún ajuste","ru":"всегда по первоначальной полной стоимости приобретения покупателем без корректировки","tr":"her zaman alıcının orijinal tam edinim maliyetinde, herhangi bir düzeltme yapılmadan","hi":"हमेशा खरीदार की मूल पूर्ण अधिग्रहण लागत पर बिना किसी समायोजन के","ar":"دائماً بتكلفة الاقتناء الأصلية الكاملة للمشتري دون أي تعديل"},{"en":"at zero, because used tooling has no dutiable value","es":"en cero, porque las herramientas usadas no tienen valor sujeto a derechos","ru":"по нулю, поскольку использованная оснастка не имеет облагаемой пошлиной стоимости","tr":"sıfır olarak, çünkü kullanılmış kalıpların gümrüğe tabi değeri yoktur","hi":"शून्य पर, क्योंकि प्रयुक्त उपकरणों का कोई शुल्क-योग्य मूल्य नहीं होता","ar":"بصفر، لأن العُدّة المستعملة ليس لها قيمة خاضعة للرسوم"}],"e":{"en":"Where the assist (such as a mold) was acquired by the buyer and previously used, regardless of whether acquired or produced by the buyer, the original cost of acquisition or production is adjusted downward to reflect its use before its value is determined. (19 CFR 152.103(d)(2))","es":"Cuando la asistencia (como un molde) fue adquirida por el comprador y usada previamente, independientemente de si fue adquirida o producida por el comprador, el costo original de adquisición o producción se ajusta a la baja para reflejar su uso antes de determinar su valor. (19 CFR 152.103(d)(2))","ru":"Когда дополнительное средство (например, форма) было приобретено покупателем и ранее использовалось, независимо от того, было ли оно приобретено или произведено покупателем, первоначальная стоимость приобретения или производства корректируется в сторону уменьшения для отражения его использования, прежде чем определяется его стоимость. (19 CFR 152.103(d)(2))","tr":"Yardımın (örneğin bir kalıp) alıcı tarafından edinilmiş ve daha önce kullanılmış olması durumunda, alıcı tarafından edinilmiş veya üretilmiş olmasına bakılmaksızın, değeri belirlenmeden önce, kullanımını yansıtacak şekilde orijinal edinim veya üretim maliyeti aşağı yönlü düzeltilir. (19 CFR 152.103(d)(2))","hi":"जहाँ सहायता (जैसे एक साँचा) खरीदार द्वारा अधिग्रहित और पहले इस्तेमाल की गई थी, चाहे वह खरीदार द्वारा अधिग्रहित हो या उत्पादित, उसके मूल्य के निर्धारण से पहले अधिग्रहण या उत्पादन की मूल लागत को उसके उपयोग को दर्शाने के लिए नीचे की ओर समायोजित किया जाता है। (19 CFR 152.103(d)(2))","ar":"حيثما كانت المساعدة (مثل قالب) قد اقتناها المشتري واستُخدمت سابقاً، بصرف النظر عما إذا كان المشتري قد اقتناها أو أنتجها، تُعدَّل تكلفة الاقتناء أو الإنتاج الأصلية بالخفض لتعكس استخدامه قبل تحديد قيمته. (19 CFR 152.103(d)(2))"}},{"cat":"valuation","a":2,"q":{"en":"A royalty or license fee paid by the buyer is added to the price actually paid or payable in determining transaction value when:","es":"Una regalía o tarifa de licencia pagada por el comprador se agrega al precio efectivamente pagado o por pagar al determinar el valor de transacción cuando:","ru":"Роялти или лицензионный сбор, уплачиваемый покупателем, добавляется к цене, фактически уплаченной или подлежащей уплате, при определении стоимости сделки, когда:","tr":"Alıcı tarafından ödenen bir telif ücreti veya lisans bedeli, işlem değeri belirlenirken fiilen ödenen veya ödenecek fiyata şu durumda eklenir:","hi":"खरीदार द्वारा भुगतान की गई रॉयल्टी या लाइसेंस शुल्क को लेनदेन मूल्य निर्धारित करते समय वास्तव में भुगतान किए गए या देय मूल्य में तब जोड़ा जाता है जब:","ar":"تُضاف الإتاوة أو رسوم الترخيص التي يدفعها المشتري إلى السعر المدفوع فعلاً أو المستحق الدفع عند تحديد قيمة المعاملة عندما:"},"o":[{"en":"it is a fee for the right to reproduce the imported merchandise in the United States","es":"es una tarifa por el derecho de reproducir la mercancía importada en los Estados Unidos","ru":"это сбор за право воспроизводить импортный товар в Соединенных Штатах","tr":"ithal malı Amerika Birleşik Devletleri'nde çoğaltma hakkı için bir ücret olduğunda","hi":"यह संयुक्त राज्य अमेरिका में आयातित माल को पुन: प्रस्तुत करने के अधिकार के लिए एक शुल्क हो","ar":"كانت رسماً مقابل الحق في إعادة إنتاج البضاعة المستوردة في الولايات المتحدة"},{"en":"it is paid to a third party for the right to distribute or resell the merchandise, where such payment is not a condition of the sale","es":"se paga a un tercero por el derecho de distribuir o revender la mercancía, cuando dicho pago no es una condición de la venta","ru":"он уплачивается третьей стороне за право распространять или перепродавать товар, когда такая оплата не является условием продажи","tr":"böyle bir ödeme satışın bir koşulu olmadığında, malı dağıtma veya yeniden satma hakkı için üçüncü bir tarafa ödendiğinde","hi":"इसे माल वितरित करने या पुनर्विक्रय करने के अधिकार के लिए किसी तीसरे पक्ष को भुगतान किया जाता है, जहाँ ऐसा भुगतान बिक्री की शर्त नहीं है","ar":"دُفِعت لطرف ثالث مقابل الحق في توزيع البضاعة أو إعادة بيعها، حيث لا يكون هذا الدفع شرطاً للبيع"},{"en":"the buyer is required to pay it, directly or indirectly, as a condition of the sale of the imported merchandise for exportation to the United States","es":"se requiere que el comprador la pague, directa o indirectamente, como condición de la venta de la mercancía importada para exportación a los Estados Unidos","ru":"покупатель обязан уплатить его, прямо или косвенно, в качестве условия продажи импортного товара на экспорт в Соединенные Штаты","tr":"alıcının, ithal malın Amerika Birleşik Devletleri'ne ihracat amacıyla satışının bir koşulu olarak, doğrudan veya dolaylı olarak ödemesi gerektiğinde","hi":"खरीदार से इसे संयुक्त राज्य अमेरिका को निर्यात के लिए आयातित माल की बिक्री की शर्त के रूप में, प्रत्यक्ष या अप्रत्यक्ष रूप से, भुगतान करना अपेक्षित हो","ar":"كان مطلوباً من المشتري دفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضاعة المستوردة للتصدير إلى الولايات المتحدة"},{"en":"it is a charge for the right to use a trademark on goods sold only within the United States","es":"es un cargo por el derecho de usar una marca comercial en bienes vendidos solo dentro de los Estados Unidos","ru":"это плата за право использовать товарный знак на товарах, продаваемых только в пределах Соединенных Штатов","tr":"yalnızca Amerika Birleşik Devletleri içinde satılan mallarda bir ticari markayı kullanma hakkı için bir bedel olduğunda","hi":"यह केवल संयुक्त राज्य अमेरिका के भीतर बेचे गए माल पर ट्रेडमार्क का उपयोग करने के अधिकार के लिए एक शुल्क हो","ar":"كانت رسماً مقابل الحق في استخدام علامة تجارية على سلع تُباع داخل الولايات المتحدة فقط"}],"e":{"en":"Royalties and license fees are added only when the buyer is required to pay them, directly or indirectly, as a condition of the sale of the merchandise for exportation. Charges for the right to reproduce in the United States, and distribution/resale payments not constituting a condition of sale, are not added. (19 CFR 152.103(b)(1)(iv), (f))","es":"Las regalías y tarifas de licencia se agregan solo cuando se requiere que el comprador las pague, directa o indirectamente, como condición de la venta de la mercancía para exportación. Los cargos por el derecho de reproducir en los Estados Unidos, y los pagos de distribución/reventa que no constituyen una condición de la venta, no se agregan. (19 CFR 152.103(b)(1)(iv), (f))","ru":"Роялти и лицензионные сборы добавляются только тогда, когда покупатель обязан уплатить их, прямо или косвенно, в качестве условия продажи товара на экспорт. Плата за право воспроизведения в Соединенных Штатах и платежи за распространение/перепродажу, не являющиеся условием продажи, не добавляются. (19 CFR 152.103(b)(1)(iv), (f))","tr":"Telif ücretleri ve lisans bedelleri yalnızca alıcının, malın ihracat amacıyla satışının bir koşulu olarak, doğrudan veya dolaylı olarak bunları ödemesi gerektiğinde eklenir. Amerika Birleşik Devletleri'nde çoğaltma hakkı için bedeller ve satışın koşulu olmayan dağıtım/yeniden satış ödemeleri eklenmez. (19 CFR 152.103(b)(1)(iv), (f))","hi":"रॉयल्टी और लाइसेंस शुल्क केवल तभी जोड़े जाते हैं जब खरीदार से उन्हें निर्यात के लिए माल की बिक्री की शर्त के रूप में, प्रत्यक्ष या अप्रत्यक्ष रूप से, भुगतान करना अपेक्षित हो। संयुक्त राज्य अमेरिका में पुन: प्रस्तुत करने के अधिकार के लिए शुल्क, और बिक्री की शर्त न बनने वाले वितरण/पुनर्विक्रय भुगतान, नहीं जोड़े जाते। (19 CFR 152.103(b)(1)(iv), (f))","ar":"تُضاف الإتاوات ورسوم الترخيص فقط عندما يكون مطلوباً من المشتري دفعها، بشكل مباشر أو غير مباشر، كشرط لبيع البضاعة للتصدير. ولا تُضاف الرسوم مقابل الحق في إعادة الإنتاج في الولايات المتحدة، ولا مدفوعات التوزيع/إعادة البيع التي لا تشكّل شرطاً للبيع. (19 CFR 152.103(b)(1)(iv), (f))"}},{"cat":"valuation","a":3,"q":{"en":"Which type of commission, when incurred by the buyer, is ADDED to the price actually paid or payable in transaction value?","es":"¿Qué tipo de comisión, cuando es incurrida por el comprador, se AGREGA al precio efectivamente pagado o por pagar en el valor de transacción?","ru":"Какой вид комиссии, понесенной покупателем, ДОБАВЛЯЕТСЯ к цене, фактически уплаченной или подлежащей уплате, в стоимости сделки?","tr":"Alıcı tarafından üstlenildiğinde, hangi tür komisyon işlem değerinde fiilen ödenen veya ödenecek fiyata EKLENİR?","hi":"किस प्रकार का कमीशन, जब खरीदार द्वारा वहन किया जाता है, लेनदेन मूल्य में वास्तव में भुगतान किए गए या देय मूल्य में जोड़ा जाता है?","ar":"أي نوع من العمولات، عندما يتكبدها المشتري، يُضاف إلى السعر المدفوع فعلاً أو المستحق الدفع في قيمة المعاملة؟"},"o":[{"en":"no commission of any kind is ever added to the price actually paid or payable","es":"ninguna comisión de ningún tipo se agrega jamás al precio efectivamente pagado o por pagar","ru":"никакая комиссия любого рода никогда не добавляется к цене, фактически уплаченной или подлежащей уплате","tr":"hiçbir türden komisyon, fiilen ödenen veya ödenecek fiyata asla eklenmez","hi":"किसी भी प्रकार का कोई कमीशन कभी भी वास्तव में भुगतान किए गए या देय मूल्य में नहीं जोड़ा जाता","ar":"لا تُضاف أي عمولة من أي نوع أبداً إلى السعر المدفوع فعلاً أو المستحق الدفع"},{"en":"a buying commission paid to the buyer's agent for representing the buyer in the purchase","es":"una comisión de compra pagada al agente del comprador por representar al comprador en la compra","ru":"закупочная комиссия, уплачиваемая агенту покупателя за представление покупателя при покупке","tr":"alıcıyı satın almada temsil ettiği için alıcının acentesine ödenen bir alım komisyonu","hi":"खरीद में खरीदार का प्रतिनिधित्व करने के लिए खरीदार के एजेंट को भुगतान किया गया खरीद कमीशन","ar":"عمولة شراء تُدفع لوكيل المشتري مقابل تمثيله للمشتري في عملية الشراء"},{"en":"any commission, whether for buying or selling, since all commissions are dutiable","es":"cualquier comisión, ya sea de compra o de venta, ya que todas las comisiones están sujetas a derechos","ru":"любая комиссия, будь то за покупку или продажу, поскольку все комиссии облагаются пошлиной","tr":"tüm komisyonlar gümrüğe tabi olduğundan, alım veya satım için olsun, herhangi bir komisyon","hi":"कोई भी कमीशन, चाहे खरीद के लिए हो या बिक्री के लिए, क्योंकि सभी कमीशन शुल्क-योग्य हैं","ar":"أي عمولة، سواء للشراء أو البيع، لأن جميع العمولات خاضعة للرسوم"},{"en":"a selling commission incurred by the buyer (a commission paid for services performed on behalf of the seller)","es":"una comisión de venta incurrida por el comprador (una comisión pagada por servicios realizados en nombre del vendedor)","ru":"комиссия за продажу, понесенная покупателем (комиссия, уплачиваемая за услуги, оказанные от имени продавца)","tr":"alıcı tarafından üstlenilen bir satış komisyonu (satıcı adına yapılan hizmetler karşılığında ödenen bir komisyon)","hi":"खरीदार द्वारा वहन किया गया बिक्री कमीशन (विक्रेता की ओर से किए गए सेवाओं के लिए भुगतान किया गया कमीशन)","ar":"عمولة بيع يتكبدها المشتري (عمولة تُدفع مقابل خدمات تُؤدَّى نيابةً عن البائع)"}],"e":{"en":"Any selling commission incurred by the buyer is added to the price actually paid or payable; buying commissions (paid to the buyer's agent for representing the buyer) are not added. (19 CFR 152.102(b); 152.103(b)(1)(ii))","es":"Cualquier comisión de venta incurrida por el comprador se agrega al precio efectivamente pagado o por pagar; las comisiones de compra (pagadas al agente del comprador por representar al comprador) no se agregan. (19 CFR 152.102(b); 152.103(b)(1)(ii))","ru":"Любая комиссия за продажу, понесенная покупателем, добавляется к цене, фактически уплаченной или подлежащей уплате; закупочные комиссии (уплачиваемые агенту покупателя за представление покупателя) не добавляются. (19 CFR 152.102(b); 152.103(b)(1)(ii))","tr":"Alıcı tarafından üstlenilen herhangi bir satış komisyonu fiilen ödenen veya ödenecek fiyata eklenir; alım komisyonları (alıcıyı temsil ettiği için alıcının acentesine ödenen) eklenmez. (19 CFR 152.102(b); 152.103(b)(1)(ii))","hi":"खरीदार द्वारा वहन किया गया कोई भी बिक्री कमीशन वास्तव में भुगतान किए गए या देय मूल्य में जोड़ा जाता है; खरीद कमीशन (खरीदार का प्रतिनिधित्व करने के लिए खरीदार के एजेंट को भुगतान किया गया) नहीं जोड़े जाते। (19 CFR 152.102(b); 152.103(b)(1)(ii))","ar":"تُضاف أي عمولة بيع يتكبدها المشتري إلى السعر المدفوع فعلاً أو المستحق الدفع؛ ولا تُضاف عمولات الشراء (المدفوعة لوكيل المشتري مقابل تمثيله للمشتري). (19 CFR 152.102(b); 152.103(b)(1)(ii))"}},{"cat":"valuation","a":2,"q":{"en":"A U.S. company buys toys for an invoice price of $1,850, which it pays in full to the foreign seller. In addition, as a condition of the sale, the buyer separately pays $350 to a third party to settle a debt the seller owes that third party. What is the price actually paid or payable?","es":"Una empresa estadounidense compra juguetes por un precio de factura de $1,850, que paga en su totalidad al vendedor extranjero. Además, como condición de la venta, el comprador paga por separado $350 a un tercero para saldar una deuda que el vendedor tiene con ese tercero. ¿Cuál es el precio efectivamente pagado o por pagar?","ru":"Американская компания покупает игрушки по фактурной цене $1,850, которую она полностью уплачивает иностранному продавцу. Кроме того, в качестве условия продажи покупатель отдельно уплачивает $350 третьей стороне для погашения долга, который продавец должен этой третьей стороне. Какова цена, фактически уплаченная или подлежащая уплате?","tr":"Bir ABD şirketi, $1,850 fatura fiyatıyla oyuncak satın alır ve bunu yabancı satıcıya tam olarak öder. Buna ek olarak, satışın bir koşulu olarak alıcı, satıcının o üçüncü tarafa olan bir borcunu kapatmak için üçüncü bir tarafa ayrıca $350 öder. Fiilen ödenen veya ödenecek fiyat nedir?","hi":"एक अमेरिकी कंपनी $1,850 के चालान मूल्य पर खिलौने खरीदती है, जिसे वह विदेशी विक्रेता को पूरा भुगतान करती है। इसके अतिरिक्त, बिक्री की शर्त के रूप में, खरीदार उस तीसरे पक्ष को विक्रेता द्वारा बकाया ऋण चुकाने के लिए अलग से $350 का भुगतान करता है। वास्तव में भुगतान किया गया या देय मूल्य क्या है?","ar":"تشتري شركة أمريكية ألعاباً بسعر فاتورة قدره $1,850، تدفعه بالكامل للبائع الأجنبي. وبالإضافة إلى ذلك، وكشرط للبيع، يدفع المشتري بشكل منفصل $350 لطرف ثالث لتسوية دَين يدين به البائع لذلك الطرف الثالث. ما هو السعر المدفوع فعلاً أو المستحق الدفع؟"},"o":[{"en":"$350","es":"$350","ru":"$350","tr":"$350","hi":"$350","ar":"$350"},{"en":"$1,500","es":"$1,500","ru":"$1,500","tr":"$1,500","hi":"$1,500","ar":"$1,500"},{"en":"$2,200","es":"$2,200","ru":"$2,200","tr":"$2,200","hi":"$2,200","ar":"$2,200"},{"en":"$1,850","es":"$1,850","ru":"$1,850","tr":"$1,850","hi":"$1,850","ar":"$1,850"}],"e":{"en":"The price actually paid or payable includes indirect payments — here the buyer's settlement of a $350 debt owed by the seller is an indirect payment added to the $1,850 invoice price: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))","es":"El precio efectivamente pagado o por pagar incluye pagos indirectos — aquí el pago por el comprador de una deuda de $350 que debe el vendedor es un pago indirecto agregado al precio de factura de $1,850: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))","ru":"Цена, фактически уплаченная или подлежащая уплате, включает косвенные платежи — здесь погашение покупателем долга $350, причитающегося с продавца, является косвенным платежом, добавляемым к фактурной цене $1,850: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))","tr":"Fiilen ödenen veya ödenecek fiyat dolaylı ödemeleri içerir — burada alıcının, satıcının borçlu olduğu $350'lik borcu kapatması, $1,850 fatura fiyatına eklenen dolaylı bir ödemedir: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))","hi":"वास्तव में भुगतान किया गया या देय मूल्य अप्रत्यक्ष भुगतानों को शामिल करता है — यहाँ खरीदार द्वारा विक्रेता के बकाया $350 ऋण का निपटान एक अप्रत्यक्ष भुगतान है जो $1,850 चालान मूल्य में जोड़ा जाता है: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))","ar":"يشمل السعر المدفوع فعلاً أو المستحق الدفع المدفوعات غير المباشرة — وهنا تسوية المشتري لدَين قدره $350 يدين به البائع تُعدّ مدفوعاً غير مباشر يُضاف إلى سعر الفاتورة $1,850: $1,850 + $350 = $2,200. (19 CFR 152.103(a)(2))"}},{"cat":"valuation","a":1,"q":{"en":"A foreign seller invoices merchandise at one dollar per unit but the buyer agrees to pay an additional one dollar per unit that accrues to the seller once the merchandise is resold in the United States. The shipment is ten thousand units, and the U.S. resale price can be determined within a reasonable time. What is the transaction value of the shipment?","es":"Un vendedor extranjero factura la mercancía a un dólar por unidad pero el comprador acuerda pagar un dólar adicional por unidad que se acumula al vendedor una vez que la mercancía se revende en los Estados Unidos. El envío es de diez mil unidades, y el precio de reventa en EE. UU. puede determinarse dentro de un tiempo razonable. ¿Cuál es el valor de transacción del envío?","ru":"Иностранный продавец выставляет счет на товар по одному доллару за единицу, но покупатель соглашается уплатить дополнительный один доллар за единицу, который причитается продавцу после перепродажи товара в Соединенных Штатах. Партия составляет десять тысяч единиц, и цена перепродажи в США может быть определена в разумный срок. Какова стоимость сделки по этой партии?","tr":"Yabancı bir satıcı malı birim başına bir dolardan faturalandırır ancak alıcı, mal Amerika Birleşik Devletleri'nde yeniden satıldığında satıcıya tahakkuk eden birim başına ilave bir dolar ödemeyi kabul eder. Sevkiyat on bin birimdir ve ABD yeniden satış fiyatı makul bir süre içinde belirlenebilir. Sevkiyatın işlem değeri nedir?","hi":"एक विदेशी विक्रेता माल का चालान प्रति इकाई एक डॉलर पर बनाता है लेकिन खरीदार प्रति इकाई एक अतिरिक्त डॉलर का भुगतान करने पर सहमत होता है जो संयुक्त राज्य अमेरिका में माल के पुनर्विक्रय होने पर विक्रेता को प्राप्त होता है। शिपमेंट दस हजार इकाइयों का है, और अमेरिकी पुनर्विक्रय मूल्य उचित समय के भीतर निर्धारित किया जा सकता है। शिपमेंट का लेनदेन मूल्य क्या है?","ar":"يُصدر بائع أجنبي فاتورة بالبضاعة بسعر دولار واحد للوحدة، لكن المشتري يوافق على دفع دولار إضافي للوحدة يؤول إلى البائع بمجرد إعادة بيع البضاعة في الولايات المتحدة. الشحنة عشرة آلاف وحدة، ويمكن تحديد سعر إعادة البيع في الولايات المتحدة خلال وقت معقول. ما هي قيمة المعاملة للشحنة؟"},"o":[{"en":"thirty thousand dollars","es":"treinta mil dólares","ru":"тридцать тысяч долларов","tr":"otuz bin dolar","hi":"तीस हजार डॉलर","ar":"ثلاثون ألف دولار"},{"en":"twenty thousand dollars","es":"veinte mil dólares","ru":"двадцать тысяч долларов","tr":"yirmi bin dolar","hi":"बीस हजार डॉलर","ar":"عشرون ألف دولار"},{"en":"eleven thousand dollars","es":"once mil dólares","ru":"одиннадцать тысяч долларов","tr":"on bir bin dolar","hi":"ग्यारह हजार डॉलर","ar":"أحد عشر ألف دولار"},{"en":"ten thousand dollars","es":"diez mil dólares","ru":"десять тысяч долларов","tr":"on bin dolar","hi":"दस हजार डॉलर","ar":"عشرة آلاف دولار"}],"e":{"en":"Proceeds of a subsequent resale that accrue, directly or indirectly, to the seller are added to the price actually paid or payable. The value is ($1 + $1) x 10,000 = $20,000, since the resale proceeds accruing to the seller can be determined within a reasonable time. (19 CFR 152.103(b)(1)(v))","es":"Los ingresos de una reventa posterior que se acumulan, directa o indirectamente, al vendedor se agregan al precio efectivamente pagado o por pagar. El valor es ($1 + $1) x 10,000 = $20,000, ya que los ingresos de la reventa que se acumulan al vendedor pueden determinarse dentro de un tiempo razonable. (19 CFR 152.103(b)(1)(v))","ru":"Выручка от последующей перепродажи, причитающаяся, прямо или косвенно, продавцу, добавляется к цене, фактически уплаченной или подлежащей уплате. Стоимость составляет ($1 + $1) x 10,000 = $20,000, поскольку выручка от перепродажи, причитающаяся продавцу, может быть определена в разумный срок. (19 CFR 152.103(b)(1)(v))","tr":"Sonraki bir yeniden satıştan satıcıya doğrudan veya dolaylı olarak tahakkuk eden gelirler, fiilen ödenen veya ödenecek fiyata eklenir. Satıcıya tahakkuk eden yeniden satış gelirleri makul bir süre içinde belirlenebildiğinden değer ($1 + $1) x 10,000 = $20,000'dır. (19 CFR 152.103(b)(1)(v))","hi":"किसी बाद के पुनर्विक्रय से प्राप्त आय जो प्रत्यक्ष या अप्रत्यक्ष रूप से विक्रेता को प्राप्त होती है, वास्तव में भुगतान किए गए या देय मूल्य में जोड़ी जाती है। मूल्य ($1 + $1) x 10,000 = $20,000 है, क्योंकि विक्रेता को प्राप्त होने वाली पुनर्विक्रय आय उचित समय के भीतर निर्धारित की जा सकती है। (19 CFR 152.103(b)(1)(v))","ar":"تُضاف عائدات إعادة بيع لاحقة تؤول، بشكل مباشر أو غير مباشر، إلى البائع إلى السعر المدفوع فعلاً أو المستحق الدفع. القيمة هي ($1 + $1) x 10,000 = $20,000، نظراً لأن عائدات إعادة البيع التي تؤول إلى البائع يمكن تحديدها خلال وقت معقول. (19 CFR 152.103(b)(1)(v))"}},{"cat":"valuation","a":3,"q":{"en":"An importer buys merchandise with a price actually paid or payable of eighty thousand dollars. The buyer also: paid a five thousand dollar royalty to the seller that was a condition of the sale; paid a three thousand dollar selling commission on behalf of the seller; supplied an assist apportioned to this shipment at four thousand dollars; and paid six thousand dollars for ocean freight from the foreign port to the United States. What is the transaction value?","es":"Un importador compra mercancía con un precio efectivamente pagado o por pagar de ochenta mil dólares. El comprador además: pagó una regalía de cinco mil dólares al vendedor que era una condición de la venta; pagó una comisión de venta de tres mil dólares en nombre del vendedor; suministró una asistencia prorrateada a este envío en cuatro mil dólares; y pagó seis mil dólares por el flete marítimo desde el puerto extranjero hasta los Estados Unidos. ¿Cuál es el valor de transacción?","ru":"Импортер покупает товар с ценой, фактически уплаченной или подлежащей уплате, в восемьдесят тысяч долларов. Покупатель также: уплатил роялти в пять тысяч долларов продавцу, что было условием продажи; уплатил комиссию за продажу в три тысячи долларов от имени продавца; предоставил дополнительное средство, распределенное на эту партию, в четыре тысячи долларов; и уплатил шесть тысяч долларов за морской фрахт из иностранного порта в Соединенные Штаты. Какова стоимость сделки?","tr":"Bir ithalatçı, fiilen ödenen veya ödenecek fiyatı seksen bin dolar olan mal satın alır. Alıcı ayrıca: satıcıya satışın bir koşulu olan beş bin dolarlık bir telif ücreti ödedi; satıcı adına üç bin dolarlık bir satış komisyonu ödedi; bu sevkiyata dağıtılmış dört bin dolarlık bir yardım sağladı; ve yabancı limandan Amerika Birleşik Devletleri'ne deniz taşımacılığı için altı bin dolar ödedi. İşlem değeri nedir?","hi":"एक आयातकर्ता अस्सी हजार डॉलर के वास्तव में भुगतान किए गए या देय मूल्य वाला माल खरीदता है। खरीदार ने यह भी: विक्रेता को पाँच हजार डॉलर की रॉयल्टी का भुगतान किया जो बिक्री की शर्त थी; विक्रेता की ओर से तीन हजार डॉलर का बिक्री कमीशन भुगतान किया; इस शिपमेंट पर चार हजार डॉलर पर आवंटित एक सहायता प्रदान की; और विदेशी बंदरगाह से संयुक्त राज्य अमेरिका तक समुद्री माल ढुलाई के लिए छह हजार डॉलर का भुगतान किया। लेनदेन मूल्य क्या है?","ar":"يشتري مستورد بضاعة بسعر مدفوع فعلاً أو مستحق الدفع قدره ثمانون ألف دولار. ودفع المشتري أيضاً: إتاوة بقيمة خمسة آلاف دولار للبائع كانت شرطاً للبيع؛ وعمولة بيع بقيمة ثلاثة آلاف دولار نيابةً عن البائع؛ وقدّم مساعدة موزَّعة على هذه الشحنة بقيمة أربعة آلاف دولار؛ ودفع ستة آلاف دولار للشحن البحري من الميناء الأجنبي إلى الولايات المتحدة. ما هي قيمة المعاملة؟"},"o":[{"en":"eighty-eight thousand dollars","es":"ochenta y ocho mil dólares","ru":"восемьдесят восемь тысяч долларов","tr":"seksen sekiz bin dolar","hi":"अट्ठासी हजार डॉलर","ar":"ثمانية وثمانون ألف دولار"},{"en":"ninety-six thousand dollars","es":"noventa y seis mil dólares","ru":"девяносто шесть тысяч долларов","tr":"doksan altı bin dolar","hi":"छियानवे हजार डॉलर","ar":"ستة وتسعون ألف دولار"},{"en":"ninety-eight thousand dollars","es":"noventa y ocho mil dólares","ru":"девяносто восемь тысяч долларов","tr":"doksan sekiz bin dolar","hi":"अट्ठानवे हजार डॉलर","ar":"ثمانية وتسعون ألف دولار"},{"en":"ninety-two thousand dollars","es":"noventa y dos mil dólares","ru":"девяносто две тысячи долларов","tr":"doksan iki bin dolar","hi":"बानवे हजार डॉलर","ar":"اثنان وتسعون ألف دولار"}],"e":{"en":"Add the dutiable royalty ($5,000), the selling commission ($3,000), and the apportioned assist ($4,000) to the price ($80,000). International freight to the United States is not part of transaction value. $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))","es":"Agregar la regalía sujeta a derechos ($5,000), la comisión de venta ($3,000), y la asistencia prorrateada ($4,000) al precio ($80,000). El flete internacional hasta los Estados Unidos no forma parte del valor de transacción. $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))","ru":"Добавьте облагаемое пошлиной роялти ($5,000), комиссию за продажу ($3,000) и распределенное дополнительное средство ($4,000) к цене ($80,000). Международный фрахт в Соединенные Штаты не является частью стоимости сделки. $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))","tr":"Gümrüğe tabi telif ücretini ($5,000), satış komisyonunu ($3,000) ve dağıtılmış yardımı ($4,000) fiyata ($80,000) ekleyin. Amerika Birleşik Devletleri'ne uluslararası navlun, işlem değerinin bir parçası değildir. $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))","hi":"शुल्क-योग्य रॉयल्टी ($5,000), बिक्री कमीशन ($3,000), और आवंटित सहायता ($4,000) को मूल्य ($80,000) में जोड़ें। संयुक्त राज्य अमेरिका तक अंतर्राष्ट्रीय माल ढुलाई लेनदेन मूल्य का हिस्सा नहीं है। $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))","ar":"أضِف الإتاوة الخاضعة للرسوم ($5,000)، وعمولة البيع ($3,000)، والمساعدة الموزَّعة ($4,000) إلى السعر ($80,000). الشحن الدولي إلى الولايات المتحدة ليس جزءاً من قيمة المعاملة. $80,000 + $5,000 + $3,000 + $4,000 = $92,000. (19 CFR 152.103(b))"}},{"cat":"valuation","a":1,"q":{"en":"'Packing costs' that are added to the price actually paid or payable include:","es":"Los 'costos de embalaje' que se agregan al precio efectivamente pagado o por pagar incluyen:","ru":"'Расходы на упаковку', добавляемые к цене, фактически уплаченной или подлежащей уплате, включают:","tr":"Fiilen ödenen veya ödenecek fiyata eklenen 'ambalaj maliyetleri' şunları içerir:","hi":"'पैकिंग लागत' जो वास्तव में भुगतान किए गए या देय मूल्य में जोड़ी जाती हैं, उनमें शामिल हैं:","ar":"تشمل 'تكاليف التعبئة' التي تُضاف إلى السعر المدفوع فعلاً أو المستحق الدفع ما يلي:"},"o":[{"en":"the cost of repackaging the merchandise in the United States for domestic retail sale","es":"el costo de reembalar la mercancía en los Estados Unidos para la venta minorista nacional","ru":"стоимость переупаковки товара в Соединенных Штатах для внутренней розничной продажи","tr":"malın iç perakende satış için Amerika Birleşik Devletleri'nde yeniden paketlenmesinin maliyeti","hi":"घरेलू खुदरा बिक्री के लिए संयुक्त राज्य अमेरिका में माल को फिर से पैक करने की लागत","ar":"تكلفة إعادة تعبئة البضاعة في الولايات المتحدة لأغراض البيع بالتجزئة المحلي"},{"en":"the cost of all containers and coverings of whatever nature and the cost of packing (labor and materials) incident to placing the merchandise in condition packed ready for shipment to the United States","es":"el costo de todos los contenedores y cubiertas de cualquier naturaleza y el costo del embalaje (mano de obra y materiales) incidente a colocar la mercancía en condición embalada lista para el envío a los Estados Unidos","ru":"стоимость всех контейнеров и оберток любого характера и стоимость упаковки (труда и материалов), сопутствующую приведению товара в состояние, упакованное и готовое к отправке в Соединенные Штаты","tr":"her türden tüm kapların ve kaplamaların maliyeti ile malı Amerika Birleşik Devletleri'ne sevkiyata hazır şekilde paketlenmiş duruma getirmeye ilişkin ambalajlama (işçilik ve malzeme) maliyeti","hi":"किसी भी प्रकार के सभी कंटेनरों और आवरणों की लागत और माल को संयुक्त राज्य अमेरिका में शिपमेंट के लिए पैक की गई तैयार स्थिति में रखने से संबंधित पैकिंग (श्रम और सामग्री) की लागत","ar":"تكلفة جميع الحاويات والأغلفة أياً كانت طبيعتها وتكلفة التعبئة (العمالة والمواد) المتصلة بوضع البضاعة في حالة معبأة جاهزة للشحن إلى الولايات المتحدة"},{"en":"the cost of reusable instruments of international traffic such as ocean shipping containers leased by the carrier","es":"el costo de instrumentos reutilizables de tráfico internacional como los contenedores marítimos arrendados por el transportista","ru":"стоимость многоразовых средств международного оборота, таких как морские контейнеры, арендованные перевозчиком","tr":"taşıyıcı tarafından kiralanan deniz konteynerleri gibi yeniden kullanılabilir uluslararası taşımacılık araçlarının maliyeti","hi":"वाहक द्वारा पट्टे पर लिए गए समुद्री शिपिंग कंटेनरों जैसे अंतर्राष्ट्रीय यातायात के पुन: प्रयोज्य उपकरणों की लागत","ar":"تكلفة أدوات النقل الدولي القابلة لإعادة الاستخدام مثل حاويات الشحن البحري المؤجَّرة من قِبل الناقل"},{"en":"only the cost of the outer shipping carton, not interior coverings","es":"solo el costo de la caja de envío exterior, no las cubiertas interiores","ru":"только стоимость внешней транспортной коробки, но не внутренних оберток","tr":"yalnızca dış sevkiyat kartonunun maliyeti, iç kaplamalar değil","hi":"केवल बाहरी शिपिंग कार्टन की लागत, आंतरिक आवरण नहीं","ar":"فقط تكلفة كرتونة الشحن الخارجية، وليس الأغلفة الداخلية"}],"e":{"en":"Packing costs are the cost of all containers and coverings of whatever nature and the cost of packing, whether for labor or materials, used in placing merchandise in condition packed ready for shipment to the United States. (19 CFR 152.102(e); 152.103(b)(1)(i))","es":"Los costos de embalaje son el costo de todos los contenedores y cubiertas de cualquier naturaleza y el costo del embalaje, ya sea por mano de obra o materiales, utilizado para colocar la mercancía en condición embalada lista para el envío a los Estados Unidos. (19 CFR 152.102(e); 152.103(b)(1)(i))","ru":"Расходы на упаковку — это стоимость всех контейнеров и оберток любого характера и стоимость упаковки, будь то труд или материалы, используемая для приведения товара в состояние, упакованное и готовое к отправке в Соединенные Штаты. (19 CFR 152.102(e); 152.103(b)(1)(i))","tr":"Ambalaj maliyetleri, her türden tüm kapların ve kaplamaların maliyeti ile malı Amerika Birleşik Devletleri'ne sevkiyata hazır şekilde paketlenmiş duruma getirmek için kullanılan, ister işçilik ister malzeme olsun, ambalajlama maliyetidir. (19 CFR 152.102(e); 152.103(b)(1)(i))","hi":"पैकिंग लागत किसी भी प्रकार के सभी कंटेनरों और आवरणों की लागत और पैकिंग की लागत है, चाहे वह श्रम के लिए हो या सामग्री के लिए, जिसका उपयोग माल को संयुक्त राज्य अमेरिका में शिपमेंट के लिए पैक की गई तैयार स्थिति में रखने में किया जाता है। (19 CFR 152.102(e); 152.103(b)(1)(i))","ar":"تكاليف التعبئة هي تكلفة جميع الحاويات والأغلفة أياً كانت طبيعتها وتكلفة التعبئة، سواء للعمالة أو المواد، المستخدمة في وضع البضاعة في حالة معبأة جاهزة للشحن إلى الولايات المتحدة. (19 CFR 152.102(e); 152.103(b)(1)(i))"}},{"cat":"valuation","a":3,"q":{"en":"Merchandise is invoiced in a foreign currency. The certified quarterly rate of exchange for the quarter is 0.0085 U.S. dollars per unit of foreign currency, but the certified daily rate on the date of exportation is 0.0090 U.S. dollars per unit. The invoice is for five million units of the foreign currency. Assuming no rate is proclaimed by the Secretary, what U.S. dollar value applies, and why?","es":"La mercancía se factura en moneda extranjera. La tasa de cambio trimestral certificada para el trimestre es de 0.0085 dólares estadounidenses por unidad de moneda extranjera, pero la tasa diaria certificada en la fecha de exportación es de 0.0090 dólares estadounidenses por unidad. La factura es por cinco millones de unidades de la moneda extranjera. Suponiendo que el Secretario no proclame ninguna tasa, ¿qué valor en dólares estadounidenses se aplica, y por qué?","ru":"Товар выставлен в счете в иностранной валюте. Заверенный квартальный курс обмена за квартал составляет 0.0085 доллара США за единицу иностранной валюты, но заверенный дневной курс на дату вывоза составляет 0.0090 доллара США за единицу. Счет выставлен на пять миллионов единиц иностранной валюты. Если предположить, что Секретарь не провозглашает никакого курса, какая стоимость в долларах США применяется и почему?","tr":"Mal yabancı para biriminde faturalandırılmıştır. Çeyrek için onaylı üç aylık döviz kuru, yabancı para biriminin birimi başına 0.0085 ABD dolarıdır, ancak ihracat tarihindeki onaylı günlük kur birim başına 0.0090 ABD dolarıdır. Fatura beş milyon birim yabancı para birimi içindir. Sekreter tarafından hiçbir kur ilan edilmediği varsayıldığında, hangi ABD doları değeri uygulanır ve neden?","hi":"माल का चालान एक विदेशी मुद्रा में बनाया गया है। तिमाही के लिए प्रमाणित त्रैमासिक विनिमय दर 0.0085 अमेरिकी डॉलर प्रति विदेशी मुद्रा इकाई है, लेकिन निर्यात की तिथि पर प्रमाणित दैनिक दर 0.0090 अमेरिकी डॉलर प्रति इकाई है। चालान विदेशी मुद्रा की पचास लाख इकाइयों के लिए है। यह मानते हुए कि सचिव (Secretary) द्वारा कोई दर घोषित नहीं की गई है, कौन-सा अमेरिकी डॉलर मूल्य लागू होता है, और क्यों?","ar":"تُصدَر فاتورة البضاعة بعملة أجنبية. سعر الصرف الفصلي المعتمد للربع هو 0.0085 دولار أمريكي لكل وحدة من العملة الأجنبية، لكن السعر اليومي المعتمد في تاريخ التصدير هو 0.0090 دولار أمريكي لكل وحدة. الفاتورة لخمسة ملايين وحدة من العملة الأجنبية. بافتراض أن الوزير (Secretary) لم يُعلن أي سعر، ما القيمة بالدولار الأمريكي التي تنطبق، ولماذا؟"},"o":[{"en":"forty-three thousand seven hundred fifty dollars, using the average of the two rates","es":"cuarenta y tres mil setecientos cincuenta dólares, usando el promedio de las dos tasas","ru":"сорок три тысячи семьсот пятьдесят долларов, используя среднее значение двух курсов","tr":"kırk üç bin yedi yüz elli dolar, iki kurun ortalamasını kullanarak","hi":"तैंतालीस हजार सात सौ पचास डॉलर, दोनों दरों के औसत का उपयोग करते हुए","ar":"ثلاثة وأربعون ألفاً وسبعمائة وخمسون دولاراً، باستخدام متوسط السعرين"},{"en":"forty-five thousand dollars, using the daily rate, because the daily rate always governs when it is higher","es":"cuarenta y cinco mil dólares, usando la tasa diaria, porque la tasa diaria siempre rige cuando es más alta","ru":"сорок пять тысяч долларов, используя дневной курс, поскольку дневной курс всегда определяющий, когда он выше","tr":"kırk beş bin dolar, günlük kuru kullanarak, çünkü günlük kur daha yüksek olduğunda her zaman geçerlidir","hi":"पैंतालीस हजार डॉलर, दैनिक दर का उपयोग करते हुए, क्योंकि दैनिक दर अधिक होने पर हमेशा लागू होती है","ar":"خمسة وأربعون ألف دولار، باستخدام السعر اليومي، لأن السعر اليومي يحكم دائماً عندما يكون أعلى"},{"en":"forty-two thousand five hundred dollars, using the quarterly rate, because the quarterly rate always governs","es":"cuarenta y dos mil quinientos dólares, usando la tasa trimestral, porque la tasa trimestral siempre rige","ru":"сорок две тысячи пятьсот долларов, используя квартальный курс, поскольку квартальный курс всегда определяющий","tr":"kırk iki bin beş yüz dolar, üç aylık kuru kullanarak, çünkü üç aylık kur her zaman geçerlidir","hi":"बयालीस हजार पाँच सौ डॉलर, त्रैमासिक दर का उपयोग करते हुए, क्योंकि त्रैमासिक दर हमेशा लागू होती है","ar":"اثنان وأربعون ألفاً وخمسمائة دولار، باستخدام السعر الفصلي، لأن السعر الفصلي يحكم دائماً"},{"en":"forty-five thousand dollars, using the daily rate, because it varies by 5 percent or more from the quarterly rate","es":"cuarenta y cinco mil dólares, usando la tasa diaria, porque varía en un 5 por ciento o más respecto a la tasa trimestral","ru":"сорок пять тысяч долларов, используя дневной курс, поскольку он отличается на 5 процентов или более от квартального курса","tr":"kırk beş bin dolar, günlük kuru kullanarak, çünkü üç aylık kurdan yüzde 5 veya daha fazla farklılık gösterir","hi":"पैंतालीस हजार डॉलर, दैनिक दर का उपयोग करते हुए, क्योंकि यह त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न है","ar":"خمسة وأربعون ألف دولار، باستخدام السعر اليومي، لأنه يتفاوت بنسبة 5 بالمائة أو أكثر عن السعر الفصلي"}],"e":{"en":"The variance is (0.0090 - 0.0085) / 0.0085 = about 5.88 percent, which is 5 percent or more, so the certified daily rate for the date of exportation is used. Value = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a); date of exportation governs per 159.32)","es":"La variación es (0.0090 - 0.0085) / 0.0085 = aproximadamente 5.88 por ciento, lo cual es 5 por ciento o más, por lo que se usa la tasa diaria certificada para la fecha de exportación. Valor = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a); la fecha de exportación rige según 159.32)","ru":"Отклонение составляет (0.0090 - 0.0085) / 0.0085 = около 5.88 процента, что составляет 5 процентов или более, поэтому используется заверенный дневной курс на дату вывоза. Стоимость = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a); дата вывоза определяющая согласно 159.32)","tr":"Sapma (0.0090 - 0.0085) / 0.0085 = yaklaşık yüzde 5.88'dir; bu da yüzde 5 veya daha fazladır, dolayısıyla ihracat tarihi için onaylı günlük kur kullanılır. Değer = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a); ihracat tarihi 159.32 uyarınca geçerlidir)","hi":"भिन्नता (0.0090 - 0.0085) / 0.0085 = लगभग 5.88 प्रतिशत है, जो 5 प्रतिशत या अधिक है, इसलिए निर्यात की तिथि के लिए प्रमाणित दैनिक दर का उपयोग किया जाता है। मूल्य = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a); 159.32 के अनुसार निर्यात की तिथि लागू होती है)","ar":"التفاوت هو (0.0090 - 0.0085) / 0.0085 = حوالي 5.88 بالمائة، وهو 5 بالمائة أو أكثر، لذا يُستخدم السعر اليومي المعتمد لتاريخ التصدير. القيمة = 5,000,000 x 0.0090 = $45,000. (19 CFR 159.34(a)؛ تاريخ التصدير هو الحاكم وفقاً لـ 159.32)"}},{"cat":"valuation","a":0,"q":{"en":"For currency conversion, the certified daily rate of exchange (rather than the certified quarterly rate) is used for a given date of exportation when:","es":"Para la conversión de moneda, la tasa de cambio diaria certificada (en lugar de la tasa trimestral certificada) se usa para una fecha de exportación determinada cuando:","ru":"Для пересчета валюты заверенный дневной курс обмена (а не заверенный квартальный курс) используется для данной даты вывоза, когда:","tr":"Para birimi dönüştürmesinde, belirli bir ihracat tarihi için onaylı günlük döviz kuru (onaylı üç aylık kur yerine) şu durumda kullanılır:","hi":"मुद्रा रूपांतरण के लिए, किसी दी गई निर्यात तिथि के लिए प्रमाणित दैनिक विनिमय दर (प्रमाणित त्रैमासिक दर के बजाय) तब उपयोग की जाती है जब:","ar":"لتحويل العملة، يُستخدم سعر الصرف اليومي المعتمد (بدلاً من السعر الفصلي المعتمد) لتاريخ تصدير معيّن عندما:"},"o":[{"en":"the certified daily rate for the date of exportation varies by 5 percent or more from the certified quarterly rate","es":"la tasa diaria certificada para la fecha de exportación varía en un 5 por ciento o más respecto a la tasa trimestral certificada","ru":"заверенный дневной курс на дату вывоза отличается на 5 процентов или более от заверенного квартального курса","tr":"ihracat tarihi için onaylı günlük kur, onaylı üç aylık kurdan yüzde 5 veya daha fazla farklılık gösterir","hi":"निर्यात की तिथि के लिए प्रमाणित दैनिक दर प्रमाणित त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है","ar":"يتفاوت السعر اليومي المعتمد لتاريخ التصدير بنسبة 5 بالمائة أو أكثر عن السعر الفصلي المعتمد"},{"en":"the certified daily rate for the date of exportation varies by any amount, however small, from the quarterly rate","es":"la tasa diaria certificada para la fecha de exportación varía en cualquier monto, por pequeño que sea, respecto a la tasa trimestral","ru":"заверенный дневной курс на дату вывоза отличается на любую величину, сколь бы малой она ни была, от квартального курса","tr":"ihracat tarihi için onaylı günlük kur, üç aylık kurdan ne kadar küçük olursa olsun herhangi bir miktarda farklılık gösterir","hi":"निर्यात की तिथि के लिए प्रमाणित दैनिक दर त्रैमासिक दर से किसी भी मात्रा में, चाहे कितनी भी छोटी हो, भिन्न होती है","ar":"يتفاوت السعر اليومي المعتمد لتاريخ التصدير بأي مقدار، مهما كان صغيراً، عن السعر الفصلي"},{"en":"the date of exportation falls in the last month of the calendar quarter","es":"la fecha de exportación cae en el último mes del trimestre calendario","ru":"дата вывоза приходится на последний месяц календарного квартала","tr":"ihracat tarihi takvim çeyreğinin son ayına denk gelir","hi":"निर्यात की तिथि कैलेंडर तिमाही के अंतिम महीने में आती है","ar":"يقع تاريخ التصدير في الشهر الأخير من الربع التقويمي"},{"en":"the importer requests use of the daily rate on the entry summary","es":"el importador solicita el uso de la tasa diaria en el resumen de entrada","ru":"импортер запрашивает использование дневного курса в итоговой декларации (entry summary)","tr":"ithalatçı, giriş özetinde (entry summary) günlük kurun kullanılmasını talep eder","hi":"आयातकर्ता प्रवेश सारांश (entry summary) पर दैनिक दर के उपयोग का अनुरोध करता है","ar":"يطلب المستورد استخدام السعر اليومي في ملخص الإدخال (entry summary)"}],"e":{"en":"The certified quarterly rate is used for any date of exportation within the quarter, except that if the certified daily rate for the date of exportation varies by 5 percent or more from the quarterly rate, the daily rate is used. (19 CFR 159.34(a))","es":"La tasa trimestral certificada se usa para cualquier fecha de exportación dentro del trimestre, excepto que si la tasa diaria certificada para la fecha de exportación varía en un 5 por ciento o más respecto a la tasa trimestral, se usa la tasa diaria. (19 CFR 159.34(a))","ru":"Заверенный квартальный курс используется для любой даты вывоза в пределах квартала, за исключением того, что если заверенный дневной курс на дату вывоза отличается на 5 процентов или более от квартального курса, используется дневной курс. (19 CFR 159.34(a))","tr":"Onaylı üç aylık kur, çeyrek içindeki herhangi bir ihracat tarihi için kullanılır; ancak ihracat tarihi için onaylı günlük kur, üç aylık kurdan yüzde 5 veya daha fazla farklılık gösterirse, günlük kur kullanılır. (19 CFR 159.34(a))","hi":"प्रमाणित त्रैमासिक दर का उपयोग तिमाही के भीतर किसी भी निर्यात तिथि के लिए किया जाता है, सिवाय इसके कि यदि निर्यात की तिथि के लिए प्रमाणित दैनिक दर त्रैमासिक दर से 5 प्रतिशत या अधिक भिन्न होती है, तो दैनिक दर का उपयोग किया जाता है। (19 CFR 159.34(a))","ar":"يُستخدم السعر الفصلي المعتمد لأي تاريخ تصدير ضمن الربع، إلا أنه إذا تفاوت السعر اليومي المعتمد لتاريخ التصدير بنسبة 5 بالمائة أو أكثر عن السعر الفصلي، يُستخدم السعر اليومي. (19 CFR 159.34(a))"}},{"cat":"duties","a":3,"q":{"en":"An ad valorem duty rate is best described as a duty assessed on which of the following bases?","es":"¿Cuál de las siguientes bases describe mejor un derecho ad valorem como un derecho calculado sobre dicha base?","ru":"Какое из следующих оснований лучше всего описывает адвалорную ставку пошлины как пошлину, начисляемую на этой основе?","tr":"Ad valorem gümrük vergisi oranı, aşağıdaki esaslardan hangisine göre tahakkuk ettirilen bir vergi olarak en iyi şekilde tanımlanır?","hi":"ad valorem शुल्क दर को निम्नलिखित में से किस आधार पर लगाए गए शुल्क के रूप में सबसे अच्छी तरह वर्णित किया जाता है?","ar":"كيف يُوصف معدل الرسوم ad valorem على أفضل وجه باعتباره رسماً يُحتسب على أي من الأسس التالية؟"},"o":[{"en":"A flat charge applied per entry regardless of value","es":"Un cargo fijo aplicado por entrada independientemente del valor","ru":"Фиксированный сбор, применяемый за каждую таможенную декларацию независимо от стоимости","tr":"Değerden bağımsız olarak her beyanname başına uygulanan sabit bir ücret","hi":"मूल्य की परवाह किए बिना प्रति प्रविष्टि लागू एक समान शुल्क","ar":"رسم ثابت يُطبَّق لكل بيان جمركي بصرف النظر عن القيمة"},{"en":"A fixed amount per unit of weight, volume, or quantity","es":"Una cantidad fija por unidad de peso, volumen o cantidad","ru":"Фиксированная сумма за единицу веса, объёма или количества","tr":"Ağırlık, hacim veya miktar birimi başına sabit bir tutar","hi":"वजन, आयतन या मात्रा की प्रति इकाई एक निश्चित राशि","ar":"مبلغ ثابت لكل وحدة من الوزن أو الحجم أو الكمية"},{"en":"A combination of a per-unit charge plus a percentage of value","es":"Una combinación de un cargo por unidad más un porcentaje del valor","ru":"Сочетание сбора за единицу плюс процент от стоимости","tr":"Birim başına bir ücret artı değerin bir yüzdesinin birleşimi","hi":"प्रति इकाई शुल्क और मूल्य के एक प्रतिशत का संयोजन","ar":"مزيج من رسم لكل وحدة بالإضافة إلى نسبة مئوية من القيمة"},{"en":"A percentage of the appraised value of the merchandise","es":"Un porcentaje del valor tasado de la mercancía","ru":"Процент от оценочной стоимости товара","tr":"Eşyanın takdir edilen değerinin bir yüzdesi","hi":"माल के निर्धारित मूल्य का एक प्रतिशत","ar":"نسبة مئوية من القيمة المقدَّرة للبضاعة"}],"e":{"en":"An ad valorem rate is expressed as a percentage of the goods' value (e.g., 5%). A specific duty is per unit; a compound duty combines both. See HTSUS General Notes and 19 USC 1401a regarding valuation as the base for ad valorem assessment.","es":"Una tasa ad valorem se expresa como un porcentaje del valor de la mercancía (p. ej., 5%). Un derecho específico es por unidad; un derecho compuesto combina ambos. Véanse las Notas Generales del HTSUS y 19 USC 1401a en cuanto a la valoración como base para la determinación ad valorem.","ru":"Адвалорная ставка выражается в виде процента от стоимости товара (например, 5%). Специфическая пошлина взимается за единицу; смешанная пошлина сочетает обе. См. Общие примечания HTSUS и 19 USC 1401a относительно оценки стоимости как основы для адвалорного начисления.","tr":"Ad valorem oran, eşyanın değerinin bir yüzdesi olarak ifade edilir (örneğin %5). Spesifik vergi birim başınadır; bileşik vergi her ikisini birleştirir. Ad valorem tahakkukunun esası olarak kıymet hakkında HTSUS Genel Notları ve 19 USC 1401a'ya bakınız.","hi":"ad valorem दर माल के मूल्य के एक प्रतिशत के रूप में व्यक्त की जाती है (उदा., 5%)। एक विशिष्ट शुल्क प्रति इकाई होता है; एक संयुक्त शुल्क दोनों को जोड़ता है। ad valorem निर्धारण के आधार के रूप में मूल्यांकन के संबंध में HTSUS General Notes और 19 USC 1401a देखें।","ar":"يُعبَّر عن معدل ad valorem كنسبة مئوية من قيمة البضاعة (مثلاً 5%). الرسم النوعي يكون لكل وحدة؛ أما الرسم المركّب فيجمع بين الاثنين. انظر الملاحظات العامة في HTSUS و19 USC 1401a بشأن التقييم كأساس للتقدير ad valorem."}},{"cat":"duties","a":3,"q":{"en":"In the HTSUS rate-of-duty columns, which column generally provides the duty rate applicable to imports from most countries that are not subject to a special program or trade sanction?","es":"En las columnas de tasas de derechos del HTSUS, ¿qué columna proporciona generalmente la tasa de derecho aplicable a las importaciones de la mayoría de los países que no están sujetos a un programa especial o a una sanción comercial?","ru":"В столбцах ставок пошлин HTSUS какой столбец, как правило, содержит ставку пошлины, применимую к импорту из большинства стран, не подпадающих под специальную программу или торговую санкцию?","tr":"HTSUS gümrük vergisi oranı sütunlarında, özel bir programa veya ticari yaptırıma tabi olmayan çoğu ülkeden yapılan ithalata uygulanacak vergi oranını genellikle hangi sütun sağlar?","hi":"HTSUS शुल्क दर स्तंभों में, कौन सा स्तंभ आमतौर पर उन अधिकांश देशों से होने वाले आयात पर लागू शुल्क दर प्रदान करता है जो किसी विशेष कार्यक्रम या व्यापार प्रतिबंध के अधीन नहीं हैं?","ar":"في أعمدة معدلات الرسوم في HTSUS، أي عمود يوفّر عموماً معدل الرسوم المطبَّق على الواردات من معظم الدول التي لا تخضع لبرنامج خاص أو لعقوبة تجارية؟"},"o":[{"en":"Column 2","es":"Columna 2","ru":"Column 2","tr":"Column 2","hi":"Column 2","ar":"Column 2"},{"en":"Column 1 Special","es":"Columna 1 Special","ru":"Column 1 Special","tr":"Column 1 Special","hi":"Column 1 Special","ar":"Column 1 Special"},{"en":"Column 3 Statutory","es":"Columna 3 Statutory","ru":"Column 3 Statutory","tr":"Column 3 Statutory","hi":"Column 3 Statutory","ar":"Column 3 Statutory"},{"en":"Column 1 General","es":"Columna 1 General","ru":"Column 1 General","tr":"Column 1 General","hi":"Column 1 General","ar":"Column 1 General"}],"e":{"en":"Column 1 General contains the normal trade relations (MFN) rates applicable to most countries. Column 1 Special lists preferential program rates, and Column 2 applies to a small set of countries (e.g., Cuba, North Korea). See HTSUS General Note 3.","es":"Column 1 General contiene las tasas de relaciones comerciales normales (MFN) aplicables a la mayoría de los países. Column 1 Special enumera las tasas de programas preferenciales, y Column 2 se aplica a un pequeño grupo de países (p. ej., Cuba, Corea del Norte). Véase HTSUS General Note 3.","ru":"Column 1 General содержит ставки нормальных торговых отношений (MFN), применимые к большинству стран. Column 1 Special перечисляет ставки преференциальных программ, а Column 2 применяется к небольшому числу стран (например, Куба, Северная Корея). См. HTSUS General Note 3.","tr":"Column 1 General, çoğu ülkeye uygulanan normal ticaret ilişkileri (MFN) oranlarını içerir. Column 1 Special, tercihli program oranlarını listeler ve Column 2, az sayıda ülkeye (örneğin Küba, Kuzey Kore) uygulanır. HTSUS General Note 3'e bakınız.","hi":"Column 1 General में अधिकांश देशों पर लागू सामान्य व्यापार संबंध (MFN) दरें शामिल हैं। Column 1 Special में अधिमान्य कार्यक्रम दरें सूचीबद्ध हैं, और Column 2 कुछ देशों (उदा., क्यूबा, उत्तर कोरिया) पर लागू होता है। HTSUS General Note 3 देखें।","ar":"يحتوي Column 1 General على معدلات العلاقات التجارية الطبيعية (MFN) المطبَّقة على معظم الدول. ويُدرج Column 1 Special معدلات البرامج التفضيلية، بينما ينطبق Column 2 على مجموعة صغيرة من الدول (مثل كوبا وكوريا الشمالية). انظر HTSUS General Note 3."}},{"cat":"duties","a":3,"q":{"en":"For Fiscal Year 2026, what is the ad valorem rate of the Merchandise Processing Fee (MPF) applied to formal entries?","es":"Para el Año Fiscal 2026, ¿cuál es la tasa ad valorem de la Merchandise Processing Fee (MPF) aplicada a las entradas formales?","ru":"На 2026 финансовый год какова адвалорная ставка Merchandise Processing Fee (MPF), применяемая к формальным таможенным декларациям?","tr":"2026 Mali Yılı için, resmi beyannamelere uygulanan Merchandise Processing Fee (MPF) ad valorem oranı nedir?","hi":"वित्तीय वर्ष 2026 के लिए, औपचारिक प्रविष्टियों पर लागू Merchandise Processing Fee (MPF) की ad valorem दर क्या है?","ar":"بالنسبة للسنة المالية 2026، ما هو معدل ad valorem لرسم Merchandise Processing Fee (MPF) المطبَّق على البيانات الرسمية؟"},"o":[{"en":"0.2125 percent of the entered value","es":"0.2125 por ciento del valor declarado","ru":"0.2125 процента от заявленной стоимости","tr":"Beyan edilen değerin 0.2125 yüzdesi","hi":"प्रविष्ट मूल्य का 0.2125 प्रतिशत","ar":"0.2125 بالمئة من القيمة المُدخَلة"},{"en":"0.1250 percent of the entered value","es":"0.1250 por ciento del valor declarado","ru":"0.1250 процента от заявленной стоимости","tr":"Beyan edilen değerin 0.1250 yüzdesi","hi":"प्रविष्ट मूल्य का 0.1250 प्रतिशत","ar":"0.1250 بالمئة من القيمة المُدخَلة"},{"en":"0.5000 percent of the entered value","es":"0.5000 por ciento del valor declarado","ru":"0.5000 процента от заявленной стоимости","tr":"Beyan edilen değerin 0.5000 yüzdesi","hi":"प्रविष्ट मूल्य का 0.5000 प्रतिशत","ar":"0.5000 بالمئة من القيمة المُدخَلة"},{"en":"0.3464 percent of the entered value","es":"0.3464 por ciento del valor declarado","ru":"0.3464 процента от заявленной стоимости","tr":"Beyan edilen değerin 0.3464 yüzdesi","hi":"प्रविष्ट मूल्य का 0.3464 प्रतिशत","ar":"0.3464 بالمئة من القيمة المُدخَلة"}],"e":{"en":"The MPF for formal entries is 0.3464% of the entered (dutiable) value, exclusive of duty, freight, and insurance, subject to a minimum and maximum. See 19 CFR 24.23(b)(1).","es":"El MPF para las entradas formales es del 0.3464% del valor declarado (sujeto a derechos), excluyendo derechos, flete y seguro, sujeto a un mínimo y un máximo. Véase 19 CFR 24.23(b)(1).","ru":"MPF для формальных деклараций составляет 0.3464% от заявленной (облагаемой пошлиной) стоимости, без учёта пошлины, фрахта и страхования, с учётом минимума и максимума. См. 19 CFR 24.23(b)(1).","tr":"Resmi beyannameler için MPF, vergi, navlun ve sigorta hariç olmak üzere beyan edilen (vergiye tabi) değerin %0.3464'üdür ve bir asgari ve azami tutara tabidir. 19 CFR 24.23(b)(1)'e bakınız.","hi":"औपचारिक प्रविष्टियों के लिए MPF, प्रविष्ट (शुल्क-योग्य) मूल्य का 0.3464% है, जिसमें शुल्क, माल-भाड़ा और बीमा शामिल नहीं हैं, और यह एक न्यूनतम तथा अधिकतम के अधीन है। 19 CFR 24.23(b)(1) देखें।","ar":"يبلغ رسم MPF للبيانات الرسمية 0.3464% من القيمة المُدخَلة (الخاضعة للرسوم)، باستثناء الرسوم والشحن والتأمين، ويخضع لحد أدنى وحد أقصى. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":2,"q":{"en":"The Harbor Maintenance Fee (HMF) is assessed at what rate, and against what base?","es":"¿A qué tasa se calcula la Harbor Maintenance Fee (HMF) y sobre qué base?","ru":"По какой ставке и на какой основе начисляется Harbor Maintenance Fee (HMF)?","tr":"Harbor Maintenance Fee (HMF) hangi oranda ve hangi esasa göre tahakkuk ettirilir?","hi":"Harbor Maintenance Fee (HMF) किस दर पर और किस आधार पर निर्धारित की जाती है?","ar":"بأي معدل وعلى أي أساس يُحتسب رسم Harbor Maintenance Fee (HMF)؟"},"o":[{"en":"0.3464 percent of the value of commercial cargo via vessel","es":"0.3464 por ciento del valor de la carga comercial transportada por buque","ru":"0.3464 процента от стоимости коммерческого груза, перевозимого судном","tr":"Gemiyle taşınan ticari yükün değerinin 0.3464 yüzdesi","hi":"जहाज द्वारा वाणिज्यिक माल के मूल्य का 0.3464 प्रतिशत","ar":"0.3464 بالمئة من قيمة البضائع التجارية المنقولة عبر السفن"},{"en":"0.125 percent of the value of all imported merchandise","es":"0.125 por ciento del valor de toda la mercancía importada","ru":"0.125 процента от стоимости всех импортируемых товаров","tr":"İthal edilen tüm eşyanın değerinin 0.125 yüzdesi","hi":"सभी आयातित माल के मूल्य का 0.125 प्रतिशत","ar":"0.125 بالمئة من قيمة جميع البضائع المستوردة"},{"en":"0.125 percent of the value of commercial cargo via vessel","es":"0.125 por ciento del valor de la carga comercial transportada por buque","ru":"0.125 процента от стоимости коммерческого груза, перевозимого судном","tr":"Gemiyle taşınan ticari yükün değerinin 0.125 yüzdesi","hi":"जहाज द्वारा वाणिज्यिक माल के मूल्य का 0.125 प्रतिशत","ar":"0.125 بالمئة من قيمة البضائع التجارية المنقولة عبر السفن"},{"en":"0.2125 percent of the value of commercial cargo via vessel","es":"0.2125 por ciento del valor de la carga comercial transportada por buque","ru":"0.2125 процента от стоимости коммерческого груза, перевозимого судном","tr":"Gemiyle taşınan ticari yükün değerinin 0.2125 yüzdesi","hi":"जहाज द्वारा वाणिज्यिक माल के मूल्य का 0.2125 प्रतिशत","ar":"0.2125 بالمئة من قيمة البضائع التجارية المنقولة عبر السفن"}],"e":{"en":"The HMF is 0.125% of the value of commercial cargo loaded or unloaded at a designated port using a commercial vessel. It does not apply to air or land shipments. See 19 CFR 24.24.","es":"El HMF es del 0.125% del valor de la carga comercial cargada o descargada en un puerto designado utilizando un buque comercial. No se aplica a envíos aéreos o terrestres. Véase 19 CFR 24.24.","ru":"HMF составляет 0.125% от стоимости коммерческого груза, погружаемого или выгружаемого в назначенном порту с использованием коммерческого судна. Он не применяется к воздушным или наземным перевозкам. См. 19 CFR 24.24.","tr":"HMF, ticari bir gemi kullanılarak belirlenmiş bir limanda yüklenen veya boşaltılan ticari yükün değerinin %0.125'idir. Hava veya kara taşımalarına uygulanmaz. 19 CFR 24.24'e bakınız.","hi":"HMF एक वाणिज्यिक जहाज का उपयोग करके किसी निर्दिष्ट बंदरगाह पर लादे या उतारे गए वाणिज्यिक माल के मूल्य का 0.125% है। यह हवाई या भूमि शिपमेंट पर लागू नहीं होता। 19 CFR 24.24 देखें।","ar":"يبلغ رسم HMF نسبة 0.125% من قيمة البضائع التجارية التي يتم تحميلها أو تفريغها في ميناء معيَّن باستخدام سفينة تجارية. ولا ينطبق على الشحنات الجوية أو البرية. انظر 19 CFR 24.24."}},{"cat":"duties","a":2,"q":{"en":"A protest of a CBP decision generally must be filed within how many days after the date of liquidation or the decision being protested?","es":"¿Dentro de cuántos días después de la fecha de liquidación o de la decisión impugnada debe presentarse generalmente una protesta de una decisión de CBP?","ru":"В течение скольких дней после даты ликвидации или оспариваемого решения, как правило, должен быть подан протест на решение CBP?","tr":"Bir CBP kararına ilişkin itiraz, genellikle tasfiye tarihinden veya itiraz edilen karardan sonra kaç gün içinde yapılmalıdır?","hi":"CBP के किसी निर्णय का विरोध आमतौर पर परिसमापन की तारीख या विरोधित निर्णय के कितने दिनों के भीतर दाखिल किया जाना चाहिए?","ar":"بوجه عام، خلال كم يوماً يجب تقديم اعتراض على قرار CBP بعد تاريخ التصفية أو القرار المعترَض عليه؟"},"o":[{"en":"90 days","es":"90 days","ru":"90 days","tr":"90 days","hi":"90 days","ar":"90 days"},{"en":"120 days","es":"120 days","ru":"120 days","tr":"120 days","hi":"120 days","ar":"120 days"},{"en":"180 days","es":"180 days","ru":"180 days","tr":"180 days","hi":"180 days","ar":"180 days"},{"en":"365 days","es":"365 days","ru":"365 days","tr":"365 days","hi":"365 days","ar":"365 days"}],"e":{"en":"A protest must be filed within 180 days after liquidation or the protested decision. See 19 USC 1514(c)(3) and 19 CFR 174.12(e).","es":"Una protesta debe presentarse dentro de los 180 days posteriores a la liquidación o a la decisión impugnada. Véanse 19 USC 1514(c)(3) y 19 CFR 174.12(e).","ru":"Протест должен быть подан в течение 180 days после ликвидации или оспариваемого решения. См. 19 USC 1514(c)(3) и 19 CFR 174.12(e).","tr":"İtiraz, tasfiyeden veya itiraz edilen karardan sonra 180 days içinde yapılmalıdır. 19 USC 1514(c)(3) ve 19 CFR 174.12(e)'ye bakınız.","hi":"विरोध परिसमापन या विरोधित निर्णय के बाद 180 days के भीतर दाखिल किया जाना चाहिए। 19 USC 1514(c)(3) और 19 CFR 174.12(e) देखें।","ar":"يجب تقديم الاعتراض خلال 180 days بعد التصفية أو القرار المعترَض عليه. انظر 19 USC 1514(c)(3) و19 CFR 174.12(e)."}},{"cat":"duties","a":1,"q":{"en":"Under modernized drawback (19 CFR Part 190, TFTEA), a drawback claim generally must be filed within what period after the date of importation of the designated merchandise?","es":"Bajo el drawback modernizado (19 CFR Part 190, TFTEA), ¿dentro de qué plazo después de la fecha de importación de la mercancía designada debe presentarse generalmente una reclamación de drawback?","ru":"В рамках модернизированного возврата пошлин (drawback) (19 CFR Part 190, TFTEA), в течение какого срока после даты импорта обозначенного товара, как правило, должно быть подано заявление о возврате?","tr":"Modernize edilmiş drawback kapsamında (19 CFR Part 190, TFTEA), bir drawback talebi genellikle belirlenmiş eşyanın ithalat tarihinden sonra hangi süre içinde yapılmalıdır?","hi":"आधुनिकीकृत drawback (19 CFR Part 190, TFTEA) के तहत, drawback दावा आमतौर पर निर्दिष्ट माल के आयात की तारीख के बाद किस अवधि के भीतर दाखिल किया जाना चाहिए?","ar":"بموجب drawback المُحدَّث (19 CFR Part 190, TFTEA)، خلال أي مدة بعد تاريخ استيراد البضاعة المعيَّنة يجب عموماً تقديم مطالبة drawback؟"},"o":[{"en":"3 years","es":"3 years","ru":"3 years","tr":"3 years","hi":"3 years","ar":"3 years"},{"en":"5 years","es":"5 years","ru":"5 years","tr":"5 years","hi":"5 years","ar":"5 years"},{"en":"180 days","es":"180 days","ru":"180 days","tr":"180 days","hi":"180 days","ar":"180 days"},{"en":"7 years","es":"7 years","ru":"7 years","tr":"7 years","hi":"7 years","ar":"7 years"}],"e":{"en":"TFTEA established a uniform 5-year period from the date of importation within which a drawback claim must be filed. See 19 USC 1313(r) and 19 CFR 190.51.","es":"TFTEA estableció un plazo uniforme de 5 years a partir de la fecha de importación dentro del cual debe presentarse una reclamación de drawback. Véanse 19 USC 1313(r) y 19 CFR 190.51.","ru":"TFTEA установил единый срок в 5 years с даты импорта, в течение которого должно быть подано заявление о возврате (drawback). См. 19 USC 1313(r) и 19 CFR 190.51.","tr":"TFTEA, bir drawback talebinin yapılması gereken, ithalat tarihinden itibaren tek tip 5 years'lık bir süre belirlemiştir. 19 USC 1313(r) ve 19 CFR 190.51'e bakınız.","hi":"TFTEA ने आयात की तारीख से एक समान 5 years की अवधि स्थापित की, जिसके भीतर drawback दावा दाखिल किया जाना चाहिए। 19 USC 1313(r) और 19 CFR 190.51 देखें।","ar":"أرسى TFTEA مدة موحدة قدرها 5 years من تاريخ الاستيراد يجب خلالها تقديم مطالبة drawback. انظر 19 USC 1313(r) و19 CFR 190.51."}},{"cat":"duties","a":1,"q":{"en":"Which of the following is generally exempt from the Merchandise Processing Fee?","es":"¿Cuál de los siguientes está generalmente exento de la Merchandise Processing Fee?","ru":"Что из следующего, как правило, освобождается от Merchandise Processing Fee?","tr":"Aşağıdakilerden hangisi genellikle Merchandise Processing Fee'den muaftır?","hi":"निम्नलिखित में से कौन सा आमतौर पर Merchandise Processing Fee से छूट प्राप्त है?","ar":"أي مما يلي يُعفى عموماً من رسم Merchandise Processing Fee؟"},"o":[{"en":"Goods imported by a nonresident importer","es":"Mercancías importadas por un importador no residente","ru":"Товары, ввозимые импортёром-нерезидентом","tr":"Yerleşik olmayan bir ithalatçı tarafından ithal edilen eşya","hi":"किसी अनिवासी आयातक द्वारा आयातित माल","ar":"البضائع المستوردة من قِبل مستورد غير مقيم"},{"en":"Goods that qualify as originating under USMCA","es":"Mercancías que califican como originarias bajo USMCA","ru":"Товары, признанные происходящими по USMCA","tr":"USMCA kapsamında menşeli sayılan eşya","hi":"ऐसा माल जो USMCA के तहत मूल के रूप में अर्ह है","ar":"البضائع المؤهَّلة كبضائع منشأ بموجب USMCA"},{"en":"Goods entered under HTSUS Chapter 99 tariffs","es":"Mercancías declaradas bajo los aranceles del HTSUS Chapter 99","ru":"Товары, заявленные по тарифам HTSUS Chapter 99","tr":"HTSUS Chapter 99 tarifeleri kapsamında beyan edilen eşya","hi":"HTSUS Chapter 99 शुल्कों के तहत प्रविष्ट माल","ar":"البضائع المُدخَلة بموجب تعريفات HTSUS Chapter 99"},{"en":"Goods subject to antidumping duties","es":"Mercancías sujetas a derechos antidumping","ru":"Товары, подлежащие антидемпинговым пошлинам","tr":"Antidamping vergisine tabi eşya","hi":"एंटीडंपिंग शुल्कों के अधीन माल","ar":"البضائع الخاضعة لرسوم مكافحة الإغراق"}],"e":{"en":"Originating goods under USMCA (and certain other free trade agreements) are exempt from MPF, as reflected in the HTSUS special program indicators. See 19 CFR 24.23(c) and General Note references for the agreements.","es":"Las mercancías originarias bajo USMCA (y ciertos otros acuerdos de libre comercio) están exentas del MPF, como se refleja en los indicadores de programas especiales del HTSUS. Véanse 19 CFR 24.23(c) y las referencias de General Note para los acuerdos.","ru":"Товары, происходящие по USMCA (и некоторым другим соглашениям о свободной торговле), освобождаются от MPF, что отражено в индикаторах специальных программ HTSUS. См. 19 CFR 24.23(c) и ссылки на General Note для соответствующих соглашений.","tr":"USMCA (ve belirli diğer serbest ticaret anlaşmaları) kapsamında menşeli eşya, HTSUS özel program göstergelerinde yansıtıldığı üzere MPF'den muaftır. 19 CFR 24.23(c)'ye ve anlaşmalara ilişkin General Note atıflarına bakınız.","hi":"USMCA (और कुछ अन्य मुक्त व्यापार समझौतों) के तहत मूल माल MPF से छूट प्राप्त है, जैसा कि HTSUS विशेष कार्यक्रम संकेतकों में परिलक्षित होता है। 19 CFR 24.23(c) और समझौतों के लिए General Note संदर्भ देखें।","ar":"تُعفى البضائع المنشأ بموجب USMCA (وبعض اتفاقيات التجارة الحرة الأخرى) من رسم MPF، كما هو مبيَّن في مؤشرات البرامج الخاصة في HTSUS. انظر 19 CFR 24.23(c) ومراجع General Note الخاصة بالاتفاقيات."}},{"cat":"duties","a":3,"q":{"en":"A compound duty rate of '4.4 cents/kg + 6%' is applied to merchandise. This rate is composed of which two elements?","es":"Se aplica a la mercancía una tasa de derecho compuesta de '4.4 cents/kg + 6%'. ¿De qué dos elementos se compone esta tasa?","ru":"К товару применяется смешанная ставка пошлины «4.4 cents/kg + 6%». Из каких двух элементов состоит эта ставка?","tr":"Eşyaya '4.4 cents/kg + 6%' şeklinde bir bileşik gümrük vergisi oranı uygulanır. Bu oran hangi iki unsurdan oluşur?","hi":"माल पर '4.4 cents/kg + 6%' की एक संयुक्त शुल्क दर लागू की जाती है। यह दर किन दो तत्वों से बनी होती है?","ar":"يُطبَّق على البضاعة معدل رسم مركّب قدره '4.4 cents/kg + 6%'. مِن أي عنصرين يتكوّن هذا المعدل؟"},"o":[{"en":"Two separate ad valorem components","es":"Dos componentes ad valorem separados","ru":"Два отдельных адвалорных компонента","tr":"İki ayrı ad valorem bileşen","hi":"दो अलग-अलग ad valorem घटक","ar":"عنصران منفصلان من نوع ad valorem"},{"en":"An ad valorem component plus a quota surcharge","es":"Un componente ad valorem más un recargo por cuota","ru":"Адвалорный компонент плюс квотная надбавка","tr":"Bir ad valorem bileşen artı bir kota ek ücreti","hi":"एक ad valorem घटक और एक कोटा अधिभार","ar":"عنصر ad valorem بالإضافة إلى رسم إضافي على الحصص"},{"en":"A specific component plus a fixed entry fee","es":"Un componente específico más una tarifa de entrada fija","ru":"Специфический компонент плюс фиксированный сбор за декларацию","tr":"Bir spesifik bileşen artı sabit bir beyanname ücreti","hi":"एक विशिष्ट घटक और एक निश्चित प्रविष्टि शुल्क","ar":"عنصر نوعي بالإضافة إلى رسم بيان ثابت"},{"en":"A specific component plus an ad valorem component","es":"Un componente específico más un componente ad valorem","ru":"Специфический компонент плюс адвалорный компонент","tr":"Bir spesifik bileşen artı bir ad valorem bileşen","hi":"एक विशिष्ट घटक और एक ad valorem घटक","ar":"عنصر نوعي بالإضافة إلى عنصر ad valorem"}],"e":{"en":"A compound duty combines a specific duty (per unit of weight/quantity, here per kg) with an ad valorem duty (a percentage of value). Both components are added to determine total duty. See HTSUS General Note 3 on rate types.","es":"Un derecho compuesto combina un derecho específico (por unidad de peso/cantidad, aquí por kg) con un derecho ad valorem (un porcentaje del valor). Ambos componentes se suman para determinar el derecho total. Véase HTSUS General Note 3 sobre los tipos de tasas.","ru":"Смешанная пошлина сочетает специфическую пошлину (за единицу веса/количества, здесь за kg) с адвалорной пошлиной (процент от стоимости). Оба компонента складываются для определения общей суммы пошлины. См. HTSUS General Note 3 о видах ставок.","tr":"Bileşik vergi, bir spesifik vergiyi (ağırlık/miktar birimi başına, burada kg başına) bir ad valorem vergiyle (değerin bir yüzdesi) birleştirir. Toplam vergiyi belirlemek için her iki bileşen toplanır. Oran türleri hakkında HTSUS General Note 3'e bakınız.","hi":"एक संयुक्त शुल्क एक विशिष्ट शुल्क (वजन/मात्रा की प्रति इकाई, यहाँ प्रति kg) को एक ad valorem शुल्क (मूल्य का एक प्रतिशत) के साथ जोड़ता है। कुल शुल्क निर्धारित करने के लिए दोनों घटक जोड़े जाते हैं। दर प्रकारों पर HTSUS General Note 3 देखें।","ar":"يجمع الرسم المركّب بين رسم نوعي (لكل وحدة وزن/كمية، هنا لكل kg) ورسم ad valorem (نسبة مئوية من القيمة). ويُجمع العنصران لتحديد إجمالي الرسم. انظر HTSUS General Note 3 بشأن أنواع المعدلات."}},{"cat":"duties","a":3,"q":{"en":"Which of the following persons is authorized to file a protest under 19 CFR Part 174?","es":"¿Cuál de las siguientes personas está autorizada para presentar una protesta bajo 19 CFR Part 174?","ru":"Кто из следующих лиц уполномочен подавать протест согласно 19 CFR Part 174?","tr":"Aşağıdaki kişilerden hangisi 19 CFR Part 174 kapsamında itiraz yapmaya yetkilidir?","hi":"निम्नलिखित में से कौन सा व्यक्ति 19 CFR Part 174 के तहत विरोध दाखिल करने के लिए अधिकृत है?","ar":"أي من الأشخاص التالين مخوَّل بتقديم اعتراض بموجب 19 CFR Part 174؟"},"o":[{"en":"Any U.S. citizen with an interest in trade policy","es":"Cualquier ciudadano estadounidense con interés en la política comercial","ru":"Любой гражданин США, заинтересованный в торговой политике","tr":"Ticaret politikasıyla ilgilenen herhangi bir ABD vatandaşı","hi":"व्यापार नीति में रुचि रखने वाला कोई भी अमेरिकी नागरिक","ar":"أي مواطن أمريكي لديه اهتمام بالسياسة التجارية"},{"en":"The carrier that transported the merchandise","es":"El transportista que transportó la mercancía","ru":"Перевозчик, доставивший товар","tr":"Eşyayı taşıyan taşıyıcı","hi":"वह वाहक जिसने माल का परिवहन किया","ar":"الناقل الذي نقل البضاعة"},{"en":"The foreign manufacturer of the goods","es":"El fabricante extranjero de las mercancías","ru":"Иностранный производитель товаров","tr":"Eşyanın yabancı üreticisi","hi":"माल का विदेशी निर्माता","ar":"الصانع الأجنبي للبضائع"},{"en":"The importer or consignee shown on the entry","es":"El importador o consignatario que figura en la entrada","ru":"Импортёр или грузополучатель, указанный в декларации","tr":"Beyannamede gösterilen ithalatçı veya alıcı","hi":"प्रविष्टि पर दर्शाया गया आयातक या परेषिती","ar":"المستورد أو المرسَل إليه المُبيَّن في البيان الجمركي"}],"e":{"en":"Protests may be filed by the importer, consignee, or their authorized agent (such as a licensed broker), among other persons whose protestable interest is established. See 19 USC 1514(c)(2) and 19 CFR 174.12(a).","es":"Las protestas pueden ser presentadas por el importador, el consignatario o su agente autorizado (como un agente de aduanas con licencia), entre otras personas cuyo interés susceptible de protesta esté establecido. Véanse 19 USC 1514(c)(2) y 19 CFR 174.12(a).","ru":"Протесты могут подаваться импортёром, грузополучателем или их уполномоченным агентом (например, лицензированным брокером), а также иными лицами, чей подлежащий протесту интерес установлен. См. 19 USC 1514(c)(2) и 19 CFR 174.12(a).","tr":"İtirazlar; ithalatçı, alıcı veya bunların yetkili temsilcisi (lisanslı bir gümrük müşaviri gibi) tarafından ve itiraz edilebilir menfaati tespit edilmiş diğer kişiler tarafından yapılabilir. 19 USC 1514(c)(2) ve 19 CFR 174.12(a)'ya bakınız.","hi":"विरोध आयातक, परेषिती, या उनके अधिकृत एजेंट (जैसे लाइसेंस प्राप्त ब्रोकर) द्वारा दाखिल किए जा सकते हैं, साथ ही अन्य व्यक्तियों द्वारा जिनका विरोध-योग्य हित स्थापित है। 19 USC 1514(c)(2) और 19 CFR 174.12(a) देखें।","ar":"يجوز تقديم الاعتراضات من قِبل المستورد أو المرسَل إليه أو وكيلهم المخوَّل (مثل وسيط مرخَّص)، إلى جانب أشخاص آخرين تثبت لهم مصلحة قابلة للاعتراض. انظر 19 USC 1514(c)(2) و19 CFR 174.12(a)."}},{"cat":"duties","a":2,"q":{"en":"Which statement about HTSUS Column 1 Special rates is TRUE?","es":"¿Cuál afirmación sobre las tasas HTSUS Column 1 Special es VERDADERA?","ru":"Какое утверждение о ставках HTSUS Column 1 Special является ВЕРНЫМ?","tr":"HTSUS Column 1 Special oranları hakkındaki hangi ifade DOĞRUDUR?","hi":"HTSUS Column 1 Special दरों के बारे में कौन सा कथन सत्य है?","ar":"أي عبارة عن معدلات HTSUS Column 1 Special صحيحة؟"},"o":[{"en":"They apply automatically to all imports regardless of origin","es":"Se aplican automáticamente a todas las importaciones independientemente del origen","ru":"Они применяются автоматически ко всему импорту независимо от происхождения","tr":"Menşeye bakılmaksızın tüm ithalata otomatik olarak uygulanırlar","hi":"वे मूल की परवाह किए बिना सभी आयातों पर स्वतः लागू होती हैं","ar":"تُطبَّق تلقائياً على جميع الواردات بصرف النظر عن المنشأ"},{"en":"They apply only to merchandise from Column 2 countries","es":"Se aplican únicamente a la mercancía procedente de países de Column 2","ru":"Они применяются только к товарам из стран Column 2","tr":"Yalnızca Column 2 ülkelerinden gelen eşyaya uygulanırlar","hi":"वे केवल Column 2 देशों से आने वाले माल पर लागू होती हैं","ar":"تُطبَّق فقط على البضائع الواردة من دول Column 2"},{"en":"They apply only when the goods qualify under a designated preference program","es":"Se aplican únicamente cuando las mercancías califican bajo un programa de preferencia designado","ru":"Они применяются только тогда, когда товары соответствуют требованиям обозначенной преференциальной программы","tr":"Yalnızca eşyanın belirlenmiş bir tercih programı kapsamında nitelendiği durumlarda uygulanırlar","hi":"वे केवल तभी लागू होती हैं जब माल किसी निर्दिष्ट अधिमान्य कार्यक्रम के तहत अर्ह हो","ar":"تُطبَّق فقط عندما تكون البضائع مؤهَّلة بموجب برنامج تفضيلي معيَّن"},{"en":"They are always higher than the corresponding Column 1 General rate","es":"Siempre son más altas que la tasa correspondiente de Column 1 General","ru":"Они всегда выше соответствующей ставки Column 1 General","tr":"Karşılık gelen Column 1 General oranından her zaman daha yüksektirler","hi":"वे हमेशा संबंधित Column 1 General दर से अधिक होती हैं","ar":"تكون دائماً أعلى من معدل Column 1 General المقابل"}],"e":{"en":"Column 1 Special rates (preferential duty rates) apply only when the merchandise qualifies under a specific program identified by a special program indicator (e.g., USMCA, AGOA). See HTSUS General Note 3(c).","es":"Las tasas Column 1 Special (tasas de derechos preferenciales) se aplican únicamente cuando la mercancía califica bajo un programa específico identificado por un indicador de programa especial (p. ej., USMCA, AGOA). Véase HTSUS General Note 3(c).","ru":"Ставки Column 1 Special (преференциальные ставки пошлин) применяются только тогда, когда товар соответствует требованиям конкретной программы, обозначенной индикатором специальной программы (например, USMCA, AGOA). См. HTSUS General Note 3(c).","tr":"Column 1 Special oranları (tercihli vergi oranları) yalnızca eşyanın, bir özel program göstergesiyle (örneğin USMCA, AGOA) tanımlanan belirli bir program kapsamında nitelendiği durumlarda uygulanır. HTSUS General Note 3(c)'ye bakınız.","hi":"Column 1 Special दरें (अधिमान्य शुल्क दरें) केवल तभी लागू होती हैं जब माल किसी विशेष कार्यक्रम संकेतक द्वारा पहचाने गए किसी विशिष्ट कार्यक्रम (उदा., USMCA, AGOA) के तहत अर्ह हो। HTSUS General Note 3(c) देखें।","ar":"تُطبَّق معدلات Column 1 Special (معدلات الرسوم التفضيلية) فقط عندما تكون البضاعة مؤهَّلة بموجب برنامج محدَّد يُعرَّف بمؤشر برنامج خاص (مثل USMCA وAGOA). انظر HTSUS General Note 3(c)."}},{"cat":"duties","a":0,"q":{"en":"For Fiscal Year 2026, the MPF on a formal entry is subject to which minimum and maximum amounts?","es":"Para el Año Fiscal 2026, la MPF en una entrada formal está sujeta a qué montos mínimo y máximo?","ru":"Для 2026 финансового года MPF при формальном ввозе подлежит каким минимальной и максимальной суммам?","tr":"2026 Mali Yılı için, resmi bir girişte MPF hangi asgari ve azami tutarlara tabidir?","hi":"वित्तीय वर्ष 2026 के लिए, औपचारिक प्रविष्टि पर MPF किन न्यूनतम और अधिकतम राशियों के अधीन है?","ar":"بالنسبة للسنة المالية 2026، تخضع رسوم MPF على الإدخال الرسمي لأي حد أدنى وحد أقصى من المبالغ؟"},"o":[{"en":"Minimum $33.58 and maximum $651.50","es":"Mínimo $33.58 y máximo $651.50","ru":"Минимум $33.58 и максимум $651.50","tr":"Asgari $33.58 ve azami $651.50","hi":"न्यूनतम $33.58 और अधिकतम $651.50","ar":"حد أدنى $33.58 وحد أقصى $651.50"},{"en":"Minimum $34.50 and maximum $700.00","es":"Mínimo $34.50 y máximo $700.00","ru":"Минимум $34.50 и максимум $700.00","tr":"Asgari $34.50 ve azami $700.00","hi":"न्यूनतम $34.50 और अधिकतम $700.00","ar":"حد أدنى $34.50 وحد أقصى $700.00"},{"en":"Minimum $27.23 and maximum $528.33","es":"Mínimo $27.23 y máximo $528.33","ru":"Минимум $27.23 и максимум $528.33","tr":"Asgari $27.23 ve azami $528.33","hi":"न्यूनतम $27.23 और अधिकतम $528.33","ar":"حد أدنى $27.23 وحد أقصى $528.33"},{"en":"Minimum $32.71 and maximum $634.62","es":"Mínimo $32.71 y máximo $634.62","ru":"Минимум $32.71 и максимум $634.62","tr":"Asgari $32.71 ve azami $634.62","hi":"न्यूनतम $32.71 और अधिकतम $634.62","ar":"حد أدنى $32.71 وحد أقصى $634.62"}],"e":{"en":"Effective October 1, 2025 (FY2026), the formal-entry MPF minimum is $33.58 and the maximum is $651.50, while the ad valorem rate remains 0.3464%. See 19 CFR 24.23(b)(1) as adjusted by the annual CBP user-fee notice.","es":"A partir del 1 de octubre de 2025 (FY2026), el mínimo de la MPF para entradas formales es $33.58 y el máximo es $651.50, mientras que la tasa ad valorem se mantiene en 0.3464%. Véase 19 CFR 24.23(b)(1) según lo ajustado por el aviso anual de tarifas de usuario de CBP.","ru":"С 1 октября 2025 года (FY2026) минимум MPF при формальном ввозе составляет $33.58, а максимум — $651.50, при этом адвалорная ставка остается 0.3464%. См. 19 CFR 24.23(b)(1) с корректировкой в ежегодном уведомлении CBP о пользовательских сборах.","tr":"1 Ekim 2025 (FY2026) itibarıyla, resmi giriş MPF asgari tutarı $33.58 ve azami tutarı $651.50 olup, ad valorem oranı 0.3464% olarak kalmaktadır. Yıllık CBP kullanıcı ücreti bildirimiyle ayarlanmış haliyle 19 CFR 24.23(b)(1)'e bakınız.","hi":"1 अक्टूबर 2025 (FY2026) से प्रभावी, औपचारिक-प्रविष्टि MPF का न्यूनतम $33.58 और अधिकतम $651.50 है, जबकि ad valorem दर 0.3464% बनी रहती है। वार्षिक CBP उपयोगकर्ता-शुल्क सूचना द्वारा समायोजित 19 CFR 24.23(b)(1) देखें।","ar":"اعتباراً من 1 أكتوبر 2025 (FY2026)، يبلغ الحد الأدنى لرسوم MPF للإدخال الرسمي $33.58 والحد الأقصى $651.50، بينما تبقى النسبة القيمية (ad valorem) عند 0.3464%. انظر 19 CFR 24.23(b)(1) بصيغته المعدّلة بموجب إشعار رسوم المستخدم السنوي الصادر عن CBP."}},{"cat":"duties","a":2,"q":{"en":"At the time of entry of merchandise subject to an antidumping or countervailing duty order, the importer is generally required to do which of the following?","es":"Al momento de la entrada de mercancía sujeta a una orden de derechos antidumping o compensatorios, ¿qué se exige generalmente que haga el importador de lo siguiente?","ru":"При ввозе товаров, на которые распространяется приказ об антидемпинговых или компенсационных пошлинах, импортер, как правило, обязан сделать что из перечисленного?","tr":"Antidamping veya telafi edici vergi emrine tabi malların girişi sırasında, ithalatçının genellikle aşağıdakilerden hangisini yapması gerekir?","hi":"एंटीडंपिंग या काउंटरवेलिंग शुल्क आदेश के अधीन माल की प्रविष्टि के समय, आयातक से आमतौर पर निम्नलिखित में से क्या करने की अपेक्षा की जाती है?","ar":"عند إدخال البضائع الخاضعة لأمر رسوم مكافحة الإغراق أو الرسوم التعويضية، يُطلب من المستورد عموماً القيام بأي مما يلي؟"},"o":[{"en":"Post a single-entry bond in lieu of any deposit","es":"Constituir una fianza de entrada única en lugar de cualquier depósito","ru":"Предоставить разовую гарантию (single-entry bond) вместо какого-либо депозита","tr":"Herhangi bir depozito yerine tek girişlik teminat (single-entry bond) sunmak","hi":"किसी भी जमा के बजाय एकल-प्रविष्टि बॉन्ड प्रस्तुत करना","ar":"تقديم سند ضمان لإدخال واحد (single-entry bond) بدلاً من أي إيداع"},{"en":"Withhold all duties until the order is revoked","es":"Retener todos los derechos hasta que se revoque la orden","ru":"Удерживать все пошлины до отмены приказа","tr":"Emir iptal edilene kadar tüm vergileri alıkoymak","hi":"आदेश रद्द होने तक सभी शुल्क रोक कर रखना","ar":"حجب جميع الرسوم حتى يتم إلغاء الأمر"},{"en":"Deposit estimated antidumping or countervailing duties","es":"Depositar los derechos antidumping o compensatorios estimados","ru":"Внести депозит расчетных антидемпинговых или компенсационных пошлин","tr":"Tahmini antidamping veya telafi edici vergileri depozito olarak yatırmak","hi":"अनुमानित एंटीडंपिंग या काउंटरवेलिंग शुल्क जमा करना","ar":"إيداع رسوم مكافحة الإغراق أو الرسوم التعويضية المقدّرة"},{"en":"Pay the final assessed ADD/CVD rate in full","es":"Pagar en su totalidad la tasa final evaluada de ADD/CVD","ru":"Полностью уплатить окончательно начисленную ставку ADD/CVD","tr":"Nihai olarak tahakkuk ettirilen ADD/CVD oranını tam olarak ödemek","hi":"अंतिम रूप से निर्धारित ADD/CVD दर का पूरा भुगतान करना","ar":"دفع معدل ADD/CVD النهائي المقرَّر بالكامل"}],"e":{"en":"On entries subject to an ADD/CVD order, the importer deposits estimated duties at the cash-deposit rate in effect; final duties are assessed at liquidation after any administrative review. See 19 USC 1673e/1671e and 19 CFR Part 351.","es":"En las entradas sujetas a una orden de ADD/CVD, el importador deposita los derechos estimados a la tasa de depósito en efectivo vigente; los derechos finales se evalúan en la liquidación tras cualquier revisión administrativa. Véase 19 USC 1673e/1671e y 19 CFR Part 351.","ru":"При ввозах, подпадающих под приказ ADD/CVD, импортер вносит депозит расчетных пошлин по действующей ставке денежного депозита; окончательные пошлины начисляются при ликвидации после любого административного пересмотра. См. 19 USC 1673e/1671e и 19 CFR Part 351.","tr":"ADD/CVD emrine tabi girişlerde, ithalatçı yürürlükteki nakit depozito oranıyla tahmini vergileri yatırır; nihai vergiler, herhangi bir idari incelemenin ardından tasfiye sırasında tahakkuk ettirilir. Bkz. 19 USC 1673e/1671e ve 19 CFR Part 351.","hi":"ADD/CVD आदेश के अधीन प्रविष्टियों पर, आयातक प्रचलित नकद-जमा दर पर अनुमानित शुल्क जमा करता है; अंतिम शुल्क किसी भी प्रशासनिक समीक्षा के बाद परिसमापन (liquidation) पर निर्धारित किए जाते हैं। 19 USC 1673e/1671e और 19 CFR Part 351 देखें।","ar":"في الإدخالات الخاضعة لأمر ADD/CVD، يودع المستورد الرسوم المقدّرة بمعدل الإيداع النقدي المعمول به؛ وتُقرَّر الرسوم النهائية عند التصفية بعد أي مراجعة إدارية. انظر 19 USC 1673e/1671e و19 CFR Part 351."}},{"cat":"duties","a":2,"q":{"en":"Liquidation of an entry is best described as which of the following?","es":"¿La liquidación de una entrada se describe mejor como cuál de las siguientes?","ru":"Что из перечисленного лучше всего описывает ликвидацию ввоза?","tr":"Bir girişin tasfiyesi aşağıdakilerden hangisi olarak en iyi şekilde tanımlanır?","hi":"किसी प्रविष्टि के परिसमापन (liquidation) को निम्नलिखित में से किस रूप में सबसे अच्छी तरह वर्णित किया जाता है?","ar":"أي مما يلي يصف تصفية الإدخال (liquidation) على نحو أدق؟"},"o":[{"en":"The importer's deposit of estimated duties at entry","es":"El depósito del importador de los derechos estimados en la entrada","ru":"Внесение импортером депозита расчетных пошлин при ввозе","tr":"İthalatçının girişte tahmini vergileri yatırması","hi":"प्रविष्टि पर आयातक द्वारा अनुमानित शुल्क की जमा","ar":"إيداع المستورد للرسوم المقدّرة عند الإدخال"},{"en":"The cancellation of an entry summary before payment","es":"La cancelación de un resumen de entrada antes del pago","ru":"Аннулирование сводки ввоза (entry summary) до оплаты","tr":"Ödemeden önce giriş özetinin iptal edilmesi","hi":"भुगतान से पहले प्रविष्टि सारांश (entry summary) का रद्द होना","ar":"إلغاء ملخص الإدخال (entry summary) قبل الدفع"},{"en":"CBP's final computation of the duties, taxes, and fees due on an entry","es":"El cálculo final de CBP de los derechos, impuestos y tarifas adeudados en una entrada","ru":"Окончательный расчет CBP пошлин, налогов и сборов, причитающихся по ввозу","tr":"CBP'nin bir girişte ödenmesi gereken vergi, harç ve ücretlerin nihai hesaplaması","hi":"किसी प्रविष्टि पर देय शुल्क, कर और फीस की CBP द्वारा अंतिम गणना","ar":"الحساب النهائي الذي تجريه CBP للرسوم والضرائب والرسوم المستحقة على الإدخال"},{"en":"The release of merchandise from CBP custody","es":"La liberación de mercancía de la custodia de CBP","ru":"Выпуск товаров из-под надзора CBP","tr":"Malların CBP gözetiminden serbest bırakılması","hi":"CBP की अभिरक्षा से माल का निर्गमन","ar":"الإفراج عن البضائع من عهدة CBP"}],"e":{"en":"Liquidation is CBP's final ascertainment and assessment of the duties, taxes, and fees accruing on an entry. It triggers the protest period. See 19 CFR 159.1.","es":"La liquidación es la determinación y evaluación final de CBP de los derechos, impuestos y tarifas que se acumulan en una entrada. Da inicio al período de protesta. Véase 19 CFR 159.1.","ru":"Ликвидация — это окончательное установление и начисление CBP пошлин, налогов и сборов, накапливающихся по ввозу. Она запускает срок для подачи протеста. См. 19 CFR 159.1.","tr":"Tasfiye, CBP'nin bir girişte tahakkuk eden vergi, harç ve ücretleri nihai olarak tespit ve tahakkuk ettirmesidir. İtiraz süresini başlatır. Bkz. 19 CFR 159.1.","hi":"परिसमापन (liquidation) किसी प्रविष्टि पर उपचित होने वाले शुल्क, कर और फीस का CBP द्वारा अंतिम निर्धारण और मूल्यांकन है। यह आपत्ति (protest) अवधि को आरंभ करता है। 19 CFR 159.1 देखें।","ar":"التصفية هي التحديد والتقدير النهائي من جانب CBP للرسوم والضرائب والرسوم المستحقة على الإدخال. وهي تبدأ فترة الاعتراض (protest). انظر 19 CFR 159.1."}},{"cat":"duties","a":2,"q":{"en":"Unused-merchandise drawback under 19 CFR Part 190 is available when imported, duty-paid merchandise is:","es":"El drawback de mercancía no utilizada bajo 19 CFR Part 190 está disponible cuando la mercancía importada con derechos pagados es:","ru":"Возврат пошлин по неиспользованным товарам (drawback) согласно 19 CFR Part 190 доступен, когда импортированный товар, по которому уплачены пошлины:","tr":"19 CFR Part 190 kapsamında kullanılmamış malların drawback'i, ithal edilmiş, vergisi ödenmiş mal şu durumda mevcuttur:","hi":"19 CFR Part 190 के अंतर्गत अप्रयुक्त-माल ड्रॉबैक तब उपलब्ध होता है जब आयातित, शुल्क-भुगतान किया गया माल:","ar":"يتوفر استرداد الرسوم عن البضائع غير المستخدَمة بموجب 19 CFR Part 190 عندما تكون البضاعة المستوردة المدفوعة الرسوم:"},"o":[{"en":"Used in domestic manufacturing before being sold","es":"Utilizada en la fabricación nacional antes de ser vendida","ru":"Использован во внутреннем производстве до продажи","tr":"Satılmadan önce yerli imalatta kullanılmış","hi":"बेचे जाने से पहले घरेलू विनिर्माण में उपयोग की गई","ar":"مستخدَمة في التصنيع المحلي قبل بيعها"},{"en":"Re-sold to a domestic customer within the United States","es":"Revendida a un cliente nacional dentro de los Estados Unidos","ru":"Перепродан внутреннему покупателю в пределах Соединенных Штатов","tr":"Amerika Birleşik Devletleri içinde yerli bir müşteriye yeniden satılmış","hi":"संयुक्त राज्य अमेरिका के भीतर किसी घरेलू ग्राहक को पुनः बेची गई","ar":"أُعيد بيعها لعميل محلي داخل الولايات المتحدة"},{"en":"Exported or destroyed without being used in the United States","es":"Exportada o destruida sin haber sido utilizada en los Estados Unidos","ru":"Экспортирован или уничтожен без использования в Соединенных Штатах","tr":"Amerika Birleşik Devletleri'nde kullanılmadan ihraç edilmiş veya imha edilmiş","hi":"संयुक्त राज्य अमेरिका में उपयोग किए बिना निर्यात या नष्ट की गई","ar":"مُصدَّرة أو متلَفة دون أن تُستخدَم في الولايات المتحدة"},{"en":"Returned to the importer for warranty repair","es":"Devuelta al importador para reparación en garantía","ru":"Возвращен импортеру для гарантийного ремонта","tr":"Garanti onarımı için ithalatçıya iade edilmiş","hi":"वारंटी मरम्मत के लिए आयातक को वापस की गई","ar":"أُعيدت إلى المستورد للإصلاح بموجب الضمان"}],"e":{"en":"Unused-merchandise drawback applies to imported duty-paid merchandise that is exported or destroyed under CBP supervision without having been used in the U.S. See 19 USC 1313(j) and 19 CFR 190 Subpart C.","es":"El drawback de mercancía no utilizada se aplica a la mercancía importada con derechos pagados que se exporta o se destruye bajo supervisión de CBP sin haber sido utilizada en los EE. UU. Véase 19 USC 1313(j) y 19 CFR 190 Subpart C.","ru":"Возврат пошлин по неиспользованным товарам применяется к импортированным товарам с уплаченными пошлинами, которые экспортируются или уничтожаются под надзором CBP без использования в США. См. 19 USC 1313(j) и 19 CFR 190 Subpart C.","tr":"Kullanılmamış mal drawback'i, ABD'de kullanılmadan CBP gözetiminde ihraç edilen veya imha edilen, ithal edilmiş vergisi ödenmiş mallara uygulanır. Bkz. 19 USC 1313(j) ve 19 CFR 190 Subpart C.","hi":"अप्रयुक्त-माल ड्रॉबैक उस आयातित शुल्क-भुगतान किए गए माल पर लागू होता है जिसे अमेरिका में उपयोग किए बिना CBP की निगरानी में निर्यात या नष्ट किया जाता है। 19 USC 1313(j) और 19 CFR 190 Subpart C देखें।","ar":"ينطبق استرداد الرسوم عن البضائع غير المستخدَمة على البضائع المستوردة المدفوعة الرسوم التي تُصدَّر أو تُتلَف تحت إشراف CBP دون أن تكون قد استُخدمت في الولايات المتحدة. انظر 19 USC 1313(j) و19 CFR 190 Subpart C."}},{"cat":"duties","a":2,"q":{"en":"Which statement regarding the Harbor Maintenance Fee is correct?","es":"¿Qué afirmación respecto a la Tarifa de Mantenimiento de Puertos (Harbor Maintenance Fee) es correcta?","ru":"Какое утверждение относительно сбора за содержание гаваней (Harbor Maintenance Fee) является верным?","tr":"Liman Bakım Ücreti (Harbor Maintenance Fee) ile ilgili hangi ifade doğrudur?","hi":"Harbor Maintenance Fee के संबंध में कौन सा कथन सही है?","ar":"أي عبارة بخصوص رسوم صيانة الموانئ (Harbor Maintenance Fee) صحيحة؟"},"o":[{"en":"It is collected only on exports of commercial cargo","es":"Se cobra únicamente sobre las exportaciones de carga comercial","ru":"Взимается только при экспорте коммерческого груза","tr":"Yalnızca ticari yük ihracatında tahsil edilir","hi":"यह केवल वाणिज्यिक माल के निर्यात पर वसूला जाता है","ar":"تُحصَّل فقط على صادرات البضائع التجارية"},{"en":"It applies to all imports regardless of mode of transportation","es":"Se aplica a todas las importaciones independientemente del modo de transporte","ru":"Применяется ко всем импортным товарам независимо от вида транспорта","tr":"Taşıma şekline bakılmaksızın tüm ithalatlara uygulanır","hi":"यह परिवहन के तरीके की परवाह किए बिना सभी आयातों पर लागू होता है","ar":"تنطبق على جميع الواردات بغض النظر عن وسيلة النقل"},{"en":"It applies to commercial cargo moved by vessel but not to air or truck shipments","es":"Se aplica a la carga comercial transportada por buque pero no a los envíos aéreos o por camión","ru":"Применяется к коммерческому грузу, перемещаемому судном, но не к авиа- или автомобильным перевозкам","tr":"Gemiyle taşınan ticari yüke uygulanır ancak hava veya kamyon sevkiyatlarına uygulanmaz","hi":"यह जहाज द्वारा ले जाए गए वाणिज्यिक माल पर लागू होता है, परंतु हवाई या ट्रक शिपमेंट पर नहीं","ar":"تنطبق على البضائع التجارية المنقولة بحراً بالسفن وليس على الشحنات الجوية أو شحنات الشاحنات"},{"en":"It is capped at the same maximum as the formal-entry MPF","es":"Tiene el mismo tope máximo que la MPF de entrada formal","ru":"Имеет тот же максимальный предел, что и MPF при формальном ввозе","tr":"Resmi giriş MPF ile aynı azami tutarda sınırlandırılmıştır","hi":"इसकी ऊपरी सीमा औपचारिक-प्रविष्टि MPF के समान अधिकतम पर निर्धारित है","ar":"محدّدة بحد أقصى مماثل للحد الأقصى لرسوم MPF للإدخال الرسمي"}],"e":{"en":"HMF applies to commercial cargo loaded or unloaded from a commercial vessel at a designated port; air and land border shipments are not subject to HMF. See 19 CFR 24.24(a).","es":"La HMF se aplica a la carga comercial cargada o descargada de un buque comercial en un puerto designado; los envíos aéreos y por frontera terrestre no están sujetos a la HMF. Véase 19 CFR 24.24(a).","ru":"HMF применяется к коммерческому грузу, погружаемому или выгружаемому с коммерческого судна в установленном порту; авиа- и наземные приграничные перевозки не подлежат HMF. См. 19 CFR 24.24(a).","tr":"HMF, belirlenmiş bir limanda ticari bir gemiye yüklenen veya gemiden boşaltılan ticari yüke uygulanır; hava ve kara sınır sevkiyatları HMF'ye tabi değildir. Bkz. 19 CFR 24.24(a).","hi":"HMF किसी निर्दिष्ट बंदरगाह पर वाणिज्यिक जहाज से लादे या उतारे गए वाणिज्यिक माल पर लागू होता है; हवाई और भूमि-सीमा शिपमेंट HMF के अधीन नहीं हैं। 19 CFR 24.24(a) देखें।","ar":"تنطبق رسوم HMF على البضائع التجارية التي تُحمَّل على سفينة تجارية أو تُفرَّغ منها في ميناء معيَّن؛ ولا تخضع الشحنات الجوية وشحنات الحدود البرية لرسوم HMF. انظر 19 CFR 24.24(a)."}},{"cat":"duties","a":0,"q":{"en":"Which of the following CBP decisions is properly the subject of a protest under 19 USC 1514?","es":"¿Cuál de las siguientes decisiones de CBP es debidamente objeto de una protesta bajo 19 USC 1514?","ru":"Какое из следующих решений CBP надлежащим образом является предметом протеста согласно 19 USC 1514?","tr":"Aşağıdaki CBP kararlarından hangisi 19 USC 1514 kapsamında usulüne uygun olarak bir itirazın konusudur?","hi":"निम्नलिखित में से कौन सा CBP निर्णय 19 USC 1514 के अंतर्गत आपत्ति (protest) का उचित विषय है?","ar":"أي من قرارات CBP التالية يُعدّ على نحو صحيح موضوعاً للاعتراض بموجب 19 USC 1514؟"},"o":[{"en":"The classification and rate of duty assessed on liquidated merchandise","es":"La clasificación y la tasa de derechos evaluada sobre mercancía liquidada","ru":"Классификация и ставка пошлины, начисленные на ликвидированный товар","tr":"Tasfiye edilmiş mal üzerinde tahakkuk ettirilen sınıflandırma ve vergi oranı","hi":"परिसमापित माल पर निर्धारित वर्गीकरण और शुल्क दर","ar":"التصنيف ومعدل الرسوم المقرَّر على البضائع المصفّاة"},{"en":"The injury determination made by the U.S. International Trade Commission","es":"La determinación de daño realizada por la Comisión de Comercio Internacional de los EE. UU.","ru":"Определение ущерба, вынесенное Комиссией США по международной торговле","tr":"ABD Uluslararası Ticaret Komisyonu tarafından yapılan zarar tespiti","hi":"यू.एस. इंटरनेशनल ट्रेड कमीशन द्वारा किया गया क्षति निर्धारण","ar":"تحديد الضرر الذي تجريه لجنة التجارة الدولية الأمريكية"},{"en":"The dumping margin calculated by the Department of Commerce","es":"El margen de dumping calculado por el Departamento de Comercio","ru":"Демпинговая маржа, рассчитанная Министерством торговли","tr":"Ticaret Bakanlığı tarafından hesaplanan damping marjı","hi":"वाणिज्य विभाग (Department of Commerce) द्वारा गणना किया गया डंपिंग मार्जिन","ar":"هامش الإغراق الذي تحتسبه وزارة التجارة"},{"en":"A binding ruling issued before entry by CBP Headquarters","es":"Una resolución vinculante emitida antes de la entrada por la Sede de CBP","ru":"Обязывающее решение (ruling), вынесенное до ввоза штаб-квартирой CBP","tr":"Girişten önce CBP Genel Merkezi tarafından verilen bağlayıcı bir karar (ruling)","hi":"CBP मुख्यालय द्वारा प्रविष्टि से पहले जारी किया गया बाध्यकारी निर्णय (ruling)","ar":"قرار مُلزِم (ruling) صادر قبل الإدخال عن المقر الرئيسي لـ CBP"}],"e":{"en":"Protestable matters include appraised value, classification, rate and amount of duties, and liquidation/reliquidation. Commerce's margin and the ITC's injury finding are not protestable to CBP. See 19 USC 1514(a) and 19 CFR 174.11.","es":"Los asuntos protestables incluyen el valor tasado, la clasificación, la tasa y el monto de los derechos, y la liquidación/reliquidación. El margen de Comercio y la conclusión de daño de la ITC no son protestables ante CBP. Véase 19 USC 1514(a) y 19 CFR 174.11.","ru":"К опротестовываемым вопросам относятся оцененная стоимость, классификация, ставка и сумма пошлин, а также ликвидация/переликвидация. Маржа Министерства торговли и заключение ITC об ущербе не подлежат протесту в CBP. См. 19 USC 1514(a) и 19 CFR 174.11.","tr":"İtiraz edilebilir konular arasında takdir edilen değer, sınıflandırma, vergilerin oranı ve tutarı ile tasfiye/yeniden tasfiye yer alır. Ticaret Bakanlığı'nın marjı ve ITC'nin zarar tespiti CBP'ye itiraz edilemez. Bkz. 19 USC 1514(a) ve 19 CFR 174.11.","hi":"आपत्ति-योग्य मामलों में मूल्यांकित मूल्य, वर्गीकरण, शुल्क की दर और राशि, तथा परिसमापन/पुनर्परिसमापन शामिल हैं। वाणिज्य का मार्जिन और ITC का क्षति निष्कर्ष CBP के समक्ष आपत्ति-योग्य नहीं हैं। 19 USC 1514(a) और 19 CFR 174.11 देखें।","ar":"تشمل المسائل القابلة للاعتراض القيمة المقدَّرة والتصنيف ومعدل الرسوم ومقدارها والتصفية/إعادة التصفية. أما هامش وزارة التجارة وقرار الضرر الصادر عن ITC فلا يجوز الاعتراض عليهما لدى CBP. انظر 19 USC 1514(a) و19 CFR 174.11."}},{"cat":"duties","a":0,"q":{"en":"Under TFTEA substitution unused-merchandise drawback, substituted merchandise generally must match the imported merchandise on what basis?","es":"Bajo el drawback de mercancía no utilizada por sustitución de TFTEA, ¿sobre qué base debe coincidir generalmente la mercancía sustituida con la mercancía importada?","ru":"В рамках возврата пошлин по неиспользованным товарам с замещением по TFTEA, замещающий товар, как правило, должен соответствовать импортированному товару на каком основании?","tr":"TFTEA ikame kullanılmamış mal drawback'i kapsamında, ikame edilen mal genellikle ithal edilen malla hangi esasa göre eşleşmelidir?","hi":"TFTEA प्रतिस्थापन अप्रयुक्त-माल ड्रॉबैक के अंतर्गत, प्रतिस्थापित माल को आम तौर पर आयातित माल से किस आधार पर मेल खाना चाहिए?","ar":"بموجب استرداد الرسوم عن البضائع غير المستخدَمة بالإحلال وفقاً لـ TFTEA، يجب عموماً أن تتطابق البضاعة المُحلَّة مع البضاعة المستوردة على أي أساس؟"},"o":[{"en":"The same 8-digit HTSUS subheading","es":"La misma subpartida de 8 dígitos del HTSUS","ru":"Та же 8-значная субпозиция HTSUS","tr":"Aynı 8 haneli HTSUS alt başlığı","hi":"वही 8-अंकीय HTSUS उपशीर्षक","ar":"البند الفرعي ذاته المكوّن من 8 أرقام في HTSUS"},{"en":"Commercial interchangeability determined case by case","es":"Intercambiabilidad comercial determinada caso por caso","ru":"Коммерческая взаимозаменяемость, определяемая в каждом конкретном случае","tr":"Vaka bazında belirlenen ticari değiştirilebilirlik","hi":"मामले-दर-मामले निर्धारित वाणिज्यिक विनिमेयता","ar":"قابلية التبادل التجاري التي تُحدَّد حالة بحالة"},{"en":"An identical Schedule B description only","es":"Únicamente una descripción idéntica del Schedule B","ru":"Только идентичное описание по Schedule B","tr":"Yalnızca aynı Schedule B tanımı","hi":"केवल एक समान Schedule B विवरण","ar":"وصف مطابق في Schedule B فقط"},{"en":"The same 10-digit HTSUS statistical suffix","es":"El mismo sufijo estadístico de 10 dígitos del HTSUS","ru":"Тот же 10-значный статистический суффикс HTSUS","tr":"Aynı 10 haneli HTSUS istatistiksel son eki","hi":"वही 10-अंकीय HTSUS सांख्यिकीय प्रत्यय","ar":"اللاحقة الإحصائية ذاتها المكوّنة من 10 أرقام في HTSUS"}],"e":{"en":"TFTEA replaced the commercial-interchangeability standard for most claims with substitution based on the same 8-digit HTSUS subheading (subject to certain restrictions). See 19 USC 1313(j)(2) and 19 CFR 190.32.","es":"TFTEA reemplazó el estándar de intercambiabilidad comercial para la mayoría de las reclamaciones con la sustitución basada en la misma subpartida de 8 dígitos del HTSUS (sujeta a ciertas restricciones). Véase 19 USC 1313(j)(2) y 19 CFR 190.32.","ru":"TFTEA заменил стандарт коммерческой взаимозаменяемости для большинства требований замещением на основе той же 8-значной субпозиции HTSUS (с учетом определенных ограничений). См. 19 USC 1313(j)(2) и 19 CFR 190.32.","tr":"TFTEA, çoğu talep için ticari değiştirilebilirlik standardını, aynı 8 haneli HTSUS alt başlığına dayalı ikame ile değiştirmiştir (belirli kısıtlamalara tabi olarak). Bkz. 19 USC 1313(j)(2) ve 19 CFR 190.32.","hi":"TFTEA ने अधिकांश दावों के लिए वाणिज्यिक-विनिमेयता मानक को वही 8-अंकीय HTSUS उपशीर्षक पर आधारित प्रतिस्थापन से बदल दिया (कुछ प्रतिबंधों के अधीन)। 19 USC 1313(j)(2) और 19 CFR 190.32 देखें।","ar":"استبدل TFTEA معيار قابلية التبادل التجاري بالنسبة لمعظم المطالبات بالإحلال القائم على البند الفرعي ذاته المكوّن من 8 أرقام في HTSUS (مع مراعاة قيود معينة). انظر 19 USC 1313(j)(2) و19 CFR 190.32."}},{"cat":"duties","a":3,"q":{"en":"Reliquidation of an entry by CBP on its own initiative to correct errors generally must occur within what period from the date of the original liquidation?","es":"La reliquidación de una entrada por CBP por iniciativa propia para corregir errores generalmente debe ocurrir dentro de qué período desde la fecha de la liquidación original?","ru":"Переликвидация ввоза, проводимая CBP по собственной инициативе для исправления ошибок, как правило, должна произойти в течение какого периода с даты первоначальной ликвидации?","tr":"CBP'nin hataları düzeltmek için kendi inisiyatifiyle bir girişi yeniden tasfiye etmesi, genellikle orijinal tasfiye tarihinden itibaren hangi süre içinde gerçekleşmelidir?","hi":"त्रुटियों को सुधारने के लिए CBP द्वारा अपनी पहल पर किसी प्रविष्टि का पुनर्परिसमापन आम तौर पर मूल परिसमापन की तिथि से किस अवधि के भीतर होना चाहिए?","ar":"إعادة تصفية الإدخال من جانب CBP بمبادرة منها لتصحيح الأخطاء يجب أن تتم عموماً خلال أي فترة من تاريخ التصفية الأصلية؟"},"o":[{"en":"180 days","es":"180 days","ru":"180 days","tr":"180 days","hi":"180 days","ar":"180 days"},{"en":"1 year","es":"1 año","ru":"1 год","tr":"1 yıl","hi":"1 वर्ष","ar":"سنة واحدة"},{"en":"5 years","es":"5 años","ru":"5 лет","tr":"5 yıl","hi":"5 वर्ष","ar":"5 سنوات"},{"en":"90 days","es":"90 days","ru":"90 days","tr":"90 days","hi":"90 days","ar":"90 days"}],"e":{"en":"CBP may voluntarily reliquidate an entry to correct errors within 90 days from the date notice of the original liquidation is given. See 19 USC 1501 and 19 CFR 173.3.","es":"CBP puede reliquidar voluntariamente una entrada para corregir errores dentro de los 90 days a partir de la fecha en que se da el aviso de la liquidación original. Véase 19 USC 1501 y 19 CFR 173.3.","ru":"CBP может добровольно переликвидировать ввоз для исправления ошибок в течение 90 days с даты вручения уведомления о первоначальной ликвидации. См. 19 USC 1501 и 19 CFR 173.3.","tr":"CBP, hataları düzeltmek için bir girişi, orijinal tasfiyeye ilişkin bildirimin verildiği tarihten itibaren 90 days içinde gönüllü olarak yeniden tasfiye edebilir. Bkz. 19 USC 1501 ve 19 CFR 173.3.","hi":"CBP त्रुटियों को सुधारने के लिए किसी प्रविष्टि का स्वेच्छा से पुनर्परिसमापन मूल परिसमापन की सूचना दिए जाने की तिथि से 90 days के भीतर कर सकता है। 19 USC 1501 और 19 CFR 173.3 देखें।","ar":"يجوز لـ CBP إعادة تصفية الإدخال طوعاً لتصحيح الأخطاء خلال 90 days من تاريخ تقديم إشعار التصفية الأصلية. انظر 19 USC 1501 و19 CFR 173.3."}},{"cat":"duties","a":2,"q":{"en":"An importer files a formal entry with an entered value of $4,000. Disregarding the minimum and maximum, what is the MPF computed at the FY2026 ad valorem rate?","es":"Un importador presenta una entrada formal con un valor declarado de $4,000. Sin tener en cuenta el mínimo y el máximo, ¿cuál es la MPF calculada a la tasa ad valorem del FY2026?","ru":"Импортер подает формальный ввоз с заявленной стоимостью $4,000. Без учета минимума и максимума, какова MPF, рассчитанная по адвалорной ставке FY2026?","tr":"Bir ithalatçı, beyan edilen değeri $4,000 olan resmi bir giriş yapar. Asgari ve azami tutarlar göz ardı edildiğinde, FY2026 ad valorem oranıyla hesaplanan MPF nedir?","hi":"एक आयातक $4,000 के प्रविष्ट मूल्य के साथ एक औपचारिक प्रविष्टि दाखिल करता है। न्यूनतम और अधिकतम की अनदेखी करते हुए, FY2026 ad valorem दर पर गणना की गई MPF क्या है?","ar":"يقدّم مستورد إدخالاً رسمياً بقيمة مُدخَلة قدرها $4,000. بصرف النظر عن الحد الأدنى والحد الأقصى، ما هي رسوم MPF المحسوبة بالنسبة القيمية (ad valorem) للسنة المالية FY2026؟"},"o":[{"en":"$50.00","es":"$50.00","ru":"$50.00","tr":"$50.00","hi":"$50.00","ar":"$50.00"},{"en":"$5.00","es":"$5.00","ru":"$5.00","tr":"$5.00","hi":"$5.00","ar":"$5.00"},{"en":"$13.86","es":"$13.86","ru":"$13.86","tr":"$13.86","hi":"$13.86","ar":"$13.86"},{"en":"$33.58","es":"$33.58","ru":"$33.58","tr":"$33.58","hi":"$33.58","ar":"$33.58"}],"e":{"en":"$4,000 x 0.003464 = $13.86. This is the raw ad valorem MPF; in practice the $33.58 formal-entry minimum would apply, but the question asks for the ad valorem computation disregarding the min and max. See 19 CFR 24.23(b)(1).","es":"$4,000 x 0.003464 = $13.86. Esta es la MPF ad valorem en bruto; en la práctica se aplicaría el mínimo de entrada formal de $33.58, pero la pregunta pide el cálculo ad valorem sin tener en cuenta el mínimo y el máximo. Véase 19 CFR 24.23(b)(1).","ru":"$4,000 x 0.003464 = $13.86. Это базовая адвалорная MPF; на практике применялся бы минимум $33.58 при формальном ввозе, но в вопросе требуется адвалорный расчет без учета минимума и максимума. См. 19 CFR 24.23(b)(1).","tr":"$4,000 x 0.003464 = $13.86. Bu, ham ad valorem MPF'dir; uygulamada $33.58 resmi giriş asgari tutarı geçerli olurdu, ancak soru asgari ve azami tutarları göz ardı eden ad valorem hesaplamasını istemektedir. Bkz. 19 CFR 24.23(b)(1).","hi":"$4,000 x 0.003464 = $13.86. यह कच्ची ad valorem MPF है; व्यवहार में $33.58 की औपचारिक-प्रविष्टि न्यूनतम लागू होती, लेकिन प्रश्न न्यूनतम और अधिकतम की अनदेखी करते हुए ad valorem गणना मांगता है। 19 CFR 24.23(b)(1) देखें।","ar":"$4,000 x 0.003464 = $13.86. هذه هي رسوم MPF القيمية (ad valorem) الأولية؛ ومن الناحية العملية سيُطبَّق الحد الأدنى للإدخال الرسمي البالغ $33.58، لكن السؤال يطلب الحساب القيمي بصرف النظر عن الحد الأدنى والحد الأقصى. انظر 19 CFR 24.23(b)(1)."}},{"cat":"duties","a":0,"q":{"en":"A party may request accelerated disposition of a protest. If CBP does not allow or deny the protest within a set period after the request is mailed, the protest is deemed denied. What is that period?","es":"Una parte puede solicitar la disposición acelerada de una protesta. Si CBP no admite ni rechaza la protesta dentro de un período establecido después de que se envíe la solicitud por correo, la protesta se considera denegada. ¿Cuál es ese período?","ru":"Сторона может запросить ускоренное рассмотрение протеста. Если CBP не удовлетворяет и не отклоняет протест в установленный срок после отправки запроса по почте, протест считается отклоненным. Каков этот срок?","tr":"Bir taraf, bir itirazın hızlandırılmış şekilde sonuçlandırılmasını talep edebilir. CBP, talep postalandıktan sonra belirli bir süre içinde itirazı kabul veya reddetmezse, itiraz reddedilmiş sayılır. Bu süre nedir?","hi":"कोई पक्ष किसी आपत्ति (protest) के त्वरित निपटान का अनुरोध कर सकता है। यदि अनुरोध डाक से भेजे जाने के बाद एक निर्धारित अवधि के भीतर CBP आपत्ति को न तो स्वीकार करता है और न ही अस्वीकार करता है, तो आपत्ति को अस्वीकृत माना जाता है। वह अवधि क्या है?","ar":"يجوز لأي طرف أن يطلب البتّ المعجَّل في الاعتراض. وإذا لم تقبل CBP الاعتراض أو ترفضه خلال فترة محددة بعد إرسال الطلب بالبريد، يُعدّ الاعتراض مرفوضاً. ما هي تلك الفترة؟"},"o":[{"en":"30 days","es":"30 days","ru":"30 days","tr":"30 days","hi":"30 days","ar":"30 days"},{"en":"180 days","es":"180 days","ru":"180 days","tr":"180 days","hi":"180 days","ar":"180 days"},{"en":"90 days","es":"90 days","ru":"90 days","tr":"90 days","hi":"90 days","ar":"90 days"},{"en":"60 days","es":"60 days","ru":"60 days","tr":"60 days","hi":"60 days","ar":"60 days"}],"e":{"en":"A request for accelerated disposition is deemed denied if CBP does not act within 30 days after the date of mailing of the request, allowing the protestant to proceed to the Court of International Trade. See 19 USC 1515(b) and 19 CFR 174.22.","es":"Una solicitud de disposición acelerada se considera denegada si CBP no actúa dentro de los 30 days posteriores a la fecha de envío de la solicitud por correo, lo que permite al protestante proceder ante el Tribunal de Comercio Internacional. Véase 19 USC 1515(b) y 19 CFR 174.22.","ru":"Запрос об ускоренном рассмотрении считается отклоненным, если CBP не принимает мер в течение 30 days после даты отправки запроса по почте, что позволяет подателю протеста обратиться в Суд по международной торговле. См. 19 USC 1515(b) и 19 CFR 174.22.","tr":"Hızlandırılmış sonuçlandırma talebi, CBP talebin postalanma tarihinden itibaren 30 days içinde işlem yapmazsa reddedilmiş sayılır ve bu da itiraz edenin Uluslararası Ticaret Mahkemesi'ne başvurmasına olanak tanır. Bkz. 19 USC 1515(b) ve 19 CFR 174.22.","hi":"त्वरित निपटान का अनुरोध अस्वीकृत माना जाता है यदि CBP अनुरोध डाक से भेजे जाने की तिथि के बाद 30 days के भीतर कार्रवाई नहीं करता, जिससे आपत्तिकर्ता को अंतर्राष्ट्रीय व्यापार न्यायालय (Court of International Trade) में आगे बढ़ने की अनुमति मिलती है। 19 USC 1515(b) और 19 CFR 174.22 देखें।","ar":"يُعدّ طلب البتّ المعجَّل مرفوضاً إذا لم تتصرّف CBP خلال 30 days من تاريخ إرسال الطلب بالبريد، مما يتيح للمعترض المضيّ قُدماً إلى محكمة التجارة الدولية. انظر 19 USC 1515(b) و19 CFR 174.22."}},{"cat":"duties","a":2,"q":{"en":"Manufacturing drawback under 19 USC 1313(a) and (b) is available in which of the following circumstances?","es":"¿En cuál de las siguientes circunstancias está disponible el drawback de manufactura conforme a 19 USC 1313(a) y (b)?","ru":"В каком из следующих случаев доступен производственный возврат пошлин (drawback) согласно 19 USC 1313(a) и (b)?","tr":"19 USC 1313(a) ve (b) kapsamındaki imalat drawback'i aşağıdaki durumlardan hangisinde mevcuttur?","hi":"19 USC 1313(a) और (b) के तहत विनिर्माण ड्रॉबैक निम्नलिखित में से किस परिस्थिति में उपलब्ध है?","ar":"متى يكون استرداد رسوم التصنيع (drawback) بموجب 19 USC 1313(a) و(b) متاحًا في أي من الحالات التالية؟"},"o":[{"en":"Imported merchandise is rejected and returned to the foreign seller","es":"La mercancía importada se rechaza y se devuelve al vendedor extranjero","ru":"Импортированный товар отклоняется и возвращается иностранному продавцу","tr":"İthal edilen mal reddedilir ve yabancı satıcıya iade edilir","hi":"आयातित माल को अस्वीकार कर विदेशी विक्रेता को वापस कर दिया जाता है","ar":"تُرفض البضاعة المستوردة وتُعاد إلى البائع الأجنبي"},{"en":"Imported merchandise is destroyed before entry is filed","es":"La mercancía importada se destruye antes de presentar la declaración de entrada","ru":"Импортированный товар уничтожается до подачи декларации о ввозе","tr":"İthal edilen mal, giriş beyanı verilmeden önce imha edilir","hi":"एंट्री दाखिल करने से पहले आयातित माल को नष्ट कर दिया जाता है","ar":"تُتلف البضاعة المستوردة قبل تقديم بيان الإدخال"},{"en":"Imported merchandise is used to manufacture an article that is then exported","es":"La mercancía importada se utiliza para fabricar un artículo que luego se exporta","ru":"Импортированный товар используется для изготовления изделия, которое затем экспортируется","tr":"İthal edilen mal, daha sonra ihraç edilen bir ürünü imal etmek için kullanılır","hi":"आयातित माल का उपयोग किसी वस्तु के विनिर्माण में किया जाता है जिसे फिर निर्यात किया जाता है","ar":"تُستخدم البضاعة المستوردة في تصنيع منتج يتم تصديره بعد ذلك"},{"en":"Imported merchandise is exported in the same condition as imported","es":"La mercancía importada se exporta en las mismas condiciones en que fue importada","ru":"Импортированный товар экспортируется в том же состоянии, в каком был импортирован","tr":"İthal edilen mal, ithal edildiği durumla aynı durumda ihraç edilir","hi":"आयातित माल को उसी स्थिति में निर्यात किया जाता है जिस स्थिति में आयात किया गया था","ar":"تُصدَّر البضاعة المستوردة بنفس الحالة التي استُوردت بها"}],"e":{"en":"Manufacturing drawback (direct identification under 1313(a) and substitution under 1313(b)) applies where imported duty-paid merchandise is used to manufacture or produce an article that is exported or destroyed. See 19 CFR 190 Subpart B.","es":"El drawback de manufactura (identificación directa conforme a 1313(a) y sustitución conforme a 1313(b)) se aplica cuando la mercancía importada con derechos pagados se utiliza para fabricar o producir un artículo que se exporta o se destruye. Véase 19 CFR 190 Subpart B.","ru":"Производственный возврат пошлин (прямая идентификация согласно 1313(a) и замещение согласно 1313(b)) применяется, когда импортированный товар с уплаченными пошлинами используется для изготовления или производства изделия, которое экспортируется или уничтожается. См. 19 CFR 190 Subpart B.","tr":"İmalat drawback'i (1313(a) kapsamında doğrudan tanımlama ve 1313(b) kapsamında ikame), gümrük vergisi ödenmiş ithal malın, ihraç edilen veya imha edilen bir ürünü imal etmek ya da üretmek için kullanıldığı durumlarda uygulanır. Bkz. 19 CFR 190 Subpart B.","hi":"विनिर्माण ड्रॉबैक (1313(a) के तहत प्रत्यक्ष पहचान और 1313(b) के तहत प्रतिस्थापन) तब लागू होता है जब शुल्क-भुगतान किए गए आयातित माल का उपयोग किसी ऐसी वस्तु के विनिर्माण या उत्पादन में किया जाता है जिसे निर्यात या नष्ट किया जाता है। देखें 19 CFR 190 Subpart B।","ar":"ينطبق استرداد رسوم التصنيع (التحديد المباشر بموجب 1313(a) والإحلال بموجب 1313(b)) عندما تُستخدم البضاعة المستوردة المدفوعة الرسوم لتصنيع أو إنتاج منتج يتم تصديره أو إتلافه. انظر 19 CFR 190 Subpart B."}},{"cat":"duties","a":0,"q":{"en":"Which fee or charge is NOT among those refundable through a TFTEA drawback claim?","es":"¿Cuál tasa o cargo NO se encuentra entre los reembolsables mediante una reclamación de drawback conforme a TFTEA?","ru":"Какой сбор или платеж НЕ относится к возмещаемым через заявление о возврате пошлин (drawback) согласно TFTEA?","tr":"Hangi ücret veya masraf, TFTEA drawback talebi yoluyla iade edilebilenler arasında DEĞİLDİR?","hi":"कौन-सा शुल्क या प्रभार TFTEA ड्रॉबैक दावे के माध्यम से वापसी योग्य लोगों में से नहीं है?","ar":"أي رسم أو تكلفة ليست من بين تلك القابلة للاسترداد عبر مطالبة استرداد الرسوم (drawback) بموجب TFTEA؟"},"o":[{"en":"The Harbor Maintenance Fee","es":"La Harbor Maintenance Fee","ru":"Сбор за обслуживание гавани (Harbor Maintenance Fee)","tr":"Harbor Maintenance Fee","hi":"Harbor Maintenance Fee","ar":"رسم صيانة الموانئ (Harbor Maintenance Fee)"},{"en":"The Merchandise Processing Fee","es":"La Merchandise Processing Fee","ru":"Сбор за обработку товаров (Merchandise Processing Fee)","tr":"Merchandise Processing Fee","hi":"Merchandise Processing Fee","ar":"رسم معالجة البضائع (Merchandise Processing Fee)"},{"en":"Ordinary customs duties","es":"Los derechos de aduana ordinarios","ru":"Обычные таможенные пошлины","tr":"Olağan gümrük vergileri","hi":"सामान्य सीमा शुल्क","ar":"الرسوم الجمركية العادية"},{"en":"Certain federal excise taxes","es":"Ciertos impuestos especiales federales (excise taxes)","ru":"Некоторые федеральные акцизные налоги","tr":"Belirli federal tüketim vergileri (excise taxes)","hi":"कुछ संघीय उत्पाद शुल्क (excise taxes)","ar":"بعض الضرائب الانتقائية الفيدرالية (excise taxes)"}],"e":{"en":"Drawback is available for duties, taxes, and fees such as MPF and many excise taxes, but the Harbor Maintenance Fee is not refundable as drawback. See 19 USC 1313 and 19 CFR 190.3.","es":"El drawback está disponible para derechos, impuestos y tasas tales como el MPF y muchos impuestos especiales (excise taxes), pero la Harbor Maintenance Fee no es reembolsable como drawback. Véase 19 USC 1313 y 19 CFR 190.3.","ru":"Возврат пошлин (drawback) доступен для пошлин, налогов и сборов, таких как MPF и многие акцизные налоги, но сбор за обслуживание гавани (Harbor Maintenance Fee) не возмещается в порядке drawback. См. 19 USC 1313 и 19 CFR 190.3.","tr":"Drawback; MPF ve birçok tüketim vergisi gibi vergiler, harçlar ve ücretler için mevcuttur, ancak Harbor Maintenance Fee drawback olarak iade edilemez. Bkz. 19 USC 1313 ve 19 CFR 190.3.","hi":"ड्रॉबैक MPF और कई उत्पाद शुल्कों जैसे शुल्कों, करों और फीस के लिए उपलब्ध है, लेकिन Harbor Maintenance Fee ड्रॉबैक के रूप में वापसी योग्य नहीं है। देखें 19 USC 1313 और 19 CFR 190.3।","ar":"يتوفر استرداد الرسوم (drawback) للرسوم والضرائب والمصاريف مثل MPF والعديد من الضرائب الانتقائية، لكن رسم صيانة الموانئ (Harbor Maintenance Fee) غير قابل للاسترداد كـ drawback. انظر 19 USC 1313 و19 CFR 190.3."}},{"cat":"duties","a":3,"q":{"en":"When a protest includes a properly supported application for further review, which statement is TRUE?","es":"Cuando una protesta incluye una solicitud de revisión adicional debidamente fundamentada, ¿cuál afirmación es VERDADERA?","ru":"Если протест включает надлежащим образом обоснованное ходатайство о дополнительном рассмотрении, какое утверждение ВЕРНО?","tr":"Bir itiraz, gerektiği gibi desteklenmiş bir ek inceleme başvurusu içerdiğinde, hangi ifade DOĞRUDUR?","hi":"जब किसी विरोध (protest) में उचित रूप से समर्थित आगे की समीक्षा हेतु आवेदन शामिल होता है, तो कौन-सा कथन सत्य है?","ar":"عندما يتضمن الاعتراض طلبًا مدعومًا بشكل سليم لإجراء مراجعة إضافية، أي عبارة تكون صحيحة؟"},"o":[{"en":"It extends the protest filing deadline to one year","es":"Amplía el plazo de presentación de la protesta a un año","ru":"Это продлевает срок подачи протеста до одного года","tr":"İtiraz başvuru süresini bir yıla uzatır","hi":"यह विरोध दाखिल करने की समय-सीमा को एक वर्ष तक बढ़ा देता है","ar":"يمدد الموعد النهائي لتقديم الاعتراض إلى سنة واحدة"},{"en":"It converts the protest into a request for an administrative ruling","es":"Convierte la protesta en una solicitud de resolución administrativa","ru":"Это превращает протест в запрос об административном решении","tr":"İtirazı idari bir karar talebine dönüştürür","hi":"यह विरोध को एक प्रशासनिक निर्णय के अनुरोध में परिवर्तित कर देता है","ar":"يحوّل الاعتراض إلى طلب للحصول على قرار إداري"},{"en":"It automatically suspends liquidation of all related entries","es":"Suspende automáticamente la liquidación de todas las declaraciones de entrada relacionadas","ru":"Это автоматически приостанавливает ликвидацию всех связанных деклараций о ввозе","tr":"İlgili tüm girişlerin tasfiyesini (liquidation) otomatik olarak askıya alır","hi":"यह सभी संबंधित एंट्रियों की लिक्विडेशन को स्वतः निलंबित कर देता है","ar":"يعلّق تلقائيًا تصفية (liquidation) جميع البيانات الجمركية ذات الصلة"},{"en":"It allows the matter to be reviewed by a CBP office other than the one that issued the decision","es":"Permite que el asunto sea revisado por una oficina de CBP distinta de la que emitió la decisión","ru":"Это позволяет рассмотреть вопрос подразделением CBP, отличным от того, которое вынесло решение","tr":"Konunun, kararı veren ofis dışında bir CBP ofisi tarafından incelenmesine olanak tanır","hi":"यह मामले की समीक्षा उस CBP कार्यालय द्वारा करने की अनुमति देता है जो उस कार्यालय से भिन्न है जिसने निर्णय जारी किया था","ar":"يسمح بمراجعة المسألة من قبل مكتب CBP غير المكتب الذي أصدر القرار"}],"e":{"en":"Further review under 19 CFR 174.21-174.24 allows a CBP authority beyond the port that made the decision to review the protest when the criteria of 19 CFR 174.24 are met. It does not extend the filing deadline.","es":"La revisión adicional conforme a 19 CFR 174.21-174.24 permite que una autoridad de CBP distinta del puerto que tomó la decisión revise la protesta cuando se cumplen los criterios de 19 CFR 174.24. No amplía el plazo de presentación.","ru":"Дополнительное рассмотрение согласно 19 CFR 174.21-174.24 позволяет органу CBP, помимо порта, принявшего решение, рассмотреть протест при соблюдении критериев 19 CFR 174.24. Оно не продлевает срок подачи.","tr":"19 CFR 174.21-174.24 kapsamındaki ek inceleme, 19 CFR 174.24 ölçütleri karşılandığında, kararı veren limanın ötesinde bir CBP makamının itirazı incelemesine olanak tanır. Başvuru süresini uzatmaz.","hi":"19 CFR 174.21-174.24 के तहत आगे की समीक्षा, 19 CFR 174.24 के मानदंड पूरे होने पर, निर्णय करने वाले बंदरगाह से परे किसी CBP प्राधिकरण को विरोध की समीक्षा करने की अनुमति देती है। यह दाखिल करने की समय-सीमा को नहीं बढ़ाती।","ar":"تتيح المراجعة الإضافية بموجب 19 CFR 174.21-174.24 لسلطة CBP خارج الميناء الذي اتخذ القرار مراجعة الاعتراض عند استيفاء معايير 19 CFR 174.24. وهي لا تمدد الموعد النهائي لتقديم الطلب."}},{"cat":"duties","a":3,"q":{"en":"Merchandise is appraised at $20,000 and is classified under a subheading carrying a compound rate of '2.5 cents/kg + 3.4%'. The shipment weighs 1,000 kg. What is the total duty?","es":"La mercancía se valora en $20,000 y se clasifica en una subpartida con una tasa compuesta de '2.5 cents/kg + 3.4%'. El envío pesa 1,000 kg. ¿Cuál es el derecho total?","ru":"Товар оценивается в $20,000 и классифицируется по субпозиции со сложной ставкой '2.5 cents/kg + 3.4%'. Партия весит 1,000 kg. Какова общая сумма пошлины?","tr":"Mal $20,000 olarak değerlendirilir ve '2.5 cents/kg + 3.4%' bileşik oranı taşıyan bir alt başlık altında sınıflandırılır. Sevkiyat 1,000 kg ağırlığındadır. Toplam vergi nedir?","hi":"माल का मूल्यांकन $20,000 किया गया है और इसे '2.5 cents/kg + 3.4%' की संयुक्त दर वाली एक उप-शीर्ष के अंतर्गत वर्गीकृत किया गया है। शिपमेंट का वजन 1,000 kg है। कुल शुल्क कितना है?","ar":"تُقدَّر قيمة البضاعة بـ $20,000 وتُصنَّف تحت بند فرعي يحمل معدلًا مركبًا قدره '2.5 cents/kg + 3.4%'. وزن الشحنة 1,000 kg. ما هو إجمالي الرسوم؟"},"o":[{"en":"$25.00","es":"$25.00","ru":"$25.00","tr":"$25.00","hi":"$25.00","ar":"$25.00"},{"en":"$680.00","es":"$680.00","ru":"$680.00","tr":"$680.00","hi":"$680.00","ar":"$680.00"},{"en":"$730.00","es":"$730.00","ru":"$730.00","tr":"$730.00","hi":"$730.00","ar":"$730.00"},{"en":"$705.00","es":"$705.00","ru":"$705.00","tr":"$705.00","hi":"$705.00","ar":"$705.00"}],"e":{"en":"Specific: 1,000 kg x $0.025 = $25.00. Ad valorem: $20,000 x 3.4% = $680.00. Total = $705.00. Compound duties add both components per HTSUS General Note 3.","es":"Específico: 1,000 kg x $0.025 = $25.00. Ad valorem: $20,000 x 3.4% = $680.00. Total = $705.00. Los derechos compuestos suman ambos componentes conforme a HTSUS General Note 3.","ru":"Специфический: 1,000 kg x $0.025 = $25.00. Адвалорный: $20,000 x 3.4% = $680.00. Итого = $705.00. Сложные пошлины суммируют оба компонента согласно HTSUS General Note 3.","tr":"Spesifik: 1,000 kg x $0.025 = $25.00. Ad valorem: $20,000 x 3.4% = $680.00. Toplam = $705.00. Bileşik vergiler, HTSUS General Note 3 uyarınca her iki bileşeni toplar.","hi":"विशिष्ट: 1,000 kg x $0.025 = $25.00। यथामूल्य (ad valorem): $20,000 x 3.4% = $680.00। कुल = $705.00। संयुक्त शुल्क HTSUS General Note 3 के अनुसार दोनों घटकों को जोड़ते हैं।","ar":"النوعي: 1,000 kg x $0.025 = $25.00. القيمي (ad valorem): $20,000 x 3.4% = $680.00. الإجمالي = $705.00. تجمع الرسوم المركبة كلا المكونين وفقًا لـ HTSUS General Note 3."}},{"cat":"duties","a":0,"q":{"en":"Under the prior disclosure provisions, a valid prior disclosure of a violation generally limits the disclosing party's exposure with respect to which item?","es":"Conforme a las disposiciones de divulgación previa (prior disclosure), una divulgación previa válida de una infracción generalmente limita la exposición de la parte que la divulga respecto de cuál concepto?","ru":"Согласно положениям о предварительном раскрытии (prior disclosure), действительное предварительное раскрытие нарушения, как правило, ограничивает ответственность раскрывающей стороны в отношении какого пункта?","tr":"Önceden ifşa (prior disclosure) hükümleri uyarınca, bir ihlalin geçerli bir önceden ifşası genellikle ifşa eden tarafın hangi kalem açısından maruziyetini sınırlar?","hi":"पूर्व प्रकटन (prior disclosure) प्रावधानों के तहत, किसी उल्लंघन का एक वैध पूर्व प्रकटन सामान्यतः प्रकटन करने वाले पक्ष की किस मद के संबंध में देयता को सीमित करता है?","ar":"بموجب أحكام الإفصاح المسبق (prior disclosure)، فإن الإفصاح المسبق الصحيح عن مخالفة يحد عمومًا من تعرض الطرف المُفصِح فيما يتعلق بأي بند؟"},"o":[{"en":"The amount of monetary penalties, while the actual lost duties plus interest remain payable","es":"El monto de las sanciones pecuniarias, mientras que los derechos efectivamente perdidos más intereses siguen siendo pagaderos","ru":"Размер денежных штрафов, при этом фактически утраченные пошлины плюс проценты по-прежнему подлежат уплате","tr":"Parasal cezaların tutarı; ancak fiilen kaybedilen vergiler artı faiz ödenmeye devam eder","hi":"मौद्रिक दंड की राशि, जबकि वास्तविक खोए हुए शुल्क और ब्याज देय बने रहते हैं","ar":"مقدار الغرامات المالية، في حين تظل الرسوم الفعلية المفقودة بالإضافة إلى الفائدة مستحقة الدفع"},{"en":"Both penalties and any obligation to tender the underlying duties","es":"Tanto las sanciones como cualquier obligación de pagar los derechos subyacentes","ru":"Как штрафы, так и любое обязательство по уплате основных пошлин","tr":"Hem cezalar hem de esas vergileri ödeme yükümlülüğü","hi":"दंड और अंतर्निहित शुल्कों का भुगतान करने का कोई भी दायित्व दोनों","ar":"كل من الغرامات وأي التزام بدفع الرسوم الأساسية"},{"en":"All civil and criminal liability arising from the violation","es":"Toda la responsabilidad civil y penal derivada de la infracción","ru":"Вся гражданская и уголовная ответственность, возникающая из нарушения","tr":"İhlalden doğan tüm hukuki ve cezai sorumluluk","hi":"उल्लंघन से उत्पन्न होने वाली समस्त सिविल और आपराधिक देयता","ar":"جميع المسؤولية المدنية والجنائية الناشئة عن المخالفة"},{"en":"Only the interest accruing on unpaid duties","es":"Únicamente los intereses devengados sobre los derechos no pagados","ru":"Только проценты, начисляемые на неуплаченные пошлины","tr":"Yalnızca ödenmemiş vergiler üzerinde tahakkuk eden faiz","hi":"केवल अदत्त शुल्कों पर अर्जित ब्याज","ar":"فقط الفائدة المتراكمة على الرسوم غير المدفوعة"}],"e":{"en":"A valid prior disclosure caps the penalty (e.g., to interest on lost duties in negligence cases), but the actual loss of duties, taxes, and fees plus interest must still be tendered. See 19 USC 1592(c)(4) and 19 CFR 162.74.","es":"Una divulgación previa válida limita la sanción (por ejemplo, a los intereses sobre los derechos perdidos en casos de negligencia), pero la pérdida efectiva de derechos, impuestos y tasas más intereses aún debe pagarse. Véase 19 USC 1592(c)(4) y 19 CFR 162.74.","ru":"Действительное предварительное раскрытие ограничивает штраф (например, процентами на утраченные пошлины в случаях небрежности), но фактически утраченные пошлины, налоги и сборы плюс проценты все равно должны быть уплачены. См. 19 USC 1592(c)(4) и 19 CFR 162.74.","tr":"Geçerli bir önceden ifşa cezayı sınırlar (örneğin, ihmal durumlarında kaybedilen vergiler üzerindeki faizle), ancak fiilen kaybedilen vergiler, harçlar ve ücretler artı faiz yine de ödenmelidir. Bkz. 19 USC 1592(c)(4) ve 19 CFR 162.74.","hi":"एक वैध पूर्व प्रकटन दंड को सीमित कर देता है (उदाहरण के लिए, लापरवाही के मामलों में खोए हुए शुल्कों पर ब्याज तक), लेकिन शुल्कों, करों और फीस की वास्तविक हानि के साथ-साथ ब्याज का भुगतान फिर भी करना होता है। देखें 19 USC 1592(c)(4) और 19 CFR 162.74।","ar":"يحد الإفصاح المسبق الصحيح من الغرامة (مثلًا، إلى الفائدة على الرسوم المفقودة في حالات الإهمال)، لكن يجب مع ذلك دفع الخسارة الفعلية في الرسوم والضرائب والمصاريف بالإضافة إلى الفائدة. انظر 19 USC 1592(c)(4) و19 CFR 162.74."}},{"cat":"duties","a":3,"q":{"en":"While an entry is subject to an antidumping order and the relevant administrative review is ongoing, what is the typical liquidation status of that entry?","es":"Mientras una declaración de entrada está sujeta a una orden antidumping y la revisión administrativa correspondiente está en curso, ¿cuál es el estado típico de liquidación de esa entrada?","ru":"Пока декларация о ввозе подпадает под антидемпинговый приказ и соответствующий административный пересмотр продолжается, каков типичный статус ликвидации этой декларации?","tr":"Bir giriş, bir antidamping emrine tabi iken ve ilgili idari inceleme devam ederken, o girişin tipik tasfiye (liquidation) durumu nedir?","hi":"जब कोई एंट्री किसी एंटीडंपिंग आदेश के अधीन है और संबंधित प्रशासनिक समीक्षा जारी है, तो उस एंट्री की सामान्य लिक्विडेशन स्थिति क्या होती है?","ar":"بينما يخضع البيان الجمركي لأمر مكافحة الإغراق وتكون المراجعة الإدارية ذات الصلة جارية، ما هي حالة التصفية (liquidation) المعتادة لذلك البيان؟"},"o":[{"en":"Liquidation is permanently barred until the order is revoked","es":"La liquidación está permanentemente impedida hasta que se revoque la orden","ru":"Ликвидация постоянно запрещена до отмены приказа","tr":"Emir iptal edilene kadar tasfiye kalıcı olarak engellenir","hi":"आदेश रद्द होने तक लिक्विडेशन स्थायी रूप से वर्जित रहती है","ar":"تُمنع التصفية بشكل دائم حتى يُلغى الأمر"},{"en":"Liquidation occurs automatically 314 days after entry","es":"La liquidación ocurre automáticamente 314 days después de la entrada","ru":"Ликвидация происходит автоматически через 314 days после ввоза","tr":"Tasfiye, girişten 314 days sonra otomatik olarak gerçekleşir","hi":"एंट्री के 314 days बाद लिक्विडेशन स्वतः हो जाती है","ar":"تحدث التصفية تلقائيًا بعد 314 days من الإدخال"},{"en":"Liquidation is deemed final at the cash-deposit rate immediately","es":"La liquidación se considera definitiva a la tasa de depósito en efectivo (cash-deposit) de inmediato","ru":"Ликвидация считается окончательной по ставке денежного депозита (cash-deposit) немедленно","tr":"Tasfiye, derhal nakit depozito (cash-deposit) oranında nihai sayılır","hi":"लिक्विडेशन को तुरंत कैश-डिपॉजिट (cash-deposit) दर पर अंतिम माना जाता है","ar":"تُعتبر التصفية نهائية بمعدل الإيداع النقدي (cash-deposit) على الفور"},{"en":"Liquidation is suspended until the review results are published","es":"La liquidación se suspende hasta que se publiquen los resultados de la revisión","ru":"Ликвидация приостанавливается до публикации результатов пересмотра","tr":"İnceleme sonuçları yayımlanana kadar tasfiye askıya alınır","hi":"समीक्षा परिणाम प्रकाशित होने तक लिक्विडेशन निलंबित रहती है","ar":"تُعلَّق التصفية حتى تُنشر نتائج المراجعة"}],"e":{"en":"Entries subject to an ADD/CVD administrative review have liquidation suspended; CBP liquidates after Commerce issues liquidation instructions following the review. See 19 USC 1675 and 19 CFR 351.212.","es":"Las declaraciones de entrada sujetas a una revisión administrativa de ADD/CVD tienen la liquidación suspendida; CBP liquida después de que Commerce emita instrucciones de liquidación tras la revisión. Véase 19 USC 1675 y 19 CFR 351.212.","ru":"Декларации, подпадающие под административный пересмотр ADD/CVD, имеют приостановленную ликвидацию; CBP ликвидирует после того, как Commerce издаст инструкции по ликвидации по итогам пересмотра. См. 19 USC 1675 и 19 CFR 351.212.","tr":"ADD/CVD idari incelemesine tabi girişlerin tasfiyesi askıya alınır; CBP, Commerce'in inceleme sonrası tasfiye talimatlarını yayımlamasının ardından tasfiye yapar. Bkz. 19 USC 1675 ve 19 CFR 351.212.","hi":"ADD/CVD प्रशासनिक समीक्षा के अधीन एंट्रियों की लिक्विडेशन निलंबित रहती है; समीक्षा के बाद Commerce द्वारा लिक्विडेशन निर्देश जारी करने पर CBP लिक्विडेशन करता है। देखें 19 USC 1675 और 19 CFR 351.212।","ar":"البيانات الجمركية الخاضعة لمراجعة إدارية لـ ADD/CVD تُعلَّق تصفيتها؛ وتقوم CBP بالتصفية بعد إصدار Commerce لتعليمات التصفية عقب المراجعة. انظر 19 USC 1675 و19 CFR 351.212."}},{"cat":"duties","a":0,"q":{"en":"Rejected-merchandise drawback under 19 USC 1313(c) and 19 CFR Part 190 permits a refund of duties on imported merchandise that, among other grounds, was:","es":"El drawback por mercancía rechazada conforme a 19 USC 1313(c) y 19 CFR Part 190 permite el reembolso de derechos sobre mercancía importada que, entre otros motivos, fue:","ru":"Возврат пошлин по отклоненному товару (rejected-merchandise drawback) согласно 19 USC 1313(c) и 19 CFR Part 190 разрешает возмещение пошлин на импортированный товар, который, среди прочих оснований, был:","tr":"19 USC 1313(c) ve 19 CFR Part 190 kapsamındaki reddedilen mal drawback'i, diğer gerekçelerin yanı sıra, aşağıdaki durumda olan ithal mal üzerindeki vergilerin iadesine izin verir:","hi":"19 USC 1313(c) और 19 CFR Part 190 के तहत अस्वीकृत-माल ड्रॉबैक उस आयातित माल पर शुल्कों की वापसी की अनुमति देता है, जो अन्य आधारों के अलावा, था:","ar":"يسمح استرداد رسوم البضاعة المرفوضة (rejected-merchandise drawback) بموجب 19 USC 1313(c) و19 CFR Part 190 باسترداد الرسوم على البضاعة المستوردة التي، من بين أسباب أخرى، كانت:"},"o":[{"en":"Shipped without the consignee's consent or not conforming to specifications, then exported or destroyed","es":"Enviada sin el consentimiento del consignatario o que no se ajusta a las especificaciones, y luego exportada o destruida","ru":"Отправлен без согласия грузополучателя или не соответствует спецификациям, а затем экспортирован или уничтожен","tr":"Alıcının rızası olmadan sevk edilen veya spesifikasyonlara uymayan, ardından ihraç edilen ya da imha edilen","hi":"परेषिती (consignee) की सहमति के बिना भेजा गया या विनिर्देशों के अनुरूप नहीं, और फिर निर्यात या नष्ट किया गया","ar":"مشحونة دون موافقة المرسل إليه أو غير مطابقة للمواصفات، ثم صُدِّرت أو أُتلفت"},{"en":"Exported in identical condition under substitution rules only","es":"Exportada en condiciones idénticas únicamente conforme a las reglas de sustitución","ru":"Экспортирован в идентичном состоянии исключительно по правилам замещения","tr":"Yalnızca ikame kuralları kapsamında aynı durumda ihraç edilen","hi":"केवल प्रतिस्थापन नियमों के तहत समरूप स्थिति में निर्यात किया गया","ar":"صُدِّرت بحالة مطابقة بموجب قواعد الإحلال فقط"},{"en":"Used in manufacturing and then sold domestically at a loss","es":"Utilizada en la manufactura y luego vendida en el mercado nacional con pérdida","ru":"Использован в производстве, а затем продан на внутреннем рынке с убытком","tr":"İmalatta kullanılan ve ardından zararına yurt içinde satılan","hi":"विनिर्माण में उपयोग किया गया और फिर घरेलू बाजार में हानि पर बेचा गया","ar":"استُخدمت في التصنيع ثم بيعت محليًا بخسارة"},{"en":"Damaged in transit before arrival and never entered","es":"Dañada en tránsito antes de su llegada y nunca declarada para entrada","ru":"Поврежден в пути до прибытия и никогда не вводился","tr":"Varıştan önce taşıma sırasında hasar gören ve hiç giriş yapılmamış","hi":"आगमन से पहले पारगमन में क्षतिग्रस्त और कभी एंट्री नहीं किया गया","ar":"تضررت أثناء النقل قبل الوصول ولم يُقدَّم لها بيان إدخال قط"}],"e":{"en":"Rejected-merchandise drawback covers imported goods that do not conform to sample/specifications, were shipped without consent, were defective at importation, or were ultimately sold at retail and returned, then exported or destroyed within the statutory period. See 19 USC 1313(c) and 19 CFR 190 Subpart D.","es":"El drawback por mercancía rechazada cubre los bienes importados que no se ajustan a la muestra/especificaciones, que fueron enviados sin consentimiento, que estaban defectuosos al momento de la importación, o que finalmente se vendieron al por menor y fueron devueltos, y luego se exportaron o destruyeron dentro del plazo legal. Véase 19 USC 1313(c) y 19 CFR 190 Subpart D.","ru":"Возврат пошлин по отклоненному товару охватывает импортированные товары, которые не соответствуют образцу/спецификациям, были отправлены без согласия, были дефектными при ввозе или в конечном итоге были проданы в розницу и возвращены, а затем экспортированы или уничтожены в установленный законом срок. См. 19 USC 1313(c) и 19 CFR 190 Subpart D.","tr":"Reddedilen mal drawback'i; numuneye/spesifikasyonlara uymayan, rıza olmadan sevk edilen, ithalat sırasında kusurlu olan ya da nihayetinde perakende satılıp iade edilen ve ardından yasal süre içinde ihraç edilen veya imha edilen ithal malları kapsar. Bkz. 19 USC 1313(c) ve 19 CFR 190 Subpart D.","hi":"अस्वीकृत-माल ड्रॉबैक उन आयातित वस्तुओं को कवर करता है जो नमूने/विनिर्देशों के अनुरूप नहीं हैं, सहमति के बिना भेजी गई थीं, आयात के समय दोषपूर्ण थीं, या अंततः खुदरा बेची गईं और वापस की गईं, और फिर वैधानिक अवधि के भीतर निर्यात या नष्ट की गईं। देखें 19 USC 1313(c) और 19 CFR 190 Subpart D।","ar":"يغطي استرداد رسوم البضاعة المرفوضة البضائع المستوردة التي لا تطابق العينة/المواصفات، أو شُحنت دون موافقة، أو كانت معيبة عند الاستيراد، أو بيعت في النهاية بالتجزئة وأُعيدت، ثم صُدِّرت أو أُتلفت خلال الفترة القانونية. انظر 19 USC 1313(c) و19 CFR 190 Subpart D."}},{"cat":"duties","a":3,"q":{"en":"Which statement concerning the refund of excess duties after a favorable protest is TRUE?","es":"¿Cuál afirmación relativa al reembolso de derechos en exceso tras una protesta favorable es VERDADERA?","ru":"Какое утверждение, касающееся возврата излишне уплаченных пошлин после удовлетворения протеста, является ВЕРНЫМ?","tr":"Olumlu bir itirazın ardından fazla ödenen vergilerin iadesine ilişkin hangi ifade DOĞRUDUR?","hi":"अनुकूल विरोध के बाद अतिरिक्त शुल्कों की वापसी से संबंधित कौन-सा कथन सत्य है?","ar":"أي عبارة تتعلق باسترداد الرسوم الزائدة بعد اعتراض مقبول تكون صحيحة؟"},"o":[{"en":"No refund is payable unless suit is filed at the Court of International Trade","es":"No se paga ningún reembolso a menos que se interponga una demanda ante el Court of International Trade","ru":"Возврат не выплачивается, если не подан иск в Court of International Trade","tr":"Court of International Trade nezdinde dava açılmadıkça hiçbir iade ödenmez","hi":"जब तक Court of International Trade में मुकदमा दायर नहीं किया जाता, तब तक कोई वापसी देय नहीं होती","ar":"لا يُدفع أي استرداد ما لم تُرفع دعوى أمام Court of International Trade"},{"en":"Refunds may only be applied as a credit against future entries","es":"Los reembolsos solo pueden aplicarse como crédito contra futuras declaraciones de entrada","ru":"Возвраты могут применяться только в качестве зачета в счет будущих деклараций о ввозе","tr":"İadeler yalnızca gelecekteki girişlere karşı kredi olarak uygulanabilir","hi":"वापसी को केवल भविष्य की एंट्रियों के विरुद्ध क्रेडिट के रूप में लागू किया जा सकता है","ar":"لا يمكن تطبيق الاستردادات إلا كرصيد دائن مقابل البيانات الجمركية المستقبلية"},{"en":"Refunds of overpaid duties are issued without any interest in all cases","es":"Los reembolsos de derechos pagados en exceso se emiten sin intereses en todos los casos","ru":"Возвраты излишне уплаченных пошлин выдаются без каких-либо процентов во всех случаях","tr":"Fazla ödenen vergilerin iadeleri her durumda faizsiz olarak yapılır","hi":"अधिक भुगतान किए गए शुल्कों की वापसी सभी मामलों में बिना किसी ब्याज के जारी की जाती है","ar":"تُصدَر استردادات الرسوم المدفوعة بالزيادة دون أي فائدة في جميع الحالات"},{"en":"CBP refunds the overpaid duties, generally with interest, following allowance of the protest and reliquidation","es":"CBP reembolsa los derechos pagados en exceso, generalmente con intereses, tras la admisión de la protesta y la reliquidación","ru":"CBP возвращает излишне уплаченные пошлины, как правило, с процентами, после удовлетворения протеста и переликвидации","tr":"CBP, itirazın kabul edilmesi ve yeniden tasfiyenin (reliquidation) ardından fazla ödenen vergileri, genellikle faiziyle birlikte iade eder","hi":"विरोध की स्वीकृति और पुनर्लिक्विडेशन के बाद CBP अधिक भुगतान किए गए शुल्कों को, सामान्यतः ब्याज सहित, वापस करता है","ar":"تعيد CBP الرسوم المدفوعة بالزيادة، عادةً مع الفائدة، بعد قبول الاعتراض وإعادة التصفية (reliquidation)"}],"e":{"en":"When a protest is allowed and the entry reliquidated showing an overpayment, CBP refunds the excess duties, and interest is payable on such refunds as provided by statute. See 19 USC 1505(c) and 19 CFR 24.36, 174.29.","es":"Cuando se admite una protesta y la entrada se reliquida mostrando un pago en exceso, CBP reembolsa los derechos en exceso, y se pagan intereses sobre dichos reembolsos según lo dispuesto por la ley. Véase 19 USC 1505(c) y 19 CFR 24.36, 174.29.","ru":"Когда протест удовлетворяется и декларация переликвидируется с указанием переплаты, CBP возвращает излишне уплаченные пошлины, и на такие возвраты выплачиваются проценты, как предусмотрено законом. См. 19 USC 1505(c) и 19 CFR 24.36, 174.29.","tr":"Bir itiraz kabul edilip giriş, fazla ödeme gösterecek şekilde yeniden tasfiye edildiğinde, CBP fazla vergileri iade eder ve bu tür iadelere kanunda öngörüldüğü şekilde faiz ödenir. Bkz. 19 USC 1505(c) ve 19 CFR 24.36, 174.29.","hi":"जब किसी विरोध को स्वीकार किया जाता है और एंट्री को अधिक भुगतान दर्शाते हुए पुनर्लिक्विडेट किया जाता है, तो CBP अतिरिक्त शुल्कों को वापस करता है, और ऐसी वापसियों पर क़ानून में निर्धारित अनुसार ब्याज देय होता है। देखें 19 USC 1505(c) और 19 CFR 24.36, 174.29।","ar":"عند قبول اعتراض وإعادة تصفية البيان الجمركي بما يظهر دفعًا زائدًا، تعيد CBP الرسوم الزائدة، وتُدفع الفائدة على هذه الاستردادات وفقًا لما ينص عليه القانون. انظر 19 USC 1505(c) و19 CFR 24.36, 174.29."}},{"cat":"duties","a":2,"q":{"en":"Which of the following statements about the FY2026 MPF on informal entries is TRUE?","es":"¿Cuál de las siguientes afirmaciones sobre el MPF del FY2026 en declaraciones informales es VERDADERA?","ru":"Какое из следующих утверждений о MPF FY2026 для неформальных деклараций (informal entries) является ВЕРНЫМ?","tr":"Gayri resmi girişlerde (informal entries) FY2026 MPF ile ilgili aşağıdaki ifadelerden hangisi DOĞRUDUR?","hi":"अनौपचारिक एंट्रियों (informal entries) पर FY2026 MPF के बारे में निम्नलिखित में से कौन-सा कथन सत्य है?","ar":"أي من العبارات التالية حول MPF لسنة FY2026 على البيانات غير الرسمية (informal entries) تكون صحيحة؟"},"o":[{"en":"It is 0.3464 percent of value with no minimum","es":"Es el 0.3464 percent del valor sin mínimo","ru":"Это 0.3464 percent от стоимости без минимума","tr":"Değerin 0.3464 percent'idir ve asgari tutarı yoktur","hi":"यह बिना किसी न्यूनतम के मूल्य का 0.3464 percent है","ar":"هو 0.3464 percent من القيمة دون حد أدنى"},{"en":"It is waived entirely for all informal entries","es":"Se exime por completo para todas las declaraciones informales","ru":"Он полностью отменяется для всех неформальных деклараций","tr":"Tüm gayri resmi girişler için tamamen muaf tutulur","hi":"इसे सभी अनौपचारिक एंट्रियों के लिए पूरी तरह माफ कर दिया जाता है","ar":"يُعفى منه بالكامل بالنسبة لجميع البيانات غير الرسمية"},{"en":"It is a set per-entry amount (such as $2.69, $8.06, or $12.09) rather than an ad valorem charge","es":"Es un monto fijo por declaración (tales como $2.69, $8.06 o $12.09) en lugar de un cargo ad valorem","ru":"Это фиксированная сумма за декларацию (например, $2.69, $8.06 или $12.09), а не адвалорный сбор","tr":"Ad valorem bir ücret yerine giriş başına sabit bir tutardır (örneğin $2.69, $8.06 veya $12.09)","hi":"यह यथामूल्य (ad valorem) प्रभार के बजाय प्रति-एंट्री एक निर्धारित राशि है (जैसे $2.69, $8.06, या $12.09)","ar":"هو مبلغ ثابت لكل بيان (مثل $2.69 أو $8.06 أو $12.09) وليس رسمًا قيميًا (ad valorem)"},{"en":"It is identical to the formal-entry maximum of $651.50","es":"Es idéntico al máximo de declaración formal de $651.50","ru":"Он идентичен максимуму для формальных деклараций в размере $651.50","tr":"Resmi giriş azami tutarı olan $651.50 ile aynıdır","hi":"यह औपचारिक एंट्री की अधिकतम सीमा $651.50 के समान है","ar":"هو مطابق للحد الأقصى للبيان الرسمي البالغ $651.50"}],"e":{"en":"For informal entries, the MPF is a flat fee per entry (FY2026 tiers of $2.69 automated/CBP-prepared, $8.06, and $12.09), not the 0.3464% ad valorem charge used for formal entries. See 19 CFR 24.23(b)(2).","es":"Para las declaraciones informales, el MPF es una tasa fija por declaración (los niveles del FY2026 de $2.69 automatizado/preparado por CBP, $8.06 y $12.09), no el cargo ad valorem del 0.3464% utilizado para las declaraciones formales. Véase 19 CFR 24.23(b)(2).","ru":"Для неформальных деклараций MPF представляет собой фиксированный сбор за декларацию (уровни FY2026: $2.69 для автоматизированных/подготовленных CBP, $8.06 и $12.09), а не адвалорный сбор 0.3464%, применяемый для формальных деклараций. См. 19 CFR 24.23(b)(2).","tr":"Gayri resmi girişler için MPF, giriş başına sabit bir ücrettir (FY2026 kademeleri: otomatik/CBP tarafından hazırlanan için $2.69, $8.06 ve $12.09), resmi girişlerde kullanılan 0.3464% ad valorem ücret değildir. Bkz. 19 CFR 24.23(b)(2).","hi":"अनौपचारिक एंट्रियों के लिए, MPF प्रति-एंट्री एक समान शुल्क है (FY2026 स्तर: स्वचालित/CBP-तैयार के लिए $2.69, $8.06, और $12.09), न कि औपचारिक एंट्रियों के लिए उपयोग किया जाने वाला 0.3464% यथामूल्य प्रभार। देखें 19 CFR 24.23(b)(2)।","ar":"بالنسبة للبيانات غير الرسمية، يكون MPF رسمًا ثابتًا لكل بيان (شرائح FY2026 وهي $2.69 للآلي/المُعدّ من قبل CBP، و$8.06، و$12.09)، وليس الرسم القيمي 0.3464% المستخدم للبيانات الرسمية. انظر 19 CFR 24.23(b)(2)."}},{"cat":"duties","a":3,"q":{"en":"Which of the following is TRUE regarding TFTEA modernized drawback under 19 CFR Part 190?","es":"¿Cuál de las siguientes es VERDADERA respecto del drawback modernizado de TFTEA conforme a 19 CFR Part 190?","ru":"Какое из следующих утверждений ВЕРНО в отношении модернизированного возврата пошлин (drawback) по TFTEA согласно 19 CFR Part 190?","tr":"19 CFR Part 190 kapsamındaki TFTEA modernize drawback'i ile ilgili aşağıdakilerden hangisi DOĞRUDUR?","hi":"19 CFR Part 190 के तहत TFTEA आधुनिकीकृत ड्रॉबैक के संबंध में निम्नलिखित में से कौन-सा सत्य है?","ar":"أي مما يلي صحيح بخصوص استرداد الرسوم المحدّث وفق TFTEA بموجب 19 CFR Part 190؟"},"o":[{"en":"Refunds are generally limited to 99 percent of the eligible duties, taxes, and fees","es":"Los reembolsos generalmente se limitan al 99 percent de los derechos, impuestos y tasas elegibles","ru":"Возвраты, как правило, ограничены 99 percent от соответствующих пошлин, налогов и сборов","tr":"İadeler genellikle uygun vergiler, harçlar ve ücretlerin 99 percent'i ile sınırlıdır","hi":"वापसी सामान्यतः पात्र शुल्कों, करों और फीस के 99 percent तक सीमित होती है","ar":"تقتصر الاستردادات عمومًا على 99 percent من الرسوم والضرائب والمصاريف المؤهلة"},{"en":"The claim must generally be filed within 5 years of importation","es":"La reclamación generalmente debe presentarse dentro de los 5 years posteriores a la importación","ru":"Заявление, как правило, должно быть подано в течение 5 years с момента импорта","tr":"Talep genellikle ithalattan itibaren 5 years içinde sunulmalıdır","hi":"दावा सामान्यतः आयात के 5 years के भीतर दाखिल किया जाना चाहिए","ar":"يجب عمومًا تقديم المطالبة خلال 5 years من الاستيراد"},{"en":"Substitution may be based on the same 8-digit HTSUS subheading","es":"La sustitución puede basarse en la misma subpartida HTSUS de 8-digit","ru":"Замещение может основываться на той же 8-digit субпозиции HTSUS","tr":"İkame, aynı 8-digit HTSUS alt başlığına dayanabilir","hi":"प्रतिस्थापन उसी 8-digit HTSUS उप-शीर्ष पर आधारित हो सकता है","ar":"يمكن أن يستند الإحلال إلى نفس البند الفرعي HTSUS المكوّن من 8-digit"},{"en":"All of the below are true","es":"Todas las siguientes son verdaderas","ru":"Все из нижеперечисленного верно","tr":"Aşağıdakilerin tümü doğrudur","hi":"नीचे दिए गए सभी सत्य हैं","ar":"كل ما يلي صحيح"}],"e":{"en":"All three statements are correct: substitution uses the 8-digit HTSUS standard (19 USC 1313(j)(2)/(b)), the filing period is 5 years from importation (19 USC 1313(r)), and drawback refunds are capped at 99% of the eligible duties, taxes, and fees. See 19 CFR Part 190.","es":"Las tres afirmaciones son correctas: la sustitución utiliza el estándar HTSUS de 8-digit (19 USC 1313(j)(2)/(b)), el plazo de presentación es de 5 years desde la importación (19 USC 1313(r)), y los reembolsos de drawback se limitan al 99% de los derechos, impuestos y tasas elegibles. Véase 19 CFR Part 190.","ru":"Все три утверждения верны: замещение использует стандарт 8-digit HTSUS (19 USC 1313(j)(2)/(b)), срок подачи составляет 5 years с момента импорта (19 USC 1313(r)), а возвраты drawback ограничены 99% от соответствующих пошлин, налогов и сборов. См. 19 CFR Part 190.","tr":"Üç ifade de doğrudur: ikame, 8-digit HTSUS standardını kullanır (19 USC 1313(j)(2)/(b)), başvuru süresi ithalattan itibaren 5 years'tır (19 USC 1313(r)) ve drawback iadeleri, uygun vergiler, harçlar ve ücretlerin 99%'u ile sınırlandırılmıştır. Bkz. 19 CFR Part 190.","hi":"तीनों कथन सही हैं: प्रतिस्थापन 8-digit HTSUS मानक का उपयोग करता है (19 USC 1313(j)(2)/(b)), दाखिल करने की अवधि आयात से 5 years है (19 USC 1313(r)), और ड्रॉबैक वापसी पात्र शुल्कों, करों और फीस के 99% तक सीमित है। देखें 19 CFR Part 190।","ar":"العبارات الثلاث كلها صحيحة: يستخدم الإحلال معيار 8-digit HTSUS (19 USC 1313(j)(2)/(b))، وفترة التقديم هي 5 years من الاستيراد (19 USC 1313(r))، واستردادات drawback محددة بحد أقصى 99% من الرسوم والضرائب والمصاريف المؤهلة. انظر 19 CFR Part 190."}},{"cat":"compliance","a":0,"q":{"en":"Under 19 CFR Part 111, what is the minimum passing grade on the customs broker license examination?","es":"Según 19 CFR Part 111, ¿cuál es la calificación mínima de aprobación en el examen de licencia de agente de aduanas?","ru":"Согласно 19 CFR Part 111, какова минимальная проходная оценка на экзамене для получения лицензии таможенного брокера?","tr":"19 CFR Part 111 uyarınca, gümrük müşaviri lisans sınavında geçer not için gereken asgari puan nedir?","hi":"19 CFR Part 111 के अंतर्गत, सीमा शुल्क ब्रोकर लाइसेंस परीक्षा में उत्तीर्ण होने के लिए न्यूनतम ग्रेड क्या है?","ar":"بموجب 19 CFR Part 111، ما هي الدرجة الدنيا للنجاح في امتحان رخصة وسيط الجمارك؟"},"o":[{"en":"75 percent or higher","es":"75 percent o más","ru":"75 percent или выше","tr":"75 percent veya daha yüksek","hi":"75 percent या उससे अधिक","ar":"75 percent أو أعلى"},{"en":"85 percent or higher","es":"85 percent o más","ru":"85 percent или выше","tr":"85 percent veya daha yüksek","hi":"85 percent या उससे अधिक","ar":"85 percent أو أعلى"},{"en":"70 percent or higher","es":"70 percent o más","ru":"70 percent или выше","tr":"70 percent veya daha yüksek","hi":"70 percent या उससे अधिक","ar":"70 percent أو أعلى"},{"en":"80 percent or higher","es":"80 percent o más","ru":"80 percent или выше","tr":"80 percent veya daha yüksek","hi":"80 percent या उससे अधिक","ar":"80 percent أو أعلى"}],"e":{"en":"19 CFR 111.11(a)(4) requires the applicant to attain a passing (75 percent or higher) grade on the written examination to establish the requisite knowledge of customs and related laws, regulations, and procedures.","es":"19 CFR 111.11(a)(4) exige que el solicitante obtenga una calificación de aprobación (75 percent o más) en el examen escrito para acreditar el conocimiento requerido de las leyes, reglamentos y procedimientos aduaneros y conexos.","ru":"19 CFR 111.11(a)(4) требует, чтобы заявитель получил проходную оценку (75 percent или выше) на письменном экзамене для подтверждения необходимых знаний таможенного и смежного законодательства, нормативных актов и процедур.","tr":"19 CFR 111.11(a)(4), başvuru sahibinin gümrük ve ilgili yasalar, düzenlemeler ve prosedürlere ilişkin gerekli bilgiyi kanıtlamak için yazılı sınavda geçer (75 percent veya daha yüksek) not almasını gerektirir.","hi":"19 CFR 111.11(a)(4) के अनुसार आवेदक को सीमा शुल्क और संबंधित कानूनों, विनियमों और प्रक्रियाओं के अपेक्षित ज्ञान को सिद्ध करने हेतु लिखित परीक्षा में उत्तीर्ण (75 percent या उससे अधिक) ग्रेड प्राप्त करना आवश्यक है।","ar":"تشترط 19 CFR 111.11(a)(4) أن يحصل مقدم الطلب على درجة نجاح (75 percent أو أعلى) في الامتحان الكتابي لإثبات المعرفة المطلوبة بقوانين الجمارك واللوائح والإجراءات ذات الصلة."}},{"cat":"compliance","a":1,"q":{"en":"What is the minimum age an individual must be to qualify for a customs broker's license?","es":"¿Cuál es la edad mínima que debe tener una persona para calificar para una licencia de agente de aduanas?","ru":"Каков минимальный возраст, которого должно достичь физическое лицо, чтобы соответствовать требованиям для получения лицензии таможенного брокера?","tr":"Bir bireyin gümrük müşaviri lisansına hak kazanması için sahip olması gereken asgari yaş nedir?","hi":"किसी व्यक्ति को सीमा शुल्क ब्रोकर लाइसेंस के लिए योग्य होने हेतु न्यूनतम आयु क्या होनी चाहिए?","ar":"ما هو الحد الأدنى للعمر الذي يجب أن يبلغه الفرد ليكون مؤهلاً للحصول على رخصة وسيط الجمارك؟"},"o":[{"en":"23 years of age","es":"23 years of age","ru":"23 years of age","tr":"23 years of age","hi":"23 years of age","ar":"23 years of age"},{"en":"21 years of age","es":"21 years of age","ru":"21 years of age","tr":"21 years of age","hi":"21 years of age","ar":"21 years of age"},{"en":"25 years of age","es":"25 years of age","ru":"25 years of age","tr":"25 years of age","hi":"25 years of age","ar":"25 years of age"},{"en":"18 years of age","es":"18 years of age","ru":"18 years of age","tr":"18 years of age","hi":"18 years of age","ar":"18 years of age"}],"e":{"en":"19 CFR 111.11(a)(2) requires that an individual applicant attain the age of 21 prior to the monthly anniversary date of the broker examination on which the applicant took and passed the examination.","es":"19 CFR 111.11(a)(2) exige que un solicitante individual cumpla la age 21 antes de la fecha de aniversario mensual del examen de agente en el que el solicitante presentó y aprobó el examen.","ru":"19 CFR 111.11(a)(2) требует, чтобы индивидуальный заявитель достиг age 21 до ежемесячной даты годовщины брокерского экзамена, на котором заявитель сдавал и сдал экзамен.","tr":"19 CFR 111.11(a)(2), bireysel başvuru sahibinin sınava girip geçtiği müşavirlik sınavının aylık yıldönümü tarihinden önce age 21 yaşını doldurmasını gerektirir.","hi":"19 CFR 111.11(a)(2) के अनुसार किसी व्यक्तिगत आवेदक को उस ब्रोकर परीक्षा की मासिक वर्षगांठ तिथि से पूर्व age 21 की आयु प्राप्त करनी होगी, जिसमें आवेदक ने परीक्षा दी और उत्तीर्ण की थी।","ar":"تشترط 19 CFR 111.11(a)(2) أن يبلغ مقدم الطلب الفرد age 21 قبل تاريخ الذكرى الشهرية لامتحان الوسيط الذي خاضه واجتازه مقدم الطلب."}},{"cat":"compliance","a":2,"q":{"en":"As amended by the customs broker modernization rules, what type of permit must a broker obtain to conduct customs business throughout the customs territory of the United States?","es":"Conforme a las modificaciones de las reglas de modernización de agentes de aduanas, ¿qué tipo de permiso debe obtener un agente para realizar actividades aduaneras en todo el territorio aduanero de los Estados Unidos?","ru":"С учетом изменений, внесенных правилами модернизации деятельности таможенных брокеров, какой тип разрешения должен получить брокер для ведения таможенной деятельности на всей таможенной территории Соединенных Штатов?","tr":"Gümrük müşaviri modernizasyon kurallarıyla değiştirildiği şekliyle, bir müşavirin Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işi yürütmek için hangi tür izni alması gerekir?","hi":"सीमा शुल्क ब्रोकर आधुनिकीकरण नियमों द्वारा संशोधित रूप में, संयुक्त राज्य अमेरिका के पूरे सीमा शुल्क क्षेत्र में सीमा शुल्क व्यवसाय करने के लिए किसी ब्रोकर को किस प्रकार का परमिट प्राप्त करना होगा?","ar":"وفقاً للتعديلات التي أدخلتها قواعد تحديث وسطاء الجمارك، ما نوع التصريح الذي يجب على الوسيط الحصول عليه لمزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة؟"},"o":[{"en":"A regional permit","es":"Un permiso regional","ru":"Региональное разрешение","tr":"Bölgesel bir izin","hi":"एक क्षेत्रीय परमिट","ar":"تصريح إقليمي (جهوي)"},{"en":"A district permit for each port","es":"Un permiso de distrito para cada puerto","ru":"Окружное разрешение для каждого порта","tr":"Her liman için bir bölge izni","hi":"प्रत्येक बंदरगाह के लिए एक जिला परमिट","ar":"تصريح إقليمي لكل ميناء"},{"en":"A national permit","es":"Un permiso nacional","ru":"Национальное разрешение","tr":"Ulusal bir izin","hi":"एक राष्ट्रीय परमिट","ar":"تصريح وطني"},{"en":"A consolidated district permit","es":"Un permiso de distrito consolidado","ru":"Сводное окружное разрешение","tr":"Birleştirilmiş bir bölge izni","hi":"एक समेकित जिला परमिट","ar":"تصريح إقليمي موحّد"}],"e":{"en":"Under the modernized 19 CFR 111.19, district permits were eliminated and a single national permit authorizes a broker to conduct customs business throughout the customs territory of the United States.","es":"Conforme al 19 CFR 111.19 modernizado, se eliminaron los permisos de distrito y un único permiso nacional autoriza a un agente a realizar actividades aduaneras en todo el territorio aduanero de los Estados Unidos.","ru":"Согласно модернизированному 19 CFR 111.19, окружные разрешения были упразднены, и единое национальное разрешение дает брокеру право вести таможенную деятельность на всей таможенной территории Соединенных Штатов.","tr":"Modernize edilmiş 19 CFR 111.19 uyarınca bölge izinleri kaldırılmış olup, tek bir ulusal izin müşaviri Amerika Birleşik Devletleri gümrük bölgesinin tamamında gümrük işi yürütmeye yetkili kılar.","hi":"आधुनिकीकृत 19 CFR 111.19 के अंतर्गत जिला परमिट समाप्त कर दिए गए और एक एकल राष्ट्रीय परमिट किसी ब्रोकर को संयुक्त राज्य अमेरिका के पूरे सीमा शुल्क क्षेत्र में सीमा शुल्क व्यवसाय करने हेतु अधिकृत करता है।","ar":"بموجب 19 CFR 111.19 المُحدَّثة، أُلغيت التصاريح الإقليمية، ويُخوّل تصريح وطني واحد الوسيط بمزاولة الأعمال الجمركية في جميع أنحاء الإقليم الجمركي للولايات المتحدة."}},{"cat":"compliance","a":0,"q":{"en":"For how long must a broker generally retain records relating to a customs transaction?","es":"¿Por cuánto tiempo debe conservar generalmente un agente los registros relacionados con una transacción aduanera?","ru":"Как долго брокер должен, как правило, хранить документы, относящиеся к таможенной операции?","tr":"Bir müşavir, gümrük işlemiyle ilgili kayıtları genel olarak ne kadar süre saklamak zorundadır?","hi":"किसी ब्रोकर को सीमा शुल्क लेन-देन से संबंधित रिकॉर्ड सामान्यतः कितने समय तक रखना आवश्यक है?","ar":"إلى متى يجب على الوسيط عادةً الاحتفاظ بالسجلات المتعلقة بمعاملة جمركية؟"},"o":[{"en":"5 years after the date of entry","es":"5 years después de la fecha de entrada","ru":"5 years после даты ввоза","tr":"Giriş tarihinden sonra 5 years","hi":"प्रवेश की तिथि के बाद 5 years","ar":"5 years بعد تاريخ الإدخال"},{"en":"7 years after the date of entry","es":"7 years después de la fecha de entrada","ru":"7 years после даты ввоза","tr":"Giriş tarihinden sonra 7 years","hi":"प्रवेश की तिथि के बाद 7 years","ar":"7 years بعد تاريخ الإدخال"},{"en":"6 years after the date of entry","es":"6 years después de la fecha de entrada","ru":"6 years после даты ввоза","tr":"Giriş tarihinden sonra 6 years","hi":"प्रवेश की तिथि के बाद 6 years","ar":"6 years بعد تاريخ الإدخال"},{"en":"3 years after the date of entry","es":"3 years después de la fecha de entrada","ru":"3 years после даты ввоза","tr":"Giriş tarihinden sonra 3 years","hi":"प्रवेश की तिथि के बाद 3 years","ar":"3 years بعد تاريخ الإدخال"}],"e":{"en":"19 CFR 111.23(b) requires records to be retained for at least 5 years after the date of entry, consistent with the recordkeeping period in 19 CFR Part 163.","es":"19 CFR 111.23(b) exige que los registros se conserven durante al menos 5 years después de la fecha de entrada, en consonancia con el período de conservación de registros del 19 CFR Part 163.","ru":"19 CFR 111.23(b) требует хранения документов в течение не менее 5 years после даты ввоза, что согласуется со сроком хранения документов, установленным в 19 CFR Part 163.","tr":"19 CFR 111.23(b), kayıtların 19 CFR Part 163'teki saklama süresiyle uyumlu olarak giriş tarihinden sonra en az 5 years saklanmasını gerektirir.","hi":"19 CFR 111.23(b) के अनुसार रिकॉर्ड को प्रवेश की तिथि के बाद कम से कम 5 years तक रखना आवश्यक है, जो 19 CFR Part 163 में निर्धारित रिकॉर्ड रखने की अवधि के अनुरूप है।","ar":"تشترط 19 CFR 111.23(b) الاحتفاظ بالسجلات لمدة لا تقل عن 5 years بعد تاريخ الإدخال، بما يتسق مع فترة حفظ السجلات المنصوص عليها في 19 CFR Part 163."}},{"cat":"compliance","a":1,"q":{"en":"How often must a licensed broker file a status report with CBP?","es":"¿Con qué frecuencia debe un agente con licencia presentar un informe de situación ante CBP?","ru":"Как часто лицензированный брокер должен подавать отчет о состоянии в CBP?","tr":"Lisanslı bir müşavir, CBP'ye ne sıklıkla durum raporu sunmak zorundadır?","hi":"लाइसेंसधारी ब्रोकर को CBP के पास स्थिति रिपोर्ट कितनी बार दाखिल करनी होती है?","ar":"كم مرة يجب على الوسيط المرخّص تقديم تقرير حالة إلى CBP؟"},"o":[{"en":"Every two years","es":"Cada dos años","ru":"Каждые два года","tr":"Her iki yılda bir","hi":"हर दो वर्ष में","ar":"كل سنتين"},{"en":"Every three years","es":"Cada tres años","ru":"Каждые три года","tr":"Her üç yılda bir","hi":"हर तीन वर्ष में","ar":"كل ثلاث سنوات"},{"en":"Every year","es":"Cada año","ru":"Каждый год","tr":"Her yıl","hi":"हर वर्ष","ar":"كل سنة"},{"en":"Every five years","es":"Cada cinco años","ru":"Каждые пять лет","tr":"Her beş yılda bir","hi":"हर पाँच वर्ष में","ar":"كل خمس سنوات"}],"e":{"en":"19 CFR 111.30(d) requires each broker to file a status report every three years (a triennial status report), due on February 1 of each third year after 1985.","es":"19 CFR 111.30(d) exige que cada agente presente un informe de situación cada tres años (un informe de situación trienal), con vencimiento el February 1 de cada tercer año después de 1985.","ru":"19 CFR 111.30(d) требует, чтобы каждый брокер подавал отчет о состоянии каждые три года (трехлетний отчет о состоянии) со сроком подачи February 1 каждого третьего года после 1985.","tr":"19 CFR 111.30(d), her müşavirin üç yılda bir durum raporu (üç yıllık durum raporu) sunmasını gerektirir; bu rapor 1985 sonrasındaki her üçüncü yılın February 1 tarihinde verilir.","hi":"19 CFR 111.30(d) के अनुसार प्रत्येक ब्रोकर को हर तीन वर्ष में स्थिति रिपोर्ट (त्रैवार्षिक स्थिति रिपोर्ट) दाखिल करनी होती है, जो 1985 के बाद प्रत्येक तीसरे वर्ष की February 1 को देय होती है।","ar":"تشترط 19 CFR 111.30(d) أن يقدّم كل وسيط تقرير حالة كل ثلاث سنوات (تقرير حالة كل ثلاث سنوات)، يُستحق في February 1 من كل سنة ثالثة بعد 1985."}},{"cat":"compliance","a":1,"q":{"en":"What is the fee that must accompany the triennial status report?","es":"¿Cuál es la tarifa que debe acompañar al informe de situación trienal?","ru":"Какой сбор должен прилагаться к трехлетнему отчету о состоянии?","tr":"Üç yıllık durum raporuna eşlik etmesi gereken ücret nedir?","hi":"त्रैवार्षिक स्थिति रिपोर्ट के साथ कौन-सा शुल्क संलग्न करना आवश्यक है?","ar":"ما هي الرسوم التي يجب أن تُرفَق بتقرير الحالة الذي يُقدَّم كل ثلاث سنوات؟"},"o":[{"en":"$50","es":"$50","ru":"$50","tr":"$50","hi":"$50","ar":"$50"},{"en":"$100","es":"$100","ru":"$100","tr":"$100","hi":"$100","ar":"$100"},{"en":"$138","es":"$138","ru":"$138","tr":"$138","hi":"$138","ar":"$138"},{"en":"$200","es":"$200","ru":"$200","tr":"$200","hi":"$200","ar":"$200"}],"e":{"en":"19 CFR 111.96(d) sets the triennial status report fee at $100; under 19 CFR 111.30(d), the report is not considered received until the fee is paid.","es":"19 CFR 111.96(d) fija la tarifa del informe de situación trienal en $100; conforme al 19 CFR 111.30(d), el informe no se considera recibido hasta que se pague la tarifa.","ru":"19 CFR 111.96(d) устанавливает сбор за трехлетний отчет о состоянии в размере $100; согласно 19 CFR 111.30(d), отчет не считается полученным до уплаты сбора.","tr":"19 CFR 111.96(d), üç yıllık durum raporu ücretini $100 olarak belirler; 19 CFR 111.30(d) uyarınca ücret ödenene kadar rapor alınmış sayılmaz.","hi":"19 CFR 111.96(d) त्रैवार्षिक स्थिति रिपोर्ट शुल्क को $100 निर्धारित करता है; 19 CFR 111.30(d) के अनुसार शुल्क का भुगतान होने तक रिपोर्ट प्राप्त नहीं मानी जाती।","ar":"تحدّد 19 CFR 111.96(d) رسوم تقرير الحالة الذي يُقدَّم كل ثلاث سنوات بمبلغ $100؛ وبموجب 19 CFR 111.30(d) لا يُعتبر التقرير مُستلَماً حتى تُدفَع الرسوم."}},{"cat":"compliance","a":1,"q":{"en":"Within how many calendar days must a broker holding a national permit submit information for a new employee to CBP?","es":"¿Dentro de cuántos días calendario debe un agente que posee un permiso nacional presentar a CBP la información de un nuevo empleado?","ru":"В течение скольких календарных дней брокер, имеющий национальное разрешение, должен предоставить в CBP сведения о новом сотруднике?","tr":"Ulusal izne sahip bir müşavir, yeni bir çalışanın bilgilerini kaç takvim günü içinde CBP'ye sunmak zorundadır?","hi":"राष्ट्रीय परमिट धारक ब्रोकर को किसी नए कर्मचारी की जानकारी CBP को कितने कैलेंडर दिनों के भीतर प्रस्तुत करनी होती है?","ar":"خلال كم يوماً تقويمياً يجب على الوسيط الحائز على تصريح وطني تقديم معلومات موظف جديد إلى CBP؟"},"o":[{"en":"15 calendar days","es":"15 calendar days","ru":"15 calendar days","tr":"15 calendar days","hi":"15 calendar days","ar":"15 calendar days"},{"en":"30 calendar days","es":"30 calendar days","ru":"30 calendar days","tr":"30 calendar days","hi":"30 calendar days","ar":"30 calendar days"},{"en":"10 calendar days","es":"10 calendar days","ru":"10 calendar days","tr":"10 calendar days","hi":"10 calendar days","ar":"10 calendar days"},{"en":"45 calendar days","es":"45 calendar days","ru":"45 calendar days","tr":"45 calendar days","hi":"45 calendar days","ar":"45 calendar days"}],"e":{"en":"19 CFR 111.28(b)(1)(ii) requires a broker that has been issued a national permit to submit information for a new employee within 30 calendar days of the start of employment.","es":"19 CFR 111.28(b)(1)(ii) exige que un agente al que se le ha emitido un permiso nacional presente la información de un nuevo empleado dentro de 30 calendar days desde el inicio del empleo.","ru":"19 CFR 111.28(b)(1)(ii) требует, чтобы брокер, которому выдано национальное разрешение, предоставил сведения о новом сотруднике в течение 30 calendar days с момента начала трудовых отношений.","tr":"19 CFR 111.28(b)(1)(ii), ulusal izin verilmiş bir müşavirin yeni bir çalışanın bilgilerini işe başlama tarihinden itibaren 30 calendar days içinde sunmasını gerektirir.","hi":"19 CFR 111.28(b)(1)(ii) के अनुसार जिस ब्रोकर को राष्ट्रीय परमिट जारी किया गया है, उसे किसी नए कर्मचारी की जानकारी रोजगार शुरू होने के 30 calendar days के भीतर प्रस्तुत करनी होगी।","ar":"تشترط 19 CFR 111.28(b)(1)(ii) أن يقدّم الوسيط الذي صدر له تصريح وطني معلومات الموظف الجديد خلال 30 calendar days من بدء التوظيف."}},{"cat":"compliance","a":3,"q":{"en":"Which of the following individuals does NOT need to hold a broker's license to transact customs business as a broker?","es":"¿Cuál de las siguientes personas NO necesita poseer una licencia de agente para realizar actividades aduaneras como agente?","ru":"Кому из перечисленных лиц НЕ требуется иметь лицензию брокера для ведения таможенной деятельности в качестве брокера?","tr":"Aşağıdaki kişilerden hangisinin müşavir olarak gümrük işi yürütmek için müşavir lisansına sahip olması GEREKMEZ?","hi":"निम्नलिखित में से किस व्यक्ति को ब्रोकर के रूप में सीमा शुल्क व्यवसाय करने के लिए ब्रोकर लाइसेंस रखने की आवश्यकता नहीं है?","ar":"أيٌّ من الأفراد التالين لا يحتاج إلى حيازة رخصة وسيط لمزاولة الأعمال الجمركية بصفته وسيطاً؟"},"o":[{"en":"A consultant filing classifications on behalf of paying clients","es":"Un consultor que presenta clasificaciones en nombre de clientes que pagan","ru":"Консультант, подающий классификации от имени платящих клиентов","tr":"Ücret ödeyen müşteriler adına sınıflandırma sunan bir danışman","hi":"एक सलाहकार जो भुगतान करने वाले ग्राहकों की ओर से वर्गीकरण दाखिल करता है","ar":"مستشار يقدّم تصنيفات نيابةً عن عملاء يدفعون أتعاباً"},{"en":"A freight forwarder filing entries for unrelated importer clients","es":"Un transitario que presenta entradas para clientes importadores no relacionados","ru":"Экспедитор, подающий декларации для не связанных с ним клиентов-импортеров","tr":"İlişkisiz ithalatçı müşteriler için giriş beyanları sunan bir nakliye komisyoncusu","hi":"एक माल अग्रेषणकर्ता जो असंबद्ध आयातक ग्राहकों के लिए प्रविष्टियाँ दाखिल करता है","ar":"وكيل شحن يقدّم بيانات الإدخال لعملاء مستوردين غير ذوي صلة"},{"en":"A corporation making entry of merchandise it does not own","es":"Una sociedad que realiza la entrada de mercancía que no le pertenece","ru":"Корпорация, оформляющая ввоз товара, который ей не принадлежит","tr":"Sahibi olmadığı malların girişini yapan bir şirket","hi":"एक निगम जो उस माल की प्रविष्टि करता है जिसका वह स्वामी नहीं है","ar":"شركة تُجري إدخال بضاعة لا تملكها"},{"en":"An importer transacting customs business solely on its own behalf for its own merchandise","es":"Un importador que realiza actividades aduaneras únicamente en su propio nombre para su propia mercancía","ru":"Импортер, ведущий таможенную деятельность исключительно от своего имени в отношении собственного товара","tr":"Yalnızca kendi adına ve kendi malları için gümrük işi yürüten bir ithalatçı","hi":"एक आयातक जो केवल अपनी ओर से अपने स्वयं के माल के लिए सीमा शुल्क व्यवसाय करता है","ar":"مستورد يزاول الأعمال الجمركية حصراً نيابةً عن نفسه ولبضاعته الخاصة"}],"e":{"en":"Under 19 CFR 111.2(a), a license is required to transact customs business as a broker, but an importer transacting customs business solely on its own behalf is acting as a principal, not as a broker, and need not be licensed.","es":"Conforme al 19 CFR 111.2(a), se requiere una licencia para realizar actividades aduaneras como agente, pero un importador que realiza actividades aduaneras únicamente en su propio nombre actúa como principal, no como agente, y no necesita licencia.","ru":"Согласно 19 CFR 111.2(a), для ведения таможенной деятельности в качестве брокера требуется лицензия, однако импортер, ведущий таможенную деятельность исключительно от своего имени, действует как принципал, а не как брокер, и не обязан иметь лицензию.","tr":"19 CFR 111.2(a) uyarınca, müşavir olarak gümrük işi yürütmek için lisans gereklidir; ancak yalnızca kendi adına gümrük işi yürüten bir ithalatçı, müşavir olarak değil asıl taraf olarak hareket eder ve lisans sahibi olması gerekmez.","hi":"19 CFR 111.2(a) के अनुसार ब्रोकर के रूप में सीमा शुल्क व्यवसाय करने हेतु लाइसेंस आवश्यक है, परंतु जो आयातक केवल अपनी ओर से सीमा शुल्क व्यवसाय करता है, वह ब्रोकर के रूप में नहीं बल्कि मूल पक्ष (प्रिंसिपल) के रूप में कार्य करता है और उसे लाइसेंस की आवश्यकता नहीं है।","ar":"بموجب 19 CFR 111.2(a)، يُشترط الترخيص لمزاولة الأعمال الجمركية بصفة وسيط، لكن المستورد الذي يزاول الأعمال الجمركية حصراً نيابةً عن نفسه يتصرف بصفته أصيلاً وليس وسيطاً، ولا يلزمه الترخيص."}},{"cat":"compliance","a":0,"q":{"en":"A partnership wishes to obtain a broker's license. What is the minimum licensing requirement for the partnership itself to qualify?","es":"Una sociedad colectiva desea obtener una licencia de agente. ¿Cuál es el requisito mínimo de licencia para que la propia sociedad califique?","ru":"Партнерство желает получить лицензию брокера. Каково минимальное лицензионное требование для того, чтобы само партнерство соответствовало критериям?","tr":"Bir ortaklık, müşavir lisansı almak istemektedir. Ortaklığın bizzat hak kazanması için asgari lisans şartı nedir?","hi":"एक साझेदारी ब्रोकर लाइसेंस प्राप्त करना चाहती है। साझेदारी के स्वयं योग्य होने के लिए न्यूनतम लाइसेंसिंग आवश्यकता क्या है?","ar":"ترغب شراكة في الحصول على رخصة وسيط. ما هو الحد الأدنى لشرط الترخيص لكي تكون الشراكة نفسها مؤهلة؟"},"o":[{"en":"At least one member of the partnership must be a licensed broker","es":"Al menos un miembro de la sociedad debe ser un agente con licencia","ru":"По крайней мере один из членов партнерства должен быть лицензированным брокером","tr":"Ortaklığın en az bir üyesinin lisanslı bir müşavir olması gerekir","hi":"साझेदारी का कम से कम एक सदस्य लाइसेंसधारी ब्रोकर होना चाहिए","ar":"يجب أن يكون عضو واحد على الأقل في الشراكة وسيطاً مرخّصاً"},{"en":"At least two members of the partnership must be licensed brokers","es":"Al menos dos miembros de la sociedad deben ser agentes con licencia","ru":"По крайней мере два члена партнерства должны быть лицензированными брокерами","tr":"Ortaklığın en az iki üyesinin lisanslı müşavir olması gerekir","hi":"साझेदारी के कम से कम दो सदस्य लाइसेंसधारी ब्रोकर होने चाहिए","ar":"يجب أن يكون عضوان على الأقل في الشراكة وسيطين مرخّصين"},{"en":"A majority of the partners must be licensed brokers","es":"La mayoría de los socios deben ser agentes con licencia","ru":"Большинство партнеров должны быть лицензированными брокерами","tr":"Ortakların çoğunluğunun lisanslı müşavir olması gerekir","hi":"साझेदारों में से बहुमत को लाइसेंसधारी ब्रोकर होना चाहिए","ar":"يجب أن تكون أغلبية الشركاء وسطاء مرخّصين"},{"en":"Every partner must be a licensed broker","es":"Cada socio debe ser un agente con licencia","ru":"Каждый партнер должен быть лицензированным брокером","tr":"Her ortağın lisanslı bir müşavir olması gerekir","hi":"प्रत्येक साझेदार को लाइसेंसधारी ब्रोकर होना चाहिए","ar":"يجب أن يكون كل شريك وسيطاً مرخّصاً"}],"e":{"en":"19 CFR 111.11(b) provides that a partnership may be licensed if at least one member of the partnership is a broker.","es":"19 CFR 111.11(b) dispone que una sociedad colectiva puede obtener licencia si al menos un miembro de la sociedad es agente.","ru":"19 CFR 111.11(b) предусматривает, что партнерство может получить лицензию, если по крайней мере один из членов партнерства является брокером.","tr":"19 CFR 111.11(b), ortaklığın en az bir üyesinin müşavir olması halinde ortaklığa lisans verilebileceğini öngörür.","hi":"19 CFR 111.11(b) यह प्रावधान करता है कि किसी साझेदारी को लाइसेंस तब दिया जा सकता है जब साझेदारी का कम से कम एक सदस्य ब्रोकर हो।","ar":"تنص 19 CFR 111.11(b) على أنه يجوز ترخيص الشراكة إذا كان عضو واحد على الأقل من الشراكة وسيطاً."}},{"cat":"compliance","a":2,"q":{"en":"Where must a broker maintain the records required to be kept under Part 111?","es":"¿Dónde debe un agente mantener los registros que deben conservarse conforme a la Part 111?","ru":"Где брокер должен хранить документы, обязательные к ведению согласно Part 111?","tr":"Bir müşavir, Part 111 uyarınca tutulması gereken kayıtları nerede saklamak zorundadır?","hi":"किसी ब्रोकर को Part 111 के अंतर्गत रखे जाने वाले आवश्यक रिकॉर्ड कहाँ रखने होते हैं?","ar":"أين يجب على الوسيط الاحتفاظ بالسجلات المطلوب حفظها بموجب Part 111؟"},"o":[{"en":"At any location designated by the client","es":"En cualquier lugar designado por el cliente","ru":"В любом месте, указанном клиентом","tr":"Müşteri tarafından belirlenen herhangi bir yerde","hi":"ग्राहक द्वारा निर्दिष्ट किसी भी स्थान पर","ar":"في أي موقع يحدّده العميل"},{"en":"At the broker's office of record only","es":"Únicamente en la oficina de registro del agente","ru":"Только в официальном офисе брокера (office of record)","tr":"Yalnızca müşavirin kayıtlı ofisinde","hi":"केवल ब्रोकर के रिकॉर्ड कार्यालय में","ar":"في المكتب الرسمي للوسيط فقط"},{"en":"Within the customs territory of the United States","es":"Dentro del territorio aduanero de los Estados Unidos","ru":"В пределах таможенной территории Соединенных Штатов","tr":"Amerika Birleşik Devletleri gümrük bölgesi içinde","hi":"संयुक्त राज्य अमेरिका के सीमा शुल्क क्षेत्र के भीतर","ar":"داخل الإقليم الجمركي للولايات المتحدة"},{"en":"Within the port district where entry was filed","es":"Dentro del distrito portuario donde se presentó la entrada","ru":"В пределах портового округа, где была подана декларация","tr":"Girişin yapıldığı liman bölgesi içinde","hi":"उस बंदरगाह जिले के भीतर जहाँ प्रविष्टि दाखिल की गई थी","ar":"داخل المنطقة المينائية التي قُدّم فيها الإدخال"}],"e":{"en":"19 CFR 111.23(a) requires that the required records be retained within the customs territory of the United States in accordance with the provisions of Part 111 and Part 163.","es":"19 CFR 111.23(a) exige que los registros requeridos se conserven dentro del territorio aduanero de los Estados Unidos de conformidad con las disposiciones de la Part 111 y la Part 163.","ru":"19 CFR 111.23(a) требует, чтобы обязательные документы хранились в пределах таможенной территории Соединенных Штатов в соответствии с положениями Part 111 и Part 163.","tr":"19 CFR 111.23(a), gerekli kayıtların Part 111 ve Part 163 hükümleri uyarınca Amerika Birleşik Devletleri gümrük bölgesi içinde saklanmasını gerektirir.","hi":"19 CFR 111.23(a) के अनुसार आवश्यक रिकॉर्ड को Part 111 और Part 163 के प्रावधानों के अनुरूप संयुक्त राज्य अमेरिका के सीमा शुल्क क्षेत्र के भीतर रखा जाना चाहिए।","ar":"تشترط 19 CFR 111.23(a) الاحتفاظ بالسجلات المطلوبة داخل الإقليم الجمركي للولايات المتحدة وفقاً لأحكام Part 111 و Part 163."}},{"cat":"compliance","a":3,"q":{"en":"What is the application fee for a national permit under the modernized regulations?","es":"¿Cuál es la tarifa de solicitud de un permiso nacional conforme a los reglamentos modernizados?","ru":"Каков сбор за подачу заявления на национальное разрешение согласно модернизированным нормам?","tr":"Modernize edilmiş düzenlemeler kapsamında ulusal izin için başvuru ücreti nedir?","hi":"आधुनिकीकृत विनियमों के अंतर्गत राष्ट्रीय परमिट के लिए आवेदन शुल्क क्या है?","ar":"ما هي رسوم تقديم طلب التصريح الوطني بموجب اللوائح المُحدَّثة؟"},"o":[{"en":"$300","es":"$300","ru":"$300","tr":"$300","hi":"$300","ar":"$300"},{"en":"$138","es":"$138","ru":"$138","tr":"$138","hi":"$138","ar":"$138"},{"en":"$200","es":"$200","ru":"$200","tr":"$200","hi":"$200","ar":"$200"},{"en":"$100","es":"$100","ru":"$100","tr":"$100","hi":"$100","ar":"$100"}],"e":{"en":"19 CFR 111.96(c) sets the national permit application fee (including a reinstatement application) at $100, payable at the time the application is submitted.","es":"19 CFR 111.96(c) fija la tarifa de solicitud del permiso nacional (incluida una solicitud de restablecimiento) en $100, pagadera al momento de presentar la solicitud.","ru":"19 CFR 111.96(c) устанавливает сбор за подачу заявления на национальное разрешение (включая заявление о восстановлении) в размере $100, подлежащий уплате в момент подачи заявления.","tr":"19 CFR 111.96(c), ulusal izin başvuru ücretini (yeniden geçerlilik başvurusu dahil) başvurunun sunulduğu anda ödenmek üzere $100 olarak belirler.","hi":"19 CFR 111.96(c) राष्ट्रीय परमिट आवेदन शुल्क (पुनर्बहाली आवेदन सहित) को $100 निर्धारित करता है, जो आवेदन प्रस्तुत करते समय देय होता है।","ar":"تحدّد 19 CFR 111.96(c) رسوم طلب التصريح الوطني (بما في ذلك طلب إعادة التفعيل) بمبلغ $100، تُدفَع وقت تقديم الطلب."}},{"cat":"compliance","a":1,"q":{"en":"A corporation seeking a broker's license must have how many licensed officers?","es":"¿Cuántos directivos con licencia debe tener una sociedad que busca una licencia de agente?","ru":"Сколько лицензированных должностных лиц должна иметь корпорация, желающая получить лицензию брокера?","tr":"Müşavir lisansı talep eden bir şirketin kaç lisanslı yetkilisi olmalıdır?","hi":"ब्रोकर लाइसेंस चाहने वाले निगम में कितने लाइसेंसधारी अधिकारी होने चाहिए?","ar":"كم عدد المسؤولين المرخّصين الذين يجب أن تتوفر عليهم الشركة الراغبة في الحصول على رخصة وسيط؟"},"o":[{"en":"All officers must be licensed brokers","es":"Todos los directivos deben ser agentes con licencia","ru":"Все должностные лица должны быть лицензированными брокерами","tr":"Tüm yetkililerin lisanslı müşavir olması gerekir","hi":"सभी अधिकारियों को लाइसेंसधारी ब्रोकर होना चाहिए","ar":"يجب أن يكون جميع المسؤولين وسطاء مرخّصين"},{"en":"At least one officer who is a licensed broker","es":"Al menos un directivo que sea agente con licencia","ru":"По крайней мере одно должностное лицо, являющееся лицензированным брокером","tr":"Lisanslı müşavir olan en az bir yetkili","hi":"कम से कम एक अधिकारी जो लाइसेंसधारी ब्रोकर हो","ar":"مسؤول واحد على الأقل يكون وسيطاً مرخّصاً"},{"en":"A majority of officers who are licensed brokers","es":"La mayoría de los directivos que sean agentes con licencia","ru":"Большинство должностных лиц, являющихся лицензированными брокерами","tr":"Lisanslı müşavir olan yetkililerin çoğunluğu","hi":"बहुमत अधिकारी जो लाइसेंसधारी ब्रोकर हों","ar":"أغلبية المسؤولين الذين يكونون وسطاء مرخّصين"},{"en":"At least two officers who are licensed brokers","es":"Al menos dos directivos que sean agentes con licencia","ru":"По крайней мере два должностных лица, являющихся лицензированными брокерами","tr":"Lisanslı müşavir olan en az iki yetkili","hi":"कम से कम दो अधिकारी जो लाइसेंसधारी ब्रोकर हों","ar":"مسؤولان على الأقل يكونان وسيطين مرخّصين"}],"e":{"en":"19 CFR 111.11(c)(2) requires that a corporation have at least one officer who is a licensed broker in order to qualify for a corporate broker's license.","es":"19 CFR 111.11(c)(2) exige que una sociedad tenga al menos un directivo que sea agente con licencia para calificar para una licencia de agente corporativo.","ru":"19 CFR 111.11(c)(2) требует, чтобы корпорация имела по крайней мере одно должностное лицо, являющееся лицензированным брокером, чтобы соответствовать требованиям для получения корпоративной лицензии брокера.","tr":"19 CFR 111.11(c)(2), bir şirketin kurumsal müşavir lisansına hak kazanabilmesi için lisanslı müşavir olan en az bir yetkilisinin bulunmasını gerektirir.","hi":"19 CFR 111.11(c)(2) के अनुसार किसी निगम को कॉर्पोरेट ब्रोकर लाइसेंस के लिए योग्य होने हेतु कम से कम एक ऐसा अधिकारी होना चाहिए जो लाइसेंसधारी ब्रोकर हो।","ar":"تشترط 19 CFR 111.11(c)(2) أن يكون لدى الشركة مسؤول واحد على الأقل يكون وسيطاً مرخّصاً لكي تكون مؤهلة للحصول على رخصة وسيط للشركات."}},{"cat":"compliance","a":0,"q":{"en":"If a broker receives payment of duties from a client after the date that payment is due to CBP, within what period must the broker transmit those funds to CBP?","es":"Si un agente recibe el pago de derechos de un cliente después de la fecha en que dicho pago debe entregarse a CBP, ¿en qué plazo debe el agente transmitir esos fondos a CBP?","ru":"Если брокер получает от клиента уплату пошлин после даты, когда этот платеж подлежит уплате в CBP, в какой срок брокер должен перечислить эти средства в CBP?","tr":"Bir müşavir, ödemenin CBP'ye yatırılması gereken tarihten sonra bir müşteriden gümrük vergisi ödemesi alırsa, bu tutarı hangi süre içinde CBP'ye aktarmak zorundadır?","hi":"यदि कोई ब्रोकर किसी ग्राहक से शुल्क का भुगतान उस तिथि के बाद प्राप्त करता है जब वह भुगतान CBP को देय था, तो ब्रोकर को वह राशि CBP को किस अवधि के भीतर भेजनी होगी?","ar":"إذا تلقّى الوسيط دفعة رسوم من عميل بعد التاريخ المستحق فيه دفع تلك المبالغ إلى CBP، فخلال أي مدة يجب على الوسيط تحويل تلك الأموال إلى CBP؟"},"o":[{"en":"5 working days from receipt","es":"5 working days desde la recepción","ru":"5 working days с момента получения","tr":"Tahsilattan itibaren 5 working days","hi":"प्राप्ति से 5 working days","ar":"5 working days من الاستلام"},{"en":"15 calendar days from receipt","es":"15 calendar days desde la recepción","ru":"15 calendar days с момента получения","tr":"Tahsilattan itibaren 15 calendar days","hi":"प्राप्ति से 15 calendar days","ar":"15 calendar days من الاستلام"},{"en":"30 calendar days from receipt","es":"30 calendar days desde la recepción","ru":"30 calendar days с момента получения","tr":"Tahsilattan itibaren 30 calendar days","hi":"प्राप्ति से 30 calendar days","ar":"30 calendar days من الاستلام"},{"en":"10 calendar days from receipt","es":"10 calendar days desde la recepción","ru":"10 calendar days с момента получения","tr":"Tahsilattan itibaren 10 calendar days","hi":"प्राप्ति से 10 calendar days","ar":"10 calendar days من الاستلام"}],"e":{"en":"19 CFR 111.29(a) requires a broker to pay duties, taxes, or other debts owed the Government within 5 working days from receipt of payment from a client when that payment is received after the date the broker's obligation was due.","es":"19 CFR 111.29(a) exige que un agente pague los derechos, impuestos u otras deudas adeudadas al Gobierno dentro de 5 working days desde la recepción del pago de un cliente cuando dicho pago se recibe después de la fecha de vencimiento de la obligación del agente.","ru":"19 CFR 111.29(a) требует, чтобы брокер уплатил пошлины, налоги или иные долги перед государством в течение 5 working days с момента получения платежа от клиента, если этот платеж получен после даты наступления срока исполнения обязательства брокера.","tr":"19 CFR 111.29(a), bir müşavirin, ödeme müşaviri yükümlülüğünün vade tarihinden sonra alındığında, müşteriden ödemenin alınmasından itibaren 5 working days içinde Hükümete borçlu olunan gümrük vergilerini, vergileri veya diğer borçları ödemesini gerektirir.","hi":"19 CFR 111.29(a) के अनुसार जब किसी ग्राहक से भुगतान ब्रोकर की बाध्यता की देय तिथि के बाद प्राप्त होता है, तो ब्रोकर को सरकार को देय शुल्क, कर या अन्य ऋण उस भुगतान की प्राप्ति से 5 working days के भीतर चुकाना होगा।","ar":"تشترط 19 CFR 111.29(a) أن يدفع الوسيط الرسوم أو الضرائب أو الديون الأخرى المستحقة للحكومة خلال 5 working days من استلام الدفعة من العميل عندما تُستلَم تلك الدفعة بعد التاريخ الذي استُحق فيه التزام الوسيط."}},{"cat":"compliance","a":2,"q":{"en":"Under 19 CFR 111.24, to which of the following may a broker disclose confidential records and information of a client without the client's authorization?","es":"Conforme al 19 CFR 111.24, ¿a cuál de los siguientes puede un agente divulgar registros e información confidenciales de un cliente sin la autorización del cliente?","ru":"Согласно 19 CFR 111.24, кому из перечисленных брокер может раскрыть конфиденциальные документы и сведения клиента без его разрешения?","tr":"19 CFR 111.24 uyarınca, bir müşavir bir müşterinin gizli kayıtlarını ve bilgilerini, müşterinin izni olmaksızın aşağıdakilerden hangisine ifşa edebilir?","hi":"19 CFR 111.24 के अंतर्गत, कोई ब्रोकर ग्राहक की अनुमति के बिना किसी ग्राहक के गोपनीय रिकॉर्ड और जानकारी निम्नलिखित में से किसे प्रकट कर सकता है?","ar":"بموجب 19 CFR 111.24، لأيٍّ ممّا يلي يجوز للوسيط الإفصاح عن السجلات والمعلومات السرية الخاصة بالعميل دون إذن العميل؟"},"o":[{"en":"A surety on an unrelated entry of a different importer","es":"Una fiadora en una entrada no relacionada de un importador distinto","ru":"Поручителю по не связанной с этим декларации другого импортера","tr":"Farklı bir ithalatçının ilgisiz bir girişindeki kefile","hi":"किसी भिन्न आयातक की असंबद्ध प्रविष्टि पर एक प्रतिभू (श्योरिटी)","ar":"ضامن على بيان إدخال غير ذي صلة لمستورد مختلف"},{"en":"A competing broker requesting account information","es":"Un agente competidor que solicita información de la cuenta","ru":"Конкурирующему брокеру, запрашивающему информацию о счете","tr":"Hesap bilgisi talep eden rakip bir müşavire","hi":"एक प्रतिस्पर्धी ब्रोकर जो खाता जानकारी का अनुरोध करता है","ar":"وسيط منافس يطلب معلومات الحساب"},{"en":"A representative of DHS or another duly authorized officer or agent of the United States","es":"Un representante del DHS u otro funcionario o agente debidamente autorizado de los Estados Unidos","ru":"Представителю DHS или иному надлежащим образом уполномоченному должностному лицу или агенту Соединенных Штатов","tr":"DHS temsilcisine veya Amerika Birleşik Devletleri'nin usulüne uygun olarak yetkilendirilmiş başka bir görevlisine ya da temsilcisine","hi":"DHS का प्रतिनिधि या संयुक्त राज्य अमेरिका का कोई अन्य विधिवत अधिकृत अधिकारी या एजेंट","ar":"ممثّل عن DHS أو موظف أو وكيل آخر مفوّض حسب الأصول من الولايات المتحدة"},{"en":"A trade publication researching import trends","es":"Una publicación comercial que investiga tendencias de importación","ru":"Отраслевому изданию, изучающему тенденции импорта","tr":"İthalat eğilimlerini araştıran bir ticaret yayınına","hi":"एक व्यापार प्रकाशन जो आयात प्रवृत्तियों पर शोध कर रहा है","ar":"منشور تجاري يجري بحثاً عن اتجاهات الاستيراد"}],"e":{"en":"19 CFR 111.24 makes client records confidential, but permits disclosure to the client, the surety on the particular entry, representatives of DHS, and other duly authorized officers or agents of the United States, or under subpoena or court order.","es":"19 CFR 111.24 hace confidenciales los registros del cliente, pero permite su divulgación al cliente, a la fiadora de la entrada en cuestión, a los representantes del DHS y a otros funcionarios o agentes debidamente autorizados de los Estados Unidos, o en virtud de una citación o una orden judicial.","ru":"19 CFR 111.24 объявляет документы клиента конфиденциальными, но разрешает их раскрытие клиенту, поручителю по соответствующей декларации, представителям DHS и иным надлежащим образом уполномоченным должностным лицам или агентам Соединенных Штатов, либо по повестке или постановлению суда.","tr":"19 CFR 111.24, müşteri kayıtlarını gizli kılar, ancak ifşayı müşteriye, ilgili girişteki kefile, DHS temsilcilerine ve Amerika Birleşik Devletleri'nin usulüne uygun olarak yetkilendirilmiş diğer görevlilerine ya da temsilcilerine veya celp ya da mahkeme kararı uyarınca yapılmasına izin verir.","hi":"19 CFR 111.24 ग्राहक के रिकॉर्ड को गोपनीय बनाता है, परंतु उन्हें ग्राहक, उस विशेष प्रविष्टि पर प्रतिभू, DHS के प्रतिनिधियों तथा संयुक्त राज्य अमेरिका के अन्य विधिवत अधिकृत अधिकारियों या एजेंटों को, अथवा सम्मन या न्यायालय के आदेश के अंतर्गत प्रकट करने की अनुमति देता है।","ar":"تجعل 19 CFR 111.24 سجلات العميل سرية، لكنها تجيز الإفصاح عنها للعميل، وللضامن على بيان الإدخال المعني، ولممثّلي DHS وغيرهم من الموظفين أو الوكلاء المفوّضين حسب الأصول للولايات المتحدة، أو بموجب أمر إحضار أو أمر من المحكمة."}},{"cat":"compliance","a":2,"q":{"en":"Within how many calendar days must a broker notify CBP of a change in the broker's office of record, mailing address, or email address?","es":"¿Dentro de cuántos días calendario debe un agente notificar a CBP un cambio en su oficina de registro, dirección postal o dirección de correo electrónico?","ru":"В течение скольких календарных дней брокер должен уведомить CBP об изменении своего официального офиса, почтового адреса или адреса электронной почты?","tr":"Bir müşavir, kayıtlı ofisinde, posta adresinde veya e-posta adresinde meydana gelen bir değişikliği kaç takvim günü içinde CBP'ye bildirmek zorundadır?","hi":"किसी ब्रोकर को अपने रिकॉर्ड कार्यालय, डाक पते या ईमेल पते में परिवर्तन की सूचना CBP को कितने कैलेंडर दिनों के भीतर देनी होती है?","ar":"خلال كم يوماً تقويمياً يجب على الوسيط إخطار CBP بأي تغيير في مكتبه الرسمي أو عنوانه البريدي أو عنوان بريده الإلكتروني؟"},"o":[{"en":"45 calendar days","es":"45 calendar days","ru":"45 calendar days","tr":"45 calendar days","hi":"45 calendar days","ar":"45 calendar days"},{"en":"30 calendar days","es":"30 calendar days","ru":"30 calendar days","tr":"30 calendar days","hi":"30 calendar days","ar":"30 calendar days"},{"en":"10 calendar days","es":"10 calendar days","ru":"10 calendar days","tr":"10 calendar days","hi":"10 calendar days","ar":"10 calendar days"},{"en":"15 calendar days","es":"15 calendar days","ru":"15 calendar days","tr":"15 calendar days","hi":"15 calendar days","ar":"15 calendar days"}],"e":{"en":"19 CFR 111.30(a) requires a broker to update CBP within 10 calendar days of any change to the broker's office of record, mailing address, telephone number, or email address.","es":"19 CFR 111.30(a) exige que un agente actualice la información ante CBP dentro de 10 calendar days de cualquier cambio en su oficina de registro, dirección postal, número de teléfono o dirección de correo electrónico.","ru":"19 CFR 111.30(a) требует, чтобы брокер обновлял сведения в CBP в течение 10 calendar days с момента любого изменения официального офиса, почтового адреса, номера телефона или адреса электронной почты брокера.","tr":"19 CFR 111.30(a), bir müşavirin kayıtlı ofisinde, posta adresinde, telefon numarasında veya e-posta adresinde meydana gelen herhangi bir değişiklikten itibaren 10 calendar days içinde CBP'yi güncellemesini gerektirir.","hi":"19 CFR 111.30(a) के अनुसार किसी ब्रोकर को अपने रिकॉर्ड कार्यालय, डाक पते, टेलीफोन नंबर या ईमेल पते में किसी भी परिवर्तन के 10 calendar days के भीतर CBP को अद्यतन करना होगा।","ar":"تشترط 19 CFR 111.30(a) أن يقوم الوسيط بتحديث بياناته لدى CBP خلال 10 calendar days من أي تغيير في مكتبه الرسمي أو عنوانه البريدي أو رقم هاتفه أو عنوان بريده الإلكتروني."}},{"cat":"compliance","a":1,"q":{"en":"Which of the following is a ground for suspension or revocation of a broker's license or permit under 19 CFR 111.53?","es":"¿Cuál de los siguientes es un motivo de suspensión o revocación de la licencia o el permiso de un agente conforme al 19 CFR 111.53?","ru":"Что из перечисленного является основанием для приостановления или аннулирования лицензии или разрешения брокера согласно 19 CFR 111.53?","tr":"Aşağıdakilerden hangisi 19 CFR 111.53 uyarınca bir müşavirin lisansının veya izninin askıya alınması ya da iptal edilmesi için bir gerekçedir?","hi":"19 CFR 111.53 के अंतर्गत निम्नलिखित में से कौन-सा किसी ब्रोकर के लाइसेंस या परमिट के निलंबन या निरस्तीकरण का आधार है?","ar":"أيٌّ ممّا يلي يُعدّ سبباً لتعليق رخصة الوسيط أو تصريحه أو إلغائهما بموجب 19 CFR 111.53؟"},"o":[{"en":"Filing more than the average number of entries per month","es":"Presentar más entradas que el promedio mensual","ru":"Подача большего, чем в среднем, числа деклараций в месяц","tr":"Aylık ortalama giriş sayısından fazla giriş sunulması","hi":"प्रति माह औसत संख्या से अधिक प्रविष्टियाँ दाखिल करना","ar":"تقديم عدد من بيانات الإدخال يفوق المعدّل الشهري"},{"en":"Violating any law enforced by CBP or the regulations thereunder","es":"Infringir cualquier ley aplicada por CBP o los reglamentos en virtud de la misma","ru":"Нарушение любого закона, исполняемого CBP, или принятых на его основании нормативных актов","tr":"CBP tarafından uygulanan herhangi bir yasanın veya bu yasaya dayanan düzenlemelerin ihlali","hi":"CBP द्वारा प्रवर्तित किसी भी कानून या उसके अंतर्गत बनाए गए विनियमों का उल्लंघन करना","ar":"انتهاك أي قانون تُنفّذه CBP أو اللوائح الصادرة بموجبه"},{"en":"Charging a fee higher than competitors for customs business","es":"Cobrar una tarifa más alta que la de los competidores por actividades aduaneras","ru":"Взимание более высокой, чем у конкурентов, платы за таможенную деятельность","tr":"Gümrük işi için rakiplerden daha yüksek ücret talep edilmesi","hi":"सीमा शुल्क व्यवसाय के लिए प्रतिस्पर्धियों से अधिक शुल्क लेना","ar":"فرض رسوم أعلى من المنافسين مقابل الأعمال الجمركية"},{"en":"Failing to advertise brokerage services in the local port","es":"No anunciar los servicios de agencia en el puerto local","ru":"Неразмещение рекламы брокерских услуг в местном порту","tr":"Müşavirlik hizmetlerinin yerel limanda reklamının yapılmaması","hi":"स्थानीय बंदरगाह में ब्रोकरेज सेवाओं का विज्ञापन न करना","ar":"عدم الإعلان عن خدمات الوساطة في الميناء المحلي"}],"e":{"en":"19 CFR 111.53(c) lists, among the grounds for suspension or revocation, that the broker has violated any provision of any law enforced by CBP or the rules or regulations issued under any such provision.","es":"19 CFR 111.53(c) enumera, entre los motivos de suspensión o revocación, que el agente haya infringido cualquier disposición de cualquier ley aplicada por CBP o las normas o reglamentos emitidos en virtud de tal disposición.","ru":"19 CFR 111.53(c) перечисляет среди оснований для приостановления или аннулирования то, что брокер нарушил любое положение любого закона, исполняемого CBP, либо правила или нормативные акты, изданные в соответствии с таким положением.","tr":"19 CFR 111.53(c), askıya alma veya iptal gerekçeleri arasında, müşavirin CBP tarafından uygulanan herhangi bir yasanın herhangi bir hükmünü veya böyle bir hükme dayanılarak çıkarılan kural ya da düzenlemeleri ihlal etmiş olmasını sayar.","hi":"19 CFR 111.53(c) निलंबन या निरस्तीकरण के आधारों में यह भी सूचीबद्ध करता है कि ब्रोकर ने CBP द्वारा प्रवर्तित किसी कानून के किसी प्रावधान या ऐसे किसी प्रावधान के अंतर्गत जारी नियमों या विनियमों का उल्लंघन किया हो।","ar":"تُدرج 19 CFR 111.53(c) ضمن أسباب التعليق أو الإلغاء أن يكون الوسيط قد انتهك أي حكم من أحكام أي قانون تُنفّذه CBP أو القواعد أو اللوائح الصادرة بموجب أي حكم من هذا القبيل."}},{"cat":"compliance","a":2,"q":{"en":"An individual applicant for a broker's license must be a citizen of the United States. As of what point must citizenship exist?","es":"Un solicitante individual de una licencia de agente debe ser ciudadano de los Estados Unidos. ¿A partir de qué momento debe existir la ciudadanía?","ru":"Индивидуальный заявитель на лицензию брокера должен быть гражданином Соединенных Штатов. С какого момента должно существовать гражданство?","tr":"Müşavir lisansı için bireysel başvuru sahibinin Amerika Birleşik Devletleri vatandaşı olması gerekir. Vatandaşlık hangi andan itibaren mevcut olmalıdır?","hi":"ब्रोकर लाइसेंस के लिए व्यक्तिगत आवेदक को संयुक्त राज्य अमेरिका का नागरिक होना चाहिए। नागरिकता किस समय से होनी चाहिए?","ar":"يجب أن يكون مقدم الطلب الفرد لرخصة الوسيط مواطناً من الولايات المتحدة. اعتباراً من أي لحظة يجب أن تتوفّر الجنسية؟"},"o":[{"en":"Within one year after the license is issued","es":"Dentro del año posterior a la emisión de la licencia","ru":"В течение одного года после выдачи лицензии","tr":"Lisansın verilmesinden sonraki bir yıl içinde","hi":"लाइसेंस जारी होने के एक वर्ष के भीतर","ar":"خلال سنة واحدة بعد إصدار الرخصة"},{"en":"On the date the license is issued","es":"En la fecha en que se emite la licencia","ru":"На дату выдачи лицензии","tr":"Lisansın verildiği tarihte","hi":"उस तिथि पर जब लाइसेंस जारी किया जाता है","ar":"في تاريخ إصدار الرخصة"},{"en":"On the date the license application is submitted","es":"En la fecha en que se presenta la solicitud de licencia","ru":"На дату подачи заявления на лицензию","tr":"Lisans başvurusunun sunulduğu tarihte","hi":"उस तिथि पर जब लाइसेंस आवेदन प्रस्तुत किया जाता है","ar":"في تاريخ تقديم طلب الرخصة"},{"en":"On the date the examination is taken","es":"En la fecha en que se presenta el examen","ru":"На дату сдачи экзамена","tr":"Sınava girilen tarihte","hi":"उस तिथि पर जब परीक्षा दी जाती है","ar":"في تاريخ خوض الامتحان"}],"e":{"en":"19 CFR 111.11(a)(1) requires that an individual be a citizen of the United States on the date of submission of the application for a license and not an officer or employee of the United States Government.","es":"19 CFR 111.11(a)(1) exige que una persona sea ciudadana de los Estados Unidos en la fecha de presentación de la solicitud de licencia y que no sea funcionario o empleado del Gobierno de los Estados Unidos.","ru":"19 CFR 111.11(a)(1) требует, чтобы физическое лицо было гражданином Соединенных Штатов на дату подачи заявления на лицензию и не являлось должностным лицом или служащим Правительства Соединенных Штатов.","tr":"19 CFR 111.11(a)(1), bir bireyin lisans başvurusunun sunulduğu tarihte Amerika Birleşik Devletleri vatandaşı olmasını ve Amerika Birleşik Devletleri Hükümetinin bir görevlisi ya da çalışanı olmamasını gerektirir.","hi":"19 CFR 111.11(a)(1) के अनुसार किसी व्यक्ति को लाइसेंस आवेदन प्रस्तुत करने की तिथि पर संयुक्त राज्य अमेरिका का नागरिक होना चाहिए और वह संयुक्त राज्य अमेरिका सरकार का अधिकारी या कर्मचारी नहीं होना चाहिए।","ar":"تشترط 19 CFR 111.11(a)(1) أن يكون الفرد مواطناً من الولايات المتحدة في تاريخ تقديم طلب الرخصة، وألّا يكون موظفاً أو مستخدَماً لدى حكومة الولايات المتحدة."}},{"cat":"compliance","a":2,"q":{"en":"If a broker fails to file the triennial status report and pay the fee by March 1, what is the consequence under 19 CFR 111.30?","es":"Si un agente no presenta el informe de situación trienal ni paga la tarifa antes del March 1, ¿cuál es la consecuencia conforme al 19 CFR 111.30?","ru":"Если брокер не подает трехлетний отчет о состоянии и не уплачивает сбор до March 1, каковы последствия согласно 19 CFR 111.30?","tr":"Bir müşavir, üç yıllık durum raporunu sunmaz ve ücreti March 1 tarihine kadar ödemezse, 19 CFR 111.30 uyarınca sonuç ne olur?","hi":"यदि कोई ब्रोकर March 1 तक त्रैवार्षिक स्थिति रिपोर्ट दाखिल नहीं करता और शुल्क का भुगतान नहीं करता, तो 19 CFR 111.30 के अंतर्गत क्या परिणाम होता है?","ar":"إذا لم يقدّم الوسيط تقرير الحالة الذي يُقدَّم كل ثلاث سنوات ولم يدفع الرسوم بحلول March 1، فما هي العاقبة بموجب 19 CFR 111.30؟"},"o":[{"en":"The license is permanently revoked immediately","es":"La licencia se revoca permanentemente de inmediato","ru":"Лицензия немедленно аннулируется навсегда","tr":"Lisans derhal ve kalıcı olarak iptal edilir","hi":"लाइसेंस तुरंत स्थायी रूप से निरस्त कर दिया जाता है","ar":"تُلغى الرخصة نهائياً وعلى الفور"},{"en":"The broker receives a 30-day written warning before any action","es":"El agente recibe una advertencia escrita de 30-day antes de cualquier acción","ru":"Брокер получает письменное предупреждение за 30-day до любых действий","tr":"Müşavire herhangi bir işlemden önce 30-day yazılı uyarı verilir","hi":"किसी कार्रवाई से पहले ब्रोकर को 30-day लिखित चेतावनी मिलती है","ar":"يتلقّى الوسيط إنذاراً كتابياً مدته 30-day قبل اتخاذ أي إجراء"},{"en":"The license is suspended by operation of law and may be revoked if not cured within 60 days","es":"La licencia queda suspendida por ministerio de la ley y puede revocarse si no se subsana dentro de 60 days","ru":"Лицензия приостанавливается в силу закона и может быть аннулирована, если нарушение не устранено в течение 60 days","tr":"Lisans, kanun gereği askıya alınır ve 60 days içinde giderilmezse iptal edilebilir","hi":"लाइसेंस कानून के प्रवर्तन से निलंबित हो जाता है और यदि 60 days के भीतर सुधार नहीं किया जाता तो निरस्त किया जा सकता है","ar":"تُعلَّق الرخصة بحكم القانون وقد تُلغى إذا لم يُصحَّح الوضع خلال 60 days"},{"en":"The broker is assessed a $1,000 late penalty but the license remains active","es":"Se impone al agente una multa por demora de $1,000 pero la licencia permanece activa","ru":"На брокера налагается штраф за просрочку в размере $1,000, но лицензия остается действующей","tr":"Müşavire $1,000 gecikme cezası kesilir ancak lisans aktif kalır","hi":"ब्रोकर पर $1,000 का विलंब जुर्माना लगाया जाता है परंतु लाइसेंस सक्रिय रहता है","ar":"تُفرَض على الوسيط غرامة تأخير قدرها $1,000 لكن تظل الرخصة سارية"}],"e":{"en":"Under 19 CFR 111.30(d), failure to file the report and pay the fee by March 1 results in suspension of the license by operation of law; if not cured within 60 calendar days of notification, the license is revoked without prejudice.","es":"Conforme al 19 CFR 111.30(d), no presentar el informe ni pagar la tarifa antes del March 1 resulta en la suspensión de la licencia por ministerio de la ley; si no se subsana dentro de 60 calendar days de la notificación, la licencia se revoca sin perjuicio.","ru":"Согласно 19 CFR 111.30(d), неподача отчета и неуплата сбора до March 1 влечет приостановление лицензии в силу закона; если нарушение не устранено в течение 60 calendar days с момента уведомления, лицензия аннулируется без ущерба для прав.","tr":"19 CFR 111.30(d) uyarınca, raporun sunulmaması ve ücretin March 1 tarihine kadar ödenmemesi, lisansın kanun gereği askıya alınmasıyla sonuçlanır; bildirimden itibaren 60 calendar days içinde giderilmezse lisans, haklar saklı kalmak kaydıyla iptal edilir.","hi":"19 CFR 111.30(d) के अनुसार, March 1 तक रिपोर्ट दाखिल न करने और शुल्क का भुगतान न करने पर लाइसेंस कानून के प्रवर्तन से निलंबित हो जाता है; यदि अधिसूचना के 60 calendar days के भीतर सुधार नहीं किया जाता, तो लाइसेंस बिना पूर्वाग्रह के निरस्त कर दिया जाता है।","ar":"بموجب 19 CFR 111.30(d)، يؤدي عدم تقديم التقرير ودفع الرسوم بحلول March 1 إلى تعليق الرخصة بحكم القانون؛ وإذا لم يُصحَّح الوضع خلال 60 calendar days من الإخطار، تُلغى الرخصة دون المساس بالحقوق."}},{"cat":"compliance","a":0,"q":{"en":"Which statement about a broker's handling of client payment of CBP charges under 19 CFR 111.29 is TRUE?","es":"¿Cuál afirmación sobre el manejo por parte de un agente del pago de cargos de CBP por parte del cliente conforme al 19 CFR 111.29 es VERDADERA?","ru":"Какое утверждение о порядке обращения брокера с оплатой клиентом сборов CBP согласно 19 CFR 111.29 является ВЕРНЫМ?","tr":"19 CFR 111.29 uyarınca bir müşavirin, müşterinin CBP harçlarını ödemesini ele alışına ilişkin aşağıdaki ifadelerden hangisi DOĞRUDUR?","hi":"19 CFR 111.29 के अंतर्गत ग्राहक द्वारा CBP शुल्कों के भुगतान को संभालने के संबंध में कौन-सा कथन सत्य है?","ar":"أيٌّ من العبارات التالية بشأن تعامل الوسيط مع دفع العميل لرسوم CBP بموجب 19 CFR 111.29 صحيحة؟"},"o":[{"en":"A broker must advise clients that they may pay certain charges, such as duties and fees, directly to CBP by a separate check made payable to CBP","es":"Un agente debe informar a los clientes que pueden pagar ciertos cargos, como derechos y tarifas, directamente a CBP mediante un cheque por separado a favor de CBP","ru":"Брокер должен информировать клиентов о том, что они могут оплачивать определенные сборы, такие как пошлины и сборы, непосредственно CBP отдельным чеком, выписанным на имя CBP","tr":"Bir müşavir, müşterilerine gümrük vergileri ve harçlar gibi belirli ödemeleri CBP'ye ödenecek ayrı bir çekle doğrudan CBP'ye ödeyebileceklerini bildirmelidir","hi":"किसी ब्रोकर को ग्राहकों को सूचित करना चाहिए कि वे कुछ शुल्क, जैसे ड्यूटी और फीस, CBP के नाम देय अलग चेक के माध्यम से सीधे CBP को भुगतान कर सकते हैं","ar":"يجب على الوسيط إبلاغ العملاء بأنه يجوز لهم دفع رسوم معيّنة، مثل الرسوم الجمركية والأتعاب، مباشرةً إلى CBP بموجب شيك منفصل مُحرَّر لأمر CBP"},{"en":"A broker must deposit all client checks into the broker's operating account first","es":"Un agente debe depositar primero todos los cheques de los clientes en su cuenta operativa","ru":"Брокер должен сначала вносить все чеки клиентов на свой операционный счет","tr":"Bir müşavir, tüm müşteri çeklerini önce kendi işletme hesabına yatırmalıdır","hi":"किसी ब्रोकर को सभी ग्राहक चेक पहले अपने परिचालन खाते में जमा करने होंगे","ar":"يجب على الوسيط إيداع جميع شيكات العملاء أولاً في حسابه التشغيلي"},{"en":"A broker may never accept a separate check made payable to CBP from a client","es":"Un agente nunca puede aceptar de un cliente un cheque por separado a favor de CBP","ru":"Брокер никогда не может принимать от клиента отдельный чек, выписанный на имя CBP","tr":"Bir müşavir, müşteriden CBP'ye ödenecek ayrı bir çeki asla kabul edemez","hi":"कोई ब्रोकर किसी ग्राहक से CBP के नाम देय अलग चेक कभी स्वीकार नहीं कर सकता","ar":"لا يجوز للوسيط أبداً قبول شيك منفصل من العميل مُحرَّر لأمر CBP"},{"en":"A broker may retain a portion of a CBP check as a processing fee","es":"Un agente puede retener una parte de un cheque destinado a CBP como tarifa de procesamiento","ru":"Брокер может удержать часть чека, предназначенного CBP, в качестве платы за обработку","tr":"Bir müşavir, CBP'ye ait bir çekin bir kısmını işlem ücreti olarak alıkoyabilir","hi":"कोई ब्रोकर CBP के चेक का एक भाग प्रसंस्करण शुल्क के रूप में रख सकता है","ar":"يجوز للوسيط الاحتفاظ بجزء من شيك CBP كرسوم معالجة"}],"e":{"en":"19 CFR 111.29(a) requires a broker to advise clients that they may pay certain charges (such as duties, taxes, or fees) by check made payable to U.S. Customs and Border Protection, which the broker will then deliver to CBP.","es":"19 CFR 111.29(a) exige que un agente informe a los clientes que pueden pagar ciertos cargos (como derechos, impuestos o tarifas) mediante cheque a favor de U.S. Customs and Border Protection, que el agente entregará luego a CBP.","ru":"19 CFR 111.29(a) требует, чтобы брокер информировал клиентов о том, что они могут оплачивать определенные сборы (такие как пошлины, налоги или сборы) чеком, выписанным на имя U.S. Customs and Border Protection, который брокер затем передаст в CBP.","tr":"19 CFR 111.29(a), bir müşavirin müşterilerine belirli ödemeleri (gümrük vergileri, vergiler veya harçlar gibi) U.S. Customs and Border Protection'a ödenecek bir çekle yapabileceklerini ve bu çeki daha sonra müşavirin CBP'ye teslim edeceğini bildirmesini gerektirir.","hi":"19 CFR 111.29(a) के अनुसार किसी ब्रोकर को ग्राहकों को सूचित करना होगा कि वे कुछ शुल्क (जैसे ड्यूटी, कर या फीस) U.S. Customs and Border Protection के नाम देय चेक के माध्यम से भुगतान कर सकते हैं, जिसे ब्रोकर फिर CBP को सौंपेगा।","ar":"تشترط 19 CFR 111.29(a) أن يبلغ الوسيط العملاء بأنه يجوز لهم دفع رسوم معيّنة (مثل الرسوم الجمركية أو الضرائب أو الأتعاب) بشيك مُحرَّر لأمر U.S. Customs and Border Protection، يقوم الوسيط بعد ذلك بتسليمه إلى CBP."}},{"cat":"compliance","a":3,"q":{"en":"Under the modernized 19 CFR Part 111, the continuing broker education requirement applies to which licensees?","es":"Conforme al 19 CFR Part 111 modernizado, ¿a qué titulares de licencia se aplica el requisito de educación continua de agentes?","ru":"Согласно модернизированному 19 CFR Part 111, к каким держателям лицензий применяется требование о непрерывном образовании брокеров?","tr":"Modernize edilmiş 19 CFR Part 111 uyarınca, sürekli müşavir eğitimi şartı hangi lisans sahiplerine uygulanır?","hi":"आधुनिकीकृत 19 CFR Part 111 के अंतर्गत, निरंतर ब्रोकर शिक्षा आवश्यकता किन लाइसेंसधारकों पर लागू होती है?","ar":"بموجب 19 CFR Part 111 المُحدَّثة، على أيٍّ من حاملي الرخص يُطبَّق شرط التعليم المستمر للوسطاء؟"},"o":[{"en":"All license holders, including corporations and partnerships","es":"Todos los titulares de licencia, incluidas sociedades y sociedades colectivas","ru":"На всех держателей лицензий, включая корпорации и партнерства","tr":"Şirketler ve ortaklıklar dahil tüm lisans sahipleri","hi":"सभी लाइसेंसधारक, जिनमें निगम और साझेदारियाँ शामिल हैं","ar":"جميع حاملي الرخص، بما في ذلك الشركات والشراكات"},{"en":"Only brokers who hold a national permit","es":"Solo los agentes que poseen un permiso nacional","ru":"Только на брокеров, имеющих национальное разрешение","tr":"Yalnızca ulusal izne sahip müşavirler","hi":"केवल वे ब्रोकर जिनके पास राष्ट्रीय परमिट है","ar":"الوسطاء الحائزون على تصريح وطني فقط"},{"en":"Only brokers who employ more than 25 people","es":"Solo los agentes que emplean a más de 25 personas","ru":"Только на брокеров, у которых работает более 25 человек","tr":"Yalnızca 25'ten fazla kişi istihdam eden müşavirler","hi":"केवल वे ब्रोकर जो 25 से अधिक लोगों को रोजगार देते हैं","ar":"الوسطاء الذين يوظّفون أكثر من 25 شخصاً فقط"},{"en":"Only individual (natural person) brokers","es":"Solo los agentes individuales (personas físicas)","ru":"Только на индивидуальных брокеров (физических лиц)","tr":"Yalnızca bireysel (gerçek kişi) müşavirler","hi":"केवल व्यक्तिगत (प्राकृतिक व्यक्ति) ब्रोकर","ar":"وسطاء الأفراد (الأشخاص الطبيعيون) فقط"}],"e":{"en":"The continuing education requirement in 19 CFR Part 111 Subpart F applies only to individual brokers; corporate, partnership, and association license holders are not subject to the continuing broker education requirement.","es":"El requisito de educación continua del 19 CFR Part 111 Subpart F se aplica solo a los agentes individuales; los titulares de licencias de sociedades, sociedades colectivas y asociaciones no están sujetos al requisito de educación continua de agentes.","ru":"Требование о непрерывном образовании в 19 CFR Part 111 Subpart F применяется только к индивидуальным брокерам; держатели лицензий корпораций, партнерств и ассоциаций не подпадают под требование о непрерывном образовании брокеров.","tr":"19 CFR Part 111 Subpart F'teki sürekli eğitim şartı yalnızca bireysel müşavirlere uygulanır; şirket, ortaklık ve dernek lisans sahipleri sürekli müşavir eğitimi şartına tabi değildir.","hi":"19 CFR Part 111 Subpart F में निरंतर शिक्षा की आवश्यकता केवल व्यक्तिगत ब्रोकरों पर लागू होती है; निगम, साझेदारी और संघ लाइसेंसधारक निरंतर ब्रोकर शिक्षा आवश्यकता के अधीन नहीं हैं।","ar":"ينطبق شرط التعليم المستمر في 19 CFR Part 111 Subpart F على وسطاء الأفراد فقط؛ أما حاملو رخص الشركات والشراكات والجمعيات فلا يخضعون لشرط التعليم المستمر للوسطاء."}},{"cat":"compliance","a":0,"q":{"en":"How many continuing broker education credits must an individual broker complete during each triennial period under the modernized regulations?","es":"¿Cuántos créditos de educación continua de agentes debe completar un agente individual durante cada período trienal conforme a los reglamentos modernizados?","ru":"Сколько кредитов непрерывного образования брокера должен набрать индивидуальный брокер в течение каждого трехлетнего периода согласно модернизированным нормам?","tr":"Modernize edilmiş düzenlemeler kapsamında, bireysel bir müşavir her üç yıllık dönemde kaç sürekli müşavir eğitimi kredisi tamamlamak zorundadır?","hi":"आधुनिकीकृत विनियमों के अंतर्गत किसी व्यक्तिगत ब्रोकर को प्रत्येक त्रैवार्षिक अवधि के दौरान कितने निरंतर ब्रोकर शिक्षा क्रेडिट पूरे करने होते हैं?","ar":"كم عدد ساعات التعليم المستمر للوسطاء التي يجب على الوسيط الفرد إكمالها خلال كل فترة من ثلاث سنوات بموجب اللوائح المُحدَّثة؟"},"o":[{"en":"36 credits","es":"36 credits","ru":"36 credits","tr":"36 credits","hi":"36 credits","ar":"36 credits"},{"en":"12 credits","es":"12 créditos","ru":"12 кредитов","tr":"12 kredi","hi":"12 क्रेडिट","ar":"12 ساعة معتمدة"},{"en":"24 credits","es":"24 créditos","ru":"24 кредита","tr":"24 kredi","hi":"24 क्रेडिट","ar":"24 ساعة معتمدة"},{"en":"48 credits","es":"48 créditos","ru":"48 кредитов","tr":"48 kredi","hi":"48 क्रेडिट","ar":"48 ساعة معتمدة"}],"e":{"en":"19 CFR Part 111 Subpart F requires an individual broker subject to the requirement to complete at least 36 continuing education credits each triennial period, first certified with the status report due in 2027.","es":"19 CFR Part 111 Subpart F exige que un agente individual sujeto al requisito complete al menos 36 credits de educación continua en cada período trienal, certificados por primera vez con el informe de situación que vence en 2027.","ru":"19 CFR Part 111 Subpart F требует, чтобы индивидуальный брокер, на которого распространяется это требование, набирал не менее 36 credits непрерывного образования за каждый трехлетний период, что впервые подтверждается отчетом о состоянии со сроком подачи в 2027.","tr":"19 CFR Part 111 Subpart F, şarta tabi bireysel bir müşavirin her üç yıllık dönemde en az 36 credits sürekli eğitim kredisi tamamlamasını gerektirir; bu ilk olarak 2027 yılında verilecek durum raporuyla belgelenir.","hi":"19 CFR Part 111 Subpart F के अनुसार आवश्यकता के अधीन किसी व्यक्तिगत ब्रोकर को प्रत्येक त्रैवार्षिक अवधि में कम से कम 36 credits निरंतर शिक्षा क्रेडिट पूरे करने होंगे, जिन्हें पहली बार 2027 में देय स्थिति रिपोर्ट के साथ प्रमाणित किया जाएगा।","ar":"تشترط 19 CFR Part 111 Subpart F أن يُكمل الوسيط الفرد الخاضع للشرط ما لا يقل عن 36 credits من ساعات التعليم المستمر في كل فترة من ثلاث سنوات، ويُصادَق عليها لأول مرة مع تقرير الحالة المستحق في 2027."}},{"cat":"compliance","a":0,"q":{"en":"Which of the following is NOT a factor CBP considers in evaluating whether a broker exercises responsible supervision and control under 19 CFR 111.28?","es":"¿Cuál de los siguientes NO es un factor que CBP considera al evaluar si un agente ejerce una supervisión y control responsables conforme al 19 CFR 111.28?","ru":"Что из перечисленного НЕ является фактором, который CBP учитывает при оценке того, осуществляет ли брокер ответственный надзор и контроль согласно 19 CFR 111.28?","tr":"Aşağıdakilerden hangisi, 19 CFR 111.28 uyarınca bir müşavirin sorumlu denetim ve kontrol uygulayıp uygulamadığını değerlendirirken CBP'nin dikkate aldığı bir faktör DEĞİLDİR?","hi":"19 CFR 111.28 के अंतर्गत यह मूल्यांकन करते समय कि कोई ब्रोकर जिम्मेदार पर्यवेक्षण और नियंत्रण रखता है या नहीं, निम्नलिखित में से कौन-सा कारक CBP विचार में नहीं लेता?","ar":"أيٌّ ممّا يلي ليس عاملاً تأخذه CBP في الاعتبار عند تقييم ما إذا كان الوسيط يمارس إشرافاً ورقابة مسؤولين بموجب 19 CFR 111.28؟"},"o":[{"en":"The political affiliation of the broker's officers and employees","es":"La afiliación política de los directivos y empleados del agente","ru":"Политическая принадлежность должностных лиц и сотрудников брокера","tr":"Müşavirin yetkililerinin ve çalışanlarının siyasi bağlılığı","hi":"ब्रोकर के अधिकारियों और कर्मचारियों की राजनीतिक संबद्धता","ar":"الانتماء السياسي لمسؤولي الوسيط وموظفيه"},{"en":"The volume and type of customs business handled by the broker","es":"El volumen y el tipo de actividades aduaneras gestionadas por el agente","ru":"Объем и характер таможенной деятельности, которой занимается брокер","tr":"Müşavirin yürüttüğü gümrük işinin hacmi ve türü","hi":"ब्रोकर द्वारा संभाले गए सीमा शुल्क व्यवसाय की मात्रा और प्रकार","ar":"حجم ونوع الأعمال الجمركية التي يتولّاها الوسيط"},{"en":"The frequency of supervisory visits to offices that do not have a resident licensed broker","es":"La frecuencia de las visitas de supervisión a oficinas que no cuentan con un agente con licencia residente","ru":"Частота надзорных посещений офисов, в которых нет штатного лицензированного брокера","tr":"Yerleşik lisanslı bir müşaviri bulunmayan ofislere yapılan denetim ziyaretlerinin sıklığı","hi":"उन कार्यालयों में पर्यवेक्षी दौरों की आवृत्ति जहाँ कोई स्थानीय लाइसेंसधारी ब्रोकर नहीं है","ar":"تكرار الزيارات الإشرافية للمكاتب التي لا يوجد بها وسيط مرخّص مقيم"},{"en":"The availability of a licensed broker for necessary consultation with employees","es":"La disponibilidad de un agente con licencia para la consulta necesaria con los empleados","ru":"Доступность лицензированного брокера для необходимых консультаций с сотрудниками","tr":"Çalışanlarla gerekli istişare için lisanslı bir müşavirin hazır bulunması","hi":"कर्मचारियों के साथ आवश्यक परामर्श हेतु किसी लाइसेंसधारी ब्रोकर की उपलब्धता","ar":"توافر وسيط مرخّص للتشاور اللازم مع الموظفين"}],"e":{"en":"19 CFR 111.28(a) and the definition in 111.1 list factors such as supervisory visit frequency, business volume, reject/error rates, and availability of a licensed broker; the political affiliation of personnel is not among the enumerated factors.","es":"19 CFR 111.28(a) y la definición en 111.1 enumeran factores como la frecuencia de las visitas de supervisión, el volumen de actividad, las tasas de rechazo/error y la disponibilidad de un agente con licencia; la afiliación política del personal no se encuentra entre los factores enumerados.","ru":"19 CFR 111.28(a) и определение в 111.1 перечисляют такие факторы, как частота надзорных посещений, объем деятельности, доля отклонений/ошибок и доступность лицензированного брокера; политическая принадлежность персонала не входит в число перечисленных факторов.","tr":"19 CFR 111.28(a) ve 111.1'deki tanım, denetim ziyareti sıklığı, iş hacmi, ret/hata oranları ve lisanslı bir müşavirin hazır bulunması gibi faktörleri sıralar; personelin siyasi bağlılığı sayılan faktörler arasında değildir.","hi":"19 CFR 111.28(a) और 111.1 की परिभाषा में पर्यवेक्षी दौरों की आवृत्ति, व्यवसाय की मात्रा, अस्वीकृति/त्रुटि दर और लाइसेंसधारी ब्रोकर की उपलब्धता जैसे कारक सूचीबद्ध हैं; कर्मचारियों की राजनीतिक संबद्धता उल्लिखित कारकों में नहीं है।","ar":"تُدرج 19 CFR 111.28(a) والتعريف الوارد في 111.1 عوامل مثل تكرار الزيارات الإشرافية وحجم الأعمال ومعدّلات الرفض/الخطأ وتوافر وسيط مرخّص؛ أما الانتماء السياسي للموظفين فليس من بين العوامل المذكورة."}},{"cat":"compliance","a":0,"q":{"en":"A broker receives funds from a client to pay duties to CBP but does not make the payment to CBP. Within how many calendar days must the broker account in writing to the client for the funds received?","es":"Un agente recibe fondos de un cliente para pagar derechos a CBP pero no realiza el pago a CBP. ¿Dentro de cuántos días calendario debe el agente rendir cuentas por escrito al cliente de los fondos recibidos?","ru":"Брокер получает от клиента средства для уплаты пошлин в CBP, но не производит платеж в CBP. В течение скольких календарных дней брокер должен письменно отчитаться перед клиентом о полученных средствах?","tr":"Bir müşavir, CBP'ye gümrük vergisi ödemek üzere bir müşteriden para alır ancak ödemeyi CBP'ye yapmaz. Müşavir, alınan para için müşteriye kaç takvim günü içinde yazılı olarak hesap vermek zorundadır?","hi":"कोई ब्रोकर किसी ग्राहक से CBP को शुल्क चुकाने हेतु धन प्राप्त करता है परंतु CBP को भुगतान नहीं करता। ब्रोकर को प्राप्त धन का लिखित हिसाब ग्राहक को कितने कैलेंडर दिनों के भीतर देना होगा?","ar":"يتلقّى الوسيط أموالاً من عميل لدفع رسوم إلى CBP لكنه لا يسدّد المبلغ إلى CBP. خلال كم يوماً تقويمياً يجب على الوسيط أن يقدّم للعميل كشف حساب كتابياً عن الأموال المستلَمة؟"},"o":[{"en":"60 calendar days","es":"60 calendar days","ru":"60 calendar days","tr":"60 calendar days","hi":"60 calendar days","ar":"60 calendar days"},{"en":"30 calendar days","es":"30 calendar days","ru":"30 calendar days","tr":"30 calendar days","hi":"30 calendar days","ar":"30 calendar days"},{"en":"90 calendar days","es":"90 calendar days","ru":"90 calendar days","tr":"90 calendar days","hi":"90 calendar days","ar":"90 calendar days"},{"en":"45 calendar days","es":"45 calendar days","ru":"45 calendar days","tr":"45 calendar days","hi":"45 calendar days","ar":"45 calendar days"}],"e":{"en":"19 CFR 111.29(a) requires a broker to provide the client with a written account or return of the funds within 60 calendar days when the broker receives money from a client to pay charges and does not make the payment, or receives more than the proper charges.","es":"19 CFR 111.29(a) exige que un agente proporcione al cliente una rendición de cuentas por escrito o la devolución de los fondos dentro de 60 calendar days cuando el agente recibe dinero de un cliente para pagar cargos y no realiza el pago, o recibe más de los cargos correspondientes.","ru":"19 CFR 111.29(a) требует, чтобы брокер предоставил клиенту письменный отчет или возвратил средства в течение 60 calendar days, когда брокер получает от клиента деньги для уплаты сборов и не производит платеж либо получает больше надлежащих сборов.","tr":"19 CFR 111.29(a), bir müşavirin, ödemeleri yapmak üzere bir müşteriden para alıp ödemeyi yapmadığında ya da gereken ücretlerden fazlasını aldığında, 60 calendar days içinde müşteriye yazılı bir hesap veya paranın iadesini sağlamasını gerektirir.","hi":"19 CFR 111.29(a) के अनुसार जब कोई ब्रोकर किसी ग्राहक से शुल्क चुकाने हेतु धन प्राप्त करता है और भुगतान नहीं करता, या उचित शुल्क से अधिक प्राप्त करता है, तो ब्रोकर को 60 calendar days के भीतर ग्राहक को लिखित हिसाब देना या धन वापस करना होगा।","ar":"تشترط 19 CFR 111.29(a) أن يقدّم الوسيط للعميل كشف حساب كتابياً أو يردّ الأموال خلال 60 calendar days عندما يتلقّى مالاً من عميل لدفع رسوم ولا يسدّد المبلغ، أو يتلقّى أكثر من الرسوم المستحقة."}},{"cat":"compliance","a":2,"q":{"en":"Which of the following must be included in a broker's national permit application under 19 CFR 111.19?","es":"¿Cuál de los siguientes debe incluirse en la solicitud de permiso nacional de un agente conforme al 19 CFR 111.19?","ru":"Что из перечисленного должно быть включено в заявление брокера на национальное разрешение согласно 19 CFR 111.19?","tr":"19 CFR 111.19 uyarınca bir müşavirin ulusal izin başvurusunda aşağıdakilerden hangisinin yer alması gerekir?","hi":"19 CFR 111.19 के अंतर्गत किसी ब्रोकर के राष्ट्रीय परमिट आवेदन में निम्नलिखित में से क्या शामिल होना चाहिए?","ar":"أيٌّ ممّا يلي يجب أن يُدرَج في طلب التصريح الوطني للوسيط بموجب 19 CFR 111.19؟"},"o":[{"en":"A surety bond rider for each district in which business is conducted","es":"Un anexo de fianza para cada distrito en el que se realicen actividades","ru":"Дополнение к гарантийной облигации для каждого округа, в котором ведется деятельность","tr":"İş yürütülen her bölge için bir kefalet senedi eki","hi":"प्रत्येक जिले के लिए एक ज़मानत बॉन्ड राइडर जहाँ व्यवसाय किया जाता है","ar":"ملحق سند ضمان لكل منطقة تُزاول فيها الأعمال"},{"en":"A list of the broker's competitors in each port of entry","es":"Una lista de los competidores del agente en cada puerto de entrada","ru":"Список конкурентов брокера в каждом порту ввоза","tr":"Müşavirin her giriş limanındaki rakiplerinin bir listesi","hi":"प्रत्येक प्रवेश बंदरगाह में ब्रोकर के प्रतिस्पर्धियों की सूची","ar":"قائمة بمنافسي الوسيط في كل ميناء دخول"},{"en":"A supervision plan describing how the broker will exercise responsible supervision and control","es":"Un plan de supervisión que describa cómo el agente ejercerá una supervisión y control responsables","ru":"План надзора с описанием того, как брокер будет осуществлять ответственный надзор и контроль","tr":"Müşavirin sorumlu denetim ve kontrolü nasıl uygulayacağını açıklayan bir denetim planı","hi":"एक पर्यवेक्षण योजना जो यह वर्णन करे कि ब्रोकर जिम्मेदार पर्यवेक्षण और नियंत्रण कैसे रखेगा","ar":"خطة إشراف تصف كيفية ممارسة الوسيط للإشراف والرقابة المسؤولين"},{"en":"Proof of district permit issuance for at least three districts","es":"Prueba de la emisión de permisos de distrito para al menos tres distritos","ru":"Подтверждение выдачи окружных разрешений по меньшей мере для трех округов","tr":"En az üç bölge için bölge izni verildiğine dair kanıt","hi":"कम से कम तीन जिलों के लिए जिला परमिट जारी होने का प्रमाण","ar":"إثبات إصدار تصاريح إقليمية لثلاث مناطق على الأقل"}],"e":{"en":"19 CFR 111.19(b) requires the national permit application to include, among other items, a supervision plan describing how the applicant will exercise responsible supervision and control over its customs business, plus the office of record, a CBP point of contact, employee information, and the records-retention location.","es":"19 CFR 111.19(b) exige que la solicitud de permiso nacional incluya, entre otros elementos, un plan de supervisión que describa cómo el solicitante ejercerá una supervisión y control responsables sobre sus actividades aduaneras, además de la oficina de registro, un punto de contacto de CBP, información de los empleados y el lugar de conservación de los registros.","ru":"19 CFR 111.19(b) требует, чтобы заявление на национальное разрешение включало, среди прочего, план надзора с описанием того, как заявитель будет осуществлять ответственный надзор и контроль над своей таможенной деятельностью, а также официальный офис, контактное лицо CBP, сведения о сотрудниках и место хранения документов.","tr":"19 CFR 111.19(b), ulusal izin başvurusunun diğer hususların yanı sıra, başvuru sahibinin gümrük işi üzerinde sorumlu denetim ve kontrolü nasıl uygulayacağını açıklayan bir denetim planını, ayrıca kayıtlı ofisi, bir CBP irtibat noktasını, çalışan bilgilerini ve kayıtların saklanacağı yeri içermesini gerektirir.","hi":"19 CFR 111.19(b) के अनुसार राष्ट्रीय परमिट आवेदन में, अन्य बातों के साथ-साथ, एक पर्यवेक्षण योजना शामिल होनी चाहिए जो वर्णन करे कि आवेदक अपने सीमा शुल्क व्यवसाय पर जिम्मेदार पर्यवेक्षण और नियंत्रण कैसे रखेगा, साथ ही रिकॉर्ड कार्यालय, एक CBP संपर्क बिंदु, कर्मचारी जानकारी और रिकॉर्ड-संरक्षण स्थान भी शामिल होना चाहिए।","ar":"تشترط 19 CFR 111.19(b) أن يتضمّن طلب التصريح الوطني، من بين أمور أخرى، خطة إشراف تصف كيفية ممارسة مقدم الطلب للإشراف والرقابة المسؤولين على أعماله الجمركية، إضافةً إلى المكتب الرسمي وجهة اتصال لدى CBP ومعلومات الموظفين وموقع حفظ السجلات."}},{"cat":"compliance","a":0,"q":{"en":"A broker holds a power of attorney that the client has revoked. How long must the broker retain the revoked power of attorney under 19 CFR 111.23?","es":"Un agente posee un poder notarial que el cliente ha revocado. ¿Por cuánto tiempo debe el agente conservar el poder notarial revocado conforme al 19 CFR 111.23?","ru":"Брокер располагает доверенностью, которую клиент отозвал. Как долго брокер должен хранить отозванную доверенность согласно 19 CFR 111.23?","tr":"Bir müşavir, müşterinin iptal ettiği bir vekaletnameye sahiptir. Müşavir, iptal edilen vekaletnameyi 19 CFR 111.23 uyarınca ne kadar süre saklamak zorundadır?","hi":"किसी ब्रोकर के पास एक मुख्तारनामा (पावर ऑफ अटॉर्नी) है जिसे ग्राहक ने रद्द कर दिया है। ब्रोकर को 19 CFR 111.23 के अंतर्गत रद्द किए गए मुख्तारनामे को कितने समय तक रखना होगा?","ar":"يحوز الوسيط توكيلاً ألغاه العميل. إلى متى يجب على الوسيط الاحتفاظ بالتوكيل المُلغى بموجب 19 CFR 111.23؟"},"o":[{"en":"Until 5 years after the date of revocation or after the client ceases to be an active client, whichever is longer","es":"Hasta 5 years después de la fecha de revocación o después de que el cliente deje de ser un cliente activo, lo que sea más prolongado","ru":"До истечения 5 years после даты отзыва либо после того, как клиент перестал быть активным клиентом, в зависимости от того, какой срок дольше","tr":"İptal tarihinden sonra veya müşterinin aktif müşteri olmaktan çıkmasından sonra 5 years süre dolana kadar; hangisi daha uzunsa","hi":"रद्द होने की तिथि के बाद या ग्राहक के सक्रिय ग्राहक न रहने के बाद, जो भी अधिक लंबा हो, 5 years तक","ar":"حتى مرور 5 years بعد تاريخ الإلغاء أو بعد أن يتوقّف العميل عن كونه عميلاً نشطاً، أيّهما أطول"},{"en":"Indefinitely, because powers of attorney may never be destroyed","es":"Indefinidamente, porque los poderes notariales nunca pueden destruirse","ru":"Бессрочно, поскольку доверенности нельзя уничтожать","tr":"Süresiz olarak, çünkü vekaletnameler asla imha edilemez","hi":"अनिश्चित काल तक, क्योंकि मुख्तारनामे कभी नष्ट नहीं किए जा सकते","ar":"إلى أجل غير مسمّى، لأن التوكيلات لا يجوز إتلافها أبداً"},{"en":"For exactly 3 years after the date of revocation","es":"Durante exactamente 3 years después de la fecha de revocación","ru":"Ровно 3 years после даты отзыва","tr":"İptal tarihinden sonra tam olarak 3 years süreyle","hi":"रद्द होने की तिथि के बाद ठीक 3 years तक","ar":"لمدة 3 years بالضبط بعد تاريخ الإلغاء"},{"en":"Only until the next triennial status report is filed","es":"Solo hasta que se presente el próximo informe de situación trienal","ru":"Только до подачи следующего трехлетнего отчета о состоянии","tr":"Yalnızca bir sonraki üç yıllık durum raporu sunulana kadar","hi":"केवल अगली त्रैवार्षिक स्थिति रिपोर्ट दाखिल होने तक","ar":"فقط حتى تقديم تقرير الحالة التالي الذي يُقدَّم كل ثلاث سنوات"}],"e":{"en":"19 CFR 111.23(b) requires powers of attorney to be retained until revoked, and revoked powers of attorney and related records to be retained for 5 years after the date of revocation or for 5 years after the date the client ceases to be an active client, whichever period is later.","es":"19 CFR 111.23(b) exige que los poderes notariales se conserven hasta su revocación, y que los poderes notariales revocados y los registros relacionados se conserven durante 5 years después de la fecha de revocación o durante 5 years después de la fecha en que el cliente deje de ser un cliente activo, el período que sea posterior.","ru":"19 CFR 111.23(b) требует хранить доверенности до их отзыва, а отозванные доверенности и связанные с ними документы — в течение 5 years после даты отзыва либо в течение 5 years после даты, когда клиент перестал быть активным клиентом, в зависимости от того, какой срок наступит позже.","tr":"19 CFR 111.23(b), vekaletnamelerin iptal edilene kadar saklanmasını, iptal edilen vekaletnamelerin ve ilgili kayıtların ise iptal tarihinden sonra 5 years veya müşterinin aktif müşteri olmaktan çıktığı tarihten sonra 5 years süreyle, hangi süre daha sonraysa o kadar saklanmasını gerektirir.","hi":"19 CFR 111.23(b) के अनुसार मुख्तारनामे को रद्द होने तक रखा जाना चाहिए, और रद्द किए गए मुख्तारनामे तथा संबंधित रिकॉर्ड को रद्द होने की तिथि के बाद 5 years तक या ग्राहक के सक्रिय ग्राहक न रहने की तिथि के बाद 5 years तक, जो भी अवधि बाद में हो, रखा जाना चाहिए।","ar":"تشترط 19 CFR 111.23(b) الاحتفاظ بالتوكيلات حتى إلغائها، والاحتفاظ بالتوكيلات المُلغاة والسجلات المتصلة بها لمدة 5 years بعد تاريخ الإلغاء أو لمدة 5 years بعد التاريخ الذي يتوقّف فيه العميل عن كونه عميلاً نشطاً، أيّ المدّتين أبعد."}},{"cat":"compliance","a":2,"q":{"en":"What is the maximum aggregate monetary penalty that may be imposed on a broker in lieu of suspension or revocation under 19 CFR 111.91?","es":"¿Cuál es la sanción monetaria máxima agregada que puede imponerse a un agente en lugar de la suspensión o revocación conforme al 19 CFR 111.91?","ru":"Каков максимальный совокупный денежный штраф, который может быть наложен на брокера вместо приостановления или аннулирования согласно 19 CFR 111.91?","tr":"19 CFR 111.91 uyarınca askıya alma veya iptal yerine bir müşavire uygulanabilecek azami toplam para cezası nedir?","hi":"19 CFR 111.91 के अंतर्गत निलंबन या निरस्तीकरण के बदले किसी ब्रोकर पर लगाया जा सकने वाला अधिकतम कुल मौद्रिक दंड क्या है?","ar":"ما هو الحد الأقصى لإجمالي الغرامة المالية التي يجوز فرضها على الوسيط بدلاً من التعليق أو الإلغاء بموجب 19 CFR 111.91؟"},"o":[{"en":"$100,000","es":"$100,000","ru":"$100,000","tr":"$100,000","hi":"$100,000","ar":"$100,000"},{"en":"$50,000","es":"$50,000","ru":"$50,000","tr":"$50,000","hi":"$50,000","ar":"$50,000"},{"en":"$30,000","es":"$30,000","ru":"$30,000","tr":"$30,000","hi":"$30,000","ar":"$30,000"},{"en":"$10,000","es":"$10,000","ru":"$10,000","tr":"$10,000","hi":"$10,000","ar":"$10,000"}],"e":{"en":"19 CFR 111.91(a) authorizes a monetary penalty not to exceed an aggregate of $30,000 against a broker for one or more of the grounds set forth in 19 CFR 111.53, imposed in lieu of suspension or revocation.","es":"19 CFR 111.91(a) autoriza una sanción monetaria que no exceda de un total de $30,000 contra un agente por uno o más de los motivos establecidos en 19 CFR 111.53, impuesta en lugar de la suspensión o revocación.","ru":"19 CFR 111.91(a) разрешает наложение на брокера денежного штрафа в совокупности не более $30,000 по одному или нескольким основаниям, изложенным в 19 CFR 111.53, налагаемого вместо приостановления или аннулирования.","tr":"19 CFR 111.91(a), 19 CFR 111.53'te belirtilen bir veya daha fazla gerekçeden dolayı, askıya alma veya iptal yerine bir müşavire toplamda $30,000'ı aşmayan bir para cezası uygulanmasına yetki verir.","hi":"19 CFR 111.91(a) के अनुसार 19 CFR 111.53 में निर्धारित एक या अधिक आधारों के लिए किसी ब्रोकर पर निलंबन या निरस्तीकरण के बदले कुल मिलाकर $30,000 से अधिक न होने वाला मौद्रिक दंड लगाने की अनुमति है।","ar":"تجيز 19 CFR 111.91(a) فرض غرامة مالية لا يتجاوز إجماليها $30,000 على الوسيط بسبب واحد أو أكثر من الأسباب المنصوص عليها في 19 CFR 111.53، تُفرَض بدلاً من التعليق أو الإلغاء."}},{"cat":"compliance","a":0,"q":{"en":"A licensed member or officer who qualifies a broker firm's license leaves the firm. Which statement about the broker's obligation is TRUE under 19 CFR 111.28 and 111.30?","es":"Un miembro o directivo con licencia que califica la licencia de una firma de agentes deja la firma. ¿Cuál afirmación sobre la obligación del agente es VERDADERA conforme al 19 CFR 111.28 y 111.30?","ru":"Лицензированный участник или должностное лицо, обеспечивающее соответствие лицензии брокерской фирмы, покидает фирму. Какое утверждение об обязанности брокера является ВЕРНЫМ согласно 19 CFR 111.28 и 111.30?","tr":"Bir müşavirlik firmasının lisansını niteleyen lisanslı bir üye veya yetkili firmadan ayrılır. 19 CFR 111.28 ve 111.30 uyarınca müşavirin yükümlülüğüne ilişkin aşağıdaki ifadelerden hangisi DOĞRUDUR?","hi":"किसी ब्रोकर फर्म के लाइसेंस को योग्य बनाने वाला लाइसेंसधारी सदस्य या अधिकारी फर्म छोड़ देता है। 19 CFR 111.28 और 111.30 के अंतर्गत ब्रोकर की बाध्यता के संबंध में कौन-सा कथन सत्य है?","ar":"يغادر الفِرمَة عضو أو مسؤول مرخّص يُؤهّل رخصة شركة الوساطة. أيٌّ من العبارات بشأن التزام الوسيط صحيحة بموجب 19 CFR 111.28 و 111.30؟"},"o":[{"en":"The broker must immediately provide written notice to CBP of the termination of the qualifying member or officer","es":"El agente debe notificar de inmediato por escrito a CBP la baja del miembro o directivo que califica la licencia","ru":"Брокер должен немедленно письменно уведомить CBP о прекращении полномочий обеспечивающего соответствие участника или должностного лица","tr":"Müşavir, niteleyen üyenin veya yetkilinin ayrılışını derhal yazılı olarak CBP'ye bildirmelidir","hi":"ब्रोकर को योग्यता प्रदान करने वाले सदस्य या अधिकारी के संबंध समाप्ति की लिखित सूचना तुरंत CBP को देनी होगी","ar":"يجب على الوسيط أن يقدّم فوراً إخطاراً كتابياً إلى CBP بانتهاء علاقة العضو أو المسؤول المُؤهِّل"},{"en":"No notice is required as long as the firm retains any other licensed employee","es":"No se requiere notificación siempre que la firma conserve cualquier otro empleado con licencia","ru":"Уведомление не требуется, пока фирма сохраняет любого другого лицензированного сотрудника","tr":"Firma, lisanslı başka herhangi bir çalışanı elinde tuttuğu sürece bildirim gerekmez","hi":"जब तक फर्म किसी अन्य लाइसेंसधारी कर्मचारी को बनाए रखती है, तब तक कोई सूचना आवश्यक नहीं है","ar":"لا يلزم أي إخطار طالما احتفظت الشركة بأي موظف مرخّص آخر"},{"en":"The broker must wait until the next triennial status report to report the change","es":"El agente debe esperar hasta el próximo informe de situación trienal para informar el cambio","ru":"Брокер должен дождаться следующего трехлетнего отчета о состоянии, чтобы сообщить об изменении","tr":"Müşavir, değişikliği bildirmek için bir sonraki üç yıllık durum raporunu beklemelidir","hi":"ब्रोकर को परिवर्तन की सूचना देने के लिए अगली त्रैवार्षिक स्थिति रिपोर्ट तक प्रतीक्षा करनी होगी","ar":"يجب على الوسيط الانتظار حتى تقرير الحالة التالي الذي يُقدَّم كل ثلاث سنوات للإبلاغ عن التغيير"},{"en":"The broker has 60 calendar days to find a replacement before any notice is required","es":"El agente dispone de 60 calendar days para encontrar un reemplazo antes de que se requiera notificación alguna","ru":"У брокера есть 60 calendar days, чтобы найти замену, прежде чем потребуется какое-либо уведомление","tr":"Müşavirin, herhangi bir bildirim gerekmeden önce bir yedek bulmak için 60 calendar days süresi vardır","hi":"किसी भी सूचना की आवश्यकता से पहले ब्रोकर के पास प्रतिस्थापन खोजने हेतु 60 calendar days हैं","ar":"لدى الوسيط 60 calendar days لإيجاد بديل قبل أن يُطلَب أي إخطار"}],"e":{"en":"19 CFR 111.28(b) and 111.30(b) require a broker to immediately provide written notice to CBP (the Executive Director, Office of Trade) when a licensed member or officer who is qualifying the firm's license terminates that relationship, because continued qualification is required.","es":"19 CFR 111.28(b) y 111.30(b) exigen que un agente notifique de inmediato por escrito a CBP (el Executive Director, Office of Trade) cuando un miembro o directivo con licencia que califica la licencia de la firma termina esa relación, ya que se requiere la calificación continua.","ru":"19 CFR 111.28(b) и 111.30(b) требуют, чтобы брокер немедленно письменно уведомил CBP (the Executive Director, Office of Trade), когда лицензированный участник или должностное лицо, обеспечивающее соответствие лицензии фирмы, прекращает эти отношения, поскольку требуется непрерывное обеспечение соответствия.","tr":"19 CFR 111.28(b) ve 111.30(b), firmanın lisansını niteleyen lisanslı bir üye veya yetkili bu ilişkiyi sona erdirdiğinde, sürekli niteliğin gerekli olması nedeniyle müşavirin derhal CBP'ye (the Executive Director, Office of Trade) yazılı bildirimde bulunmasını gerektirir.","hi":"19 CFR 111.28(b) और 111.30(b) के अनुसार जब फर्म के लाइसेंस को योग्य बनाने वाला कोई लाइसेंसधारी सदस्य या अधिकारी उस संबंध को समाप्त करता है, तो ब्रोकर को तुरंत CBP (the Executive Director, Office of Trade) को लिखित सूचना देनी होगी, क्योंकि निरंतर योग्यता आवश्यक है।","ar":"تشترط 19 CFR 111.28(b) و 111.30(b) أن يقدّم الوسيط فوراً إخطاراً كتابياً إلى CBP (the Executive Director, Office of Trade) عندما يُنهي عضو أو مسؤول مرخّص يُؤهّل رخصة الشركة تلك العلاقة، لأن استمرار التأهيل مطلوب."}},{"cat":"compliance","a":0,"q":{"en":"A licensed broker wishes to continue employing a person who has been convicted of a felony. Which of the following best reflects the broker's obligation under Part 111?","es":"Un agente con licencia desea seguir empleando a una persona que ha sido condenada por un delito grave. ¿Cuál de los siguientes refleja mejor la obligación del agente conforme a la Part 111?","ru":"Лицензированный брокер желает продолжать нанимать лицо, осужденное за тяжкое преступление. Что из перечисленного наилучшим образом отражает обязанность брокера согласно Part 111?","tr":"Lisanslı bir müşavir, ağır bir suçtan mahkûm olmuş bir kişiyi istihdam etmeye devam etmek istemektedir. Aşağıdakilerden hangisi Part 111 uyarınca müşavirin yükümlülüğünü en iyi yansıtır?","hi":"एक लाइसेंसधारी ब्रोकर ऐसे व्यक्ति को नियोजित रखना जारी रखना चाहता है जिसे किसी गंभीर अपराध (फेलनी) के लिए दोषी ठहराया गया है। निम्नलिखित में से कौन-सा Part 111 के अंतर्गत ब्रोकर की बाध्यता को सबसे अच्छी तरह दर्शाता है?","ar":"يرغب وسيط مرخّص في الاستمرار في توظيف شخص أُدين بجناية. أيٌّ ممّا يلي يعكس على أفضل وجه التزام الوسيط بموجب Part 111؟"},"o":[{"en":"The broker may knowingly continue to employ the person only with the written approval of the appropriate Executive Director, Office of Trade","es":"El agente puede seguir empleando a sabiendas a la persona solo con la aprobación por escrito del Executive Director, Office of Trade correspondiente","ru":"Брокер может заведомо продолжать нанимать это лицо только с письменного одобрения соответствующего Executive Director, Office of Trade","tr":"Müşavir, kişiyi bilerek istihdam etmeye yalnızca ilgili Executive Director, Office of Trade'in yazılı onayıyla devam edebilir","hi":"ब्रोकर उस व्यक्ति को जानबूझकर नियोजित रखना केवल संबंधित Executive Director, Office of Trade की लिखित स्वीकृति से ही जारी रख सकता है","ar":"لا يجوز للوسيط أن يستمر عن علم في توظيف الشخص إلا بموافقة كتابية من the appropriate Executive Director, Office of Trade"},{"en":"The broker may continue the employment without restriction since the conviction is the employee's personal matter","es":"El agente puede continuar el empleo sin restricción, ya que la condena es un asunto personal del empleado","ru":"Брокер может продолжать трудовые отношения без ограничений, поскольку осуждение является личным делом сотрудника","tr":"Mahkûmiyet çalışanın kişisel meselesi olduğundan, müşavir istihdamı kısıtlama olmaksızın sürdürebilir","hi":"ब्रोकर बिना किसी प्रतिबंध के रोजगार जारी रख सकता है, क्योंकि दोषसिद्धि कर्मचारी का व्यक्तिगत मामला है","ar":"يجوز للوسيط الاستمرار في التوظيف دون قيد، لأن الإدانة شأن شخصي للموظف"},{"en":"The broker may continue the employment only after the employee passes the broker license examination","es":"El agente puede continuar el empleo solo después de que el empleado apruebe el examen de licencia de agente","ru":"Брокер может продолжать трудовые отношения только после того, как сотрудник сдаст экзамен на лицензию брокера","tr":"Müşavir, istihdama yalnızca çalışan müşavir lisans sınavını geçtikten sonra devam edebilir","hi":"ब्रोकर रोजगार केवल तभी जारी रख सकता है जब कर्मचारी ब्रोकर लाइसेंस परीक्षा उत्तीर्ण कर ले","ar":"لا يجوز للوسيط الاستمرار في التوظيف إلا بعد أن يجتاز الموظف امتحان رخصة الوسيط"},{"en":"The broker must terminate the employee within 5 working days and report the termination to the surety","es":"El agente debe despedir al empleado dentro de 5 working days y notificar el despido a la fiadora","ru":"Брокер должен уволить сотрудника в течение 5 working days и сообщить об увольнении поручителю","tr":"Müşavir, çalışanın işine 5 working days içinde son vermeli ve bu durumu kefile bildirmelidir","hi":"ब्रोकर को कर्मचारी को 5 working days के भीतर हटाना होगा और इस समाप्ति की सूचना प्रतिभू को देनी होगी","ar":"يجب على الوسيط إنهاء خدمة الموظف خلال 5 working days وإبلاغ الضامن بالإنهاء"}],"e":{"en":"19 CFR 111.53(e) makes it a ground for suspension or revocation to knowingly employ, without the written approval of the appropriate Executive Director, Office of Trade, a person who has been convicted of a felony or who has been the subject of an order of revocation/suspension.","es":"19 CFR 111.53(e) establece como motivo de suspensión o revocación el emplear a sabiendas, sin la aprobación por escrito del Executive Director, Office of Trade correspondiente, a una persona que ha sido condenada por un delito grave o que ha sido objeto de una orden de revocación/suspensión.","ru":"19 CFR 111.53(e) делает основанием для приостановления или аннулирования заведомый наем без письменного одобрения соответствующего Executive Director, Office of Trade лица, осужденного за тяжкое преступление или в отношении которого был издан приказ об аннулировании/приостановлении.","tr":"19 CFR 111.53(e), ağır bir suçtan mahkûm olmuş veya hakkında iptal/askıya alma kararı verilmiş bir kişiyi, ilgili Executive Director, Office of Trade'in yazılı onayı olmaksızın bilerek istihdam etmeyi askıya alma veya iptal gerekçesi sayar.","hi":"19 CFR 111.53(e) के अनुसार किसी ऐसे व्यक्ति को, जिसे किसी गंभीर अपराध के लिए दोषी ठहराया गया हो या जो निरस्तीकरण/निलंबन के आदेश का विषय रहा हो, संबंधित Executive Director, Office of Trade की लिखित स्वीकृति के बिना जानबूझकर नियोजित करना निलंबन या निरस्तीकरण का आधार है।","ar":"تجعل 19 CFR 111.53(e) من أسباب التعليق أو الإلغاء أن يُوظَّف عن علم، دون موافقة كتابية من the appropriate Executive Director, Office of Trade، شخص أُدين بجناية أو صدر بحقه أمر بالإلغاء/التعليق."}},{"cat":"compliance","a":3,"q":{"en":"Which of the following best describes a broker's general duty of due diligence under 19 CFR 111.29?","es":"¿Cuál de los siguientes describe mejor el deber general de diligencia debida de un agente conforme al 19 CFR 111.29?","ru":"Что из перечисленного наилучшим образом описывает общую обязанность брокера проявлять должную осмотрительность согласно 19 CFR 111.29?","tr":"Aşağıdakilerden hangisi, 19 CFR 111.29 uyarınca bir müşavirin genel özen yükümlülüğünü en iyi şekilde tanımlar?","hi":"निम्नलिखित में से कौन-सा 19 CFR 111.29 के अंतर्गत किसी ब्रोकर के सम्यक तत्परता (ड्यू डिलिजेंस) के सामान्य कर्तव्य का सबसे अच्छा वर्णन करता है?","ar":"أيٌّ ممّا يلي يصف على أفضل وجه واجب الوسيط العام في بذل العناية الواجبة بموجب 19 CFR 111.29؟"},"o":[{"en":"A broker must keep records only at the office of record","es":"Un agente debe mantener los registros únicamente en la oficina de registro","ru":"Брокер должен хранить документы только в официальном офисе","tr":"Bir müşavir, kayıtları yalnızca kayıtlı ofiste tutmalıdır","hi":"किसी ब्रोकर को रिकॉर्ड केवल रिकॉर्ड कार्यालय में रखने होंगे","ar":"يجب على الوسيط الاحتفاظ بالسجلات في المكتب الرسمي فقط"},{"en":"A broker must collect the proper fees before any merchandise may be imported","es":"Un agente debe cobrar las tarifas correspondientes antes de que pueda importarse cualquier mercancía","ru":"Брокер должен взимать надлежащие сборы до того, как любой товар может быть импортирован","tr":"Bir müşavir, herhangi bir mal ithal edilebilmesinden önce gereken ücretleri tahsil etmelidir","hi":"किसी ब्रोकर को किसी भी माल के आयात से पहले उचित शुल्क वसूलने होंगे","ar":"يجب على الوسيط تحصيل الرسوم المناسبة قبل أن يُسمَح باستيراد أي بضاعة"},{"en":"Client information is strictly confidential and may never be shared","es":"La información del cliente es estrictamente confidencial y nunca puede compartirse","ru":"Информация клиента строго конфиденциальна и никогда не может быть передана","tr":"Müşteri bilgileri kesinlikle gizlidir ve asla paylaşılamaz","hi":"ग्राहक की जानकारी पूर्णतः गोपनीय है और कभी साझा नहीं की जा सकती","ar":"معلومات العميل سرية تماماً ولا يجوز مشاركتها أبداً"},{"en":"A broker must exercise due diligence in making financial settlements, answering correspondence, and preparing or filing records relating to any customs business handled as a broker","es":"Un agente debe ejercer diligencia debida al realizar liquidaciones financieras, responder correspondencia y preparar o presentar registros relacionados con cualquier actividad aduanera gestionada como agente","ru":"Брокер должен проявлять должную осмотрительность при проведении финансовых расчетов, ответе на корреспонденцию и подготовке или подаче документов, относящихся к любой таможенной деятельности, осуществляемой в качестве брокера","tr":"Bir müşavir, mali ödemeleri yaparken, yazışmalara yanıt verirken ve müşavir olarak yürütülen herhangi bir gümrük işiyle ilgili kayıtları hazırlarken veya sunarken gereken özeni göstermelidir","hi":"किसी ब्रोकर को वित्तीय निपटान करने, पत्राचार का उत्तर देने और ब्रोकर के रूप में संभाले गए किसी भी सीमा शुल्क व्यवसाय से संबंधित रिकॉर्ड तैयार करने या दाखिल करने में सम्यक तत्परता बरतनी होगी","ar":"يجب على الوسيط بذل العناية الواجبة عند إجراء التسويات المالية والرد على المراسلات وإعداد أو تقديم السجلات المتعلقة بأي عمل جمركي يتولّاه بصفته وسيطاً"}],"e":{"en":"19 CFR 111.29(a) imposes the general duty of due diligence: a broker must exercise due diligence in making financial settlements, in answering correspondence, and in preparing or assisting in the preparation and filing of records relating to any customs business matter handled as a broker.","es":"19 CFR 111.29(a) impone el deber general de diligencia debida: un agente debe ejercer diligencia debida al realizar liquidaciones financieras, al responder correspondencia y al preparar o ayudar en la preparación y presentación de registros relacionados con cualquier asunto de actividad aduanera gestionado como agente.","ru":"19 CFR 111.29(a) устанавливает общую обязанность проявлять должную осмотрительность: брокер должен проявлять должную осмотрительность при проведении финансовых расчетов, ответе на корреспонденцию, а также при подготовке или содействии в подготовке и подаче документов, относящихся к любому вопросу таможенной деятельности, осуществляемой в качестве брокера.","tr":"19 CFR 111.29(a), genel özen yükümlülüğünü getirir: bir müşavir, mali ödemeleri yaparken, yazışmalara yanıt verirken ve müşavir olarak yürütülen herhangi bir gümrük işi konusuyla ilgili kayıtların hazırlanmasında ve sunulmasında hazırlık yaparken veya yardımcı olurken gereken özeni göstermelidir.","hi":"19 CFR 111.29(a) सम्यक तत्परता का सामान्य कर्तव्य आरोपित करता है: किसी ब्रोकर को वित्तीय निपटान करने, पत्राचार का उत्तर देने तथा ब्रोकर के रूप में संभाले गए किसी भी सीमा शुल्क व्यवसाय मामले से संबंधित रिकॉर्ड तैयार करने या उनकी तैयारी और दाखिल करने में सहायता करने में सम्यक तत्परता बरतनी होगी।","ar":"تفرض 19 CFR 111.29(a) واجب العناية الواجبة العام: يجب على الوسيط بذل العناية الواجبة عند إجراء التسويات المالية والرد على المراسلات وإعداد السجلات أو المساعدة في إعدادها وتقديمها فيما يتعلق بأي مسألة عمل جمركي يتولّاها بصفته وسيطاً."}},{"cat":"compliance","a":0,"q":{"en":"Which of the following accurately reflects requirements under the modernized 19 CFR Part 111?","es":"¿Cuál de los siguientes refleja con precisión los requisitos conforme al 19 CFR Part 111 modernizado?","ru":"Что из перечисленного точно отражает требования модернизированного 19 CFR Part 111?","tr":"Aşağıdakilerden hangisi, modernize edilmiş 19 CFR Part 111 kapsamındaki gereklilikleri doğru şekilde yansıtır?","hi":"निम्नलिखित में से कौन-सा आधुनिकीकृत 19 CFR Part 111 के अंतर्गत आवश्यकताओं को सटीक रूप से दर्शाता है?","ar":"أيٌّ ممّا يلي يعكس بدقّة المتطلبات بموجب 19 CFR Part 111 المُحدَّثة؟"},"o":[{"en":"A single national permit governs customs business nationwide and the triennial status report fee is $100","es":"Un único permiso nacional rige las actividades aduaneras en todo el país y la tarifa del informe de situación trienal es de $100","ru":"Единое национальное разрешение регулирует таможенную деятельность по всей стране, а сбор за трехлетний отчет о состоянии составляет $100","tr":"Tek bir ulusal izin, ülke genelinde gümrük işini düzenler ve üç yıllık durum raporu ücreti $100'dür","hi":"एक एकल राष्ट्रीय परमिट देशभर में सीमा शुल्क व्यवसाय को नियंत्रित करता है और त्रैवार्षिक स्थिति रिपोर्ट शुल्क $100 है","ar":"تصريح وطني واحد يحكم الأعمال الجمركية على مستوى البلاد، ورسوم تقرير الحالة الذي يُقدَّم كل ثلاث سنوات هي $100"},{"en":"Continuing education applies to all corporate and individual license holders equally","es":"La educación continua se aplica por igual a todos los titulares de licencia corporativos e individuales","ru":"Непрерывное образование применяется одинаково ко всем корпоративным и индивидуальным держателям лицензий","tr":"Sürekli eğitim, tüm kurumsal ve bireysel lisans sahiplerine eşit şekilde uygulanır","hi":"निरंतर शिक्षा सभी कॉर्पोरेट और व्यक्तिगत लाइसेंसधारकों पर समान रूप से लागू होती है","ar":"ينطبق التعليم المستمر على جميع حاملي رخص الشركات والأفراد على حدّ سواء"},{"en":"The recordkeeping retention period is 3 years from the date the entry summary is filed","es":"El período de conservación de registros es de 3 years a partir de la fecha en que se presenta el resumen de entrada","ru":"Срок хранения документов составляет 3 years с даты подачи итоговой декларации (entry summary)","tr":"Kayıt saklama süresi, giriş özetinin sunulduğu tarihten itibaren 3 years'dır","hi":"रिकॉर्ड रखने की संरक्षण अवधि एंट्री सारांश दाखिल करने की तिथि से 3 years है","ar":"فترة الاحتفاظ بالسجلات هي 3 years من تاريخ تقديم ملخّص الإدخال"},{"en":"Brokers must obtain a separate district permit for each port and pay an annual district permit fee","es":"Los agentes deben obtener un permiso de distrito separado para cada puerto y pagar una tarifa anual de permiso de distrito","ru":"Брокеры должны получать отдельное окружное разрешение для каждого порта и уплачивать ежегодный сбор за окружное разрешение","tr":"Müşavirler her liman için ayrı bir bölge izni almalı ve yıllık bölge izni ücreti ödemelidir","hi":"ब्रोकरों को प्रत्येक बंदरगाह के लिए एक अलग जिला परमिट प्राप्त करना होगा और वार्षिक जिला परमिट शुल्क देना होगा","ar":"يجب على الوسطاء الحصول على تصريح إقليمي منفصل لكل ميناء ودفع رسوم تصريح إقليمي سنوية"}],"e":{"en":"Under the modernized regulations, district permits were eliminated in favor of a single national permit (19 CFR 111.19), the triennial status report fee is $100 (19 CFR 111.96(d)), continuing education applies only to individual brokers (Subpart F), and records are retained 5 years from the date of entry (19 CFR 111.23).","es":"Conforme a los reglamentos modernizados, se eliminaron los permisos de distrito en favor de un único permiso nacional (19 CFR 111.19), la tarifa del informe de situación trienal es de $100 (19 CFR 111.96(d)), la educación continua se aplica solo a los agentes individuales (Subpart F) y los registros se conservan 5 years a partir de la fecha de entrada (19 CFR 111.23).","ru":"Согласно модернизированным нормам, окружные разрешения были упразднены в пользу единого национального разрешения (19 CFR 111.19), сбор за трехлетний отчет о состоянии составляет $100 (19 CFR 111.96(d)), непрерывное образование применяется только к индивидуальным брокерам (Subpart F), а документы хранятся 5 years с даты ввоза (19 CFR 111.23).","tr":"Modernize edilmiş düzenlemeler uyarınca, bölge izinleri kaldırılarak tek bir ulusal izin getirilmiş (19 CFR 111.19), üç yıllık durum raporu ücreti $100'dür (19 CFR 111.96(d)), sürekli eğitim yalnızca bireysel müşavirlere uygulanır (Subpart F) ve kayıtlar giriş tarihinden itibaren 5 years saklanır (19 CFR 111.23).","hi":"आधुनिकीकृत विनियमों के अंतर्गत जिला परमिट समाप्त कर एक एकल राष्ट्रीय परमिट (19 CFR 111.19) लाया गया, त्रैवार्षिक स्थिति रिपोर्ट शुल्क $100 है (19 CFR 111.96(d)), निरंतर शिक्षा केवल व्यक्तिगत ब्रोकरों पर लागू होती है (Subpart F), और रिकॉर्ड को प्रवेश की तिथि से 5 years तक रखा जाता है (19 CFR 111.23)।","ar":"بموجب اللوائح المُحدَّثة، أُلغيت التصاريح الإقليمية لصالح تصريح وطني واحد (19 CFR 111.19)، ورسوم تقرير الحالة الذي يُقدَّم كل ثلاث سنوات هي $100 (19 CFR 111.96(d))، وينطبق التعليم المستمر على وسطاء الأفراد فقط (Subpart F)، وتُحفَظ السجلات لمدة 5 years من تاريخ الإدخال (19 CFR 111.23)."}},{"cat":"trade","a":2,"q":{"en":"Under 19 CFR Part 134, in what language must an article's country of origin marking generally appear?","es":"Conforme a 19 CFR Part 134, ¿en qué idioma debe aparecer generalmente el marcado del país de origen de un artículo?","ru":"Согласно 19 CFR Part 134, на каком языке, как правило, должна указываться маркировка страны происхождения изделия?","tr":"19 CFR Part 134 uyarınca, bir eşyanın menşe ülke işareti genel olarak hangi dilde görünmelidir?","hi":"19 CFR Part 134 के तहत, किसी वस्तु के मूल देश का अंकन आमतौर पर किस भाषा में दिखाई देना चाहिए?","ar":"بموجب 19 CFR Part 134، بأي لغة يجب أن تظهر علامة بلد منشأ السلعة بوجه عام؟"},"o":[{"en":"The language of the country of origin","es":"El idioma del país de origen","ru":"Язык страны происхождения","tr":"Menşe ülkenin dili","hi":"मूल देश की भाषा","ar":"لغة بلد المنشأ"},{"en":"The importer's choice of language","es":"El idioma que elija el importador","ru":"Язык по выбору импортёра","tr":"İthalatçının seçtiği dil","hi":"आयातक की पसंद की भाषा","ar":"اللغة التي يختارها المستورد"},{"en":"English","es":"Inglés","ru":"Английский","tr":"İngilizce","hi":"अंग्रेज़ी","ar":"الإنجليزية"},{"en":"French","es":"Francés","ru":"Французский","tr":"Fransızca","hi":"फ्रेंच","ar":"الفرنسية"}],"e":{"en":"19 CFR 134.11 and 19 USC 1304 require that every imported article of foreign origin be marked legibly, conspicuously, and permanently in English to indicate the country of origin to the ultimate purchaser.","es":"19 CFR 134.11 y 19 USC 1304 exigen que todo artículo importado de origen extranjero esté marcado de forma legible, visible y permanente en inglés para indicar el país de origen al comprador final.","ru":"19 CFR 134.11 и 19 USC 1304 требуют, чтобы каждое импортируемое изделие иностранного происхождения было промаркировано разборчиво, заметно и стойко на английском языке для указания страны происхождения конечному покупателю.","tr":"19 CFR 134.11 ve 19 USC 1304, yabancı menşeli her ithal eşyanın menşe ülkesini nihai alıcıya göstermek üzere İngilizce olarak okunaklı, göze çarpar ve kalıcı şekilde işaretlenmesini gerektirir.","hi":"19 CFR 134.11 और 19 USC 1304 के अनुसार विदेशी मूल की प्रत्येक आयातित वस्तु पर अंतिम खरीदार को मूल देश दर्शाने के लिए अंग्रेज़ी में सुपाठ्य, स्पष्ट और स्थायी रूप से अंकन आवश्यक है।","ar":"تشترط 19 CFR 134.11 و19 USC 1304 أن تُعلَّم كل سلعة مستوردة ذات منشأ أجنبي بوضوح وبشكل بارز ودائم باللغة الإنجليزية لبيان بلد المنشأ للمشتري النهائي."}},{"cat":"trade","a":2,"q":{"en":"What is the standard rate of marking duty assessed when an article is not properly marked with its country of origin and is not exported, destroyed, or properly marked under CBP supervision?","es":"¿Cuál es la tasa estándar del arancel por marcado que se aplica cuando un artículo no está correctamente marcado con su país de origen y no se exporta, destruye ni se marca correctamente bajo supervisión de CBP?","ru":"Какова стандартная ставка пошлины за маркировку, начисляемой, когда изделие не имеет надлежащей маркировки страны происхождения и не экспортируется, не уничтожается и не маркируется надлежащим образом под надзором CBP?","tr":"Bir eşya menşe ülkesiyle düzgün şekilde işaretlenmediğinde ve CBP gözetiminde ihraç edilmediğinde, imha edilmediğinde veya düzgün şekilde işaretlenmediğinde uygulanan standart işaretleme vergisi oranı nedir?","hi":"जब किसी वस्तु पर उसके मूल देश का सही अंकन नहीं होता और उसे CBP की निगरानी में निर्यात, नष्ट या सही ढंग से अंकित नहीं किया जाता, तो अंकन शुल्क की मानक दर क्या होती है?","ar":"ما هو المعدل القياسي لرسم العلامة الذي يُفرض عندما لا تُعلَّم السلعة ببلد منشئها بشكل صحيح ولا تُصدَّر أو تُتلَف أو تُعلَّم بشكل صحيح تحت إشراف CBP؟"},"o":[{"en":"15 percent ad valorem","es":"15 percent ad valorem","ru":"15 percent ad valorem","tr":"15 percent ad valorem","hi":"15 percent ad valorem","ar":"15 percent ad valorem"},{"en":"25 percent ad valorem","es":"25 percent ad valorem","ru":"25 percent ad valorem","tr":"25 percent ad valorem","hi":"25 percent ad valorem","ar":"25 percent ad valorem"},{"en":"10 percent ad valorem","es":"10 percent ad valorem","ru":"10 percent ad valorem","tr":"10 percent ad valorem","hi":"10 percent ad valorem","ar":"10 percent ad valorem"},{"en":"5 percent ad valorem","es":"5 percent ad valorem","ru":"5 percent ad valorem","tr":"5 percent ad valorem","hi":"5 percent ad valorem","ar":"5 percent ad valorem"}],"e":{"en":"Under 19 USC 1304(i) and 19 CFR 134.2, a marking duty of 10 percent ad valorem applies to articles not properly marked and not exported, destroyed, or marked under CBP supervision before liquidation.","es":"Conforme a 19 USC 1304(i) y 19 CFR 134.2, se aplica un arancel por marcado del 10 percent ad valorem a los artículos que no estén correctamente marcados y que no se exporten, destruyan ni marquen bajo supervisión de CBP antes de la liquidación.","ru":"Согласно 19 USC 1304(i) и 19 CFR 134.2, пошлина за маркировку в размере 10 percent ad valorem применяется к изделиям, не имеющим надлежащей маркировки и не экспортированным, не уничтоженным и не промаркированным под надзором CBP до ликвидации (окончательного расчёта пошлин).","tr":"19 USC 1304(i) ve 19 CFR 134.2 uyarınca, düzgün şekilde işaretlenmemiş ve tasfiye öncesinde CBP gözetiminde ihraç edilmemiş, imha edilmemiş veya işaretlenmemiş eşyalara 10 percent ad valorem oranında işaretleme vergisi uygulanır.","hi":"19 USC 1304(i) और 19 CFR 134.2 के तहत, उन वस्तुओं पर 10 percent ad valorem की अंकन शुल्क लागू होती है जो सही ढंग से अंकित नहीं हैं और निपटान (liquidation) से पहले CBP की निगरानी में निर्यात, नष्ट या अंकित नहीं की गईं।","ar":"بموجب 19 USC 1304(i) و19 CFR 134.2، يُفرض رسم علامة قدره 10 percent ad valorem على السلع التي لا تُعلَّم بشكل صحيح ولا تُصدَّر أو تُتلَف أو تُعلَّم تحت إشراف CBP قبل التصفية."}},{"cat":"trade","a":1,"q":{"en":"The trade agreement that replaced NAFTA effective July 1, 2020 is the:","es":"El acuerdo comercial que reemplazó al NAFTA con vigencia desde July 1, 2020 es el:","ru":"Торговое соглашение, заменившее NAFTA с July 1, 2020, — это:","tr":"July 1, 2020 itibarıyla NAFTA'nın yerini alan ticaret anlaşması şudur:","hi":"July 1, 2020 से प्रभावी NAFTA की जगह लेने वाला व्यापार समझौता है:","ar":"الاتفاقية التجارية التي حلّت محل NAFTA اعتبارًا من July 1, 2020 هي:"},"o":[{"en":"Caribbean Basin Initiative (CBI)","es":"Iniciativa de la Cuenca del Caribe (CBI)","ru":"Инициатива стран Карибского бассейна (CBI)","tr":"Karayip Havzası Girişimi (CBI)","hi":"कैरिबियन बेसिन इनिशिएटिव (CBI)","ar":"مبادرة حوض الكاريبي (CBI)"},{"en":"United States-Mexico-Canada Agreement (USMCA)","es":"Acuerdo Estados Unidos-México-Canadá (USMCA)","ru":"Соглашение между США, Мексикой и Канадой (USMCA)","tr":"Amerika Birleşik Devletleri-Meksika-Kanada Anlaşması (USMCA)","hi":"संयुक्त राज्य अमेरिका-मेक्सिको-कनाडा समझौता (USMCA)","ar":"اتفاقية الولايات المتحدة والمكسيك وكندا (USMCA)"},{"en":"Trans-Pacific Partnership (TPP)","es":"Acuerdo Transpacífico (TPP)","ru":"Транстихоокеанское партнёрство (TPP)","tr":"Trans-Pasifik Ortaklığı (TPP)","hi":"ट्रांस-पैसिफिक पार्टनरशिप (TPP)","ar":"الشراكة عبر المحيط الهادئ (TPP)"},{"en":"U.S.-Central America Free Trade Agreement (CAFTA-DR)","es":"Tratado de Libre Comercio EE. UU.-Centroamérica (CAFTA-DR)","ru":"Соглашение о свободной торговле между США и Центральной Америкой (CAFTA-DR)","tr":"ABD-Orta Amerika Serbest Ticaret Anlaşması (CAFTA-DR)","hi":"अमेरिका-मध्य अमेरिका मुक्त व्यापार समझौता (CAFTA-DR)","ar":"اتفاقية التجارة الحرة بين الولايات المتحدة وأمريكا الوسطى (CAFTA-DR)"}],"e":{"en":"NAFTA terminated June 30, 2020, and the USMCA entered into force July 1, 2020. CBP's implementing regulations are codified at 19 CFR Part 182.","es":"El NAFTA terminó el June 30, 2020, y el USMCA entró en vigor el July 1, 2020. Las regulaciones de implementación de CBP están codificadas en 19 CFR Part 182.","ru":"NAFTA прекратило действие June 30, 2020, а USMCA вступило в силу July 1, 2020. Имплементационные нормы CBP кодифицированы в 19 CFR Part 182.","tr":"NAFTA June 30, 2020 tarihinde sona ermiş ve USMCA July 1, 2020 tarihinde yürürlüğe girmiştir. CBP'nin uygulama düzenlemeleri 19 CFR Part 182'de düzenlenmiştir.","hi":"NAFTA June 30, 2020 को समाप्त हुआ, और USMCA July 1, 2020 को लागू हुआ। CBP के कार्यान्वयन विनियम 19 CFR Part 182 में संहिताबद्ध हैं।","ar":"انتهى NAFTA في June 30, 2020، ودخلت USMCA حيز التنفيذ في July 1, 2020. وُدوِّنت لوائح التنفيذ الخاصة بـ CBP في 19 CFR Part 182."}},{"cat":"trade","a":1,"q":{"en":"Which HTSUS provision generally permits products of the United States to be returned duty-free without having been advanced in value or improved in condition while abroad?","es":"¿Qué disposición del HTSUS generalmente permite que los productos de los Estados Unidos sean retornados libres de aranceles sin haber sido aumentados en valor ni mejorados en su condición mientras estuvieron en el extranjero?","ru":"Какое положение HTSUS, как правило, разрешает возвращать товары производства США беспошлинно при условии, что за рубежом их стоимость не была увеличена, а состояние не было улучшено?","tr":"Hangi HTSUS hükmü, ABD ürünlerinin yurt dışındayken değerinin artırılmamış veya durumunun iyileştirilmemiş olması koşuluyla gümrük vergisinden muaf olarak geri getirilmesine genel olarak izin verir?","hi":"कौन सा HTSUS प्रावधान आमतौर पर संयुक्त राज्य अमेरिका के उत्पादों को बिना शुल्क के वापस लाने की अनुमति देता है, बशर्ते वे विदेश में रहते हुए मूल्य में न बढ़े हों या स्थिति में सुधार न हुआ हो?","ar":"أي حكم من أحكام HTSUS يسمح عمومًا بإعادة منتجات الولايات المتحدة معفاة من الرسوم دون أن تكون قد زادت قيمتها أو تحسّنت حالتها أثناء وجودها في الخارج؟"},"o":[{"en":"Subheading 9802.00.50","es":"Subpartida 9802.00.50","ru":"Субпозиция 9802.00.50","tr":"9802.00.50 alt pozisyonu","hi":"उपशीर्षक 9802.00.50","ar":"البند الفرعي 9802.00.50"},{"en":"Subheading 9801.00.10","es":"Subpartida 9801.00.10","ru":"Субпозиция 9801.00.10","tr":"9801.00.10 alt pozisyonu","hi":"उपशीर्षक 9801.00.10","ar":"البند الفرعي 9801.00.10"},{"en":"Subheading 9813.00.05","es":"Subpartida 9813.00.05","ru":"Субпозиция 9813.00.05","tr":"9813.00.05 alt pozisyonu","hi":"उपशीर्षक 9813.00.05","ar":"البند الفرعي 9813.00.05"},{"en":"Subheading 9802.00.80","es":"Subpartida 9802.00.80","ru":"Субпозиция 9802.00.80","tr":"9802.00.80 alt pozisyonu","hi":"उपशीर्षक 9802.00.80","ar":"البند الفرعي 9802.00.80"}],"e":{"en":"HTSUS 9801.00.10 covers U.S. goods returned (and certain foreign goods returned within 3 years) that were not advanced in value or improved in condition abroad, allowing duty-free treatment. The other cited subheadings address repairs/alterations, assembly, or temporary importation.","es":"HTSUS 9801.00.10 abarca mercancías estadounidenses retornadas (y ciertas mercancías extranjeras retornadas dentro de 3 años) que no fueron aumentadas en valor ni mejoradas en su condición en el extranjero, permitiendo el tratamiento libre de aranceles. Las demás subpartidas citadas se refieren a reparaciones/alteraciones, ensamblaje o importación temporal.","ru":"HTSUS 9801.00.10 распространяется на возвращаемые товары США (и некоторые иностранные товары, возвращаемые в течение 3 years), стоимость которых за рубежом не была увеличена, а состояние не было улучшено, что допускает беспошлинный режим. Остальные указанные субпозиции касаются ремонта/изменений, сборки или временного ввоза.","tr":"HTSUS 9801.00.10, yurt dışında değeri artırılmamış veya durumu iyileştirilmemiş, geri getirilen ABD eşyalarını (ve 3 years içinde geri getirilen belirli yabancı eşyaları) kapsar ve gümrük vergisinden muafiyet sağlar. Atıf yapılan diğer alt pozisyonlar onarım/değişiklik, montaj veya geçici ithalat ile ilgilidir.","hi":"HTSUS 9801.00.10 उन वापस लाई गई अमेरिकी वस्तुओं (और कुछ विदेशी वस्तुओं को जो 3 years के भीतर वापस लाई गई हों) को शामिल करता है जिनका मूल्य विदेश में न बढ़ा हो और न ही स्थिति में सुधार हुआ हो, जिससे शुल्क-मुक्त उपचार की अनुमति मिलती है। उद्धृत अन्य उपशीर्षक मरम्मत/परिवर्तन, असेंबली, या अस्थायी आयात से संबंधित हैं।","ar":"يغطي HTSUS 9801.00.10 السلع الأمريكية المعادة (وبعض السلع الأجنبية المعادة خلال 3 years) التي لم تَزِد قيمتها أو تتحسّن حالتها في الخارج، مما يتيح معاملتها معفاة من الرسوم. أما البنود الفرعية الأخرى المذكورة فتتعلق بالإصلاحات/التعديلات أو التجميع أو الاستيراد المؤقت."}},{"cat":"trade","a":2,"q":{"en":"Customs bonds and their conditions are governed primarily by which part of 19 CFR?","es":"Las fianzas aduaneras y sus condiciones se rigen principalmente por ¿cuál parte de 19 CFR?","ru":"Таможенные гарантии (бонды) и их условия регулируются главным образом какой частью 19 CFR?","tr":"Gümrük kefaletleri ve bunların şartları esas olarak 19 CFR'nin hangi bölümüyle düzenlenir?","hi":"सीमा शुल्क बॉन्ड और उनकी शर्तें मुख्य रूप से 19 CFR के किस भाग द्वारा शासित होती हैं?","ar":"تخضع كفالات الجمارك وشروطها في المقام الأول لأي جزء من 19 CFR؟"},"o":[{"en":"Part 146","es":"Part 146","ru":"Part 146","tr":"Part 146","hi":"Part 146","ar":"Part 146"},{"en":"Part 19","es":"Part 19","ru":"Part 19","tr":"Part 19","hi":"Part 19","ar":"Part 19"},{"en":"Part 113","es":"Part 113","ru":"Part 113","tr":"Part 113","hi":"Part 113","ar":"Part 113"},{"en":"Part 132","es":"Part 132","ru":"Part 132","tr":"Part 132","hi":"Part 132","ar":"Part 132"}],"e":{"en":"19 CFR Part 113 governs CBP bonds, including bond conditions in Subpart G. Part 19 covers bonded warehouses, Part 132 covers quotas, and Part 146 covers foreign trade zones.","es":"19 CFR Part 113 rige las fianzas de CBP, incluidas las condiciones de las fianzas en el Subpart G. Part 19 abarca los depósitos aduaneros, Part 132 abarca las cuotas, y Part 146 abarca las zonas de comercio exterior.","ru":"19 CFR Part 113 регулирует гарантии CBP, включая условия гарантий в Subpart G. Part 19 охватывает таможенные склады, Part 132 — квоты, а Part 146 — зоны внешней торговли.","tr":"19 CFR Part 113, Subpart G'deki kefalet şartları dahil olmak üzere CBP kefaletlerini düzenler. Part 19 antrepoları, Part 132 kotaları ve Part 146 serbest ticaret bölgelerini kapsar.","hi":"19 CFR Part 113 CBP बॉन्ड को शासित करता है, जिसमें Subpart G में बॉन्ड की शर्तें शामिल हैं। Part 19 बॉन्डेड गोदामों को, Part 132 कोटा को, और Part 146 विदेशी व्यापार क्षेत्रों को कवर करता है।","ar":"ينظّم 19 CFR Part 113 كفالات CBP، بما في ذلك شروط الكفالة الواردة في Subpart G. ويغطي Part 19 المستودعات الجمركية، ويغطي Part 132 الحصص، ويغطي Part 146 مناطق التجارة الأجنبية."}},{"cat":"trade","a":0,"q":{"en":"On a CBP bond, the activity code that corresponds to the basic importation and entry bond is:","es":"En una fianza de CBP, el código de actividad que corresponde a la fianza básica de importación y entrada es:","ru":"В гарантии CBP кодом деятельности, соответствующим базовой гарантии импорта и ввоза (entry), является:","tr":"Bir CBP kefaletinde, temel ithalat ve giriş (entry) kefaletine karşılık gelen faaliyet kodu şudur:","hi":"किसी CBP बॉन्ड पर, बुनियादी आयात और एंट्री बॉन्ड के अनुरूप गतिविधि कोड है:","ar":"في كفالة CBP، رمز النشاط المقابل لكفالة الاستيراد والإدخال الأساسية هو:"},"o":[{"en":"Activity Code 1","es":"Activity Code 1","ru":"Activity Code 1","tr":"Activity Code 1","hi":"Activity Code 1","ar":"Activity Code 1"},{"en":"Activity Code 3","es":"Activity Code 3","ru":"Activity Code 3","tr":"Activity Code 3","hi":"Activity Code 3","ar":"Activity Code 3"},{"en":"Activity Code 4","es":"Activity Code 4","ru":"Activity Code 4","tr":"Activity Code 4","hi":"Activity Code 4","ar":"Activity Code 4"},{"en":"Activity Code 2","es":"Activity Code 2","ru":"Activity Code 2","tr":"Activity Code 2","hi":"Activity Code 2","ar":"Activity Code 2"}],"e":{"en":"Under 19 CFR Part 113, Activity Code 1 is the Importer or Broker (basic importation and entry) bond. Activity Code 2 is custodian of bonded merchandise, Code 3 is international carrier, and Code 4 is foreign trade zone operator.","es":"Conforme a 19 CFR Part 113, Activity Code 1 es la fianza de Importador o Agente (importación y entrada básica). Activity Code 2 es el custodio de mercancía afianzada, Code 3 es el transportista internacional, y Code 4 es el operador de zona de comercio exterior.","ru":"Согласно 19 CFR Part 113, Activity Code 1 — это гарантия импортёра или брокера (базовый импорт и ввоз). Activity Code 2 — хранитель товаров под гарантией (bonded), Code 3 — международный перевозчик, а Code 4 — оператор зоны внешней торговли.","tr":"19 CFR Part 113 uyarınca, Activity Code 1 İthalatçı veya Aracı (temel ithalat ve giriş) kefaletidir. Activity Code 2 antrepo eşyasının emanetçisi, Code 3 uluslararası taşıyıcı ve Code 4 serbest ticaret bölgesi işletmecisidir.","hi":"19 CFR Part 113 के तहत, Activity Code 1 आयातक या ब्रोकर (बुनियादी आयात और एंट्री) बॉन्ड है। Activity Code 2 बॉन्डेड माल का संरक्षक है, Code 3 अंतरराष्ट्रीय वाहक है, और Code 4 विदेशी व्यापार क्षेत्र संचालक है।","ar":"بموجب 19 CFR Part 113، فإن Activity Code 1 هو كفالة المستورد أو الوسيط (الاستيراد والإدخال الأساسي). و Activity Code 2 هو حافظ البضائع المكفولة، و Code 3 هو الناقل الدولي، و Code 4 هو مشغّل منطقة التجارة الأجنبية."}},{"cat":"trade","a":1,"q":{"en":"What is the current legal status of the Generalized System of Preferences (GSP) program as of 2026?","es":"¿Cuál es el estatus legal actual del programa Sistema Generalizado de Preferencias (GSP) a partir de 2026?","ru":"Каков текущий правовой статус программы Общей системы преференций (GSP) по состоянию на 2026 год?","tr":"2026 itibarıyla Genelleştirilmiş Tercihler Sistemi (GSP) programının mevcut hukuki durumu nedir?","hi":"2026 तक सामान्यीकृत वरीयता प्रणाली (GSP) कार्यक्रम की वर्तमान कानूनी स्थिति क्या है?","ar":"ما هو الوضع القانوني الحالي لبرنامج نظام الأفضليات المعمم (GSP) اعتبارًا من 2026؟"},"o":[{"en":"Permanently repealed by the USMCA","es":"Derogado permanentemente por el USMCA","ru":"Окончательно отменён в рамках USMCA","tr":"USMCA tarafından kalıcı olarak yürürlükten kaldırılmış","hi":"USMCA द्वारा स्थायी रूप से निरस्त","ar":"أُلغي بشكل دائم بموجب USMCA"},{"en":"Lapsed since December 31, 2020 and awaiting congressional renewal","es":"Caducado desde December 31, 2020 y a la espera de renovación por el Congreso","ru":"Истёк с December 31, 2020 и ожидает продления Конгрессом","tr":"December 31, 2020 tarihinden bu yana yürürlükten kalkmış ve Kongre tarafından yenilenmeyi beklemekte","hi":"December 31, 2020 से समाप्त और कांग्रेस द्वारा नवीनीकरण की प्रतीक्षा में","ar":"منتهٍ منذ December 31, 2020 وفي انتظار تجديده من الكونغرس"},{"en":"In effect but limited only to least-developed beneficiary countries","es":"En vigor pero limitado solo a los países beneficiarios menos desarrollados","ru":"Действует, но ограничен только наименее развитыми странами-бенефициарами","tr":"Yürürlükte ancak yalnızca en az gelişmiş yararlanıcı ülkelerle sınırlı","hi":"प्रभावी, लेकिन केवल सबसे कम विकसित लाभार्थी देशों तक सीमित","ar":"ساري المفعول لكنه يقتصر فقط على البلدان المستفيدة الأقل نموًا"},{"en":"In effect with no expiration date","es":"En vigor sin fecha de expiración","ru":"Действует без даты истечения срока","tr":"Sona erme tarihi olmaksızın yürürlükte","hi":"बिना किसी समाप्ति तिथि के प्रभावी","ar":"ساري المفعول دون تاريخ انتهاء"}],"e":{"en":"GSP authorization (19 USC 2461 et seq.) expired December 31, 2020, and has not been reauthorized as of 2026; claims may be filed but duty-free GSP treatment is not currently being granted pending renewal legislation.","es":"La autorización del GSP (19 USC 2461 et seq.) expiró el December 31, 2020 y no ha sido reautorizada a partir de 2026; pueden presentarse reclamaciones, pero actualmente no se otorga el tratamiento libre de aranceles del GSP a la espera de la legislación de renovación.","ru":"Полномочия GSP (19 USC 2461 et seq.) истекли December 31, 2020 и не были возобновлены по состоянию на 2026 год; заявления могут подаваться, но беспошлинный режим GSP в настоящее время не предоставляется в ожидании закона о продлении.","tr":"GSP yetkisi (19 USC 2461 et seq.) December 31, 2020 tarihinde sona ermiş ve 2026 itibarıyla yeniden yetkilendirilmemiştir; talepler dosyalanabilir ancak yenileme yasası beklenirken şu anda GSP gümrük muafiyeti tanınmamaktadır.","hi":"GSP प्राधिकरण (19 USC 2461 et seq.) December 31, 2020 को समाप्त हो गया और 2026 तक इसे पुनः अधिकृत नहीं किया गया है; दावे दायर किए जा सकते हैं लेकिन नवीनीकरण कानून लंबित रहने तक वर्तमान में GSP शुल्क-मुक्त उपचार नहीं दिया जा रहा है।","ar":"انتهى تفويض GSP (19 USC 2461 et seq.) في December 31, 2020 ولم يُعَد ترخيصه حتى 2026؛ ويمكن تقديم المطالبات لكن معاملة الإعفاء من الرسوم بموجب GSP لا تُمنح حاليًا في انتظار تشريع التجديد."}},{"cat":"trade","a":1,"q":{"en":"The principle by which an article that undergoes processing in a country resulting in a new article with a new name, character, and use acquires that country as its origin is known as:","es":"El principio por el cual un artículo que se somete a un procesamiento en un país que da como resultado un nuevo artículo con un nuevo nombre, carácter y uso adquiere ese país como su origen se conoce como:","ru":"Принцип, согласно которому изделие, прошедшее в стране обработку, в результате которой возникает новое изделие с новым наименованием, свойствами и назначением, приобретает эту страну в качестве страны происхождения, известен как:","tr":"Bir eşyanın bir ülkede işlem görmesi sonucunda yeni bir ad, nitelik ve kullanıma sahip yeni bir eşya ortaya çıktığında o ülkeyi menşe olarak kazanmasını sağlayan ilke şu şekilde bilinir:","hi":"वह सिद्धांत जिसके अनुसार किसी देश में संसाधित होने वाली वस्तु, जिसके परिणामस्वरूप नए नाम, स्वरूप और उपयोग वाली एक नई वस्तु बनती है, उस देश को अपने मूल के रूप में प्राप्त करती है, कहलाता है:","ar":"المبدأ الذي بموجبه تكتسب السلعة التي تخضع لمعالجة في بلد ما ينتج عنها سلعة جديدة باسم وطبيعة واستخدام جديد ذلك البلد كمنشأ لها يُعرف باسم:"},"o":[{"en":"Tariff shift","es":"Cambio arancelario","ru":"Изменение тарифной классификации (tariff shift)","tr":"Tarife değişimi","hi":"टैरिफ शिफ्ट","ar":"تغيّر التعريفة الجمركية"},{"en":"Substantial transformation","es":"Transformación sustancial","ru":"Существенная переработка","tr":"Esaslı dönüşüm","hi":"पर्याप्त रूपांतरण","ar":"التحوّل الجوهري"},{"en":"Simple assembly","es":"Ensamblaje simple","ru":"Простая сборка","tr":"Basit montaj","hi":"सरल असेंबली","ar":"التجميع البسيط"},{"en":"De minimis incorporation","es":"Incorporación de minimis","ru":"Минимальное (de minimis) включение","tr":"De minimis dahil etme","hi":"डि मिनिमिस समावेश","ar":"الإدماج البسيط (de minimis)"}],"e":{"en":"Substantial transformation is the long-standing common-law test (see 19 CFR 134.1(b)) under which a new and different article of commerce with a new name, character, or use confers origin. Tariff shift is a USMCA rule-of-origin tool, distinct from the general substantial transformation test.","es":"La transformación sustancial es el criterio de derecho consuetudinario de larga data (véase 19 CFR 134.1(b)) según el cual un artículo de comercio nuevo y distinto con un nuevo nombre, carácter o uso confiere el origen. El cambio arancelario es una herramienta de regla de origen del USMCA, distinta del criterio general de transformación sustancial.","ru":"Существенная переработка — это давно сложившийся критерий общего права (см. 19 CFR 134.1(b)), согласно которому новое и иное изделие торговли с новым наименованием, свойствами или назначением определяет происхождение. Изменение тарифной классификации (tariff shift) — это инструмент правил происхождения USMCA, отличный от общего критерия существенной переработки.","tr":"Esaslı dönüşüm, yeni bir ad, nitelik veya kullanıma sahip yeni ve farklı bir ticari eşyanın menşe kazandırdığı, uzun süredir yerleşik ortak hukuk (common law) testidir (bkz. 19 CFR 134.1(b)). Tarife değişimi ise USMCA'nın bir menşe kuralı aracıdır ve genel esaslı dönüşüm testinden farklıdır.","hi":"पर्याप्त रूपांतरण एक दीर्घकालिक कॉमन-लॉ परीक्षण है (देखें 19 CFR 134.1(b)) जिसके तहत नए नाम, स्वरूप या उपयोग वाली एक नई और भिन्न वाणिज्यिक वस्तु मूल प्रदान करती है। टैरिफ शिफ्ट एक USMCA मूल-नियम उपकरण है, जो सामान्य पर्याप्त रूपांतरण परीक्षण से अलग है।","ar":"التحوّل الجوهري هو اختبار القانون العام الراسخ منذ زمن طويل (انظر 19 CFR 134.1(b))، الذي بموجبه تكتسب المنشأ سلعة تجارية جديدة ومختلفة ذات اسم أو طبيعة أو استخدام جديد. أما تغيّر التعريفة الجمركية فهو أداة من أدوات قواعد المنشأ في USMCA، ويختلف عن اختبار التحوّل الجوهري العام."}},{"cat":"trade","a":3,"q":{"en":"Foreign trade zones (FTZs) are administered under which part of 19 CFR?","es":"Las zonas de comercio exterior (FTZs) se administran conforme a ¿cuál parte de 19 CFR?","ru":"Зоны внешней торговли (FTZ) администрируются согласно какой части 19 CFR?","tr":"Serbest ticaret bölgeleri (FTZ), 19 CFR'nin hangi bölümü kapsamında yönetilir?","hi":"विदेशी व्यापार क्षेत्र (FTZs) 19 CFR के किस भाग के तहत प्रशासित होते हैं?","ar":"تُدار مناطق التجارة الأجنبية (FTZs) بموجب أي جزء من 19 CFR؟"},"o":[{"en":"Part 113","es":"Part 113","ru":"Part 113","tr":"Part 113","hi":"Part 113","ar":"Part 113"},{"en":"Part 19","es":"Part 19","ru":"Part 19","tr":"Part 19","hi":"Part 19","ar":"Part 19"},{"en":"Part 191","es":"Part 191","ru":"Part 191","tr":"Part 191","hi":"Part 191","ar":"Part 191"},{"en":"Part 146","es":"Part 146","ru":"Part 146","tr":"Part 146","hi":"Part 146","ar":"Part 146"}],"e":{"en":"19 CFR Part 146 governs the operation of foreign trade zones. Part 19 covers bonded warehouses, Part 113 covers bonds, and Part 191/190 covers drawback.","es":"19 CFR Part 146 rige el funcionamiento de las zonas de comercio exterior. Part 19 abarca los depósitos aduaneros, Part 113 abarca las fianzas, y Part 191/190 abarca el drawback (reembolso de aranceles).","ru":"19 CFR Part 146 регулирует деятельность зон внешней торговли. Part 19 охватывает таможенные склады, Part 113 — гарантии, а Part 191/190 — возврат пошлин (drawback).","tr":"19 CFR Part 146, serbest ticaret bölgelerinin işleyişini düzenler. Part 19 antrepoları, Part 113 kefaletleri ve Part 191/190 vergi iadesini (drawback) kapsar.","hi":"19 CFR Part 146 विदेशी व्यापार क्षेत्रों के संचालन को शासित करता है। Part 19 बॉन्डेड गोदामों को, Part 113 बॉन्ड को, और Part 191/190 ड्रॉबैक को कवर करता है।","ar":"ينظّم 19 CFR Part 146 تشغيل مناطق التجارة الأجنبية. ويغطي Part 19 المستودعات الجمركية، ويغطي Part 113 الكفالات، ويغطي Part 191/190 استرداد الرسوم (drawback)."}},{"cat":"trade","a":2,"q":{"en":"Under USMCA, who may complete a certification of origin?","es":"Conforme al USMCA, ¿quién puede completar una certificación de origen?","ru":"Согласно USMCA, кто может оформить сертификацию происхождения?","tr":"USMCA uyarınca, menşe sertifikasını kim doldurabilir?","hi":"USMCA के तहत, मूल का प्रमाणन कौन पूरा कर सकता है?","ar":"بموجب USMCA، من الذي يجوز له إكمال شهادة المنشأ؟"},"o":[{"en":"Only an exporter located in Canada or Mexico","es":"Solo un exportador ubicado en Canadá o México","ru":"Только экспортёр, находящийся в Канаде или Мексике","tr":"Yalnızca Kanada veya Meksika'da bulunan bir ihracatçı","hi":"केवल कनाडा या मेक्सिको में स्थित एक निर्यातक","ar":"مصدّر موجود في كندا أو المكسيك فقط"},{"en":"Only a licensed customs broker acting for the importer","es":"Solo un agente de aduanas con licencia que actúe en nombre del importador","ru":"Только лицензированный таможенный брокер, действующий от имени импортёра","tr":"Yalnızca ithalatçı adına hareket eden ruhsatlı bir gümrük müşaviri","hi":"केवल आयातक के लिए कार्य करने वाला एक लाइसेंसधारी सीमा शुल्क ब्रोकर","ar":"وسيط جمركي مرخّص يتصرّف نيابة عن المستورد فقط"},{"en":"The importer, exporter, or producer of the good","es":"El importador, exportador o productor de la mercancía","ru":"Импортёр, экспортёр или производитель товара","tr":"Eşyanın ithalatçısı, ihracatçısı veya üreticisi","hi":"वस्तु का आयातक, निर्यातक या उत्पादक","ar":"مستورد السلعة أو مصدّرها أو منتجها"},{"en":"Only the producer of the good","es":"Solo el productor de la mercancía","ru":"Только производитель товара","tr":"Yalnızca eşyanın üreticisi","hi":"केवल वस्तु का उत्पादक","ar":"منتج السلعة فقط"}],"e":{"en":"Under 19 CFR 182.12 and the USMCA, a certification of origin may be completed by the importer, exporter, or producer of the good, a key change from NAFTA, which did not allow importer certification.","es":"Conforme a 19 CFR 182.12 y al USMCA, una certificación de origen puede ser completada por el importador, exportador o productor de la mercancía, un cambio clave respecto del NAFTA, que no permitía la certificación por parte del importador.","ru":"Согласно 19 CFR 182.12 и USMCA, сертификацию происхождения может оформить импортёр, экспортёр или производитель товара — ключевое изменение по сравнению с NAFTA, которое не допускало сертификацию импортёром.","tr":"19 CFR 182.12 ve USMCA uyarınca, menşe sertifikası eşyanın ithalatçısı, ihracatçısı veya üreticisi tarafından doldurulabilir; bu, ithalatçı sertifikasyonuna izin vermeyen NAFTA'ya göre önemli bir değişikliktir.","hi":"19 CFR 182.12 और USMCA के तहत, मूल का प्रमाणन वस्तु के आयातक, निर्यातक या उत्पादक द्वारा पूरा किया जा सकता है, जो NAFTA से एक महत्वपूर्ण बदलाव है, जिसमें आयातक प्रमाणन की अनुमति नहीं थी।","ar":"بموجب 19 CFR 182.12 و USMCA، يجوز إكمال شهادة المنشأ من قبل مستورد السلعة أو مصدّرها أو منتجها، وهو تغيير جوهري مقارنةً بـ NAFTA الذي لم يكن يسمح بتصديق المستورد."}},{"cat":"trade","a":0,"q":{"en":"Articles exempted from individual country-of-origin marking under section 304(a)(3)(J) of the Tariff Act are commonly known as the:","es":"Los artículos exentos del marcado individual del país de origen conforme a la sección 304(a)(3)(J) de la Tariff Act se conocen comúnmente como la:","ru":"Изделия, освобождённые от индивидуальной маркировки страны происхождения согласно разделу 304(a)(3)(J) Tariff Act, обычно известны как:","tr":"Tariff Act'in 304(a)(3)(J) bölümü uyarınca bireysel menşe ülke işaretlemesinden muaf tutulan eşyalar genellikle şu adla bilinir:","hi":"Tariff Act की धारा 304(a)(3)(J) के तहत व्यक्तिगत मूल-देश अंकन से छूट प्राप्त वस्तुएँ आमतौर पर किस नाम से जानी जाती हैं:","ar":"السلع المعفاة من علامة بلد المنشأ الفردية بموجب القسم 304(a)(3)(J) من Tariff Act تُعرف عمومًا باسم:"},"o":[{"en":"J-list","es":"J-list","ru":"J-list","tr":"J-list","hi":"J-list","ar":"J-list"},{"en":"F-list","es":"F-list","ru":"F-list","tr":"F-list","hi":"F-list","ar":"F-list"},{"en":"Q-list","es":"Q-list","ru":"Q-list","tr":"Q-list","hi":"Q-list","ar":"Q-list"},{"en":"K-list","es":"K-list","ru":"K-list","tr":"K-list","hi":"K-list","ar":"K-list"}],"e":{"en":"The 'J-list' exceptions are set out at 19 CFR 134.33, listing classes of articles excepted from individual marking under 19 USC 1304(a)(3)(J); however, the outermost container reaching the ultimate purchaser must still be marked.","es":"Las excepciones de la 'J-list' están establecidas en 19 CFR 134.33, que enumera las clases de artículos exceptuados del marcado individual conforme a 19 USC 1304(a)(3)(J); no obstante, el contenedor más externo que llega al comprador final aún debe estar marcado.","ru":"Исключения 'J-list' установлены в 19 CFR 134.33, где перечислены классы изделий, освобождённых от индивидуальной маркировки согласно 19 USC 1304(a)(3)(J); однако внешняя упаковка, доходящая до конечного покупателя, всё равно должна быть промаркирована.","tr":"'J-list' istisnaları 19 CFR 134.33'te belirtilmiş olup, 19 USC 1304(a)(3)(J) uyarınca bireysel işaretlemeden muaf tutulan eşya sınıflarını listeler; ancak nihai alıcıya ulaşan en dıştaki kabın yine de işaretlenmesi gerekir.","hi":"'J-list' अपवाद 19 CFR 134.33 में निर्धारित हैं, जो 19 USC 1304(a)(3)(J) के तहत व्यक्तिगत अंकन से छूट प्राप्त वस्तुओं की श्रेणियों को सूचीबद्ध करते हैं; हालाँकि, अंतिम खरीदार तक पहुँचने वाले सबसे बाहरी कंटेनर को फिर भी अंकित किया जाना चाहिए।","ar":"تَرِد استثناءات 'J-list' في 19 CFR 134.33، التي تُعدّد فئات السلع المعفاة من العلامة الفردية بموجب 19 USC 1304(a)(3)(J)؛ ومع ذلك، يجب أن تُعلَّم الحاوية الخارجية التي تصل إلى المشتري النهائي."}},{"cat":"trade","a":1,"q":{"en":"Bonded warehouses are governed by which part of 19 CFR?","es":"Los depósitos aduaneros se rigen por ¿cuál parte de 19 CFR?","ru":"Таможенные склады регулируются какой частью 19 CFR?","tr":"Antrepolar 19 CFR'nin hangi bölümüyle düzenlenir?","hi":"बॉन्डेड गोदाम 19 CFR के किस भाग द्वारा शासित होते हैं?","ar":"تخضع المستودعات الجمركية لأي جزء من 19 CFR؟"},"o":[{"en":"Part 113","es":"Part 113","ru":"Part 113","tr":"Part 113","hi":"Part 113","ar":"Part 113"},{"en":"Part 19","es":"Part 19","ru":"Part 19","tr":"Part 19","hi":"Part 19","ar":"Part 19"},{"en":"Part 18","es":"Part 18","ru":"Part 18","tr":"Part 18","hi":"Part 18","ar":"Part 18"},{"en":"Part 144","es":"Part 144","ru":"Part 144","tr":"Part 144","hi":"Part 144","ar":"Part 144"}],"e":{"en":"19 CFR Part 19 governs customs bonded warehouses (classes 1 through 11). Part 18 covers transportation in bond, Part 113 covers bonds generally, and Part 144 covers warehouse and rewarehouse entries and withdrawals.","es":"19 CFR Part 19 rige los depósitos aduaneros afianzados (clases 1 a 11). Part 18 abarca el transporte bajo fianza, Part 113 abarca las fianzas en general, y Part 144 abarca las entradas y retiros de depósito y redepósito.","ru":"19 CFR Part 19 регулирует таможенные склады под гарантией (классы с 1 по 11). Part 18 охватывает перевозку под гарантией (transportation in bond), Part 113 — гарантии в целом, а Part 144 — складские и повторно складские ввозы и изъятия.","tr":"19 CFR Part 19, gümrük antrepolarını (1 ila 11. sınıflar) düzenler. Part 18 kefaletli taşımayı, Part 113 genel olarak kefaletleri ve Part 144 antrepo ve yeniden antrepo girişleri ile çekişlerini kapsar.","hi":"19 CFR Part 19 सीमा शुल्क बॉन्डेड गोदामों (कक्षा 1 से 11) को शासित करता है। Part 18 बॉन्ड में परिवहन को, Part 113 सामान्य रूप से बॉन्ड को, और Part 144 गोदाम और पुनः-गोदाम एंट्री व निकासी को कवर करता है।","ar":"ينظّم 19 CFR Part 19 المستودعات الجمركية المكفولة (الفئات من 1 إلى 11). ويغطي Part 18 النقل تحت الكفالة، ويغطي Part 113 الكفالات عمومًا، ويغطي Part 144 إدخالات وسحوبات المستودعات وإعادة الإيداع."}},{"cat":"trade","a":3,"q":{"en":"Which statement correctly distinguishes an absolute quota from a tariff-rate quota under 19 CFR Part 132?","es":"¿Qué afirmación distingue correctamente una cuota absoluta de una cuota arancelaria conforme a 19 CFR Part 132?","ru":"Какое утверждение правильно отличает абсолютную квоту от тарифной квоты согласно 19 CFR Part 132?","tr":"Hangi ifade, 19 CFR Part 132 uyarınca mutlak kotayı tarife oranı kotasından doğru şekilde ayırt eder?","hi":"कौन सा कथन 19 CFR Part 132 के तहत एक पूर्ण कोटा को टैरिफ-दर कोटा से सही ढंग से अलग करता है?","ar":"أي عبارة تميّز بشكل صحيح الحصة المطلقة عن حصة معدّل التعريفة بموجب 19 CFR Part 132؟"},"o":[{"en":"An absolute quota permits unlimited entries at a higher rate once filled, while a tariff-rate quota bars all further entries once filled","es":"Una cuota absoluta permite entradas ilimitadas a una tasa más alta una vez llena, mientras que una cuota arancelaria prohíbe todas las entradas adicionales una vez llena","ru":"Абсолютная квота после заполнения допускает неограниченные ввозы по более высокой ставке, тогда как тарифная квота после заполнения запрещает любые дальнейшие ввозы","tr":"Mutlak kota dolduktan sonra daha yüksek bir oranla sınırsız girişe izin verirken, tarife oranı kotası dolduktan sonra tüm ek girişleri yasaklar","hi":"एक पूर्ण कोटा भरने के बाद उच्च दर पर असीमित एंट्री की अनुमति देता है, जबकि एक टैरिफ-दर कोटा भरने के बाद सभी आगे की एंट्री पर रोक लगाता है","ar":"تسمح الحصة المطلقة بإدخالات غير محدودة بمعدل أعلى بمجرد امتلائها، في حين تمنع حصة معدّل التعريفة جميع الإدخالات الإضافية بمجرد امتلائها"},{"en":"Both absolute and tariff-rate quotas bar all further entries once filled","es":"Tanto las cuotas absolutas como las arancelarias prohíben todas las entradas adicionales una vez llenas","ru":"И абсолютные, и тарифные квоты после заполнения запрещают любые дальнейшие ввозы","tr":"Hem mutlak hem de tarife oranı kotaları, dolduktan sonra tüm ek girişleri yasaklar","hi":"पूर्ण और टैरिफ-दर दोनों कोटा भरने के बाद सभी आगे की एंट्री पर रोक लगाते हैं","ar":"تمنع كل من الحصة المطلقة وحصة معدّل التعريفة جميع الإدخالات الإضافية بمجرد امتلائها"},{"en":"Both absolute and tariff-rate quotas permit unlimited entries at the in-quota duty rate","es":"Tanto las cuotas absolutas como las arancelarias permiten entradas ilimitadas a la tasa arancelaria dentro de la cuota","ru":"И абсолютные, и тарифные квоты допускают неограниченные ввозы по внутриквотной ставке пошлины","tr":"Hem mutlak hem de tarife oranı kotaları, kota içi vergi oranıyla sınırsız girişe izin verir","hi":"पूर्ण और टैरिफ-दर दोनों कोटा कोटा-अंतर्गत शुल्क दर पर असीमित एंट्री की अनुमति देते हैं","ar":"تتيح كل من الحصة المطلقة وحصة معدّل التعريفة إدخالات غير محدودة بمعدّل الرسوم ضمن الحصة"},{"en":"An absolute quota bars further entries for consumption once the quantity is filled, while a tariff-rate quota allows continued entry at a higher duty rate once the in-quota amount is filled","es":"Una cuota absoluta prohíbe nuevas entradas para consumo una vez que se llena la cantidad, mientras que una cuota arancelaria permite la entrada continua a una tasa arancelaria más alta una vez que se llena la cantidad dentro de la cuota","ru":"Абсолютная квота после заполнения объёма запрещает дальнейшие ввозы для потребления, тогда как тарифная квота после заполнения внутриквотного объёма допускает дальнейший ввоз по более высокой ставке пошлины","tr":"Mutlak kota, miktar dolduğunda tüketim için ek girişleri yasaklarken, tarife oranı kotası kota içi miktar dolduğunda daha yüksek bir vergi oranıyla girişin sürmesine izin verir","hi":"एक पूर्ण कोटा मात्रा भरने के बाद उपभोग के लिए आगे की एंट्री पर रोक लगाता है, जबकि एक टैरिफ-दर कोटा कोटा-अंतर्गत मात्रा भरने के बाद उच्च शुल्क दर पर निरंतर एंट्री की अनुमति देता है","ar":"تمنع الحصة المطلقة الإدخالات الإضافية للاستهلاك بمجرد امتلاء الكمية، في حين تتيح حصة معدّل التعريفة استمرار الإدخال بمعدّل رسوم أعلى بمجرد امتلاء الكمية ضمن الحصة"}],"e":{"en":"Per 19 CFR 132.1, absolute quotas permit no further entries for consumption once the quota quantity is filled, whereas tariff-rate quotas permit a specified quantity at a reduced rate and allow over-quota merchandise to enter at a higher duty rate.","es":"Conforme a 19 CFR 132.1, las cuotas absolutas no permiten más entradas para consumo una vez que se llena la cantidad de la cuota, mientras que las cuotas arancelarias permiten una cantidad determinada a una tasa reducida y permiten que la mercancía que excede la cuota entre a una tasa arancelaria más alta.","ru":"Согласно 19 CFR 132.1, абсолютные квоты после заполнения объёма квоты не допускают дальнейших ввозов для потребления, тогда как тарифные квоты допускают определённый объём по сниженной ставке и позволяют сверхквотным товарам ввозиться по более высокой ставке пошлины.","tr":"19 CFR 132.1 uyarınca, mutlak kotalar kota miktarı dolduğunda tüketim için başka girişe izin vermezken, tarife oranı kotaları belirli bir miktara indirimli oranla izin verir ve kotayı aşan eşyanın daha yüksek bir vergi oranıyla girmesine olanak tanır.","hi":"19 CFR 132.1 के अनुसार, पूर्ण कोटा कोटा मात्रा भरने के बाद उपभोग के लिए आगे कोई एंट्री नहीं देता, जबकि टैरिफ-दर कोटा एक निर्दिष्ट मात्रा को घटी हुई दर पर देता है और कोटा से अधिक माल को उच्च शुल्क दर पर एंट्री की अनुमति देता है।","ar":"وفقًا لـ 19 CFR 132.1، لا تسمح الحصص المطلقة بأي إدخالات إضافية للاستهلاك بمجرد امتلاء كمية الحصة، بينما تتيح حصص معدّل التعريفة كمية محددة بمعدّل مخفّض وتسمح للبضائع التي تتجاوز الحصة بالدخول بمعدّل رسوم أعلى."}},{"cat":"trade","a":2,"q":{"en":"The person in the United States who will receive an article in the form in which it is imported, and whom the marking must inform, is the:","es":"La persona en los Estados Unidos que recibirá un artículo en la forma en que se importa, y a quien debe informar el marcado, es el:","ru":"Лицо в Соединённых Штатах, которое получит изделие в том виде, в котором оно импортируется, и которое маркировка должна информировать, — это:","tr":"Bir eşyayı ithal edildiği biçimde alacak olan ve işaretlemenin bilgilendirmesi gereken Amerika Birleşik Devletleri'ndeki kişi şudur:","hi":"संयुक्त राज्य अमेरिका में वह व्यक्ति जो किसी वस्तु को उसी रूप में प्राप्त करेगा जिस रूप में वह आयात की जाती है, और जिसे अंकन सूचित करना चाहिए, वह है:","ar":"الشخص في الولايات المتحدة الذي سيتلقى السلعة بالشكل الذي استُوردت به، والذي يجب أن تُعلِمه العلامة، هو:"},"o":[{"en":"Nominal consignee","es":"Consignatario nominal","ru":"Номинальный грузополучатель","tr":"Nominal alıcı/gönderilen","hi":"नाममात्र परेषिती","ar":"المرسَل إليه الاسمي"},{"en":"Consignee of record","es":"Consignatario registrado (consignee of record)","ru":"Зарегистрированный грузополучатель (consignee of record)","tr":"Kayıtlı alıcı/gönderilen (consignee of record)","hi":"रिकॉर्ड का परेषिती (consignee of record)","ar":"المرسَل إليه المسجَّل (consignee of record)"},{"en":"Ultimate purchaser","es":"Comprador final","ru":"Конечный покупатель","tr":"Nihai alıcı","hi":"अंतिम खरीदार","ar":"المشتري النهائي"},{"en":"Importer of record","es":"Importador registrado (importer of record)","ru":"Зарегистрированный импортёр (importer of record)","tr":"Kayıtlı ithalatçı (importer of record)","hi":"रिकॉर्ड का आयातक (importer of record)","ar":"المستورد المسجَّل (importer of record)"}],"e":{"en":"Under 19 CFR 134.1(d), the 'ultimate purchaser' is generally the last person in the U.S. who will receive the article in the form in which it was imported; the marking must be conspicuous enough for that person to identify the country of origin.","es":"Conforme a 19 CFR 134.1(d), el 'comprador final' es generalmente la última persona en los EE. UU. que recibirá el artículo en la forma en que fue importado; el marcado debe ser lo suficientemente visible para que esa persona identifique el país de origen.","ru":"Согласно 19 CFR 134.1(d), 'конечный покупатель' — это, как правило, последнее лицо в США, которое получит изделие в том виде, в котором оно было импортировано; маркировка должна быть достаточно заметной, чтобы это лицо могло определить страну происхождения.","tr":"19 CFR 134.1(d) uyarınca, 'nihai alıcı' genellikle ABD'de eşyayı ithal edildiği biçimde alacak olan son kişidir; işaretleme, o kişinin menşe ülkeyi tanımlayabilmesi için yeterince göze çarpar olmalıdır.","hi":"19 CFR 134.1(d) के तहत, 'अंतिम खरीदार' आमतौर पर अमेरिका में वह अंतिम व्यक्ति होता है जो वस्तु को उसी रूप में प्राप्त करेगा जिस रूप में वह आयात की गई थी; अंकन इतना स्पष्ट होना चाहिए कि वह व्यक्ति मूल देश की पहचान कर सके।","ar":"بموجب 19 CFR 134.1(d)، فإن 'المشتري النهائي' هو عمومًا آخر شخص في الولايات المتحدة سيتلقى السلعة بالشكل الذي استُوردت به؛ ويجب أن تكون العلامة بارزة بما يكفي ليتمكن ذلك الشخص من تحديد بلد المنشأ."}},{"cat":"trade","a":3,"q":{"en":"Which of the following is NOT one of the three statutory characteristics required of country-of-origin marking under 19 USC 1304?","es":"¿Cuál de las siguientes NO es una de las tres características legales exigidas para el marcado del país de origen conforme a 19 USC 1304?","ru":"Что из перечисленного НЕ является одной из трёх установленных законом характеристик, требуемых для маркировки страны происхождения согласно 19 USC 1304?","tr":"Aşağıdakilerden hangisi 19 USC 1304 uyarınca menşe ülke işaretlemesi için gereken üç yasal nitelikten biri DEĞİLDİR?","hi":"निम्नलिखित में से कौन सा 19 USC 1304 के तहत मूल-देश अंकन के लिए आवश्यक तीन वैधानिक विशेषताओं में से एक नहीं है?","ar":"أيٌّ مما يلي ليس من الخصائص القانونية الثلاث المطلوبة لعلامة بلد المنشأ بموجب 19 USC 1304؟"},"o":[{"en":"Legible","es":"Legible","ru":"Разборчивая","tr":"Okunaklı","hi":"सुपाठ्य","ar":"مقروءة"},{"en":"Permanent","es":"Permanente","ru":"Стойкая","tr":"Kalıcı","hi":"स्थायी","ar":"دائمة"},{"en":"Conspicuous","es":"Visible (conspicuo)","ru":"Заметная","tr":"Göze çarpar","hi":"स्पष्ट (दृश्यमान)","ar":"بارزة"},{"en":"Color-coded","es":"Codificada por colores","ru":"Цветовая кодировка","tr":"Renk kodlu","hi":"रंग-कोडित","ar":"مرمّزة بالألوان"}],"e":{"en":"19 USC 1304 and 19 CFR 134.41 require marking to be conspicuous, legible, and permanent (indelible). There is no requirement that origin marking be color-coded.","es":"19 USC 1304 y 19 CFR 134.41 exigen que el marcado sea visible, legible y permanente (indeleble). No existe requisito de que el marcado de origen esté codificado por colores.","ru":"19 USC 1304 и 19 CFR 134.41 требуют, чтобы маркировка была заметной, разборчивой и стойкой (несмываемой). Требования о цветовой кодировке маркировки происхождения нет.","tr":"19 USC 1304 ve 19 CFR 134.41, işaretlemenin göze çarpar, okunaklı ve kalıcı (silinmez) olmasını gerektirir. Menşe işaretlemesinin renk kodlu olmasına dair bir gereklilik yoktur.","hi":"19 USC 1304 और 19 CFR 134.41 के अनुसार अंकन का स्पष्ट, सुपाठ्य और स्थायी (अमिट) होना आवश्यक है। मूल अंकन के रंग-कोडित होने की कोई आवश्यकता नहीं है।","ar":"تشترط 19 USC 1304 و19 CFR 134.41 أن تكون العلامة بارزة ومقروءة ودائمة (غير قابلة للمحو). ولا يوجد اشتراط بأن تكون علامة المنشأ مرمّزة بالألوان."}},{"cat":"trade","a":0,"q":{"en":"Under HTSUS 9802.00.80, when qualifying U.S.-fabricated components are assembled abroad, duty is assessed on:","es":"Conforme a HTSUS 9802.00.80, cuando componentes fabricados en EE. UU. que califican se ensamblan en el extranjero, el arancel se aplica sobre:","ru":"Согласно HTSUS 9802.00.80, когда соответствующие требованиям компоненты, изготовленные в США, собираются за рубежом, пошлина начисляется на:","tr":"HTSUS 9802.00.80 uyarınca, niteliklere uygun ABD'de üretilmiş bileşenler yurt dışında monte edildiğinde, gümrük vergisi şu üzerinden hesaplanır:","hi":"HTSUS 9802.00.80 के तहत, जब अमेरिका में निर्मित योग्य घटकों को विदेश में असेंबल किया जाता है, तो शुल्क किस पर लगाया जाता है:","ar":"بموجب HTSUS 9802.00.80، عندما تُجمَّع في الخارج مكوّنات مصنّعة في الولايات المتحدة ومستوفية للشروط، يُفرض الرسم على:"},"o":[{"en":"The full value of the article less the cost or value of the U.S. components","es":"El valor total del artículo menos el costo o valor de los componentes de EE. UU.","ru":"Полную стоимость изделия за вычетом стоимости или ценности компонентов США","tr":"Eşyanın tam değerinden ABD bileşenlerinin maliyeti veya değeri düşülerek","hi":"वस्तु का पूर्ण मूल्य घटाकर अमेरिकी घटकों की लागत या मूल्य","ar":"القيمة الكاملة للسلعة مطروحًا منها تكلفة أو قيمة المكوّنات الأمريكية"},{"en":"Only the cost of the foreign assembly labor regardless of materials","es":"Solo el costo de la mano de obra de ensamblaje en el extranjero sin importar los materiales","ru":"Только стоимость зарубежных трудозатрат на сборку независимо от материалов","tr":"Malzemelerden bağımsız olarak yalnızca yurt dışı montaj işçiliğinin maliyeti","hi":"सामग्री की परवाह किए बिना केवल विदेशी असेंबली श्रम की लागत","ar":"تكلفة عمالة التجميع الأجنبية فقط بغضّ النظر عن المواد"},{"en":"The full value of the assembled article with no allowance","es":"El valor total del artículo ensamblado sin ninguna deducción","ru":"Полную стоимость собранного изделия без какого-либо вычета","tr":"Hiçbir indirim yapılmadan monte edilmiş eşyanın tam değeri","hi":"बिना किसी कटौती के असेंबल की गई वस्तु का पूर्ण मूल्य","ar":"القيمة الكاملة للسلعة المجمّعة دون أي خصم"},{"en":"The cost or value of the U.S. components only","es":"Solo el costo o valor de los componentes de EE. UU.","ru":"Только стоимость или ценность компонентов США","tr":"Yalnızca ABD bileşenlerinin maliyeti veya değeri","hi":"केवल अमेरिकी घटकों की लागत या मूल्य","ar":"تكلفة أو قيمة المكوّنات الأمريكية فقط"}],"e":{"en":"HTSUS Chapter 98, subheading 9802.00.80, allows a duty allowance for U.S.-fabricated components: duty applies to the full value of the imported assembled article less the cost or value of the qualifying U.S. components, subject to the regulatory conditions in 19 CFR 10.11-10.26.","es":"El Capítulo 98 del HTSUS, subpartida 9802.00.80, permite una deducción arancelaria por componentes fabricados en EE. UU.: el arancel se aplica al valor total del artículo ensamblado importado menos el costo o valor de los componentes estadounidenses que califican, sujeto a las condiciones reglamentarias de 19 CFR 10.11-10.26.","ru":"Глава 98 HTSUS, субпозиция 9802.00.80, допускает вычет пошлины за компоненты, изготовленные в США: пошлина применяется к полной стоимости импортируемого собранного изделия за вычетом стоимости или ценности соответствующих требованиям компонентов США, при соблюдении нормативных условий 19 CFR 10.11-10.26.","tr":"HTSUS Bölüm 98, alt pozisyon 9802.00.80, ABD'de üretilmiş bileşenler için bir vergi indirimine izin verir: gümrük vergisi, ithal edilen monte edilmiş eşyanın tam değerinden niteliklere uygun ABD bileşenlerinin maliyeti veya değeri düşülerek uygulanır; bu, 19 CFR 10.11-10.26'daki düzenleyici koşullara tabidir.","hi":"HTSUS अध्याय 98, उपशीर्षक 9802.00.80, अमेरिका में निर्मित घटकों के लिए शुल्क छूट की अनुमति देता है: शुल्क आयातित असेंबल की गई वस्तु के पूर्ण मूल्य पर लागू होता है, घटाकर योग्य अमेरिकी घटकों की लागत या मूल्य, जो 19 CFR 10.11-10.26 की विनियामक शर्तों के अधीन है।","ar":"يتيح الفصل 98 من HTSUS، البند الفرعي 9802.00.80، خصمًا في الرسوم مقابل المكوّنات المصنّعة في الولايات المتحدة: يُفرض الرسم على القيمة الكاملة للسلعة المجمّعة المستوردة مطروحًا منها تكلفة أو قيمة المكوّنات الأمريكية المستوفية للشروط، مع مراعاة الشروط التنظيمية في 19 CFR 10.11-10.26."}},{"cat":"trade","a":0,"q":{"en":"A continuous customs bond differs from a single transaction bond primarily in that a continuous bond:","es":"Una fianza aduanera continua se diferencia de una fianza de transacción única principalmente en que una fianza continua:","ru":"Непрерывная (continuous) таможенная гарантия отличается от гарантии на единичную операцию главным образом тем, что непрерывная гарантия:","tr":"Sürekli gümrük kefaleti, tek işlemlik kefaletten esas olarak şu yönüyle ayrılır: sürekli kefalet:","hi":"एक निरंतर सीमा शुल्क बॉन्ड एकल लेनदेन बॉन्ड से मुख्य रूप से इस मायने में भिन्न होता है कि एक निरंतर बॉन्ड:","ar":"تختلف كفالة الجمارك المستمرة عن كفالة المعاملة الواحدة بشكل رئيسي في أن الكفالة المستمرة:"},"o":[{"en":"Covers multiple transactions at all ports for a one-year term until terminated","es":"Cubre múltiples transacciones en todos los puertos por un plazo de un año hasta su terminación","ru":"Покрывает множество операций во всех портах на годичный срок до её прекращения","tr":"Sona erdirilene kadar bir yıllık dönem için tüm limanlardaki birden çok işlemi kapsar","hi":"समाप्ति तक एक वर्ष की अवधि के लिए सभी बंदरगाहों पर अनेक लेनदेन को कवर करता है","ar":"تغطي معاملات متعددة في جميع الموانئ لمدة سنة واحدة إلى أن يتم إنهاؤها"},{"en":"Covers only one entry at one port and then expires","es":"Cubre solo una entrada en un puerto y luego expira","ru":"Покрывает только один ввоз в одном порту, а затем истекает","tr":"Yalnızca bir limanda bir girişi kapsar ve ardından sona erer","hi":"केवल एक बंदरगाह पर एक एंट्री को कवर करता है और फिर समाप्त हो जाता है","ar":"تغطي إدخالًا واحدًا فقط في ميناء واحد ثم تنتهي"},{"en":"Eliminates the importer's liability for supplemental duties after liquidation","es":"Elimina la responsabilidad del importador por aranceles suplementarios después de la liquidación","ru":"Устраняет ответственность импортёра за дополнительные пошлины после ликвидации","tr":"İthalatçının tasfiye sonrası ek vergilere ilişkin sorumluluğunu ortadan kaldırır","hi":"निपटान के बाद अनुपूरक शुल्कों के लिए आयातक की देयता को समाप्त करता है","ar":"تُلغي مسؤولية المستورد عن الرسوم التكميلية بعد التصفية"},{"en":"Is required only for warehouse withdrawals and not for consumption entries","es":"Solo se requiere para retiros de depósito y no para entradas de consumo","ru":"Требуется только для изъятий со склада, а не для ввозов для потребления","tr":"Yalnızca antrepo çekişleri için gereklidir, tüketim girişleri için değil","hi":"केवल गोदाम निकासी के लिए आवश्यक है, उपभोग एंट्री के लिए नहीं","ar":"مطلوبة فقط لسحوبات المستودعات وليس لإدخالات الاستهلاك"}],"e":{"en":"Under 19 CFR 113.11-113.12, a continuous bond remains in effect covering multiple transactions across all ports for successive annual periods until terminated, while a single transaction bond covers one importation at one port. Neither eliminates liability for duties due.","es":"Conforme a 19 CFR 113.11-113.12, una fianza continua permanece vigente cubriendo múltiples transacciones en todos los puertos por períodos anuales sucesivos hasta su terminación, mientras que una fianza de transacción única cubre una importación en un puerto. Ninguna elimina la responsabilidad por los aranceles adeudados.","ru":"Согласно 19 CFR 113.11-113.12, непрерывная гарантия остаётся в силе, покрывая множество операций во всех портах в течение последовательных годовых периодов до её прекращения, тогда как гарантия на единичную операцию покрывает один ввоз в одном порту. Ни одна из них не устраняет ответственность за причитающиеся пошлины.","tr":"19 CFR 113.11-113.12 uyarınca, sürekli kefalet, sona erdirilene kadar ardışık yıllık dönemler boyunca tüm limanlardaki birden çok işlemi kapsayarak yürürlükte kalır; tek işlemlik kefalet ise bir limanda bir ithalatı kapsar. Hiçbiri ödenmesi gereken vergilere ilişkin sorumluluğu ortadan kaldırmaz.","hi":"19 CFR 113.11-113.12 के तहत, एक निरंतर बॉन्ड समाप्ति तक क्रमिक वार्षिक अवधियों के लिए सभी बंदरगाहों पर अनेक लेनदेन को कवर करते हुए प्रभावी रहता है, जबकि एकल लेनदेन बॉन्ड एक बंदरगाह पर एक आयात को कवर करता है। कोई भी देय शुल्कों के लिए देयता को समाप्त नहीं करता।","ar":"بموجب 19 CFR 113.11-113.12، تظل الكفالة المستمرة سارية وتغطي معاملات متعددة في جميع الموانئ على مدى فترات سنوية متتالية إلى أن يتم إنهاؤها، بينما تغطي كفالة المعاملة الواحدة استيرادًا واحدًا في ميناء واحد. ولا تُلغي أيٌّ منهما المسؤولية عن الرسوم المستحقة."}},{"cat":"trade","a":3,"q":{"en":"Which preference program provides duty-free treatment for eligible goods from designated sub-Saharan African countries?","es":"¿Qué programa de preferencias otorga tratamiento libre de aranceles a las mercancías elegibles de los países subsaharianos designados de África?","ru":"Какая преференциальная программа предоставляет беспошлинный режим для подходящих товаров из назначенных стран Африки к югу от Сахары?","tr":"Hangi tercih programı, belirlenmiş Sahra altı Afrika ülkelerinden uygun eşyalara gümrük muafiyeti sağlar?","hi":"कौन सा वरीयता कार्यक्रम निर्दिष्ट उप-सहारा अफ्रीकी देशों से योग्य वस्तुओं को शुल्क-मुक्त उपचार प्रदान करता है?","ar":"أي برنامج أفضليات يمنح معاملة معفاة من الرسوم للسلع المؤهَّلة من بلدان أفريقيا جنوب الصحراء المُحدَّدة؟"},"o":[{"en":"Andean Trade Preference Act (ATPA)","es":"Ley de Preferencias Comerciales Andinas (ATPA)","ru":"Закон об андских торговых преференциях (ATPA)","tr":"And Ülkeleri Ticaret Tercihleri Yasası (ATPA)","hi":"एंडियन ट्रेड प्रेफरेंस एक्ट (ATPA)","ar":"قانون الأفضليات التجارية للدول الأنديزية (ATPA)"},{"en":"Generalized System of Preferences (GSP)","es":"Sistema Generalizado de Preferencias (GSP)","ru":"Общая система преференций (GSP)","tr":"Genelleştirilmiş Tercihler Sistemi (GSP)","hi":"सामान्यीकृत वरीयता प्रणाली (GSP)","ar":"نظام الأفضليات المعمم (GSP)"},{"en":"Caribbean Basin Initiative (CBI)","es":"Iniciativa de la Cuenca del Caribe (CBI)","ru":"Инициатива стран Карибского бассейна (CBI)","tr":"Karayip Havzası Girişimi (CBI)","hi":"कैरिबियन बेसिन इनिशिएटिव (CBI)","ar":"مبادرة حوض الكاريبي (CBI)"},{"en":"African Growth and Opportunity Act (AGOA)","es":"Ley de Crecimiento y Oportunidad para África (AGOA)","ru":"Закон об ускорении роста и расширении возможностей Африки (AGOA)","tr":"Afrika Büyüme ve Fırsat Yasası (AGOA)","hi":"अफ्रीकी विकास और अवसर अधिनियम (AGOA)","ar":"قانون النمو والفرص في أفريقيا (AGOA)"}],"e":{"en":"The African Growth and Opportunity Act (AGOA) provides duty-free treatment for eligible articles from designated sub-Saharan African beneficiary countries; goods typically claim it with HTSUS special program indicator 'D'.","es":"La Ley de Crecimiento y Oportunidad para África (AGOA) otorga tratamiento libre de aranceles a los artículos elegibles de los países beneficiarios subsaharianos designados de África; las mercancías generalmente lo reclaman con el indicador de programa especial 'D' del HTSUS.","ru":"Закон об ускорении роста и расширении возможностей Африки (AGOA) предоставляет беспошлинный режим для подходящих изделий из назначенных стран-бенефициаров Африки к югу от Сахары; товары обычно заявляют его с использованием индикатора специальной программы HTSUS 'D'.","tr":"Afrika Büyüme ve Fırsat Yasası (AGOA), belirlenmiş Sahra altı Afrika yararlanıcı ülkelerinden uygun eşyalara gümrük muafiyeti sağlar; eşyalar bunu genellikle HTSUS özel program göstergesi 'D' ile talep eder.","hi":"अफ्रीकी विकास और अवसर अधिनियम (AGOA) निर्दिष्ट उप-सहारा अफ्रीकी लाभार्थी देशों से योग्य वस्तुओं को शुल्क-मुक्त उपचार प्रदान करता है; वस्तुएँ आमतौर पर इसका दावा HTSUS विशेष कार्यक्रम संकेतक 'D' के साथ करती हैं।","ar":"يمنح قانون النمو والفرص في أفريقيا (AGOA) معاملة معفاة من الرسوم للسلع المؤهَّلة من بلدان أفريقيا جنوب الصحراء المستفيدة المُحدَّدة؛ وعادةً ما تُطالَب السلع بذلك باستخدام مؤشّر البرنامج الخاص 'D' في HTSUS."}},{"cat":"trade","a":2,"q":{"en":"Which statement about the USMCA certification of origin is TRUE?","es":"¿Qué afirmación sobre la certificación de origen del USMCA es VERDADERA?","ru":"Какое утверждение о сертификации происхождения по USMCA является ВЕРНЫМ?","tr":"USMCA menşe sertifikası hakkında hangi ifade DOĞRUDUR?","hi":"USMCA मूल प्रमाणन के बारे में कौन सा कथन सत्य है?","ar":"أي عبارة بشأن شهادة منشأ USMCA صحيحة؟"},"o":[{"en":"It may only cover a single shipment and never a blanket period","es":"Solo puede cubrir un único envío y nunca un período general (blanket)","ru":"Она может охватывать только одну поставку и никогда — общий (blanket) период","tr":"Yalnızca tek bir sevkiyatı kapsayabilir ve asla bir toplu (blanket) dönemi kapsamaz","hi":"यह केवल एक ही शिपमेंट को कवर कर सकता है और कभी भी एक सामूहिक (blanket) अवधि को नहीं","ar":"يجوز أن تغطي شحنة واحدة فقط ولا تغطي أبدًا فترة شاملة (blanket)"},{"en":"It must be issued exclusively by the producer of the good","es":"Debe ser emitida exclusivamente por el productor de la mercancía","ru":"Она должна выдаваться исключительно производителем товара","tr":"Yalnızca eşyanın üreticisi tarafından düzenlenmelidir","hi":"इसे केवल वस्तु के उत्पादक द्वारा ही जारी किया जाना चाहिए","ar":"يجب أن تصدر حصريًا عن منتج السلعة"},{"en":"It need not be on a prescribed form but must contain the required minimum data elements","es":"No necesita estar en un formulario prescrito, pero debe contener los elementos de datos mínimos requeridos","ru":"Она не обязана быть на предписанной форме, но должна содержать требуемые минимальные элементы данных","tr":"Öngörülen bir formda olması gerekmez ancak gerekli asgari veri unsurlarını içermelidir","hi":"इसे किसी निर्धारित फॉर्म पर होना आवश्यक नहीं है, परंतु इसमें आवश्यक न्यूनतम डेटा तत्व होने चाहिए","ar":"لا يلزم أن تكون على نموذج محدّد ولكن يجب أن تتضمن عناصر البيانات الدنيا المطلوبة"},{"en":"It must be submitted on a CBP-prescribed government form to be valid","es":"Debe presentarse en un formulario gubernamental prescrito por CBP para ser válida","ru":"Чтобы быть действительной, она должна быть подана на предписанной CBP государственной форме","tr":"Geçerli olması için CBP'nin öngördüğü resmi bir formda sunulmalıdır","hi":"मान्य होने के लिए इसे CBP द्वारा निर्धारित सरकारी फॉर्म पर प्रस्तुत किया जाना चाहिए","ar":"يجب تقديمها على نموذج حكومي تحدّده CBP لكي تكون صالحة"}],"e":{"en":"Unlike NAFTA's prescribed CF 434, USMCA does not require a specific form; under 19 CFR 182.12 the certification may be on any document, including a commercial invoice, that contains the nine minimum data elements, and it may cover a blanket period up to 12 months.","es":"A diferencia del CF 434 prescrito del NAFTA, el USMCA no requiere un formulario específico; conforme a 19 CFR 182.12, la certificación puede estar en cualquier documento, incluida una factura comercial, que contenga los nueve elementos de datos mínimos, y puede cubrir un período general (blanket) de hasta 12 months.","ru":"В отличие от предписанной NAFTA формы CF 434, USMCA не требует определённой формы; согласно 19 CFR 182.12, сертификация может быть на любом документе, включая коммерческий счёт-фактуру, который содержит девять минимальных элементов данных, и может охватывать общий (blanket) период до 12 months.","tr":"NAFTA'nın öngördüğü CF 434'ün aksine, USMCA belirli bir form gerektirmez; 19 CFR 182.12 uyarınca sertifika, dokuz asgari veri unsurunu içeren herhangi bir belge üzerinde olabilir; bir ticari fatura dahil; ve 12 months'a kadar bir toplu (blanket) dönemi kapsayabilir.","hi":"NAFTA के निर्धारित CF 434 के विपरीत, USMCA किसी विशिष्ट फॉर्म की आवश्यकता नहीं रखता; 19 CFR 182.12 के तहत प्रमाणन किसी भी दस्तावेज़ पर हो सकता है, जिसमें एक वाणिज्यिक चालान भी शामिल है, जिसमें नौ न्यूनतम डेटा तत्व हों, और यह 12 months तक की एक सामूहिक (blanket) अवधि को कवर कर सकता है।","ar":"خلافًا لنموذج CF 434 الذي يفرضه NAFTA، لا تشترط USMCA نموذجًا محددًا؛ فبموجب 19 CFR 182.12 يجوز أن تكون الشهادة على أي مستند، بما في ذلك فاتورة تجارية، يتضمن عناصر البيانات الدنيا التسعة، ويجوز أن تغطي فترة شاملة (blanket) تصل إلى 12 months."}},{"cat":"trade","a":3,"q":{"en":"Under the J-list exceptions of 19 CFR 134.33, when a listed article is imported in a container, which marking requirement still applies?","es":"Conforme a las excepciones de la J-list de 19 CFR 134.33, cuando un artículo enumerado se importa en un contenedor, ¿qué requisito de marcado sigue aplicándose?","ru":"Согласно исключениям J-list в 19 CFR 134.33, когда указанное в списке изделие импортируется в упаковке, какое требование к маркировке всё же применяется?","tr":"19 CFR 134.33'ün J-list istisnaları uyarınca, listelenen bir eşya bir kap içinde ithal edildiğinde hangi işaretleme gerekliliği yine de geçerli olur?","hi":"19 CFR 134.33 के J-list अपवादों के तहत, जब कोई सूचीबद्ध वस्तु किसी कंटेनर में आयात की जाती है, तो कौन सी अंकन आवश्यकता फिर भी लागू होती है?","ar":"بموجب استثناءات J-list في 19 CFR 134.33، عندما تُستورَد سلعة مدرجة في حاوية، أي اشتراط علامة يظل ساريًا؟"},"o":[{"en":"Only the invoice, not the container, must state the origin","es":"Solo la factura, no el contenedor, debe indicar el origen","ru":"Происхождение должно указываться только в счёте-фактуре, а не на упаковке","tr":"Menşei yalnızca fatura belirtmelidir, kap değil","hi":"केवल चालान को, कंटेनर को नहीं, मूल बताना चाहिए","ar":"يجب أن تذكر الفاتورة فقط، وليس الحاوية، بلد المنشأ"},{"en":"No marking is required on either the article or its container","es":"No se requiere marcado ni en el artículo ni en su contenedor","ru":"Маркировка не требуется ни на изделии, ни на его упаковке","tr":"Ne eşya üzerinde ne de kabı üzerinde işaretleme gerekmez","hi":"न तो वस्तु पर और न ही उसके कंटेनर पर कोई अंकन आवश्यक है","ar":"لا يُطلَب وضع علامة على السلعة ولا على حاويتها"},{"en":"The article itself must be die-stamped with its origin","es":"El artículo en sí debe estar estampado con su origen mediante troquel","ru":"Само изделие должно быть промаркировано штампом с указанием его происхождения","tr":"Eşyanın kendisi menşei ile kalıpla damgalanmalıdır","hi":"वस्तु पर स्वयं उसके मूल को डाई-स्टैम्प किया जाना चाहिए","ar":"يجب أن تُختَم السلعة نفسها ببلد منشئها بالقالب"},{"en":"The outermost container that reaches the ultimate purchaser must be marked with the article's origin","es":"El contenedor más externo que llega al comprador final debe estar marcado con el origen del artículo","ru":"Внешняя упаковка, доходящая до конечного покупателя, должна быть промаркирована с указанием происхождения изделия","tr":"Nihai alıcıya ulaşan en dıştaki kabın, eşyanın menşeiyle işaretlenmesi gerekir","hi":"अंतिम खरीदार तक पहुँचने वाले सबसे बाहरी कंटेनर पर वस्तु के मूल को अंकित किया जाना चाहिए","ar":"يجب أن تُعلَّم الحاوية الخارجية التي تصل إلى المشتري النهائي بمنشأ السلعة"}],"e":{"en":"19 CFR 134.33 excepts the listed articles from individual marking, but the outermost container in which the article ordinarily reaches the ultimate purchaser must be marked to indicate the country of origin of its contents.","es":"19 CFR 134.33 exime a los artículos enumerados del marcado individual, pero el contenedor más externo en el que el artículo normalmente llega al comprador final debe estar marcado para indicar el país de origen de su contenido.","ru":"19 CFR 134.33 освобождает перечисленные изделия от индивидуальной маркировки, но внешняя упаковка, в которой изделие обычно доходит до конечного покупателя, должна быть промаркирована для указания страны происхождения её содержимого.","tr":"19 CFR 134.33, listelenen eşyaları bireysel işaretlemeden muaf tutar, ancak eşyanın olağan olarak nihai alıcıya ulaştığı en dıştaki kabın, içeriğinin menşe ülkesini gösterecek şekilde işaretlenmesi gerekir.","hi":"19 CFR 134.33 सूचीबद्ध वस्तुओं को व्यक्तिगत अंकन से छूट देता है, लेकिन वह सबसे बाहरी कंटेनर जिसमें वस्तु आमतौर पर अंतिम खरीदार तक पहुँचती है, उसकी सामग्री के मूल देश को दर्शाने के लिए अंकित किया जाना चाहिए।","ar":"يُعفي 19 CFR 134.33 السلع المدرجة من العلامة الفردية، لكن يجب أن تُعلَّم الحاوية الخارجية التي تصل بها السلعة عادةً إلى المشتري النهائي لبيان بلد منشأ محتوياتها."}},{"cat":"trade","a":1,"q":{"en":"A U.S. importer brings in foreign-origin steel rods, which a third party in the United States cuts, threads, and machines into finished bolts before retail sale. For marking purposes under 19 CFR Part 134, who is most likely the ultimate purchaser?","es":"Un importador estadounidense trae barras de acero de origen extranjero, que un tercero en los Estados Unidos corta, rosca y mecaniza para convertirlas en pernos terminados antes de la venta minorista. Para efectos del marcado conforme a 19 CFR Part 134, ¿quién es muy probablemente el comprador final?","ru":"Импортёр из США ввозит стальные прутки иностранного происхождения, которые третья сторона в Соединённых Штатах режет, нарезает резьбу и обрабатывает, превращая их в готовые болты перед розничной продажей. Для целей маркировки согласно 19 CFR Part 134, кто, скорее всего, является конечным покупателем?","tr":"Bir ABD ithalatçısı yabancı menşeli çelik çubuklar getirir; ABD'deki bir üçüncü taraf bunları perakende satıştan önce keser, dişler açar ve işleyerek bitmiş cıvatalara dönüştürür. 19 CFR Part 134 uyarınca işaretleme açısından, büyük olasılıkla nihai alıcı kimdir?","hi":"एक अमेरिकी आयातक विदेशी मूल की स्टील की छड़ें लाता है, जिन्हें संयुक्त राज्य अमेरिका में एक तीसरा पक्ष खुदरा बिक्री से पहले काटकर, चूड़ी बनाकर और मशीनिंग करके तैयार बोल्ट में बदल देता है। 19 CFR Part 134 के तहत अंकन प्रयोजनों के लिए, सबसे अधिक संभावना से अंतिम खरीदार कौन है?","ar":"يستورد مستورد أمريكي قضبان فولاذية ذات منشأ أجنبي، يقوم طرف ثالث في الولايات المتحدة بقطعها وتسنينها وتشكيلها آليًا لتصبح براغي تامة الصنع قبل البيع بالتجزئة. لأغراض العلامة بموجب 19 CFR Part 134، من هو الأرجح أن يكون المشتري النهائي؟"},"o":[{"en":"The foreign producer of the steel rods","es":"El productor extranjero de las barras de acero","ru":"Иностранный производитель стальных прутков","tr":"Çelik çubukların yabancı üreticisi","hi":"स्टील की छड़ों का विदेशी उत्पादक","ar":"المنتج الأجنبي لقضبان الفولاذ"},{"en":"The U.S. manufacturer who substantially transforms the rods into bolts","es":"El fabricante estadounidense que transforma sustancialmente las barras en pernos","ru":"Производитель из США, который существенно перерабатывает прутки в болты","tr":"Çubukları esaslı şekilde cıvatalara dönüştüren ABD üreticisi","hi":"वह अमेरिकी निर्माता जो छड़ों को बोल्ट में पर्याप्त रूप से रूपांतरित करता है","ar":"الصانع الأمريكي الذي يحوّل القضبان جوهريًا إلى براغي"},{"en":"The retail consumer who buys the finished bolts","es":"El consumidor minorista que compra los pernos terminados","ru":"Розничный потребитель, который покупает готовые болты","tr":"Bitmiş cıvataları satın alan perakende tüketici","hi":"वह खुदरा उपभोक्ता जो तैयार बोल्ट खरीदता है","ar":"المستهلك بالتجزئة الذي يشتري البراغي تامة الصنع"},{"en":"The customs broker who filed the entry","es":"El agente de aduanas que presentó la entrada","ru":"Таможенный брокер, который подал ввоз (entry)","tr":"Girişi (entry) dosyalayan gümrük müşaviri","hi":"वह सीमा शुल्क ब्रोकर जिसने एंट्री दाखिल की","ar":"الوسيط الجمركي الذي قدّم الإدخال (entry)"}],"e":{"en":"Under 19 CFR 134.1(d)(1), if an imported article is used in manufacture, the manufacturer is the ultimate purchaser when the processing results in a substantial transformation; the conversion of rods into bolts is such a transformation, so the U.S. manufacturer is the ultimate purchaser.","es":"Conforme a 19 CFR 134.1(d)(1), si un artículo importado se utiliza en la fabricación, el fabricante es el comprador final cuando el procesamiento da como resultado una transformación sustancial; la conversión de barras en pernos es tal transformación, por lo que el fabricante estadounidense es el comprador final.","ru":"Согласно 19 CFR 134.1(d)(1), если импортируемое изделие используется в производстве, производитель является конечным покупателем, когда обработка приводит к существенной переработке; превращение прутков в болты является такой переработкой, поэтому производитель из США является конечным покупателем.","tr":"19 CFR 134.1(d)(1) uyarınca, ithal edilen bir eşya üretimde kullanılıyorsa, işlem esaslı bir dönüşümle sonuçlandığında üretici nihai alıcıdır; çubukların cıvataya dönüştürülmesi böyle bir dönüşümdür, dolayısıyla ABD üreticisi nihai alıcıdır.","hi":"19 CFR 134.1(d)(1) के तहत, यदि किसी आयातित वस्तु का उपयोग निर्माण में किया जाता है, तो जब प्रसंस्करण के परिणामस्वरूप पर्याप्त रूपांतरण होता है, तब निर्माता अंतिम खरीदार होता है; छड़ों का बोल्ट में परिवर्तन ऐसा ही एक रूपांतरण है, इसलिए अमेरिकी निर्माता अंतिम खरीदार है।","ar":"بموجب 19 CFR 134.1(d)(1)، إذا استُخدمت سلعة مستوردة في التصنيع، يكون الصانع هو المشتري النهائي عندما تؤدي المعالجة إلى تحوّل جوهري؛ وتحويل القضبان إلى براغي هو تحوّل من هذا القبيل، لذا يكون الصانع الأمريكي هو المشتري النهائي."}},{"cat":"trade","a":0,"q":{"en":"Which instrument is added to an existing continuous bond to modify it, such as to add a new trade name or principal, without issuing an entirely new bond?","es":"¿Qué instrumento se agrega a una fianza continua existente para modificarla, como para añadir un nuevo nombre comercial o principal, sin emitir una fianza completamente nueva?","ru":"Какой инструмент добавляется к существующей непрерывной гарантии для её изменения, например для добавления нового торгового наименования или принципала, без выпуска полностью новой гарантии?","tr":"Tamamen yeni bir kefalet düzenlemeden, mevcut bir sürekli kefaleti değiştirmek için, örneğin yeni bir ticari unvan veya asıl borçlu eklemek amacıyla, hangi belge eklenir?","hi":"किसी मौजूदा निरंतर बॉन्ड में संशोधन के लिए कौन सा साधन जोड़ा जाता है, जैसे कि नया व्यापार नाम या प्रिंसिपल जोड़ने के लिए, बिना पूरी तरह से नया बॉन्ड जारी किए?","ar":"أي صكّ يُضاف إلى كفالة مستمرة قائمة لتعديلها، مثل إضافة اسم تجاري جديد أو أصيل، دون إصدار كفالة جديدة بالكامل؟"},"o":[{"en":"A rider","es":"Un anexo (rider)","ru":"Дополнение (rider)","tr":"Bir ek (rider)","hi":"एक राइडर (rider)","ar":"ملحق (rider)"},{"en":"A reconciliation entry","es":"Una entrada de reconciliación (reconciliation)","ru":"Ввоз по согласованию (reconciliation entry)","tr":"Bir mutabakat girişi (reconciliation entry)","hi":"एक समाधान एंट्री (reconciliation entry)","ar":"إدخال تسوية (reconciliation entry)"},{"en":"A protest","es":"Una protesta (protest)","ru":"Протест (protest)","tr":"Bir itiraz (protest)","hi":"एक प्रोटेस्ट (protest)","ar":"اعتراض (protest)"},{"en":"A supplemental petition","es":"Una petición suplementaria","ru":"Дополнительное ходатайство","tr":"Ek bir dilekçe","hi":"एक अनुपूरक याचिका","ar":"التماس تكميلي"}],"e":{"en":"Under 19 CFR Part 113, a bond rider is used to amend a continuous bond, for example to add or delete a principal's name, trade name, or address, without requiring execution of a new bond.","es":"Conforme a 19 CFR Part 113, se utiliza un anexo (rider) de fianza para enmendar una fianza continua, por ejemplo para añadir o eliminar el nombre, nombre comercial o dirección de un principal, sin requerir la ejecución de una nueva fianza.","ru":"Согласно 19 CFR Part 113, дополнение (rider) к гарантии используется для внесения изменений в непрерывную гарантию, например для добавления или удаления имени, торгового наименования или адреса принципала, без необходимости оформления новой гарантии.","tr":"19 CFR Part 113 uyarınca, sürekli bir kefaleti değiştirmek için, örneğin bir asıl borçlunun adını, ticari unvanını veya adresini eklemek ya da silmek amacıyla, yeni bir kefalet düzenlenmesini gerektirmeden bir kefalet eki (rider) kullanılır.","hi":"19 CFR Part 113 के तहत, एक निरंतर बॉन्ड में संशोधन के लिए एक बॉन्ड राइडर (rider) का उपयोग किया जाता है, उदाहरण के लिए किसी प्रिंसिपल का नाम, व्यापार नाम या पता जोड़ने या हटाने के लिए, बिना किसी नए बॉन्ड के निष्पादन की आवश्यकता के।","ar":"بموجب 19 CFR Part 113، يُستخدَم ملحق الكفالة (rider) لتعديل كفالة مستمرة، على سبيل المثال لإضافة أو حذف اسم أصيل أو اسم تجاري أو عنوان، دون الحاجة إلى تنفيذ كفالة جديدة."}},{"cat":"trade","a":1,"q":{"en":"Which of the following is among the conditions of the basic importation and entry bond under 19 CFR 113.62?","es":"¿Cuál de las siguientes se encuentra entre las condiciones de la fianza básica de importación y entrada conforme a 19 CFR 113.62?","ru":"Что из перечисленного входит в условия базовой гарантии импорта и ввоза согласно 19 CFR 113.62?","tr":"Aşağıdakilerden hangisi 19 CFR 113.62 uyarınca temel ithalat ve giriş kefaletinin şartları arasındadır?","hi":"निम्नलिखित में से कौन सा 19 CFR 113.62 के तहत बुनियादी आयात और एंट्री बॉन्ड की शर्तों में से एक है?","ar":"أيٌّ مما يلي يُعدّ من شروط كفالة الاستيراد والإدخال الأساسية بموجب 19 CFR 113.62؟"},"o":[{"en":"Agreement to store merchandise only in a Class 3 bonded warehouse","es":"Acuerdo de almacenar la mercancía únicamente en un depósito aduanero de Clase 3","ru":"Обязательство хранить товары только на таможенном складе класса 3 (Class 3)","tr":"Eşyayı yalnızca bir Sınıf 3 (Class 3) antrepoda depolama taahhüdü","hi":"माल को केवल Class 3 बॉन्डेड गोदाम में संग्रहीत करने का समझौता","ar":"الالتزام بتخزين البضائع فقط في مستودع جمركي من الفئة 3 (Class 3)"},{"en":"Agreement to pay duties, taxes, and charges and to make or complete entry","es":"Acuerdo de pagar aranceles, impuestos y cargos y de realizar o completar la entrada","ru":"Обязательство уплачивать пошлины, налоги и сборы и осуществлять или завершать ввоз (entry)","tr":"Vergileri, harçları ve ücretleri ödeme ve girişi (entry) yapma veya tamamlama taahhüdü","hi":"शुल्क, कर और प्रभार भुगतान करने तथा एंट्री करने या पूरी करने का समझौता","ar":"الالتزام بدفع الرسوم والضرائب والمصاريف وبإجراء الإدخال (entry) أو إكماله"},{"en":"Agreement to relinquish all claims for drawback on exported goods","es":"Acuerdo de renunciar a todas las reclamaciones de drawback sobre mercancías exportadas","ru":"Обязательство отказаться от всех требований о возврате пошлин (drawback) по экспортируемым товарам","tr":"İhraç edilen eşyalara ilişkin tüm vergi iadesi (drawback) taleplerinden vazgeçme taahhüdü","hi":"निर्यात की गई वस्तुओं पर ड्रॉबैक के सभी दावों को त्यागने का समझौता","ar":"الالتزام بالتخلي عن جميع مطالبات استرداد الرسوم (drawback) على السلع المصدَّرة"},{"en":"Agreement to waive all rights to protest a liquidation","es":"Acuerdo de renunciar a todos los derechos a protestar una liquidación","ru":"Обязательство отказаться от всех прав на оспаривание (protest) ликвидации","tr":"Bir tasfiyeye itiraz (protest) etme haklarının tümünden feragat etme taahhüdü","hi":"किसी निपटान का विरोध (protest) करने के सभी अधिकारों को त्यागने का समझौता","ar":"الالتزام بالتنازل عن جميع حقوق الاعتراض (protest) على التصفية"}],"e":{"en":"19 CFR 113.62 lists basic importation and entry bond conditions, including the obligation to deposit/pay duties, taxes, and charges, to make or complete entry, to produce documents, and to redeliver merchandise; it does not waive protest rights or drawback claims.","es":"19 CFR 113.62 enumera las condiciones de la fianza básica de importación y entrada, incluida la obligación de depositar/pagar aranceles, impuestos y cargos, de realizar o completar la entrada, de presentar documentos y de reentregar la mercancía; no renuncia a los derechos de protesta ni a las reclamaciones de drawback.","ru":"19 CFR 113.62 перечисляет условия базовой гарантии импорта и ввоза, включая обязательство вносить депозит/уплачивать пошлины, налоги и сборы, осуществлять или завершать ввоз, представлять документы и осуществлять повторную поставку (redeliver) товаров; оно не отменяет права на протест и требования о возврате пошлин (drawback).","tr":"19 CFR 113.62, vergileri, harçları ve ücretleri yatırma/ödeme, girişi yapma veya tamamlama, belgeleri ibraz etme ve eşyayı yeniden teslim etme yükümlülüğü dahil olmak üzere temel ithalat ve giriş kefaleti şartlarını sıralar; itiraz (protest) haklarından veya vergi iadesi (drawback) taleplerinden feragat etmez.","hi":"19 CFR 113.62 बुनियादी आयात और एंट्री बॉन्ड की शर्तों को सूचीबद्ध करता है, जिसमें शुल्क, कर और प्रभार जमा/भुगतान करने, एंट्री करने या पूरी करने, दस्तावेज़ प्रस्तुत करने और माल पुनः-वितरित (redeliver) करने का दायित्व शामिल है; यह विरोध (protest) अधिकारों या ड्रॉबैक दावों को नहीं त्यागता।","ar":"يُعدّد 19 CFR 113.62 شروط كفالة الاستيراد والإدخال الأساسية، بما في ذلك الالتزام بإيداع/دفع الرسوم والضرائب والمصاريف، وإجراء الإدخال أو إكماله، وتقديم المستندات، وإعادة تسليم البضائع؛ ولا يتنازل عن حقوق الاعتراض (protest) أو مطالبات استرداد الرسوم (drawback)."}},{"cat":"trade","a":3,"q":{"en":"Under USMCA rules of origin, which origin criterion applies to a good produced entirely in the territory of one or more parties exclusively from originating materials?","es":"Conforme a las reglas de origen del USMCA, ¿qué criterio de origen se aplica a una mercancía producida enteramente en el territorio de una o más partes exclusivamente a partir de materiales originarios?","ru":"Согласно правилам происхождения USMCA, какой критерий происхождения применяется к товару, произведённому полностью на территории одной или нескольких сторон исключительно из материалов, имеющих происхождение?","tr":"USMCA menşe kuralları uyarınca, bir veya daha fazla tarafın ülkesinde tamamen menşeli malzemelerden üretilen bir eşyaya hangi menşe kriteri uygulanır?","hi":"USMCA मूल नियमों के तहत, एक या अधिक पक्षों के क्षेत्र में पूर्णतः केवल मूल सामग्रियों से उत्पादित वस्तु पर कौन सा मूल मानदंड लागू होता है?","ar":"بموجب قواعد المنشأ في USMCA، أي معيار منشأ ينطبق على سلعة مُنتَجة بالكامل في إقليم طرف أو أكثر حصريًا من مواد ناشئة؟"},"o":[{"en":"Criterion A","es":"Criterion A","ru":"Criterion A","tr":"Criterion A","hi":"Criterion A","ar":"Criterion A"},{"en":"Criterion D","es":"Criterion D","ru":"Criterion D","tr":"Criterion D","hi":"Criterion D","ar":"Criterion D"},{"en":"Criterion B","es":"Criterion B","ru":"Criterion B","tr":"Criterion B","hi":"Criterion B","ar":"Criterion B"},{"en":"Criterion C","es":"Criterion C","ru":"Criterion C","tr":"Criterion C","hi":"Criterion C","ar":"Criterion C"}],"e":{"en":"Under the USMCA origin criteria, Criterion A is wholly obtained or produced; Criterion B uses a tariff-shift/regional value content rule with possible non-originating materials; and Criterion C is for goods produced entirely from originating materials. (See 19 CFR Part 182 and USMCA Annex 4-B.)","es":"Conforme a los criterios de origen del USMCA, Criterion A es totalmente obtenido o producido; Criterion B utiliza una regla de cambio arancelario/contenido de valor regional con posibles materiales no originarios; y Criterion C es para mercancías producidas enteramente a partir de materiales originarios. (Véase 19 CFR Part 182 y USMCA Annex 4-B.)","ru":"Согласно критериям происхождения USMCA, Criterion A — полностью полученный или произведённый; Criterion B использует правило изменения тарифной классификации/регионального содержания стоимости с возможным использованием материалов, не имеющих происхождения; а Criterion C — для товаров, произведённых полностью из материалов, имеющих происхождение. (См. 19 CFR Part 182 и USMCA Annex 4-B.)","tr":"USMCA menşe kriterleri uyarınca, Criterion A tamamen elde edilmiş veya üretilmiştir; Criterion B, olası menşeli olmayan malzemelerle birlikte bir tarife değişimi/bölgesel değer içeriği kuralı kullanır; ve Criterion C, tamamen menşeli malzemelerden üretilen eşyalar içindir. (Bkz. 19 CFR Part 182 ve USMCA Annex 4-B.)","hi":"USMCA मूल मानदंडों के तहत, Criterion A पूर्णतः प्राप्त या उत्पादित है; Criterion B संभावित गैर-मूल सामग्रियों के साथ टैरिफ-शिफ्ट/क्षेत्रीय मूल्य सामग्री नियम का उपयोग करता है; और Criterion C पूर्णतः मूल सामग्रियों से उत्पादित वस्तुओं के लिए है। (देखें 19 CFR Part 182 और USMCA Annex 4-B।)","ar":"بموجب معايير المنشأ في USMCA، فإن Criterion A هو المُحصَّل أو المُنتَج بالكامل؛ ويستخدم Criterion B قاعدة تغيّر التعريفة/محتوى القيمة الإقليمية مع احتمال وجود مواد غير ناشئة؛ و Criterion C هو للسلع المُنتَجة بالكامل من مواد ناشئة. (انظر 19 CFR Part 182 و USMCA Annex 4-B.)"}},{"cat":"trade","a":0,"q":{"en":"Which statement regarding HTSUS 9801.00.10 returned-goods treatment is correct?","es":"¿Qué afirmación con respecto al tratamiento de mercancías retornadas de HTSUS 9801.00.10 es correcta?","ru":"Какое утверждение относительно режима возвращаемых товаров по HTSUS 9801.00.10 является правильным?","tr":"HTSUS 9801.00.10 geri getirilen eşya işlemine ilişkin hangi ifade doğrudur?","hi":"HTSUS 9801.00.10 वापस लाई गई वस्तुओं के उपचार के संबंध में कौन सा कथन सही है?","ar":"أي عبارة بشأن معاملة السلع المعادة بموجب HTSUS 9801.00.10 صحيحة؟"},"o":[{"en":"U.S.-origin goods may be returned duty-free with no time limit, while foreign-origin goods must be returned within 3 years","es":"Las mercancías de origen estadounidense pueden retornarse libres de aranceles sin límite de tiempo, mientras que las mercancías de origen extranjero deben retornarse dentro de 3 years","ru":"Товары происхождения США могут возвращаться беспошлинно без ограничения по времени, тогда как товары иностранного происхождения должны быть возвращены в течение 3 years","tr":"ABD menşeli eşyalar süre sınırı olmaksızın gümrük vergisinden muaf olarak geri getirilebilirken, yabancı menşeli eşyalar 3 years içinde geri getirilmelidir","hi":"अमेरिकी मूल की वस्तुएँ बिना किसी समय-सीमा के शुल्क-मुक्त वापस लाई जा सकती हैं, जबकि विदेशी मूल की वस्तुएँ 3 years के भीतर वापस लाई जानी चाहिए","ar":"يجوز إعادة السلع ذات المنشأ الأمريكي معفاة من الرسوم دون حدّ زمني، بينما يجب إعادة السلع ذات المنشأ الأجنبي خلال 3 years"},{"en":"Only foreign-origin goods qualify, and only if returned within 5 years","es":"Solo las mercancías de origen extranjero califican, y solo si se retornan dentro de 5 años","ru":"Соответствуют требованиям только товары иностранного происхождения, и только если они возвращены в течение 5 лет","tr":"Yalnızca yabancı menşeli eşyalar uygundur ve yalnızca 5 yıl içinde geri getirilirlerse","hi":"केवल विदेशी मूल की वस्तुएँ योग्य हैं, और केवल तभी यदि 5 वर्षों के भीतर वापस लाई जाएँ","ar":"السلع ذات المنشأ الأجنبي فقط هي المؤهَّلة، وفقط إذا أُعيدت خلال 5 سنوات"},{"en":"Both U.S.-origin and foreign-origin goods must be returned within 1 year","es":"Tanto las mercancías de origen estadounidense como las de origen extranjero deben retornarse dentro de 1 año","ru":"И товары происхождения США, и товары иностранного происхождения должны быть возвращены в течение 1 года","tr":"Hem ABD menşeli hem de yabancı menşeli eşyalar 1 yıl içinde geri getirilmelidir","hi":"अमेरिकी मूल और विदेशी मूल दोनों वस्तुएँ 1 वर्ष के भीतर वापस लाई जानी चाहिए","ar":"يجب إعادة كل من السلع ذات المنشأ الأمريكي والأجنبي خلال سنة واحدة"},{"en":"U.S.-origin goods must be returned within 3 years, while foreign-origin goods have no time limit","es":"Las mercancías de origen estadounidense deben retornarse dentro de 3 years, mientras que las mercancías de origen extranjero no tienen límite de tiempo","ru":"Товары происхождения США должны быть возвращены в течение 3 years, тогда как для товаров иностранного происхождения нет ограничения по времени","tr":"ABD menşeli eşyalar 3 years içinde geri getirilmelidir, yabancı menşeli eşyalar için ise süre sınırı yoktur","hi":"अमेरिकी मूल की वस्तुएँ 3 years के भीतर वापस लाई जानी चाहिए, जबकि विदेशी मूल की वस्तुओं की कोई समय-सीमा नहीं है","ar":"يجب إعادة السلع ذات المنشأ الأمريكي خلال 3 years، بينما لا يوجد حدّ زمني للسلع ذات المنشأ الأجنبي"}],"e":{"en":"Under HTSUS 9801.00.10, products of the U.S. may be returned duty-free with no time limit, whereas foreign-origin goods returned without advancement in value qualify only if returned within 3 years of export, provided no drawback was claimed.","es":"Conforme a HTSUS 9801.00.10, los productos de EE. UU. pueden retornarse libres de aranceles sin límite de tiempo, mientras que las mercancías de origen extranjero retornadas sin aumento en su valor califican solo si se retornan dentro de 3 years desde la exportación, siempre que no se haya reclamado drawback.","ru":"Согласно HTSUS 9801.00.10, товары США могут возвращаться беспошлинно без ограничения по времени, тогда как товары иностранного происхождения, возвращаемые без увеличения стоимости, соответствуют требованиям только если они возвращены в течение 3 years с момента экспорта, при условии что не был заявлен возврат пошлин (drawback).","tr":"HTSUS 9801.00.10 uyarınca, ABD ürünleri süre sınırı olmaksızın gümrük vergisinden muaf olarak geri getirilebilirken, değeri artırılmadan geri getirilen yabancı menşeli eşyalar yalnızca ihracattan itibaren 3 years içinde geri getirilirlerse ve vergi iadesi (drawback) talep edilmemişse uygun olur.","hi":"HTSUS 9801.00.10 के तहत, अमेरिका के उत्पाद बिना किसी समय-सीमा के शुल्क-मुक्त वापस लाए जा सकते हैं, जबकि मूल्य में वृद्धि के बिना वापस लाई गई विदेशी मूल की वस्तुएँ केवल तभी योग्य होती हैं यदि निर्यात के 3 years के भीतर वापस लाई जाएँ, बशर्ते कोई ड्रॉबैक का दावा न किया गया हो।","ar":"بموجب HTSUS 9801.00.10، يجوز إعادة منتجات الولايات المتحدة معفاة من الرسوم دون حدّ زمني، في حين أن السلع ذات المنشأ الأجنبي المعادة دون زيادة في القيمة تكون مؤهَّلة فقط إذا أُعيدت خلال 3 years من التصدير، شريطة عدم المطالبة باسترداد الرسوم (drawback)."}},{"cat":"trade","a":1,"q":{"en":"An importer admits foreign merchandise into a foreign trade zone in 'privileged foreign' status, then withdraws it for U.S. consumption after a tariff increase takes effect. Which is TRUE regarding the duty treatment?","es":"Un importador admite mercancía extranjera en una zona de comercio exterior con estatus de 'privileged foreign', y luego la retira para consumo en EE. UU. después de que entra en vigor un aumento arancelario. ¿Qué es VERDADERO con respecto al tratamiento arancelario?","ru":"Импортёр помещает иностранные товары в зону внешней торговли в статусе 'privileged foreign', а затем изымает их для потребления в США после вступления в силу повышения тарифа. Что является ВЕРНЫМ относительно режима начисления пошлин?","tr":"Bir ithalatçı, yabancı eşyayı bir serbest ticaret bölgesine 'privileged foreign' statüsünde kabul ettirir, ardından bir tarife artışı yürürlüğe girdikten sonra bunu ABD'de tüketim için çeker. Gümrük vergisi işlemine ilişkin hangisi DOĞRUDUR?","hi":"एक आयातक विदेशी माल को 'privileged foreign' स्थिति में विदेशी व्यापार क्षेत्र में प्रवेश कराता है, फिर एक टैरिफ वृद्धि प्रभावी होने के बाद उसे अमेरिकी उपभोग के लिए निकालता है। शुल्क उपचार के संबंध में कौन सा कथन सत्य है?","ar":"يُدخِل مستورد بضائع أجنبية إلى منطقة تجارة أجنبية بصفة 'privileged foreign'، ثم يسحبها للاستهلاك في الولايات المتحدة بعد سريان زيادة في التعريفة الجمركية. أيٌّ مما يلي صحيح بشأن معاملة الرسوم؟"},"o":[{"en":"No duty is owed because goods in a zone are deemed exported","es":"No se adeuda ningún arancel porque las mercancías en una zona se consideran exportadas","ru":"Пошлина не подлежит уплате, поскольку товары в зоне считаются экспортированными","tr":"Bir bölgedeki eşyalar ihraç edilmiş sayıldığından hiçbir gümrük vergisi borçlanılmaz","hi":"कोई शुल्क देय नहीं है क्योंकि किसी क्षेत्र में मौजूद वस्तुओं को निर्यात किया हुआ माना जाता है","ar":"لا تُستحق أي رسوم لأن السلع الموجودة في المنطقة تُعدّ مُصدَّرة"},{"en":"Duty is assessed based on the classification and rate fixed when privileged foreign status was elected","es":"El arancel se aplica con base en la clasificación y tasa fijadas cuando se eligió el estatus privileged foreign","ru":"Пошлина начисляется на основе классификации и ставки, зафиксированных при выборе статуса privileged foreign","tr":"Gümrük vergisi, privileged foreign statüsü seçildiğinde sabitlenen sınıflandırma ve oran esas alınarak hesaplanır","hi":"शुल्क उस वर्गीकरण और दर के आधार पर लगाया जाता है जो privileged foreign स्थिति चुने जाने पर निर्धारित की गई थी","ar":"يُفرض الرسم استنادًا إلى التصنيف والمعدل المثبَّتين عند اختيار صفة privileged foreign"},{"en":"Duty is assessed at the rate in effect on the date the zone was activated","es":"El arancel se aplica a la tasa vigente en la fecha en que se activó la zona","ru":"Пошлина начисляется по ставке, действовавшей на дату активации зоны","tr":"Gümrük vergisi, bölgenin aktive edildiği tarihte yürürlükte olan oran üzerinden hesaplanır","hi":"शुल्क उस दर पर लगाया जाता है जो क्षेत्र के सक्रिय किए जाने की तिथि पर प्रभावी थी","ar":"يُفرض الرسم بالمعدل الساري في تاريخ تفعيل المنطقة"},{"en":"Duty is assessed at the rate and value in effect when the goods are entered for consumption from the zone","es":"El arancel se aplica a la tasa y valor vigentes cuando las mercancías se ingresan para consumo desde la zona","ru":"Пошлина начисляется по ставке и стоимости, действующим на момент ввоза товаров для потребления из зоны","tr":"Gümrük vergisi, eşyalar bölgeden tüketim için girildiğinde yürürlükte olan oran ve değer üzerinden hesaplanır","hi":"शुल्क उस दर और मूल्य पर लगाया जाता है जो तब प्रभावी हो जब वस्तुएँ क्षेत्र से उपभोग के लिए दर्ज की जाती हैं","ar":"يُفرض الرسم بالمعدل والقيمة الساريين عند إدخال السلع للاستهلاك من المنطقة"}],"e":{"en":"Under 19 CFR 146.65, electing privileged foreign status fixes the tariff classification and applicable rate (and dutiable value, with limited exceptions) as of the date the application for that status is approved, insulating the goods from later rate changes; non-privileged foreign status would instead use the rate at withdrawal.","es":"Conforme a 19 CFR 146.65, elegir el estatus privileged foreign fija la clasificación arancelaria y la tasa aplicable (y el valor sujeto a arancel, con excepciones limitadas) a partir de la fecha en que se aprueba la solicitud de dicho estatus, protegiendo las mercancías de cambios de tasa posteriores; el estatus non-privileged foreign usaría en cambio la tasa al momento del retiro.","ru":"Согласно 19 CFR 146.65, выбор статуса privileged foreign фиксирует тарифную классификацию и применимую ставку (а также облагаемую пошлиной стоимость, с ограниченными исключениями) на дату утверждения заявления на этот статус, защищая товары от последующих изменений ставки; статус non-privileged foreign вместо этого использует ставку на момент изъятия.","tr":"19 CFR 146.65 uyarınca, privileged foreign statüsünün seçilmesi, tarife sınıflandırmasını ve uygulanabilir oranı (ve sınırlı istisnalarla vergiye tabi değeri) bu statü başvurusunun onaylandığı tarih itibarıyla sabitler ve eşyayı sonraki oran değişikliklerinden korur; non-privileged foreign statüsü ise bunun yerine çekiş anındaki oranı kullanır.","hi":"19 CFR 146.65 के तहत, privileged foreign स्थिति चुनना उस स्थिति के आवेदन की मंजूरी की तिथि के अनुसार टैरिफ वर्गीकरण और लागू दर (और सीमित अपवादों के साथ शुल्क-योग्य मूल्य) को निर्धारित कर देता है, जिससे वस्तुएँ बाद के दर परिवर्तनों से सुरक्षित रहती हैं; non-privileged foreign स्थिति इसके बजाय निकासी के समय की दर का उपयोग करेगी।","ar":"بموجب 19 CFR 146.65، فإن اختيار صفة privileged foreign يثبّت التصنيف الجمركي والمعدل المطبَّق (والقيمة الخاضعة للرسوم، مع استثناءات محدودة) اعتبارًا من تاريخ الموافقة على طلب تلك الصفة، مما يعزل السلع عن تغيّرات المعدل اللاحقة؛ أما صفة non-privileged foreign فتستخدم بدلًا من ذلك المعدل وقت السحب."}},{"cat":"trade","a":3,"q":{"en":"Regarding the consequences of failing to properly mark imported articles, which of the following may CBP do under 19 CFR Part 134?","es":"Con respecto a las consecuencias de no marcar correctamente los artículos importados, ¿cuál de las siguientes acciones puede realizar CBP conforme a 19 CFR Part 134?","ru":"Что касается последствий ненадлежащей маркировки импортируемых изделий, что из перечисленного CBP может сделать согласно 19 CFR Part 134?","tr":"İthal eşyaların düzgün şekilde işaretlenmemesinin sonuçlarına ilişkin olarak, CBP 19 CFR Part 134 uyarınca aşağıdakilerden hangisini yapabilir?","hi":"आयातित वस्तुओं को सही ढंग से अंकित न करने के परिणामों के संबंध में, 19 CFR Part 134 के तहत CBP निम्नलिखित में से क्या कर सकता है?","ar":"فيما يتعلق بعواقب عدم وضع علامة صحيحة على السلع المستوردة، أيٌّ مما يلي يجوز لـ CBP فعله بموجب 19 CFR Part 134؟"},"o":[{"en":"Demand redelivery of released merchandise that was not legally marked","es":"Exigir la reentrega de la mercancía liberada que no estaba marcada legalmente","ru":"Потребовать повторной поставки (redelivery) выпущенных товаров, которые не были промаркированы в соответствии с законом","tr":"Yasal olarak işaretlenmemiş serbest bırakılan eşyanın yeniden teslimini (redelivery) talep etmek","hi":"ऐसे जारी किए गए माल की पुनः-डिलीवरी (redelivery) की मांग करना जो कानूनी रूप से अंकित नहीं था","ar":"المطالبة بإعادة تسليم (redelivery) البضائع المُفرَج عنها التي لم تُعلَّم بشكل قانوني"},{"en":"Require the goods to be properly marked, exported, or destroyed under CBP supervision","es":"Exigir que las mercancías se marquen correctamente, se exporten o se destruyan bajo supervisión de CBP","ru":"Потребовать, чтобы товары были надлежащим образом промаркированы, экспортированы или уничтожены под надзором CBP","tr":"Eşyaların CBP gözetiminde düzgün şekilde işaretlenmesini, ihraç edilmesini veya imha edilmesini istemek","hi":"मांग करना कि वस्तुओं को CBP की निगरानी में सही ढंग से अंकित, निर्यात या नष्ट किया जाए","ar":"اشتراط وضع علامة صحيحة على السلع أو تصديرها أو إتلافها تحت إشراف CBP"},{"en":"Assess a marking duty of 10 percent ad valorem if the goods are released and not corrected","es":"Aplicar un arancel por marcado del 10 percent ad valorem si las mercancías se liberan y no se corrigen","ru":"Начислить пошлину за маркировку в размере 10 percent ad valorem, если товары выпущены и не исправлены","tr":"Eşyalar serbest bırakılır ve düzeltilmezse 10 percent ad valorem oranında işaretleme vergisi tahakkuk ettirmek","hi":"यदि वस्तुएँ जारी कर दी जाएँ और सुधार न की जाएँ तो 10 percent ad valorem की अंकन शुल्क लगाना","ar":"فرض رسم علامة قدره 10 percent ad valorem إذا أُفرِج عن السلع ولم تُصحَّح"},{"en":"All of the above","es":"Todas las anteriores","ru":"Всё перечисленное выше","tr":"Yukarıdakilerin tümü","hi":"उपरोक्त सभी","ar":"كل ما سبق"}],"e":{"en":"Under 19 CFR 134.2, 134.3, and 134.51-134.55, CBP may require marking, exportation, or destruction under supervision; assess the 10 percent marking duty under 19 USC 1304(i); and demand redelivery of improperly marked merchandise; therefore all of the listed actions are available.","es":"Conforme a 19 CFR 134.2, 134.3 y 134.51-134.55, CBP puede exigir el marcado, la exportación o la destrucción bajo supervisión; aplicar el arancel por marcado del 10 percent conforme a 19 USC 1304(i); y exigir la reentrega de la mercancía marcada incorrectamente; por lo tanto, todas las acciones enumeradas están disponibles.","ru":"Согласно 19 CFR 134.2, 134.3 и 134.51-134.55, CBP может потребовать маркировки, экспорта или уничтожения под надзором; начислить пошлину за маркировку в размере 10 percent согласно 19 USC 1304(i); и потребовать повторной поставки ненадлежащим образом промаркированных товаров; следовательно, доступны все перечисленные действия.","tr":"19 CFR 134.2, 134.3 ve 134.51-134.55 uyarınca CBP, gözetim altında işaretleme, ihracat veya imha talep edebilir; 19 USC 1304(i) uyarınca 10 percent işaretleme vergisi tahakkuk ettirebilir; ve düzgün şekilde işaretlenmemiş eşyanın yeniden teslimini talep edebilir; bu nedenle listelenen eylemlerin tümü mevcuttur.","hi":"19 CFR 134.2, 134.3 और 134.51-134.55 के तहत, CBP निगरानी में अंकन, निर्यात या विनाश की मांग कर सकता है; 19 USC 1304(i) के तहत 10 percent अंकन शुल्क लगा सकता है; और अनुचित ढंग से अंकित माल की पुनः-डिलीवरी की मांग कर सकता है; इसलिए सूचीबद्ध सभी कार्रवाइयाँ उपलब्ध हैं।","ar":"بموجب 19 CFR 134.2 و134.3 و134.51-134.55، يجوز لـ CBP اشتراط وضع العلامة أو التصدير أو الإتلاف تحت الإشراف؛ وفرض رسم العلامة البالغ 10 percent بموجب 19 USC 1304(i)؛ والمطالبة بإعادة تسليم البضائع المعلَّمة بشكل غير صحيح؛ ولذلك فإن جميع الإجراءات المذكورة متاحة."}},{"cat":"trade","a":0,"q":{"en":"Which statement about claiming USMCA preferential tariff treatment and origin verification is FALSE?","es":"¿Qué afirmación sobre reclamar el tratamiento arancelario preferencial del USMCA y la verificación de origen es FALSA?","ru":"Какое утверждение о заявлении преференциального тарифного режима USMCA и проверке происхождения является ЛОЖНЫМ?","tr":"USMCA tercihli tarife muamelesi talep etme ve menşe doğrulamasına ilişkin hangi ifade YANLIŞTIR?","hi":"USMCA अधिमान्य टैरिफ उपचार का दावा करने और मूल सत्यापन के बारे में कौन सा कथन असत्य है?","ar":"أي عبارة بشأن المطالبة بالمعاملة التعريفية التفضيلية لـ USMCA والتحقق من المنشأ خاطئة؟"},"o":[{"en":"Goods that merely transit a non-party while undergoing further production still qualify so long as they touch a USMCA party's territory","es":"Las mercancías que simplemente transitan por un país no parte mientras se someten a producción adicional siguen calificando siempre que toquen el territorio de una parte del USMCA","ru":"Товары, которые лишь следуют транзитом через сторону, не являющуюся участником, проходя дополнительную обработку, всё равно соответствуют требованиям, если они касаются территории стороны USMCA","tr":"Daha fazla üretimden geçerken yalnızca taraf olmayan bir ülkeden transit geçen eşyalar, bir USMCA tarafının ülkesine değdikleri sürece yine de uygun olur","hi":"वे वस्तुएँ जो आगे के उत्पादन से गुजरते हुए केवल किसी गैर-पक्ष से होकर पारगमन करती हैं, फिर भी योग्य होती हैं, बशर्ते वे किसी USMCA पक्ष के क्षेत्र को स्पर्श करें","ar":"السلع التي تمرّ فقط عبر دولة غير طرف بينما تخضع لمزيد من الإنتاج تظل مؤهَّلة طالما أنها تلامس إقليم طرف في USMCA"},{"en":"An importer making a USMCA claim must have the certification of origin in its possession at the time of the claim","es":"Un importador que presenta una reclamación del USMCA debe tener la certificación de origen en su poder al momento de la reclamación","ru":"Импортёр, заявляющий о применении USMCA, должен иметь сертификацию происхождения на руках на момент заявления","tr":"USMCA talebinde bulunan bir ithalatçı, talep anında menşe sertifikasını elinde bulundurmalıdır","hi":"USMCA दावा करने वाले आयातक के पास दावे के समय मूल प्रमाणन उसके कब्जे में होना चाहिए","ar":"يجب أن يكون لدى المستورد الذي يقدّم مطالبة USMCA شهادة المنشأ في حوزته وقت تقديم المطالبة"},{"en":"A certification of origin may cover multiple shipments of identical goods over a blanket period of up to 12 months","es":"Una certificación de origen puede cubrir múltiples envíos de mercancías idénticas durante un período general (blanket) de hasta 12 months","ru":"Сертификация происхождения может охватывать множество поставок идентичных товаров в течение общего (blanket) периода до 12 months","tr":"Bir menşe sertifikası, 12 months'a kadar bir toplu (blanket) dönem boyunca özdeş eşyaların birden çok sevkiyatını kapsayabilir","hi":"एक मूल प्रमाणन 12 months तक की एक सामूहिक (blanket) अवधि में समान वस्तुओं के अनेक शिपमेंट को कवर कर सकता है","ar":"يجوز أن تغطي شهادة المنشأ شحنات متعددة من سلع متطابقة على مدى فترة شاملة (blanket) تصل إلى 12 months"},{"en":"A post-importation USMCA preference claim may be made within one year of importation under 19 USC 1520(d)","es":"Una reclamación de preferencia del USMCA posterior a la importación puede presentarse dentro de un año desde la importación conforme a 19 USC 1520(d)","ru":"Заявление о преференции USMCA после ввоза может быть подано в течение одного года с момента ввоза согласно 19 USC 1520(d)","tr":"İthalat sonrası bir USMCA tercih talebi, 19 USC 1520(d) uyarınca ithalattan itibaren bir yıl içinde yapılabilir","hi":"आयात-पश्चात USMCA अधिमान दावा 19 USC 1520(d) के तहत आयात के एक वर्ष के भीतर किया जा सकता है","ar":"يجوز تقديم مطالبة تفضيل USMCA بعد الاستيراد خلال سنة واحدة من الاستيراد بموجب 19 USC 1520(d)"}],"e":{"en":"Mere transit or transshipment through a non-party does not preserve origin if the goods undergo further production or are not under customs control there; the transit and transshipment rules (19 CFR 182.18 and USMCA Art. 4.18) bar preference. The other statements correctly describe blanket periods, the possession requirement (19 CFR 182.12), and post-importation claims under 19 USC 1520(d).","es":"El mero tránsito o transbordo a través de un país no parte no preserva el origen si las mercancías se someten a producción adicional o no están bajo control aduanero allí; las reglas de tránsito y transbordo (19 CFR 182.18 y USMCA Art. 4.18) impiden la preferencia. Las demás afirmaciones describen correctamente los períodos generales (blanket), el requisito de posesión (19 CFR 182.12) y las reclamaciones posteriores a la importación conforme a 19 USC 1520(d).","ru":"Простой транзит или перегрузка через сторону, не являющуюся участником, не сохраняет происхождение, если товары проходят дополнительную обработку или не находятся там под таможенным контролем; правила о транзите и перегрузке (19 CFR 182.18 и USMCA Art. 4.18) исключают преференцию. Остальные утверждения правильно описывают общие (blanket) периоды, требование о владении (19 CFR 182.12) и заявления после ввоза согласно 19 USC 1520(d).","tr":"Taraf olmayan bir ülkeden yalnızca transit geçiş veya aktarma, eşyalar orada daha fazla üretimden geçiyorsa veya gümrük denetimi altında değilse menşei korumaz; transit ve aktarma kuralları (19 CFR 182.18 ve USMCA Art. 4.18) tercihi engeller. Diğer ifadeler, toplu (blanket) dönemleri, bulundurma gerekliliğini (19 CFR 182.12) ve 19 USC 1520(d) uyarınca ithalat sonrası talepleri doğru şekilde tanımlamaktadır.","hi":"किसी गैर-पक्ष से केवल पारगमन या ट्रांसशिपमेंट मूल को संरक्षित नहीं करता यदि वस्तुएँ वहाँ आगे के उत्पादन से गुजरती हैं या सीमा शुल्क नियंत्रण में नहीं होतीं; पारगमन और ट्रांसशिपमेंट नियम (19 CFR 182.18 और USMCA Art. 4.18) अधिमान को रोकते हैं। अन्य कथन सामूहिक (blanket) अवधियों, कब्जा आवश्यकता (19 CFR 182.12), और 19 USC 1520(d) के तहत आयात-पश्चात दावों का सही वर्णन करते हैं।","ar":"مجرّد العبور أو إعادة الشحن عبر دولة غير طرف لا يحفظ المنشأ إذا خضعت السلع لمزيد من الإنتاج أو لم تكن تحت الرقابة الجمركية هناك؛ فقواعد العبور وإعادة الشحن (19 CFR 182.18 و USMCA Art. 4.18) تمنع التفضيل. أما العبارات الأخرى فتصف بشكل صحيح الفترات الشاملة (blanket)، واشتراط الحيازة (19 CFR 182.12)، والمطالبات بعد الاستيراد بموجب 19 USC 1520(d)."}},{"cat":"trade","a":3,"q":{"en":"A shipment of counterfeit-trademarked goods and a separate shipment requiring FDA review both arrive. Which statement about restricted merchandise and partner government agency (PGA) requirements is TRUE?","es":"Llegan un envío de mercancías con marca falsificada y un envío separado que requiere revisión de la FDA. ¿Qué afirmación sobre la mercancía restringida y los requisitos de las agencias gubernamentales asociadas (PGA) es VERDADERA?","ru":"Прибывают партия товаров с поддельным товарным знаком и отдельная партия, требующая проверки FDA. Какое утверждение об ограниченных товарах и требованиях партнёрских государственных ведомств (PGA) является ВЕРНЫМ?","tr":"Taklit markalı eşya içeren bir sevkiyat ile FDA incelemesi gerektiren ayrı bir sevkiyat birlikte gelir. Kısıtlanmış eşya ve ortak devlet kurumu (PGA) gereklilikleri hakkında hangi ifade DOĞRUDUR?","hi":"नकली-ट्रेडमार्क वाली वस्तुओं की एक खेप और FDA समीक्षा की आवश्यकता वाली एक अलग खेप दोनों आती हैं। प्रतिबंधित माल और साझेदार सरकारी एजेंसी (PGA) आवश्यकताओं के बारे में कौन सा कथन सत्य है?","ar":"تصل شحنة من سلع ذات علامة تجارية مزيّفة وشحنة منفصلة تتطلب مراجعة FDA. أي عبارة بشأن البضائع المقيَّدة ومتطلبات الوكالة الحكومية الشريكة (PGA) صحيحة؟"},"o":[{"en":"Counterfeit goods are admissible if duties are paid, and PGA review is optional at the importer's discretion","es":"Las mercancías falsificadas son admisibles si se pagan los aranceles, y la revisión de la PGA es opcional a discreción del importador","ru":"Поддельные товары допускаются к ввозу при уплате пошлин, а проверка PGA является необязательной по усмотрению импортёра","tr":"Taklit eşyalar, vergiler ödenirse kabul edilebilir ve PGA incelemesi ithalatçının takdirine bağlı olarak isteğe bağlıdır","hi":"शुल्क का भुगतान करने पर नकली वस्तुएँ स्वीकार्य हैं, और PGA समीक्षा आयातक के विवेक पर वैकल्पिक है","ar":"السلع المزيّفة مقبولة إذا دُفعت الرسوم، ومراجعة PGA اختيارية حسب تقدير المستورد"},{"en":"Only the trademark owner, not CBP, has authority to detain goods bearing a counterfeit recorded mark","es":"Solo el titular de la marca, no CBP, tiene autoridad para detener mercancías que lleven una marca registrada falsificada","ru":"Только владелец товарного знака, а не CBP, имеет полномочия задерживать товары с поддельным зарегистрированным знаком","tr":"Taklit kayıtlı bir marka taşıyan eşyayı alıkoyma yetkisi yalnızca marka sahibine aittir, CBP'ye değil","hi":"नकली दर्ज चिह्न वाले माल को रोकने का अधिकार केवल ट्रेडमार्क मालिक को है, CBP को नहीं","ar":"صاحب العلامة التجارية وحده، وليس CBP، هو من يملك صلاحية احتجاز البضائع التي تحمل علامة مسجَّلة مزيّفة"},{"en":"PGA-regulated goods are exempt from CBP examination once a customs bond is on file","es":"Las mercancías reguladas por una PGA están exentas de la inspección de CBP una vez que se presenta una fianza aduanera","ru":"Товары, регулируемые PGA, освобождаются от досмотра CBP после подачи таможенной гарантии","tr":"PGA tarafından düzenlenen eşyalar, bir gümrük kefaleti dosyalandığında CBP incelemesinden muaftır","hi":"एक बार सीमा शुल्क बॉन्ड दाखिल हो जाने पर PGA-विनियमित वस्तुएँ CBP जाँच से मुक्त हो जाती हैं","ar":"تُعفى السلع الخاضعة لـ PGA من فحص CBP بمجرد تقديم كفالة جمركية"},{"en":"CBP may seize merchandise bearing a counterfeit mark recorded with CBP, and PGA-regulated goods may require release authorization from the relevant agency before CBP release","es":"CBP puede incautar mercancía que lleve una marca falsificada registrada ante CBP, y las mercancías reguladas por una PGA pueden requerir autorización de liberación de la agencia correspondiente antes de la liberación por CBP","ru":"CBP может изъять товары с поддельным знаком, зарегистрированным в CBP, а товары, регулируемые PGA, могут требовать разрешения на выпуск от соответствующего ведомства до выпуска CBP","tr":"CBP, CBP'ye kaydedilmiş taklit bir marka taşıyan eşyaya el koyabilir ve PGA tarafından düzenlenen eşyalar, CBP serbest bırakmadan önce ilgili kurumdan serbest bırakma izni gerektirebilir","hi":"CBP CBP के पास दर्ज नकली चिह्न वाले माल को जब्त कर सकता है, और PGA-विनियमित वस्तुओं को CBP द्वारा जारी करने से पहले संबंधित एजेंसी से जारी करने का प्राधिकरण आवश्यक हो सकता है","ar":"يجوز لـ CBP حجز البضائع التي تحمل علامة مزيّفة مسجَّلة لدى CBP، وقد تتطلب السلع الخاضعة لـ PGA إذنًا بالإفراج من الوكالة المعنية قبل إفراج CBP عنها"}],"e":{"en":"Under 19 USC 1526 and 19 CFR Part 133, CBP may seize and forfeit goods bearing a counterfeit version of a federally registered, CBP-recorded trademark; and under the PGA/ACE framework, partner agencies such as FDA may require their own admissibility determination before CBP releases the merchandise.","es":"Conforme a 19 USC 1526 y 19 CFR Part 133, CBP puede incautar y decomisar mercancías que lleven una versión falsificada de una marca registrada federalmente y registrada ante CBP; y conforme al marco PGA/ACE, las agencias asociadas como la FDA pueden requerir su propia determinación de admisibilidad antes de que CBP libere la mercancía.","ru":"Согласно 19 USC 1526 и 19 CFR Part 133, CBP может изъять и конфисковать товары с поддельной версией федерально зарегистрированного и записанного в CBP товарного знака; а в рамках PGA/ACE партнёрские ведомства, такие как FDA, могут требовать собственного определения о допустимости до того, как CBP выпустит товары.","tr":"19 USC 1526 ve 19 CFR Part 133 uyarınca, CBP federal düzeyde tescilli ve CBP'ye kaydedilmiş bir markanın taklit versiyonunu taşıyan eşyaya el koyabilir ve müsadere edebilir; ve PGA/ACE çerçevesi uyarınca FDA gibi ortak kurumlar, CBP eşyayı serbest bırakmadan önce kendi kabul edilebilirlik kararlarını isteyebilir.","hi":"19 USC 1526 और 19 CFR Part 133 के तहत, CBP संघीय रूप से पंजीकृत और CBP के पास दर्ज ट्रेडमार्क के नकली संस्करण वाले माल को जब्त और अधिग्रहीत कर सकता है; और PGA/ACE ढाँचे के तहत, FDA जैसी साझेदार एजेंसियाँ CBP द्वारा माल जारी करने से पहले अपना स्वयं का स्वीकार्यता निर्धारण मांग सकती हैं।","ar":"بموجب 19 USC 1526 و19 CFR Part 133، يجوز لـ CBP حجز ومصادرة البضائع التي تحمل نسخة مزيّفة من علامة تجارية مسجَّلة فيدراليًا ومسجَّلة لدى CBP؛ وبموجب إطار PGA/ACE، قد تشترط الوكالات الشريكة مثل FDA إصدار قرارها الخاص بشأن المقبولية قبل أن تُفرِج CBP عن البضائع."}},{"cat":"trade","a":3,"q":{"en":"An importer of merchandise subject to an antidumping duty (ADD) order claims USMCA preferential duty treatment and marks the goods as a USMCA-country product. Which statement is correct?","es":"Un importador de mercancía sujeta a una orden de derecho antidumping (ADD) reclama el tratamiento arancelario preferencial del USMCA y marca las mercancías como producto de un país del USMCA. ¿Qué afirmación es correcta?","ru":"Импортёр товаров, на которые распространяется приказ об антидемпинговой пошлине (ADD), заявляет о применении преференциального пошлинного режима USMCA и маркирует товары как продукт страны USMCA. Какое утверждение является правильным?","tr":"Bir antidamping vergisi (ADD) emrine tabi eşyanın ithalatçısı, USMCA tercihli gümrük vergisi muamelesi talep eder ve eşyayı bir USMCA ülkesi ürünü olarak işaretler. Hangi ifade doğrudur?","hi":"एक प्रति-डंपिंग शुल्क (ADD) आदेश के अधीन माल का आयातक USMCA अधिमान्य शुल्क उपचार का दावा करता है और वस्तुओं को USMCA-देश के उत्पाद के रूप में अंकित करता है। कौन सा कथन सही है?","ar":"يطالب مستورد بضائع خاضعة لأمر رسم مكافحة الإغراق (ADD) بالمعاملة التعريفية التفضيلية لـ USMCA ويضع علامة على السلع كمنتج لبلد عضو في USMCA. أي عبارة صحيحة؟"},"o":[{"en":"Qualifying for USMCA preferential tariff treatment exempts the goods from the antidumping duty order","es":"Calificar para el tratamiento arancelario preferencial del USMCA exime a las mercancías de la orden de derecho antidumping","ru":"Соответствие требованиям для преференциального тарифного режима USMCA освобождает товары от приказа об антидемпинговой пошлине","tr":"USMCA tercihli tarife muamelesine hak kazanmak, eşyayı antidamping vergisi emrinden muaf tutar","hi":"USMCA अधिमान्य टैरिफ उपचार के लिए योग्य होना वस्तुओं को प्रति-डंपिंग शुल्क आदेश से छूट देता है","ar":"استيفاء شروط المعاملة التعريفية التفضيلية لـ USMCA يُعفي السلع من أمر رسم مكافحة الإغراق"},{"en":"Country-of-origin marking determines ADD liability and overrides the scope of the order","es":"El marcado del país de origen determina la responsabilidad por ADD y prevalece sobre el alcance de la orden","ru":"Маркировка страны происхождения определяет обязательство по ADD и имеет приоритет над сферой действия приказа","tr":"Menşe ülke işaretlemesi, ADD yükümlülüğünü belirler ve emrin kapsamının üzerine geçer","hi":"मूल-देश अंकन ADD देयता निर्धारित करता है और आदेश के दायरे पर अधिभावी होता है","ar":"علامة بلد المنشأ تحدّد مسؤولية ADD وتَجُبّ نطاق الأمر"},{"en":"Antidumping duties never apply to goods produced in a USMCA country regardless of the order","es":"Los derechos antidumping nunca se aplican a mercancías producidas en un país del USMCA sin importar la orden","ru":"Антидемпинговые пошлины никогда не применяются к товарам, произведённым в стране USMCA, независимо от приказа","tr":"Antidamping vergileri, emir ne olursa olsun bir USMCA ülkesinde üretilen eşyalara asla uygulanmaz","hi":"प्रति-डंपिंग शुल्क आदेश की परवाह किए बिना किसी USMCA देश में उत्पादित वस्तुओं पर कभी लागू नहीं होते","ar":"لا تنطبق رسوم مكافحة الإغراق أبدًا على السلع المُنتَجة في بلد عضو في USMCA بغضّ النظر عن الأمر"},{"en":"USMCA preference may reduce or eliminate the regular (column 1) duty, but it does not exempt goods from an applicable ADD order, which depends on the order's scope and country of origin","es":"La preferencia del USMCA puede reducir o eliminar el arancel regular (columna 1), pero no exime a las mercancías de una orden ADD aplicable, la cual depende del alcance de la orden y del país de origen","ru":"Преференция USMCA может снизить или устранить обычную пошлину (колонка 1), но не освобождает товары от применимого приказа ADD, который зависит от сферы действия приказа и страны происхождения","tr":"USMCA tercihi, normal (sütun 1) gümrük vergisini azaltabilir veya ortadan kaldırabilir, ancak eşyayı uygulanabilir bir ADD emrinden muaf tutmaz; bu, emrin kapsamına ve menşe ülkesine bağlıdır","hi":"USMCA अधिमान नियमित (column 1) शुल्क को घटा या समाप्त कर सकता है, परंतु यह वस्तुओं को लागू ADD आदेश से छूट नहीं देता, जो आदेश के दायरे और मूल देश पर निर्भर करता है","ar":"قد يقلّل تفضيل USMCA من الرسم العادي (العمود 1) أو يُلغيه، لكنه لا يُعفي السلع من أمر ADD المطبَّق، الذي يعتمد على نطاق الأمر وبلد المنشأ"}],"e":{"en":"Trade-preference programs like USMCA address the regular tariff rate, not trade-remedy duties; antidumping and countervailing duties under 19 CFR Part 351 and the relevant scope/order apply independently based on the order's covered merchandise and country, regardless of a preferential tariff claim or marking.","es":"Los programas de preferencia comercial como el USMCA abordan la tasa arancelaria regular, no los derechos de remedio comercial; los derechos antidumping y compensatorios conforme a 19 CFR Part 351 y el alcance/orden correspondiente se aplican de manera independiente con base en la mercancía y el país cubiertos por la orden, sin importar una reclamación de arancel preferencial o el marcado.","ru":"Программы торговых преференций, такие как USMCA, касаются обычной тарифной ставки, а не пошлин в рамках мер торговой защиты; антидемпинговые и компенсационные пошлины согласно 19 CFR Part 351 и соответствующей сфере действия/приказу применяются независимо на основании охватываемых приказом товаров и страны, независимо от заявления о преференциальном тарифе или маркировки.","tr":"USMCA gibi ticaret tercihi programları, ticaret çaresi vergilerini değil, normal tarife oranını ele alır; 19 CFR Part 351 ve ilgili kapsam/emir uyarınca antidamping ve telafi edici vergiler, tercihli tarife talebi veya işaretlemeden bağımsız olarak, emrin kapsadığı eşya ve ülkeye göre bağımsız olarak uygulanır.","hi":"USMCA जैसे व्यापार-अधिमान कार्यक्रम नियमित टैरिफ दर को संबोधित करते हैं, व्यापार-उपचार शुल्कों को नहीं; 19 CFR Part 351 के तहत प्रति-डंपिंग और प्रति-वर्तीकरण शुल्क और संबंधित दायरा/आदेश स्वतंत्र रूप से आदेश के अंतर्गत आने वाले माल और देश के आधार पर लागू होते हैं, चाहे कोई अधिमान्य टैरिफ दावा या अंकन हो।","ar":"تتناول برامج التفضيل التجاري مثل USMCA معدّل التعريفة العادي، وليس رسوم العلاج التجاري؛ فرسوم مكافحة الإغراق والرسوم التعويضية بموجب 19 CFR Part 351 والنطاق/الأمر ذي الصلة تُطبَّق بشكل مستقل استنادًا إلى البضائع والبلد المشمولين بالأمر، بغضّ النظر عن أي مطالبة بتعريفة تفضيلية أو علامة."}}]};
